insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='VAZQUEZ'and apellido2='GILEZ'),'2021-05-13','miguel, llega email de Amalia: Buenos dias , desde el CSS Mérida nos envian esta documentación con respecto a MANUEL VAZQUEZ . No es la primera vez que lo envian desde la Agencia tributaria , lo podéis ver en la intranet. Son deudas por multas de tráfico , cuando él está ingresado en CSS hace años ,sin salir . He pedido al centro un cdo. de ingreso . Supongo que algún familiar estará suplantando su identidad o tiene el coche a nombre de él ... En cuanto tenga el cdo. del centro os lo envio y a ver cómo podemos solventarlo . *********************************************** mi contestación: Buenos días, ya hay una anotación similar en la intranet de agosto de 2020. No creo que podamos parar la ejecución que se le avecina de AEAT, tendrá que ir pagando, a ver de qué forma…aunque luego judicialmente intentemos ir contra quién haya usado el vehículo. Si eso es así necesitaríamos para remitir a AEAT la siguiente documentación: -Denuncia por robo o hurto (según haya habido violencia o no cuando se han llevado el vehículo) -Certificado del Centro acreditando desde cuándo reside, horarios y régimen de estancia completa. Una vez que tengamos dicha documentación lo suyo sería paralelamente a contestar a AEAT remitir a DGT solicitud de baja temporal del vehículo (habría que localizar los papeles y llaves del vehículo). ************************************************ Contestación de Juana: Me uno al hilo....estas deudas son antiguas, según consta en Nº expediente ejecutiva: 4351/2016 de la agencia tributaria de Sevilla. Yo le di a todos los vehículos de baja en junio del año pasado. Yo opino que si tiene dinero se pague y saldemos esta deuda, lo malo, es que no tiene dinero...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='VAZQUEZ'and apellido2='GILEZ'),'2021-05-13','Me uno al hilo....estas deudas son antiguas, según consta en Nº expediente ejecutiva: 4351/2016 de la agencia tributaria de Sevilla. Yo le di a todos los vehículos de baja en junio del año pasado. Yo opino que si tiene dinero se pague y saldemos esta deuda, lo malo, es que no tiene dinero...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='VAZQUEZ'and apellido2='GILEZ'),'2021-05-13','Buenos días, ya hay una anotación similar en la intranet de agosto de 2020. No creo que podamos parar la ejecución que se le avecina de AEAT, tendrá que ir pagando, a ver de qué forma…aunque luego judicialmente intentemos ir contra quién haya usado el vehículo. Si eso es así necesitaríamos para remitir a AEAT la siguiente documentación: -Denuncia por robo o hurto (según haya habido violencia o no cuando se han llevado el vehículo) -Certificado del Centro acreditando desde cuándo reside, horarios y régimen de estancia completa. -Respuesta Miguel juridico: Una vez que tengamos dicha documentación lo suyo sería paralelamente a contestar a AEAT remitir a DGT solicitud de baja temporal del vehículo (habría que localizar los papeles y llaves del vehículo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2021-05-13','Ana: llamada de Vere, Direcotra de la Res. Puente Real San Vicente (924 411 032), Agustín sigue bien. Muy obsesioando con el dinero y en que no le vayan a quitar el dinero que hay en su cuenta. Ya ha pasado el mes de adaptación. Por lo demás todo bien. La hija le llama frecuentemente y le visita una vez cada 15 días apróx. *Agustín dice que necesita pilas y alguna otra cosilla. Preguntarán a la hija si se lo va a comprar ella. Sino, como Vere tienen guardados unos 400€, le darán para lo que necesita. Las asignaciones semanales, cuando las requiera (se le agote lo que se quedó) se las irán administrando también en la resi con ese dinero. Una vez se haya agotado ést, se acordará un presupuesto de bolsillos con la secc. ecca. Como ya se valoró en su día, de momento no es necesario.················· Comunico a Amalia por mail que ya se puede encargar del seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-05-13','Belén. Se da de baja en el servicio de catering del centro de día.','2');
