insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-05-11','Ana: Llamada de Maribel Rivera, Responsable de la VV.TT. de Inclusives Vva. (696 43 29 58): La primera entrevista con Darío será el jueves 13, le acompañará Chema, responsable del piso de menores. El ingreso lo programarán para la semana del 17. Me irán informando.','2');
