insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-13','Ana: Llamo al Grupo de Extrajería de la Policía Nacional de CC (Brigada de Extranjería) 927 62 65 25: Hay que solicitar el NIE. **Necesitan el Documento de Identificación Francés, solicitarlo al Consulado de Francia en España (o pasaporte o carta de identidad francesa). Cuando tenga ese documento, me dicen que vuelva a llamar para que me indiquen cómo proceder. ················· **La nacionalidad española se solicita en el Registro Civil que le corresponda por su domicilio (En el Jdo.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='SERRADILLA'and apellido2='CANO'),'2021-05-13','Belén. Envío documento de autorización y consentimiento informado de SPD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-05-13','-Amalia: hablo con la TS del ESM , se ha reunido con la madre, Belén . El chico está de nuevo en la casa , al día siguiente ya estaba allí. Pasó una noche en un hostal del que fue expulsado por dejar la habitación en nefastas condiciones. La madre ha anulado su tarjeta del Corte I. Ya ha enviado la documentacion a la UHDAC. Va a comentar con ECAS si puede hacer tto. ambulatorio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-07','Ana: llamada del Subinspector Vasallo (927 62 90 92): al grabar los datos, para gestionar el DNI, les consta que Mª del Rosario ha perdido su nacionalidad española, consta como ciudadana Francesa. **La recuperación de la nacionalidad tarda unos 2 años apróx. A día de hoy está totalmente "ilegal". **Me falicita el contacto de la Brigada de Extranjería: 927 62 65 25.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-05-14','Ana: Envío correo-e a Pilar Márquez, TS SSASB-Valencia de Alcántara (marquezsilvap@hotmail.com): "Buenos días Pilar, ¿Qué tal estás? Espero que bien. En relación a Julián Ramón Civantos Fernández, comunicarte que, por fin, entre ayer y hoy se están realizando las tareas de limpieza y desinfección en su domicilio. Por tanto, por nuestra parte la semana que vienen puede comenzar a prestarse ya el Servicio de Ayuda a Domicilio concedido. No sé cómo continúa el Ayto. con la baja de las auxiliares que me comentaste, espero que estén mejor y ya esté el equipo al completo. Si quieres hablamos a lo largo de la mañana para concretar o puedes escribirme si te viene mejor. Seguimos en contacto. Un saludo y buena mañana." ··························································································································································································································································· Respuesta de Pilar: "Ana, Buenos días, Sé que están con las labores de limpieza, hemos visto movimiento en el domicilio. Necesito que me digáis que horario tenéis pensado para Ramón, puede ser jornada continua o partida. Seguimos con la trabajadora dada de baja, pero incrementaremos la jornada laboral a una de las que están trabajando para poder cubrir el nuevo servicio. Esta mañana tengo mesa de coordinación de violencia de género con subdelegación del gobierno, me va a ser difícil que detallemos cosas. Si quieres el lunes hablamos detenidamente. Gracias!!" ··············································································································································································································· Respondo: "Hola de nuevo Pilar, Pues puede ser interesante el que tenga jornada partida, pues así tendría “seguimiento” y apoyo en distintos momentos del día. El lunes lo hablamos entonces y concretamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2021-05-14','TERESA el pasado 11 de Mayo se visitó con Cándido Retamal González, que reside en la calle Velázquez de Almendralejo, la tienda de Chollo Muebles. Se estuvieron viendo los sillones de dos plazas que había en la tienda y el encargado nos enseñó dos opciones buenas y bastante viables económicamente. A Cándido le gustó mucho el sofá de 250€ porque era más cómodo y tenía más refuerzo para la espalda. Se adjuntan envían los dos presupuestos. Seguidamente ese día, se habló por teléfono con el encargado de Cepsa de la localidad y se le pidió que enviara un presupuesto para la colocación de una goma y un regulador de gas butano en la cocina. El hombre comentó que aparte de hacer eso, el técnico que fuera a casa de Cándido, tenía que dejar echa la inspección de la instalación de gas que acababa de poner y contó que esta inspección sería válida por 5 años. La instalación de goma y regulador eran 12€ y la revisión serían 49€, el costa total sería de 61€. Se adjunta envía el presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2021-05-14','TERESA rechazo que lleva manifestando para ser visitada en estos dos últimos meses. Desde finales de febrero llama insistentemente para que desde Comisión tutelar le incrementen la asignación semanal, alegando que necesita más de 100 euros para sus gastos semanales. Cuando se intenta trabajar con ella la gestión económica, para determinar qué gastos precisa que sean prioritarios para cubrir necesidades básicas o extras que se le presenten, rechaza cualquier ayuda indicando que lo quiere y punto. Es decir, su objetivo es tener más dinero para salir con los amigos y que no le pidan explicaciones de cómo lo administra. En abril coincidiendo con otras visitas programadas quedamos con ella para verla, pero esa misma mañana a través de un audio de WhatsApp nos indica que si la comisión no le da más dinero para el fin de semana ella rechazará cualquier intervención desde el programa de apoyo social comunitario. Entre las últimas gestiones planificadas con ella ha sido para comprobar el estado de su móvil, ya que indicó a la comisión que el suyo estaba roto. Igualmente, la respuesta ha sido que ella quiere el dinero y que no va a ir con nadie del programa de apoyo social comunitario, que irá con su hermano a comprarse el nuevo móvil. Las profesionales del programa lo único que podemos afirmar es que no hemos tenido problemas para contactar con ella por teléfono, por ello no sabemos que problemática presentará su terminal y si sus manifestaciones en este sentido son ciertas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-05-14','TERESA La residente Maria Elena Duran Duran, quiere salir mañana dia 14 de mayo a Fuente de Cantos a un "paseo a caballos" junto con su hijo, quien se encargará de recogerla y traerla .Es por la mañana , pero no sabemos la hora en concreto. Dinos si es posible autorizar dicha salida TRAS CONVERSACION CON SU HIJO SE AUTORIZA LA SALIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2021-05-14','Belén.Se envía por fax el modelo de informe médico para la solicitud de reconocimiento de la situación de dependencia y del derecho a las prestaciones del SAAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-05-14','TERESA empezamos la ayuda a domicilio el día 1 de junio y damos por finalizado el contrato actual el 31 de mayo. Aceptamos el presupuesto Con respecto al horario no hay ningún preferencia lo que si queremos que vaya todos los días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2021-05-14','TERESA La semana pasada se visitó a Adolfo García Cruz en la calle Luis Zorrilla de Villafranca de los Barros. Se llamó a la puerta varias veces porque estaba cerrada y se escuchó a Adolfo a lo lejos diciendo que se estaba levantando de la cama. Cuando Adolfo abre la puerta, se le pregunta si se está levantando a esa hora y contesta que si, eran las 11:20h de la mañana. Seguidamente se le pregunta si está durmiendo en esa casa (la de la madre) desde que salió del centro y él contesta afirmativamente, comenta que el piso de su hermano no le gusta y no ha llegado a dormir ni un solo día. Adolfo comenta que se acuesta tarde, de madrugada y por lo tanto se levanta tarde porque tiene mucho sueño. Se pasa el día en su habitación con el ordenador de mesa y su hermano Lorenzo va para allá a verle un rato y a llevarle el desayuno y la comida. Se le pregunta si se está tomando la medicación y Adolfo contesta que no, que antes se tomaba una pastillita blanca pero que ya no lo hace por que no quiere. Se propone a Adolfo dar un paseo por los alrededores de su casa pero dice que no porque no le apetece ponerse la mascarilla, dice que está muy cansado y que hace calor. Seguidamente se llama a Lorenzo, el hermano de Adolfo y se le pregunta por qué su hermano está viviendo en la casa de sus padres y no en su piso como acordó con el sociosanitario cuando su hermano salió de alta. Lorenzo contesta que lo ha intentado e incluso cuenta que Adolfo pasa algunos ratos con él en el piso pero también relata que Adolfo tiene devoción por la casa de sus padres y no quiere moverse de allí, por lo que Lorenzo va para allá varias veces al día para verle y llevarle la comida. Se le pregunta por la medicación de Adolfo, y Lorenzo contesta que él se la deja con el desayuno y la comida pero al rato se va, por lo que no puede comprobar a ciencia cierta si se la toma o no. Aunque cuando le pregunta a Adolfo si se ha tomado las pastillas, él le responde que si. Lorenzo cuenta que él intenta que su hermano se duche y se cambie de ropa a menudo pero no siempre lo consigue porque el tutelado es muy tozudo y hace siempre lo que le parece. Se habla más tarde tanto con Marisa de los SASB del ayuntamiento de Vilafranca (924 52 78 22), como con Charo, la trabajadora social del centro de salud de Villafranca (924 52 02 56) y se les comenta la situación actual de Adolfo. Marisa dice que hablará con la comisión tutelar y también con el sociosanitario para informar del caso de Adolfo y para comentarles que los requisitos con los que se fue de alta no se están cumpliendo. Charo comenta que la situación de la salud mental de Villafranca es pésima ya que no tienen ahora mismo psiquiatra asignado en Almendralejo, ya que ahora las citas se hacen allí. Aunque cuenta que si se necesita contactar con el servicio de salud mental ella puede echar una mano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-05-14','TERESA Andrés está de pase en P.I. desde el lunes. Ayer se descompenso y tuvieron que llamar al 112. Ingresó en UHB por la tarde y ahora mismo ya va de vuelta al centro de alta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-05-14','TERESA 5 de Mayo se acompañó a Jose Antonio Delgado Rodríguez, vecino de la localidad de Higuera la Real, a su cita de salud mental en Zafra. La Dra. Marisa estuvo conversando un buen rato con el tutelado y le preguntó cómo se encontraba, José Antonio respondió que estaba algo preocupado y nervioso. Comentó que su tía se había operado de una rodilla y como tiene mucha relación con ella, está preocupado por su recuperación. Además está muy pendiente de la resolución de la herencia de su madre y de los pagos de la contribución y de las demás facturas de la casa. Se le comenta a la Dra. Marisa que José Antonio ha dejado de recoger las comidas y cenas del centro de día de su localidad, que pagaba por valor de 100€. El tutelado comenta que es cierto y cuenta que no va a cambiar de parecer porque ahora mismo tiene que pagar muchas cosas de la casa y quiere guardar dinero hasta que llegue ese momento, además puede apañarse solo comiendo bocadillos en los bares o comida prefabricada de los supermercados. Por más que le comenta la psiquiatra la importancia de comer de manera equilibrada y seguir una dieta más sana, el tutelado no escucha y sigue con el mismo discurso. Se habla con Rosa de los SSB de Higuera la Real, que confirma que el tutelado se ha pasado por su despacho para darse de baja en el servicio de comidas del Centro de Día. Ella ha intentado explicarle que el servicio es algo muy beneficioso para él pero el tutelado no ha querido escucharla. La delegada de apoyo ha intentado hablar con José Antonio sobre este tema también explicándole las grandes ventajas de la comida casera del centro de día pero no se ha conseguido que el tutelado cambie de parecer o se replantee su decisión. Aunque ha comentado que quizá de que pasen unos meses y se pague la contribución y otras cosas de la casa, vuelva a apuntarse de nuevo. Al respecto de ayere dia10 de Mayo se acompañó a José Antonio Delgado Rodrígue, a su cita programada en el EVI en la Seguridad Social de Badajoz. Cuando se llegó al edificio del INSS, se preguntó si se podía acompañar a José Antonio en la consulta de la médico, y después de consultarlo, lo permitieron. Se pasó a la sala de espera y cuando le tocó el turno, se pasó con él a la consulta de la médico que iba a evaluarle. La doctora le preguntó a José Antonio si había trabajado alguna vez y en qué materia, el tutelado contestó que había trabajado en diferentes áreas pero nunca durante mucho tiempo y dejó de hacerlo cuando le operaron de la mano izquierda hace muchos años. La doctora le preguntó por su enfermedad, sus citas de salud mental y su medicación, aunque comentó que había leído el último informe clínico que la Dra. Marisa había redactado sobre el tutelado. Al cabo de unos pocos minutos en su consulta, la doctora comentó que ya disponía de información suficiente y que en unas semanas le llegaría una carta a José Antonio con el dictamen. A la salida, se acompañó al tutelado a la estación de autobuses donde cogió el bus de las 13:30h de vuelta a Higuera la Real.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2021-05-14','TERESA RECIBO EMAI DE MARISA TS SSB VILLAFRNCA Buenos días, no sé si te ha llegado el informe sobre el seguimiento de Adolfo que se hace desde la entidad encargada de ello, pero me comentó Susana que Adolfo está desde que volvió al pueblo viviendo en casa de la madre, que el hermano va y le da una vuelta de vez en cuando y le lleva la comida sin control de horario, Según comenta Adolfo, no se está tomando la medicación y la compañera ha podido observar que no tiene rutina ni horarios, que la casa está sucia. el otro día estaba acostado y eran sobre las 11,30 cuando ella fue a la casa. El hermano dice que está viviendo con él pero la compañera ya tiene confirmación de que no es así, Esto ya lo veníamos venir desde un principio, de nada sirve los compromisos del hermano y desde aquí únicamente podemos iros informando de lo que vayamos sabiendo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-05-14','Ana: Correo de ayer por la tarde de Raquel, TS SSASB, como respuesta a mi propuesta de que comuniquen el ingreso al hermano de Florencia: "Buenas tardes Ana, no te preocupes, mañana traslado la información a la persona responsable del Ayuntamiento, para que se lo comuniquen a su hermano, si no pudieran de forma verbal, que es lo que puede pasar, pues que le dejen una nota debajo de la puerta. Creo que no ha preguntado por ella, no me han dicho nada al respecto. La que me ha preguntado ha sido Esperanza."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-14','Ana: llamo al Consulado de Francia en Madrid, varias veces (917 007 800) sin éxito. ··············· Llamo a la Embajada de Francia en Madrid (914 238 900): tras exponerle la situación me indica que debo llamar al consulado (nº al que he llamado). Como le explico que no consigo contactar me facilita una dirección de email: ecrire@consulfrance-madrid.org: ················· Envío el siguiente correo-e: "Buenos días, Dada mi imposibilidad para contactar por teléfono, procedo a hacerles una consulta por esta vía. En la Comisión Tutelar de Adultos de Extremadura (CTAEX) tenemos una Señora tutelada, cuyo DNI no hemos podido realizar, pues según nos informan en la Oficina del DNI de la Policía Nacional correspondiente, al grabar los datos les consta que perdió su nacionalidad (cuestión que curiosamente no consta en el Registro Civil, no hay anotaciones en el margen del certificado literal). Según nos informa es ciudadana francesa, pero no tenemos documento alguno al respecto. Sólo disponemos del Certificado Literal de Nacimiento y número de NIE que debieron asignarle en su día (X0745160Y). Para poder renovar su NIE, nos solicitan Documento de Identidad o Pasaporte en vigor. ¿Podrían por favor ponerse en contacto conmigo y/o indicarnos cómo debemos proceder para su expedición? Es una cuestión un tanto urgente, pues comenzamos a tener problemas con el banco y como le bloqueen la cuenta dejará de percibir su pensión y por tanto se quedará sin ingresos. Agradezco de antemano su atención. Un saludo."Buenos días, Dada mi imposibilidad para contactar por teléfono, procedo a hacerles una consulta por esta vía. En la Comisión Tutelar de Adultos de Extremadura (CTAEX) tenemos una Señora tutelada, cuyo DNI no hemos podido realizar, pues según nos informan en la Oficina del DNI de la Policía Nacional correspondiente, al grabar los datos les consta que perdió su nacionalidad (cuestión que curiosamente no consta en el Registro Civil, no hay anotaciones en el margen del certificado literal). Según nos informa es ciudadana francesa, pero no tenemos documento alguno al respecto. Sólo disponemos del Certificado Literal de Nacimiento y número de NIE que debieron asignarle en su día (X0745160Y). Para poder renovar su NIE, nos solicitan Documento de Identidad o Pasaporte en vigor. ¿Podrían por favor ponerse en contacto conmigo y/o indicarnos cómo debemos proceder para su expedición? Es una cuestión un tanto urgente, pues comenzamos a tener problemas con el banco y como le bloqueen la cuenta dejará de percibir su pensión y por tanto se quedará sin ingresos. Agradezco de antemano su atención. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-05-14','TERESA PIDO PRESUPUESTO A CENTRO DIRECCIONES CENTROS PLAZA JM MORON HERNANDEZ Encinar Cuadrado S.L. (Residencia Las Cumbres) Ávila Telf.: 920269527 Carolina Email: residencialascumbres@hotmail.com El Serenil, Hospital de Salud Mental, Málaga Tel: 952513267 Email: trabajosocial@serenil.com Hermanas Hospitalarias, Centro Neuropsiquiatría Ntra Sra del Carmen, Zaragoza Telf.: 976770635 Email: aclemente.zaragoza@hospitalarias.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2021-05-14','Belén. Se envía por fax consentimiento informado para administración de anestesia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-05-14','Belén. Se envía por fax a la embajada de Mauritania escrito ya remitido por mail junto a la sentencia de incapacitación y la aceptación del cargo de tutor. ······· Da ocupado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-05-17','Ana: Recibimos los informes de salud originales para las solicitudes de Dependencia y Res. de Mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-05-17','Ana: Correo del viernes a última hora de Alberto Arias Bueso - EVD (alberto.arias@salud-juntaex.es): "Buenos días, ¿ha comenzado ya el servicio de ayuda a domicilio? Muchas gracias." ······························································································································································································ Mi respuesta: "Buenos días Alberto, Aún no. Se unieron varios factores por ambas partes: Necesidad de limpieza previa y en profundidad en el domicilio de Julián Ramón y la baja de algunas Aux. de SAD del Ayto. El viernes intercambiamos correos Pilar Márquez y yo y acordamos hablar hoy para dejar ya todo organizado. Por nuestra parte el servicio podría comenzar esta misma semana. Un saludo." ······························································································································································································ Ana: Llamo a Pilar, TS de Valencia de Alcánara (627 34 11 19 / 927 580 326, ext.8) varias veces, pero no obtengo respuesta. ········ Le envío un correo-e (marquezsilvap@hotmail.com): "Hola Pilar, Te he llamado, pero estarás ocupada. Si te es posible llámame mañana, para que cerremos lo del SAD de Civantos, ya me ha preguntado de nuevo hoy Alberto Arias. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-05-17','Ana: Se envía de nuevo por fax a la embajada de Mauritania escrito ya remitido por mail la semana pasada junto a la sentencia de incapacitación y la aceptación del cargo de tutor. ***Una vez da "ocupado" y la siguiente "ERROR"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-17','miguel, emails de Damian: El lunes 24 de mayo tengo la entrada al CRR de merida y el lunes 17 tengo una entrevista por videoconferencia me gasto todo el dinero para que se lo diga al juez y llevo varios dias pidiendo por la calle***************************************** Esta noche me he vuelto a orinar me gustaria de corazon que como si se hiciera que no se nada y deseeme suerte mañana 17 de mayo tengo la entrevista por video conferencia con el director de plasencia y el equipo y al lunes de la otra semana el 24 ingreso en el CRR de merida es por protocolo o preguntele mañana a la directora a blanca que porque me hacen la entrevista?es por protocolo? Gracias ya mañana me informa.muchas gracias don miguel','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2021-05-17','Ana: En relación al correo-e de Ángela, Placeat (directora@placeat.org), a última hora del viernes: "...que acaban de llamar desde Mérida para darle cita a Maria en consulta de ginecología en Cáceres el dia 18 de mayo a las 17h. Ella tiene pendiente la intervención de ligadura de trompas. Al ser en Cáceres la intervención nos complica a nosotros el darle apoyo, por lo que necesitamos nos digais como actuar., si seguimos a la espera hasta que se realice en Plasencia rechazando la consulta e intervención en Cáceres , o de lo contrario solucionais su acompañamiento en Cáceres." ·································· Mantenemos conversación telefónica (927 421 950): Les hace mucho trastorno que la intervención se realice en Cáceres, por lo que van a pedir que se la hagan en Plasencia, aunque tarden algo más. *Me mantendrán informada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-05-17','Ana: Convesación telefónica con Ángela Bueno, Directora de Asuntos Soc. Placeat (927 421 950): Nos remitirán CI para Intervención Quirúrgica "Pólipo nasal", de Cristofer, con la dirección para que una vez firmado se devuelva al hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-05-17','Ana: Pregunto a Maite por la solicitud de plaza en centro de Juan Carlos. *Están pendientes de pedir perfil al CADEX. ································································································································································································ Como cada 10-15 días, recibo llamada de Juan Carlos: Pregunta cuándo va a ir a otro centro pues ya se le hace largo estar allí. Esta tarde tienen cine y el taller está haciendo un "gremlin". La semana pasada también acudió a la protectora de animales y sacó a pasear a 2 perros. *Además va a participar en las Jornadas Deportivas de Extremadura. Se muestra contento con las actividades en sí. *Al finalizar programamos nueva llamada con a T.O.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2021-05-17','Ana: Envío correo al CADEX-CC: "Buenos días, En relación a D. Mateo Ruano Moreno, tutelado por la CTAEX, solicitamos a fecha de 7/07/21 nos remitieseis Certificado de Discapacidad y Dictamen Técnico, pero aún no lo hemos recibido. Agradeceríamos nos lo enviaseis a la mayor brevedad pues lo requerimos para ciertas gestiones. Adjunto oficio-solicitud registrado. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2021-05-17','Tf. de su hermana Eusebia Fdez. Baez 924680861 El viernes le dieron el alta de la UHB , su familia se molestó pq no se le avisó. Se respetó su voluntad porque ella no quería que se le avisara , ni teniamos su tf.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-05-17','miguel, hablo con Evelyn 622253784, y compruebo que quién le pide la documentación es su banco de Liberbank, ya que el fallecido sólo tenía dos cuentas en Bbvva e Ibercaja. Le comento que no podemos darle esa información a un particular y que hablaré con su Asesor (Carlos 661761502)para que tramite la parte de nuestros dos tutelados. Hablaré con él para que me remita qué necesita para enviarselo cuando llegue.********************** Envío email a Coral para que me indique qué le falta para enviar la rendición final de este expediente. Mientras mando********************Llamo al asesor y no logro hablar con él******************Coral me indica que le falta la Declaración de ultimas voluntades','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-05-17','TERSA Tras pasar el informe facilitado a Dirección Médica me informa de la NO ACEPTACIÓN del paciente en este Hospital Psiquiátrico.SERENIL','2');
