insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-05-17','Ana: Conversación con Pilar Martín, TS ESM-CC: le explico que el cargo se ha aceptado la semana pasada, estamos en periodo de inventario. Aún no tenemos información de ningún tipo. *Intentará facilitarnos lo que pueda. No es urgente. Vive con la madre y es una remoción de la tutela que ya tenía.','2');
