insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-05-17','TERESA Respecto a la salida de Mª Elena el viernes 14 de Mayo a su pueblo con su hijo, no hubo ninguna incidencia. Regresó a la hora que le indicamos y al parecer todo fue bien. Hoy me ha comentado que quiere volver a ir con su hijo a su pueblo el sábado 22 de Mayo y según le he entendido le gustaría que pudiera hacerlo un día todas las semanas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-05-18','TERESA EMAIL TS PLENA INCLSUISION SOBRE ACERCAMIETO DE ANDRES Buenas tardes: Según nos informan, ha contactado el Dr. Pizarro con la UHB de Mérida y el psiquiatra finalmente lo deriva a la UHDAC de Plasencia, acompañado en el traslado por enfermero y celador con contención para evitar riesgos como el ocurrido esta mañana. Saludos ___________________________________________________________________ Asunto: RV: NOTIFICACIÓN INCIDENCIA ASB Hola otra vez. Comunicaros que finalmente nos dicen que en el camino en ambulancia desde Mérida a Cabeza del Buey, ASB ha tenido un intento de autolisis y se ha derivado otra vez a la UHB de Hospital de Mérida. Saludos ___________________________________________________________________________ Asunto: NOTIFICACIÓN INCIDENCIA ASB Buenos días: En relación al usuario ASB, procedente de la UHDAC de Plasencia, que está en periodo de acercamiento, informaros que en la tarde de ayer se produjo un incidente en el transcurso de una salida del centro. El usuario echó a correr dejando atrás a las 2 cuidadoras con las que sale (tiene ratio 2:1 todo el tiempo), y se acercó a dos chicas que estaban en el parque, a quienes empezó a tocar, abrazar, besar sin mascarilla y les quitaba el móvil, les pedía su número, etc. Ante esto las cuidadoras intentan por las buenas convencerle para que mantenga las medidas de distancia social pero no lo consiguen, y finalmente agrede a ambas cuidadoras con carácter leve (puñetazo y torcedura de brazo). Se vuelve a escapar y las cuidadoras le siguen hasta el centro. Una vez en el centro, el usuario entra corriendo y sube hacia un balcón de la planta alta para tirarse, y las cuidadoras del centro en varias ocasiones le bajan del balcón. Finalmente se necesita reducirle ante otro intento de agresión a cuidadoras, y por todo lo anterior se activa 112. Acuden al centro guardia civil, policía y médicos, y se le traslada en ambulancia de Soporte Vital hacia la UHB de Mérida. En Mérida, según consta en el informe del médico psiquiatra, se encuentra colaborador y dice que no quiere matarse y quiere volver a Cabeza del Buey, por lo que se le traslada de nuevo esta mañana al centro, estando de camino. Hemos hablado con la UHDAC, para su vuelta a dicha unidad , por lo que su MAP ha solicitado traslado especial hacia Plasencia acompañado. Aun no tenemos respuesta sobre si se autoriza este traslado especial ni el momento en el que se hará. Solicitamos a la UHDAC que se ponga en contacto con la UHB de Mérida o deje por escrito que en caso de nuevo episodio, tras el alta, el usuario sea propuesto para regresar a Plasencia, para evitar a la persona estar desplazándose innecesariamente por toda la Extremadura. Igualmente recomendamos a la UHAC que informe al MAP o servicios sanitarios para que dejen constancia de la medicación actualizada en JARA puesto que no hay registros desde mayo del año pasado, y es conveniente actualizar dicha información médica de cara a pautas de medicación y/o rescate. Según las conductas recogida, esta semana se muestra más obsesivo que en la anterior semana de acercamiento; está más desafiante, no participa en ninguna actividad propuesta, no respeta horarios ni rutinas establecidas, no respeta las normas mínimas, inoportuna e incomoda más a los compañeros de residencia (entra en habitaciones y no hay forma de que salga, se acuesta en la cama con las usuarias, quita el móvil a compañeros, besa en la boca a los compañeros, etc.), manifiesta que no quiere estar aquí, dice que quiere morirse o amenaza con autolesionarse, ha realizado intentos de ingesta de objetos, etc. En la calle no respeta distancias, sale a correr y se aleja de las cuidadoras, no usa mascarilla, intenta abrazar a personas desconocidas, pide dinero, pide teléfonos, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-05-18','Belén. Se envía documentación (PIA, Declaración Guardador de Hecho y contrato de ayuda a domicilio) según requerimiento de documentación para el nuevo servicio de ayuda a domicilio.','2');
