insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-05-18','Ana: En relación a los correos-e intercambiados con Amor, TS de ASPACE, relativos a los desperfectos ocasionado por Brahim en la habitación, así como a las consultas que realicé también por mail a Manuelas González, Jefa de Secc. RR. Discapacidad, llamo a Genoveva Gil González, Jefa Secc. Gestión de Convenios y Subvenciones (924 00 84 79: En principio considera que los arreglos/compras a causa de los desperfectos ocasionados por Brahim, pueden ser financiables con cargo a fondos públicos. No obstante me pide que le reenvíe los correos así como los presupuestos que adjuntaron para estudiar el caso. Darán una respuesta a la entidad y me pondrán en copia. **Guardo los correos en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-18','miguel, me comenta Juana que está la asesoria preparando la declaración de la renta de Damian y necesitan saber qué importes de alquiler poner. Pongo un email a la Abogada Rocio Gracian: Buenas tardes Rocio, estamos con la declaración de la renta de Damian, y teniendo el problema pendiente de solucionar con el inquilino, necesitaría lo antes posible, qué cantidad debemos declarar como recibida por Damian? Desde mi punto de vista si no lo ha recibido no tendríamos que declararlo es así? En cuanto sepas algo sobre si se marcha y en qué condiciones el inquilino avísame. ********************************************************* su contestación: Hola Miguel, Los temas fiscales no los trabajo, por lo que no puedo informarte sobre qué debe o no incluirse en la renta de Damián, ni tampoco se que cuantía ha cobrado en realidad. Con el inquilino sigo manteniendo contacto periódico solicitándole las facturas y los documentos que dice que tiene firmados por Damián de cantidades que según parece le pago, tal y como te conté por teléfono. El caso es que no me envía nada, siempre se excusa con que está empaquetando todo para irse y lo tiene que buscar.... Continuaré intentando tener buena relación para que se marchen en la fecha establecida y no encontrarnos más problemas Te informo de cualquier novedad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-05-18','Llamo al C. Salud de Alcuéscar (927 38 42 10) varias veces, no obtengo respuesta. ·············· Llamo al ESM-CC (927 213 730): Pilar, TS, me dice que en principio ella no tiene acceso a ciertos informes, tendríamos que solicitarlos por escrito pero además, dado que se trata de una incapacidad parcial para la gestión patrimonial, tampoco podrían enviárnoslos, pues no nos competen ni la esfera personal ni de la salud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-05-18','Ana: Llamo a la Residencia El Pendere - Aligex, de Santiago de Alcántara (927 59 21 35): La Directora no se encuentra, pero me atiende Gema, Admvo. Me informa de que Florencia está bien, nada más llegar no quería bajarse de la ambulancia y tuvieron que subirla en silla de ruedas a la planta. Al principio decía que se quería ir de allí, pero en estos pocos días ha comenzado a mostrarse agradecida. Está comiendo bien. La ducharon y sin problemas. Parece que poco a poco se va adaptando a estar allí. *Me enviarán email con el contrato y otra documentación necesaria. ··································································································································· Recibo correo de Gema, Admvo. Residencia (resisantiago@hotmail.com), con la documentación. *La pondré para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-05-18','Ana: Pilar Martín, TS del ESM-CC (pilar.martinp@salud-juntaex.es), me reenvía el correo-respuesta que le han enviado desde el INSS: "Buenos días, Pilar: Efectivamente, está cobrando una IP Absoluta, de cuantía 689,70. Si ha habido cambio de tutor se debe de comunicar por escrito a Control de Pensiones adjuntando copia del cambio. Saludos" ·············· Se lo reenvío a Icíar, secc. ecca. ················· Hasta que no puedan abrir una cuenta nueva no puedo comunicar el cambio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-05-18','Ana: Correo-e de Chema, Coord. Piso Cerujovi: "Buenas tardes, Ana. Simplemente comunicarte que el traslado de Darío López Gilarte se ha realizado hoy martes 18 de mayo por la mañana. Todo ha ido bien y no se ha producido ninguna incidencia reseñable. Estaremos en contacto con el recurso para ir estableciendo llamadas periódicas con su hermano, además de organizar las visitas. Toda la documentación de Darío ( informes médicos, dni, tarjeta sanitaria...) se han entregado a los responsables del recurso residencial. Por otra parte, les pase el contacto de Futuex y les expliqué cuales fueron las acciones que llevaron a cabo hasta el momento. Si necesitáis cualquier cosa, o tenéis alguna duda o pregunta no dudéis en contactar con nosotros. Un saludo y gracias por todo." ································································································································································································· Envío correo-e a Maribel (residencia@aprosuba9.org): "Buenas tardes Maribel, Tal y como acordamos ayer, te remito adjunto los siguientes documentos relativos a Darío López Gilarte: - Testimonio de firmeza de la sentencia - Testimonio de aceptación del cargo Ya sé que hoy el ingreso ha transcurrido con normalidad. Confío en que el joven se adapte bien. Ante cualquier cuestión seguimos en contacto. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-05-17','Ana: Llamada de Maribel, Responable de la VV.TT. de Inclusive, Vva. de la Serena (924 84 09 00): La entrevista del jueves con Darío fue bien. Se fue muy contento. *Su única pena es separarse de su hermano pequeño (de 15 años), quien también reside en el PP.TT. de Plasencia gestionado por Cerujovi. *Se programarán visitas periódicas para mantener los lazos familiares. *El ingreso se producirá mañana día 18. ··············· En cuanto a la beca de estudios concedida, desde el C.O. le van a apoyar para que mantenga la asistencia a clases de forma telemática y *tendrá que presentarse a los exámenes, para los que también le van a apoyar y a acompañar a realizarlos a Plasencia. ················· Maribel me pide que le envíe la Copia de la Sentencia y Aceptación del Cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-05-18','Ana: En relación a la llamada de Felisi y Jesús, pidiendo extra para la visita de su hijo y para unas zapatillas y ropa interior. *De entrada les explico a ambos que no es posible, que ya se les da todo lo que se les puede dar. No obstante veremos posibilidades de su hijo Aitor y consultaré a la secc. ecca. *pues piden que se les de de sus ahorros. ·············· Envío correo a Teresa, TS CTAEX: "Buenas tardes compi, Hoy me ha llamado Felisi Felipe Teomiro, tutelada por la CTAEX y madre de Aitor Moreno Felipe, dada la próxima visita de su hijo, pide que se le aumente la asignación para “tener la nevera llena” cuando vaya su hijo. Darle un extra a priori no es viable, le dan toda lo que pueden darse en las asignaciones semanales (tiene una PNC, paga alquiler y suministros). Antes percibía la PFHC, por su hijo, ahora ya la percibe Aitor (quién imagino que pagando el centro tampoco debe quedarle mucho margen). La cuestión es ¿cuánto dinero se le va aprobar a Aitor para la visita? Es para ver si se le puede dar algo más dadas las circunstancias. Si no es viable, tendrán que amoldarse a lo que hay. Vamos viendo. Mañana hablamos. Buena tarde." ··············· Y otro a Juana y Alberto, Secc. Ecca.: "Buenas tardes a los dos, De entrada, ya sé que a Felisi Felipe Teomiro se le da semanalmente todo lo que se le puede dar, en base a sus escasos ingresos y sus gastos. De hecho les he dicho que en principio no creo que pueda ser, pero que lo consultaría con la sección ecca. No sé como están sus ahorros, ¿sería posible autorizarle para unas zapatilla y ropa interior? Si fuera así pediríamos a Futuex que la acompañen pedir presupuesto. Si no puede ser, pues nada, se lo diré de nuevo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-05-18','Ana: Envío correo a Julio, Amalia y Alberto CTAEX: "Buenas tardes a todos, En relación a Francisco Cacho Garrido, comunicaros el cambio de recurso a la VV.TT. Salud Mental de Mérida. - Julio, porfa, te encargas del cambio en la base de datos cuando puedas. - Alberto, Manuel Picado es el nuevo coordinador del recurso (manuel.picado@salud-juntaex.es), ha enviado presupuesto de gastos (no lo he abierto) - Amalia, me falta poner al día la Intranet, no me ha dado tiempo a poner las últimas anotaciones. Durante el periodo de adaptación sigo yo pen diente, después ya “todo tuyo” para el seguimiento. A ver qué tal funciona. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-05-19','-Amalia : correo de respuesta del ESM : Respecto a Mercedes, acude a las consultas de seguimiento en el ESM, tiene adherencia. En cuanto a la medicación pues nunca podemos determinar si el tratamiento lo hace correcto, no tiene supervisión, esa duda siempre está. Por indicación de su psiquiatra, me señala que Mercedes es una paciente con un diagnóstico cronificado y residual,... Considero que para abordar la situación de Mercedes, sería mejor una reunión con su psiquiatra para valorarlo en conjunto. Estamos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2021-05-19','Buenos días Amalia: Por este medio os comunicamos y pedimos autorización para que Daniel Montaño, en algunas ocasiones (suele coincidir con jueves o viernes), pueda cambiar su parada de bajada del autobús que hace el trasporte al centro ocupacional. Cuando va a pasar un ratito a casa de su abuela, pide que le dejemos en la calle Isidro Pacense, cuando suele bajar en Carolina Coronado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2021-05-19','Pedro Sudón ingresó ayer por la tarde en el hospital de Merida en la UHB . Desde el CSS les dijeron qu su psiquiatra del ESM les hiciera un cdo. para el ingreso y lo llevaron por la tarde al hospital .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2021-05-19','miguel, llega email de Rafa su hno: Buenos días, Miguel Ángel ¿Que tal todo? Espero que bien. Necesito que presentéis la renuncia de mi hermano, evidentemente, de forma telemática, en el Registro de la Junta de Andalucía. Yo no he podido hacerlo, al no disponer de autorización vuestra, que sois los que lo tutelan. Si tenéis alguna duda o consulta, me lo dices. Muchas gracias. *****************************mi contestación: Buenos días, efectivamente no te la remitimos en su día. Quieres que te la envíe el viernes por carta certificada tanto la escritura original como la autorización para presentarla en el Registro de la Junta de Andalucía (en cuyo caso tendrías que escanear y remitirme la correspondiente solicitud de presentación en dicho registro de la Junta de Andalucía). Caso contrario, necesitaría me indicaras los datos de dónde dirigir el registro de salida de dichas escrituras. Gracias, y disculpa pues pensé que te la habíamos remitido hacía tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-19','miguel, recibo email de Damian, con las siguientes cuestiones: 1)informarme que el lunes día 24 empieza en CRR de Mérida 2)quiere una modificación en sus cantidades mensuales. 3)cómo va el asunto del juzgado (procedimiento de desahucio) 4)de algún juzgado le han llamado (no sabe si la policía)pidiendole la denuncia que en su día interpuso contra quies le robaron 5000€ de un centro para pedirle el nº de cuenta. Le vuelvo a explicar que las cuestiones económicas las hable con ellos, las dudas generales que platea y no sean judiciales que las hable con su trabajadora social. ************************************ Manda el siguiente email: Acabamos de hablar hace un momento gracias por todo decirle para decirselo al juez que la medicacion de anoche la tire toda al water y ayer como la medicacion me hace tanto efecto me tome 6 cafes y una bebida energetiva con ginseng taurina etc.....porque tenia las dosis de medicacion muy altas y ahora mismo tambien para que le comente al juez que acabo de recoger en medico de cabecera los resultados de una analitica especifico sobre la alimentacion y me han detectado que soy intolerante a la lactosa y a partir de este momento tengo que comer tanto como lo que me queda en el CRR de plasencia y cuando el lunes 24 de mayo cambie y me incorpore al CRR de merida me tienen que hacer el menu sin lactosa escrito e informe echo por medico de cabecera con pruebas en mano que entrego a la monitora maru del CRR de plasencia para que ya hoy jueves 19 de mayo me ponga cocina el menu sin lactosa comuniqueselo al juez.muchas gracias y que tiene usted muy buen corazon esto de la lactosa tambien se puede presentar cuando presentemos de nuevo los papeles para que me putuen a ver si me dan grado 1.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-05-19','TERESA Buenas tardes Teresa, solo para información. Hoy día 18 de mayo, AITOR MORENO FELIPE, ha recibido la visita para la revisión Grado de la Ley de la Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-05-19','miguel, llama Adrian el arquitecto de la obra de C/ GEenarl Margallo. Le comento que por error del juzgado de Logrosan nº1 han enviado para que informe el el MF de Cáceres (ya que por error lo mandaron al de Plasencia). Recordemos que este procedimiento de gastos extraordinarios se inició en el Juzgado de Plasencia, quien se declaró incompetente una vez que el tutelado se fue a vivir a Guadalupe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-05-19','Ana: Correo-e de ayer por la tarde de Felisa Custodio, TS CAMF-Alcuéscar (trabajador_social_alcuescar@imserso.es): "Hola Ana, en relación al correo que me mandaste el pasado 23 de marzo y que figura abajo, te comento que la residente insiste de forma reiterada en salir al exterior con este señor argumentando que ya no hay estado de alarma. Me pide mi directora (le pongo copia de este correo) que os traslade la petición para ver que opináis al respecto. Saludos." ··············· Reenvío el correo a Ángel y Miguel, Asesores Jurídicos, para trasladarles la consulta y puedan dar respuesta con los argumentos legales oportunos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-19','Ana: Correo de David Lefevre, Consulado de Francia en Madrid (david.lefevre@diplomatie.gouv.fr): "Buenos dias Ana, Seria posible que me remitieras copia de su DNI español y su DNI o pasaporte francés (si lo tiene)? Verificaré si tiene nacionalidad francesa y te indicaré como renovar su DNI francés. Mi telefono de contacto : 91-700-78-36 o 78-39 o 78-14 Un saludo David LEFEVRE Service des Affaires Sociales / Servicio de Asuntos sociales" ···················· Tras revisar expte. de nuevo, envío correo a Sandra, Res. de Mayores del Real Patronato - Coria (alexandra.alfonso@coria.org): "Buenas tardes Sandra, En relación a la renovación del DNI de Rosario, el Subinspector de la Policía Nacional de la Ofician del DNI, se puso en contacto conmigo para informarme de que cuando procedieron a grabar los datos, no pudieron realizar los trámites porque les constaba que esta Señora tiene nacionalidad francesa. Puesto que a día de hoy tampoco tiene renovada su Carta de Identidad de Francia, está como “ilegal” en España. *Ya estoy en contacto con el Consulado de Francia en España, pero me preguntan desde allí si tenemos algún documentos más antiguo de ella (a ser posible Pasaporte o Documento de Identidad Francés). He vuelto a revisar su expediente físico de arriba abajo pero no hay ningún documento identificativo ¿Podríais confirmarme si tenéis alguno en la residencia? ¿O incluso contactar con su hija (anterior tutora) por si tuviera ella al menos alguna copia antigua?? Ya me dices. Pongo en copia a mi compañera Juana, para que esté al corriente. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-05-20','Amalia : datos del nuevo recurso Cambio de recurso - Francisco Cacho Garrido Julio!! Perdona, el Piso Supervisado es de gestión directa del SEPAD, no había caído que hasta ahora no teníamos a nadie allí. Te anoto dirección, teléfono, mail y persona de contacto: Avda. de Portugal, 17, portal 4, bajo B. 06800 – Mérida (Badajoz) Telf. 606 993 766 // 924 38 81 79 Coordinador: Manuel Picado Méndez: manuel.picado@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-05-20','TERESA APRUEBAN ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='FARIÑAS'and apellido2='SOTO'),'2021-05-20','EXITUS El centro comunica, mediante oficio de 13/05/2021, su fallecimiento, acaecido el 12/05/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-20','Ana: Correo-respuesta de Sandra, TS de la Res. Mayores (alexandra.alfonso@coria.org): "Buenos días Ana, te mando la fotocopia que tengo en el Expediente que en su día me enviásteis vosotros. Si no os sirve, me vuelves a escribir e intento contactar con su hija. Un saludo" **Guardo la copia en el Expte. E la tarjeta de Residente del Régimen Comunitario (aparece el NIE y la Nacionalidad) ···························································································································································································· Envío correo a David Lefevre, Consulado de Francia en España (david.lefevre@diplomatie.gouv.fr): "Buenos días David, Te envío adjunto lo único que tenemos de Rosario González Jorna, espero que te sirva, aunque no se ve demasiado bien, pues por lo pronto no hemos conseguido ningún otro documento, a excepción de su Certificado Literal de Nacimiento. Tomo nota de tu número por si tengo que contactar, el mío directo es el que aparece en la firma. Ya me vas informando. Ante cualquier cuestión seguimos en contacto. Gracias y un saludo." ················ En nuevo corro David me solicita también el Certificado literal de Nacimiento. Se lo envío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-05-20','Ana: Envío correo a Alberto, Julio y Tere - CTAEX: "Comunicaros que el joven Darío López Gilarte, cambió de recurso residencial el pasado martes 18 de mayo. Ha pasado del Piso Tutelado de Menores de Plasencia a la Vivienda Tutelada de Inclusive de Vva. De la Serena. • Julio: ¿Puedes cambiarlo en la base, porfa? • Alberto: Ya os ponéis en contacto para el pago de la plaza y el presupuesto de gastos. *De momento sólo tienen en la cuenta la beca de estudios que le concedieron, pero precisamente hace unos días no s han comunicado ya la aprobación de la PFHC con fechas de efecto: 1/07/21 (399,20€/mes x 12) • Tere: de momento, durante el periodo de adaptación me encargo yo, de papeleo y demás. Una vez haya pasado dicho periodo, ya podrás hacer el seguimiento. La Coordinadora se llama Maribel. Tlf. 924 84 09 00 Email: residencia@aprosuba9.org El domicilio de la sede es: Ctra. de La Haba s/n. Pero la vivienda no estoy segura si es en la Carretera de Circunvalación. Lo he preguntado, en cuanto me contesten os digo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2021-05-20','TERESA ENVIO SOLICITUD DE CERRTIFICADO DE NACIMIEENTO A AYLLON','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-05-20','Ana: correo de Sonia Bernavé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, te he estado llamando porque quería informarte que ayer fue derivado a Salud Mental de Cáceres Aarón Rosado Alarcón. Tuvo alteración de conducta agrediendo a compañeros, profesionales e incluso a los Policías Municipales que vinieron hasta que la Guardia Civil llegó. No sabemos todavía el tiempo que estará ingresado. Por lo que recuerdo no lleva ni 15 días en el centro. Su padre, actualmente, también está en el hospital y no hemos podido contactar con él. Cuando tengamos más información por parte del Psiquiatra que le atiende, os comento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-05-20','Ana: correo de Icíar, ya está el inventario hecho. Averiguaré si vive alguien en su domicilio (creo que no, pero lo corroboraré) para dar de baja los suministros y otros gastos asociados al mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-05-19','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "... el padre de Justo y de Roberto Hernández Castaño, me ha llamado porque quiere que vayan a casa sus hijos para poder verlos. En todo el tiempo de pandemia le han venido a visitar una vez hace ya bastantes meses. Informé al padre que tenía que hablarlo con vosotros ya que hay que firmar solicitud de salida y tendríamos que ver el transporte. Cómo lo podríamos hacer? Normalmente los pocos residentes que se van a casa lo hacen por un periodo de una semana o más, en el caso de Roberto, no sé si será conveniente que se marche tanto tiempo porque luego le cuesta mucho el regreso y el control de la medicación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-05-19','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "... el padre de Justo y de Roberto Hernández Castaño, me ha llamado porque quiere que vayan a casa sus hijos para poder verlos. En todo el tiempo de pandemia le han venido a visitar una vez hace ya bastantes meses. Informé al padre que tenía que hablarlo con vosotros ya que hay que firmar solicitud de salida y tendríamos que ver el transporte. Cómo lo podríamos hacer? Normalmente los pocos residentes que se van a casa lo hacen por un periodo de una semana o más, en el caso de Roberto, no sé si será conveniente que se marche tanto tiempo porque luego le cuesta mucho el regreso y el control de la medicación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-05-21','TERSA El pasado 14 de Mayo se recibió una llamada de María, de la empresa de servicios sociosanitarios de Almendralejo (605 87 42 32) para comentar que el auxiliar de ayuda a domicilio de Bartolomé Colchón Carmona estaba llamando a la puerta de su piso y no le abría nadie ni escuchaba a nadie en el interior. María llamó a la policía para comentar el caso y tanto ella como Alexis se acercaron al piso de abajo de Bartolomé, que tenía una copia de la llave, para que les abriera. María comenta que cuando abren la puerta del piso, se encuentran con una chica latinoamericana dentro, que comenta que lleva unos días viviendo en el piso de Bartolomé con su pareja. Ella cuenta que cuida mucho de Bartolomé y le hace la comida. Pero cuando acceden al piso, se dan cuenta de que está muy revuelto y hay cosas tiradas por el suelo, además no hay señal del tutelado. Al cabo de unos minutos se presenta la policía local y le dicen a la chica latinoamericana que tiene que salir de la vivienda porque el dueño de la misma no está allí y ella no puede permanecer allí. Cuando se termina de hablar con María, se llama al móvil de Bartolomé pero lo tiene apagado. Seguidamente se llama a Antonia Morán de los SSB de Almendralejo (682 20 90 60) para informarla de la desaparición de Bartolomé. También se habla con Elena, la trabajadora social de FEAFES Almendralejo (924 66 46 77), y se le pregunta si ha visto a Bartolomé últimamente. Ella cuenta que el tutelado estuvo en la sede hacía unas semanas acompañado de una chica y pidiendo ayuda para ella, se le dió cita para que volviera a acudir y no había vuelto. Por último se llama al hospital de Mérida y se habla con el personal de la UHB (924 38 10 49) para preguntar si Bartolomé estuviera ingresado, contestan que si. Se habla con la Dra. Álvarez, que es la psiquiatra que lleva su caso y cuenta que todavía no ha podido verle porque están a la espera del resultado de la PCR que se le ha hecho durante la madrugada. Bartolomé se encuentra en la unidad, aislado hasta que salgan los resultados. El pasado 18 de Mayo se llamó por teléfono a la UHB de Mérida y se habló con la Dra. Álvarez, la psiquiatra que llevaba el caso de Bartolomé Colchón Carmona, que reside en Almendralejo. La doctora comentó que le había dado el alta al tutelado el día anterior ya que el paciente se encontraba muy estable y tranquilo, sin alteraciones de ningún tipo. Bartolomé le había contado a la psiquiatra, que él tiene una amiga latinoamericana en Almendralejo, Poliani, y la dejó que pasara unos días en su casa hasta que encontrara otro sitio en el que vivir. Pero cuando Bartolomé le pidió amablemente que se marchara, ella no quiso y empezaron a discutir hasta el punto de provocarle a Barto un ataque de ansiedad. De hecho fue él mismo el que llamó a la ambulancia y pidió que le ingresaran en la unidad de Mérida hasta que estuviera más tranquilo. Bartolomé ha estado ingresado en la UHB de Mérida desde la madrugada del 13 a la tarde del 17 de Mayo. También se queda por recabar más información sobre el motivo del ingreso de Bartolomé, ya que los vecinos de su bloque han comentado que hubo una gran pelea durante la noche del 12 de Mayo pero no se ha podido ampliar más la información. Se seguirá investigando sobre este tema y se mandará otra nota en cuanto se sepan más detalles.','2');
