insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-21','Ana: Correo de David Lefevre: "Estimada Ana, Te informo de que nuestro consulado no ha encontrado ninguna prueba de que la Sra. GONZALEZ JORNA tenga la nacionalidad francesa (con esta identidad) NO hemos encontrado nigun DNI francés o passaporte francés. Tampoco hemos encontrado nada al nivel del registro civil francés (no he encontrado ningun acta de nacimiento o de matrimonio) o a nivel de la nacionalidad (no he encontrado ninguna adquisición de la nacionalidad francesa) Atentamente," ··················· Me pondré en contacto de nuevo con la Policía Nacional y con la Brigada de Extranjería. ····························································································································································································· Llamo al Subinspector Vasallo, Policía Nacional - Oficina DNI (927 62 90 92): No obtengo respuesta. ························································································································································································· Llamo a la Brigada de Extranjería - CC (927 62 65 25): tampoco obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-05-20','Ana: Correo de Minerva, TS C.R. Cervantes (minerva.salvador@salud-juntaex.es): "Buenos días Ana, soy Minerva, me gustaría poder hablar contigo sobre el asunto de las salidas de Mª Luisa al banco, y también si has podido averiguar en qué centro está ingresada la hija de Mª Luisa. Espero tu respuesta. Gracias y un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-05-21','Ana: mi respuesta al correo de ayer de Minerva, TS CR Cervantes (minerva.salvador@salud-juntaex.es) : "Buenas tardes Minerva, Te he llamado. Hasta ahora lo que te puedo decir es que Carolina, hija de Maria Luisa, no está residiendo en el CRR de Plasencia. En cuánto al tema del banco, ¿cuál es el problema? Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2021-05-21','miguel, la notaria de Mérida me confirma que lo único que tienen es la escritura de ratificación de la herencia y nos dan una escritura autorizada cuya transfrencia le hacemos hoy y se la mando a la notaria por email. Mientras ayer hable con la notaria de Cáceres de D. Carlos del Solar Barroso y el de escrituras quedó en llamarme (no lo hizo) Hoy envío justificante de haber pagado dicha escritura de renuncia de herencia y le indico a Antonio por email que se lo dé a su compañero de copias y me remitan al SEPAD las escrituras','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-05-21','Ana: Llamo a Lucía, TS de la Residencia El Conquistador de Trujillo (660 963 767): que ella sepa no vive nadie en el domicilio de Félix. No obstante, cree que la "pareja" de Félix tienen llaves de dicha vivienda. *Me indica que pregunte en el SSASB. ······· **Posiblemente habrá que cambiar la cerradura de la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-05-24','miguel, email de Damian: PERSONAL.--DAMIAN SALVADOR GRANADOS HEREDIA , TIENE PENDIENTE RECOGER DOCM. EN EL SERVICIO NOTIF, JUZGADOS MERIDA, RFE 4023/21, CITANDOLE HASTA EL DIA 24/05/2021 ,DE 9 A 14 H. FNO.CONTACTO 924.31.78.82,924.387427. VENDRA CON MASCARILLA, BOLIGRAFO, SIN ACOMPAÑANTE, Y D.N.I************************************************ Don miguel buenas tardes me han mandado un mensaje de texto ordinario para presentarme como ultimo dia mañana de 9 14 y no me da tiempo a llegar a los juzgados de merida mañana salgo para merida a las 12 de la msñana de aqui de plasencia y pone que valla con boligrafo mascarilla y sin acompañante a lo mejor me piden un numero de cuenta para ingresarme n dinero me pide que valla sin acompañante con mi D.N.I es urgente mañana ultimo dia es mañana.notificacion.juzgados de merida RFE 4023/21 citandome hasta el dia 24 de mayo que es mañana y no me da tiempo a llegar de 9 a14 horas estos son los telefonos 924317882 y el otro 924387427 ayudeme por favor que no me da tiempo a llegar.gracias y es para cobrar un dinero**************************************************** Yo voy muy tranquilo a preguntarle que la lavadora le quedan 6 minutos y me contesta que yo ocupo todo el tiempo la secadora me cagué por las patas abajo y a pesar de decirle que me voy mañana me habla mal*********************************************************Mi contestación: Buenos días Damian, si no me adjunta el documento no podré localizar el juzgado y el procedimiento para el que le han citado. La otra opción es que usted les llame y les comunique que hoy no podrá asistir','2');
