insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-05-24','Ana: Envío correo a Manuel Casado, TO EVD (manuel.casado@salud-juntaex.es) con copia a Paz Boticario, TS Cruz Blanca (et-caceres@cruzblanca.org): "Buenos días Manuel, Tras habernos enviado desde la entidad Hermanos de la Cruz Blanca Aceptación PIA de Alejandro Montero Vázquez, tutelado por la Comisión Tutelar de Adultos de Extremadura, me pongo en contacto contigo para comunicar que el Tutor Legal (Persona Física que ostenta el Cargo), ya no es Consolación Serrano Gía. Desde hace algo más de año y medio el cargo de Presidente de la Comisión Tutelar de Adultos es ejercido por D. José Vicente Granado Granado, actual D-Gerente del SEPAD. Te envío adjunta documentación Acreditativa. ¿Podrías, por favor, hacerme llegar a mí la ACEPTACION DEL PIA para que la pueda poner a la firma? En cuanto la tenga firmada le daré registro de entrada. Ante cualquier cuestión no dudes en contactar. Gracias y un saludo. PD: Pongo en copia a Paz Boticario, para que esté al corriete." ································ Una vez me envía Manuel Casado la Aceptación del PIA actualizada la subo al portafirmas digital. ················ Una vez firmado digitalmente, pido a Belén, TS CTAEX, que lo ponga para REGISTRO DE ENTRADA.','2');
