insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-05-24','Ana: Correo del viernes de Estrella, TS CSS Plas (estrella.duranc@salud-juntaex.es): "Hola Ana. Te escribo para informarte que ayer se fue Desi junto a su pareja de pase a casa hasta el viernes día 28. He hablado con Futuex y me han comentado que vendrán la semana que viene a verlos. Me preguntan si proceden como siempre con tema del dinero. Le he dicho que creo que no, ya que el viernes vuelven aquí y previsiblemente a principios del mes que viene sigan aquí (que es cuando le permiten que retire una cantidad) con lo que si necesitan algo, con la autorización vuestra le extraemos nosotros. Por otra parte, ya la hemos valorado la dependencia y ha dado un Grado II, así que le indico a la profesional de Futuex que en su visita trabajen con ella el tema de una Ayuda a Domicilio. Dime que os parece a vosotros, estas dos cuestiones, tema dinero mensual y tema Ayuda a domicilio..." ·································································································································································································· Mi respuesta: "Buenos días Estrella, Gracias por informar. Ok a la cuestión económica. En cuanto al Servicio de Ayuda a Domicilio, siempre nos ha parecido una buena opción, pero Ángel siempre se ha negado, y tú sabes que Desi suele aceptar todo lo que dice Ángel. Por otra parte, como Ángel no está tutelado, es más difícil la intervención por parte de las compañeras de FUTUEX. Pero claro que se puede plantear, ya te digo que se valoró e intentó en su día. En relación al Grado de Dependencia, estupendo, cuando sea posible, por favor, envíame la resolución. Ya me vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-05-18','Ana: Correo de Leonor Chamorro, CRR BA (lchamorro.sanmiguel@hospitalarias.es), a Icíar en el ctutelar@: "De acuerdo, Icíar. He hablado con Teresa, delegada de Futuex y le acompañará a comprar la ropa el jueves por la tarde; por lo que necesitamos cita para Liberbank mañana o pasado por la mañana para que lo pueda sacar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-05-24','Ana: Envío correo a Toni-Futuex (areasocial3@futuex.es), preguntando por la evolución y adherencia de José Manel al recurso. Y qué tal lo notó Teresa el jueves. ····························································································································································································· Llamada de José Manuel: dice que se quiere ir a su casa a Cáceres. Que ha hablado con Amalia-CTAEX y que ésta le ha dicho que si se quiere ir que lo haga. Que cuando perciba su asignación el 1 de junio que se marche. *Le digo que en mi opinión no debería irse, pues en su casa tampoco estará bien, de hecho estará peor y allí no cuenta con los apoyos y recursos que tienen en el CRR. Desde la CTAEX no se va a firmar nada. Otra cosa es que sea él quien firme el alta voluntaria y se marche.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-05-21','Ana: Comunico a Tere y Julio, CTAEX, la dirección de la Vva. Tutelada de Inclusive en Vva. Serena: C/ Olivo Gordo nº 50 06700 Villanueva de la Serena','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-05-24','Belén. Se envía consentimiento para revisiones médicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-05-24','Belén. Se envía alta de terceros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-24','Ana: Llamo a la Brigada de Extranjería - CC (927 62 65 25): el último trámite que realizó Mª del Rosario fue en el año 2.000, pero en alquel entonces no se hacía en la Policía, se hacía en la Subdelegación del Gobierno. En la Brigada no tienen ningún documento suyo. ······························································································································································································· Llamo a Delegación del Gobierno en Ba (924 97 90 00), me pasan con Extranjería: comprueba los datos. Corroboran que el último trámite se llevó a cabo en la Subdelegación del Gobierno en CC, en el Negociado de Extranjeros en el año 2000, Tarjeta de Régimen Comunitario. Allí tuvo que presentar algún documento oficial para poder realizar la gestión. *El primer trámite lo hizo en 1993 en el Registro Central de Extranjeros (Madrid). *Me facilita una dirección de correo-e para que realice la consulta: oficina_extranjeros.caceres@correo.gob.es ······························································································································································································· Envío un correo a dicha dirección: "Buenas tardes, En relación a Dña. María del Rosario González Jorna, Incapacitada Judicialmente y tutelada por la Comisión Tutelar de Adultos de Extremadura, me pongo en contacto con ustedes tras haber consultado en la Policía Nacional (Oficina del DNI), en la Brigada de Extranjería, en el Consulado de Francia en España y finalmente en la Delegación de Gobierno. Me indican que tiene nacionalidad francesa y que a día de hoy está indocumentada. Pero en el Consulado de Francia tampoco les consta como ciudadana francesa. Los únicos documentos que tenemos en el expte. son el Certificado Literal de Nacimiento y una copia de una Tarjeta de Residencia de Ciudadana Comunitaria (adjunto ambos). El último trámite que realizó al respecto, según me han informado, fue en el año 2000 en la Subdelegación de Gobierno de Cáceres, en el Negociado de Extranjería. Pero la citada tarjeta está caducada desde 2005 y no volvió a renovarla. En el Consulado, para poder expedir el Pasaporte, necesitan un documento que la reconozca como ciudadana francesa, pues me dicen que no encuentran nada que lo demuestre. ¿Podrían, por favor, localizar y enviarnos copia, del documento que presentó en su día para que le expidieran dicha Tarjeta de Régimen Comunitario? Adjunto así mismo el Testimonio del Acuerdo de Aceptación del Cargo de Tutor. Espero su respuesta y ante cualquier cuestión no duden en contactar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-05-24','Ana: Llamada de Minerva, TS del C.R. Cervantes: En el centro han acordado que para la retirada de la asignación semanal, puesto que Virginia-Futuex no puede acudir todos los viernes rigurosamente, continúe acudiendo al banco con el ordenanza como ha venido haciendo. Y que Virginia le acompañe a otras gestiones puntuales así como a compras. ········· *En cuanto a esto último, cuando Virginia la acompañó la última vez a comprar ropa, Mª Luisa se negó, porque decía que qué era eso de abonarlo mediante transferencia, que las cosas se pagaban con dinero... y no hubo forma de convencerla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2021-05-24','-Amalia : Buenas tardes , he hablado con Miguel , para saber qué opinaba al respecto . Lo que me dice es que le da miedo ,pero que no le importa operarse , lo que no quiere es que sea en verano . Le comento que la opción de elegir fecha no creo que sea posible pero que lo comente con el médico . La decisión final sobre operarse o no la ha de tomar él libre y voluntariamente , no vamos a interferir en esa decisión. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-25','Ana: El correo que envié ayer a la Subdelegación, no se ha entregado, da erro en el envío. ··············· Llamo a la Subdelegación de Gob. en CC (927 749 000), me indican esta otra dirección de correo: oficina_extranjeria.caceres@correo.gob.es *Reenvío el correo de ayer. ············· También da error en el envío. Vuelvo a llamar y me facilitan un número de la Oficina de Extranjería: 927 74 91 51. Aquí me facilitan otra dirección de correo: personal_extranjeria.caceres@correo.gob.es a la que vuelvo a reenviar el correo de ayer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-05-25','Ana: Reenvío la respuesta de Ángel, Asesor Jurídico CTAEX, a Felisa Custodio: "Buenos días, compis, En mi opinión, mientras el covid continúe, debe cumplir, al igual que hacemos el resto de ciudadanos, con las medidas que el Ministerio de Sanidad recomienda a la ciudadanía, esto es: - Uso de mascarilla. - Distancia de 2 metros. - Lavado de manos frecuentes. - MENOS CONTACTOS Y EN UNA BURBUJA ESTABLE. Que no parece se cumpla en este caso. Además, parece ser que esta persona tiene más parejas, lo que incrementa el riesgo. A los efectos de no impedir a Isabel que pueda ver a “su pareja”, ya les contestamos en su día, autorizando las visitas, una vez a la semana con una hora de duración en la recepción del CAMF, siendo un entorno contralo y en el que además se pueden extremar las medidas anticovid. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2021-05-25','Ana: Llamada de María, Directora del C.R. Fco. de Asís, Aldea del Cano (927 194 889): Les han concedido un turno de vacaciones del 7 - 13 de junio, en un chalet, irán sólo residentes. Pregunta si Inés puede acurir. Puesto que seguirán manteniendo todas las medidas anticovid, por mi parte no hay inconveniente en que asista. *El precio son 350€, me enviará un correo. Por otra parte me indica que necesita unas zapatillas y un bañador. Como apenas gasta dinero de bolsillo, se lo comprarán con su asignación y enviarán los tiquets. ·················· Hablado ya con Alberto y Belén, secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLAUDIA LORENA'and edp.apellido1='CAMPUS'and apellido2='ANTE'),'2021-05-25','Belén. Se envía consentimiento informado para procedimientos con anestesia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2021-05-25','miguel, logro hablar con la notaria de Cáceres que me confirman que envían hoy por sobre certificado la escritura de renuncia de herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-05-25','Ana: Llamada de Minerva, TS del C.R. Cervantes (22237): Han llamado a la Res. desde la Comunidad Terapéutica para mujeres Charo Cordero de Plasencia, han hablado con la Directora y le han dicho que la hija de Mª Luisa está allí. Y que al parecer ha hablado con su madre y han acordado que pasarán alguien del recurso el viernes a recoger un sobre con 15€. ······· Tras esto, Minerva, TS, ha llamado a dicha Comunidad Terapéutica, ha hablado con Carolina, TS, del recurso. Al parecer Carolina, hija, ha sido derivada del Centro Victor Guerrero de Vva. de la Serena, hace un mes. Según informa la TS, parece tener las ideas claras y estar bastante centrada. De hecho va a comenzar en la lanzadera de empleo. El tratamiento dura apróx. 9 meses. **Acuerdan que cuando haya pasado algunos meses más, volverán a hablar para ver evolución y si procede organizar una visita. *En cuanto al dinero, de momento no se va a autorizar a darle nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2021-05-25','miguel, llega el certificado de nacimiento del registro civil de la curatelada y se lo envío a Ana de la notaria de Romero Leal. Intentaré firmar la ratificación de la compraventa hoy mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-05-25','Ana: Recibo correo de Choni, TS de SSASB de Miajadas y responsable de los PP.TT.: "Buenos día Ana , hoy, Esteve Pascual ha tenido consulta en urología para retomar la intervención quirúrgica que se ha suspendido en varias ocasiones con motivo de las crisis que ha presentado últimamente. Te adjunto el documento del consentimiento informado para recabar la firma del representante, espero que este nuevo intento sea definitivo, y pueda realizarse la intervención. saludos." ··········· Falta la segunda página. Pido que me la envíen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-05-25','Ana: Llamada de Francisca, madre de Isabel (639 019 336): Se le hará una transferencia de 20 € para visitar a su hija en el CSS este próximo fin de semana. Le informo que podrá retirarlo el jueves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-05-25','Belén. Se envía aceptación PIA para mantenimiento del servicio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-05-26','Ana: Correo de ayer por la tarde de Sonia Bernbé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería comunicarte que Aarón ha tenido que ser ingresado nuevamente. Por lo que me han trasladado según entraba en Alcántara se ha puesto nervioso en la ambulancia dando golpes a las ventanas. Al llegar ha entrado en el centro acompañado de un celador y del conductor de la ambulancia, y ha empujado a dos profesionales e insultado a cualquier profesional que le saludaba o le preguntaba cómo se encontraba. Ha sido necesario llamar al 122. Mañana hablaremos con el psiquiatra que le atiende. Un saludo," ·············· Contesto y le recuerdo que deben seguir informando a la U.G.PP.AA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-05-25','Ana: Correo respuesta de Toni-Futuex (areasocial3@futuex.es): "Hola Ana! que tal? espero que la semana vaya bien o lo mejor posible, te contesto al email de ayer, actualizandote un poquito la situación de JMRM, dentro de lo que cabe no va mal. Tenemos pensado ir con el, de nuevo a comprar ropa este proximo viernes, ya que tenia que retirar dinero para ello esta semana. Adjuntamos nota informativa sobre las gestiones iniciadas y desarrolladas con José Manuel Romero Mediavilla. Muy demandante y dependiente de los profesionales que siguen su proceso. Llamadas diarias telefónicas a este equipo de apoyo social comunitario de Badajoz, al 112 ,a urgencias, ya ha estado una vez allí. Repite eventualmente que quiere marcharse a Cáceres, pero sin ideación o planificación del mismo, más como una secuncia esterotipada. Por lo tanto hasta el momento actual, podemos afirmar que aunque existen situacuiones de querer irse de inmediato ante sus situaciones de ansiedad e impaciencia, seguimos trabajando para que avance en su adaptación. Seguimos realizando acompañamientos a gestiones de retirada de asignación, compra tabaco, recarga telefónica, compra de ropa ect. sin incidencias reseñables. Siempre demandante, pero correcto en las visitas, sin incidencias. Adjuntamos nota, al respecto." ················ Guardo nota en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-05-26','Ana: Mi respuesta al último correo de Toni-Fututex: "Buenos días Toni, Me alegra leer que “no va mal”, en la nota queda bastante claro la evolución e intervención por vuestra parte. A la CTAEX también llama a diario, yo hablo con él con frecuencia (estoy intentando no hacerlo todos los días…) y me consta que con Amalia también ha hablado en más de una ocasión. Aunque el periodo de adaptación ya ha finalizado y tendría que pasar a la zona de Amalia, sigo pendiente y atendiéndole, dado que el proceso de adherencia al CRR no está siendo fácil… Con su hermano José Luis también he hablado en distintas ocasiones. Cada vez que me llama, planteando el querer irse, la conversación finaliza, tras la exposición de motivos por mi parte y promover que reflexione mínimamente, con el reconocimiento por su parte de que en Cáceres tampoco estaba bien ni lo va a estar si vuelve, de hecho estaba peor en muchos aspectos antes de ingresar en el recurso. En mi opinión hay que seguir intentando que se adapte, pues es en un recurso donde tiene mejor cubiertas sus necesidades y cuenta con el apoyo de profesionales. En cuanto al hijo… siempre ha supuesto un foco de más conflictos y complicaciones para él… Y en relación a su hermano José Luis, sabe que José Manuel está mejor en un recurso, pero cuando lo escucha quejarse con tanta insistencia, le da miedo que vuelva a realizar algún intento autolítico. Pongo en copia a Amalia para que esté al corriente y por si quiere aportar algo. Seguimos en contacto. Gracias y buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-05-26','TERESA UHDAC Informar que esta mañana hemos procedido a comunicar al Juzgado de Guardia nº1 de Plasencia de incidencia grave protagonizada por el paciente JC.R.G. por agresión a otro paciente en la UME, dónde permanece desde el pasado 2 de marzo por amenazas e intentos de agresión hacia otro paciente en la UHDAC, Unidad de ingreso en CSS de Plasencia proveniente del Hospital Psiquiátrico Penitenciario de Sevilla desde el 12 de diciembre. No es un episodio aislado, hace unas semanas tuvo otro episodio de heteroagresividad hacia un profesional sanitario, que como ha ocurrido hoy gracias a la actuación del personal se ha podido controlar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-05-26','Ana: Choni, TS SSASB y responsable de los PP.TT., me envía el CI completo. Se pone para firma del D-Gerente. ············· Belén, TS CTAEX, lo remite a Choni por email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-05-24','Ana: Correo de Amor López, TS ASPACE (amor.lopez@aspacecaceres.es): "Hola ANA Esta es la nueva pauta de medicación que recibe Brahim, de su último informe médico revisada por su nuevo médico de atención primaria de Jaraiz de la Vera. Si no te importa, nos la puede firmar su tutor?? Es simplemente un protocolo interno del centro. Muchas gracias y disculpa las molestias" ·········· Se pone a firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2021-05-26','Me pongo en contacto para comentarte sobre Antonio Manuel Álvarez Hidalgo. Se trata de un chico que vivía con su madre Valencia del Ventoso e ingresó en nuestro centro en mayo de 2019 por diferentes motivos entre ellos las nefastas condiciones de la vivienda, la situación de riesgo y posible desamparo puesto que su madre enfermó y vivía solo. Su madre ingresó en un centro de mayores en Medina de las Torres. Antes de la pandemia su madre se desplazaba a Llerena a visitarlo cada 10 días aproximadamente y aunque el estar con su madre era deseo y demanda constante se puede decir que se adaptó bien a la dinámica del centro. Durante la pandemia ha realizado videollamadas y dos visitas en verano, puesto que el hecho de que ambos residan en centros ha supuesto que tuvieran las salidas restringidas. Este próximo viernes día 14 vendrá su madre a visitarlo. El pasado viernes se puso en contacto la trabajadora social de su pueblo de Valencia del Ventoso para comunicarme que un abogado de Legalitas se había puesto en contacto con ella para comentarle que su madre había solicitado sus servicios con el objetivo de la reagrupación familiar, es decir, que la madre quiere que su hijo se vaya al Centro de Mayores a residir permanentemente con ella. Ayer hablé con la directora del centro de mayores y también la han llamado para el mismo tema. Desde el centro no consideramos conveniente que Antonio Manuel se traslade a vivir a una residencia de mayores puesto que se trata de un perfil idóneo de Centro Ocupacional y se encuentra integrado en nuestro centro. Aunque sí consideramos oportuna la posibilidad de que madre e hijo pasasen un tiempo juntos. Yo ayer le comenté a la directora del centro de mayores si Antonio Manuel podría pasar 10 o 15 días en verano en su centro ocupando una plaza de forma privada y me dijo que habría que estudiarlo y que ahora mismo no tiene ninguna plaza libre. Esa sería la única posibilidad puesto que la vivienda familiar no es habitable. Me parece importante facilitaros esta información y poder coordinarnos, en cuanto a valorar esta posibilidad de cara a agosto, en caso de que tuvieran alguna plaza libre en el centro de mayores y Antonio Manuel pudiera asumir el coste, aunque no tiene porqué ser íntegro ya que su madre podría pagar una parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-26','Ana: Correo respuesta de la oficina de extranjería de CC (personal_extranjeria.caceres@correo.gob.es): "Buenos días. Le informamos que nos hemos puesto en contacto con la Brigada de Extranjería de la Comisaría de Policía de Cáceres para que consulten el expediente de expedición de la Tarjeta de Identidad de Extranjero solicitada por la interesada en el año 2.000 no habiendo recibido aún contestación. Saludos y que tenga un buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2021-05-26','-Amalia :pregunto a los juridicos : Buenos días , os voy a comentar este caso a ver qué opináis al respecto. Os reenvio los emails mios y de la TS del centro de la Luz , porque discrepo con ella en este caso. Miguel es un chico con discapacidad límite que lleva allí mucho tiempo , con ganas de un traslado de centro que ya tengo pedido, pero con muchisimas capacidades , yo no lo veo para tutela . El médico le ha dicho que tiene que operarse por un tema de salud y que si no lo hace en un futuro podría ser que su salud mermase hasta el punto de poder llegar a quedar en silla de ruedas . El chico , que tiene capacidad suficiente para entender todo lo que se le ha explicado , decide que no quiere operarse de momento . Me llama la TS para que hable con él y lo " convenza" para que se opere. Le digo que yo no voy a obligarle a operarse pero que hablaré con el sobre el asunto. Lo llamo y me da sus explicacciones de por qué no quiere operarse, y entre ellas es porque Sole le está coaccionando para que se opere , le ha dicho que si no lo hace , no pediriamos el cambio de centro entre otras cosas. Le aclaro que no tiene nada que ver , y que él decida voluntariamente lo que desea hacer. Escribo a Sole para comentarle la llamada , el chico no se ha decidio aún , y este es el email que recibo. Le he conteestado que en breve la nueva normativa cambiará este sistema , ya está aprobada en Senado pendiente solo de publicación, y se seguirá la misma .Se va a pasar a un sistema en el que prima la voluntariedad de la persona . Qué os parece ? Supongo que si decide no operarsee tendriamos que comunicarlo al juzgado para que decida no ? lo que tengo claro es que yo no lo voy a obligar a operarse , como ella pretende , quiere que la comisión le obligue porque somos sus tutores . Y que lo atan a la camilla ? Un saludo ---------------------------------------------------- respuesta de los juridicos sobre el tema de la operacion Buenos días, He hablado en alguna ocasión con Miguel y, aparentemente, se le ve un chico que pudiera tener alguna limitación, parcial a mi parecer también, por la forma en la que se comunica y razona. Sin embargo, está sometido al régimen de tutela, al estar incapacitado totalmente, y según sentencia, tiene ausencia de capacidad para valorar convenientemente lo que le conviene, entre otras… En estos casos, siempre hemos seguido el criterio técnico médico, en beneficio de la salud de nuestros tutelados. Ahora bien, si como dices, él no quiere operarse, no hay que olvidar lo que establece el artículo 12 de la Convención de Nueva York, sobre los derechos de las personas con discapacidad , “Igual reconocimiento como persona ante la ley”, que entró en vigor en el año 2008, aunque en España lo hará en breve, debiendo adaptarse nuestra legislación a dicha Convención. En la misma si se tiene en cuenta la voluntad de la persona con discapacidad y se deben respetar los derechos, la voluntad y las preferencias de la persona con discapacidad. Por lo tanto y a los efectos de no contravenir la misma, en mi opinión, deberíamos poner en conocimiento del Juzgado que lleve la incapacidad este tema, para que resuelva lo que proceda. Un saludo. firma angel 2019 MIGUEL FERNANDEZ DE LLERA Mié 26/05/2021 9:30 Buenos días, los artículos que mencionan son artículos que a mi entender vienen a indicar que si no se está de acuerdo con las decisiones del representante legal de una persona se acuda al juzgado a resolver la discrepancia. Entiendo que eso es lo que debemos hacer, no entrar en discusiones con el centro simplemente indicarles que necesitamos informe social y de los médicos especialistas para remitirlos al juzgado y que sea éste el que resuelva. Lógicamente pondremos en el escrito lo que tu indicas de la opinión de Miguel Ortíz. Por favor súbe todo a la intranet para cuando hagamos el copia y pega al escrito del juzgado. Seguimos… firma miguel 2019','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2021-05-25','-Amalia , respuesta de Sole de la Luz , creo que Miguel puede decidir sobre la operacion voluntarimente, tiene capacidad suficiente para ello y no voy a obligarle a una operación como ella pretende : Buenos días, Amalia. Muchas gracias por tu Apoyo al haber hablado con Miguel ayer por la tarde. Creo que tu intervención va a a contribuir en gran medida para que se opere. Por otra parte decirte, que respeto que digas que si decide no operarse, no vais a interferir en esa decisión pero en ese caso , nosotros directamente pondríamos en conocimiento este hecho a los Servicios Jurídicos de la CTAEX /Ministerio Fiscal en virtud del art. 158. 1º y 6º, y 216 del Código Civil que establece: Artículo 216: "Las funciones tutelares constituyen un deber, se ejercerán en beneficio del tutelado y estarán bajo la salvaguarda de la autoridad judicial. Las medidas y disposiciones previstas en el artículo 158 de este Código podrán ser acordadas también por el Juez, de oficio o a instancia de cualquier interesado, en todos los supuestos de tutela o guarda, de hecho o de derecho, de menores e incapaces, en cuanto lo requiera el interés de éstos". Y conforme a lo previsto en el artículo 9.6 de la Ley 41/2002, de 14 de noviembre, básica reguladora de la autonomía del paciente y de derechos y obligaciones en materia de información y documentación clínica: En los casos en los que el consentimiento haya de otorgarlo el representante legal o las personas vinculadas por razones familiares o de hecho en cualquiera de los supuestos descritos en los apartados 3 a 5, la decisión deberá adoptarse atendiendo siempre al mayor beneficio para la vida o salud del paciente. Aquellas decisiones que sean contrarias a dichos intereses deberán ponerse en conocimiento de la autoridad judicial, para que adopte la resolución correspondiente. Y en el artículo 25.3 la Ley 3/2005, de 8 de julio, de información sanitaria y autonomía del paciente, de la Comunidad Autónoma de Extremadura: Cuando la decisión del representante legal pueda presumirse contraria a los intereses del menor o incapacitado, deberán ponerse los hechos en conocimiento de la autoridad competente en virtud de lo dispuesto en la legislación civil. En ese caso, sería necesario un informe previo del Médico Forense y dictamen del Fiscal antes que el Juez se pronunciara si autoriza o no pues existiría negativa de la persona con discapacidad y se trata de una decisión que puede afectar a su salud/vida. Seguimos en contacto. De todas formas, confío en que tu buen hacer y nuestras intervenciones conduzcan a que finalmente decida operarse. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-05-26','Ana: envío correo-e a Alfonso Rodilla, Consulado de España en Bruselas (alfonso.rodilla@maec.es): "Buenos días Alfonso, ¿qué tal estás? Espero que sigas bien. Me pongo nuevamente en contacto contigo en relación a Javier Agudo Cumplido. Por un lado, nos gustaría saber si habéis vuelto a tener noticias de él. Nosotros no hemos vuelto a saber nada. Por otro, recordarte que seguimos a la espera de “correo oficial” o “escrito de la Cónsul” comunicando su paso por el Consulado y las atenciones/gestiones llevadas a cabo por vuestra parte, tal y como habíamos acordado. Entiendo que debéis estar también muy ocupados, pero dadas las circunstancias, agradeceríamos, que en la medida de lo posible, agilizaseis esta cuestión. Seguimos en contacto. Un saludo."','2');
