insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-05-26','Ana: Llamada de Pepa, Psicóloga del Instituto de Medicina Legal de CC (927 62 04 01). En relación a la denuncia interpuesta por el SEPAD, por la negativa de José Mª Tovar, a llevar a la joven al C.O. asignado (Down CC), el Juez le ha pedido que valore a Soledad y acudirá al recurso el próximo lunes. Me hace algunas preguntas relativas a la situación, pues no tenía toda la información. Inidco también los motivos por los que en su día se solicitó el recurso y los beneficios que desde la CTAEX consideramos que puede tener para ella acudir y participar en el mismo. *Entiende que si José María no es el tutor, no puede negarse a llevar a las jóvenes al recurso solicitado por su representante legal y concedido por la Ud. correspondiente en base a unos criterios. **No obstante, en cuanto a la denuncia, le emplazo a hablar con Soraya Masa, Jefa de U.G.PP.AA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-05-26','Ana: puesto que no he recibido respuesta al correo-e enviado hace días a la Embajada y el fax que hemos intentado enviar en multiples ocasiones siempre da ocupado, llamo a la Embajada de Mauritania (915 75 70 06): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-05-27','Ana: correo-e respuesta de Alfonso Rodilla, Consulado de España en Bruselas (alfonso.rodilla@maec.es): "Buenos días, Ana, La verdad es que, como dices, estamos desbordados por todas partes, hacemos lo que podemos para resistir. En referencia a Javier Agudo, desde su última aparición en el Consulado el 6 de mayo, no hemos vuelto a tener noticias. Todos los elementos disponibles hasta ahora han sido comunicados. He transferido a la Cónsul tu correo para que os envíe alguna comunicación de carácter oficial. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-04-16','Ana: Paula, TO del CRR-Plas., remite informe de evolución de Antonia en que se indica que la evolución está siendo positiva. Ha logrado los objetivos teraéuticos marcados y muestra gran competencia para la vida autónoma. "...en consonancia con su meta vital, el plan individual de intervención contempla para los próximos meses el inicio de búsqueda de vivienda en una localidad de la provincia de Cáceres, afianzando los logros conseguidos hasta el momento, para alcanzar el alta terapéutica del piso supervisado..." ············· *Guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-05-26','Ana: Correo de Paula, TO CRR-Plas: "Hola Ana, ¿cómo seguís? supongo que muy liadas por los cambios de compis y en pleno reajuste. Comentarte acerca de Antonia Bernardo Piris. Como apuntábamos en el informe que os enviamos en el mes de Abril, Toñi ha cumplido con todos los objetivos que se ha ido planteando y los que, desde el recurso, creíamos imprescindibles para poder abordar una vida autónoma. Por ello estamos inmersas en la última fase descrita en el informe, en la que Toñi está iniciando la búsqueda de casa/habitación en Cáceres. Para esto vamos a apoyar sus iniciativas e ir manteniendo el contacto con vosotras para que, si encuentra una oportunidad de vivienda interesante, podamos concretar lo necesario para poder gestionar el Alta Terapéutica. Estamos muy contentas de compartir con vosotras tan buenas noticias, que parece que siempre trasladamos las dificultades. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-05-27','Ana: Recibimos RESOLUCIÓN de la Direcc. Provincial reconociendo el complemento a mínimos. Fecha de efectos de la modificación: 31/01/21- Importe líquido a percibir 689,70€. En concepto de atrasos le abonarán 1476,01€. ············· **Llamo a Marina Carmen Cintas, Jefa de Secc. de PNC, **tienen que volver a recalcular la cuantía del cobro indebido por los meses en que ha cobrado de forma simultánea las dos pensiones. **No hacer nada con respecto a la resulución de PNC recibida y esperar a que llegue la nueva. ········ *Tal y como acuerdo con Marina, envío a Adela Molina, PNC (adela.molina@salud-juntaex.es) la resolución del complemento a mínimos escaneada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='BUENO'and apellido2='GUISADO'),'2021-05-27','miguel, ratifico escritura de venta ante el notario de Mérida, Fco Javier Hdez Tellez con nº de protocolo 944 hoy 27-5-21. Me indican que mandarán telemáticamente a la notaria de Timoteo Diez Gutierrez de Badajoz dicha ratificación para unirlo a la escritura de compraventa firmada hace unos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-05-27','miguel, tras hablar con Tere quién me indica el tlfno de la policía (924-380138 jesús Ramón, y hablo con el posible comprador con el que ha hablado Iciar (Eugenio Galan 606985996). Dicho posible comprador irá a verlo hoy y mañana nos hará una oferta por el coche(no tenemos papeles ni llave). La policía le urge que lo retiremos de la calzada con lo que daremos una solución mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-05-27','-Amalia : recibo llamada de la TS del SSASB , la señora se ha peleado con su hija y no quiere regresar al domicilio. Ya se estaba gestionando el ingreso en plaza residencial de forma voluntaria como habia pedido Maria. Se envia toda la documentacion a Ana Moreno para que asignen plaza T3 o T4 por emergencia . Se necesita PCR negativa , en centro de salud no se lo puede hacer hoy . Pasará a un hostal unas noches que cubrirá el SSASB y si para el lunes está ese tramite se procede al traslado en taxi al centro residencial que nos asignen . Recibido Ana, muchas gracias. Nos mantenemos a la espera de que nos podáis facilitar la solicitud y declaración de bienes firmada por José Vicente Granados (cuando podáis). Mientras tanto estamos introduciéndola en el programa para poder adjudicar plaza lo antes posible. Gloria, la trabajadora social , está pendiente de programar una PCR para poder ingresar en un centro. A priori la señora irá a un hostal hasta poder ingresar. Un saludo Ana Isabel Moreno Gilgado Trabajadora Social Gerencia Territorial de Badajoz SEPAD ANA MATAMOROS GOMEZ Jue 27/05/2021 13:30 Buenos días Ana, De acuerdo a la conversación mantenida con mi compañera Amalia y con Gloria Salguero, TS del SSASB de Badajoz, te envío adjuntos los documentos pertinentes para el Ingreso por emergencia social de María Báez Soriano. La solicitud firmada por le Representanta Legal está en el último documento adjunto, la que aparece en el mismo PDF que el DNI es la que nos han remitido tal cual. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-05-28','Ana: Llamo a la Embajada de Mauritania (915 75 70 06), varias veces y en distintos horarios: no obtengo respuesta. ·················· Intento enviar de nuevo el escrito por fax, pero el reporte da "ocupado". ··············· Redacto oficio y se lo doy a Julio-CTAEX junto al escrito y el tesmitmonio de aceptación del cargo, para que le dé REGISTRO DE SALIDA y lo envíe por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-05-28','Ana: Llamada de José Manuel (627 788 797): dice que está BIEN, que ha decidido quedarse en el CRR, que sabe que si vuelve a su casa va a tener problemas con su hijo. Qué además hay una serie de cuestiones que estando en el centro las tienen cubiertas como recargas de teléfono y ropa si la necesita. *Por otra parte el día 23/06 tiene el juicio relativo a la manutención que pasa a hijos aún. *Quiere aprovechar este viaje para pasar unos días en su casa. Le pregunto literalmente si está seguro de pasar allí unos día, no vaya a ser que le entre la tentación de querer quedarse, pero dice muy convecido que NO, que sabe que lo mejor para él es quedarse en el CRR. ·············· Envío correo informando al respecto a Toni-Futuex, Amalia-CTAEX, Beatriz-CRR y Pilar-ESM CC. *Comunicando además que a partir de la semana que viene ya se encargará Amalia del seguimiento. ·························································································································· Correo-e de Beatriz, CRR (bgonzalez.sanmiguel@hospitalarias.es): "Buenos días a todas, Aunque ayer había hecho las maletas para marcharse, finalmente fue capaz de reflexionar y reconocer las dificultades que tiene en relación a su hijo y a las condiciones de vida en su casa. También nos ha comentado su idea de pasar unos días en casa aprovechando que tiene el juicio en Cáceres y por nuestra parte si desde la Comisión lo autorizáis no hay problema en que haga una salida de 48 horas y regrese al centro, porque quizás siete días para la primera salida igual serían muchos días. De todas formas, va a depender de cómo se encuentre cuando vaya llegando la fecha, lo vemos más adelante si os parece. Muchas gracias Ana por tu seguimiento y bienvenida Amalia!" ······························ Correo-e de Amalia, CTAEX: "Buenos días , ya había hablado con Leonor de esta posibilidad , por mi parte no habria problema si se cumple con las medidas establecidas para centros por el covid."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-05-28','Ana: Llamo a Pilar Márquez, TS de Valencia de Alcánara (927 580 326, ext.8): Ayer justo comenzó a prestársele a Ramón el SAD, tal y como habíamos hablado se realizará en horario partido, la Aux. acudirá al domicilio de L a V a las 13 h. y a las 18h. ··············· Se lo comunico por mail a Alberto Arias Bueso, EVD (alberto.arias@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-03-31','Ana: Correo-e de Toni-Futuex: "Buenas de nuevo, se adjunta el informe de marzo, mas el de revisión de ginecologia de Octubre tal y como comentabas" ····· *Tras leerlos, guardo ambos informes en su expte. **En el Informe de la Educadora se resalta el deseo de Julia de ingresar en un centro y las malas relaciones convivenciales con su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-05-26','Ana: Tras recibir llamada de Estrella del CSS, envío correo al Alberto y Amalia - CTAEX: "En relación a Remedios Chaves Masero, me ha llamado Estrella, TS del C. Sociosanitario de Plasencia. Plantean una visita para que vea a su madre, a quién hace mucho que no ve. La idea es que sea en un entorno controlado, pero como no hay posibilidades de que lleven hasta allí a su madre, proponen que tenga lugar en Aprosuba 3 (Badajoz). Yo no veo inconveniente en que se lleve a cabo. La rendición es de hace casi un año, pero supongo que hay dinero suficiente para asumir la contratación de un taxi, que es lo solicitan. Amalia, si ves inconveniente dímelo. Alberto, les he pedido que envíen presupuesto del taxi."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-05-28','Ana: Correo - respuesta de Amalia, TS CTAEX: "...Ana no veo inconveniente , supongo que los dos centros se habrán coordinado para ello y habrán cuadrado horarios . Un saludo" ········ Correo-respuesta de Alberto, Jefe secc. ecca. CTAEX: "Hola. SIN problema el temas del taxi: factura, nº CCC y pagamos x transferencia. IMPORTANTE: en abril de 2021 ya pagamos otros taxi x importe de 220 €...entiendo que no va a tener viajes de 220 € cada mes, no??? Otra cuestión: a ver si no me equivoco. Remedios está en CSS Plasencia pero seguimos pagando plaza en APROSUBA 3...no hay un presupuesto hecho para reintegros con APROSUBA 3...Ana: anótate que cuando vuelva a APROSUBA 3 tenemos que establecer un presupuesto y que el mismo deberá contemplar los gastos en TAXI y los REINTEGROS...tampoco veo gasto en teléfono. ················· Se lo comunico a Estrella, TS CSS (24146)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-28','Ana: Llamo al Registro Civil de Coria (927 50 81 69): el procedimiento correspondiente debería iniciarse en el Registro Civil de Villamiel (que a su vez depende del Juez de Paz de Coria). No obstante insiste que si en la partida de nacimiento no hay ninguna inscripción al margen de que haya perdido la nacionalidad, no la ha perdido y por tanto no se puede iniciar expte. alguno de recuperación de nacionalidad. ·················· Llamo al Registro Civil de Villamiel (927 51 30 55), no obtengo respuesta. ······························································································································································································ Llamo al Subinspector Vasallo, Policía Nacional - Oficina DNI (927 62 90 92): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2021-05-28','Belén. Se envía solicitud de material ortoprotésico','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-05-31','TERESA desde Centro de Recuperación Funcional azul queremos informarte que el usuario Jose Antonio Delgado ya tiene una auxiliar de ayuda a domicilio para comenzar este servicio a partir del 1 de Junio. si necesitas algún tipo de información no dudes en ponerte en contacto con nosotros. Gracias por tu atención Un Saludo. Mª Ángeles Pagador Bayón Centro de Recuperación Funcional "Azul" teléfonos: 924501015, 634785050','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-05-31','-Amalia : La Sra. ingresó el viernes por la tarde , con PCR negativa en el centro municipal de mayores PUENTE REAL de San Vicente de Alcantara . Tf 924411032 ( mª Angeles Dtra. ) Va a enviarme contrato y modelo alta a 3º para firmar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-05-31','TERESA ARCHIVO GUIA USUARIO DEL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-05-31','TERESA ARCHIVO DILEGENCIAS POLICIALES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-05-28','Ana: Correo de Adela Molina, PNC (adela.molina@salud-juntaex.es): "Buenos dias, El día 16/04/2021 el INSS me comunica una pensión de viudedad a nombre de Doña María Romero Rodriguez con una cuantía mensual de 323,65 € y fecha de efectos 15/01/2021. En base a ello, para el mes de mayo le modifico la cuantía a la beneficiaria a 235,54 € con fecha de efectos 01/02/2021 y le reclamo las cantidades desde el 01/02/2021 hasta el 30/04/2021. Si ahora le han reconocido la cuantía de 689,70 € desde la misma fecha de efectos, le extinguiré el derecho a la pnc en el mes de junio/2021 con los mismos efectos económicos, es decir, desde el 01/02/2021, y le reclamaré todo lo percibido desde esa fecha hasta el 31/05/2021. Ya recibiréis la Resolución de Extinción. Gracias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-05-31','TERESA ARCHIVO RESOLUCION DE EXTINCION DEL SAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-27','Ana: Correo-e de la Oficina de Extranjería (personal_extranjeria.caceres@correo.gob.es): "Buenos días. Lamentamos informarle que la Brigada de Policía nos comunica que no tienen ningún documento de la interesada ya que dicha documentación fue destruida. Saludos y que tenga un buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-05-31','TERESA ENVIO OFICIO PETICION TRASLADO EXPEDIENTE DISCPACIDAD Y DICTAMEN TECNCIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-05-26','Ana: Envío correo a Toni-Futuex: "Quería preguntaros por Miguel Santos Cordero, en los últimos correos decíais que el hijo quería comenzar a acompañarle a las citas médicas, pero no sé en qué punto está esto, pues hasta entonces le estabais acompañando desde el Programa. Pero tengo correo de Pilar Martín, TS ESM, preguntando por qué acudió ayer a consulta sólo… Ya me dices. Seguimos en contacto. Buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-05-27','Ana: Correo-respuesta de Toni-Futuex: indica varias cuestiones. *El hijo de Miguel había dicho que iba a acompañar a su pasre a la consulta de Psiquiatría, no saben por qué no lo ha hecho. En las próximas volverán a acompañarle desde el programa. **Envía un requerimiento de pago de Iberdrola que ha recibido Miguel. **Miguel y su hijo solicitan que se pida presupuesto para hacer reforma en la casa. *En cuanto a la limpieza, la casa ha mejorado en algunos aspectos, pero aún falta mucho por hacer. **Miguel es bastante descuidado con su higiene y aspecto personasl. NO quiere SAD. **También demanda un aumento en su asignación. ········ Guardo correo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-05-31','Ana: Envío correo-respuesta a Toni-Futuex: "Paso a Alberto el tema de Iberdrola así como la posibilidad de aumentar la asignación. En cuanto a la reforma, confirmarme, según las observaciones en la visita realizada, qué reformas serían realmente necearais. Yo me plantearía también el contratar una empresa de limpieza, visto que la ayuda del hijo no está siendo suficiente y aún queda bastante por hacer en este sentido. ¿Podríais encargaros de pedir presupuestos? A ver si su situación ecca. lo permite. Por otra parte, por favor, seguid abordando el hecho de que necesita un apoyo diario, lo bien que le vendría un servicio de ayuda a domicilio, tanto para el mantenimiento y limpieza de la vivienda, como el apoyo que le puede suponer en otros aspectos. Sería bueno contar con esa figura para un “control” en la toma de medicación e higiene personal… Ya me vais diciendo." ············· Envío correo a Alberto, Jefe secc. ecca., con requerimiento de Iberdrola y planteando un aumento de asignación. Informo tb de enviarán próximamente presupuesto de limpieza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-05-31','Ana: corero de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Hola Ana, te escribo para comentarte que Toñi Bernardo quiere ir a visitar a la familia en Valencia de Alcántara del 3 de Junio al 17 de Junio, teniendo en cuenta todas las medidas de prevención. Toñi está vacunada y lleva sin ver a la familia desde hace muchos meses, por lo que pensamos que puede ser muy positivo para ella. Ya nos dices." ················ Mi respuesta: "Buenos días Paula, Si así lo valoráis en el equipo y, como bien dices, siempre que se cumplan todas las medidas frente al Covid, por mi parte no hay ningún inconveniente. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2021-05-31','Amalia : correo de Ana : Acabo de recibir llamada de Carmen, Directora del CSS Mérida, dice que es el primer nº que ha visto. Iba con prisas, así que le he dicho que no se preocupe que yo te informaba. Ayer envió un correo al ctutelar@ en relación a Mª Jesús Cruz Esperilla, nueva tutela, pues ayer mismo fueron a poner una denuncia contra otro paciente por abuso sexual. Ha firmado ella como Guardadora de hecho. Ahora se marcha con ella al Juzgado, pues entra como caso de Violencia de Género. Si necesitas/consideras hablar con ella, puedes llamarla al nº móvil corporativo: 626 524 378. -------------------------- Hablo con la Dtra. le paso tf de jurídicos por si necesita algo más . Envio sentencia al CSS .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='MORUNO'and apellido2='GALLO'),'2021-05-31','-Amalia : me comunica Maribel , TS del CSS que hoy están operandolo en Caceres . El consentimiento informado lo firmaron ellos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-05-31','Ana: Llamo al Subinspector Vasallo, Policía Nacional - Oficina DNI (927 62 90 92) varias veces en distintos momentos de la mañana: no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-05-31','Ana: Llamo a Jorge Morán Pilo (924 930 415), en relación a la resolución de extinción de la prestación ecca. vinculada al SAD (190,64 €/mes), no da llamada. Vuelto a intentarlo y salta un buzón de voz. **No obstante, según me informó en correo de 12/03/21, tenemos que esperar a recibir la propuesta de pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-05-31','Amalia : email a S. eco : Buenas , os he puesto en copia en mi respuesta a la Dtra. de la residencia del centro . Esta señora ingresó por urgencia el viernes por la tarde , otra movida . El jueves me avisaron que la hija con la que vivía la había agredido .Pasó una noche con una vecina ,solicitamos por urgencia plaza en la Gerencia SEPAD , se le hizo PCR por la tarde y en cuanto nos dieron el resultado se trasladó . Percibe una PNC , no sé el Nº de cuenta , me preocupa que en esa cuenta esté la hija y pueda retirar el dinero . Cuando podáis , habria que averiguar ésto , si no está la hija incluir al D.Gerente y si no abrir una cuenta nueva a la que yo solicitaré cambio de la PNC. El copago ya lo he solicitado en Gerencia , va a ser el 65% de la PNC incluidas las p. extras . El resto se le autorizará para que pueda sacarlo como dinero de bolsillo. Estamos en contacto..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2021-05-31','Belén. Se habla con la directora del centro Soledad (697417348), el presupuesto que se ha fijado es 150€/mes. Se va pedir Informe al equipo de salud mental para ver si es conveniente que se saque el carné de conducir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-05-31','Ana: En relación a la conversación mantenida la semana pasada con Julián, COCENFE (927 239 028), proponiendo retirada de extra para regalo de cumpleaños de Tomás y solicitud de acompañamiento 2días/semana (lo propondré a Futuex), envío correo a Alberto, Jefe secc. ecca.: "...Desde COCENFE, solicitan un EXTRA por el cumpleaños de Tomás Esteban Iglesias, esta misma semana. Por mi parte OK. ¿Podríais autorizar un extra de 100€ para retirarlo esta semana junto a la asignación mensual habitual??" ····························································································································································································· Envío correo a Toni-Futuex: "Buenas tardes Toni, Quería derivaros al programa a otra persona tutelada, se trata de Tomás Esteban Iglesias, reside en COCEMFE Cáceres. No cuenta con apoyos familiares de ningún tipo y tampoco mantiene contacto con su hermana (otra tutelada residente en NACE…). El planteamiento sería el de visitarlo y acompañarlo a pasear, hacer gestiones, compras, tomar café… para que pueda salir del centro y tener algo de vida social. A raíz de ahí se podría valorar y trabajar que cuente con otros apoyos/relaciones externas al centro (a través de voluntariado por ejemplo). La petición del centro es de 2 días a las semana (en torno a 1,5 – 2 horas), pero no sé si sería factible por vuestra parte. Julián, responsable del recurso, me enviará en cuanto pueda un correo con más información acerca de las características de Tomás y las necesidades de apoyo que presenta. Está dispuesto también a mantener una reunión por videoconferencia si fuera preciso para que valoremos más en detalle todo. Ya me confirmas cuando puedas. Un saludo y buena tarde!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2021-06-01','Belén. Solicitud de PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-06-01','Ana: Envío correo a Julián-Gerente de COCEMFE (gerencia@cocemfecaceres.org): "Buenos días Julián, En relación a la autorización para retirada de un extra de 100€ para el cumpleaños de Tomás Esteban Iglesias, dan el ok desde la sección económica. Podréis retirarla junto a la asignación mensual habitual. Por otra parte, me pregunta Alberto, Jefe de Sección Económica, si cuando se compró la silla de ruedas el pasado octubre, se solicitó la subvención del SES asociada a tal fin. Yo lo desconozco, no sé si trataste este tema con Pedro, pero en nuestra Intranet no hay nada anotado al respecto. Si no lo habéis hecho, quizá estemos a tiempo de solicitarla. Seguimos en contacto. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-05-26','TERESA EL 26 DE MAYO ES TRASLADADO DESDE EL C.P. SEVILLA HASTA LA RESIDENCIA LAS CUBMBRES EN AMBULANCIA ORGANIZA EL TRASLADO EL ARE DE SALUD DE CORIA M TERESA ENCINA 927149221 RESPONSABLE TRANSP SANITARIO TERESA.ENCINASRIVERA@SALUD-JUNATAEX.ES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2021-06-01','-Amalia , email de la DTRa . del CSS a los jurídicos: Buenas tardes: Os paso las diligencias previas resultado de la declaración de Mª Jesús Cruz Esperilla en el Juzgado este mañana. El chico implicado se encuentra en el centro cumpliendo una sentencia actual 600/2019 del Juzgado de los Penal 33 de Badajoz (13/05/2020- 08/11/2021) y pendiente una 11/2020 del Juzgado 13 de Fregenal de la Sierra (08/11/2021- 21/11/2021). Dada la dificultad de llevar a término las medidas establecidas por el magistrado, al ser un centro abierto con unidades abiertas, donde se comparten actividades y sin posibilidad de poner vigilancia permanente o mantener "encerrado" al chico, como dirección me preocupa enormemente no poder mantener la seguridad de vuestra tutelada, Por lo que creo que la propuesta al juez que determinó el ingreso de Andrés Gale en el centro es que traslade al mismo a otro centro donde cumplir la condena y que sea lo antes posible, ya que las medidas de seguridad tienen efecto desde hoy. También sería conveniente que esta parte de petición al juzgado sea solicitada por vuestros servicios jurídicos que tendrá un mayor peso al ser la usuaria tutelada por la CTA (aunque desde la dirección se elabore informe pertinente sobre este tema de seguridad). Espero noticias vuestras lo antes posible para poder tramitar el tema de manera ágil','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2021-06-30','TERESA Eugenio tiene cita en salud mental mañana día 2, va con otra compañera y les lleva la psicóloga, tendrían que pagar a medias el kilometraje que son 14€ No hay que hacer ingreso de esto Cuando tenga info de la consulta te envio,ok?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-06-01','TERESA PROXIMA VISTA BEATRIZ A SU HIJA EL 8 DE JIUNIO A LAS 18:00 HORAS LA MADRE DE BEATRIZ INSISTE LLAMANDO AL CENTRO Y A LA CTAEX PARA QUE LE DEMOS PERMISO PARA QUE SU HIJA PASE ALLI UNOS DIAS NO SE LE CONCEDE PUESTO QUE LA CASA NO REUNE LAS CONDICIONS OPTIMAS PARA QUE BEATRIZ PASE ALLI UNOS DIAS ADEMAS CUANDO VANA VISITARLA LA MADRE MUESTRA POCO INTERES EN LA VISITA, SALE A SALUDARAL Y SE VA PARA DENTRO A SEGUIR VIENDO LA NOVELA SEGUN NOS COMENTA LA CUIDADORA QUE ACOMPAÑA A BEA EN LAS VISITAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-06-01','Ana: Correo de Sonia Bernabé - Asindi: "Hola Ana, te escribo para informaros que han invitado a Justo Hernández Castaño a la presentación del corto documental sobre diversidad sexual y discapacidad que se grabó hace bastante tiempo. Estamos valorando la posibilidad de que acuda al acto, siempre que lo autoricéis. Iría acompañado de un profesional de la entidad y cumpliendo con todas las medidas establecidas para prevención del COVID. A continuación te copio el correo/invitación que nos han remitido. Estamos en contacto, tenemos que dar respuesta antes del día 14 de junio. Un saludo," ················· Mi respuesta: "Buenas tardes Sonia, Por mi parte no hay ningún problema en que asista, es más, creo que sería positivo e importante para él asistir. No obstante pongo en copia a mis compañeros Asesores Jurídicos, para que den el visto bueno y no sé si hay que enviar alguna autorización al respecto. Seguimos en contacto. Buena tarde."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-06-01','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, te escribo para informaros que han invitado a Justo Hernández Castaño a la presentación del corto documental sobre diversidad sexual y discapacidad que se grabó hace bastante tiempo. Estamos valorando la posibilidad de que acuda al acto, siempre que lo autoricéis. Iría acompañado de un profesional de la entidad y cumpliendo con todas las medidas establecidas para prevención del COVID. A continuación te copio el correo/invitación que nos han remitido. Estamos en contacto, tenemos que dar respuesta antes del día 14 de junio." ······················· Mi respuesta: "Buenas tardes Sonia, Por mi parte no hay ningún problema en que asista, es más, creo que sería positivo e importante para él asistir. No obstante pongo en copia a mis compañeros Asesores Jurídicos, para que den el visto bueno y no sé si hay que enviar alguna autorización al respecto. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-06-01','miguel, entrego físicamente en su buzon de despacho al abogado fotocopia de escritura de compraventa con nota simple, solicitud a la policía local para que se personen y averiguen si alguien viven en la vivienda de la c/ Macón, quedando pendiente del informe de la policia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-06-02','Ana: Correo de Estrela, TS CSS-Plas.: "Buenos días. Como sabéis estamos organizando viaje de Remedios Chaves Masero a Aprosuba 3 de Badajoz para que allí tenga un encuentro con su madre. Hemos acordado que vaya el próximo miércoles día 9 de junio a las 10,30 horas. Si nos dais vosotros el visto bueno. Os envío el presupuesto del taxi. El taxista acepta transferencia bancaria Saludos" *El presupuesto es de 170€, con 1 hora de espera. ··················· Se lo paso a Alberto y a Amalia, dando OK por mi parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-06-02','miguel, Jairo me llama para decirme que el médico Herrero le ha preguntado que si tiene trabajo y tiene donde ir, él lo comunicará al Juzgado la haber cumplido 1/3 parte de la pena.Por lo que hablará con Ana para que lo incorpore a un programa de empleo.*************************************** Quiere una hipoteca para arreglar su casa de 60.000€...para que Ana lo hable con la parte económica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2021-06-02','Belén. Se contacta por telf. para comunicar que la sucursal no se cierra solamente se reduce el horario de atención, que vaya y pregunte para poder retirar su asignación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-06-02','TERESA se le han llevado al Hospital, les ha costado bastante tranquilizarle porque con la presencia de los guardias se puso más nervioso. Ya les he comentado que desde sanidad se comuniquen con vosotros para gestionar luego el alta o cualquier tipo de comunicación sobre su situación. Lamento tener que deciros que ha destrozado el salón: ha lanzado una silla a la TV, lanzado el extintor a un monitor, agujeros en las paredes...etc. (estos desperfectos se os van a solicitar). La maleta y la TV que trajo se la tuvieron que llevar en la ambulancia porque dijo que hasta que no lo tuviera con el no dejaba que le pincharan. El resto de cosas DNI y documentación e incluso dinero en efectivo, os lo envío por correo postal donde me digáis. Te voy a enviar una carta/ documento de expulsión de José Mª para que quede constancia del mismo. No sé si se lo comunicaras tu a la madre, o si quieres que se lo comunique yo. Un saludo Carolina','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-06-02','miguel, llega físicamente la citación para el día 16-6-21 a 12:30h aceptación de la videoconferencia que solicité por fax el 25-5-21. La vista la haremos a través del programa CISCO (móvil). Según hablo con el del Juzgado no lo pueden hacer vía SCACE porque intervienen MF, abogacía general y lo harán por el mismo programa. Dice además que el abogado de la Junta también le ha pedido intervenir con CISCO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2021-06-02','miguel, a raiz de contactar con la nieta Evelyn, del fallecido D. josé Martinez Ortega, y teniendo en cuenta que desde esta Ctaex se lleva la tutela de dos de sus tres hijos. Se contacta con el asesor de Evlyn, Carlos (gerencia@casasesores.com) y quedamos en que nos tramite tanto el Imp de Sucesiones como el desbloqueo de las cuentas bancarias y su ingreso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2021-06-02','miguel, a raiz de contactar con la nieta Evelyn, del fallecido D. josé Martinez Ortega, y teniendo en cuenta que desde esta Ctaex se lleva la tutela de dos de sus tres hijos. Se contacta con el asesor de Evlyn, Carlos (gerencia@casasesores.com) y quedamos en que nos tramite tanto el Imp de Sucesiones como el desbloqueo de las cuentas bancarias y su ingreso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2021-06-02','Buenos días , ante la negativa absoluta de Minerva y su madre a ingresar en la plaza residencial que se le ha concedido en P.Inclusión de Almendralejo , no va a ingresar en la misma . Se lo comunicáis vosotros a la entidad ?? como hablamos , permanecerá en su plaza en CO en Aprosuba 7 de Mérida . No veo viable un ingreso involuntario de momento , tiene capacidad para fugarse del centro y volver a su casa al ser centros abiertos . En el domicilio vive con la madre y su hermano Jorge . He solicitado nuevamente C O para Jorge , estuvo en el centro La Encina y quiere volver . Lo dejó por un contrato con el Ayto. de Mérida . Cual es el trámite para solicitarlo de nuevo ? Un saludo ...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2021-05-31','Ana: Correo de Alberto, Jefe secc. ecca.: "Hola. A día de hoy la tutelada cuenta con un saldo de 170.000 € aprox. Deriva de la venta de la vivienda que le quedaba. Cobra pensión x 1498,03 € x 14 meses Cobra vinculada x 175 € x 12 meses COSTE centro: 2.310,60 € x 12 meses DIFERENCIAL anual ingresos-gastos: entre - 6.000 a - 7.000 € año Alberto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORCILLO'and apellido2='HERRERO'),'2021-06-02','Ana: Correo-e de Mª Dolores Venegas Antequera, T.S. EVD Zona Coria -Ubicación Moraleja- (dolores.venegas@salud-juntaex.es): "Hola Ana , Buenos Dias hace ya mucho tiempo, que quedamos en que te remitiría la resolución de grado de dependencia de este señor , pues ahí lo llevas ( lo han subido a SIDEX el 25 de mayo, después de la resolución de ingreso en plaza pública). Se le ha asignado plaza pública en Residencia de Coria donde se encuentra, si lo necesitas, ya me dices. Un saludo" ····················· Mi respuesta: "Buenos días Dolores, Muchas gracias. Me lo guardo. En cuanto a la plaza pública, estupendo, cuando puedas nos envías la resolución. No obstante, comentarte, para que lo tengáis en cuenta, más que nada, que el Juzgado todavía no nos ha enviado la firmeza de la sentencia, a pesar de que mis compañeros jurídicos ya la han pedido hasta en 3 ocasiones… Ante cualquier cuestión seguimos en contacto." ···················· Nuevo correo de Dolores: "Buenas , nosotros ya hemos finalizado con este señor. Te remito la resolucion de plaza pública. Buen dia" ······· **Guardo ambos documentos en el expte. de Defensa Judicial (Carpeta "Personal")','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-06-02','Ana: Envío correo a Sonia Bernabé - Asindi: "Buenas tardes de nuevo, Sonia, Te envío adjunto, ya firmado por el Representante Legal, el escrito de la Comisión Técnica de Observación de ASINDI. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2021-06-02','Ana: María, Directora de la Res. me comunica que aún no han recibido la transferencia para la vacaciones de Inés. Se lo comunico a Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-06-02','Ana: Correo de Toni de Diego, TS del C.R. Cervantes (antonia.dediego@salud-juntaex.es): "Buenos días Ana Le comunico que hoy Guillermo ha ido a la consulta del otorrino-oncología vía urgencia. EL medico ha dado un mal pronóstico, situación muy grave y desenlace inminente. las posibles intervenciones son: • Traqueotomía de urgencias en caso de dificultad respiratoria • Sonda PEG ante la imposibilidad de comer por boca Quisiéramos dar respuestas algunas cuestiones, ante este pronóstico tan grave: • si se le comunica a la familia la situación sanitaria de Guillermo • quién debe dar esta información y por qué medio • quién debe firmar los consentimientos de las decisiones medicas • en el caso que muriese quién se haría cargo de los gastos fúnebres (ya que no tiene seguro). A quien se llamaría • Dinero no tiene, porque Iba a salir hoy al banco, de momento no necesitaría nada, porque los traslados posiblemente sean a través de ambulancias. pero si necesitase y él no pudiese ir al banco por su salud, como se podría realizar esta gestión Esperando tu respuesta" ················ Mi respuesta: "Buenas tardes Toni, Qué mala noticia… gracias por informar. La cuestión económica se la he trasladado a Alberto, jefe de dicha sección. En cuanto me dé respuesta te digo. Los Consentimientos Informados deben firmarse por el Representante Legal, el Director Gerente del SEPAD, o nos los hacéis llegar vosotras o desde el Servicio correspondiente del Hospital, preferiblemente por mail y se devolverán por la misma vía. En su defecto por fax. Del resto de cuestiones hablamos mañana. Que yo sepa, sólo tienen un hermano y está tutelado también por la CTAEX. Lo hablaré con mi compañera que lleva el caso. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-06-03','Ana: envío correo a Toni, TS del CR Cervantes: "Buenos días Toni, Me han corroborado que Guillermo no tiene más familia a parte de su hermano. Desde la CTAEX se decidirá cuándo y quién le da la noticia. No obstante su hermano está con problemas de conducta y consumo… **Sí que tiene seguro de Decesos. Te adjunto la póliza. Seguimos en contacto. Ya nos irá informando de su evolución. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MILAGROS'and edp.apellido1='CORDERO'and apellido2='DIEGUEZ'),'2021-06-02','Ana: Correo-e de Emilia Almodóvar, TS CSS Plas (emilia.almodovar@salud-juntaex.es): "actualmente está ingresada en el Hospital de Cáceres, en breve será trasladada al Hospital de Plasencia, os iré informando según me comunique el equipo Médico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2021-06-02','Ana: Correo-e de Emilia Almodóvar, TS CSS Plas (emilia.almodovar@salud-juntaex.es): "asistió al juzgado, resultando el procedimiento abierto y en investigación, seguimos con las medidas de alejamiento en el centro con respecto al otro paciente implicado en los hechos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MILAGROS'and edp.apellido1='CORDERO'and apellido2='DIEGUEZ'),'2021-06-03','Ana: Correo-e de Emilia Almodóvar, TS CSS Plas (emilia.almodovar@salud-juntaex.es): "Pues el motivo del ingreso es que se encontraba mal, tenía infección de orina, y otras alteraciones de tensión, con las pruebas médicas que se realizaron, se observó que tiene un pulmón inhabilitado(no funciona), ayer a última hora su evolución según el doctor Gil era positiva, estaba mejor, estamos a la espera del traslado a Plasencia, durante el dia de hoy si tengo más noticias te escribo. aun así, si necesitas informes médicos, o un diagnóstico somático, lo solicito al medico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-06-03','Ana: En relación al correo remitido por Susana Guerrero, Jefa de Negociado de Prestaciones Sociales I (susana.guerrero@salud-juntaex.es), envío a Sonia Bernabé, TS y Directora de Asindi (trabajosocial@asindi.e.telefonica.net) el siguiente correo: "Buenos días, de nuevo, Sonia, Me solicitan desde el Servicio de Prestaciones Sociales, para la revisión anual de las PNC, Certificado del director/a del centro donde se encuentra residiendo, con la fecha de ingreso, cada una de las siguientes personas tuteladas por la CTAEX: - Felisa Bruno Saavedra - Aarón Rosado Alarcón Si están firmados digitalmente, nos servirán escaneados, sino necesitaremos el original. Gracias de antemano y un saludo."','2');
