insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDA'and edp.apellido1='GARCIA'and apellido2='CARRILLO'),'2021-06-03','TERESA La tutelada SEGUNDA GARCÍA, lleva un tiempo hospitalizada grave, y la familia quiere que no esté sola nunca, con lo cual tiene acompañamiento las 24 horas del día desde hace tiempo, y hay que abonárselo a las personas que han estado y están con ellas. Os he llamado en numerosas ocasiones a los teléfonos 924 00 38 59 y 924 00 85 43 para comunicaros sobre su situación y no os localizo. También os he remitido correo electrónico el 24.05.2021. Por favor llamadme cuando podáis al 924 67 71 76','2');
