insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-06-04','Buenos dias , Aprobado los audífonos , la seccion eco se pondrá en contacto con la empresa para concretar la forma de pago , se va a financiar . Podéis pedir cita para que Emilia . Un saludo','1');
