insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2021-06-04','Ana: Tras llamada de Cristina, Ed. Asoc. Vera, envío correo a los Asesores Jurídicos CTAEX: "He recibido llamada de Cristina, Educadora de la Asoc. Vera (681 143 911). Le ha llamado el hermano de Antonia Bravo Patilla porque necesita documentos (copia del DNI y no sé si algo más), en relación a la Declaración de Herederos (su madre falleció hace unos meses). ¿Podríais por favor llamarle y aclarar lo que sea oportuno? Los teléfono del contacto son: - José Manue: 627 359 136 - Teresa (pareja de José Manuel y prima de ambos hermanos): 616 67 11 86 Ya me iréis contando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='VERA'and apellido2='NAVAS'),'2021-06-04','TERESA HABLO CON ANTONIA TS DE FUENLABRADA 924656005 A RAIZ DE UNA FACTURA QUE NOS ENVIA DE MATERIALES DE CONSTRUCCION POR IMPORTE DE 1000€ SIN PREVIA AUTORIZACION NOS COMENTA QUE HA DEJADO EL SERVICIO DE BANDEJAS DEL AYTO QUE PREFIERE HACERSE EL DE COMER Y POR ELLO PIDE QUE SE LE SUBA LA ASIGNACION PLANTEO A LOS JURIDICO EL REINTEGRO DE LA CAPACIDAD YA QUE CARMELO SE DESENVUELVE BIEN Y TIENE CONTROL SOBRE SU GASTOS CARMELO INCIO POR SU CUENTA ESTE PROCESO PERO NO SABESMOS NADA AL RESPECTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-05-11','Ana: correo de Toni Futuex: "Buenas de nuevo, al respecto de la tutelada Florencia Simón Martín, la semana pasada se realiza visita de seguimiento en el domicilio de la tutelada, en la vista están presentes Marcelina (madre de la tutelada de 96 años) Florencia y Francis la auxiliar de ayuda a domicilio que es quien proporciona toda la información sobre la tutelada, como es habitual. En primer lugar, transmite que a finales de marzo Florencia sufrió un fuerte mareo y acudió a la consulta del MAP, allí se la realizo una analítica general en la que dio bastante anemia, a raíz de ello se pauto hierro por vía oral y se la derivo al internista para revisión general. Esa cita es el próximo jueves 13 de mayo y se realizará acompañamiento a la misma en el hospital de Plasencia." ····· Adjunta dos documentos relativos a banco y a una deuda con una financiera que enviaré a Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-04','Ana: envío correo a Toni, Futuex: "Buenos días Toni, En relación a Florencia Simón Martín, ¿la compañera la acompañó finalmente a la cita médica, consulta en Medicina Interna, en Plasencia el día 13 de mayo? Y si es así, ¿os facilitaron informe al respecto? Si es así, facilítamelo por favor. Por otra parte, si ha vuelto a visitarla a posteriori y nos puede facilitar información de cómo se encuentra, os lo agradeceríamos también. Vamos a promover su internamiento. Gracias. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-06-04','miguel, se aplaza el juicio del día 14-6-21 por la división de la herencia, porque la parte demandante está pendiente que desde el Colegio de Abogados le asignen un abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-06-04','miguel, nos dan vista para el día 22-6-21 para la solicitud de internamiento involuntario solicitada. Solicito vía fax videoconferencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-05-28','Ana: Recibo correo oficial del Consulado de España en Bruselas. Se lo remito a los Asesores Jurídicos CTAEX para que hagan la comunicación al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-04','Ana: Pido a Julio, CTAEX, que consulte en SIDEX. Me informa: "Desde el 09/03/2017 tiene el PIA en trámite para una revisión del grado. La prestación de servicio que tendría sería atención residencial en residencia de mayores. El estudio económico lo tiene hecho desde el 04/04/2017. La fecha de fin de negociación es 10/07/2017 y la de salida de registro de Gerencia es 08/08/2017. Fue notificada la resolución el 29/05/2017 y recogió la misma una tal Francisca Hdez. (dni: 11.764.669P) Con lo que entiendo que la información anterior es lo que está en vigor actualmente. A pesar de que en el resumen el PIA aparezca como en trámite desde el 09/03/2017." ····························································································································································································· Llamo a Mª José Polo, TS del SSASB (664 018 209) varias veces, pero no obtengo respuesta. ····· Le envío un correo-e (ssbm@trasierratierrasdegranadilla.es): "Buenos días María José, Dado que no he podido contactar contigo por teléfono te envío este correo. En relación a Florencia Simón Martín, he pedido a un compañero que realice una consulta en SIDEX, y esta es la información que me facilita: “Desde el 09/03/2017 tiene el PIA en trámite para una revisión del grado. La prestación de servicio que tendría sería atención residencial en residencia de mayores. El estudio económico lo tiene hecho desde el 04/04/2017. La fecha de fin de negociación es 10/07/2017 y la de salida de registro de Gerencia es 08/08/2017. Fue notificada la resolución el 29/05/2017 y recogió la misma una tal Francisca Hdez. (dni: 11.764.669P) Con lo que entiendo que la información anterior es lo que está en vigor actualmente. A pesar de que en el resumen el PIA aparezca como en trámite desde el 09/03/2017” Creo que podríamos agilizar más por Dependencia, y que lo mejor sería aportar un Informe Social (Anexo IV) emitido por tu parte informando de la insostenibilidad de la situación y la desprotección en la que se ha quedado para y pedimos que le asignen plaza de forma urgente. Hablamos el lunes. Un saludo y buen fin de semana." ··········· Me llama Mª José, como finalmente fue revisada (antes de ser incapacitada) y dio Grado II, vamos a hacerlo por la vía de Decreto como acordamos ayer. Me enviará después los informes. **El lunes registraré todo de entrada (*Incluir informes previos para mayor información)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2021-06-04','Ana: Recibimos escrito de José: solicita que a partir de ahora, las comunicaciones con la CTAEX, siempre que sea posible se realicen a través de correo electrónico, a la siguiente dirección: josemoreno0092@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-05-11','Ana: Solicito a Begoña, Directora de la Res., que renueven el DNI. Se encargarán de solicitar la Ud. Móvil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-06-03','Ana: Correo de Mª Jesús, TS, Comarca de Trujillo (ssb32mancomunidadcomarcatrujillo@hotmail.com) : "Buenos días Ana: Isabel Muñoz, tutelada por la CTAEx , que reside en la Residencia de Jaraicejo, tiene un problema dental, parece ser que le duele mucho un diente y necesita ir al dentista, me comentan que esta alterada porque dice le duele mucho y así no puede estar. Tiene cita para el miércoles próximo para el dentista. El problema es que la taxista de la localidad, Ana, no la quiere llevar, porque la debe 220 €. Ese dinero atrasado, parece ser que se lo tendría que haber abonado la CTAEx , a quien se le hicieron llegar las facturas, pero no ha abonado tal cantidad. Si se pudiera agilizar este pago, la taxista no tendría inconveniente en llevar a Isabel, el miércoles, a su cita con el dentista. Gracias" ··············· Se lo reenvío a Alberto, Jefe Secc. Ecca. y pido que se abone la factura pendiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-06-04','Ana: Correo-respuesta de Alberto, Jefe secc. ecca: "Hola Ana. El problema es que NO nos consta la autorización previa (del área social o del área económica). En este caso, si te parece, cuando me mandes la factura, se abona, pero necesito un sistema a través del cual se acepte con anterioridad el gasto. NO NOS VALE QUE NOS MANDE LA FACTURA SI ANTES NO TIENE TU OK O EL MIO. Xfa, habla con la TS de Trujillo y que le comunique al taxista que todo servicio debe estar previamente aceptado por la CTAEX o que deberá cobrar en efectivo a la tutelada, porque no volveremos a pagar otra factura. A nivel ECO está bien pero hay que tener en cuenta que los 220 € son la mitad de su pensión. Alberto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-06-07','Ana: Llamo Mª Jesús Gómez Lozano, TS SSASB Mancomunidad Comarca Trujillo (621 247 237): hoy no está trabajando, motivos familiares. ··················· Llamo a Jose, Director Res. de Jaraicejo (608 962 782): no obtengo respuesta. Dejo un mensaje en el buzón de voz. ······································································································································ Envío correo a ambos (ssb32mancomunidadcomarcatrujillo@hotmail.com // josevillegassanchez356@gmail.com): "Buenos días Mª Jesús y Jose, Espero que estéis bien. En vista de que no puedo hablar con ninguno hoy, os reenvío el correo con la respuesta que me da Alberto, Jefe de la Secc. Ecca. Al parecer no tenemos constancia, en ninguna de las dos secciones, del desplazamiento anterior en taxi. Como podéis leer, es necesaria la autorización previa. En esta ocasión hacednos llegar la factura pendiente y se abonará a la mayor brevedad, pero pedirnos por escrito la autorización para la siguiente consulta al dentista. Y si os parece bien, de ahora en adelante se hará así, nos lo solicitáis previamente y una vez autorizado se abonará después la factura. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-06-07','Tfno. Padre: 657656184; Tfno. Hija: 611070785','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-06-07','Ana: Correo de Minerva, TS del CR Cervantes: "Buenos días Ana, La tutelada Mª Luisa Montaña Aliseda está teniendo distintos problemas de comportamiento en el centro. Pide insistentemente dinero y tabaco tanto a residentes como a trabajadores, y últimamente con amenazas. La semana pasada amenazó incluso a la directora del centro. Se la ha avisado también en reiteradas ocasiones que no está permitido fumar en las habitaciones, haciendo caso omiso a ello. Este fin de semana ha tenido un altercado con uno de los residentes, se han propiciado varios insultos entre ellos, terminando con un intento de agresión por parte del residente. Por los distintos comportamientos se le ha llamado la atención en varias ocasiones. Como consecuencia del último altercado se ha tomado desde el centro medidas disciplinarias: no bajará al comedor general, permaneciendo en su habitación para las comidas, y solo podrá salir a la sala multidisciplinar de la planta. No pudiendo bajar a la primera planta, ni a otras habitaciones de otros residentes. Está medida en principio se aplicará durante 15 días. Se ha trabajado con ella de manera multidisciplinar sin obtener resultados. Por todo ello se ha decidido por parte de la dirección del centro la posibilidad de traslado de Mª Luisa, ella por su parte en varias ocasiones ha manifestado su deseo de traslado de centro." ····························································································································································································· Mi respuesta: "Buenos días Minerva, Gracias por informarme. ¿Lo habéis comunicado a la Sección de Mayores o a la Unidad? Ya me vais diciendo." ································································································································································································ Conversación telefónica con Minerva, ya lo han comunicado a la Secc. Mayores. *Desde la CTAEX se acatarán las medidas como sanción que se decidan adoptar, pero nosotros no vamos a solicitar el cambio de centro. Si lo determinan se aceptará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-06-07','TERESA LLAMA EL PADRE JOSE MANUEL, TOMAS. SE QUEJA DE QUE NO PUEDE HABLAR CON SU HIJO CUANDO LLAMA AL CENTRO LE COMENTO QUE HABLARE CON EL CENTRO PARA INFORMARME LLAMO A MARIBEL PI ME COMENTA LA TRAYECTORIA DEL PADRE, TOMAS: TOMAS SE LLEVO A SU HIJO A BARCELONA, CUANDO SE QUEDO SIN DINERO EL PADRE YA NO QUISO NADA CON EL, INGRESO EN PSIQUITRICO Y DE ALLI FUE DERIVADO A PLENA INCLUSION EL PADRE HA ESTADO DESAPARCIDO DURANTE MUCHOS AÑOS. HACE UN PAR DE AÑOS APARECE UNA TIA PATERNA Y COMIENZA A LLAMAR AL CENTRO E INTERESARSE POR JOSE MANUEL ES POR ENTONCES CUANOD REAPARECE EL PADRE EL PADRE MANIFIEA QUE LE DEJEN QUE VEA AL SOBRINO PUES LA TIA TIENE UN INTERES ECONOMICO A PARTIR DE ENTONCES EL PADRE COMIENZA A LLMAR AL CENTRO TODOS LOS VIERNES (HACE UN AÑO) JOSE MANUEL SE PONE MUY NERVIOSO CON ESTAS LLAMADAS POR ELLO NO SE LE PASAN LAS LLLAMADAS CON EL HIJO, MARBIEL LE INFORMA DE COMO SE ENCUENTRA, ESTAS LLAMADAS NO LE VIENEN BIEN, SE PONE MUY NERVIOSO CON ESTAS LLAMADAS POR ELLO SE HA TOMADO ESTA DECISION EN CUANTO EL PADRE HACE PRESENCIA EN LA VIDA DE JOSE MANUEL LOS PROBLEMAS DE CONDUCTA APARECEN (LLORA, FANTASEA), LE AFECTAT MUCHO LAS LLAMADAS DEL PADRE JOSE MANUEL NO RECLAMA HABLAR CON SU PADRE YA QUE NO EXITE APEGA NI ARRAIGO ALGUNO','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-06-07','Ana: Correo de Cristina, Psicóloga del CRR-Mérida (psicologia.crrmerida@grupo5.net): "Buenos días Ana, ¿Qué tal? Soy Cristina, del CRR de Mérida. Comentarte que durante este fin de semana Damián G.H ha acudido de nuevo al servicio médico, de manera autónoma, y ha regresado al centro con un cambio de tratamiento." ·············· Mi respuesta y cita: "Buenos días Cristina, Gracias por informarnos al respecto. A ver qué tal evoluciona. Es muy dado a acudir a urgencias. Aprovecho para poner en copia a Gisela, y comunicaros a ambas, que dada la demanda insistente de Damián S. Granados Heredia, le damos cita mi compañero Miguel y yo para el próximos jueves día 10 a las 10 h. ¿Seríais tan amables de comunicárselo? Explicarle por favor que será una excepción (lo cuál ya le hemos dicho), no puede pretender que se le atienda presencialmente con asiduidad, y que será una cita breve puesto que tenemos más gestiones pendientes y una reunión ese día. Gracias por adelantado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-07','Ana: Envío el siguiente correo a Mª José Polo, TS SSASB: "Buenas tardes Mª José, Decirte que esta mañana ya se registró de ENTRADA la solicitud de ingreso en centro, relativa a Florencia Simón Martín, junto a los siguientes documentos: - DNI Florencia - DNI José Vicente - Nombramiento José Vicente - Delegación de competencias - Informe Social Modelo Solicitud - Informe Salud – Modelo solicitud - Informe Social TS SSASB - Informe Social TS C. Salud - Autorización Judicial Ingreso Involuntario Se ha enviado a: A/A: Pedro Sánchez Secc. Centros de Mayores Gerencia Territorial de Cáceres *Si no me equivoco, nos van a pedir informe de Psiquiatría en que se diga que actualmente no presenta alteraciones de conducta… veremos. Yo voy a ponerme ahora en contacto. Y mañana subiré en persona a hablar con May, jefa de secc. de recursos de mayores, pues hoy estoy teletrabajando. A ver si mañana mismo le dan curso y se puede agilizar el ingreso. **Por cierto, el jefe de la secc. económica de la CTAEX, me pregunta por “la manutención” del exmarido de Florencia. Y el compañero jurídico por el convenio regulador de la separación. ¿Podrías informarnos al respecto? Y ¿no tendrás copia del Convenio Regulador en el expte., no? Ya me dices cuando puedas." ····························································································································································································· Tras hablar con Pedro Sánchez, secc. centros mayores - Gerencia Territorial, envío nuevo correo a Mª José Polo: "Hola de nuevo Mª José, Acabo de hablar con Pedro, de la Gerencia Territorial, como me imaginaba, dado el Trastorno que presenta Florencia, hay que presentar Informe de Psiquiatría, ya le he dicho que hace mucho tiempo que no asiste a consultas con el especialista. En este caso dice que al menos un informe médico de Atención Primaria (a parte del ya enviado) en que se especifique que no presenta alteraciones de conducta. Ya me dices si es posible conseguirlo. Pero sin él no le van a querer adjudicar plaza… Mañana hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-06-07','TERESA RECIBO LLAMADA DEL PSIQUIATRA HOSPITAL DE AVILA SE ENCUENTRA TRAQUILO, DURANTE EL FIN DE SEMANA SE LE HA PUESTO ALGO DE CONTENCION POR ALGUNO EPISODIO DE AGRESIVIDAD NO MUY GRAVE TIENE VARIACIONES DE COMPORTAMIENTO VA A HACER REAJUSTE DEL TRATAMIENDO PARA MEJORAR EL PROBLEMA GRAVE DE APNEA DEL SUEÑO QUE LE ESTA PROVOCANDO INSUFICIENCIA RESPIRATORIA ESTA CON OXIGENO VA A PERMANECER INGRESADO TODA LA SEMANA ESTAMOS A LA ESPERA DE ASINGNARLE CENTRO POR DEPENDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2021-06-04','Ana: Correo de Cristina Castro, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "Buenos días Ana, Adjunto envío las nuevas resoluciones del reconocimiento del grado de discapacidad de: - Mª Antonia Bravo Patilla - Joaquín Herrero García Tengo los originales, ¿os lo envío mediante correo postal o lo guardo en su expediente del centro? Un saludo" ········· Guardo en el expte. digital y pido nos remita los originales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2021-06-04','Ana: Correo de Cristina Castro, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "Buenos días Ana, Adjunto envío las nuevas resoluciones del reconocimiento del grado de discapacidad de: - Mª Antonia Bravo Patilla - Joaquín Herrero García Tengo los originales, ¿os lo envío mediante correo postal o lo guardo en su expediente del centro? Un saludo" ········· Guardo en el expte. digital y pido nos remita los originales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2021-06-07','Ana: Hablo con Toni, TS C.R. Cervantes, en relación al correo que me envió el viernes. Acordamos que solicitaré el Alta de Terceros a la secc. ecca. y una vez nos la traigan del banco la registraré de entrada para envairla "prestaciones" del SES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-06-04','Belén: Se le concede plaza en la residencia Felipe Trigo. El traslado se realizará el miércoles 9 de junio tras prueba negativa de PCR. La tutelada manda un escrito solicitando que no se le traslade de centro porqque está totalmente adaptada en el que se encuentra. Esta petición se estudia pero no es viable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2021-06-08','-Amalia , envio email con la renuncia de la plaza residencial concedida aunte su negativa y la de su madre para que ingresara . NO considero de momento hacerlo de manera involuntaria , al ser centros abiertos corremos el riesgo de que se fuera del centro. Seguirá en plaza CO en P. I . Mérida . Buenos días , adjunto documento firmado por el Gerente respecto a la renuncia de la plaza de residencia concedida a MINERVA MARTÍN BLANCO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2021-05-21','miguel, en relación al procedimento de remoción del cargo de tutoro nº 37/2021 del jzdo de 1º instancia e instrucción nº1 de Villafranca de los Barros, remito a abogacía general informe solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA VICTORIA'and edp.apellido1='COBOS'and apellido2='REAL'),'2021-06-08','Ana: Nos comunican desde el CSS-Plas. que Mª Victoria ha fallecido esta misma mañana. Ha sido algo repentino. NO TIENE SEGURO DE DECESOS. ·············· No había manifestado con anterioridad deseo alguno sobre si quería ser enterrada/incinerada ni dónde. *Han hablado con los familiares, quienes viven lejos y dada la avanzada edad y problemas de salud, manifiestan que no van a acudir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-08','Ana: Llamo a Mª José Polo, TS del SSASB (664 018 209): solicitará informe médico a la MAP, en que se indique que actualmente Florencia no presenta alteraciones de conductas. ··························································································································································································· Envío correo-e a Pedro, TS Secc. Mayores - Gerencia Territorial (residenciasmayorescc@salud-juntaex.es), con copia a May Masegosa: "Buenas tardes Pedro, En relación a Florencia Simón Martín, tutelada por la CTAEX, te remito adjunta la solicitud de ingreso en residencia por emergencia social registrada ayer, junto con el resguardo de dicho registro de entrada y la siguiente documentación también registrada: - DNI Florencia - DNI Tutor Legal - Nombramiento José Vicente Granado Granado - Delegación de competencias José Vicente Granado Granado - Informe Social Modelo Solicitud – Vía Decreto - Informe Salud – Modelo solicitud – Vía Decreto - Informe Social TS SSASB (previo) - Informe Social TS C. Salud (previo) - Autorización Judicial Ingreso Involuntario Te remito también el Certificado de PFHC, que ayer no se registró. En cuanto al informe médico del que hemos hablado, creen que mañana me lo podrán hacer llegar. Te lo remitiré en cuanto lo tenga. Pongo en copia a May, Jefa de Secc, con la cuál en esta ocasión aún no he hablado, para que esté al corriente. Seguimos en contacto. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-06-03','Ana: Recibimos por fax, la respuesta de la Embajada de Mauritania: para renovar el pasaporte requieren alguno de los siguientes documentos: 1- Nuevo número nacional de identificación mauritano conforme al censo biométrico del 2011. 2- Pasaporte biométrico. *La persona también puede acudir a la embajada para la toma de las huellas dactilares para comprobar si sus datos figuran en la base de datos biométrica de Mauritania.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-06-08','Ana: Envío a Amor López, TS ASPACE, el escrito recibido de la Embajada y el escrito que se envió previamente desde aquí. Veremos si es suficiente en la oficina de Extranjería.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-06-08','Ana: Adelanto por correo a Gema, Admvo. Residencia El Pendere(resisantiago@hotmail.com), la documentación relativa al ingreso debidamente firmada y sellada. ············ Preparo oficio y se lo dejo junto a los documentos originales a Julio - CTAEX, para que le dé registro de salida y lo remita por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-06-08','Ana: Correo de Estrella, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. El día 14 de este mes y hasta el día 21 irá de pase a su domicilio Isabel Mª Cano Blázquez. Llama su madre para decir que necesita 120 euros para que se compre ropa... Tú dirás....espero tu respuesta. Gracias, Ana" ··································································································································································································· Mi respueta: "Buenas tardes Estrella, Antes de pasar la consulta al Jefe de Secc. Económica, que será quién autorice o no dicho extra, necesitaríamos saber si realmente existe dicha necesidad de comprar ropa, pues en la cuenta de Isabel, como ya sabéis, no hay que se diga un gran saldo… Si desde el equipo consideráis que existe tal necesidad se lo comunicaré a Alberto, quién verá si la cuantía que solicita Francisca es viable o no. Seguimos en contacto. Buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-06-08','Ana: Correo de Carmen, TS SSASB de Coria (carmen.martinez@coria.org): "Hola Ana, estoy tramitando el SAD Municipal para Emilia. Necesito me faciliteis en nº de cuenta para poder formalizar el contrato con la empresa encargarda de ejecutar el servicio, el Atyo le bonifica una parte y ella debe pagar otra a la empresa. En cuanto disponga de la Resolución de Alcaldia y Notificación, os la hago llegar. gracias un saludo" ····························································································································································································· Mi respuesta: "Buenas tardes Carmen, Me parece perfecto que le estéis tramitando el SAD. No obstante, en la sección económica, antes de facilitar los datos, necesitan saber la cuantía del copago que correspondería a Emilia, para que puedan autorizar dicho gasto. En cuanto el jefe de sección lo autorice te facilitamos el nº de cuenta a tal fin. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-06-09','Ana: Correo de Carmen, TS SSASB de Coria (carmen.martinez@coria.org): "Hola Ana, en cuanto tenga el contrato firmado lo envío, no obstante para poder ir adelantando la autorización del gasto, te informo que el coste de hora que ella debe pagar es de 3,50€/hora (iva incluido)) y tiene 8 horas mensuales aprobadas (28€ mes), no obstante necesito el nº de cuenta para formalizar contrato y así poder enviarlo. Gracias." ······························································································································································································· Mi respusta con copia a Alberto, jefes secc. ecca: "Buenos días Carmen, Entiendo que esa cuantía es asumible, son poquitas horas pero algo es algo. Le doy traslado a Alberto, jefe de sección económica. Le pongo en copia directamente. Alberto! Por mí OK al SERVICIO DE SAD (puedes ver el precio más abajo). Si hay inconveniente dínoslo (no sé como van las deudas y demás, pero Emilia tiene buena pensión) Te facilito aquí el nº de cuenta..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-06-09','Ana: Correo de Amor López, TS ASPACE: "Buenos dias Te mando la solicitud para renovar la cédula de Brahim para que la pueda firmar su tutor. Le he cambiado la fecha solamente es que ya había pasado tres meses... no sea que me digan algo cuando llegue. La fecha que he confirmado es el próximo miércoles 16 de junio a la 9.00, adjunto la confirmación de la cita. Te voy informando de todo. Un saludo." ··············· Completo la solicitud (Mod. EX16) y la pongo para la firma digital del D. Gerente. ········· Se la envío firmada digitalmente. ······ A petición de Amor, le envío escaneados tb los reportes de fax de todos los intentos de envío a la Embajada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-06-09','Belén. Se recibe el resultado de la PCR negativo y se envía a mayores. El traslado a la residencia Felipe Trigo se hará en el coche de un familiar(hermana)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA SAGRARIO'and edp.apellido1='GARCIA'and apellido2='PECES'),'2021-06-09','TERESA SE AUTORIZA EXCURSION DEL 15 AL 20 DE JUNIO','2');
