insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-06-09','Ana: Begoña, directora de la Res. Santiago de Alcántara, me remite por mail el Certificado de Ingreso en Centro de Florencia. ················ Se lo paso a los Asesores Jurídicos. Miguel lo remitirá al Jdo con la comunicación de ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-06-07','Ana: Llamo al Subinspector Vasallo, Policía Nacional - Oficina DNI (927 62 90 92): Me dice que lo siente, pero que no puede hacer nada. *Le digo que al menos podrán facilitarnos un documento en que se indique que Mª del Rosario ha perdido la nacionalidad, pues en el Registro me dice que como a ellos no les consta no pueden iniciar el expte. de recuperación de la misma. ·············· Me facilita el contacto del José Luis Gía, Secretario Gral. 927 62 65 48. Llamo, pero me dicen que está ocupado. Le dejan nota para queme devuelva la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-06-09','Ana: Puesto que no me ha devuelto la llamada, llamo a José Luis Gía, Secretario Gral. (927 62 65 48): Está reunido. Me devolverá la llamada. ················ Llamada de José Luis, Secretario Gral. de la Comisaría de CC: Quizá haya que preguntar en el Registro Civil Central Nacinal (Madrid). No obstante se compromete a relaizar otras consutlas para averiguar qué es lo que impide hacer el trámite de su DNI o ver cómo se puede solucionar. Me volverá a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2021-06-09','Belén. Solicitud PIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2021-06-09','Teléfono Carmen 661112466 dejo mensaje en el contestador para decirle que tiene cita para la vacuan del covid. Futuex la está llamando pero ella no quiere vacunarse . Le pido a los jurídicos información sobre protocolo a seguir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='RUBIANO'and apellido2='NAVAS'),'2021-06-09','TERESA HABLO CON LA URH ( 924388180)Y ME COMENTA QUE CARMEN ESTA BIEN, QUE VA A ESTAR UN TIEMPO AHI Y POSTERIORMENTE SERA DERIVADA A PISO TUTELADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2021-06-09','Ana: Correo de Felisa Custodio, TS CAMF-Alcuescar (trabajador_social_alcuescar@imserso.es): "Estimadas compañeras, se han puesto en contacto conmigo desde servicios centrales de COCEMFE en Madrid, para informarme que este año se reanuda el programa de vacaciones para personas con discapacidad de Cocemfe subvencionado por el IMSERSO. La residente quiere ir a la playa como otros años. Os comento: Van un grupo reducido de residentes de Alcuéscar a Benidorm, salida y vuelta en autobús privado desde Alcuéscar. Del 19 al 26 de agosto. Aún falta pero me han pedido en Cocemfe tener las solicitudes lo antes posible para la reserva del hotel, por las limitaciones de aforo. El coste total a aportar cada residente es aproximadamente 1500 euros, incluye traslados, hotel, pago estancia del cuidador/acompañante, gratificación al cuidador/acompañante, dinero de bolsillo etc. Ruego la firma de los documentos adjuntos autorizando las vacaciones. Muchas gracias. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2021-06-10','Ana: Envío correo a Felisa Custodio (trabajador_social_alcuescar@imserso.es): "Buenos días Felisa, Desde la sección económica nos dan la conformidad para la asistencia Rosario Solís Bermejo al programa de vacaciones del IMSERSO. Ponemos los documentos a la firma del D. Gerente. En cuanto los tengamos firmados te los hacemos llegar. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-06-07','TERESA LLAMA EL PADRE JOSE MANUEL, TOMAS. SE QUEJA DE QUE NO PUEDE HABLAR CON SU HIJO CUANDO LLAMA AL CENTRO LE COMENTO QUE HABLARE CON EL CENTRO PARA INFORMARME LLAMO A MARIBEL PI ME COMENTA LA TRAYECTORIA DEL PADRE, TOMAS: TOMAS SE LLEVO A SU HIJO A BARCELONA, CUANDO SE QUEDO SIN DINERO EL PADRE YA NO QUISO NADA CON EL, INGRESO EN PSIQUITRICO Y DE ALLI FUE DERIVADO A PLENA INCLUSION EL PADRE HA ESTADO DESAPARCIDO DURANTE MUCHOS AÑOS. HACE UN PAR DE AÑOS APARECE UNA TIA PATERNA Y COMIENZA A LLAMAR AL CENTRO E INTERESARSE POR JOSE MANUEL ES POR ENTONCES CUANOD REAPARECE EL PADRE EL PADRE MANIFIEA QUE LE DEJEN QUE VEA AL SOBRINO PUES LA TIA TIENE UN INTERES ECONOMICO A PARTIR DE ENTONCES EL PADRE COMIENZA A LLMAR AL CENTRO TODOS LOS VIERNES (HACE UN AÑO) JOSE MANUEL SE PONE MUY NERVIOSO CON ESTAS LLAMADAS POR ELLO NO SE LE PASAN LAS LLLAMADAS CON EL HIJO, MARBIEL LE INFORMA DE COMO SE ENCUENTRA, ESTAS LLAMADAS NO LE VIENEN BIEN, SE PONE MUY NERVIOSO CON ESTAS LLAMADAS POR ELLO SE HA TOMADO ESTA DECISION EN CUANTO EL PADRE HACE PRESENCIA EN LA VIDA DE JOSE MANUEL LOS PROBLEMAS DE CONDUCTA APARECEN (LLORA, FANTASEA), LE AFECTAT MUCHO LAS LLAMADAS DEL PADRE JOSE MANUEL NO RECLAMA HABLAR CON SU PADRE YA QUE NO EXITE APEGA NI ARRAIGO ALGUNO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-06-09','Ana: Tras llamada de de Julián, COCEMFE, envío correo a Alberto, Jefe Secc. Ecca.: "Hola otra vez, Alberto, Acabo de hablar con Julián de COCEMFE en relación a la subvención para la silla de ruedas de Tomás Esteban, me comunica que había habido una incidencia en la resolución de la solicitud. En teoría ya está subsanado y el ingreso se hará efectivo entre finales de esta semana y la semana que viene en su cuenta. ¿Podríais comprobarlo la semana que viene y confirmarme si ha sido así por favor? Seguimos." ················· Otras cuestiones abordadas con Julián-COCEMFE: Proponen la asistencia de Tomás al Programa de Vacaciones del IMSERSO, sólo pueden ir algunos residentes, pero le van a dar preferencia a él, dado que no tiene salidas con familiares. La duración es de 1 semana y necesitaría ir acompañado de 1 cuidador/a, a quién también habría que pagar. **Acordamos que envirán presupuesto, tanto relativo a vacaciones, así como de acompañamiento periódico a salidas para disfrutra de ocio y TL en la comunidad (Enviará 2 propuestas, una con 2h/semana y otra con 4h/semana). ············ Así mismo, se realizará seguimiento por parte de 1 educadora de Futuex un día/semana. *Se lo confirmo a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-06-10','miguel, remito email a Amalia y Alberto: Buenos días Amalia, no he logrado localizarte telefónicamente. He vuelto a llamar a inmobiliaria Colón, persona de contacto Ana (652410390)y con inmobiliaria Finca Servicios Inmobiliarios(tlfno 924452828, persona de contacto Emilio Delfa). Una de las dos o las dos pueden ser las que nos lo vendan, el precio lo darán una vez que visiten la vivienda, para lo cual necesitamos que te hagas con las llaves y alguien (supongo que la Trabajadora Social del pueblo) les acompañe a verla, una vez lo cual tendrán que volver a hablar conmigo y ya decidimos entre las 3 secciones cuál de ellas elegimos. Por favor haz las gestiones de hacerte con la llave y o bien les llama la trabajadora social o bien me das el teléfono y vuelvo yo a llamar a las inmobiliarias y les doy el teléfono de dichas inmobiliarias. ***************************************************** Buenas Miguel , no te he podido coger la llamada pero estamos como el perro y el gato, te estoy llamando y ahora no puedes cogerla tú. El caso lo lleva ya Teresa , ha pasado a su zona de referencia , la incluyo en el email para que vea la gestión que se propone. Las llaves del piso las tiene la TS del pueblo , se quedaron allí guardadas . Tere puede quedar con ella o con la delegada tutelar para enseñar la casa . ***************************************************** Tere dime día y hora en que la Ts puede quedar para enseñar la casa para avisar a la inmobiliaria. Tendría que ser en dos días ya que van a ir a verlo dos inmobiliarias….','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-06-10','Ana: Envío correo a Gisela, TO CRR-Mérida (tocupacional.crrmerida@grupo5.net): "Buenos días Gisela, Como sabes hoy hemos tenido la visita de Damián, le hemos atendido Miguel, Asesor Jurídico, y yo. Pero a las cuestiones que suele plantear a Miguel hoy no le ha hecho mucho caso. Venía con la idea fija de solicitar el aumento de la asignación mensual y las asignaciones semanales con las que le ayudáis a gestionarse en el recurso (insiste en que quiere 20€/lunes, 7€/miércoles y 20€/viernes). Ya le he dicho que esta propuesta debe partir desde el CRR y siempre y cuando entendáis en el Equipo Terapéutico que se va a hacer un buen uso del dinero. Que no sea para gastarlo en algo dañino para su salud. Por otra parte, nos ha contado que ya se ha inscrito en la Ciudad Deportiva y nos ha enseñado el contrato y la pulsera. El contrato, tal y como le hemos pedido, lo ha enviado al correo de la Comisión Tutelar. Pero ya le he explicado que no debería haberlo hecho así, que sabe que primero hay que enviar presupuesto a la CTAEX y solicitar la autorización previa (Esto no es nuevo pues ya se le explicó en Plasencia). Y que, además, ese contrato sin la firma de su Representante Legal, no tiene validez, pues su curatela es también económica. Ya he hablado con Alberto, Jefe Secc. Ecca., de ambas cuestiones. Me pide que os traslade por favor, que de forma “urgente” Damián anule ese contrato y si quieren uno nuevo tiene que ir aprobado desde aquí y firmado por su Representante Legal. Si no se hace así, los recibos que entren en su cuenta (sin haber sido autorizados) se van a devolver y perderá, posiblemente, la opción de volver a apuntarse al mismo gimnasio. ¿Podríais por favor abordar este asunto con él? En cuanto al aumento de la asignación Alberto lo estudiará en cuanto nos enviéis la propuesta. Ante cualquier cuestión, hablamos. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-06-10','Buenas, pues el traslado se esta produciendo en este momento. El piso de Merida, la verdad que debe estar en un estado lamentable...la fianza sin duda que no la devuelve y veremos si no pide mas dinero para limpieza. Si te parece para la semana que viene, que vayan Sonia y Tere (que conoce al arrendador, Pedro) y queden con el para entregarle las llaves. Le vamos a llamar para adelantarle que dia podemos quedar si te parece. En el piso nuevo, aun no ha entrado, porque estaba llegando a Merida, ira todo sin incidencias, imagino. Estan dos compañeras alli esperandolo en Zafra. Estamos teniendo problemas para localizar a alguien en CEDEX Merida, ya que desde Zafra nos indican que son ellos los que deben pedir la derivacion del tratamiento por cambio de domicilio. Seguiremos intentando. El tema del banco, supongo que sera lo que mas inquiete al tutelado, creo recordar que saca a la quincena, asiuqe cuando este la oficina nueva donde retire, comentadnoslo para que se lo digamos a el, e intentaremos apoyarle en eestas gestiones por lo menos al principio. Seguimos en contacto!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-06-10','Hablo con madre de Isabel , Francisca, nos confirma que ha pasado la linea de tlf a MAsmovil y el recibo que nos ha llegado de jaztel es el último. El tlf de Isabel que utiliza solo cuando está en casa de la madre 649642635','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-10','miguel, Buenos días, me ha llamado el abuelo para comentarme que le ha llegado ayer día 9-6-21 dos cartas, una de la AEAT que parece ser una complementaria y otra de clases pasivas. Le dan un mes para alegaciones con lo que está intentando contactar contigo para quedar y llevártelas para que me las hagas llegar (si quieres escanealas, a ver de qué se trata) Ya le he dicho que del otro asunto del reparto de la cuenta, no tengo noticias del otro abogado que quedó en indicarme un contacto del SCH para que nosotros como representantes de Alejandro pudiésemos solicitar un certificado que acredite la procedencia del dinero de esa cuenta. Intentaré hablar con el abogado próximamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-06-10','-Amalia , envio email a seccion eco ( Alberto ) Alberto , no sé cómo estarán sus cuentas , y si valorarás positivamente darle algún extra para verano , para que compre ropa y demás . Es el mismo tema de siempre , no veo yo tanto problema a la limitación económica si no a su falta de capacidad para administrarlo , no sabe ya qué hacer para sacar dinero . Ha llegado a amenazar a los trabajadores del banco que nos indican que la van a vetar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-06-11','Ana: Tras varios correos intercambiados con Juana-CTAEX, Toni Futuex, y Toni, TS del CR Cervantes, relativos a la Declaración de la Renta de Eugenia, recibo correo de Toni TS Cervantes concretando lo siguiente: "Buenos días Ana. He hablado con Gloria, la educadora de Eugenia Pacheco, y ya ha concretado la cita Presencial en hacienda de Cáceres. la cita la tiene el viernes 18 de junio a las 10. Acompañará Gloria a Eugenia. un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TRINIDAD'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2021-06-11','Ana: Llamo a Raquel, TS SSASB Mancomunidad de la Vera (667 068 078) varias veces, pero no obtengo respueta. ············ Le envío un correo-e (ssasbrpa@gmail.com): "En relación a Trinidad Sevillano Sevillano, según veo en el expte. digital, se trata de una defensa judicial aceptada por la CTAEX en 2018. En la defensa no se encomienda nada en concreto a la CTAEX, por tanto en esto casos no podemos hacer nada. Es más, al procedimiento judicial acuden desde Abogacía General de la Junta de Extremadura en representación de la CTAEX, mis compañeros Asesores Jurídicos no ejercen como Abogados. A posteriori, 2n 2019, se solicitó una aclaración de sentencia al Juzgado y que yo sepa, a día de hoy no hemos obtenido respuesta. Le he trasladado a mis compañeros la consulta, a ver si pueden decirnos algo más."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TRINIDAD'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2021-06-10','Ana: Correo-e de Raquel, TS del SSASB Valverde de la Vera (ssasbrpa@gmail.com): "... preguntarte sobre una persona, que hace un par de años o más, promovieron una incapacitación, pero no hemos vuelto a saber nada del tema, sé que una vecina fue citada al juzgado, pero ella dijo que no quería ser tutora, es por si tenéis conocimiento de algo, el señor se llama Trinidad Sevillano Sevillano, su hermana, ya fallecida, estaba tutelada por la Comisión, se llamaba Marcelina Sevillano Sevillano, y su tutor era según la información que he podido recabar, "Jose". Me consta que aún no se ha resuelto nada de la herencia, ya que hay cuentas bancarias, en las que figuran los dos hermanos y está bloqueada la parte que le corresponde a la difunta. Te agradecería que me informaras al respecto, más que nada, por ver qué rumbo tomar con Trinidad. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-06-10','-Amalia : envio email a seccion eco y juridica : Buenos días , Mercedes lleva una semana acudiendo a todos los recursos , incluidos éste , solicitando poder sacar dinero de su cuenta . Les enseña la cartilla bancaria para que vean que tiene dinero y que ella no tiene" ni para comer " . Literal es lo que ha dicho en el comedor social desde donde me han llamado hoy . Les he explicado que desde la Comisión se garantiza la cobertura de todas sus necesidades básicas , se cubre alquiler , suministros.. y se le dan 200€ a la semana para alimentos . Me ha llamado directamente Mercedes , insta a que se cumpla su sentencia en la que se dispone que tiene que ser consensuado y quiere que se le revise nuevamente el presupuesto . Desconozco si a nivel jurídico se tendría que aceptar su solicitud económica . En su cartilla según me dice la compañera del comedor hay un embargo del OAR de 6.000 € por si tenéis que echarle un vistazo. Seguimos... ------------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-11','Ana: Envío a Pedro Sánchez, Gerencia Territorial (residenciasmayorescc@salud-juntaex.es) el informe médico del MAP que me remite Mª José Polo, TS SSASB Trasierra. ················· **Respuesta de Pedro: "Buenos días Ana En el informe no acredita que no tenga alteraciones conductuales que impidan el normal desarrollo en la vida del centro, como regula el Decreto 88/96 Según el protocolo que tenemos, necesitamos que se acredite dicha situación Un saludo" ················ Se lo comunico a Mª José Polo, quién volverá a pedir nuevo informe a la MAP.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-06-10','Ana: Llamada del Subinspector Manuel Vasallo, Policía Nacional - Oficina DNI (927 62 90 92): Me dice que por mediación de José Luis han hecho más averiguaciones. Me indica que puede haber 2 posibilidades: 1- Llamar al registro civil provincial de CC para solicitar la "Recuperación de la Nacionalidad como Española de Origen". Con el documento que me facilitaran una vez presentado lo que nos indiquen, se podría gestionar el DNI. *En el mes de julio la Ud. Móvil seguramente volverá a Coria. 2- Contactar con el Grupo de Extranjeros de la Policía y Solicitar la renovación del NIE, pero estos tendrían que acudir a la residencia de mayores a tomar las huellas de Rosario y puede ser más complicado y más lento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA VICTORIA'and edp.apellido1='COBOS'and apellido2='REAL'),'2021-06-11','EXITUS El centro informa de su óbito, acaecido el 08/06/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-06-11','Ana: Llamo al Registro Civil de CC (927 62 02 68): pregunto si me pueden facilitar el nº del Registro Provincial, me indican que no existe tal registro. Ante la actitud de colaboración, expongo la situación: Entiende que en úlitmo termino, habría que solicitar le "Recuperación de la nacionalidad de origen mediante una una Declaración por escrito ante el Registro Civil de la localidad de residencia (o en este caso del representante legal - Mérida), de acuerdo con el art. 26 del Código Civil. **Habría que ratificarla ante el Registro. **En teoría con esto conseguiríamos respuesta por escrito de que "no se puede inciar tal procedimiento pues no consta en el registro que dicha señora haya perdido la nacionalidad". ····························································································································································································· Llamo a Ángel, Asesor Jurídico CTAEX, le informo de la situación y de todas las gestiones llevadas a cabo hasta la fecha. Intentará conseguir las respuestas por escrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2021-06-11','miguel, recibo email del hermano del tutelado, Rafael confirmandome que ya ha presentado en registro de Junta de Andalucía la renuncia de herencia de sus padres del curatelado y me remite justificante de presentación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-06-14','Ana: Correo de Gisela, TO CRR: "Hola Ana buenas tardes. Disculpa en no responderte ayer, hoy ya lo hago con lo resuelto por parte de Damián, la baja del contrato del gimnasio. Adjunto el comprobante y ha traído el contrato (si lo necesitas también te lo envío). He llamado al centro deportivo para que contemplen no cobrarle desde el día que se dio de alta hasta hoy (baja) ya que no ha ido. Estiman que se lo compensarán si Damián retoma, una vez que esté valorado por vosotros. El presupuesto que le entregan es informativo (folleto), el precio 39,95€ al mes. Y sabe que, si le autorizan que se apunta de nuevo, el contrato lo deben firmar ustedes. Sobre el aumento de asignación, hacemos revisión semanal de su planificación económica, por lo que la semana próxima lo trataremos. Te mantenemos al tanto y desde ya muchas gracias por la coordinación. Un saludo." ················· Se lo reenvío a Alberto, jefe secc. ecca. Por mi parte Ok al presupuesto de la Ciudad Deportiva. ·················· Alberto da el OK.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2021-06-14','-Amalia: pongo en registro entrada oficio y documentación solicitada por el INSS de Sevilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-06-14','Ana: Recibimos Resolución de extinción de PNC y la cuantía recalculada de Cobro indebido: 807,89 € a abonar. **Se la paso a Alberto, Jefe de Secc. Ecca. para que procedan a devolverlo. **Escaneo y guardo en el extpe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-06-14','miguel, ya está casi tramitado la presentación del impuesto de sucesiones de este curatelado. Pregunto a Tere qué gestoría lo está tramitando ya que hay un documento "cuaderno particional privado" firmado electrónicamente del día 10-6-2021. La gestoría es: Del Cid y Villafaina C/ Rafael Ortega, 5 06340 FREGENAL DE LA SIERRA Tfno. 924 700 303 Fax 924 702 129 Inmaculada Zambrano Hernández ***************************************************** Tras comentarlo con Alberto, y a petición de éste remito email a Tere con copia a él de las siguientes cuestiones: Una vez que se tramite la presentación del impuesto de sucesiones, diles que se tienen que encargar de presentar la documentación que requieran esas entidades y desbloquen las cuentas e ingresen el dinero que corresponda al curatelado (tanto de cuentas corrientes, fondos de inversión y cuenta de valores). Que gestionen el cobro del seguro de vida para su ingreso en la cuenta del curatelado (son 100.461,50€) Te dejamos en tu mesa el documento firmado electrónicamente, junto con unos recibos que habrá que ver si son o no del curatelado y habremos de verlo con Alberto más adelante…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2021-06-14','TERESA el pasado 4 de Junio se visitó a Ramón González Hernández en su vivienda de la calle Toledillo Bajo de Jerez de los Caballeros. Comentó que uno de los guarros adultos del campo había destrozado una de las paredes de la cochiquera y tenía que repararla, por lo que necesitaba materiales de construcción. Se le acompañó al campo para comprobar el destrozo que había producido el animal y se ratifica la información que había comentado Ramón, ya que una de las paredes de la coquiquera estaba totalmente destrozada. Seguidamente se fue con el tutelado a una tienda de materiales de construcción de la localidad y se pidió un presupuesto para comprar unos bloques, arena y unos sacos de cemento. Se adjunta envía dicho presupuesto. Hoy ha llamado muy nervioso a la compañera, porque otro animal a destrozado otra parte y le urge mucho al parecer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-06-14','miguel, llega del Jzdo de Coria el traslado de actuaciones para que informe el MF','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-06-14','Ana: Correo de Toni, TS del C.R. Cervantes: "Buenos días Ana en relación a Guillermo Galan Gigaldo sigue estable. A la espera del que el día 21 de junio le hagan un TAC Un saludo Toni de Diego"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-06-14','Ana: Correo-e de Miguel, Asesor Jurídico: "Buenos días, compis, El Juzgado de Trujillo ha archivado el procedimiento de internamiento involuntario, al encontrarse en Bélgica. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-06-14','Ana: nueva llamada de Juan Carlos, contenido similar a las últimas conversaciones: su taller, salidas a cafeterías, cine... dado el calor se ha parado la actividad en la protectora de animales. **Sigue preguntando cuándo se va a poder ir a otro centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-06-14','Ana: Subimos a hablar con May, Jefa de secc. mayores, Miguel, Asesor Jurídico, Maite, Jefa de secc. CTAEX, y yo. Estamos de acuerdo que pedir el cambio de centro sin agotar otras opciones es "mover el problema de sitio". Hablaré con la TS para proponer valoración en ESM. Por si fuera necesario un reajuste de la medicación. ············ Llamo a Minerva, TS del C.R. Cervantes (22237) varias veces: comunica. ················· Envío correo-e a Minerva (minerva.salvador@salud-juntaex.es): "...En relación a la situación actual de Mª Luisa y las conversaciones mantenidas al respecto tanto contigo como con Ana, Directora de la Residencia, esta mañana hemos estado hablando la nueva Jefa de Secc. de la CTAEX, uno de los Asesores Jurídicos y yo con May Masegosa, Jefa de Secc. Recursos de Mayores. Mañana si quieres lo hablamos con más calma. Pero lo primero que se plantea, antes de solicitar el cambio de recurso, es que la valoren en el Equipo de Salud Mental, por si pudiera estar descompensada, ¿sería posible que la derivasen de nuevo? Lo digo más que nada porque en el informe que me enviaste consta el Alta que le dio la Dra. Espárrago en Febrero de 2020, aunque mantenía tratamiento. Pero sería interesante que valorasen las alteraciones de conducta que presenta últimamente, por si pudiera obedecer a su patología."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='CARVAJAL'and apellido2='MORENO'),'2021-06-14','TERESA ANTE SENTENCIA QUE NO NOS PERMITE HACER GESTIOENS EN LA CUETAN SIN LA PREVIA FIRMA DE CATALINA VAMOS A PEDIR MOFICAR LA SENTENCIA PARA QUE CAMBIE YA QUE CATALINA TIENE DIFICUALTD DE MOVIMIENTO Y NO PUEDE DESPLZAZAR A LA ENTDA PARA FIRMAR VAMOS A HACER UN REINTEGRO Y LO CUSTODIARA LA DIRECTORA PARA IR PAGANGO LOS GASTOS PERSONALES QUE VAYA GENERADO, LA PLZA SE CARGA EN CUENTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-06-14','Ana: Recibimos firmeza de la sentencia de Isabel Muñoz. Subimos a hablar con May, Jefa de secc. mayores, Miguel, Asesor Jurídico, Maite, Jefa de secc. CTAEX, y yo. ········ Ahora no hay más opción que solicitar de nuevo cambio de centro. **Llamar a la Técnica PIA y solicitar el cambio de centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-06-10','Ana: Minerva, TS del CR Cervantes, me remite por mail 2 informes médicos. En la última consulta en el ESM en febrero de 2020 la Dra. Espárrago le dio el alta. ····· Diagnóstico: Trast. delirante crónico. ··············· Los guardo en el expte. digital.','2');
