insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-06-15','Ana: Correo-e de Minerva, TS CR Cervantes: "Buenos días Ana, Respecto al asunto de derivar a Mª Luisa nuevamente a los Equipos de Salud Mental, dado que ya fue valorada y el facultativo especialista consideró darla el alta, desde el centro y según criterio del médico que hace el seguimiento diario a Mª Luisa no se considera oportuno volverla a derivar al psiquiatra, dado que las alteraciones conductuales que presenta actualmente no se deben a su patología y ella es consciente de sus actos. Un saludo" ····························································································································································································· Conversación telefónica con Ana, Directora del C.R. Cervantes: Dado que la Médica del centro no estima hacer la derivación a Mª Luisa a Salud Mental, mantienen su propuesta de que solicitemos desde la CTAEX cambio a otro recurso, como el CSS. Esta última propuesta nos parece incongruente teniendo en cuenta que le dieron el Alta en Salud Mental y la respuesta que da la Médica del centro. No existe otro recurso "más adecuado a su perfil". *Plantea entonces que solicitemos un centro residencia más pequeño, pero desde la CTAEX tampoco consideramos que sea la solución. Mª Luisa, aunque al principio le costó un poco, se adaptó bien al recurso. Los principales problemas han surgido a raíz del confinamiento. Antes de La Covid, ella salía sola de la Residencia, pero ahora no le dejan salir sola porque dicen que ocupa una Plaza de Asistidos y que en este caso no puede salir si no es acompañada (sigo sin comprender por qué antes sí). Además, estando en el centro se le valoró con Grado I de Dependencia, por ello tampoco nos cuadra que la plaza que ocupa sea de Asistidos... consultaré en la Secc. Mayores. ······························································································································································································ Envío correo a Toni-Futuex: "...En relación a María Luisa Montaña Aliseda, dada los problemas conductuales y transgresión de las normas de que viene presentando de un tiempo a esta parte en el Centro Residencial y su necesidad de salir más del centro (consideramos que las restricciones por La Covid le han afectado bastante), ¿sería posible intensificar el seguimiento y el acompañamiento a salidas por parte de Virginia? En las salidas podría abordar su actitud y conductas inadecuadas (pedir dinero a otros residentes y familiares, colare en habitaciones ajenas…) Así mismo, nos gustaría que nos informaseis sobre si demanda o no un cambio de centro y en caso afirmativo, constatar si esta solicitud por su parte obedece al deseo de acercamiento a su hija, la cual actualmente reside en un recurso de Plasencia. Consideramos que los últimos contactos que ha mantenido con ella pueden estar también afectándole negativamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-06-15','Ana: Correo-respuesta de Estrella, TS CSS-Plas, en relación al PIA para la prestación vinculada al SAD: "Buenos días, Ana Sí, he llamado a 7 empresas para comparar precios y saber si tienen un profesional con perfil de "educador" que les enseñe a organizar el hogar. La más económica es Khenea por 20 horas cobran 220 euros y claro les reducirían la subvención, no he preguntado exactamente la cantidad que le quedaría, pero supongo que rondaría los 70 euros, con lo que tendrían que abonar unos 150 euros. Yo todavía no he hablado con ellos, sí lo han hecho sus Psiquiatras, y se muestran de acuerdo en que se le preste la Ayuda a Domicilio y abonar lo que les corresponda. Mi itinerario es: Primero consultar con vosotros. Ya lo he hecho y os mostráis de acuerdo. Segundo hablar con Desi y Ángel, para ver si aceptan. Tercero, comunicar al Sepad el cambio de horas para que hagan otra Resolución PIA con subvención a conceder. Cuarto, Correo a la empresa para que hagan contrato. Así que continúo, hablo con Desi y Ángel, a ver si me da tiempo hoy (tengo la mañana apretada, reuniones....), sino mañana."','2');
