insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-06-16','-Amalia . Pasa a Piso Supervisado de Mérida . Que D. Beatriz Mejias de la Morena,con D.N.I n.º 08890699A, tiene establecida su residencia actual en MÉRIDA, Avda. de Portugal n.º 17, portal 4, bajo B, C.P 06800. Ingresará en el PS fue el 16 de junio del 2021. Convivirá en un Piso Supervisado (PS) con fines rehabilitadores, dependiente del SEPAD, de la Consejería de Sanidad y Políticas Sociales de la Junta de Extremadu','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-06-16','-Amalia : PREVISIÓN DE GASTOS MENSUALES PACIENTE: Dña. BEATRIZ MEJIAS de la MORENA. DNI: 08890699A La usuaria mencionada se incorporará a los PS el miércoles 16 de junio del 2021. Auxiliar de referencia: D. Miguel González. 1.-Aportación mensual (40 € semanales para gastos de comida) = 160€/mes 2.- Móvil = 20€/mes 3.- Tabaco = 125€/mes 4.- Productos para higiene personal = 40€/mes 5.- Asignación personal = 60 €/semana TOTAL MENSUAL = 405€/mensual Para el inicio de su incorporación al piso, Beatriz tiene que hacer una única aportación extra de 200€ para: ropa personal, ropa de cama, aseo, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-06-16','TERESA ME PONGO EN CONTACTO CON EL PSIQUIATRA Y ME COMENTA QUE SE ENCUENTRA TRANQUILO Y COLABORADOR, INSISTE EN LA PROBLEMATICA DE LA APNEA, LE A REAJUSTADO EL TRATAMIETNO PARA MEJORARLA EL ALTA ES INMININENTE, ESTAMOS PENDIENTE ASIGNEN CENTRO POR DEPENDENDENCIA MANDO EMAIL A TERESA.ENCINASRIVERA@SALUD-JUNTAEX.ES RESPONDABLE TRANSPOTE SANITARIO DEL ARA DE CORIA PARA GESTIOANAR TRASLADADO YA QUE DESDE AVILA NO NOS FACILITAN TRASLADO EN AMBULANCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2021-06-16','Buenos días , Miguel , Rosa tiene una curatela " exclusivamente para la esfera económica ", ajustándonos a sentencia, para el resto de las esferas no están incapacitada . Económicamente su situación es deficiente , con más gastos que ingresos y con muchas deudas pendientes . No creo que sea viable económicamente hacer frente a gastos de seguros de coche , ITV , mantenimiento , carburante... Ni creo que sea algo muy necesario para moverse por Montijo. Cuando me enteré que había solicitado 50€ para pasar revisión médica hablé con el centro , para que pidieran informes médicos que valorasen si eran compatible con la actividad de conducir . Esos informes te los pasé , supongo que lo enviaste al juzgado del que aún no se ha recibido respuesta. Desde la parte social nada más puedo aportar ,no está incapacitada para esa esfera. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-06-16','Buenas tardes, a continuación se desarrolla nota relativa al cambio de domicilio de Mérida a Zafra, del tutelado Jose M, Valle Simón, asi como la factura pendiente de pago del traslado en taxi, reflejamos el núnero de taxista en caso de necesitarse, 651319047 (Israel). Mañana 16, se ocudira al piso de Mérida para hacerle entrega al dueño de las llaves. Nota gestión cambio de domicilio – traslado de localidad: El nuevo domicilio se encuentra en la calle Canal nº6 en Zafra, muy bien situado cerca de la plaza de España y a tan solo 7 min andando al centro de salud – CEDEX y a Liberbank (banco de referencia). Además, cerca tiene estanco, farmacia y varios supermercados. En cuanto al piso: - Observamos una avería en el termo y avisamos a la inmobiliaria que directamente gestiona el arreglo con un fontanero. - El piso no se encuentra muy limpio por lo que también se avisa a la inmobiliaria que inmediatamente gestiona la limpieza del mismo para esa misma tarde. - Dos juegos de llaves: uno que se queda José Mª y otro que lo recoge Susana educadora de apoyo del equipo de apoyo social comunitario. Una vez instalado en domicilio y explicarle el funcionamiento de la televisión, luces de la vivienda, lavadora y el termo para la ducha, le acompañamos para conocer el entorno y gestionar el cambio de CEDEX. En el centro de salud: - Se le solicita la asignación de médico de atención primaria. - CEDEX: mañana tiene que ir para recoger la metadona y en este CEDEX pasará a recoger el tratamiento lunes y jueves debido a la alta dosis de tratamiento. Además se le realizará controles de orina. El día 21/06/2021 tiene cita con la Trabajadora social del CEDEX para abrirle la historia clínica y conocer más a José Mª. Por otro lado, con el dinero en efectivo que tenía José Mª (30€) se realiza acompañamiento y apoyo para la realización de la compra de productos de higiene personal y alimentación por un total de 17.37€. Por lo tanto, aún le quedan 12.63€ hasta la próxima retirada de dinero. Gestiones pendientes y posibles líneas de intervención: Económico: - Seria necesaria la autorización para comenzar con la retirada de dinero correspondiente a su asignación quincenal en el Liberbank de Zafra. Le toca sacar mañana y si no puede sacar, no cuenta con dinero ya. - Valorar la posibilidad de abordar gastos extras para: cafetera, sabanas, toallas, almohada, lámpara y cubo de basura. Sanitario: - Cita con el médico de familia para regular la tarjeta sanitaria, solicitar derivación a salud mental para retomar las revisiones y comentarle sobre la 2ª dosis de la vacuna frente a la covid19 que la tiene en Mérida el próximo 26 de Junio. Social: - Empadronamiento y ver las posibilidades para solicitar una ayuda a domicilio desde el Ayuntamiento. - Buscar posibilidades para contratación de catering para así mantener una dieta y alimentación saludable pudiéndose reducir su asignación ya que solo tendría los gastos de tabaco, productos de limpieza y aseo y alimentación para desayuno. Cualquier cosa al respecto, quedamos a disposicón!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-06-16','-Amalia , escribo a la sección eco : Buenas , habrás escuchado a Jonathan , solicita 250€ de la extra de junio para gastos de alquiler , comida , medicación , tasas DNI y fotos , ropa ... He hablado con su pareja ( Susana ) y le he pedido que guarde tikets de todo . Solicita el reintegro para mañana , si es posible , cuando esté lista avisadles al tf de Susana 643248625 para que puedan ir al banco . Seguimos ....','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-06-15','Ana: Ángel, Asesor Jurídico CTAEX, me remite autorización judicial de ingreso involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-06-16','Ana: En relación a la Sentencia de Incapacitación Judicial y al internamiento, Ángel, Asesor Jurídico CTAEX, me envía un correo: "La firmeza es el 13 de julio, fecha en la que solicitaremos testimonio de la misma al Juzgado, para aceptar el cargo. Toda la documentación está en su expediente, en la carpeta de incapacitación. No obstante, el plazo de recurso, no produce efectos suspensivos, con lo que ya puedes empezar a trabajar con ella, para ir solicitando centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-06-16','miguel, me confirma Belén TS, que tanto inmobiliaria Colón como Fincasi irán en próximos días a visitar la vivienda de la calle Hinojo. Las envío un email con la escritura de compraventa, donde les indico que una vez la valoren nos den presupuesto y decidiremos a cuál de las dos o a las dos (si no se oponen)podemos darles el encargo y reenvío los dos email a la parte económica y social (Alberto y Belén Ts)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-06-16','miguel, tras hablarlo con Alberto (me comenta si renuevan o no el seguro del coche). Hablo con Ana Ts quién se informará acerca del único dato que tenemos (conforme recibo del banco) que es la matrícula 3722HVZ. Ana me dirá si hay algún interesado en quedarselo o podremos darlo de baja en DGT como paso previo a rescindir o no renovar el seguro. ··············································································································································································································································································································· Ana: a petición de Miguel, Asesor Jurídico, remito correo a Toni-Futuex: "Buenos días Toni, Como sabéis, a Miguel Santos Cordero se le retiró el permiso de conducir. A día de hoy no se ha hecho nada con su vehículo, Miguel, Asesor Jurídico está con gestiones oportunas, pero necesitaríamos saber en las condiciones en que se encuentra dicho vehículo con matrícula 3722-HVZ (desconocemos marca y modelo del mismo), y si está siendo utilizado por algún familiar (hijo, hermano…) o si alguien está interesado en adquirirlo. Sino, dado que el tutelado no puede conducir, tendríamos que dar de baja el mismo, así como la póliza del seguro (En Alianz Seguros) e impuestos. Ya nos decís cuando hayáis hecho las averiguaciones oportunas. Gracias y un saludo. PD: Pongo en copia a Miguel, Asesor Jurídico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-06-16','Ana: a petición de Miguel, Asesor Jurídico, remito correo a Toni-Futuex: "Buenos días Toni, Como sabéis, a Miguel Santos Cordero se le retiró el permiso de conducir. A día de hoy no se ha hecho nada con su vehículo, Miguel, Asesor Jurídico está con gestiones oportunas, pero necesitaríamos saber en las condiciones en que se encuentra dicho vehículo con matrícula 3722-HVZ (desconocemos marca y modelo del mismo), y si está siendo utilizado por algún familiar (hijo, hermano…) o si alguien está interesado en adquirirlo. Sino, dado que el tutelado no puede conducir, tendríamos que dar de baja el mismo, así como la póliza del seguro (En Alianz Seguros) e impuestos. Ya nos decís cuando hayáis hecho las averiguaciones oportunas. Gracias y un saludo. PD: Pongo en copia a Miguel, Asesor Jurídico."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2021-06-16','Ana: Envío correo a Felisa Custodio, TS CAMF-Alcuescar: "... Te adelanto escaneados la autorización así como el resto de documentos remitidos por vosotros, necesarios para el disfrute de Mª Rosario Solís Bermejo de Programa de Vacaciones del IMSERSO gestionado por COCEMFE. Posteriormente recibiréis los originales por correo certificado." ························· Redacto oficio y se lo dejo a Julio junto con la documentación para que le dé registro de salida y lo envíe por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-06-16','Ana: Llamo a la Técnico PIA EVD-Plas., Mª Carmen Gía Mnez (927 63 80 08 / 24208) varias veces, no obtengo respuesta. ·········· Llamo a José, Director de la Res. Jaraicejo (608 962 782) Hablará mañana con Isabel. *Le enviáre el oficio del Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2021-06-16','miguel, remito por fax comunicación Dº imagen a Fiscalía de Mérida y al centro las autorizaciones firmadas.','2');
