insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-06-16','Ana: Tras conversación con Mª Ángeles, Auxiliar de SAD de Felipe (lleva ya más de 3 años atendiéndole), envío correo a Alberto, Jefe Secc. Ecca.: "Buenas Alberto, Me comunican desde el Servicio de Ayuda a Domicilio que atiende a Felipe Rodríguez Solís, que éste llega muy justo con su asignación semanal, hay semanas incluso que no le llega. ¿Sería posible aumentar su asignación a 75€/semana? Ya me dices cuando puedas. Seguimos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-06-16','recibido por email de la ctutelar del dueño del piso alquilado: Buenas tardes. Por indicación de AMALIA DIAZ informo a Vd. de la situación en la que ha quedado la vivienda alquilada en 2.017 a la Comisión Tutelar, para uso de su tutelado JOSE MARIA VALLE SIMÓN, que dejó la vivienda el pasado día 1. Esta mañana del día 16, nos personamos en la vivienda -por parte de la Comisión- Teresa Pacheco y Sonia y también mi mujer y yo mismo. La impresión fue para todos desoladora, porque el piso está prácticamente inutilizado y daba "grima" entrar. Se han realizado fotos por parte de Teresa y Sonia y yo mismo. En ellas se aprecia la necesidad de hacer: 1.- Limpieza integral y desinfección del suelo, y limpieza y pintura de paredes, techo y puertas. Eran blancas y están sucias y marrones. Igual que las cortinas. Los vecinos se han quejado de las cucarachas que salen del piso. 2.- Sustitución de mobiliario de cocina completo (armarios, cajones, encimera) , incluyendo grifo, campana de humos y placa de quemadores. 3.- Sustitución de frigorífico, lavadora y calentador. 4.- Arreglo o sustitución de aparato de aire acondicionado que no funciona. 5.- Arreglo de persianas y toldo del balcón. 6.- Sustitución de colchón de la cama grande 7.- Sustitución de los sofás del salón, silla y mesas. 8.- Arreglo/sustitución de lámparas de techo y algunos enchufes 9.- Colocación de nueva cerradura, que ha eliminado el resbalón de la puerta de entrada y manillas en otras puertas. 10.- Arreglo de fontanería y limpieza o sustitución de la loza del baño 11.-Revisión del estado de mobiliario del dormitorio (armario, mesillas y cómoda) y en su caso, sustitución. Yo tengo fotos de todo esto y supongo que algunas cosas se me escapan, pero prefiero que vean las que han hecho Teresa Pacheco y Sonia. De todo esto, no proporciono Presupuesto... porque Amalia sólo me ha pedido relación de daños, pero si hace falta lo busco y lo presento, aunque -a groso modo-, no pienso que se valoren los daños en menos de 5.800 euros. Sin incluir los posibles ingresos que se pudieran obtener por un nuevo alquiler durante el tiempo que esté el piso en reparación : Teresa y Sonia fueron testigos de que una vecina se acercó para preguntar si alquilaba la vivienda a un pariente...cuando estuviese acondicionada. Aunque la idea es vender, pero mientras esté en estas condiciones, no se puede hacer nada. Pero lo que sí ruego encarecidamente es que la respuesta de la Comisión sea inmediata y compense todo los daños y las molestias que me va a ocasionar la situación en que se ha dejado la vivienda. Siempre ha estado alquilada a personas con precios muy asequibles y en difícil situación social, incluso algunos me han dejado de abonar algunas mensualidades, aunque siempre la han dejado en un estado asumible, pero en este caso las reparaciones superan en mucho cualquier tipo de previsión. Yo preferíría que la vivienda se me entregase arreglada y lista, con todo en condiciones, pero también admitiría -si no hay otro remedio- la compensación económica que me permita reacondicionar la vivienda, aunque eso supone un trabajo extra para mí, siempre que lo pueda hacer preferentemente antes de mediados de julio. Hoy se me han entregado las llaves, pero cuando las necesiten para "comprobar y revisar" el estado de vivienda y enseres, se las proporciono cuándo y dónde me indiquen, tal como he quedado con Teresa: No pienso tocar nada de la vivienda hasta que conformen una resolución. Un cordial saludo y gracias por su interés. PEDRO HERRERA MARTIN. 07416576L tfno: 676597609','2');
