insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-06-17','Belén: se envía Certificado para revisión anual de PNC ··································································································································································································· Ana: Llamada de Sonia Bernabé, Asindi (669 60 29 20): Tras 7 días en el centro, Aarón, esta mañana ha vuelto a presentar alteracones de conduca, ha salido del centro sin permiso y ha comenzado a lanzar sillas de una terraza de un bar cercano. Le ha dado a un coche. *De nuevo a tenido que intervenir la policía. (**Distingue en su actitud entre hombres y mujeres, con las mujeres se "encara" y "envalentona" más). Se ha hecho daño en un pie. **Han tenido que volver a derivarlo al hospital de CC, no saben si lo dejarán ingresado o no.','2');
