insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2021-06-17','Buenas tardes, adjunto las autorizaciones dº de imagen de Cristina. Asimismo las he remitido a fiscalía, tal como exige la Ley. ( JURIDICO)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2021-06-17','Ana: Envío correo-e a Toni-Futuex: "Buenos días Toni, Ayer a última hora me resultó imposible escribirte… No sé si desde la Asoc. Vera ya han contactado con Teresa, Educadora. El caso es que Adrián Ortigosa Fuentes, acudirá próximamente por vacaciones al domicilio familiar. El problema es que es una gran distancia, y no es posible asumir de nuevo el coste del taxi como en navidad. Van a mirar los horarios, para ver si hay buen “enlace” de autobuses, para ir primero a Badajoz, y en la estación de allí, coger después otro bus para su pueblo. Nos planteábamos si es posible que le esperase Teresa en la estación y le acompañase hasta subir al otro para ir a su pueblo. Si no hubiera buena combinación, se miraría la opción de taxi desde Badajoz, aunque también son muchos km… Ya me decís si es viable y si podéis organizarlo con Cristina, Ed. Soc. Vera. Un saludo y buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-17','Ana: Envío a Pedro Sánchez, Gerencia Territorial (residenciasmayorescc@salud-juntaex.es) nuevo informe médico (SOAP) complementario de la MAP que me remite Mª José Polo, TS SSASB Trasierra. ································································································································ Tras recibir llamada de Pedro, TS Gerencia Territorial (927 004 239), llamo a Mª José Polo, TS SSASB (664 018 209). Como no obtengo respuesta le envío un correo: "...me ha llamado Pedro, de la Gerencia Territorial. Va a empezar con las trámites para la adjudicación de plaza. Pero al parecer han cambiado los criterios y necesitan saber si está vacunada (Covid) y en tal caso necesitan “la cartilla de vacunación”. ¿Podrías solicitarlo?..." ··············· Respuesta de Mª José: "tiene las dos dosis puesta. No esta la medica intentare conseguir la cartilla de vacunacion es que aqui en Zarza no se la dan a nadie"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-06-17','Ana: Envío correo a Jose, Director Res. Jaraicejo con copia a Mª Jesús, TS SSASB: "Buenos días Jose, Tal y como acordamos ayer mediante conversación telefónica, te remito adjunto el documento del Juzgado relativo a Isabel Muñoz Melchor en que nos piden que informemos sobre el cumplimiento la medida y en que se indica que la sentencia ya es firme… Ya me dirás qué tal lo ha tomado Isabel. Os mantendré informados con respecto a las gestiones con Dependencia y la Secc. de Mayores para la adjudicación de nueva plaza. Pongo en copia a Mª Jesús, TS SSASB, para que esté al corriente, con ella no he hablado aún. Seguimos en contacto. Buena mañana." ······························································································································································································ Llamo a la Técnico PIA EVD-Plas., Mª Carmen Gía Mnez (927 63 80 08 / 24208): el teléfono no está disponible. ········ Le envío en correo: "...En relación a Isabel Muños Melchor, tutelada por la CTAEX y residente en la Res. de Jaraicejo, hace aproximadamente un mes, le ofrecieron plaza en la Res. San Francisco de Plasencia, la había pedido en 2016, pero no quiso irse, no hubo manera de convencerla, a pesar de que le había puesto una orden de alejamiento y de abandono del pueblo durante 6 meses por incidente con otra señora en el pueblo, pero como esta sentencia no era firme, tampoco podíamos obligarla a aceptarla. *Ahora sí es firme, y desde el Juzgado nos preguntan sobre el cumplimiento de la misma. Te adjunto el oficio del Juzgado. Fui a hablar con May Masegosa, Jefa Sección de Mayores, me dijo que hay que asignarle plaza nueva y que para ello me pusiera en contacto con la Técnico PIA. Ya me dices si tenemos que hacer algo más por nuestra parte. ..." ····························································································································································································· Correo de Jose, Director Res.: "Hola Ana!! Pues mira fijate que quiero hablar con el medico antes de decírselo por el tema de la medicación, porque ella como es y como se lo va a tomar la verdad es que me da miedo como se lo vaya a tomar y que pueda hacer.... entonces quiero gestionarlo primero con el médico y luego decírselo, otra cosa Ana, no sé si seria posible, ya que en Navezuelas tenemos una plaza publica, que fuese allí, ya que estaría al lado de jarsicdjo y cerca de plasencia también, y bueno es nuestra y de alguna manera luego quizás podamos ayudarla a volver a Jaraicejo que es donde ella quiere residir, todo si fuese posible Ana. Pues muchas gracias por todo y a ver que tal se lo toma Isabel, ya te contaré..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-06-17','TERESA Hemos autorizado un reintegro para el día 21 de 476€ en concepto de medio mes de gastos mensuales mas 200€ para gastos extras (ropa, ajuar, aseo, etc.) A partir del mes de julio puede retirar en la primera semana de cada mes 555€ para los gastos mensuales que me has detallado (aportación, móvil, tabaco, higiene personal y asignación personal)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-06-17','Ana: Llamo al Ministerio de Interior (91 837 22 95), me informan que el REGISTRO CIVIL CENTRAL sólo realiza trámites de Españoles NO nacidos en España. ··············· Envío correo informando a Ángel, Asesor Jurídico CTAEX, con copia a Miguel y Maite, Jefa Secc, CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-06-17','-EMAIL DE TERE: Buenos días Ha estado aquí Beatriz, hemos estado hablando y resolviendo sus dudas Comentarte varias cosas Hemos autorizado un reintegro para el día 21 de 476€ en concepto de medio mes de gastos mensuales mas 200€ para gastos extras (ropa, ajuar, aseo, etc.) A partir del mes de julio puede retirar en la primera semana de cada mes 555€ para los gastos mensuales que me has detallado (aportación, móvil, tabaco, higiene personal y asignación personal) Entiendo que este dinero se le controla desde el piso Con respecto al dinero que se saca con la línea del Tarot la comisión tutelar no ejerce ningún tipo de control sobre él, si desde el piso se lo queréis controlar porque ella así lo pida no hay ningún inconveniente por nuestra parte Por mi parte nada más, solo comentarte que la trabajadora social de referencia es mi compañera Amalia ya que es ella la que gestiona la zona Mérida. Te paso su contacto para que puedas hablar con ella por si necesitas algo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-06-17','llega email de Alberto comunicandonos el proc abreviado 114/2021 con prisión provisional y un embargo que tramitará la parte económica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-06-17','miguel, la gestoría del Cid y Villafaina me remiten el presupuesto por 500€ que a su vez se lo remito a ALberto y Tere para me confirme la parte económica que puede asumir el gasto. Mañana redactaré y les enviaré la autorización para las gestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-06-17','miguel, hablo con la policia local y me dan los teléfonos de la policia de paisano, Subinspector 924-210222 y el General 924-210195. Llamo y no me lo coge nadie. Cuando tenga respuesta se la comunicaré al abogado Jorge Calvo para que empiece a actuar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-06-17','-Amalia : pregunto a Ana el copogado de la plza t4 , son 469,93€ , incluidas pagas extras . se lo paso a seccion eco para calcular gastos de bolsillo.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TRINIDAD'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2021-06-17','Ana: envío correo a Raquel Pérez, TS de SSASB: "Buenos días Raquel, En relación al caso de Trinidad Sevillano Sevillano, esta es la respuesta que hoy mismo me ha dado mi compañero Miguel, Asesor Jurídico: “… ya he hablado con el jzdo nº1 de Navalmoral. Parece ser que sí somos tutores y que el problema es que notificaron a MF pero no a nosotros. La forma más rápida que me han ofrecido de que nos lleguen la firmeza es vía fax y por correo físico…” En cuanto lo tengamos, hablamos de nuevo." ··························································································································································································· Respuesta de Raquel: "Buenos tarde Ana, decirte, la próxima semana le darán el alta hospitalaria, primero dijo que sí, que quería ir a una residencia, en coordinación con T.Social del hospital gestionamos para ingreso por emergencia, cuando la compañera subió para que firmara, pues.....nada que ahora si quiere venir a Cuacos. Por lo que me han comentado desde el hospital viene encamado (tiene lexiones en la columna, el no entiende que no volverá a caminar), sin olvidar la enfermedad oncológica existente. A ver como transcurren las cosas. Gracias por tu información, seguimos en contacto. Está bien saber este tema, te agradecería que en la medida de lo posible me dijérais el número de expediente del juzgado (el número de incapacitación o número de sentencia de la tutela administrativa), por si tengo que enviar correo electrónico a fiscalía, porque me dá que será una situación complicada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TRINIDAD'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2021-06-18','Ana: Envío correo a Raquel Pérez, TS SSASB (ssasbrpa@gmail.com): "Buenos días Raquel, Pues acabamos de recibir la sentencia, y me temo que esto va a ser más complicado aún, pues en el fallo dice textualmente: “…declaro la incapacidad de D. TRINIDAD SEVILLANO SEVILLANO en lo referente a sus actividades económicas de cierta envergadura, que se salgan de su desenvolvimiento habitual, como pueden ser gestiones de compraventa de bienes, solicitud de créditos o cualquier otro tipo de relación contractual compleja…” Con lo cual, no nos nombra para la espera personal…. Y aún así, sin autorización judicial no podríamos obligarlo a ingresar en ningún centro…. El Juzgado es el de 1ª Instancia e Instrucción nº1 de Navalmoral de la Mata Sentencia: 70/2009 ICP Incapacitación: 505/2017 Ya nos decís si contactáis con el Juzgado y/o si enviáis informe explicando la situación actual y solicitando ingreso como medida cautelar (creo que podría ser una opción). Porque no tengo a día de hoy más información que la que tú me has transmitido y la sentencia, no sé si tiene posibilidades económicas para asumir la contratación de personas que le atiendan 24 horas en su domicilio…. Supongo que no está valorado por dependencia, no? Bueno, ya me irás diciendo. Seguimos en contacto." ···························································································································································································· Nuevo correo de Raquel, TS: "Buenos días Ana, de momento vamos a esperar a ver qué pasa. Ya he contactado con el médico de cabecera y cuando le den el alta, vamos a intentar que tome la decisión de irse por voluntad propia, ya que la realidad es que estará encamado el tiempo que le queda de vida, que parece ser que es poquito. Por lo cual sigo con la vía de emergencia social en cuanto llegue al pueblo (que tenga la experiencia unos días en casa, él solo y pueda valorar por sí mismo). A la par de realizar gestiones sobre pensiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-06-18','Ana: correo de Ángela-Placeat: "Buenos dias Ana, solo informarte que el día 21 de junio tiene Cristofer consulta de Preanestesia y el día 22 de anestesia, con lo cual no tartdará mucho en realizarle la intervencion."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-05-26','Se envía CI para intervención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-06-11','Es para ver cómo hacemos con el dinero de bolsillo de Mª Andrea Daza. Al parecer, ella disponía de algún dinero de bolsillo para tomar un descafeinado, en el Encinar, desde la pandemia, tienen cerrada la cafetería, así que últimamente no ha estado consumiendo.. Aquí tenemos cafetería y quiere tomar su descafeinado o helado (hemos acordado con ella una consumición al día). Belén: Según me comenta Nieves TS (924001828) de la residenia Felipe Trigo el ingreso fue bien, los dos primeros días más nerviosa por el cambio. Pero ya va durmiendo mejor. Nos pasa además un cuadrante con los gastos mensuales y de bolsillo. Desde el área económica se está estudiando porque los gastos siguen siendo más elevados que los ingresos. La opción sería vender la vivienda situada en Navalvillar de Pela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-06-18','TERESA Genaro tuvo ayer revisión de salud mental, me dice la psicóloga que mantiene tto y que la próxima cita es el 18 de noviembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2021-06-18','TERESA ME LLAMA M JOSE DE LOS PISOS TUTELADOS PARA COMENTAR QUE EL PROXIMO DIA 22 TIENE CITA EN SALUD MENTAL, LA LLEVA LA AMBULANCIA Y LA ACOMPAÑA SU HERMANA HAY GASTOS PENDIENTES DE FARMCIA, LE INDICO QUE ME MANDE FACTURA CON GASTOS TRIMESTRALES Y LA ABONAMOS POR TRANSFERENCIA DE MOMENTO TIENE DINERO EN EFECTIVO PARA IR PAGANDO LOS GASTOS QUE SURJAN (PODOLOGIA, PELUQUERIA ETC)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2021-06-16','Belén: nos envían presupuesto para tratamiento ortodoncia que es aceptado una vez se ha comunicado a la sección económica. Estamos a la espera de las facturas. También se da el visto bueno desde la sección jurídica con el informe de APTO del reconocimiento de las pruebas médicas y psicológicas para poder obtener el carné de conducir. Estamos pendiente de que manden el presupuesto de la autoescuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GEORGE'and edp.apellido1='ANDRE'and apellido2='GRENET'),'2021-06-18','Ana: Correo de ayer a última hora de Pilar Cerrillo, TS Grupo Ciudad Jardín (calidad@grupociudadjardin.com): "Buenos días Ana, como te comenté esta mañana por teléfono, ha ingresado un señor, George Andre, en plaza T1. El ingreso ha sido por orden judicial Tiene dos causas abiertas una de Incapacidad y otra por lo penal. Me dicen en el Juzgado de Coria que han nombrado defensor judicial a la Ctutelar. Ruego me digas si sabes algo porque está muy grave y no sabemos como proceder en el caso de que fallezca. Muchas gracias Un saludo" ······························································································································································································ Se lo reenvío a los Asesores Jurídicos - CTAEX, y pido que le den respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-18','Ana: Tras recibir llamada de Pedro, Gerencia Territorial (927 004 239), envío correo a Mª José Polo, TS (ssbm@trasierratierrasdegranadilla.es): "Buenos días Mª José, Comunicarte que me ha llamado Pedro, de la Gerencia Territorial. Me dicen que a día de hoy en la única residencia en que pueden darle plaza es en la Municipal de Aldea del Cano, dónde ya lo han comunicado. La Directora se llama Fermina y este es su número de teléfono: 646 437 879, aunque yo la llamaré, no estaría de más que tú, que conoces el caso de primera mano, pudieran hablar también con ella para detallarle las características y necesidades de Florencia. Estamos a la espera de la Resolución de Plaza, en cuanto la tengan y me la envíen te aviso. Seguimos en contacto." ························ **Llamada de Mª José Polo, ha hablado ella con el centro. **Acordamos que el lunes organizarán todo entre la TS del C.Salud, ella y la Aux. y se procederá al ingreso el martes. **Necesitan comprarle algo de ropa. **Como Alberto, Jefe Secc. no está pido a Estrella que hagan una autorización de extra de 50€ para el lunes (excepcionalmente por ser necesario). ················ El traslado lo harán en taxi, le acompañará la propia TS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-06-17','Ana: Correo de Estrella Durán, TS - CSS: "Hola Ana. Ya le dimos el alta a Desi, han quedado en venir a parcial cada 15 días para que los vean sus Psiquiatras y así evitar los ingresos... Ya está informada Sonia de futuex."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-06-17','miguel, remito el siguiente email a Alberto y Amalia: Buenos días, en relación a la tutelada, he mantenido contactos estos últimos días con AEAT. Como recordaréis nos enfrentamos al problema de que le están revisando las rentas desde el 2014 y van por el 2016 por el siguiente motivo: • cobro desde Alemania de esta pensión 919,60 €...la continúa percibiendo= Pensión Deutsche rentenversicherung bund(anual en 2015 según AEAT unos 9.330,96€) • NO cobro desde Alemania de la pensión de 746,48 €/MES...en CCC. Último día de cobro 31/08/2020 y hasta hoy no la ha vuelto a cobrar= PENSION Vbl versorg. anstalt d.bundes u.der Lander bav(anual en 2015 según AEAT unos 8.480,82€) He comprobado que tanto hacienda como a nosotros nos consta la misma cuenta en el Santander. Me comentan que a ellos conforme a la Asistencia Mutua entre la Hacienda Alemana y la AEAT nos pidieron en un requerimiento que les dijéramos en que cuanta las cobraban. El motivo es que ellos tienen duda de que haya dejado de percibir la 2º de las pensiones alemanas (Vbl versorg. anstalt d.bundes u.der Lander bav) Los datos a los que dirigirnos a Alemania, creo que lo estas viendo Amalia(por lo que veo en su expediente virtual tenéis localizado quién lleva la primera pensión que le siguen pasando, esto es , Deutsche rentenversicherung bund). Pero no veo tengáis localizado lo que pidieron desde la AEAT (acreditar si cobró o no y en qué cuenta la pensión de 746,48 €/MES Vbl versorg. anstalt d.bundes u.der Lander bav, que dejó de cobrar el 31/8/2020, y es esta segunda pensión de la que están pasando las revisiones de renta). Desde la AEAT no saben donde nos podemos dirigir en Alemania para esta segunda Pensión, a ver si tu puedes localizar quién puede emitirnos desde Alemania un justificante de que ha dejado de cobrarlo y el motivo. El problema es que hay que parar estas revisiones y solucionar las ya abiertas, por lo que os comento lo que he averiguado: Renta ejercicio 2014: si no lo pagamos embarran por la cuenta del SCH donde tiene los aproximadamente 79.000€. Y más adelante la pasaran una 2º liquidación por el 25% que descuentan siempre dando por supuesto que el contribuyente va a pagar en período voluntario (lo cual no sucedió) Renta ejercicio 2015: Adjunto carta de pago para su abono antes del 20-7-21(he comprobado que utilizan bases diferentes de 8.300, 8.400, y en la revisión de la renta del 2016 llegan a 8.700 (otra base pone 8.500 aproximadamente), esto significa que seguramente se incrementa por algún cargo que cobra la hacienda Alemana antes de enviarnos este dinero. Renta ejercicio 2016: No está finalizado el procedimiento, nos dieron trámite de audiencia, que entiendo cumplido porque no sé cuándo llegó y la carta es de marzo o abril del 2021. Teniendo en cuenta que deja de percibir la pensión referida el 31/8/21, van a revisarnos hasta entonces, y para lograr que no sigan haciéndolo en un futuro os comento qué hacer: Alberto: 1)Paga las dos cartas de pago que te adjunto de ejercicios 2014 y 2015. 2)Encarga a una gestoría que haga las rentas del 2017 a 2019 inclusive y las presente (al ser extemporáneas cobran el recargo más los intereses de demora). 3)Tienen que hacer también la del ejercicio del 2020 ya que percibió esta 2º pensión hasta el 31/8/20 4)Necesitaré los movimientos bancarios de la cuenta porque me recomiendan que pida cita con Gestión Tributaria y les comente el caso. Amalia: Necesitaré justificante que acredite que ya no cobra dicha pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-06-18','miguel, doy a Alberto las cartas de pago de los ejercicios 2014, 2015, quedando pendiente de resolución administrativa la de 2016. Hablo con la asesoría que habitualmente tramita las declaraciones de la renta de la Ctaex (José Pinilla), pero me confirma Iciar que esta tutelada ya tenía un asesor al cual llamo (Javier Romero 687936330 email:jrp@atrimer.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-06-18','Ana: Llamada de Rosa Bravo, Admvo. CSS-Plas. (24145): Isabel está ingresada en la Unidad de Quemado de la HUC, se ha prendido fuego. *La madre ha llamado al CSS para comunicarlo, dice que necesita a alguien 24 h y que ella no se va a quedar allí. ···················· Llamo al HUC, me pasan con Enfermería de la Ud. de Quemados(56185). Sara, Enfermera, efectivamente Isabel está allí ingresada. No sabían que está tutelada por la CTAEX, su madre ha firmado el C.I. y la Autorización para las sujecciones, le indico que no tienen validez, pues la tutela recae sobre la CTAEX. **Me enviarán los documentos para la firam. En cuanto al acompañamiento, hablará con los médicos para consensuar cuántas hora y en qué horario es más necesario. Toma mis datos de contacto. ····························································································································································································· Recibo correo de Sara, TS del HUC (sara.pozo@salud-juntaex.es): "Buenos días Ana. Adjunto remito CI de CANO BLAZQUEZ ISABEL MARÍA para firmar lo antes posible. Hay un cirujano que quiere operarla de urgencia, hoy tendría un hueco. No sé cuánto puede tardar este trámite..." ·········· Tras hablar con ella por teléfono, le remito por correo-e el CI debidamente firmado y sellado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2021-06-09','Belén: tras conversación telefónica con Manuela TS(ext.24012) del centro sociosanitario de Mérida nos pasa los gastos mensuales 120€. Se le da autorización a la madre para que se los lleve mientras se le abre la nueva cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-06-18','Ana: Llamada de Begoña, Directora de la Res. El Pendere. Puesto que la unidad móvil para la renovación del DNI, le han dicho que no podría ir hata septiembre-octubre, plantea el llevar ella, con alguien más a Florencia a Valencia de Alcántara para hacerlo allí directamente si le damos nuestra autorización. Cree que no habrá problemas. ···················· Pido a Ángel y Miguel, Asesores Jurídicos CTAEX, que hagan la aurorización para este acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-06-18','Ana: Envío correo a Toni-Futuex: "Buenas Toni, Espero que estéis bien. Este correo es meramente informativo, para que por favor le comuniques a Gloria, Ed. que desde la secc. ecca. se: • Modificará el reintegro PERMANENTE: pasa a 75 €/semana a partir del 01/07/2021. • Reclamará a LA OPTICA la devolución de la factura ya que se abonó, x error, en 2 ocasiones. **Lo que sí pediría es que, en las medidas de sus posibilidades, Gloria siga abordando la necesidad de dejar de fumar de Felipe, o a las malas, al menos reducir el consumo. (Ya lo abordaron ayer en el Despacho de la TS) Gracias y un saludo." ··············· Traslado la mima información a Isabel Pino, TS SSASB, mediante conversación telefónica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-06-18','Ana: Correo de Estrella, TS CSS: "Buenos días, Ana Ayer a última hora me comunicaron que Reme se había tragado un lápiz, así que la llevaron al Hospital, le hicieron una endoscopia y se lo extrajeron. A las 5 de la tarde regresó al Centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-06-18','Ana: Correo de Sonia Bernabé: "...Aprovecho para comunicarte que Aarón quedó ingresado y, según nos han dicho hoy desde Salud Mental, ahora mismo está tranquilo. Le decía al Psiquiatra que se aburría."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2021-06-21','EXITUS Se está a la espera de la comunicación de la fecha de fallecimiento y de la remisión del certificado de defunción. Ambas cosas fueron solicitadas por Teresa (el 17/06/2021) y Julio (el 21/09/2021). Estamos a la espera de recibir lo solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-06-21','TERESA ARCHIVO SOLICITUD DE DEPENDENCIA Y CONTRATO ADMINISTRATIVO DE SERVICIO EN RESIDENCIA LAS CUMBRES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-06-21','TERESA RECIBO LLAMADA DE LA TS DEL CAMP DON BENITO, SOLICITA INFORAMCION SOBRE LA VENTA DE LA VIVIENDA Y SUBIDA DE LA ASIGNACION AHORA MISMO LA SITUACION DE TUTELADO ES CRITICA Y NO PODEMOS ASUMIR NINGUN GASTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2021-06-16','Belén: se habla con Julieta (635149247) ante la posibilidad de un cambio de residencia del tutelado debido a que su situación a largo plazo será inviable económicamente. Se le va a solicitar una plaza pública pero sólo le interesa la zona de Don Benito. Se empieza a tramitar. Se solicita informe médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-06-21','miguel, envio email a Alberto y Amalia: Buenos días, comentaros que las rentas que envía el asesor fiscal y que os he dejado en la carpeta virtual Rentas, no ha declarado la 2º pensión de Alemania (de 2017-2019) La única solución sería hacer una declaración complementaria con esa 2º pensión, para lo cual o bien desde Alemania os mandan lo que cobró esos años (parece ser que no es posible…) o bien una relación de movimientos de cuentas desde enero de 2015 hasta diciembre de 2019… Es posible pedir dichos movimientos Alberto? Imagino que al ostentar el cargo desde finales de 2020 nos dirán que no, pero habríamos de intentarlo…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-06-21','Ana: Correo de Estrella Durán, TS CSS-Plas: "Buenos días. Os escribo para comunicaos que, vamos a proceder a extraer 300 euros del paciente, de Ibercaja, para sus gastos de bolsillo. Saludos" ······························································································································································································ Nuevo correo de Estrella: "Hola Ana. El sábado día 19 sobre las 19:00 salió del recinto de este centro, sin autorización, Juan Carlos Ruíz García, dando parte a la Policía, siendo traído por ésta aproximadamente a las 20,45 horas del mismo sábado. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-21','Ana: Pedro, TS Gerencia Territorial, me remite por mail RESOLUCIÓN DE PLAZA por Decreto - Emergencia Social. ······· Archivo en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-06-21','Ana: Conversación con Mª Carmen Gía Mnez, Técnico PIA EVD-Plas. (927 63 80 08 / 24208): habará que negociar un nuevo PIA. me enviará una nueva aceptación del PIA para la firma del Representante Legal. Intentarán que sea algún centro cercano a Jaraicejo o Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-06-21','miguel, envío email al asesor fiscal Fco Javier Romero Pavon y despues lo reenvío a Alberto y Amalia: Buenos días, en cuanto tenga hecha la declaración del ejercicio 2020 envímela. En otro orden, veo que no ha sido incluida la 2º pensión de Alemania en ninguna de las declaraciones que me remitió de años anteriores. Vamos a intentar hacernos con los movimientos de cuenta desde 2015 o 2016 hasta diciembre de 2020 a efectos de enviárselo para que pueda presentar unas declaraciones complementarias. Como le comenté ya han revisado los ejercicios de 2014 a 2016(de esta última estamos a la espera de la resolución definitiva de AEAT).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2021-06-21','EXITUS Recibida copia del certificado de defunción se constata que la fecha de óbito es el 23/05/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-06-21','En relación con la renovación del DNI, hablo con el Secretario General de la Policía, José Luis Gía y le envío este correo: "Buenos días, Siguiendo con nuestra conversación telefónica, le escribo desde la Comisión Tutelar de Adultos de Extremadura, como tutores de Dª. María Del Rosario González Jorna. A los efectos de renovarle su DNI, precisamos nos emitan un Certificado de Identidad, para poder dirigirnos con el mismo al Registro Civil de Coria o al de Villamiel (lugar de nacimiento) y acreditar la nacionalidad de nuestra tutelada. En nuestra base de datos tan sólo nos consta un número de identificación de Régimen comunitario: X-0745160-Y. Como recordatorio, • El Registro Civil de Coria, nos indica que “en su partida de nacimiento no consta que haya perdido la nacionalidad, por lo tanto, no hay que iniciar el expediente de recuperación de la nacionalidad” • El Consulado de Francia en Madrid, nos indica que “en nuestro consulado no se ha encontrado ninguna prueba de que la Sra. González Jorna tenga la nacionalidad francesa. No hemos encontrado ningún DNI francés”. • La Delegación del Gobierno en Badajoz, Extranjería: “Corroboran que el último trámite se llevó a cabo en la Subdelegación del Gobierno en Cáceres, en el Negociado de Extranjeros en el año 2000, Tarjeta de Régimen Comunitario. Allí tuvo que presentar algún documento oficial para poder realizar la gestión. El primer trámite lo hizo en 1993 en el Registro Central de Extranjeros (Madrid)” • El Ministerio de Interior informa que “el Registro Civil Central sólo realiza trámites de Españoles no nacidos en España” Agradeciendo su colaboración, Reciba un cordial saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-06-16','Belén: Se habla con las 2 inmobiliarias para que vayan a valorar la vivienda situada en la C/ Hinojo de Guadiana. Las llaves están en el Ayuntamiento y es la policía local la que se encargará de enseñarla. La Finca Servicios Inmobiliarios- Emiliano Delfa (924452828) la visitará a las 10 h el viernes 18 y la Inmobiliaria Colón- Ana (652410390) a las 12.30 de ese mismo día. Estamos a la espera de su propuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-06-21','Ana: Gisela, TO, CRR-Mér, nos remite escaneado el contrato de Damián para abonarse a la Ciudad Deportiva de Mérida. ···························································································································································································· Envío correo-e a Gisela: "Buenos días, de nuevo, Gisela, En cuanto a la Declaración de la Renta de Damián, según me informan mi compañera, ya hace semanas que se encargó la gestión a una asesoría, no obstante, faltaban datos con respecto a los inquilinos de Damián. Creo que ya está solucionado y si no surge nada más podrán finalizarla en breve. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-06-21','Ana: Llamo al Ayto. de Alcuescar (927 38 40 02): me dicen que la TS ha salido a un domicilio, le dejarán nota para que me llame cuando vuelva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-06-21','Ana: Conversación con Icíar: En la Asesoría le han dicho que Félix no está obligado a hacer la declaración de IRPF, es más, ti tiene algún grado de discapacidad reconocido se saldría a devolver. *En el expte. no tenemos aún dicho documento. ·············· Envío mail al CADEX solicitando nos lo envíen y adjunto el oficio solicitud registrado en su día en el SIREX. ············· Respuesta del CADEX (cadex.caceres@salud-juntaex.es): "Buenos días No tenemos antecedentes de esa persona en nuestros archivos. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-06-21','Ana: Envío correo a Toni- Futuex: "... A Felipe Rodríguez Solís le acaba de caducar el DNI (el día 16/6), ¿Sería posible que Gloria hiciera las gestiones oportunas para renovárselo? (pedir cita y acompañarlo). Cuando tenga fecha nos decís para la autorización para el extra para abonar las tasas (lo indicáis al área económica y me ponéis en copia si queréis). Si no me equivoco, Gloria está esta semana de vacaciones, espero que a la vuelta se pueda encargar. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2021-06-21','Ana: Tras recibir llamda del Ayto. de Trujillo, envío correo a compañero de la CTAEX (Teresa, Alberto, Miguel y Ángel): "Buenos días Teresa y demás compañeros, He recibido llamada Goyi Delgado, Técnica del Ayto. de Trujillo (927 32 10 50), en relación a la vivienda en que residía Miguel Trinidad Esteban, quien a día de hoy es de la zona de Teresa, pues lleva año y medio residiendo en la Res. Felipe Trigo de Vva. De la Serena. A parecer es necesario hacer limpieza en el patio, dado el crecimiento de maleza, por el riesgo que supone. Por lo visto también hay un sobrino que entra y sale del domicilio y lo han visto los vecinos llevándose cosas de allí… pero no quiere hacerse cargo de nada. *Habría que ver la opción de cambiar la cerradura quizá. A los compañeros jurídicos los pongo en copia porque Miguel era el Usufructuario, pero la casa es propiedad de varias personas. En este caso no sé si el gasto de la limpieza del terreno le corresponde asumirlo todo a él. Le he preguntado a Goyi y podrían facilitarnos varios contactos de personas autónomas del pueblo que se dedican a este tipo de trabajos. En cualquier caso hay que ponerse en contacto con ella al respecto. Seguimos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-06-21','Ana: Envío correo a Julián - Gerente de COCEMFE (gerencia@cocemfecaceres.org): "Buenas tardes Julián, ¿qué tal estás? Tan sólo comentarte que me ha confirmado la compañera de al secc. económica que a día de hoy a Tomás Esteban Iglesias no le han ingresado la ayuda para la silla de ruedas del SES. Para que podáis establecer los contactos oportunos. Seguimos en contacto. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-06-22','-EMAIL CRR Aprovecho para informar sobre Damián Granado, ha tenido un cambo de pauta psiquiátrica hoy. Tenia primera cita en salud mental y han accedido a este cambio.','2');
