insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GARCIA'and apellido2='PEREZ'),'2021-05-27','Belén. Se habla con la TS del centro Mª Carmen (924175600) para que hable con la tutelada e intente conseguir las llaves de la casa de VPO que tiene para hacer el inventario de sus cosas. Los gastos mensuales serán de 30€/mes. Actualmente tiene un saldo en la residencia de aprox. 1600€. de donde irán retirando esa cantidad. De que quede 250-300€ nos avisarán para que se le empieze a ingresar los 30€/mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GARCIA'and apellido2='PEREZ'),'2021-06-22','Belén. Se manda un correo a FUTUEX para que vayan a visitarla e intenten convencer a la tutelada que les de la llave del domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-22','Ana: Recibo llamada de Mª José Polo, TS SSASB (664 018 209), iban a proceder al tralado de Florencia, pero ésta se ha negado, ha acudido incluso la MAP, pero no ha habido manera de convencerla para subir al taxi. ·········· Llamar al 112 y hablo con Nuria, Jefa de Sala: acordamos que el traslado se realizará hoy mismo. Avisará al personal sanitario, MAP y a la Gurdia Civil. *Le envío un correo: "Buenos días Nuria, Tal y como hemos acordado mediante conversación telefónica, te envío adjunta la siguiente documentación: - Sentencia de incapacitación judicial y nombramiento de tutor - Acuerdo de aceptación del cargo - Resolución de plaza residencia por emergencia social - Firmeza de Autorización de Internamiento Involuntario Relativos a Dña. Florencia Simón Martín, incapacitada judicialmente por Sentencia Judicial Nº 4/2019 de fecha 4 de enero de 2019 dictada por el Juzgado de Primera Instancia Nº 3 de Plasencia, cargo que fue aceptado mediante acuerdo de 28 de marzo de 2019 por la Comisión Tutelar de Adultos. Para que se pueda proceder, a fecha de hoy al internamiento involuntario en la Residencia de Mayores de Aldea del Cano, en la que se le ha adjudicado plaza residencial por emergencia social. Ante cualquier cuestión no dudes en contactar. Gracias y un saludo." ······························································································································································································· Nueva llamda de Mª José Polo: Al taxista habrá que abonarle el desplazamiento hasta allí y el tiempo que ha estado esperando e incluso apoyando en la situación (es él el que ha ido a buscar a la MAP). Le indico que envién factura a nombre de Florencia con el nº de cuenta del taxista para hacerle transferencia. ··········· **En cuanto a la hermana de Florencia ya está llamando a la auxiliar para pedirle las llaves de la vivienda. *Según, "no aparece como propietaria de ningún inmueble según Certificado Catastral". *Lo hablo con Miguel, Asesor Jurídico, mientras que la hermana no demuestre documentalmente a quién pertenece dicha vivienda, no se le entregarán las llaves. *Se lo transmito a Mª José - TS. ································ *Finalmente el taxista tuvo que llevar las maletas de Florencia a la Residencia. Habrá que abonar el viaje completo. ····························································································································································································· Llamo a Fermina, Directora de la Res. de Aldea del Cano (646 437 879), ella no estaba en el momento del ingreso en sí en la residencia. Gestionan varios centros. Me facilita su correo: ferminasanchezgarcia@gmail.com, pide se pongan en contacto desde la secc. ecca. para orgnizar los pagos. Se harán mediante transferencia bancaria. Le indico que deberán enviar una presupuesto aproximado de gastos para la asingación mensual de Florencia (podología, peluqería y otros). ············ Envío un correo a Alberto (indicando también que deben darse de baja los suministros de la vivienda que estén a nombre de Florencia) y a Fermina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GARCIA'and apellido2='PEREZ'),'2021-06-16','Belén: La TS del centro habla varias con veces con la tutelada para el tema de las llaves de la vivienda y no ha conseguido nada. Los intentos no han tenido éxito. Se mandará correo a FUTUEX para que vayan a visitarla y e intenten convencerla.','2');
