insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-06-22','Ana: Llamo a Control de Enferería de la Ud. de quemados del HUC (55185), Raquel, Enfermera, dice que el acompañamiento hospitalario al menos habría que contratarlo para el turno de noche, que es cuando hay menos personal y no pueden estar tan pendiente. Especifica de 22:00 h a 8:00h, pero si no fuera posible, pide que al menos de 00:00 a 8:00 h. *En cuanto a Isabel, dice que aunque está con sujecciones, ayer casi se traga la mascarilla. Se está negando a comer. Ya la ha visitado hoy el Psiquiatra, van a intentar administrale la medicación horal, si no lo consiguen se la pondrán a través de sonda nasogátrica. **En cuanto a la intevención quirúgica, a priori fue bien, pero hasta el jueves no le levantarán la cura. ······························································································································································································· Llamo a la empresa EDADES (927 77 26 05), varias veces, pero el teléfono no está disponible. ····························································································································································································· Llamo a la empresa SUMAN (927 76 23 35), Raquel me pide que le envíe un correo (rrodriguez@suman.es): "Buenos días Raquel, Tal y como hemos acordado mediante conversación telefónica, te hago la solicitud por esta vía. Necesitaríamos un presupuesto de un servicio de ACOMPAÑAMIENTO HOSPITALARIO a nombre de Dña. Isabel María Cano Blázquez, tutelada por la Comisión Tutelar de Adultos de Extremadura. Se encuentra hospitalizada en la unidad de quemados del Hospital Universitario de Cáceres. El acompañamiento tendría lugar en horario de noche, de 22:00 a 8:00 horas, es lo que nos piden desde el hospital, pero si Isabel no pudiera asumir ese gasto habría que reducir el número de horas. No sabemos el tiempo que tendrá que estar hospitalizada, ¿se podría contratar por una semana inicialmente y luego ir ampliando por días según nos vaya diciendo el equipo médico? Quedamos a la espera de su repuesta. Gracias y un saludo." ······························································································································································································· Llamo a la Empres Depende de Ti (927 22 20 82), Feli me incida que se abonarían 100 €/noche. Si llega a la semana, serían 600€/semana, y a partir de ahí la parte proporcional por día. *Me enviará un correo electrónico con el presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-06-22','Ana: Ángela, Placeat, me remite CI para anestesia. *Necesitarán el original. ······· Se lo adelanto escaneado debidamente firmado y sellado. Y le paso el original a Julio junto con el oficio para que lo envíe por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-06-21','miguel, recibido presupuesto de inmobiliaria Colon ANA ISABEL GALLEGO BARROSO >anaisabel@inmobiliariacolon.es>: Buenas tardes, según visita realizada al inmueble y tras realizar un estudio de valoración de mercado, os informo que el precio de venta adecuado para la venta del inmueble sito en calle El Hinojo, es de 60.000 euros, adjunto envío valoración de mercado donde podrán ver las tres últimas viviendas que se han vendido en la zona y las que están en venta que no se venden y posteriormente las ponderaciones con las características de la vivienda valorada. Con respecto al tema de la comercialización, tengo que informarles que Inmobiliaria Colón, trabaja únicamente en exclusiva debido a que tenemos diseñado un plan de Marketing para la comercialización de nuestros inmuebles, dicho plan de marketing tiene una duración de 6 meses, que es lo que la duración del documento de Encargo de Venta que nos firman nuestros clientes. Nuestros honorarios serán de 7.260 euros IVA INCLUIDO, os informo que dentro de esta tarifa está incluido el Certificado de Eficiencia Energética y la Cédula de habitabilidad que necesitan los vendedores para vender la vivienda y entregar en notaria una vez que vayamos a firmar las escrituras de compra-venta. Si tenéis alguna duda o consulta, podéis contactar conmigo en el 652 410 390. Un saludo El mié, 16 jun 2021 a las 11:15, MIGUEL FERNANDEZ DE LLERA (>miguel.fernandezd@salud-juntaex.es>) escribió: Buenos días, según conversación con ustedes, les remitimos a efectos de que nos calculen el valor de mercado de esta vivienda VPO. Una vez la visiten y calculen el valor de la misma, necesitamos nos den presupuesto y nos indiquen si es o no posible la venta con otra inmobiliaria que también está pendiente de visitar la vivienda. Si fuera obligado la venta en exclusiva necesitamos igualmente dicho presupuesto para ver a cuál de las dos se asigna. Adjunto las escrituras de compraventa que en su día se formalizó.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-06-22','Ana: Llamo al Ayto. de Alcuescar (927 38 40 02), me dicen que hoy no está la TS, que llame de nuevo mañana. *No obstante le dejarán nota. *No pueden facilitarme ninguna dirección de correo electrónico en la que contactar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-06-21','miguel, llega presupuesto de Info finca INFO FINCA >info@fincasi.es>:Buenos días, te adjunto el presupuesto para la venta del dúplex sito en Guadiana en la calle El Hinojo y fotografías del estado actual. Quedamos a la espera de tus indicaciones. Saludos FINCA INMOBILIARIA EMILIANO DELFA TLF.- 654 552 843','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2021-06-23','TERESA ARCHIVO Y ESCANEA PARTIDA DE NACIMIENTO Y CERTIFICDO DE DEFUNCION DE LOS PROGENITORES SOLICITADO PARA PEDIR ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='CARVAJAL'and apellido2='MORENO'),'2021-06-23','TERESA ACUERDO CON ALBERTO SACAR CON LA FIRMA DE LUCIA LA CANTIDAD DE 500 EUROS PARA CUBRIR LOS GASTOS DE PODOLOGIA, PELUQUERIA Y COMPRAR ROPA ARCHIVO ESCRITO ENTREGA 500 EUROS EN CONCEPTO DE DINERO DE BOLSILLO A LA DIRECTORA DEL CENTRO ANTE LA IMPOSIBILIDAD DE PODER HACERLO DE OTRA MANERA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GONZALEZ'and apellido2='SILVA'),'2021-06-01','Belén: Tiene un embargo ejecutivo de la Tesorería General de la Seguridad Social por cobro indebido de PNC desde el 2018 hasta el fallecimiento de su hermano Domingo con quien convivía. Le han sido embargados hasta el momento 2500€ y aún debe 1200€ aprox. La TS del CR El Cuartillo Claudia (927005280) envía informe social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GONZALEZ'and apellido2='SILVA'),'2021-06-22','Belén: La TS Claudia (927005280) del CR. el cuartillo nos envía presupuesto de gastos mensuales y de bolsillo. Se guarda en su expediente. Por ahora no se le da asignación porque con los embargos tiene más gastos que ingresos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-23','email Futuex ultimas incidencias , no adherencia a tratamiento .Voy a solicitar al ESM internamiento involuntario. Derivo el caso a coordinacion de equipo. Hola Amalia, buenas tardes, pues resulta que lo tiene renovado, lo perdió y se lo renovó la madre, lo adjunto-. Tiene validez hasta 2025 Aprovecho para actualizarte la situación de la semana pasada, negándose a acudir a cedex y consulta de salud mental. Con fecha de hoy, jueves 17 de junio 2021, tenía programada Alejandro Núñez, consulta de revisión en equipo de salud mental de Valdepasillas, Dr. Pablo Calderón López, citado desde su última visita el 15 de febrero de este mismo año, al que se le realizó acompañamiento desde este equipo de apoyo social comunitario de Badajoz. En dicho informe que se adjuntó en su momento, el Dr. Calderón le realiza un diagnóstico de: discapacidad intelectiva, alteraciones del comportamiento, trastorno relacionado con el consumo de cannabis y antecedentes de TDAH tipo combinado. Insistiendo en la toma de su medicación diaria (Topamax 0-1-0-1) e inyectable mensual (Abilify maintena 400 mg). El inyectable, podemos confirmar que hasta el mes de mayo (18 de mayo) ha estado administrándose a su debido tiempo (realizando los acompañamientos) aunque la toma diaria del Topamax, ha sido muy irregular, pues ya depende de él. Pero no ha sido posible contactar con Alejandro ya que se niega a ello, ni siquiera a través del teléfono de su madre con la que sí logramos comunicar, para planificar la consulta tanto de inyectable como de revisión de psiquiatría que le corresponde con fecha de: martes 15 de Junio inyectable; jueves 17 de Junio nsulta psiquiatría. Ha tenido dos derivaciones a servicio de urgencias del hospital Universitario de Badajoz: una por presentar cuadro de asma con insuficiencia respiratoria, tuvo que estar algunas horas con oxígeno e inhaladores. Se le recomendó llevar una vida más sana y urgente pérdida de peso (120 Kilos) actual. Una segunda derivación a urgencias, siendo valorado por psiquiatría, al negarse su madre a darle dinero para realizarse un tatuaje. Situaciones de violencia, gritos y golpes en las puertas y pared de la vivienda. Se le administró medicación en el momento y recomendaron mantener su pauta diaria. Confirmamos que mantiene sus conductas y alteraciones del comportamiento, con violencia en el ámbito familiar en muchas ocasiones que derivan en llamadas a la policía por parte de su madre y abuelos, así como de los vecinos que comentan que es una situación insoportable. Se levanta cerca del mediodía, siempre usa la misma ropa, obligando a veces a su madre a lavarla rápidamente, a pesar de que tiene ropa suficiente. Se marcha a la calle con esos amigos a los que vende, en realidad regala, todo lo que compra. Sin otras actividades, ni horario en su vida diaria. Amenaza constantemente a su madre y a sus abuelos, y cuando sus demandas no son respondidas: dinero y más dinero, emplea la violencia para conseguir sus objetivos. Se supone que en salud mental estan al tanto de que esta ausentandose de las citas, pero que sepamos no se esta programando ningun ingreso en UHB. Seguimos, buen dia!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-23','Ana: Llamo a la Residencia de mayores de Aldea del Cano, para interesarme por Florencia (927 38 30 90/20): la auxiliar que me atiende dice que está traquila, ha hecho bien la noche, peo se lo quiere llevar todo consigo en todo momento diciendo "no que me lo quitan", tanto fotos como otros objetos. Llevaba puesta una toalla a modo de compresa, por lo que se la cambiaron y pedirán el médico que se las prescriba para poder comprárselas y no coger las de otras usuarias. ································································································································································································ Llamo a Mª José Polo, TS del SSASB (664 018 209): ya ha hablado ella con la empresa de SAD, han acordado que si todo va bien con la "adaptación" de Florencia, el próximo lunes se dará de baja. **Lo comunciará ella al SEPAD. ················ Informo a Alberto al repecto. ·········· **Con respecto a gastos de bolsillo, Mª José entregó a Florencia en un monedero junto a la documentación (DNI y tarjeta sanitaria) entre 50-60 € que finalmente le habían sobrado. *Lo comunicó ayer a la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-23','-Amalia , escribo al ESM Badajoz. Buenos días Carmen, cómo estás ? te reenvio directamente el email de Futuex con el seguimiento que le tengo programado a Alejandro para conocimiento de su psiquiatra. Se ha planteado la posibiidad de internamiento involuntario en UHB ?? Un saludo , estamos en contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2021-06-23','Ana: Correo de Paloma Reyes, TO CRR-CC: "Buenos días: Me pongo en contacto con vosotros en referencia a Antonia, y ciertas demandas que nos está haciendo. Creo que Pedro ya os comentó algo, pero ahora mismo no se encuentra en activo. En primer lugar en referencia al testamento. Antonia lleva meses insistiendo en este tema, y en querer hacer algo sencillo para determinar qué se hará con sus posesiones y delegarlas a su hermano. Ella ha acudido en su tiempo libre a una notaría y se ha informado del procedimiento (me indica que le costará alrededor de unos 50€). Por parte del equipo, creemos que es algo que sería positivo para su estabilidad clínica y para ayudar a controlar las ideas que, en ocasiones, aparecen sobre quien se quedaría con su dinero en caso de fallecimiento. Por otro lado, tiene planificado el cambio de armario y renovación de ropa de temporada, necesitando adquirir nuevas prendas de ropa y calzado. Tenemos cita el próximo día 25 de junio para retirar la mensualidad correspondiente, pero no es suficiente para estos gastos extras. Sería necesario retirar al menos 120-150€ más para hacer frente a ellos, por lo que solicito vuestra autorización. Sin otro particular." ······························································································································································································· Envío correo a Alberto, Ángel y Miguel CTAEX: "Os reenvío este correo remitido por el CRR-CC relativo a Antonia Canelada del Río, subrayo en amarillo lo más importante. - Alberto: si se puede, hay que autorizar un extra de entre 120-150 € para ropa y calzado, para retirar el día 25, a ser posible, pues tienen ya cita para retirar la asignación mensual. - Ángel y Miguel: creo que alguno de vosotros ya estuvo con este tema. Antonia quiere realizar testamento. En el hilo tenéis el contacto (teléfono y mail) de Paloma, TO, para que podáis contactar con ella al respecto. Ya me vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2021-06-23','ANA: subo al portafirmas digital la Aceptación de Mantenimiento de PIA (mantenimiento plaza en CSS)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='PEREIRA'and apellido2='RUIZ'),'2021-06-23','Ana: Pongo para la firma del D-Gerente (portafirmas digital) la Aceptación PIA "mantenimiento de plaza en el CSS".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2021-06-23','Ana: Tras recibir llamada de Isabel Pino (927 347 000), TS, Ayto. de Miajadas, envío correo a Alberto e Icíar, secc. ecca. CTAEX,: "He recibido llamada de Isabel Pino, TS del Ayto. de Miajadas. **Necesitan los JUSTIFICANTES BANCARIOS de todas las mensualidades del ABONO DEL ALQUILER de la vivienda de Vanesa Fernández Gómez relativos al año 2019 (fecha en que aún la CTAEX tenía asumido el cargo de Tutor), pues, dada la escasez de viviendas social salieron unas ayudas complementarias al alquiler y a ella se la han concedido. Se solicitan a año vencido y se justifican a posteriori, de hecho ahora tiene que presentar la solicitud para el 2020. Seguimos." ··············· *Enviarlos a Isabel por mail: ipino@miajadas.org // Vanesa abona 175€/mes de alquiler y le han concedido 113€/mes de ayuda. *Continúa residiendo en el mismo domicilio: C/Donoso Cortés, 23.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2021-06-23','Belén: se envía CI para Cateterismo y Angioplastia coronaria a la Unidad de TS de HIC (924219615)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-06-23','Ana: Envío correo a Ángel con copia a Maite (CTAEX): "He recibido llamada de José Luis García, Secretario General de la Policía Nacional del Cáceres (927 626 548). El certificado que te dijo que te intentaría facilitar relativo a Mª Rosario González Jorna, por lo visto no nos lo pueden expedir porque no figura en su base de datos, por, según dice, no haberse hecho nunca el DNI. Según dice debió de irse muy jovencita a Francia y se fue sin habérselo hecho. Tal como dice, y ya sabíamos, la cuestión es más que complicada por dos motivos: • Carecer de documento de identidad español • Carecer de documento de identidad francés No obstante, dado que les consta que llegó a solicitar la tarjeta de régimen comunitario hasta en 3 ocasiones, debió presentar en dichas ocasiones el documento francés. La otra contrariedad es que ellos tampoco tienen dicho documento por haberse destruido el expte. cuando se trasladó de ubicación al comisaria. **Nos piden que intentemos localizar donde sea (a través de familiares, domicilio antiguos, aytos., recibos de luz/agua, etc.) una fotocopia de dicho documento que debió utilizar en alguna que otra gestión una vez que se vino a España en 1995, año en que solicitó la tarjeta de residencia por primera vez... Veré a ver qué puedo hacer al respecto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GONZALEZ'and apellido2='SILVA'),'2021-06-23','Belén: tras conversación teléfonica con PNC y Tesorería de la Seguridad Social para solucionar el tema del embargo se hace escrito para solicitar una revisión del expediente explicando la situación en la que se encontraba el tutelado y su incapacidad para resolver este tipo de temas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-06-24','TERESA Beatriz ha pasado a piso supervisado de Mérida le paso el seguimietno del caso a Amalia por zonificacion Ya está ajustado presupuesto, 550 euros mes para pagar gastos piso y gasto para ella que sacara en la primera semana de cada mes. El coordinador es Manuel Picado.','2');
