insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2021-06-25','Envío correo al CSS, de Mérida, así como a compañeros de Comisión y Soraya: "Buenos días, En relación a este procedimiento, la Comisión Tutelar de Adultos de Extremadura, trasladó escrito al Juzgado de Primera Instancia e Instrucción, nº 4, de Mérida (Badajoz), que éste recibió, en el procedimiento DPA nº 255/2021, comunicando la imposibilidad de cumplir la medida impuesta, toda vez que ambos, Dª. María Jesús Cruz Esperilla y D. Andrés Gale Cabrera, son residentes del CSS, de Mérida (Badajoz), acompañando plano de situación de ambas unidades en las que se encuentran, así como Informe del CSS, de Mérida (Badajoz). Puestos en contacto con el Juzgado, ha manifestado, verbalmente, a esta Comisión Tutelar de Adultos de Mérida, que no va a proceder a modificar la medida impuesta, puesto que es una circunstancia que no le compete. Nos traslada que ya se lo expuso en sala, a la dirección del CSS, de Mérida, así como a la Letrada que representó a nuestra tutelada, Dª. María Luisa García Soto. La única vía posible es que la dirección del CSS, de Mérida, se ponga en contacto con el Centro Penitenciario que determinó que, D. Andrés Gale Cabrera, cumpliera la pena impuesta en el CSS, de Mérida, procedimiento al que esta Comisión Tutelar de Adultos es completamente ajeno, y le traslade la incompatibilidad en el cumplimiento de ambas resoluciones, por un lado la pena impuesta y por otro la medida impuesta en el DPA nº 255/2021, a los efectos que resuelvan trasladar a D. Andrés Gale Cabrera a otro centro y poder cumplirlas. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2021-06-25','Envío correo al CRR, de Cáceres, residenciato@feafescaceres.com, residenciadir@feafescaceres.com, en relación con la opción que Antonia otorgue testamento: "Buenos días, En relación con la posibilidad que Dª. Antonia Canelada del Río pueda otorgar testamento, le indico, La sentencia de incapacitación de Dª. Antonia, no contempla expresamente la prohibición de otorgar testamento. En estos casos, existe la posibilidad de otorgarlo, pero precisa que dos facultativos designados por el Notario la reconozcan y lo autoricen, respondiendo sobre su capacidad. Si os parece bien, previamente a que os trasladéis con Dª. Antonia a la Notaría, traslado a ésta el caso, a los efectos de poder ofreceros una respuesta por su parte. Un saludo"','2');
