insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-06-25','Ana: Correo de Sonia Bernabé, TS y Directora ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería comunicarte que ayer ingresó Felisa Bruno Saavedra en Salud Mental en Cáceres. Desde por la mañana se mostró un tanto nerviosa porque no le gustaba el comportamiento de una compañera. Se intentó que se calmara pero ya en la hora de la siesta, agredió a dicha compañera, a cuidadoras que estaban atendiéndola dándoles patadas y queriendo morderles, tiró muebles, ... tuvimos que llamar al 112. El Psiquiatra refiere que se queda el fin de semana ingresada porque aunque está tranquila le notan signos de inestabilidad. También Felisa les ha comentado que está embarazada y que tiene más hijos. Le van a hacer un test de embarazo aunque las posibilidades de embarazo son muy muy pocas. El Lunes volveremos a llamar y te informo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TRINIDAD'and edp.apellido1='SEVILLANO'and apellido2='SEVILLANO'),'2021-06-25','Envío correo a SSB en relación con la posibilidad de otorgar testamento, "Buenos días, Con respecto a su consulta, le indico, Con respecto a D. Trinidad Sevillano Sevillano, actualmente ostentamos el cargo de Defensores Judiciales, porque, a pesar de habernos nombrado tutores, estamos pendientes de recibir la firmeza de la sentencia, a los efectos de aceptar el cargo. Una vez aceptemos el cargo de D. Trinidad, estaremos en disposición de aceptar o no las herencias de las hermanas fallecidas, Marcelina y María de los Ángeles. Con respecto a la posibilidad que D. Trinidad pueda otorgar testamento, la sentencia que le incapacita no se lo prohíbe expresamente, con lo que, en teoría, podrá plantear esta posibilidad a un Notario que, una vez designe a dos facultativos que le reconozcan, determine su capacidad para poder otorgarlo. Un saludo."','2');
