insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-06-28','Ana: correo de Feli- Empresa Depende de ti (info@dependedetisad.com) el domingo: "Buenos días Ana Al final solo hemos estado en el hospital 1 Noche. El sábado al mediodía trasladaron a Isabel a la planta de psiquiatría del hospital San Pedro de Alcantara y allí no nos han dejado entrar al ser una planta de Alta Seguridad. Ya me dices si tenemos que hacer algo FELI" ···················· Lo comunico a Alberto, Jefe Secc. Ecca. CTAEX en relación al abono del servicio. Y a Estrella, TS del CSS. ··························································································································································································· Llamada de Sara, TS HUC, me informa, para que lo tengamos en cuenta en futuras ocasiones: Según le han inforamdo las enfermeras, la Aux. que enviaron desde la empresa de SAD, era muy jovencita, se asustó con Isabel y no sabía como manejar la situación, incluso se salía de la habitación. Isabel tuvo una noche difícil, quería tragarse los guantes. No sirvió de mucho que la Aux. estuviera allí.','2');
