insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-06-28','Ana: Recibo correo-e de Albero con el Ok al presupuesto de la persiana. *Llamo a Mª Ángeles, Aux. de SAD (675 264 255) para confirmárselo. En cuanto hagan el arreglo nos harán llegar la factura con el número de cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-06-28','Ana: Correo de Sandra, TS Res. Coria (alexandra.alfonso@coria.org): Buenos días, te voy a dar el teléfono de la hija para que lo hables con ella mejor. Se llama Elisabeth y el teléfono es: ( 621 01 26 09 ) ·································································································································································································· Llamo a Elisabeth, hija de Mª Rosario (621 01 26 09). Su madre no se fue siendo una niña a Francia, se fue con "veintipico" años. Sí que tuvo DNI español. *Me puede facilitar varios documentos: Pasaporte, Libro de familia en que aparecía con sus padres y Permiso de Conducir francés. *Me pide que vuelva a llamarla sobre las 13 h para facilitarle la dirección de email, ahora no puede anotar. ············· Vuelvo a llamarle a la hora acordada, pero aún no ha llegado a casa y no tiene dónde apuntar. *Acordamos que le enviaré un correo y así hago (isacini1970@gmail.com): "Buenas tardes Elisabeth, Tal y como hemos acordado mediante conversación telefónica, le envío este correo para que tenga mi dirección y, cuando pueda, me remita escaneado todo documento de que disponga en que se haga constar la nacionalidad de su madre, tanto de la nacionalidad francesa (Pasaporte, Carta de Identidad, Permiso de Conducir) como de cuando contaba con la española (libro de familia o DNI antiguo si tuvieran copia) Con ello espero poder gestionarle su documentación de Identidad, pues como le comenté llevo meses intentándolo y sólo encuentro trabas y dificultades. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-06-28','-Del tema del nicho de la madre se están encargando Miguel e Iciar según me informa Ana . Buenos días, del tema nicho no hay hecha ninguna gestión que yo sepa no ha remitido documentación sobre este asunto. Lo suyo sería hablar con el ayuntamiento para nos informara para lo cual necesito que nos remita documentación acreditativa de la localización y titularidad del mismo. Miguel (jurídico ) . Se lo envio al CRR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-06-24','TERESA Natalia para su cumpleaños pidió un tatuaje y por varias razones, entre las principales el objetivo de mejorar su comportamiento, aún no se le había facilitado el hacérselo. Pues bien, esta semana que ella se ha quedado aquí (cuando el 98% de sus compañeros de resi se han ido a la playa) pudimos conseguir cita para que se lo haga por fin. En cuanto a la parte económica, aquí dispone de dinero, ya que como te dije, al no irse a Badajoz, ahorró bastante y aún le queda. El miércoles tiene cita para renovarse el DNI que lo tiene caducado, te enviaré copia escaneada. Y por último, pero como se suele decir no menos importante…, y tanto que no…. te enviaremos un registro de incidencias (está Isa con él ahora mismo) con el último episodio en el que está envuelta y por el que la familia de la afectada (Lorena) está “removiendo” en juzgado y demás para ver qué se puede hacer al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-28','miguel, llama Patricia (tía del curatelado 628297513)me comenta la impotencia que sienten con la situación del curatelado, que es extrema y que tal y como yo hablé con su padre han ido a denunciarlo a la policía. Recabaran todas las denuncias posibles y me las remitirán. La indico que tiene que hablar con Amalia y que es quien puede buscar un recurso por remoto que pueda ser (con o solicitud de internamiento involuntario). Nos escribe el siguiente email: Me dirijo a ustedes en nombre de la madre, los abuelos y en el mío propio tía de mencionado, para exponerles la situación entorno Alejandro Núñez Bono, de la que ustedes son conocedores por las reiteradas llamadas efectuadas por parte de la madre y de los abuelos a la comisión y de la que siempre obtiene la misma respuesta “ estamos en ello”. La situación es insostenible para Alejandro, pasa el tiempo y el deteriora en su situación personal va en aumento, su vida transcurre sin horarios, comiendo compulsivamente, sin nada que hacer y con el único objetivo de conseguir dinero para gastárselo, dinero que pide o incluso roba a su madre y abuelos y que cuando no le parece suficiente muestra una actitud agresiva hacia ellos, que termina muchas veces en destrozos en la vivienda de alquiler que comparte con su madre o en la de sus abuelos, imagínense la situación con la que tiene que lidiar unas persona con 85 años, a cualquier hora del día, pues estos episodio se repiten tanto de día como de noche. Alejandro necesita poner su vida en orden, como dice la sentencia necesita auxilio es una persona vulnerable, no sabe gobernar su persona, es incapaz de llevar su control terapéutico y también se hace complicado incluso a través de la persona asignada para llevarle al médico. Desde nuestro punto de vista necesita estar en un centro, donde lo controlen, lo supervisen, siga su tratamiento, corrija su comportamiento, deje los porros y su problema con el dinero (ahora empieza también a jugar a las máquinas), se quite de malas compañías, aprenda hacer algo y que pueda tener una vida, no se puede con 20 años condenarlo a un fracaso total. Entendemos que en la sentencia del proceso de modificación de capacidad 924/2018 que se dictó el 28 de octubre de 2019, faculta a la Administración para que tome medidas de protección hacia Alejandro y decida el ingreso en un centro adecuado cuando sea necesario, la situación es cada vez más complicada, queremos saber que se está haciendo o que soluciones se plantean para que esto no termine en tragedia. Un saludo Patricia Bono Contreras En nombre de: Belén Bono Contreras (madre) Pedro Bono Mena y Primitiva Contreras Baños (abuelos)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-06-28','miguel, escribo a petición de Maite a la Trabajadora Social del centro penitenciario nº2 de Cáceres para nos informe en relación al procedimiento penal y de qué juzgado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-28','miguel, remito email a Carlos Jurado el abogado ya que no he vuelto a tener noticias de él: Buenos días Carlos, necesito me indiques si ya conseguiste la documentación que necesitabas del SCH o si necesitas que me ponga yo en contacto con ellos y solicitarles el origen de la cantidad objeto del requerimiento. Si es así indícame la cuenta antigua, la actual, saldo y un email a quién dirigirlo. Por favor vamos a agilizar este asunto porque la familia pregunta a menudo por este asunto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-28','-Amalia . LLamada de su tía Patricia , está detenido por intentar arrebatarle el bolso a su madre cuando ha acudido al banco . No quieren interponer denuncia pq no saben cómo harían luego para garantizar la Orden de alejamiento . Fue expulsado del hostal la última vez . Insiste en un ingreso . Envio email al equipo CTAEX : Buenos días , he hablado con la tía de Alejandro , ya lo he hecho en varias ocasiones y no hay opciones de ingreso en ningún sitio mientras no deje el consumo de drogas . Como sabéis , para ingresar en comunidad terapéutica se exige su voluntariedad . Está acudiendo a CEDEX de manera ambulatoria , acompañado por delegada tutelar . Por favor , leed en la intranet todas las actuaciones que he llevado a cabo , a pesar de ser curatela patrimonial . Lo último , la semana pasada he solicitado al ESM derivación a la Unidad de psiquiatría si lo consideraban oportuno pero no he obtenido respuesta. Miguel si ves factible solicitar internamiento involuntario para compensación mental puedes iniciarlo . Aunque me temo que como mucho pasaría unos días ingresados en el hospital . Mayte si te parece bien , este caso , me gustaría abordarlo en equipo , incluidos jurídicos para que todos estemos al tanto de las actuaciones realizadas . Seguimos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-06-28','miguel,sigo llamando desde hace días a la policía de paisano y no lo cogen, por lo que el abogado enviará un burofax','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-28','miguel, escribo a Amalia: Hola, te va a llamar la tía de Nuñez Bono insistiendo que hay que internarle y que la situación es insostenible. La he remitido a ti… También la he recordado tal como le dije a su padre que recaben denuncias y cualquier incidencia para cuando tengamos varias remitirlas al juzgado. ************************** Contestación de Amalia: Buenos días , he hablado con la tía de Alejandro , ya lo he hecho en varias ocasiones y no hay opciones de ingreso en ningún sitio mientras no deje el consumo de drogas . Como sabéis , para ingresar en comunidad terapéutica se exige su voluntariedad . Está acudiendo a CEDEX de manera ambulatoria , acompañado por delegada tutelar . Por favor , leed en la intranet todas las actuaciones que he llevado a cabo , a pesar de ser curatela patrimonial . Lo último , la semana pasada he solicitado al ESM derivación a la Unidad de psiquiatría si lo consideraban oportuno pero no he obtenido respuesta. Miguel si ves factible solicitar internamiento involuntario para compensación mental puedes iniciarlo . Aunque me temo que como mucho pasaría unos días ingresados en el hospital . Mayte si te parece bien , este caso , me gustaría abordarlo en equipo , incluidos jurídicos para que todos estemos al tanto de las actuaciones realizadas . Seguimos.. ************************************** miguel, mi contestación: Hola, en relación al curatelado, veo inviable lo que entendemos por solicitud de internamiento involuntario al tratarse de una curatela (previamente tendría que haber una modificación de la limitación de la capacidad impliandola a tutela), lo cual habría que justificar con informes médicos y sociales indicándolo. Soy partidario de comunicar al juzgado todas las denuncias y quejas, unido a lo que hay en la intranet, y esperar a que una vez entre la nueva ley de discapacidad solicitar la revisión de la sentencia para convertirla en tutela y solicitar paralelamente autorización de internamiento involuntario (aunque como dices sólo serviría como dices para que pasara unos días en el hospital).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-28','- Miguel : Hola, en relación al curatelado, veo inviable lo que entendemos por solicitud de internamiento involuntario al tratarse de una curatela (previamente tendría que haber una modificación de la limitación de la capacidad impliandola a tutela), lo cual habría que justificar con informes médicos y sociales indicándolo. Soy partidario de comunicar al juzgado todas las denuncias y quejas, unido a lo que hay en la intranet, y esperar a que una vez entre la nueva ley de discapacidad solicitar la revisión de la sentencia para convertirla en tutela y solicitar paralelamente autorización de internamiento involuntario (aunque como dices sólo serviría como dices para que pasara unos días en el hospital). Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-28','-Amalia , vuelvo a escribir al ESm : Amalia Diaz Gonzalez Lun 28/06/2021 14:10 Buenos días Carmen , espero que estéis bien. Te escribí la semana pasada con este mismo caso. Me ha llamado la tía de Alejandro , Patricia, para comunicar que está detenido en calabozos por abordar a su madre cuando iba al banco. Comenta que está " desquiciado " , que necesitaría algún ingreso en centro . Le he explicado la complejidad de su situación , y de la denegación que han dado los recursos solicitados. Desde ESM , su psiquiatra cómo valoraría solicitar internamiento involuntario ? Tiene adherencia al tratamiento ? Estamos en contacto , un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2021-06-28','TERESA RECIBO LLAMADA DE CAROLINA TS DEL HOSPITAL DE ZAFRA LE DAN EL ALTA A JOSE MARIA, SE ENCUENTRA BIEN Y PUEDE VOLER AL DOMICILIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-06-28','miguel, me confirma Eugenio que el miercoles me llama por si decide quedarse con el vehículo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2021-06-28','Ana: Correo-respuesta de Toni: "Buenos dias Ana, que tal arranca la semana? yo bien, me vino bien pedirme el viernes y oxigenarme un poco. Esto sin problemas, se puede perfectamente hacer, esperarle hasta el siguiente bus, en el caso que cuadren las combinaciones, o incluso llevarle nosotros desde Badajoz a su pueblo, excepcionalmente si no encuentra otra via viable, aunque siempre es la ultima opcion. Por lo tanto hablaremos con la asociacion para conocer fechas y opciones"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-06-28','Ana: Correo de Felisa Custodio, CAMF Alcuéscar: "Estimadas compañeras, se han puesto en contacto conmigo desde servicios centrales de COCEMFE en Madrid, para informarme que este año se reanuda el programa de vacaciones para personas con discapacidad de Cocemfe subvencionado por el IMSERSO. La residente quiere ir a la playa. Os comento: Van un grupo reducido de residentes de Alcuéscar a Benidorm, salida y vuelta en autobús privado desde Alcuéscar. Del 19 al 26 de agosto. Aún falta pero me han pedido en Cocemfe tener las solicitudes lo antes posible para la reserva del hotel, por las limitaciones de aforo. El coste total a aportar cada residente es aproximadamente 1500 euros, incluye traslados, hotel, pago estancia del cuidador/acompañante, gratificación al cuidador/acompañante, dinero de bolsillo etc. Ruego la firma de los documentos adjuntos autorizando las vacaciones, al igual que hicimos con Rosario Solís Bermejo, siento no haber mandado todo junto pero Maribel se ha decidido a última hora a ir. Muchas gracias. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-06-29','De: ALBERTO MARTIN ROSETE >alberto.martinr@salud-juntaex.es>Enviado: lunes, 28 de junio de 2021 15:16Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es>; ESTRELLA MARIANA GUERRERO PEREZ >estrella.guerrero@salud-juntaex.es>Asunto: RE: presupuesto depilación Beatriz Mejias Hola AMALIA: OKa presupuesto de 2.206,59 € (184 €/mes aprox). Pero ten en cuenta que le damos 550 €/mes para centro. NO AHORRA PRÁCTICAMENTE: lo digo porque si, a lo largo del tratamiento de depilación solicita EXTRAS, estos deberían restringirse. Xfa, habla con tutelada y déjaselo claro. Y luego se lo confirmas a ESTRELLA para el PAGO. ESTRELLA: cuando AMALIA nos de OK, te pones en contacto con centro estética (Centros Unica (depilación láser y medicina estética) en CC. Carrefour Mérida) y cierras con ellos la forma de pago: preferentemente a través de transferencia: que te faciliten el PRESUPUESTO INICIAL y el CCC para efectuar los pagos. Alberto De: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es>Enviado: lunes, 28 de junio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MENDO'and apellido2='RODRIGUEZ'),'2021-06-29','Belén: se envía Consentimiento Informado para Biopsia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-06-29','TERESA SE PROCEDE AL TRASLADO A RESINDENCIA DE DISCPACIDAD INCLUSIVES DE VILLANUEVA APORTO INFORME MEDICO Y PAUTA DE MEDICACION ES NECESARIO INICIAR EL ESTUDIO DEL SUEÑO A TRAVES DEL NEUMOLOGO ESTA VACUNADO CON JANSSEN','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-06-29','miguel, a petición de Ana me informo con el Jzdo nº4 de Plasencia: Buenos días, acabo de hablar con el Juzgado de instrucción nº4 de Plasencia en relación a DPA Procedimiento abreviado 602/2019 donde me confirman que mañana día 30-6-21 han citado a la otra parte para tomarla declaración, y por tanto todavía no hay resolución del procedimiento. Conforme tengan resolución nos lo notificaran','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-06-29','miguel, llega la detención y juicio rápido por malos tratos y violencia doméstica contra su madre ayer, siendo la vista hoy, correspondiente al procedimiento Diligencias previas, juicio rápido 63/21 del jzdo de instrucción nº 4 Badajoz. Le reenvío el email a Amalia y aunque es el mismo juzgado lo remitiré vía fax a los efectos oportunos al de 1º instancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-06-29','Belén: envío correo a Felisa Custodio, TS CAMF-Alcuescar adjuntándole documentación firmada para el disfrute de las vacaciones de Mª Isabel Debón Chenique del Programa de Vacaciones del IMSERSO gestionado por COCEMFE. Posteriormente se envía originales por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-06-29','Ana: Recibo llamada de Ana Benavente (74955): Ceferino ha vuelto a llamarla expresando su malestar sostenido en el tiempo por seguir en Plasencia. Quiere irse de allí y pide cambio a otro CRR. *Como se le ha explicado que al de Badajoz no puede ir, plantea el de Mérida. **Aunque en los últimos 2 años ha solicitado verbalmente muchos cambios distintos (irse al pueblo con su pareja, irse a Piso Supervisado, a otro CRR, a vivir de alquiler a Cáceres...) lo que sí se ha mantenido en el tiempo es su deseo de abandonar dicho CRR y su malestar por seguir allí. Ya se valoró en Septiembre de 2020, nos enviaron informe (guardado en expte. digital); En aquel momento no consideraron procedente el cambio de recurso, seguirían trabajando con él y si en el futuro persistía su malestar se valoraría el cambio que solicita. **Acordamos que Ana Benavente enviará correo al CRR traslando la demanda y malestar expresado por Ceferino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-06-29','Ana: Llamada de Ana Benavente: pregunta quién lleva el expte. de Alfonso. Le pasará mi contacto a la Psiquiatra. Ésta quiere hablar con nosotros pues le preocupa Alfonso. **El inyectable se lo puso el día 25 de junio. *En esta ocasión no quería acudir a ponérselo, pero finalmente se lo puso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2021-06-29','Recibo llamada de Manuela Holguín (675903771), Abogada, actúa en representación de Mónica Gracia Bonifacio que quiere pedir la Remoción de la tutela. Van a iniciar el procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-06-29','Ana: Recibo llamada de María Jesús, TS Comarca de Trujillo (621 247 237): le han llamado de Serv. Sociales de La Roda, (Albacete), ha aparecido allí Javier Cumplido y le han llamado a ella. Ella le ha dicho que está tutelado por la Comisión Tutelar y que nos lo diría. Me facilita los contactos. (Ayto. de La Roda: 967 441 403 - Nuria, TS Ext. 2150 email: nrarenas@laroda.es /// Compañera: Elena, TS Ext. 2130) ······························································································································································································· Llamo a Nuria, TS de La Roda (Albacete) (967 441 403, Ext. 2150 email: nrarenas@laroda.es): Ha acudido Javier a su despacho, lo ve mal, "con mirada perdida, sucio, discurso cíclico, sin sentido y a veces un poco vilento", dice que le han robado el pasaporte y ha acudido a la Guardia Civil a poner la denuncia. Tb ha expresado que en Perpiñán le "engañaron". "Su discurso es cíclico y sin sentido". ···· *Acordamos que activarán el 112, para que lo puedan valorar y si está descompensado ingresar en el Servicio de Psiquiatría, después se podría gestionar el traslado al hospital de Cáceres. ······························································································································································································· Vuelvo a llamar a Nuria al final de la mañana. Me informa de que activaron el 112, pero que cuándo Javier vio a lo lejos el coche de la Guardia Civil se fue corriendo. La ambulancia llegó después. La Guardia Civil y Policía intentarán localizarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-06-29','TERESA El día 7 de julio tenemos planificado un seguimiento presencial en la localidad de Monterrubio de la Serena para la retirada de dinero pautado quincenalmente, compra de necesidades básicas y acompañamiento al CEDEX de Castuera teniendo ese día control de orina, psicóloga y médico. Si para la fecha ya tiene disponibilidad de trasladarse se le acompañaría también en este proceso, ya que entendemos la gran carga de trabajo que requiere cualquier mudanza. Quedamos a la espera de confirmación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2021-06-29','Correo de Blanca, Directora del CRR-Plas. (direccion.crrplasencia@grupo5.net): "Buenas Ana, Comentaros que estamos preparando una salida de un día a la playa, para el sábado 17 de julio de 2021. El viaje es con una empresa de autobuses. Se han apuntado: M. Ángeles Santos Ceferino Mariscal Félix Franco. Van acompañados de profesionales del CRR..."','2');
