insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2021-06-30','- Amalia , email a seccion juridica : Buenos días , esta autorizacion para tto. hormonal ya la conociamos hace unos meses , de hecho ya ha iniciado el tratamiento, y la entidad la debe tener pq se personaron en el juzgado directamete . Esto viene a coalición con el tema de la autorizacion que solicitan para el cambio de nombre en el DNI . Al parecer y según nos informa la Asociación Triángulo , sí se puede solicitar aunque todavía no haya cambiado de sexo . Le he pedido a la entidad que nos envíe toda la documentación al respecto y os la facilitaré . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICOLAS'and edp.apellido1='SANCHEZ'and apellido2='AREVALO DONOSO'),'2021-06-30','-Amalia , escribo a seccion eco: Buenos días , es una tutela nueva , desde PNC nos piden documentación . Ya he hablado con la Jefa de Seccion de PNC sobre el cumplimiento de estos plazos dificiles de cumplir , no habrá problemas si se tuviese que retrasar unos días más','2');
