insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-06-30','Ana: Tras recibir correo de los SS.SS. de la Roda, llamo tay como solicitan. Hablo con Elena, TS: Ayer la Guardia Civil y Policía Local, localizó a Javier en la localidad sobre las 20:30 - 21:00 h. Le llevaron al centro de salud, pero como estaba tranquilo, aparentemente bien, indocumentado y sin constancia de su incapacitación le dijeron que podía marcharse. **Esta mañana ha vuelvo a aparecer por los Servicios Sociales pidiendo comida. Le han dado un vale para un bocadillo y le han pedido que vuelva más tarde. ······· En cuanto al pequeño escrito que solicité ayer a su compañera Nuria, me dice que mejor lo pida por escrito, por email es suficiente. *Le envío el siguiente email (nrarenas@laroda.es): "Buenos días Nuria, Tal y como he acordado con tu compañera Elena mediante conversación telefónica, procedo a solicitaros un escrito en que se haga constar que D. Javier Agudo Cumplido, tutelado por la Comisión Tutelar de Adultos de la Junta de Extremadura, se encuentra desde ayer en el término municipal de La Roda (Albacete) así como las acciones/gestiones que desde los Servicios Sociales habéis llevado a cabo con respecto al mismo, a fin de poder comunicar al Juzgado la situación y ejercer el cargo encomendado de la mejor manera posible. Adjunto remito copia de: - Testimonio de Sentencia Firme de Incapacitación y Nombramiento - Acuerdo de aceptación del cargo Gracias y un saludo." ································································································································································································ Recibo escrito del Departamento de SS.SS. de La Roda y se lo remito a los Asesores Jurídicos CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='VARGAS'and apellido2='SUAREZ'),'2021-06-30','TERESA SE AUTORIZA 90 EUROS DE GASTOS DE BOLSILLO LOS SACA LA DIRECTORA COMO AUTORIZADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-06-30','miguel, logro hablar con la policía local de paisano, tras días intentandolo quienes me indican que el email lo enviaron a ctutelar el 3-6-21. Lo subo a su expediente y lo remito al abogado Jorge Calvo para que tramite el desahucio correspondiente. ************************************************** Contestación del abogado Jorge Calvo: A la vista de que la inquilina es la firmante del contrato. Procedo a remitir burofax para solicitarle el pago y la resolución del contrato. O , en su defecto, que aclare la situación. Perdona una pregunta. Para enviar el burofax entiendo que es poca cosa para mis servicios. Pero para iniciar acciones judiciales, desconozco cual es la capacidad que tiene Maria del Carmen para ello. Es ella la que debe firmarme la hoja de encargo o debe estar revisada por la comisión? Es algo que me gustaría ir agilizando para que no nos pare en su momento, llegado el caso. ************************************************ mi contestación: Hola Jorge envíame cuánto serían tus honorarios en los distintos escenarios según: 1) Burofax y se fuese por las buenas (sin o con daños en la vivienda) 2) Interposición de procedimiento de desahucio sin reclamación de cuantía (previo burofax, incluyendo aproximadamente gastos de procurador) 3)Interposición de procedimiento de desahucio sin reclamación de cuantía Y si a dichos procedimientos de desahucio hubiera que incluir daños en la vivienda Entiendo que no puedan ser exactos, pero es para ver si podremos reclamar lo que debe o no…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-06-30','miguel, recibo del centro penitenciario de Cáceres 2 indicación del procedimiento penal Diligencias Previas 751/20 por el que el tutelado se encuentra en la carcel. Llamo al Jzdo nº6 de Cáceres, que no me facilita documentación si no nos personamos por escrito, lo cual haré, pero sí me indica el nombre de la abogada que le está defendiendo, Carmen Lucas Duran (927-226664, email mlucasduran@icac.es). Llamo a la abogada y la remito el email: Buenos días Carmen, conforme conversación telefónica y en relación al procedimiento en Diligencias Previas 751/20 del Juzgado de 1º instancia e instrucción nº6 de Cáceres, adjunto la sentencia de nombramiento a la Comisión Tutelar de Adultos. Adjunto también la autorización de internamiento involuntario que en 2017 se tramitó desde esta Comisión y por la cual estuvo un tiempo ingresado. Voy a remitir al juzgado dicha sentencia también. Quedo a tu disposición para cualquier cuestión. ******************************************************* Preparo escrito dirigido al juzgado para personarnos, adjuntando testimonio de nombramiento. ******************************************* Llamo tanto al ju','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-06-30','Ana: Correo de ayer de Maru Rodríguez, TS de CS Manuel Encina (angeles.rodriguezl@salud-juntaex.es): "Buenos días, Ana Como sabrás, junto con la compañera de salud mental, he promovido también la incapacitación de Clementa. Actualmente estoy en contacto y trabajando con su hija y yerno. Ayer tuvieron comparecencia ante el juez y planteó la hija su imposibilidad para hacerse cargo de la anciana (apoyo la postura) y la conveniencia de ingreso en centro residencial dada la actual situación: grave conflictiva familiar (la anciana mantiene rivalidad conflictiva con yerno y actualmente duerme con su hija en la habitación y el yerno en el salon, como ejemplo). La hija tiene graves problemas con el alcohol que le impiden hacerse cargo de la anciana. Supongo que en este momento procede reactivar PIA con propuesta de ingreso en centro residencial. Si consideras que puedo colaborar en esto, comentamos cuando puedas." ······································································································································································································ Mi respuesta con copia a Miguel y Ángel, Asesores Jurídicos CTAEX: "No hay ningún inconveniente en que se reactive el PIA de Clementa Amado Vivas, al menos por nuestra parte, no obstante recordarte que la CTAEX sólo ostenta el cargo de Administrador de Bienes, y por tanto no podemos firmar dicha solicitud, la debe firmar la propia Clementa. Quién por otra parte, no sé si querrá ingresar voluntariamente, ¿te lo ha manifestado ella o la hija? Desde la CTAEX, a pesar de tener sólo aceptado el cargo de la Administración de Bienes, se solicitó, a finales de diciembre, el internamiento involuntario de Clementa, aportando informe social de Pilar Martín e Informe de la Compañera de Futuex que está haciendo el Seguimiento en el domicilio. Pero a día de hoy no nos han enviado autorización para dicho internamiento. Por tanto, si ella voluntariamente no quiere, habrá que volver a solicitarlo, bien desde los Servicios de proximidad, Pilar o tú, bien desde la CTAEX reiterando la solicitud ya remitida en su día y, a ser posible, adjuntando un informe complementario que tú nos facilitaras para acreditar la situación actual y la necesidad de dicho internamiento. Pongo en copia a mis compañeros jurídicos para que estén al corriente y por si pueden añadir alguna información que yo desconozca."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-06-30','Ana: Tras haber recibido en el ctutelar@ correos de Pablo Morato diciendo que "el individuo" que vive con su abuela se la lleva de nuevo fuera sin comunicárnoslo, envío correo a la empresa de SAD Servicios del Fresno (visitas@serviciosdelfresno.es): Buenos días Amelia, Espero que estés bien. En relación a Dña. Manuela Morato Picado, tutelada por la Comisión Tutelar de Adultos de Extremadura, ¿podrías, por favor, confirmarnos si la Auxiliar de SAD está acudiendo esta semana a su domicilio? Así mismo, agradeceríamos que nos comuniques, por escrito, cada vez que la Auxiliar vaya a disfrutar de sus vacaciones o no realice el servicio por cualquier circunstancia (baja, asuntos personales u otros motivos) y en su caso, si es sustituida por otra persona, a fin de tener un mejor seguimiento en el ejercicio del cargo de Tutor. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-06-30','Ana: Llamo a Elisabeth, hija de Mª Rosario,(621 01 26 09) para confirmar que recibió bien el correo que le envié, me confirma que sí, pero que debido a trabajo no ha tenido ocasión de enviarme los documentos, me los enviará mañana que no trabaja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2021-06-30','Ana: Correo de Estrella, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. El equipo de la UHDAC nos estamos planteando con Yolanda el que pueda hacer visitas de un día a su centro de Villanueva de la Serena, a ver si le sirve de motivación para control de impulsos y se reducen las alteraciones de conducta que presenta. Te escribo para ver si os parece bien y si podemos hacer como hicimos con Remedios Chaves, que se pague ella el taxi... Hablé con Directora del Centro y les parece bien. Ya me dices..." ······························································································································································································ Mi respuesta: "Buenas, de nuevo, Estrella, Tras hablar con mi compañera Teresa (TS de Referencia en Villanueva), te planteamos las siguientes cuestiones: - ¿Yolanda ha manifestado interés en acudir a pasar un día al centro? En este caso, ¿tienen ella claro que debe regresar a la UHDAC el mismo día así como de la distancia y tiempo de traslado? Rogamos le incidáis en este aspecto, para que sea consciente de ello y de que el tiempo que permanencia en el centro no será muy prolongado. - En cuanto al taxi, ¿irá acompañada? ¿o valoráis que pueda ir sola? - Cuando dices que hablaste con la Directora del centro, ¿te refieres a Inclusive Villanueva de la Serena? En ese caso, si el centro también está de acuerdo y pueden organizarse para la visita, dado que desde el equipo técnico de la UHDAC, consideráis que será beneficioso para ella y que le servirá de motivación para mejorar y controlar su conducta, no tenemos inconveniente en que la visita se lleve a cabo. Económicamente podría asumirlo, en cuanto me envíes presupuesto del taxi le doy traslado al jefe de secc. económica para que nos dé su conformidad. Ante cualquier cuestión seguimos en contacto." ····························································································································································································· Respuesta de Estrella: 1ª pregunta, no sé si ella lo ha pedido, entiendo que su Psicóloga lo ha planteado porque intuye que le gustaría. Por supuesto, que se le dejarían claras todas esas cuestiones, distancia, tiempo etc. 2ª pregunta, por supuesto que iría acompañada por personal auxiliar de este centro. 3ª pregunta, sí, me refería a la Directora de Inclusives Villanueva de la Serena"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-06-30','Ana: Correo de Sonia Bernabé: Mañana dan el alta a Felisa en la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-06-30','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "...Me han mandado la solicitud para salida el fin de semana de los hermanos Hernández Castaño. Se irían el día 2 y regresarían el domingo 4. El sábado su hermana estará con ellos en el pueblo y ya me contará cómo se organizan. Cómo se van a casa? En taxi? No sé cómo estaba el tema de Cruz Roja porque el último viaje con ellos sería en Marzo del 2020." ······························································································································································································· Mi respuesta: "...En cuanto al viaje de los hermanos Hernández Castaño, pues como lo hayan hecho otras veces. En la Intranet me consta que en alguna ocasión ha habido que recurrir a un taxista de confianza para llevar a Roberto (cuando no regresó con el hermano), pero previamente se hacía con Cruz Roja. ¿Quién organizó esto en su día? Por aquel entonces yo no estaba trabajando aquí. Si tenéis el contacto y se puede hacer con Cruz Roja, como antes, perfecto, sino pues al taxista que conozcáis y esté disponible.. Y ambos casos tendréis que enviarnos presupuesto previo para que el jefe de sección económica nos de su conformidad. Ya me decís."','2');
