insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2021-06-30','Belén: se establece hacer transferencia a Julieta (635149247) de 160€ que se los administrará de acuerdo a las necesidades de José Antonio (cafés, dulces,...). Cuando se vayan agotando nos avisará para hacerle otro reintegro. Anteriormente no tenía asignado gastos de bolsillo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-07-01','Ana: A petición de la secc. ecca. envío el siguiente correo a Rosa Bravo, Admvo. CSS Plasencia: "...En el expte. de José Luis Murillo Horrillo, tenemos su DNI caducado. ¿Sería posible que nos enviaseis escaneado a color el DNI actualizado? Lo necesitan en la secc. económica para el banco. Gracias y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-07-01','TERESA RECIBE INGRESO POR IMPORTE DE 996,44€ EN CONCEPTO DE VENTA DE UNOS COCHINOS QUE TENIA A SU NOMBRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CORBACHO'and apellido2='GALINDO'),'2021-07-01','EXITUS Fallecido el 26/06/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-07-01','miguel, me llama Eugenio (posible comprador) 606985996 y me dice que el coche no está en la calle Legión, Rover 25 matricula 588BBG. Amalia y Tere me confirman que él decía que lo había vendido a la chica del contrato del 2017 Mª Guadalupe Garcia Fernandez. Alberto me confirma que no paga seguro. La policía llamar mañana q hoy no está el que lo lleva','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-07-01','Ana: Correo de ayer de Toni-Futuex en relación a cuestiones pendientes con J. Ramón, cuestiones enquistadas y que hay que darle respuesta ya (vehículo que compró estando en la residencia de mayores y que no merece la pena su arreglo y obra pendiente de la cubierta del edificio que corresponde asumir a la comunidad de propietarios). *Guardo las notas informativas en su expte. digital y envío correo a los Asesores Jurídicos CTAEX: "Os remito correo de Toni, Futuex, con cuestiones a las que tenemos que dar respuesta ya. En cuanto al vehículo, en mi opinión que se lo lleven al desguace y listo. No sé si en este caso tenemos que firmar desde aquí algo. Y en cuanto al arreglo de la cubierta del edificio, que cada vez está peor es un peligro, lleva coleando mucho tiempo. En la anotación del 26/05/21 de la Intranet, podéis leer que hablé con el albañil que en teoría iba a hacer la obra, y me dijo que había hablado con dos propietarios y que no habría problemas, que en cuanto terminase la obra con la que estaba lo arreglaría… Le acabo de volver a llamar y claro, ahora me dice que hasta que la comunidad de vecinos no esté constituida que no se atreve a realizar la reparación. ¿Podemos iniciar algo para exigir dicha constitución de la comunidad o para hacer el arreglo y exigir a cada propietario su parte del abono?? (no sé si viene algo en la Ley de la Propiedad Horizontal o en qué normativa… se me escapa) ya me decís, pero no debemos dejarlo más tiempo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-07-01','miguel, contestación a Ana: Hola Ana, con respecto al arreglo o no del vehículo necesitamos que por escrito indique el taller qué tiene el vehículo para decidir si solicitamos retirada por la grúa y al taller. Desconozco si tiene o no seguro (para el traslado al desguace…) Con respecto a la segunda cuestión en relación al arreglo de la vivienda, veo en los antecedentes y la respuesta que se le dio al juzgado (cuando nos requirió para informásemos acerca del estado de salud del tutelado) que se lleva arreglando su vivienda al menos desde el 2019…por lo que indica Futuex parece que es la cubierta del edificio lo que esta mal…Si es un elemento común al edificio el arreglo corresponde a la comunidad de vecinos que independientemente de haberse constituido tienen que arreglarla y pagarla según la cuota de participación que tengan en el edificio, lo cual pueden comprobarlo en nota simple (finca matriz del registro de la propiedad) o bien en la escritura de división horizontal…Dicha documentación debe tenerla el presidente o la asesoría… En esta cuestión no entramos porque nosotros al representar únicamente al tutelado sólo nos encargaremos de abonar previo presupuesto el importe que a él le corresponda. Dependerá del importe que cueste el arreglo que al tutelado corresponda, el que tengamos que solicitar al juzgado o no los gastos extraordinarios… Por tanto sólo podemos dar solución por ahora a lo del coche que como digo nos tienen que dar por escrito el diagnóstico del mismo (por escrito y el presupuesto de arreglo) y tras averiguar si tiene seguro o no, enviar al desguace si el arreglo es superior a su valor...Dicho valor sólo podríamos calcularlo si nos dan matrícula y marca y modelo del vehículo, cilindrada, diesel o gasolina…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-07-01','Ana: Correo de Emilia Almodóvar, TS del CSS-Plas. (emilia.almodovar@salud-juntaex.es): "Buenos días Ana. Adjunto el listado de pacientes que desde el equipo se ha decido que pueden participar activamente con el proyecto presentado desde Futuex. El paciente que más utilidad y mejora de rendimiento personal puede tener de este proyecto es Jairo, por esos motivos está incluido en la mayoría de las áreas a excepción de la sanitaria. Con respecto a Jairo te informo que ha pasado a la UNIDAD DE REAHABILITACION DEL CENTRO, U.R.A. Te seguiré informando." ······························································································································································································ Llamada de Jairo, me cuenta que ha cambiado de unidad y comienza un discurso en que apenas me deja intervenir sobre la búsqueda de empleo, "desvincularse legalmente" de su pueblo, "pedir la remoción pero mantener el vínculo con la Junta"...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-07-01','Ana: Correo de Maru, TS C.Salud Manuel Encinas: "Buenos días, Ana El 26/06/2021 fue la comparecencia en ese sentido: ingreso involuntario y tutela. Estamos a la espera de sentencia para poder proceder. estoy en coordinación con Pilar (ESM) para agilizar lo que se pueda el caso. Gracias y buenos días" ······································································································································································································· Mi respuesta: "Buenos días Maru, Ok, pues gracias por la información, supongo que el Jdo. nos remitirá también la firmeza a la CTAEX, hasta entonces seguimos sólo con la administración de bienes. Por vuestra parte, perfecto, ya me vais diciendo. Buen día a ti también."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2021-07-01','TERESA ENVIO SOLICITUD PENSION DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-01','Amalia, este es el correo que le ha enviado Pablo al coordinador de la UHB´me ha dado permiso para reenviartelo. Un abrazo SíNo De: PABLO CALDERON LOPEZ >pablo.calderon@salud-juntaex.es> Enviado: miércoles, 30 de junio de 2021 13:41 Para: MOISES BOLIVAR PERALVAREZ >moises.bolivar@salud-juntaex.es> Asunto: Comunicación acerca paciente ANB Buenas tardes Moisés. Te pongo en conocimiento de la situación del paciente ALEJANDRO NUÑEZ BONO, fue el motivo de llamarte ayer. Se trata de un paciente con antecedentes de DISCAPACIDAD INTELECTIVA. ALTERACIONES DEL COMPORTAMIENTO, TRASTORNO RELACIONADO CON EL CONSUMO DE SUSTANCIAS, CANNABINOIDES), ANTECEDENTES DE TDAH TIPO COMBINADO con seguimiento desde JULIO/2020 por alteraciones del comportamiento. En su patobiografía consta estancia en centro penitenciario desde Agosto/2019 hasta Diciembre/2019; ha estado en pisos tutelados; su padre abandonó el hogar familiar cuando el paciente tenía 3-4 años y no ha vuelto a tener contacto con él; no asiste a ningún recurso formativo u ocupacional. Carmen Días ha recibido un correo desde la Comisión Tutelar de Mayores en el que se nos informa de la falta de asistencia del paciente a las consultas (efectivamente no acudió a la cita que tenía programada) así como la falta de cumplimentación de la medicación (oral y parenteral). También se nos informa que presenta alteraciones del comportamiento que han precisado de dos asistencias en el Servicio de Urgencias del HUB, la última el pasado 02 de Junio de 2021 siendo valorado por PSQ - G que no indicó ingreso manteniendo la prescripción farmacológica. Por otra parte, se ha denegado el ingreso del paciente en la UDHAC de CS de Plasencia al presentar el paciente consumo activo de cannabis. Desde el CEDEX plantean riesgos de ingreso en una Comunidad Terapéutica ya que existe la posibilidad de que el paciente amplie el consumo a otras sustancias. Actualmente el paciente está en dependencias policiales por amenazas a la madre en la puerta del banco cuando se disponía a sacar dinero (a fecha del día de hoy no sabemos su situación policial / judicial). Ante estas circunstancias relacionadas con su comportamiento, la Comisión Tutelar plantean un ingreso en UHB incluso con carácter involuntario. Con esta situación y ante una eventual visita al Servicio de Urgencias, considero que sería conveniente un ingreso en la UHB para control y contención (abstinencia de sustancias) así como para reintroducción de la medicación que ha abandonado. En una futura estancia en la Unidad se podría retomar la solicitud de derivación a la UDHAC para un ingreso (valorando uno involuntario) dentro de los plazos en los que se cumplan los objeticos de internamiento en la UHB. Por nuestra parte, seguimos en contacto con la Comisión Tutelar para intentar recuperar seguimiento o, en su caso, iniciar gestiones clínicas de ingreso (ya sea voluntario o involuntario). Estamos planteando la convocatoria de una Subcomisión de Gestión de Casos para abordar el caso. El motivo del presente es darte a conocer la situación clínica de ALEJANDRO para que se tenga en cuenta ante una eventual consulta al Servicio de Urgencias en horario de mañana a fin de que lo comuniques a la/os compañera/os que atienden las Urgencias en dicho horario. Ya he registrado en su historial esta cuestión del ingreso en la UHB. Intento ponerme en contacto por telefóno en estos próximos días. Saludos cordiales. pablo calderón.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCAS'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2021-07-02','TERESA El motivo del presente email es informar sobre el estado actual de salud del tutelado LUCAS GOMEZ GALLARDO. De acuerdo con la conversación mantenida la semana pasada, Lucas sigue hospitalizado. Después de la primera intervención no se obtuvieron los resultados esperados, como consecuencia, ayer se le volvió a intervenir de manera urgente. En estos momento, se encuentra recuperándose. La persona trabajadora encargada del acompañamiento hospitalario ha cambiado, por lo que ahora es otra persona la que presta dicho servicio. Se procede a realidad el abono de los gastos ocasionados en cuanto al acompañamiento hospitalario perteneciente a la primera persona trabajadora. En cualquier caso, para cualquier tipo de duda puede ponerse en contacto con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-02','miguel, recibimos email de su tía PATRICIA BONO >patibo@hotmail.com>: Como ya os comenté en un correo anterior a Alejandro le había detenido por intentar quitarle a su madre dinero en la calle, os paso la documentación, tiene que comparecer el 12 de Julio, nos gustaría estar informados de la defensa que va a tener, como no se tomen medidas para que siga su tratamiento y se le dispense ayuda para que se estabilice, estas situaciones por desgracia para él y para su familia se repetirán. *************************************************** Nos remite citación del curatelado para el 12-7-21 ante el jzdo de instrucción nº4 Badajoz Proced Dilig Urgentes/Juicio Rapido 63/21 al cual no tenemos que asistir porque la sentencia nos nombra únicamente para el ámbito patrimonial y de la salud','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-07-02','TERESA ENVIO AUTORIZACION PARA SALIDA DEL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-06-29','Ana: recibimos por correo-e escrito de Mª José Polo, TS del Zarza de Granadilla, un escrito junto con la cartilla bancaria. Pero la cartilla es la antigua de Caja Duero, el número de cuenta ha cambiado, por la fusión de entidades, ahora es Unicaja. Por tanto se destruye esa cartilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-07-01','Ana: Correo-e de Sonia Bernabé-Asindi: "Hola, te mando el informe de Felisa que ha llegado esta mañana. Por lo que dicen las compañeras no tiene muchas ganas de estar aquí pero intentaremos que se motive con actividades como piscina, fiesta de cumpleaños,..." **Guardo informe médico en el expte. ditital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-07-02','Ana: Los hermanos finalmente se irán en taxi. Con Cruz Roja habrá que volver a hacer gestiones, no sabemos si podrán volver a disfrutar de este servicio. *Sonia Bernabé - Asindi, me envía correo sobre presupuesto del taxi para que acudan a visitar a la familia los dos hermanos: "...El presupuesto desde Alcantara a la Roca de la Sierra serían 90€ Iva incluido (10%) por dos días (viernes y domingo), el precio final importaría 180€ Iva incluido (10%)." ··········· Se lo paso a Alberto, Jefe secc. ecca. **Éste da el OK. Se lo comunico a Sonia-Asindi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2021-07-02','Ana: Correo de Ángel, Asesor Jurídico: "Buenas, Con respecto al monitorio por el que le reclamaban a J.M. Ramos Bargón, al pago de 1.273,72 euros y al que nos opusimos, la parte actora ha desistido en su petición y se procede al archivo del procedimiento."','2');
