insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-07-02','-Amalia , facilito a Julio documento para registrar la solicitud de peticion de informes a la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2021-07-01','Ana: correo de Blanca, Directora del CRR-Plas. (direccion.crrplasencia@grupo5.net): "Buenas Ana, Siento avisarte con tan poca antelación, mañana se va M. Carmen Solana Chanclón al domicilio familiar hasta el lunes. Nosotras lo vemos beneficioso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GONZALEZ'and apellido2='SILVA'),'2021-07-02','miguel, remito a prestaciones sociales de la Direcc de Infancia y Familia y a Tesoreria General de Seguridad Social solicitud de devolución de ingresos indebidos por Embargo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-07-02','2021/07/01: Amalia (Área Social), Alberto (Área ECO). Se decide incrementar el reintegro semanal del tutelado de forma que se le entregue la totalidad de la pensión excepto una paga extra y el valor del seguro de deceso que tiene contratado. El nuevo importe del reintegro semanas del tutelado, a partir del 05/07/2021 pasará a ser de 97 €/semana. Cálculo: Ingresos: PNC: 402,80 €/mes x 14 pagas. se aparta 1 paga y por tanto el dinero del que dispone son 402,80 €/mes x 13= 5.236,4€/año - 100 € (valora anual actual del seguro de deceso) = 5.136,4 €/ 52 semanas del año= 97 €/mes aprox. Con la paga extra no utilizada de 402,80 €, el área social (AMALIA): autorizará extras que considere que son indispensables y que no tendrán nada que ver con las necesidades de gastos de bolsillo o similares del tutelado. Se renuncia al AHORRO por parte del tutelado, al menos de forma temporal. Es probable que la reinteración de EMBARGOS en la CCC del tutelado obligue a modificar esta situación en un plazo de tiempo indeterminado. Alberto/Amalia ICIAR: xfavor, modifica para el día 05/07/2021 el reintegro PERMANENTE del tutelado, que pasará a ser de 97 €/semana. ICIAR: desde la parte ECO NO SE AUTORIZARÁ NINGÚN TIPO DE REINTEGRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-07-02','Reunidos el 01/07/2021, María Teresa Gómez Martín y Amalia Díza Gonzalez, del Área Social, Miguel Fernández de Llera, del Área Jurídicia y Alberto Martín Rosete del Área Económica, acuerdan renovar (el plan de trabajo anterior se adoptó el 03/07/2019) y acordar la siguiente propuesta de trabajo con la tutelada Dª María Mercedes Pérez Pinna. Se exponen los datos económicos de la tutelada, relativos al periodoc comprendido entre 11/06/2020 y 10/06/2021: SALDO ACTUAL 15/06/2021: 135.492,39 € (SE HAN PERIDO 12.545,4 € DURANTE EL ÚLTIMO AÑO Y 27.867,61 € CON RESPECTO A HACE 2 AÑOS) SALDO (HACE 1 AÑO) 16/06/2020: 148.037,79 € (SE HAN PERDIDO 15.322,21 € CON RESPECTO AL AÑO ANTERIOR) SALDO (HACE 2 AÑOS) 03/07/2019: 163.360 € IMPORTANTE: EL DETERIORO DEL SALDO ES CONTINUADO Y EN LOS ÚLTIMOS 2 AÑOS AL MENOS SIEMPRE APARECEN IMPREVISTOS QUE REPERCUTEN ENORMEMENTE EN EL SALDO. ESTE AÑO 2021 SE HA PRODUCIDO UN EMBARGO X 6.858,3 € RELACIONADO CON LA PLUSVALÍA DE LA VENTA DE SU VIVIENDA DE BADAJOZ. INGRESOS: PENSIÓN: 892,34 €/MES X 14 MESES: 1.041,06 €/MES (INCLUIDAS P. EXTRAS). ALQUILER PISO D/ BERENGUELA (CORDOBA): 600 €/MES X 12 MESES TOTAL INGRESOS: 1.641,06 €/MES X 12 MESES (19.692,72 €/AÑO) GASTOS: REINTEGRO: 425 €/QUINCENA= 850 €/MES + 2 PAGAS EXTRAS 850= 991,66 €/MES(11.899,92 €/año): actualmente cobra 400 €/quincena y pasaría a cobrar 425 €/quincena a partir de 12/07/2021. REINTEGRO: 350 €/MES (4.200 €/año) PARA PAGAR AYUDA DOMICILIO: se trata de un acuerdo alcanzado con la tutelada y se mantendría este importe siendo ella misma quien lo gestione con plena autonomia. OTROS GASTOS (GASTOS DOMICILIADOS Y ACEPTADOS POR LA CTAEX CON CARGO A SU AHORRO): IMPOSIBLES DE CUANTIFICAR YA QUE EN SU MAYORÍA ESTÁ ASOCIADOS A CONSUMOS ALQUILER: 500 €/MES X 12 MESES (6.000 €/AÑO) LUZ: 154 €/MES X 12 MESES (1.848 €/AÑO) - IMPORTANTE: MEDIA DE LOS ÚLTIMOS 5 MESES (ULTIMO AÑO SERÍA DE 105 €/MES) AGUA: 18 €/MES X 12 MESES (216 €/AÑO) TELEFÓNICA ESPAÑA: 156 €/MES X 12 MESES (1.872 €/AÑO) - IMPORTANTE: MEDIA DE LOS ÚLTIMOS 4 MESES (ULTIMO AÑO SERÍA DE 94 €/MES) SEGURO DEKV: 7 €/MES X 12 MESES (84 €/AÑO) COMISIONES BANCARIAS: 5 €/MES (60 €/AÑO) OTROS: DURANTE EL ÚLTIMO AÑO SE OBSERVA QUE TUTELADA HA CARGADO RECIBOS SIN AUTORIZACIÓN X COMPRAS X 144 €/MES (1.728 €/AÑO) TOTAL GASTOS DOMICILIADOS: 984 €/MES X 12 MESES (11.808 €/AÑO) TOTAL GASTOS: REINTEGROS (991,66+350) + OTROS GASTOS ------- 1.341,66 + 984= 2.325,66 €/MES --- 16.099,92 + 11.808= 27.907,92 €/AÑO DIFERENCIA INGRESOS-GASTOS: (+1.641,06-2.325,66)= -684,60 €/MES NEGATIVO ------- (19.692,72-27.907,92)= -8.215,20 €/AÑO NEGATIVO CRITERIOS APLICABLES A PARTIR DE 01/07/2021: Estos datos, así como los que pudieran aportarse desde el Área Social y Jurídica, se comunicarán de forma inmediata al Juzgado, a los efectos de obtener su parecer, así como su aprobación. Por consenso de la CTAEX se acepta, en tanto en cuanto el Juzgado no se manifieste en contra o realice alguna instrucción o recomendación, que la tutelada genere unos gastos superiores a sus ingresos en cuantía similar a la del periodo mostrado. Por el Área Social se redactarán los motivos que recomiendan esta aceptación y que serán comunicados al juzgado para su estudio. Si se producen gastos de gran cuantía y cuyo pago es de obligado cumplimiento (multas, impuestos, embargos, deudas generadas...): se aceptarán dichos gastos sin que haya repercusión en los reintegros autorizados a la tutelada. Ejemplo: en el periodo estudiado ha habido un embargo por importe de 6.858,3 € RELACIONADO CON LA PLUSVALÍA DE LA VENTA DE SU VIVIENDA DE BADAJOZ. Los gastos incluidos podrán variar a lo largo del tiempo, ya que gran parte de los mismos están asociados a consumos (luz, agua, teléfono...) y, dadas las especiales características de la tutelada, su control resulta imposible. Criterios Económicos: NO SE AUTORIZARÁ NINGÚN REINTEGRO EXTRAORDINARIO MÁS ALLA DE LOS YA INDICADOS (REINTEGRO PERMANENTE Y AYUDA DOMICILIO). TUTELADA DEBERÁ HACER FRENTE A CUALQUIER GASTO CON LOS REINTEGROS PERCIBIDOS. EJEMPLOS: ROPA, CALZADO, LIBROS, SIMILARES. GIMNASIO, CLASES, SIMILARES. REPARACIONES VIVIENDA, COLCHON, MENAJE, SIMILARES. ELECTRODOMÉSTICOS, SIMILARES. GAFAS, AUDIFONOS, SIMILARES FARMACIA , FISIOTERAPIA, DENTISTA, SIMILARES EN CASO DE GENERARSE GASTOS QUE NO CUENTEN CON LA PREVIA AUTORIZACIÓN DE LA CTAEX Y CUYO ABONO SEA INELUDIBLE, ESTOS MINORARÁN EN DICHA CUANTÍA LOS REINTEGROS ASOCIADOS A LAS PAGAS EXTRAORDINARIAS DE LOS QUE LA TUTELADA DISPONE EN JUNIO Y DICIEMBRE Y SI NO FUESE SUFICIENTE CON LA TOTALIDAD DE LAS PAGAS EXTRAORDINARIAS, SE PROCEDERÁ A MINORAR EL IMPORTE DEL REINTEGRO PERMANENTE. POR LA CTAEX SE DEVOLVERÁ, DE FORMA INMEDIATA Y SIEMPRE QUE SEA POSIBLE, TODO RECIBO O DARÁ DE BAJA CUALQUIER DOMICILIACIÓN QUE SE PRODUZCA SIN CONTAR CON AUTORIZACIÓN PREVIA. TODA LA INFORMACIÓN Y DATOS CONTENIDOS EN ESTE DOCUMENTO SE PONEN EN CONOCIMIENTO (DE IGUAL FORMA QUE CON EL ACUERDO ANTERIOR) DE LA TUTELADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-07-02','TERESA El pasado 25 de Junio se visitó por primera vez a Antonia Engracia Lavado del Hoyo que reside en la calle Federico García Lorca, 6, 2ºB de Almendralejo. La visita se hizo acompañada de Antonia Morán de los SSB de la localidad. Se encontró una vivienda destrozada, con las paredes llenas de pintadas, los pocos muebles que hay están rotos o en muy mal estado y Toni, la curatelada, comenta que no sabe quién le hace tantos destrozos pero lo último ha sido que le han roto todas la sillas de la casa. Ella está convencida de que otras personas entran en su casa y le destrozan todo o le roban. Se le comenta a Antonia que no se tiene un DNI actualizado y ella accede gustosamente a enseñarnos el que tiene e incluso permite que se escanee. Se adjunta envía el DNI de Antonia escaneado. Al terminar la visita se conversa un rato con Antonia Morán de los SSB que cuenta que hace unas pocas semanas se ha realizado un subcomisión de caso sobre la curatelada y se ha decidido que había que activar el 112 para que Antonia Engracia pasara a la UHB de Mérida pero eso no se ha hecho efectivo aún y no se sabe cuándo o quién lo activará. Se hablará en las próximas semanas con el personal de salud mental de Almendralejo sobre este tema para saber en qué punto se encuentran ellos. GUARDO DNI ACTUALIZADO EN SU EXPED TRAS LA SUBCOMISION CELCEBRADA LE PREGUNTO A NURIA PANIAGUA Y ME INFORMA QUE ESTAN PENDIENTE DE QUE SE ACTIVE EL 112 PARA INGRESO EN UHB','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2021-07-02','Ana: Las compañeras de secc. ecca. me traen de banco el Alta de Terceros de Victoriana. Preparo oficio para la Gerencia del Área de Salud de Cáceres y se le entrego a Julio, CTAEX, para que dé registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-07-02','miguel, envío email a Toni de Futuex: Buenos días Toni, tras comentar con Ana las dos cuestiones del vehículo y la vivienda, necesitamos vuestra intervención en lo siguiente: 1.-En cuanto al vehículo: informe del taller que indique el diagnostico del vehículo así como el presupuesto de lo que sería su reparación, a efectos de poder justificar su retirada posterior al desguace. Por tanto una vez que nos remitáis dicho informe y comprobemos que su valor de reparación sea superior al valor del vehículo, en cuyo caso os avisaríamos para que el propio taller se encargue de llamar al desguace. 2.-En cuanto a la vivienda: necesito nos remitáis información de quién ejerce en el edificio funciones de presidente (pagos y contratación de limpieza del edificio, etc) Caso de que nadie realice dichas funciones, necesitaremos identificación de cada propietarios del edificio para ponerlo en manos de un abogado. Asimismo necesitamos actualización del presupuesto de arreglos. Cualquier duda nos dices a Ana y a mí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-05-11','-La oficina de Cajaalmendralejo envia un escrito instando a que se traslade su cuenta a otra entidad , debido a amenazas fisicas de Mercedes a los trabajadores .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-07-02','-Amalia : envio la ficha económica de Mercedes a la delegada tutelar para que se la muestre y explique en la próxima cita programada que tenga en su domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-07-05','Ana: Llamada de Sonia Bernabé - Asindi (669 602 920): ayer de nuevo surgió un incidente en la piscina, pegó a la pareja y les costó mucho separla. El desencadenante, al parecer, fue una conversación telefónica con su padre. *Cuando acudió la ambulancia del 112, le inyectaron Haloperidol, con lo cual al llegar al hptal. estaba mucho más "tranquilo", Lo han tenido en observación y ha vuelto al centro esta mañana a primera hora. *Sonia me pide que hable con las compañeras de Discapacidad, el Psiquiatra insiste en que es necesario ingreso en UHDAC o, si no es posible, cambio de centro. ··········· *Sonia me envia informe de alta del Serv. de Urgencias. En este insisten en la necesidad de ingreso en UHDAC o cambio de recurso residencial. ······························································································································································································ Llamada de Inma, tía de Aarón (686 34 23 78). Es auxiliar de enfermería en el hptal. Se quedó con Aarón esa noche, pues salió de su turno a las 22 h. Muestra su preocupación por los contínuos ingresos de Aarón en la UHB. El Psiquiatra le ha dicho que ya no puede hacer más. Ya ha enviado varios informes al SEPAD exponiendo la situación y solicitando ingreso en la UHB. Y le ha modificado 3 veces el tratamiento. ···························································································································································································· Recibimos del CADEX-CC: Citación para valoración por el EVO para el día 14 de julio a las 11:30h. *Se lo comunico a Maribel, TS Secc. Discap. Quién hablará con Soraya para que hable con Domingo, Director del CADEX, para intentar adelantar la cita. ··········· Envío citación a Sonia Bernabé-Asindi y la guardo también en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-07-05','Ana: Llamada de Sonia Bernabé - Asindi (669 602 920): Felisa el sábado volvió a ingresar en la UHB por alteraciones de conducta. El día 7 tenía declaración en el Jdo. pero no sabe cuándo le van a dar el alta. Hablará con Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GEORGE'and edp.apellido1='ANDRE'and apellido2='GRENET'),'2021-07-02','Ana: Correo de Pilar Cerrillo, TS Grupo Ciudad Jardín (calidad@grupociudadjardin.com) con copia a Ángel y Miguel, Asesores Jurídicos: "Buenos días, adjunto emito resolución de George Andre. Informarles que desde el centro nos pusimos en contacto con Fiscalía y nos derivaron al Juzgado nº 7 y ellos a ustedes. Finalmente creo que el Ayto de casar de Cáceres se hará cargo del entierro cundo fallezca el señor. Muchas gracias por su atención. Un saludo" *Guardo en el expte. digital el PDF que remite con varios documentos. ············· Contesto a Pilar que Miguel está de vacaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2021-07-05','Belén: Se habla con la TS del CSS de Mérida, Manuela (ext.24012). Mª Jesús Cruz Esperilla se encuentra en la URH, pendiente de valoración para ponerla en lista de espera para pisos tutelados. Se habla con la madre Loli (605977520) para que vaya a retirar los 120€/mes y se los haga llegar al CSS de Mérida. Se los llevará el día 7.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NURIA BELEN'and edp.apellido1='GARCIA'and apellido2='OLIVERA'),'2021-07-05','TERESA La familia de la tutelada NURIA BELEN GARCIA OLIVERA nos solicita una estancia de Nuria en el domicilio familiar del 16 al 24 de agosto. Dicho familiar es una prima del pueblo con la que ha estado otros años y ha sido una experiencia muy positiva para la tutelada. El transporte de ida y vuelta, lo realizaría en taxi, sufragando ella misma sus gastos. El regreso estaría supeditado a PCR negativa, gestionado por la familia. Los datos del familiar son: Milagros López Olivera C/ Travesía de la Verónica, 3-2º Guijo de Galistéo Telf. De contacto: 695 83 40 69 SE AUTORIZA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2021-07-05','TERESA Teresa nos indica que, si es posible, se suba el REINTEGRO PERMANENTE del tutelado hasta los 100 €/mes. Motivo: va a comenzar a trabajar Centro: Plena Inclusión Llerena (Mercedes - 924 87 10 37) • Le hacemos un REINTEGRO PUNTUAL de 50 € lo antes posible: avisa a centro. • Le hacemos el REINTEGRO PERMANENTE x 100 €/mes a partir del mes de JULIO 2021. Tere: que el centro te avise cuando se modifique la situación para modificar de nuevo el reintegro si es preceiso.','2');
