insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2021-07-05','TERESA ENVIO AUTORIZACION PARA EXCURSION CADIZ DEL 8 AL 15','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GEORGE'and edp.apellido1='ANDRE'and apellido2='GRENET'),'2021-06-17','Ana: Tras recibir llamada de Pilar Cerrillo, envío correo a Ángel y Miguel, Asesores Jurídicos CTAEX, con copia a Maite, Jefa Secc.: "...He recibido llamada Pilar Cerrillo, TS Grupo Ciudad Jardín, preguntando por este expediente: GEORGE ANDRE GRENET. Es una situación un tanto rocambolesca… entre otras cosas, hay un procedimiento penal abierto por haber sido víctima de delito patrimonial. Se acaba de aceptar el cargo de Defensor Judicial, cuando lo miré esta mañana aún no estaba creada si quiera su carpeta de expte., ahora ya sí. Acabo de leer el Decreto y no especifica nada que debamos hacer al respecto, al margen de la defensa en el procedimiento (por parte de Abogacía). Desde la Residencia me preguntan si tenemos margen de maniobra, pues el Sr. ocupa una plaza sanitaria (T1) y se encuentra en coma… tienen una deuda grande con la residencia de Hoyos (en la que ha estado ingresado previamente). En la actual ingresó ayer… Temen que se muera y no saber/poder actuar ante el sepelio (y el gasto claro, además de la deuda…). Ya le he explicado que la CTAEX a día de hoy no ostenta la Tutela."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GEORGE'and edp.apellido1='ANDRE'and apellido2='GRENET'),'2021-06-25','Ana: Tras llamada de Pilar Cerrillo, envío correo a los compañeros Jurídicos: "Tras haber hablado con Pilar Cerrillo, sobre esta Defensa Judicial, GEORGE ANDRE GRENET (Miguel ya le dio respuesta a la consulta realizada previamente), le he pedido que nos exponga las gestiones/contactos realizados hasta la fechas, pues desde el centro no saben qué más hacer y es totalmente comprensible su preocupación. ¿Sería posible que con esta información que nos detalla contactaseis/mediaseis (vosotros o a través de Abogacía General, no sé, se me escapa el modo de proceder en este caso) con Fiscalía o con el Juzgado para que dicten MEDIDAS CAUTELARES o se pronuncien de alguna manera en relación a cómo proceder en caso de fallecimiento de este señor? Pongo en copia a Pilar Cerrillo, TS Residencia del Casar en que reside a día de hoy George Andre." ····························································································································································································· Respuesta de Miguel, con copia a Pilar (calidad@grupociudadjardin.com): "Buenas tardes, como ya indiqué en el otro email, lo normal es que el centro pusiese en conocimiento del juzgado a través del Ministerio Fiscal esta situación. Por parte de la Comisión Tutelar al no estar habilitados todavía para ejercer más cargo que el defensor judicial, lo más que se puede hacer es remitir a abogacía general cualquier informe del centro (médico a ser posible y/o social) en los términos de la urgencia que el caso requiere, para que abogacía pueda acreditar ante el juzgado la situación extrema de este señor. Por tanto si nos remiten algún informe nosotros lo remitiremos a abogacía, pero si no hay informe no se podrá acreditar nada verbalmente. Los informes que obran en autos para el procedimiento de incapacitación son de hace meses y no hacen referencia a esta situación. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2021-07-01','TERESA ENVIO SOLICITUD AYUDAS PARA SOLUCION HABITACIONAL A MERCERDES TS DE CENTRO HERMNAO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-05','Ana: Correo de Cristina, Psicóloga CRR-Mérida (psicologia.crrmerida@grupo5.net): "Buenos días, Comentaros que desde ayer por la noche Damián G.H se encuentra ingresado en el hospital, está bien, acudió por su cuenta y se prevé que puedan darle el alta en las próximas 24/ 48h. Os seguimos informando," ······························································································································································································· Mi respuesta: "Buenas tardes Cristina, Gracias por informar. Entiendo que en la unidad que está ingresado Damián es la de Hospitalización Breve (Servicio de Psiquiatría). Aunque el seguimiento ya debe pasar a Amalia, pues ya ha pasado el periodo de adaptación a vuestro recurso, dado que Amalia esta semana no está, podéis seguir escribiéndome a mí ante cualquier incidencia o cuestión. Seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-07-05','TERESA ENVIO AUTORIZACION VACACIONES 9-13 DE AGOSTO A CHIPIONA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='RANGEL'and apellido2='MONROY'),'2021-07-05','TERESA ENVIO AUTORIZACION VACACIONES CHIPIONA AGOSTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-07-05','Ana: llamada de Felisi y Jesús, de nuevo solicitan dinero para ropa, abono de piscina y arreglos en la vivienda. Y dicen que ahora que ha ingresado la paga extra tendríamos que darle más dinero. Se les vuelve a explicar que ya se les da todo lo que se les puede dar, en los cálculos ya se tiene en cuenta las pagas extras, de hecho tiene una media de 460€/mes de gasto (superior a cuantía de PNC mensual).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-07-05','Ana: Conversación telefónica con María, hermana de Jonathan (624 29 37 71): comunica que el sábado ingresó en prisión, en Badajoz. Dice que llevaba una temporada muy agresivo, ha pegado a su hermano y a su madre la ha amenzado con pegarle con una figura de porcelana en la cabeza. ··················································································································································································································································· Llamo al Centro Penintenciario: me confirman que está allí. Ahora tendrá que pasar 2 semanas en el módulo de aislamiento (protocolo COVID) y la cuenta peculio es la mima de las otras ocasiones en que estuvo interno. **Acuerdo con Alberto, Jefe Secc. Ecca., que se le ingresará la misma cuantía que la última vez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2021-07-05','TERESA ENVIO DECLARACION JURADA A PETICION DE JOSE TS SSB','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2021-07-06','Belén: Se envía contrato de trabajo sellado y firmado tanto a Plena Inclusión de Llerena como a PNC informando de la actividad laboral del tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-07-06','Ana: Maribel, TS Secc. Discap. me comunica que no podrá adelantarse la cita para valoración en el CADEX. ····························································································································································································· Llamada de Sonia Bernabé, Asindi (927 390 193): Aarón no está en aislamiento como tal, pero sí que están procurando un menor contacto con el resto de residentes. No asiste a C.O., pues es donde han ocurrido la mayoría de los incidentes. Sale al patio y a pasear con profesionales. Éstos suben también a su habitación continuamente a verle y hacerle compañía. En su habitación tiene TV y sus juegos. Ayer pasó buena parte de la tarde hablando con Yaiza, su novia, tienen puesta como una pantalla de su habitación al pasillo y hablan por ahí. *Por otra parte, Yaiza se irá 15 días en verano a casa con su familia y Aarón pide irse con ella. Están tratando de disuadirle de esa idea para no darle directamente y no rotundo. ···························································································································································································· Llamada de Inma, tía de Aarón (686 34 23 78): estaba un poco molesta porque ayer por la tarde llamó a Asindi para preguntar por su sobrino y ver si podía hablar con él. Pero le atendión el coordinador, y según dice, de forma muy desagradable y sin modales le dijo que Aarón estaba encerradono y no tenía por qué darle información, qué no sabía quién era y sólo le daba información a los tutores y a su padre. *Le recordé que con Sonia el otro día habló y no hubo problema en ello y mientra se siga demostrando su buena fé hacia Aarón no se iba a poner inconvenientes por nuestra parte para que se le pudiera informar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-07-06','Ana: Llamada de Paqui López, pareja de Félix (617 025 534): El jueves tuvo cita con Maru, TS del C.S. Arroyo de la Luz, le facilitó mi contacto. Me informa que su hijo es quién compró el trastero de Félix, por tanto este tiene los documentos de la notaría. Me los facilitarán por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-06-28','Ana: Llamada de Maru, TS C.Salud Manuel Encinas y Arroyo de la Luz (927249850/62 - 52939): *Ella es quién promovió la incapacitación de Felix. Éste procede de Arroyo de la Luz, es viudo, no tiene hijos. Mantuvo una relación con una Sra. de Arroyo, Francisca, quién le atendía en el domicilio, pero ante la imposibilidad de procurarle los cuidados que necesitaba, acudión a la TS del C. Salud. Se demostraron tanto las deficiencias en el Aseo personasl como la falta de higiene en el domicilio. *Le valoraron por Dependencia, le concedieron Grado III. Presentaba un deterioro cognitivo incipiente (GDS 4-5). Pero su deseo era poder ingresar en la Res. de Arroyo de la Luz. El acuerdo fue ingresar en la Res. de Trujillo de forma temporal. **Ahora hay plazas libres en Arroyo, pero está pendiente de PIA para poder solicitar dicha plaza, pero en el EVD no pueden finalizar el procedimiento sin la Declaración de la Renta de 2019. *Le explico que se ha intentado solucionar desde aquí, pero que en dicho año al parecer vendió un trastero y sin la documentación de la compra-venta no pueden hacer la declaración de IRPF. Carecemos de información al respecto. *Como el jueves tiene cita con Francisca ("Paqui") se lo comentará, por si ella pudiera facilitárnoslo. **En cuanto a Francisca, dice que demuestra una preocupación sincera. Es la única persona que va a visitarlo y le compra ropa sin pedir el dinero de las facturas ni nada. ················ Lucía, Res. El Conquistador de Trujillo, muestra cierta reticencia por el posible interés ecco. que pueda tener Francisca, pero Maru ha visto que no es así.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-06-25','Ana: llamada de "Teresa": dice que quiere abrirse una cuenta y usar Facebook. Le indico que es una cuestión que tenemos que valorar en equipo, que debe esperar. ····· Consultaré con las áreas social y jurídica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-07-05','Ana: Correo de Ángela Bueno, Placeat (directora@placeat.org): "informarte que ya han citado a Cristofer para la intervención quirúrgica, será el lunes 19 de Julio, tiene ingreso hospitalario. Hemos contactado con una cuidadora de fines de semana para que pudiera hacer el acompañamiento, y ha aceptado. Desconozco si teneis algun protocolo al respecto, me refiero en cuanto a precio a abonar al acompañante o ciertos requisitos al respecto, de ser así hazmelo saber. Estamos en contacto. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-07-06','Ana: En relación a mi consulta a Plena Inclusión-Federación, relativa a la posible disforia de género de "Teresa", recibo la siguiente respuesta de Almudena Medina, Técnica/Sexóloga de la Federación (almudena@plenainclusionextremadura.org): "...Le he ofrecido mi apoyo a la psicóloga en varias ocasiones y he intentado darle algunas pautas de trabajo, pero no llevo un seguimiento riguroso como tal porque la psicóloga quiere trabajarlo ella. De todas formas esta persona está en el grupo de apoyo LGBTI, así es que espero que a través de él podamos trabajar cositas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-06','Ana: Correo de Cristina Román, Psicóloga del CRR-Mérida (psicologia.crrmerida@grupo5.net): "Buenos días Ana, Si, efectivamente se encuentra en UHB, aunque él comentó que iba a urgencias porque sentía que tenía febrícula. He intentado esta mañana hablar con el Dr que está llevando su caso pero no ha sido posible por el momento. Seguiremos intentándolo,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-07-05','Ana: Correo de Nuria, TS de La Roda (nrarenas@laroda.es): "Buenos días Ana; Lo último que sabemos de Javier, fue lo que pusimos en el escrito, ya que desde ese día no lo hemos vuelto a ver, ni hemos tenido constancia de que estuviese por La Roda. Si volviese a aparecer, te informo. Buen día Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2021-07-06','Belén. Se envía consentimiento informado para colonoscopia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='RODRIGUEZ'and apellido2='CACERES'),'2021-06-04','Buenos dias , Aprobado los audífonos , la seccion eco se pondrá en contacto con la empresa para concretar la forma de pago , se va a financiar . Podéis pedir cita para que Emilia . Un saludo','2');
