insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2021-07-07','Belén: se adjunta por correo electrónico (cf-caceres@cruzblanca.org) Informe Social realizado por el centro sellado y firmado. También se envía el original por correo postal.','2');
