insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-07-07','Ana: correo de Sonia Bernabé, Asindi, ayer por la tarde: "Hola Ana, quería informarte que Aaron por la mañana nos ha dicho que está bien teniendo menos ruido, y la habitación para él solo con sus objetos personales que no se los toca nadie. Ha salido un rato a dar un paseo por el patio con una cuidadora. Si llama su familia se le pasará la llamada, y, creemos que si solicitan salida la familia para dar un paseo con él por el pueblo pueden hacerlo. El equipo técnico está elaborando material para él y viendo la intervención en esta nueva situación. Lo que intentamos es prevenir otra agresión a su novia o a otros compañeros por lo que las relaciones con otros residentes son muy controladas, y la única forma que tenemos es estando un poco separado en esa zona, pero atendido igualmente por todo el equipo. Sus compañeros, excepto su novia, no quieren tener trato con él. Es una situación complicada y la veremos más detenidamente con el gerente en estos días. Estamos organizando el viaje al CADEX el día 14. Quería comentarte la posibilidad de que se comprara una televisión pequeña para la habitación? Ahora tiene una del centro para que la estancia sea más llevadera y le viene bien, pero podemos necesitarla para otra dependencia. ¿Lo hablo con la sección económica? Podemos ver presupuestos y que valoren si puede ser. Estamos en contacto. Un saludo," ··············· Les pido que envíen presupuesto para la compra de la TV','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-07-07','Ana: Begoña, directora de la Res. Santiago de Alcántara, me remite por mail (resisantiago@hotmail.com), escaneado, el DNI nuevo de Florencia. ············ *Se lo remito a Icíar, secc. ecca. *Le abrirán nueva cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-07-05','Ana: Correo de Blanca Conejero, Directora CRR-Plas. (direccion.crrplasencia@grupo5.net): "Por otro lado Flora Guitierrez, tiene contratado con una empresa de ayuda a domicilio dos dias a la semana, le gustaria poder contratar un día más, a nosotras nos parece que le beneficiaría." ············· Paso a Alberto, jefe secc. ecca. la consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-07-07','Ana: Envío correo a Blanca Conejero, directora del CRR-Plas.: "Buenos días Blanca, Espero que sigáis bien. En relación a la ampliación de SAD de Flora Gutiérrez García, esta es la respuesta que me da Alberto, Jefe Secc. Económica: “INCREMENTO COSTE AYUDA DOMICILIO: OK a pasar de 2 a 3 días. Se supone que coste estará en torno a 198 €/mes. Ana, xfavor, indícales que a partir de ahora pasen el recibo a la CCC de sólo Flora. El CCC es ES54 2048 1086 1934 0008 1420” ¿Podríais por favor confirmar que la estimación del precio es correcta? Y por otra parte, ¿podríais encargaros también de la gestión del cambio de cuenta para el cobro? En su defecto, por favor, facilitarme los datos de contacto de la empresa para poder hacerlo yo. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2021-07-05','TERESA Primero informarte de que Tomás y los otros dos compañeros, ya han encontrado piso de alquiler. Ayer firmaron el contrato y les han entregado las llaves, por lo que Tomás terminará de cambiar sus cosas hoy y ya hará noche en la nueva casa. La dirección nueva es: C/ Damián Téllez la Fuente Nº4, 2ºD, de Badajoz. Por otro lado, hoy hemos obtenido un certificado de prestaciones para adjuntarlo al informe de la subvención y nos hemos llevado la sorpresa de que ya aparece la prestación por orfandad, se la han concedido desde el 4 de febrero de 2021, no sé exactamente qué día del mes harán el ingreso, pero me imagino que en este mes o el siguiente le pagarían los atrasos. No sé si hay que hacer más cambios respecto a la PNC o ya lo que cobraría serían la PNC y Orfandad, en total de 613,60€ al mes. No sé si él seguirá disponiendo de los 400€ o de los 600€, para explicarle a él. El alquiler a Tomás le costará 125€. En el mes de julio haremos con él un control de gastos para saber el gasto real que le va a suponer estar en el piso y volvería a escribirte para contarte. (En agosto me voy de vacaciones, por lo que intentaré tenerlo listo a finales de éste mes).','2');
