insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-07-07','Ana: Tras recibir llamada de Ángela, Directora Placeat (927 421 950), envío correo a Alberto, Jefe Secc. Ecca.: "Hola de nuevo Alberto, Me confirman que Cristofer Montero Vázquez necesitará acompañamiento las 24 horas, por sus características y por el protocolo de entradas y salidas del hospital de Plasencia. El precio que han acordado con la Auxiliar es de 7€/h independientemente de que sea un horario u otro. Y en cuanto a los días de ingresos, por las características de la intervención quirúrgica, que no es muy complicada, no creemos que sean más de 2-3 días. Seguimos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GONZALEZ'and apellido2='SILVA'),'2021-07-07','Belén: se envía modelo para alta de terceros a PNC para ingreso en la nueva cuenta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-07-07','TERESA EMAIL ANTONIA SSB ALMENDRALEJO Buenas tardes , no consigo contactar telefonicamente . Me imagino que sabreis por la Subcomisión de Salud Mental que Dña. Antonia Engracia Lavado del Hoyo se encuentra ingresada en la unidad de breve estancia del hospital de Merida, tras haberse activado el protocolo terapeutico que dicho órgano estableció para la interesada. La vivienda en la que esta reside, no reúne condiciones de habitabilidad ni salubridad en estos momentos por lo que se precisa la intervención de una empresa de limpieza que mejore estos aspectos , no solo para que cuando su retorno se produzca, las condiciones de la vivienda sean aceptables sino también para no causar más daños a terceros (vecinos) , al manifestar estos que se desprenden malos olores, existen cucarachas...y en este sentido versan mis dudas. En primer lugar ¿teneis experiencia de haber tenido que entrar en un domicilio sin que su propietaria o inquilina estuviera presente? y en segundo lugar ¿los gastos que conlleven la limpieza , seran asumidos por la titular a traves de la comisión , no ? Si puedes me respondes a estas cuestiones o hablamos por teléfono como tu prefieras. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-07-07','Ana: Recibo correo de Elisabeth, la hija Mª Rosario (isacini1970@gmail.com) con imágenes del Pasaporte y del Permiso de Conducir Francés. **Como en ninguna de las 2 imágenes aparece el nº de identificación le llamo y envío tamibén correo, solicitando que nos envíe imágenes de todas las páginas en que aparezcan datos. *Dice que le será difícil acudir a algún sitio para escanearlo. ·············· Por la tarde recibo nuevo correo de Elisabeth, hija Mª Rosario, con imagen de la página del pasaporte en que aparece el número de identificación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2021-07-07','Ana: Llamada de Cruz C. Merino, TS Mancomunidad TajoSalor, UTS. Alcántara (927 12 28 33): ella es quién inición procedimiento de incapacitación. Le ha solicitado Valoración de Dependencia. Está residiendo en la Residencia de Alcántara, de titularidad municipal. *Las deudas que tenía en Diputación, ya las ha saldado. *Presenta Ludopatía, en este sentido el confinamiento le ha venido muy bien. **En cuanto pueda, nos enviará informe social actualizado junto con el que envió a Fiscalía para su incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-07-07','TERESA 2021/07/06: FICHA CON NUEVO ALQUILER ZAFRA Y GASTOS MANUTENCIÓN: - NUEVO ALQUILER: 250 €/MES. - CONSUMOS: SE DESCONOCEN: A EFECTOS DE ESTA FICHA SE SIMULAN 40 €/MES (LUZ, AGUA, GAS) - REINTEGRO: 175 €/QUINCENA (350 €/MES) - PROHIBIDO CUALQUIER EXTRA. - COMIDA: 5,5 €/DÍA (170 €/MES Total: 810 €/mes INGRESOS: con pagas extras prorrateadas: 689,70 €x14/12= 804,65 €/mes GASTOS mayores que INGRESOS: y eso sin tener en cuenta ningún tipo de extra, ni las comisiones bancarias, Y SIEMPRE QUE LOS CONSUMOS NO SUPEREN LOS 40 €/MES!!! En mi opinión, con estos números NO es viable...tengamos en cuenta el desembolso que vamos a realizar para soventar el problema del piso anterior. Creo que tiene un reintegro EXCESIVO: habla con FUTUES, si te parece y mirad de donde podeis recortar.','2');
