insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2021-07-09','TERESA Ayer miércoles 7 de julio realizamos seguimiento presencial en su localidad, para la retirada de dinero quincenal, compra de necesidades básicas y acompañamiento al CEDEX de Castuera para la consulta de medicina y psicología. Cuando nos encontramos con él, lo primero que nos dice que su actual casero (Jesús Cadena) en la tarde de ayer le dijo que ya no tenía que irse del domicilio, que finalmente se podía quedar allí porque no iba a vender el piso. Hoy hemos comprobamos esta información por teléfono y nos afirma todo lo que nos comunicó el tutelado. Desde el programa de apoyo social comunitario recomendamos que se haga un contrato de alquiler, para garantizar que no cambie de opinión en un corto periodo de tiempo. La persona de contacto es Jesús Cadenas: 625 49 42 48. Lo del nuevo piso, por lo tanto no sigue para adelante. Pedro Tomás ha estado muy inestable por el traslado de domicilio y ante el cambio de decisión de su casero quiere seguir residiendo en la vivienda actual, es decir, no seguir con los trámites que se estaban gestionando con la inmobiliaria para irse a otro piso. Otra de las cuestiones que nos cuenta en el seguimiento, es que el día anterior tuvo un altercado con la guardia civil, indicando que lo confundieron con un ladrón, pero comprobamos que nos miente en los hechos, ya que Antonio (trabajador social de los servicios sociales de base) nos facilita el informe de hechos redactado por la guardia civil donde indica que intentó conseguir alcohol en un bazar de la localidad a cambio de entregar una navaja, la cual fue requisada por la guardia civil. En uno de los últimos controles de orina ha dado positivo en cocaína y alcohol, desde CEDEX y con el visto bueno de Pedro Tomás van a dar este mes de margen siguiendo con el tratamiento ambulatorio, hasta la próxima consulta con el médico el día 19 de agosto. Si el consumo persiste se derivará para ser ingresado en una unidad de desintoxicación. El médico le tiene prescrito tratamiento para la deshabituación del alcohol, él indica que lo toma correctamente, pero desde el programa no podemos corroborar este dato.','2');
