insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-07-09','Ana: Tras hablarlo con Ángel, Asesor Jurídico, decidimos que comunicará a Fiscalía la situación en la vive, habiendo sido nombrada la CTAEX, Curadora exclusivamente para la administración de bienes y patrimonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-09','Ana: Envío correo a Jorge Morán Pilo, Dependencia (jorge.moran@salud-juntaex.es): "Buenas tardes Jorge, ¿Qué tal? Hemos detectado que JOSÉ MANUEL MORENO CARLOS, curatelado por la CTAEX, continúa percibiendo la prestación vinculada al servicio de SAD, pero a fecha de 17 de agosto de 2020, ingresó en el CRR de Plasencia. ¿Cómo tenemos que hacer para comunicarlo y se proceda a la extinción del derecho a la prestación? ¿Es suficiente con este correo?. Ya me dices cuando puedas, pues habrá que devolver los cobros indebidos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-07-09','Ana: Pregunto a Jorge Morán por mail (jorge.moran@salud-juntaex.es) por la orden de pago pendiente para la devolución de los cobros indebidos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2021-07-09','TERESA Como te comenté, se ha valorado el alta de Javier para mediados de septiembre, principios de octubre, pero vamos a ir haciendo aproximaciones a la independencia total. Irá en un principio un rato por las mañanas, después a comer, así se irá incrementando el tiempo, hasta que termine durmiendo solo y pasando el día completo, para ver cómo se adapta. Por ese motivo, me ha pedido que os informe de que va a ir viendo pisos por Zafra, para tenerlo disponible a principios o mediados de agosto. Una vez tenga el piso, a parte de informarte a ti, informaré a gestión económica para que se hagan los cambios oportunos para los pagos de alquiler y mensualidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-07-12','Ana: Respuesta de Esther, Administración - Res. Ntra. Sra. de la Luz de Malpartida de Plasencia (administracion@residencialaluz.com): "Buenos días, en principio no hay ningún problema para que le acompañen, se lo hago saber a la directora y les informamos al respecto Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-12','Ana: Respuesta de Jorge Morán, Jefe de Secc. Prestac. Eccas. - UGRDS (jorge.moran@salud-juntaex.es): "Buenos días Ana, Acabo de dar de baja la prestación de José Manuel Moreno Carlos, aunque percibirá el mensual de julio pues ya tenemos hecha la nómina. El mes que viene ya nos salta el pago indebido y me dices donde te lo mando o si lo recoges aquí." ············ Acordamos que bajaré a recogerlo en cuanto me avise.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-07-12','Ana: Respuesta de Jorge Morán, Jefe de Secc. Prestac. Eccas. - UGRDS (jorge.moran@salud-juntaex.es): "Respecto a Saturnino puedo sacar el pago indebido hoy. ¿Te aviso cuando lo tenga firmado y pasas a por el? Son 3.831,86€" ······· En cuanto al fraccionamiento: "Se puede fraccionar una vez enviemos la resolución. Ahora generamos una propuesta de pago indebido, y aproxidamente en tres meses sacamos la resolución. En este caso lo podemos tramitar con mayor celeridad, y generar la resolución en un mes. Una vez notifiquemos la resolución, te doy el modelo para solicitar el fraccionamiento y lo registras, me lo das y se lo enviamos a Hacienda, que es quién tramita los fraccionamientos ( cobran algo de intereses) Te aviso en cuanto tenga la propuesta" ·········· *Bajo a por la propuesta de pago. - Se la pasaré a Alberto mañana, hoy no está.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-07-03','Con fecha 03/07/2021, ha ingresado en este Centro Penitenciario. Un saludo Ángela Pescador Vega Trabajadora Social Centro Penitenciario de Badajoz C/Carretera de Olivenza km 7,300. C.P. 06011. Badajoz Telf.: 924 289117 Fax: 924 289113 Angela.Pescador@dgip.mir.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2021-07-12','Buenas , sería conveniente mantener la misma situación , viven en una pedanía de Badajoz y no tienen transporte , se les facilita así que puedan hacer la retirada de efectivo . Para evitar Nº rojos en cuenta , no sé si hay algún gasto que se pudiera prescindir , guardar alguna de las extras o reducir en unos euros la mensualidad. Seguimos .','2');
