insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2021-07-12','Belén: se manda correo electrónico a Lorenzo (lorenzogarcia1950@hotmail.com) solicitando libro de familia o certificado de defunción de la madre. También se le pide información sobre el pago de facturas de la vivienda donde reside el tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-07-12','Ana: Envío correo a Toni-Futuex, en relación al correo enviado por una vecina al ctutelar@ (guardado en expte.): "Buenos días Toni, ¿qué tal estáis? En relación a Martín Domínguez Palencia, Curatela Económica, te facilito esta otra dirección, a ver si aquí hay más suerte: Calle Huaina Capac 1 3E Cáceres. Nos ha escrito la vecina de abajo pues le están produciendo desperfectos en su vivienda, al parecer tiene la bañera averiada y algunas tuberías le esta calando los techos y produciendo goteras. A ver si es posible contactar con él en esta ocasión y ya de paso, que algún profesional vaya a ver el domicilio y aporte presupuesto. Ya me decís. Gracias y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-07-03','Ana: Recibimos correo de una vecina de Martín (mariangeles.reyes@hotmail.es) al ctutelar@: "El señor Martín con domicilio en Calle Huaina Capac 1 3E Cáceres está causando graves desperfectos en nuestra vivienda, que está bajo la suya. Tiene la bañera averiada y algunas tuberías y está calando nuestros techos; llegando a caer agua en nuestro suelo. Pone música a altas horas de la madrugada a todo volumen, mueve los muebles, etc. Como está tutelado por la Junta de Extremadura, necesito que pongáis solución a estos problemas ya que no puedo arreglar las goteras ya que primero deben arreglarse el origen que las provoca y esto debe ser con vuestro consentimiento, es decir, del tutor que tiene asignado. Esperando que me atiendan lo antes posible, atentamente María de los Ángeles Reyes Gómez. 679 074 618 les dejo mi número de contacto. Estoy esperando su respuesta ya que es un tema que me preocupa y necesito arreglar mi vivienda."','2');
