insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-07-12','Buenos días , la parte económica está sin personal y sólo se gestionan urgencias , si puede del dinero de la asignación pagarse el viaje perfecto si no tendrá que esperar. Todas sus peticiones tienen que ser gestionadas de acuerdo a nuestro protocolo establecido , sólo atenderemos demandas que vengan directamente solicitadas desde el CRR . A la delegada tutelar se lo puede contar , pero la solicitud sólo la tramitaré gestionada con vosotros . Creo que es lo más eficiente en este caso , si a tí te parece bien claro. Ya ha llamado a la CTAEX varias veces con el mismo tema , se le explica siempre el mismo procedimiento pero sigue sin aceptarlo. Sus peticiones vendrán canalizadas a través del centro . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='CEDILLO'),'2021-07-12','Este correo símplemente es para que tengas información ECO actualizada de esta tutelada a día de hoy: Saldo 08/07/2021: 130.728,25 € (habría que abonar entierro x no contar con seguro deceso x edad: -3.000 € aprox.) Diferencial anual: -8.700 €/año (gastos muy superiores a ingresos sin que haya existido ningún extra) Evolución: con este saldo, restándole el seguro deceso aprox. y con este diferencial de gasto ((130.728,25-3000))/8.700), aproximadamente tendríamos para 14 años aprox. y siempre que NO aparezcan gastos EXTRAS. Edad (1933): 87 años aprox.','2');
