insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-12','Ana: José Manuel ha dejado de percibir el subsidio por desempleo. / Tiene Grado I de Dependencia reconocido y 54% de Discapacidad. ························ Llamo al SEPE de Plasencia (927 74 89 65), le pasarán la consulta al Jefe de Prestaciones. ··············· Recibo llamda del Jefe de Prestaciones: Podemos solicitar la renocación online, en la oficina virtual del SEPE. Los meses que no ha percibido no los podra percibir. Sería un año a partir de la nueva solicitud. **Como me falta algunos datos no puedo realizar hoy la solicitud.','2');
