insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-07-13','Ana: María Álvarez Feria, TS SSASB (tsocial7@mancomunidadsierrademontanchez.es), me remite las fotos a color de las distintas visitas al domicilio. - Se las paso a Ángel, Asesor Jurídico quien las enviará a Abogacía. ······························································································································································································ Envío correo a Alberto, jefe secc. ecca.: "Buenas Alberto, Teníamos pendiente establecer asignación periódica a Antonio Hidalgo Romo, pero aún nadie me ha pasado propuesta de presupuesto (aún habiéndolo pedido expresamente) y el propio tutelado, aunque le dieron mi número a tal fin antes de salir de prisión, no me ha llamado para esto ni para ninguna otra cosa.. Yo no tengo cómo contactar con él directamente. Desde Futuex si se le visita. Se ha comunicado ya al Juzgado la grave situación (vivienda inhabitable entre otras cosas preocupantes) avalada por informes de Futues y de los Servicios Sociales. Pero mientras tanto, hay que concederle asignación y en mi opinión, más importante aún, contratar un cáterin. **Te paso presupuesto de la residencia de mayores con la que se contrataría, no hay más opciones en el pueblo. Si me das el ok me encargo de contratarlo y, así y todo, habría que mirar si se le puede dar algo más a la semana. Ya me dices. Seguimos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-07-17','Ana: Correo de María González Palomo, TS Autismo Sur (teayudamos@autismosur.es): "Buenos días que tal??? Ana... la situación de la PNC sigue igual y tiene muchas necesidades de ropa de verano, ya que llego en invierno.... y ropa interior... te lo adjunto... Además de los pagos que están acumulados. De verdad, la situaciones hasta ahora la hemos sostenido, pero se nos hace cuesta arriba... cada vez tenemos más trampas y complicaciones. Muchas gracias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-13','Ana: Tras consultarlo ayer en el SEPE, cumplimento telemáticamente las Pre-solicitud de Prestación Individual para mayores de 52 del SEPE. *Dejó de percibirla porque no realizó Declaración Anual en febrero (desonocíamos este plazo y no recibimos notificación). Se podrá reactivar para otro año a partir de ahora, pero los meses que no ha percibido ya no los percibirá. ································································································································································································ Tal y como me indica Soraya Masa, Jefa UGPPAA: Intento contactar con Placido Alejandre "Tete", Responsable de T3 el la Gerencia Territorial de CC, por teléfono. Como no obtengo respuesta le envío un correo (placido.alejandreb@salud-juntaex.es) pidiendo que se ponga en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-07-13','Ana: Recibimos carta de HC-Energía, se ha procedido a dar la baja del contrato con fecha de efectos: 02/07/21. ······ Se lo comunico a Alberto, Jefe de secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-07-14','TERESA RECIBO LLAMADA DE LA TS DEL SSB DE DON BENITO, ME COMENTA QUE EMILIA QUIERE QUE PIDAMOS LA AMPLIACION DE LA INCAPCIDAD PARA QUE ESTE TUTELADA EN VEZ DE CURATELADA, DICE QUE ASI NO ABANDONARA EL CRR COMENTA QUE HA DENUNCIADO A SU PAREJA POR MALTRATO, EMILIA YA PUSO UNA DENUNCIA ANTERIORMENTE A OTRA PAREJA QUE TUVO IBAR A SER DERIVADA A LA CASA DE LA MUJER PERO NO CUMPLE PERFIL POR TERNER ENFERMEDAD MENTAL LE EXPLICO QUE LA SOLUCION NO ESTA EN LA TUTELA Y QUE ADEMAS A PARTIR DE SEPTIEMBRE ESTA FIGURA DESAPERECE CON UNA NUEVA LEGISLACION QUE ENTRA EN VIGOR EN SEPBRE ACORDAMOS ME ENVIE INFORME SOCIAL PARA COMUNIAR LA SITUACION AL JUZGADO AUNQUE LE INSISTO QUE ES UNA CURATELA DE LA EFERA PATRIMONIAL Y QUE DESDE LA CTAEX NO PODEMOS INTERVENIR EN MAS ASUNTOS','2');
