insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-07-14','Ana: Envío correo a Julián - COCEMFE (gerencia@cocemfecaceres.org): "Buenos días Julián, En relación a las vacaciones de Tomas Esteban Iglesias, confirmarte que se ha dado el visto bueno al presupuesto de vacaciones con el acompañamiento de Asistente-Auxiliar de COCEMFE: “OK a presupuesto de COCEMFE de 990 € en concepto coste 7 días vacaciones que incluye cuidador y alojamiento (tutelado y cuidador) + 200 € en concepto gastos personales. TOTAL: 1.190 €” Cuando puedas, dime cómo hay que proceder al abono, si hay que ingresar ya todo, sólo lo del hotel y a su regreso lo del cuidador, o cómo y a qué número de cuenta hay que hacer la transferencia. Gracias y buen día."','2');
