insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-14','Ana: se envía por mail el contrato de amdisión a centro residencial. *Paso a Julio, aux. admvo. el original con el oficio para que lo remita por correo certificado. ································································································································································································ Llamo a Tete (Plácido Alejandre), Responsable de T3 en Gerencia Territorial CC (927 004 261): Dada la situación de José Manuel (a día de hoy no tiene ingresos). Se puede saltar la lista de espera por situación de emergencia. **Ahora mismo no hay plazas, pero por este procedimiento en cuanto quede una vacante se la asignarán a él. **Pero tendré que emitir y enviarles un informe social en que se haga constar la situación de emergencia social por falta de recursos económicos.','2');
