insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-07-14','miguel, voy a la citación en SCACE Mérida del procedimiento del jzdo nº4 de Plasencia por el procedimiento DPA 191/2020, donde nombran sobre la marcha un abogado de Oficio Moises Palacios Coetano tlfno 927-678114. La toman declaración y al haber pasado hace meses por el Forense, nos citan para el día 26-7-21 para que abogado y Ministerio Fiscal intenten llegar a un acuerdo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-07-14','miguel, recibo dos emails del abogado Jorge Calvo: Buenas tardes, De conformidad con lo acordado adjunto condiciones del despacho. Doc Hoja Encargo: Encargo específico del servicio. Condiciones generales: Son las condiciones que solicito me firme (en todas sus hojas) cualquier cliente a fin de que tenga conocimiento del tratamiento de sus datos y de las condiciones y forma de trabajar del despacho. P Proc: presupuesto aproximado de procurador (Dª. CRISTINA SOTO) a quien se le deberá hacer los oportunos poderes para pleito y poder representar a Dª. Carmen Leal. Quedo a la espera de sus noticias y a vuestra disposición para aclarar cualquier duda. ***************************************************** Buenas tardes, Según lo acordado, adjunto comprobante de envío de Burofax. Un saludo','2');
