insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-05','Ana: Correo de Blanca, Directora del CRR-Plas. (direccion.crrplasencia@grupo5.net): "José Manuel Moreno Carlos, el viernes pasado sufrió un accidente en el que fue atropellado por un coche. Se ha roto la muñeca de una mano y parece que el hombro contrario. Se encuentra ingresado en el hospital a la espera de que mañaa le operen. Tiene una curatela y queriamos consultaros la posibilidad de poder contratar a una persona que le ayude en la ducha cuando venga ya que va a taner los dosn brazos inmovilizados." ················ Se lo envío a Alberto para que pueda valorar las posibilidades económicas.','2');
