insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-09','Ana: Hablo con Soraya, Jefa UGPPA: a José Manuel le van a dar el alta hoy mismo en el hptal. Le han pasado la herramienta T3 y ha dado 20 puntos. Puede acceder a plaza sociosanitaria T3, pero no hay plazas disponibles y ha quedado en lista de espera. ········· Desde CRR plantean ingreso en plaza privada en la Residencia Ciudad Jardín de Plasencia hasta que pueda acceder a Plaza pública. ································································································································································································ Llamo a la Res. Ciudad Jardín (927 80 51 01), me pasan con Cristina, Directora. José Manuel podría ingresar con la PCR negativa. El precio del fin de semana sería 150 €. Si estuviera más tiempo, 60€/día. ··········· Alberto Jefe Secc. da OK, para unos días. ·········· Soraya hablará con Blanca, Directora CRR, para que organicen el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='CUEVAS'and apellido2='MOYANO'),'2021-07-14','-Amalia : Ingresado en Centro Residencial de Felipe Trigo . Es de la zona de Tere pero yo haré el plan de intervención inicial. Presenta abuso de alcohol , trastorno delirante . Han solicitado cambio de residencia a la de su pueblo , está el primero en lista . Escribo a la sección Eco : Me traslada la TS que no está incluido en su cuenta Jose Vicente , aparece como único titular , de momento el banco no ha puesto pegas . Hay que incluir al Gerente en su cuenta y enviar al centro la autorización para que puedan hacer la retirada del dinero . No es prioriatario de momento , pero tampoco se puede dejar mucho tiempo . Seguimos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-07-14','Ana: Nuevo correo de Toni, TS de la Res. con informe médico: "...dado el estado general del paciente, se desestima tratamiento específico para su enfermedad, recomendándose valoración y seguimiento por la Unidad de Cuidado Paliativos" ···· Guardo informe en el expte.','1');
