insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-07-14','Ana: Llamada de Mamen, TS de HSPA-CC: Javier está ingresado en al UHB, activaron el 112 en Trujillo. *No tienen documentación. *Ha hablado con la Policía Nacional y le han dicho que desde la CTAEX como Representante Legal, podemos pedir un CERTIFICADO DE TITULARIDAD DE DNI. *Adjuntar Fotocopia de la Sentencia Judicial de Incapacitación, Aceptación del cargo y DNI del Presidente de la CTAEX. **El Psiquiatra de referencia es el Dr. Javier Jerez. En principio permanecerá ingresado 3 semanas en UHB. La idea es, si evoluciona bien, derivarlo a CRR, en ppio a plaza privada (Grupo 5 - Mérida) hasta que le concedan plaza pública. ······················· Tal y como acordamos, envío sentencia de incapacitación a Mamen, TS HSPA (maria.alvarezs@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-07-15','Ana: En cuanto a sus ingresos, aún no hemos recibido Certificados del INSS (solicitados de oficio), según el informe del SSASB, percibía una pensión de Orfandad más PFHC. *No obstante, según los movimientos bancarios, le ingresan en su cuenta una tercera pensión de 929,20 €. ············ *Llamo a control de pensiones INSS de la Seg.Soc.-CC (927 62 00 49 / 927 62 00 62): Miguel Cillán, me informa de que Javier percibe PFHC, P. Orfandad Simple y Pensión de Orfandad absoluta con el complemento de viudedad que percibía el padre por la madre fallecida. *Todas compatibles. ····· Envío correo a Miguel (angel-miguel.cillan@seg-social.es): "Buenos días Miguel, Tal y como hemos acordado, envío oficio-solicitud registrado en SIREX a fecha de 30 de marzo de 2020, relativo a Javier Agudo Cumplido, tutelado por la CTAEX. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-07-14','Ana: Recién aceptado el cargo de Tutor, desde el Ayto. de Torre de Don Miguel, me llama Carlos. Ha recibido solicitud de Certificado de Empadronamiento (el que se solicita de oficio desde la CTAEX) pero Ángeles aún no está empadronada allí. Me enviará al mail el modelo de Solicitud para devolvérselo firmado por el representante legal junto con el DNI de Ángeles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-07-15','Ana: Envío a Estrella, secc. ecca., la factura del arreglo de la persiana para su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2021-07-15','Ana: Recibo correo de Toni-Futuex, con información sobre una reclamación que le hace la AGENCIA TRIBUTARIA a José por una deuda que tienen los dueños de la pensión en que reside. *Se lo paso a Alberto, jefe secc. ecca., y a los Asesores Jurídicos. ··· Guardo correo con documentos en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-07-14','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería comentarte que Aaron ha estado hoy en el Cadex y, a la compañera le han indicado que probablemente le concedan el cambio de perfil. El en la situación que está teniendo menos contacto con los compañeros se muestra,en general más tranquilo. Su padre también lo nota más tranquilo porque no tiene esa relación con los demás. Aunque él pregunta por qué no come junto a los demás,... Intentamos explicarle la situación. El padre ya está mejor de salud y me ha preguntado si puede ir Aaron algún fin de semana a casa. Mañana lo veré con la Psicóloga pero creo que si es un periodo corto le puede venir bien. No puede ser largo porque no tienen control al administrar la medicación y en casa le dan permiso para hacer lo que quiera."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-07-14','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Con los hermanos Hernández Castaño, esperaremos un poco y en agosto, según como esté la situación que vayan otra vez a casa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-07-14','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Con los hermanos Hernández Castaño, esperaremos un poco y en agosto, según como esté la situación que vayan otra vez a casa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-07-15','Belén. Según informe social el tutelado vive con su madre (anteriomente su tutora, mala relación)en una vivienda de alquiler por la que pagan 400€. La madre administra la pensión de Incapacidad absoluta (10€ diarios). Tiene 3 hermanos con los que mantiene buena relación. Pasa bastante tiempo en el hogar del pensionista. Conduce y a la madre le parece un riesgo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2021-07-15','BAJA DE EXPTE. Se procede a la baja del expte. No se ha seguido el protocolo establecido. No se ha remitido a Abogacía para el correspondiente reparto (Miguel recibió la notificación del nombramiento de defensor judicial).*************************** Se procede a la baja de todo rastro de esta defensa judicial. Se remitirá la documentación que se posee a Abogacía: Exhorto nombramiento, escrito fiscalía y cédula notificación para emplazamiento (estas actuaciones las realiza JULIO).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-14','miguel, llegan dos emails de Damian: Como va el nicho de mi madre que sino la echa a lafosa común y el piso el1 deagosto tie e que estar libre yo quiero hablar personalmente que me llame por teléfono esta mañana gracias uncordial saludo la terapeuta esta de vacaciones llameme usted a mi gracias muy señornuestro **************************************************** Necesito ayuda por favor para salir donde estoy y volver con mi familia a mi casa a malaga *********************************************************** Escribo a la Abogada Rocio Gracian: Buenos días, me pregunta Damian que cómo van las gestiones del inquilino. Me indica que el 1-8-21 tiene que haber desalojado el piso. Cuando puedas infórmame. **************************************************** Contestación de la Abogada: Buenos días Miguel, Estoy en permanente contacto con el arrendatario vía Whatsapp para intentar solucionar todo amistosamente y que deje la vivienda el día 1. Sigo pidiéndole las facturas y los recibos de pago que dice que ha realizado en todo este tiempo tanto a Damián como por reparaciones y reformas a la casa. El siempre responde que las está buscando y recopilando. De todas formas, como el tema de la deuda ya hablamos que iba a ser mejor no tocarlo por las irregularidades que se han producido con la subvención, voy a usar esa estrategia para hacer ver al arrendatario, cuando se aproxime el día, que perdonamos la deuda y que entregue la vivienda puntualmente. Si llegado el día no abandona tendremos que interponer demanda de desahucio. ************************************************* Remito email de la abogada a Damian y Alicia: Buenos días Damian y Alicia, adjunto contestación de la abogada en relación al alquiler de la vivienda. *************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-15','miguel, además de renviar el email que me manda la abogada en relación al inquilino, le envío otro email en relación al nicho donde desde aqui no podemos gestionarlo a él y a su prima Alicia: Buenos días Damián, conforme sentencia judicial somos curadores tuyo no de familiares por lo que las gestiones relacionadas con el nicho no podemos gestionarlas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-15','miguel, quedo con el abogado de la otra parte para mañana Carlos Jurado quién dice que podrá acreditarnos que la cuenta actual se corresponde con la antigua. Al tiempo solicito catastro y nota simple al registro de la propiedad del padre desaparecido ya que en la ejecución del divorcio contencioso de la madre del curatelado (casada en 2º nupcias con el padre desaparecido)se menciona la reclamación del pago de unas cantidades pero no se detallan los conceptos con lo que no sambemos si son únicamente derechos de pensión compensatorias, o también derecho de manutención del curatelado, unido a un préstamo hipotecario (no identificado), motivo por el que solicito certificado (negativo en catastro del padre) y nota simple donde aparece titular de una finca en Trujillo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-07-15','Enviamos a Fiscalía estado en el que se encuentra la vivienda de Antonio, para su conocimiento, a los efectos que adopten las medidas que consideren más oportunas, entra las que pudiera ser la de internamiento involuntario, puesto que nosotros no podemos solicitarlo.','2');
