insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-07-15','TERESA Te adjunto el recibo del viaje que finalmente hicieron ayer Bea y la cuidadora a Trujillo para visitar a la hija de Bea. Quedamos con la abuela en hacer la visita en el patio, porque allí tienen sombra y una piscina pequeña, pero finalmente la abuela dijo que salir al parque porque no hacía mucho calor y estaba el padre de la niña en la casa y resultaba incómodo. Me comenta Patricia, la cuidadora que las visitas resultan muy gratificantes, Bea interactúa cada vez más con su hija y viceversa y la abuela como siempre se muestra colaboradora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2021-07-15','Belén. Se envía autorización para viaje a Chipiona de 26 al 30 de julio por correo electrónico (coordinacion.fa@aprosuba3.org). También se envían originales por correo postal.','2');
