insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2021-07-15','Ana: A petición de Estrella, secc. ecca, llamo a Aída (671507221) pues le ha llamado con consultas varias: salta el buzón de voz y le dejo un mensaje pidiéndole que me devuelva la llamada. ····················· Llamo de nuevo: Continúa con rehabilitación para su lumbalgia. Preparó con Gloria, su Ed. de Futuex, un presuesto para irse de vacaciones una semana a su pueblo a visitar a su familia. *Intentaré localizarlo o preguntaré a Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-07-15','Ana: Llamada de Juan Carlos, hoy está contento porque hace unos días fueron a visitarle Gloria y Sonia de Futuex. *Le han dicho que algún día saldrán por Plasencia. Por otra parte, continúa participando en los talleres (se ha hecho una pulsera de hilos), acude a la cafetería y da paseos. **Vuelve a preguntar cuándo se va a ir a otro centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-07-15','TERESA SE ORGANIZA VISITA PARA QUE LA FAMILIA VISITE A JOSE MARIA EL PROXIMO DOMINGO DIA 18 A LAS 19.30 HARAN EL DESPLAZAMIENTO EN TAXI Y ASUME EL GASTO JOSE MARIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2021-07-15','Ana: En relación a las últimas llamadas de Juan José, envío correo a Paloma, TO - CRR-CC (residenciato@feafescaceres.com): "Buenos días Paloma, ¿Qué tal estáis? En relación a Juan José Bergantiño González, como sabrás, lleva ya mucho tiempo pidiendo retirar su asignación de forma quincenal en lugar de semanal, pues considera que ya se administra suficientemente bien para ello. A fecha de 30 de octubre, Miguel Ángel, anterior Director, nos comunicó esto por escrito: “…No creemos que sea favorable que pueda disponer de efectivo semanalmente ya que uno de los aspectos en los cuales está presentando más problemática es en el control de impulsos con respecto a las compras de alimentación de manera individual y el uso de indebido del dinero.” ¿Sería posible que volvieseis a valorarlo y exponerlo en un breve informe? Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-07-15','Ana: Tras conversación con Julián, Gerente de COCEMFE (927 239 028), le envío DNI del Representante Legal junto con el resto de documentos acreditativos del Cargo de Tutor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-07-15','Ana: Correo de Pilar, TS ESM-CC (pilar.martinp@salud-juntaex.es): "Ana, me llama Clara la compañera de su CS para decirme que el paciente tutelado por vosotros Juan Chamorro Holguín le refiere en su despacho que se niega a asistir a la próxima cita de su psiquiatra el día 3 de agosto, hablo con su psiquiatra para ver si puede ser la opción de consulta telefónica, pero me dice que tiene que ser presencial, cosa que os informo y lo mismo hago saber a Clara, a la que sugiero que lo ponga en conocimiento de su MAP, de momento hoy le han puesto el inyectable. Tal vez sería conveniente la intervención de la delegada tutelar. Ya me dices. Un abrazo." ······························································································································································································· Mantengo conversación telefónica tanto con Pilar, ESM, como con Clara, TS del C.S. Guadalupe. ····· Pediré a Futuex que intenten ir a visitarlo. *A lo que sí asistirán a acompañarle es a la cita a la cuál él no quiere ir. ·········· Envío correo a Toni-Futuex. ···························································· *Por otra parte, Clara me informa que tiene una nueva MAP, la Dra. Cristina Ayuso. ······························································································································································································· Correo-respuesta de Toni-Futuex: "Buenas de nuevo Ana, pues si Teresa tambien estuvo hablando antes con el... y estaba desbocado, tambien es cierto que queda bastante para la cita y puede que cambie de opinión, hemos pensado que como el la ropa se la quiere comprar en el mercadillo del pueblo y es lo miercoles, para intentar motivarlo y reforzarlo, se le podria liberar un extra para el miercoles 28 de Julio, Teresa iria con el a comprar la ropa al mercadillo y justificariamos que lo gasta en eso, de esta manera al estar mas cerca de la cita, podemos motivarlo, que te parece??" *Confirmamos. Desde la secc. ecca. se acepta el presupuesto y se realiza autorizización de un extra de 125€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-07-15','Ana: Envío correo a Carlos Asensio, Ayto. Torre de Don Miguel (cultura@torrededonmiguel.es): "Buenas tardes Carlos, Te envío adjunta la solicitud de empadronamiento relativa a Ángeles Martínez Gavilán junto con la copia de su DNI. Si necesitáis algo más, házmelo saber. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2021-07-13','Belén. Envían facturas de ortodoncia con dos formas de pago. Se elige el pago donde no hay entrada inicial, solo pagos mensuales. Se van a domiciliar los pagos. Estamos a la espera de que nos digan la fecha de inicio de los pagos así como cuando van a cargar en cuenta cada mensualidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-16','miguel, llega email de Damian: Bueno pues quítame por favor lo de curadores que yo pueda disponer de mi dinero para irme del centro y el piso me informa como va para cuando se quede vacío me voy y ya en Málaga me ocupo de pagar el nicho de mi madre no voy a permitir que la echen a la fosa común así que arregle documentacion para irme y quitarme la curatela se lo pido por favor con mucho respeto ya me administro bien mi dinero ************************************ Hable con el juez gisela ya ha venido de vacaciones comuniquele al juez que quiero disponer de mi cuenta y le comunica al centro mi deseo de irme y dejarme por favor de disponer de mi dinero regresar a Málaga y pagar el nicho de mi madre es urgente por favor **************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-16','Ana: Envío a Tete (Plácido Alejandre), Gerencia Territorial de CC (residenciasmayorescc@salud-juntaex.es), correo con el informe social de emergencia social solicitado. ····························································································································································································· Recibo llamada de Plácido (927 00 42 61). Ya ha hablado con su jefa. Amplian la solicitud a toda Extremaura, la próxima plaza libre se la asignarán a José Manuel. Posiblemente lunes o martes podrá ingresar. **Como yo no voy a estar se pondrá en contacto con Belén-TS CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-07-14','Ana: Correo de María Núñéz, Directora Res. (direccion@residencialaluz.com) : "Buenos días Ana, Me comenta Esther, la administrativo, sobre la comparecencia a la que tiene que acudir Guadalupe Barragán García, el próximo lunes día 19 de julio a las 13`45 h sobre si irá acompañada por algún profesional del Centro. Sí, siempre van acompañados si la familia no puede ir, en este caso, por supuesto que sí, ya está organizado el medio de transporte y todo. Me han enviado la providencia del juzgado nº 2, y también me ha llamado un abogado amigo suyo , con el que tiene contacto ella, que seguramente acudirá también a la cita. Estoy a tu disposición. Saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2021-07-16','Ana: informo a Estrella Durán, TS, del ok de la secc. ecca. al presupuesto para el viaje a Vva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2021-07-14','Ana: correo de Estrella Duran, TS CSS-Plas: "Hola de nuevo. El viaje que estamos organizando para que Yolanda Caldera Martín visite a su centro de Plena Inclusión Villanueva de la Serena, será para después del 23 de agosto, que se incorpora el Psicólogo de dicho centro, con el que tiene un vínculo importante... Ese día, también me incorporo yo de mis vacaciones, las cuales empiezo el día 19 de julio. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2021-07-16','Ana: Eduardo no tiene sufiente dinero para la compra de la silla de ruedas. Se propondrá a la ortopedia alguna fórmula de pago fraccionada. *Informo a María, TS CTAEX, mediante email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2021-07-16','Buenas tardes A continuacion se envia, la información recopilada sobre las tarifas móviles con limitación de datos. Además añadimos un resguardo sobre el IBI de su vivienda, que nos facilitó la tutelada en el último seguimiento. En conversación mantenida el pasado día 2 de julio, con Carmen (Trabajadora Social de los Servicios Sociales de Base) nos indica que ha acordado con gestión económica de Comisión tutelar modificar los contratos de teléfono que tiene la tutelada con LOWI para evitar cualquier tipo de conexión a internet. Esto supondría el cambio de dos tarifas. La que corresponde a la tutelada y la que corresponde a su marido Blas. Desde el programa no hemos comunicado el cambio a Mª Rosa ya que va a rechazar dicha decisión, al limitarle relacionarse vía WhatsApp o por videollamada. Estas son algunas de las tarifas encontradas que solo tienen llamadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-07-16','ALBERTO MARTIN ROSETE Jue 15/07/2021 14:57 Hola. Tal y como quedamos os mando un resumen de lo que hemos hablado sobre la tutelada. Ángel informa de que se ha emitido EMBARGO, x importe de 1.285,8 € y en relación con COFIDIS. Tutelada tiene plena disposición de su CCC en BBVA (incluso cuenta con tarjeta) ya que, en su día, se trató esta cuestión con su familia (Amalia) y se decidió que era lo mejor dada las características de la tutelada (enfrentamiento con padres, robos,...). No disponemos de claves pero es facil llegar a la conclusión de que en ningún momento va a disponer de saldo suficiente para hacer frente al embargo. Amalia se pondrá en contacto con los padres tutelada x si quieren hacerse cargo del embargo, en cuyo caso Ángel los asesorará para que liquiden la deuda con el juzgado. En caso de que los padres no quieran hacer frente al embargo, el mismo se cargará en la CCC de la tutelada que será quién asuma su abono. Si alguno quiere hacer alguna consideración que se me haya pasado, contestad a este correo. Alberto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-07-16','Ana: Tal y como me pide Amor, TS Aspace, le envío firmada por el representante legal, la nueva pauta de medicación de Brahim. *Les pido el informe de la consulta de Psiquiatría ······························································································································································································· A última hora recibo el informe de consulta de seguimiento en el ESM. *Nada destacable, continúa igual. Guardado en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-07-16','miguel, vuelvo a intentar hablar con la policía Jesús o Ramón pero no está ninguno. Al no estar el vehículo ya aparcado donde estaba tenemos que averigurar si la policia ha sido quién lo ha retirado, porque caso contrario habría que denunciar su desaparación y obligar a a que la posible compradora Mª Guadalupez García Fedez conforme contrato de compraventa 25-4-18 lo ponga a su nombre. **************************************** Volveré a llamar la semana que viene a la policía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2021-07-16','TERESA Otro tema del que te quería hablar es de Jacinto Díaz Boza, en todo este tiempo de pandemia no ha ido a casa, a Oliva de la Frontera, y ya no puede más, sinceramente… Él tiene unas circunstancias muy especiales con su madre, con discapacidad también, y la casa …en condiciones complicadas…pero necesita ir…si iba con la cruz roja (lo tramitaba Maite, ahora no sé quien lo lleva) y se llevaba comida de aquí preparada para el fin de semana. En previsión de que pase el mes de agosto, de vacaciones, más tranquilo y no provoquemos ninguna alteración al ver que ya si se van los demás compañeros de residencia asiduamente a sus casa (y no como antes, que le decíamos que no se podían ir ninguno y que su pueblo tenía la carretera cortada), hemos pensado en acompañarlo (su psicóloga y yo) a su pueblo el miércoles, con la excusa de que su compañero y mejor amigo también quiere conocer su pueblo y a su madre pero que tenemos que volver todos de vuelta. Esperamos que al cambiar el contexto de la visita: un miércoles en vez de viernes, no con cruz roja si no con nosotros, ir acompañados…surta efecto y se vuelva sin problema…peeeerooooo por si acaso hay que tener plan B…y por eso te escribo…para saber si necesitamos autorización vuestra previa para ello…por si puedes preguntar a Maite quien lleva lo de la cruz roja y si podríamos retomar esos viajes… a ver cómo lo veis','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-07-15','Ana: Correo de Estrella Durán, TS CSS: "Buenos días. Queda organizado viaje a Badajoz a su centro de Aprosuba 3, acompañada por personal auxiliar y en taxi, para ver a su madre, el día 11 de agosto a las 8 de la mañana saldrán del Centro Socio-Sanitario de Plasencia y volverán sobre las 14,30 horas, saliendo de Badajoz sobre las 12,30 horas. Cuando emita factura el taxista, os la reenvío. Saludos." ············· Le pido que remita la factura a Estrella, secc. ecca., pues el gasto ya está autorizado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-07-16','-Amalia : llamo a los padres de Macarena para informarles del embargo de Cofidis . Me cuentan que se han ido a pasar unos días a Francia y que ella en el ultimo momento no quiso ir . solo han pasado allí 2 días y vienen de vuelta . Al parecer les ha contado que un cuñado de Esperanza le ha robado 800€ y ha abusado de ella. Se retracta luego y les dice que lo del robo es mentira pero no saben si creer lo del abuso . Hablaran con ella y la llevarán al médico si ella confirma lo expuesto. El verano pasado les robó la tarjeta de crédito y les robó 14.000€ de la cuenta donde pagan la hipoteca . Han tenido que vender su casa de Portugal para pagar su casa No van abonar nada de COFIDIS. Les progongo limitar la cuenta , lo hablaremos la proxima semana de nuevo. Aviso a delegada tutelar para que les haga visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-16','miguel, Carlos jurado me envía escaneado del SCH la identificación entre la cuenta origen y la cuenta actual del dinero. ********************************************* Hablo con el abuelo Pedro y le reclamo la sentencia de divorcio. Me comenta que Jorge Juan Zarza Fdez 607-266232 quien les ha estado llevando la reclamación de la devolución que tuvieron que hacer a clases pasivas (cuando se interrumpieron los pagos). Me comenta que la ejecución que nos envió se correponde con la pensión alimenticia referida en la sentencia de divorcio, por lo que le solicito que me envíe dicha sentencia de divorcio y liquidación de matrimonio. Dice que la referencia a un prestamo hipotecario se refiere al piso que tenía su hija en castillo puebla de alcocer, el cual sólo estaba a nombre de ella.Dicho piso fue ejecutado por el banco y además tuvieron que pagar una derrama, cantidades referidas en la ejecución que envió. Quedo a la espera que me mande la documentación para ver exactamente qué tenía que pagar el padre y a qué se refieren las cantidades del auto de ejecución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-16','miguel, llega la nota simple del registro de la propiedad de Trujillo, pero no se corresponde con el padre del curatelado ya que aunque tiene el mismo dni es una persona distinta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-07-16','Ana: Correo de Pilar Martín, ESM CC: "Ana he hablado con Virginia de Martín Dominguez Palencia, ¿me puedes remitir por favor la sentencia?. Su psiquiatra ante lo que me refiere Virginia me dice que es mejor que lo vea antes de la consulta con ella su MAP para valorar caso que fuese necesario el ingreso involuntario." ········· Le envío el testimonio de la senencia a Pilar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-07-16','Envío correo a Toni-Futuex: "Hola Toni, Me acaban de confirmar de la Residencia Amada Corral que en el presupuesto que facilitaron no está incluido el IVA. Con éste son 9,90 €/día. En cuanto a la asignación semanal, viendo que sube el precio del catering y que cobra una PNC, se autorizarán 20€/semana. Yo la próxima semana no estaré, pero puedes contactar con Icíar (si fuera necesario también con Teresa o Belén, TS) para acordar qué día podrá acudir Gloria para explicarle y acompañarle por primera vez a por el catering y retirar por primera vez la asignación. Para que puedan hacer la autorización bancaria. En cuanto al Catering, por favor, confirmar también el día de comienzo a la empresa. Yo no lo he hecho hoy mismo pues no sé la disponibilidad de Gloria. Pongo en copia a Icíar y a Alberto, sección económica. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-07-16','miguel, llega presupuesto de la obra. Quedo a la espera que Toni de Futuex nos remita quién es el presidente de la Comunidad o a quién dirigirnos para que hagan la obra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2021-07-19','Belén. Se envía la solicitud de Desplazamiento del Equipo Móvil de la Policía Nacional de Cáceres, debidamente firmada por el Representante Legal por correo electrónico (et-caceres@cruzblanca.org). También se envía por correo postal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-16','miguel, llega email Damian: Recibido muchas gracias y podríamos incinerar a mi madre? Para evitar los costes del nicho para que la comisión se informará como pagar una incineracion. ******************************************** Le propongo para seguir con la comisión y tener un piso aquí en merida que la comisión me ayude lo tengo claro vender mi piso de Málaga y comprarme un piso en merida así puedo ir del CRR a mi casa que me compre en merida cuando tenga permiso para irme unos días a el piso que gestionéis comprarme en merida claro buena zona y que pueda sacarle un dinero a ver si se van los inquilinos y me ayudáis a comprar un piso amueblado completamente aquí en merida.eso lo puede hacer la comisión para estar a vuestro lado.consultelo y me contesta por favor para irlo preparando y que me busquéis buena zona.muchas gracias don Miguel ayúdeme en esto de la venta de mi piso así la comisión está al lado del piso que me compraré a través vuestra y antes me hagáis la venta del piso de Málaga.no deseo vivir en Málaga así mi número de cuenta seguiría con la comisión en liberbank y mi pensión estaría aquí mucho mejor y con el CRR al lado.vamos que quiero que me ayudéis a la venta del piso de Málaga y la compra de piso en merida a ver si a través de rocio la abogada se puede gestionar esto pero compraría un piso aquí en merida tras la venta del de Málaga completamente amueblado con cocina y piso reformado para yo entrar directamente a mi uso personal cuando pueda salir de permiso unos días libres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-17','miguel, emails de Damian: Al final don Miguel en vez de comprarme aquí algo mi mejor decisión cuando el piso se quede vacío irme a mi casa el mensaje de ayer lo retiro yo aquí no tengo familia y mi deseo es volver a Málaga hable con el juez para deshacer la curatela se lo pido por favor déjenme hacer mi vida sino no voy a disponer dinero y me quiero marchar ya se lo comento con mucho respeto y necesito volver a mi casa cuando el piso se quede vacío comprar aquí es más complicado . *************************************** Usted que opina me podríais comprar una vivienda aquí espero el lunes que me llame muy señor nuestro gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-07-19','TERESA Para agilizar todo este tema, en vez de ir con pequeños presupuestos, cuando tengas todo presupuestado me lo haces llegar, aceptamos tu propuesta de abonar el 2/3 del presupuesto de la cocina el cual el importe total sería 2097.3€ y el de la lavadora de 290.40€ Y frigorífico 314.60€ Tenemos que pedir autorización judicial para hacer el pago, por ello es mas práctico que la pidamos por la cantidad total que hay que abonar para cubrir todos los desperfectos. Me quedo a la espera de que me pases los presupuestos pendientes para hacer la suma de todo, pedir la autorización y hacer el pago por transferencia en la mayor brevedad posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-18','miguel, llega email Damian: Podría mañana llamarme para preguntarle como va lo de mi curatela si ya ha hablado con el juez.deseo que me la quiten así en un mensaje se lo he expresado a mi familia gracias buen domingo.espero que se ponga en contacto conmigo por favor ********************************************* Me puede llamar mañana por favor? ***************************************** Buenos días Miguel esta mañana me puede llamar o responder a éste mensaje sobre el tema de quitarme la curatela muchas gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2021-07-19','TERESA SOLICITO DICTAMEN TENCNICO FACULTATIVO A LA PROVINICA DE CACERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-19','miguel, escribo a Damian y comunico a la Amalia Ts: Buenos días, esta mañana estaré en el juzgado con lo que no podré llamarle. Las cuestiones que plantea en sus emails sobre quitarle la curatela, dónde vivir y los restos de su madre debe tratarlas con su trabajadora social Amalia. En cuanto a la petición de quitarle la curatela no me corresponde a mi tomar esa decisión, hable con Amalia que se lo explicará(necesitará nombrar un abogado que solicite la remoción del cargo al juzgado a través de un procedimiento judicial). ************************************************* envío email a Amalia: Buenos días, entra en la intranet y lee los mensajes que envía este Curatelado, es diario los mensajes que envía. Le he remitido a ti para tratar sus peticiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2021-07-19','TERESA ENVIO SOLICITUD DE DEPENDENCIA PARA PETICION DE TRASLADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-07-19','TERESA LLAMA PILAR DEL PISO SUPERVISADO Y NOS COMUNICA QUE MANUEL HA VUELTO SACAR DINERO LO COMPROBAMOS Y HA SACADO 1200€, SALDO ACTUAL EN CUENTA 189.60€ ESTAN PENDIENTE DE REUNIRSE PARA TOMAR UNA DECISION SOBRE LA CONTINUIDAD EN EL PISO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2021-07-19','miguel, remito a petición de Amalia al juzgado comunicación de que reside en piso supervisado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-19','Belén. Me llama Plácido Alejandre para confirmarme que Jose Manuel Moreno Carlos tiene plaza asignada en la residencia Ntra. Sra. de Guadalupe de Bohonal de Ibor. Le tengo que mandar la pauta de vacunación del curatelado. Me pongo en contacto con la Directora del CRR de Plasencia (927423978) que me mandará a lo largo de la mañana la pauta de vacunación...............Me llama Plácido para informarme que la pauta de vacunación va en el expediente, que le avise del día del traslado. Me pongo en contacto con la Residencia Ciudad Jardín (927805101) y con Residencia Ntra. Sra. de Guadalupe de Bohonal de Ibor, Mario (927574262). El traslado se realizará mañana 20/07 a las 11h en taxi (mandará factura por correo electrónico) se habla con ambas residencias para informar del traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-19','miguel, remito a Damian contestación de Amalia: Buenas tardes, adjunto contestación de Amalia donde explica que sus peticiones tienen que venir a través de Gisela. Saludos “Buenos días , Miguel , Damián es una curatela económica y supervisión de la salud. No se hace intervención desde la parte social . Él ya conoce cual es el protocolo , todas sus demandas se las tiene que hacer a su terapeuta en el centro y es ella quien nos deriva lo que considere oportuno . Todos los usuarios en centro tienen este mismo protocolo , por lo tanto , sólo hay que decirle que siga el protocolo establecido y hable con Gisela “ .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-07-16','Belén. Nieves TS me manda la nueva cuota de la residencia, teniendo en cuenta el importe de la hipoteca, pasa de pagar 318,72€/mes a 271,94€mes. Sin embargo los gastos aún siguen siendo superiores a los ingresos........................... Se habla con la sección económica, dada la situación económica existente, se decide que, en tanto en cuanto se procede a la venta de la vivienda (cuestión no posible hasta noviembre: fecha en la que se cumplen 5 años desde compra inicial (protección oficial)), y para que tutelada pueda disponer de unos recursos mínimos en el centro, se autorizarán 100 €/mes para gastos varios asociados a la estancia en la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-07-19','Belén. Se envía correo a Nieves TS (marian.ramirez@salu-juntaex.es)para que la residencia le gestione 100€ mensuales para todos los gastos que puedan surgir así como el modo de abornarlo (transferencia o reintegro). Estos 100 € suponen que, en computo anual, los gastos son superiores a ingresos. Se autorizan porque la intención de la CTAEX es proceder a la VENTA de la vivienda y liberar todos los gastos asociados a la misma','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-07-19','miguel, pongo a la firma del gerente el preuspuesto de abogado y procuradora','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-07-19','miguel, me confirma la policia local de Mérida 924-380138 Ramón, que ellos no han retirado el vehículo y que la denuncia la tenemos que interponer ante la Policía Nacional','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-07-19','miguel, envío el siguiente email al representante del 3º hermano hijo del fallecido tutelado por esta Ctaex: Buenos días, a petición de Evelyn le remitimos la rendición de cuenta final remitida al juzgado nº1 de Olivenza a efectos de poder preparar la herencia del fallecido. Al no haber otorgado testamento quedamos a la espera nos indiquen la notaria (y persona de contacto) donde se vaya a firmar la declaración de herederos por su representado, para unamos las firmas de los dos representados por esta Comisión Tutelar de Adultos.','2');
