insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='QUIROS'and apellido2='BERROCAL'),'2021-07-19','Belén. Llega informe social; nacido en Piedras Albas de 74 años. Está en residencia Alcántara. Problemas de ludopatía. Tenía deudas contraídas que debido a la pandemia se han saldado. Tiene 2 viviendas una en mal estado. No consta seguro de decesos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2021-07-19','miguel, tras email a Secretaria General en días anteriores y tras hablar hoy con Felisa de Abogacía general, remito a petición de ésta al email contencioso@juntaex.es el siguiente email acerca de la solicitud que hicimos en noviembre de 2020 para la retirada del carnet de conducir: Buenas tardes conforme conversación telefónica remito archivo de presentación en el juzgado Decano de Badajoz de procedimiento voluntario para la retirada de carnet de conducir. Necesitamos saber el número de procedimiento y juzgado que lo lleva y si se ha recibido alguna actuación con respecto al mismo por abogacía general.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-20','-Email de la TS del ESM: Buenas tardes Amalia, no sé si estás de vacaciones o no, he intentado hablar contigo. La abuela de Alejandro me ha llamado esta mañana porque el domingo otra vez han llamado a 112 y se lo han llevado al HUB. Según la abuela, Alejandro ha dicho que en Urgencias se ha encontrado a Gutiérrez, su psiquiatra anterior, y éste le ha dicho que le pidiera cita. Se fue de urgencias, le pidió a la madre que le enviara un taxi, y se fue por ahí, hasta las 5 de la madrugada. La madre no fué detrás de la ambulancia. He visto el informe y se fugó de urgencias, no ha podido verlo el psiquiatra. He contactado con Alejandro y me ha corroborado que estaba muy cansado de estar en Urgencias, así que se fue, también me dice lo de Gutiérrez, eso tengo que comprobarlo, suena a milonga. He comentado a la madre, que otra vez, ella tiene que ir con él, que se pille un taxi. No sabía que se había ido de Urgencias porque había querido. Un abrazo P.D: si no estás de vacaciones, me llamas porfa.','2');
