insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-07-20','miguel, envío email al abogado Jorge: Buenos días Jorge, confirmame por favor si el poder apud acta que necesitamos es para procedimiento de desahucio, ante el juzgado de primera instancia de los juzgados de Badajoz que corresponda, a favor de la procuradora Dña Cristina Soto. Voy a ir pidiendo cita para me acompañe el Gerente del Sepad (representante de la Comisión Tutelar de Adultos) para otorgarlo en los juzgados de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-07-20','TERESA RECIBO EMIAL DE MANUEL Me voy del recurso a casa de un amigo este lunes ablare con el gerente del recurso ya que la sicologa no me quiere derivar a otro piso ni dar el alta me están privando de libertad y cuacionando para firmar informes que no estoy de acuerdo y trasversando sobre mi a vosotros no se si tendréis que firmar algún papel y e sacado 1200 e del banco','2');
