insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2021-07-20','TERESA RECIBO LLAMADA DE DORA LA MADRE DE JAVIER ME COMENTA QUE HA VISTO UN PISO EN ZAFRA PARA ALQUILAR DE CARA AL ALTA TERAPEUTICA DE JAVIER ME DA EL CONTACTO DAVID 627527331 ME PONGO EN CONTACTO CON EL Y LE COMENTO QUE HASTA QEU NO ESTE ALBERTO NO PUEDO APROBAR LA OPERACION DAVID DICE QEU SE VA DE VACACIONES EL VIERNES Y NO VUELVE HASTA EL 17 DE AGOSTO LE PASO EL CORREO DE ANGEL PARA IR VIENDO LAS CONDICIONES Y ME QUEDO A LA ESPERA DE LA VUELTA DE ALBERTO PARA AUTORIZAR EL ALQUILER','2');
