insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GONZALEZ'and apellido2='SILVA'),'2021-07-19','miguel, remito a la Consejería de Servicios Sociales, dirección de infancia y familia, servicio de prestaciones, los informes sociales que me requieren','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-07-21','miguel, hablo con la abogada de la nuera Estefanía de Gijón (985-170250, email: estefania@beramendiygonzalez.com quien me ratifica lo que me comentó en el email del 13-4-21. En principio la liquidación del Impuesto de Sucesiones del hijo de la tutelada (Juan Felipe Rodriguez Montalban) presentado en la oficina liquidadora de Herrera del duque coincide con la masa total hereditaria (piso en Madrid y Talarrubias gananciales, y la cuenta de la Caixa) Concretamos pasos a seguir: -Llamar a la oficina liquidadora de herrera del dugue para que agilicen la liquidación del impuesto de sucesiones -hace Declaracion de herederos de su hijo Agustin Mientras Estefanía hablará con su representada Mercedes (nuera de la tutelada) para que le justifique el alquiler (Contrato, forma de pago, tiempo que lleva alquilado el piso de Madrid)Dice que hay propuesta verbal de compra del inquilino. Una vez tengamos la liquidación del IS de la oficina liquidadora de Herrera del Duque se pagará la Funeraria y a partir de ahí, haremos la Adjudicación de herencia de ambos hijos de la tutelada (Juan Felipe y Agustin)y la correspondiente autorización judicial de aprobación de herencia y autorización de venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-07-21','TERESA Con respecto al tutelado Guillermo Galán, comentaros que el responsable de la funeraria nos explica que después de realizar todos los tramites del sepelio y pagar los gastos que todo ello conlleva, le han sobrado dinero del seguro. No sabemos si ese dinero lo devuelven, que se hace con él. Mi compañera le comunica que envie factura a la comisión. Les doy el teléfono del tanatorio por si os queréis poner en contacto con ellos. • Tanatorio San Pedro de Alcántara • persona responsable TEO • teléfono 607588570 • teodoro.gonzalez@grupoia.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-07-21','Belén. Correo de Felisa Custodio, TS CAMF-Alcuescar informando que las vacaciones de Mª Isabel Debón Chenique del Programa de Vacaciones del IMSERSO gestionado por COCEMFE han sido aplazadas y que se reiniciarán a partir de octubre.','2');
