insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2021-07-21','Belén. Nacido en Valdemorales (Cáceres) Se encuentra en el CSS de Plasencia. Tiene 2 hermanos que no se sabe su paradero. Relación con los compañeros y comportamiento adecuados. Cobra pensión de viudedad (534,81€) y pensión de invalidez (1398,29€). Tiene un embargo y deudas con Jaztel. Propietario de una mitad indivisa y del usufructo de la totalidad de la vivienda en Castuera. No sabemos si tiene seguro de decesos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GONZALEZ'and apellido2='SILVA'),'2021-07-21','miguel, llega la recepción física de la presentación en TGSS del recurso de alzada que presenté impugnando el embargo que le están haciendo al tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2021-07-21','miguel, remito email a Amalia: Buenos días, ha llamado la trabajadora social de la Fuente del Maestre (Luisa) y ha hablado con la parte económica y les ha comentado que hay emails de febrero y mayo y que no le damos respuesta a los desperfectos que se le están ocasionando a la vecina. Parece ser la vecina va continuamente a quejarse. Te transcribo anotación que puse en la intranet en febrero a ti y a Alberto, sin que hasta la fecha me hayáis comunicado nada: Buenos días, ha llegado queja de un vecino de la Andrea indicando que hay problemas en su vivienda y nos pide arreglemos los desperfectos que parece vengan de la vivienda de Andrea. Necesito Amalia que solicites alguien se persone en la vivienda y o bien el seguro lo repare o caso no haya seguro, consigue un presupuesto que según el importe tendríamos que solicitarlo al juzgado. Mando copia a Alberto para tenga controlado si podemos disponer llegado el momento, de dinero para arreglo, incluso para gastos de abogado si fuera necesario. Ya me dices si hay o no que pedir autorización judicial para gastos extraordinarios para lo cual tendrías que enviarme desglose de qué hay que reparar y presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-07-21','miguel, llega la resolución definitiva del juzgado de Coria de aprobación de herencia y autorización de venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-21','miguel, escribe Alicia la prima de Damian (aliciente69@hotmail.com): Buenos días, Respecto a la gestión económica de Damian, entiendo que es un pago que le corresponde a él directamente puesto que se refiere a su madre y es hijo único. En principio y mientras resolvemos el tema, asumiré yo el gasto. He estado en contacto con el Centro y también están de acuerdo. No sé exactamente qué cantidad de dinero tiene prevista mensualmente pero supongo que podrá asumirlo aunque sea de forma fraccionada para no desequilibrar su economía. A la vuelta de mis vacaciones trataré de ponerme en contacto telefónico con vosotras. ***************************************************** Mi respuesta:Buenos días, envía un email a ctutelar@salud-juntaex.es adjuntando factura o presupuesto de lo que haya de pagar. Y pon A/A de la Sección Económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2021-07-21','Belén. Se encuentra en Plena Inclusión de Puebla de Alcocer. buena relación con compañeros y trabajadores. Percibe prestación familiar (598,8€/mes). Relaciones familiares casi inexistentes, el padre está en residencia y tiene un hermano que se fue a trabajar fuera y no saben nada de él. Tiene seguro de decesos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-07-21','miguel, remito al abogado y la procuradora el presupuesto firmado que nos enviaron. Jose Vicente vendrá el 27-7-21 a 9:30h al juzgado al poder apud acta y pido cita al Jzdo de Mérida para ese día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-07-21','Belén. Ingresa en residencia por emergencia social, Centro Residencial Virgen de la Asunción (TS 927441097) en Torre de Don Miguel. Perfectamente adaptada al centro. Se abrió cuenta en liberbank para ingresar dinero en efectivo y se guardan joyas en la residencia. Relaciones familiares se limitan a un hermano con el que mantiene contacto telefónico. Tiene 2 hijos con los que no mantiene contacto. No sabemos si tiene seguro de decesos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-07-21','TERESA RENDICION ANUAL BEATRIZ VIVE EN ZAFRA PERO TIENE MULTIPLES INGRESO EN UHB POR CONTINUAS DESCOMPENSACIONES VIVE EN PISO DE ALQUILER Y TIENE AYUDA A DOMICILIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2021-07-21','contestación de Amalia: Buenas Miguel , el problema es que Andrea tiene las cuentas a 0 , no tengo ni para comprarle unas medias , ni zapatos , y debemos a las monjas el seguro de deceso mensual pq tampoco lo puede pagar . Angel pidió autorización judicial para vender varias de sus propiedades y tierras pero desconozco si hay ya respuesta. Habría que priorizar en esos trámites y que esta señora pudiera disponer de liquidez. No tiene dinero para arreglar ningún desperfecto , ni tiene seguro . ************************************************** miguel: Gracias Amalia, me dice Angel que seguimos sin tener una resolución judicial (autorización para vender), así que toca esperar porque han nombrado un perito judicial pero éste necesita que el ayuntamiento le mande una documentación que no acaban de remitirle.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-22','miguel, recibo email de Carlos Jurado quien me remitió el viernes la documentación acreditativa de la identificación entre la cuenta origen y la actual objeto de reclamación por las hermanastras. "Te mando aquí de nuevo los documentos junto con el que faltaba y algún otro que, aunque lo tengas, me vale para explicaros todo perfectamente. Te he entregado muchos documentos pero para que no os forméis ningun lío, aquí están los únicos documentos que realmente os hacen falta. Te ruego de nuevo que los imprimas y con ellos delante leas esta explicación que te doy a continuación. Doc. 0 Justificante de que en la cuenta acabada en 7273 es la cuenta donde Francisco Nuñez Mure (padre de los tres hermanos) percibía su pensión. Doc. 1 Certificado del banco que la cuenta acabada en 7273 figuraba como titular el menor Alejandro Nuñez y autorizado el padre Francisco Nuñez y que al día 14/2/2019 tenía un saldo de 147.408,84 euros Doc. 2 Detalle de todos los movimientos habidos en la cuenta acabada en 7273 desde el 1 de febrero del 2019 hasta su cancelación. Vereis que el saldo inicial coincide con los 147.408,84 euros y veis que el 18 de julio del 2019 se cancela esa cuenta. ¿ A donde ha ido el dinero? veis que el 25 de marzo se hace una transferencia de 140.000 euros a la cuenta corriente acabada en 3312 que apertura ahora Alejandro Nuñez Bono. Y veis que el 18 de julio del 2019 se hace un traspaso a la cuenta corriente acabada en 3312 de 7.416,41 eruos. Doc. 3 Es la cuenta nueva, la acabada en 3312 donde tiene un saldo cero en su inicio y el siguiente apunte son los 140.000 euros traspasados a esa cuenta el 25 de marzo del 2019 Y en ese mismo documento veis que en esa cuenta el 18 de julio se ingresan los 7.416,41 euros de la cuenta iniciar ( la 7273). Doc. 4 NO es muy importante pero son los movimientos de esa nueva cuenta que tenía los 7.416,41 euros y que ahora estará en unos 4.600 euros. Doc. 5 Este sí es importante es la justificación de que se ha constituido un fondo con los 140.000 euros y que provienen de la cuenta abierta por Alejandro, la 3312 que al mismo tiempo viene de la inicia la 7273. Os adjunto tambien en este e mail la declaración notarial de herederos donde se declaran herederos de Francisco Nuñez Mure a sus tres hijos, Alejandro, Gema Inmaculada y Maria del Carmen. Creo que todo está bastante claro. NO vamos a entrar en otros dineros que pudieran existir o en los saldos que se hayan ido gastando por parte de Alejandro o de su entorno, pero mis clientes, la otras dos hijas del señor Francisco Nuñez Mure se contentarían con el reparto a tres partes del fondo de inversión por los 140.000 euros. Tener en cuenta que si no lo arreglamos por las buenas tenemos que meternos en un procedimiento judicial que durará bastante tiempo. Os llamaré el lunes próximo que entra e intentamos tener una videoconferencia".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-07-22','TERESA ENVIO AUTORIZACION SALIDA DE ARON A PETICION DE ASINDI','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-22','miguel, reenvío email del abogado Carlos Jurado junto con la documentación acreditativa a la tía del curatelado (patricia bono (patibo@hotmail.com). Y también se lo reenvío a Amalia y Alberto. Buenos días, para su conocimiento y el de su familia, con la finalidad de que puedan comprobarlo, le adjunto la documentación acreditativa del derecho solicitado por las hermanas de Alejandro que nos ha remitido el abogado, junto con la explicación de los mismos. La otra parte pretende llegar a un acuerdo extrajudicial para evitar tanto la duración como el coste (abogados, procuradores, reclamación del total de cantidades) que conlleva dicho procedimiento judicial. Salvo que ustedes puedan demostrar el error en la explicación que más abajo nos remite el abogado, por parte de la Comisión Tutelar de Adultos vemos correcta la documentación como la explicación. La otra parte propone el reparto de 140.000€ olvidándonos de los importes que hubiera en total en la cuenta y los posibles derechos que a cada parte correspondieren. La explicación de la documentación que se adjunta es la siguiente: Doc. 0 Justificante de que en la cuenta acabada en 7273 es la cuenta donde Francisco Nuñez Mure (padre de los tres hermanos) percibía su pensión. Doc. 1 Certificado del banco que la cuenta acabada en 7273 figuraba como titular el menor Alejandro Nuñez y autorizado el padre Francisco Nuñez y que al día 14/2/2019 tenía un saldo de 147.408,84 euros Doc. 2 Detalle de todos los movimientos habidos en la cuenta acabada en 7273 desde el 1 de febrero del 2019 hasta su cancelación. El saldo inicial coincide con los 147.408,84 euros y veis que el 18 de julio del 2019 se cancela esa cuenta. ¿ A donde ha ido el dinero? Con fecha del 25 de marzo se hace una transferencia de 140.000 euros a la cuenta corriente acabada en 3312 que apertura ahora Alejandro Nuñez Bono. Y veis que el 18 de julio del 2019 se hace un traspaso a la cuenta corriente acabada en 3312 de 7.416,41 eruos. Doc. 3 Es la cuenta nueva, la acabada en 3312 donde tiene un saldo cero en su inicio y el siguiente apunte son los 140.000 euros traspasados a esa cuenta el 25 de marzo del 2019 Y en ese mismo documento veis que en esa cuenta el 18 de julio se ingresan los 7.416,41 euros de la cuenta inicial ( la 7273). Doc. 4 NO es muy importante pero son los movimientos de esa nueva cuenta que tenía los 7.416,41 euros y que ahora estará en unos 4.600 euros. Doc. 5 Este sí es importante es la justificación de que se ha constituido un fondo con los 140.000 euros y que provienen de la cuenta abierta por Alejandro, la 3312 que al mismo tiempo viene de la inicia la 7273. Os adjunto tambien en este e mail la declaración notarial de herederos donde se declaran herederos de Francisco Nuñez Mure a sus tres hijos, Alejandro, Gema Inmaculada y Maria del Carmen. Las otras dos hijas del señor Francisco Nuñez Mure se contentarían con el reparto a tres partes del fondo de inversión por los 140.000 euros. Quedo a su disposición para cualquier aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-07-22','miguel, hablo con la oficina liquidadora de Herrera del Duque donde me indican que intentaran agilizar los trámites de liquidación del impuesto de sucesiones del hijo de la tutelada Juan Felipe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-07-22','Belén. Llevo toda la mañana llamando al centro de salud de Zafra (924554831-924554539) sin obtener respuesta para poder solicitar el informe médico para poder reactivar el PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2021-07-21','Belén. Se vuelve a llamar a la residencia La Salud de Villanueva de la Serena porque se les había solicitado por teléfono que nos mandaran informe médico para solicitar ingreso en centro de la comunidad autónoma y también se el envió un correo (mayoreslasalud@gmail.com) el día 28.07 solicitándolo. Nos confirman que nos lo mandan por correo postal el 22.07.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-07-21','Belén. Llamo al centro Ntra. Sra. de Guadalupe de Bohonal de Ibor (927574262) para ver que tal fue el traslado e ingreso del curatelado. Me informa que todo fue bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GARCIA'and apellido2='PEREZ'),'2021-06-29','Belén. Correo de Toni (FUTUEX). Hola Belen! a pesar que te comenté que no sería posible hasta después de las vacaciones de la compañera de zona, encontramos un huequito en la planificación la semana pasada y pasó a visitarla... pero por ahora fatal, imposible hacer ninguna gestión de las solicitadas. El pasado 24 de Junio se fue a la residencia Juan Carlos Rodríguez Ibarra a conocer a la tutelada María García Pérez que lleva viviendo en la residencia más de cinco años. Se habló primero con Mª Carmen, la trabajadora social del centro, para comentarle que se iba a ir a la residencia a visitar a la tutelada y a intentar hablar con ella del tema de su casa y de la importancia de la recogida de la llave para hacer inventario y para recoger sus pertenencias personales. Mª Carmen comentó que el tema de su casa y de la llave era muy delicado para María y no consentía hablar de ello ni siquiera con el personal del centro. Mª Carmen comentó que intentaría hablar con ella y sacarla a uno de los patios del centro para que se pudiera hablar un rato con ella, pero cuando se ha llegado a la residencia, Mª Carmen ha comentado que ha estado hablando con la tutelada y le ha explicado que había ido una representante de sus tutores a verla y no ha querido salir al patio, y eso que ya estaba en la puerta. Se ha negado en redondo y ha vuelto a subir a su habitación. Mª Carmen ha comentado que la tutelada es una persona muy tozuda, con mucho carácter y muy desconfiada, y que cuando se le mete algo en la cabeza no hay nada ni nadie que le haga cambiar de opinión por lo que proponía que se volviera a intentar visitarla en otro momento. Se seguirá yendo a visitarla las próximas semanas para intentar hablar con ella y sacar el tema de la casa para ver cómo reacciona la tutelada y si es posible que accediera a dejar la llave para ir a la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-07-22','-Amalia : consulto con discapacidad como está en la lista de espera , sólo tiene 40,5 puntos , lo más cercano es el puesto nº3 en Almoharín en VT . Están pedidas todas las zonas . En RAL queda muy atras . No se puede pedir por emergencia pq vive en casa de los padres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-07-22','Buenas , por favor me pide Iciar que hagáis visita a MARIA BAEZ , en la residencia. Necesitan que le confirméis si Caja Rural tiene allí entidad . La Dtra. dice que sí y el banco les dice que no . Han pedido a la dtra. que se acerque y lo confirme pero nada . Si no existe esa entidad , cuales son las que hay ?? todavia no ha podido sacar dinero por este asunto . Por otro lado , la Dtra. ha llamado a SSASB , dice que Maria quiere hablar con la hija , les he dicho que faciliten el tf a la hija y al revés que pueden darle el de la hija a la residencia. Solicita tb que le mandemos dinero a la hija para sus nietos , no se puede dar dinero a prestamo , no se va a autorizar , máxime cuando esta hija fue quien la agredió.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2021-07-22','-AMALIA . Desde el Ctro . penitenciario piden 250€ par gafas , solo tiene ahorrado 400€ . Desde la sección eco no quieren que se quede con tan poco dinero , le han propuesto rebajar su asignacion mensual , coge toda la PNC pero no lo acepta. Le digo a Estrella que lo mire con Alberto .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='MORALES'and apellido2='MORALES'),'2021-07-22','TERESA RENDICION ANUAL FRANCISCA RESIDEN EN RM SANTA TERESA DE JORNET DE DON BENITO NO TENEMOS CONTROL DE LA CUETNA PUESTO QUE LA PNC DE 402€ ES INGRESADA DIRECTAMENTE EN LA CUENTA DE LA CONGREGACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2021-07-22','TERESA RENDICION ANUAL JUAN SE ENCUENTRA EN LA RM FELIPE TRIGO, SE ENCUENTRA BIEN ADAPTADO AL CENTRO, ES SOLITARIO NO PARTICIPA DE LAS ACTIVIADES DEL CENTRO INGRESO EN RESINDENIA ANTE LA SITUACION DE ABANDONO EN LA QUE VIVIA TIENE ENFERMEDAD MENTAL Y RETRASO MENTAL PERCIBE PF Y ORFANDAD SALDO 18000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-07-22','-Amalia : Hablo con el padre de Macarena , me comenta que según ella el abuso que decia haber recibido por parte de un cuñado de la madre , de 75 años de edad ,eS verdad. Que han encontrado en el tf de la chica chats de tipo sexual . Pero que no la llevaron al médico ni lo han querido denunciar. Que lo han hablado en familia y que él lo negaba No quieren que limitemos la cuenta , que la dejemos como está , pq ella no sabe administrar ni 100 ni 400 y que temen que les amenace . Que le dan dinero suyo extra todos los meses. Solicito a Futuex priorizar la visita a domicilio para la semana que viene. Lo comento con los jurídicos , consideran que vamos a comunicar la situación al M. Fiscal . Espero por si la Delegada tutelar nos puede enviar algun informe .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='LOPEZ'and apellido2='CASTAÑARES'),'2021-07-22','TERESA RENDICION ANUAL ADELA RESIDEN EN LA RM FELIPE TRIGO NECESITA AYUDA PARA TODAS LAS ABVD,TIENE DETERIORO COGIITIVO, SOLO TIENE CONTACTO CON UN SOBRINO QEU ESTA EN SUIZA EL CUAL LLAMA DE VEZ EN CUANDO SE ENCUENTRA BIEN ADAPTADA AUNQUE NO PARTICIPA DE LA VIDA SOCIAL DE LA RESIDENCIA PERCIBE UNA PNC TIENE UN SALDO DE 16.000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA SAGRARIO'and edp.apellido1='GARCIA'and apellido2='PECES'),'2021-07-22','TERESA RENDICION ANUAL MARGARITA RESIDE EN PROINES SE MUESTRA ESTABLE EN SU ENFERMEDAD SIN REQUERIR INGRESOS EN EL CENTRO HA EVOLUCIONADO MUY POSITIVAMENTE PERO HA LLEGADO AL TECHO TERAPEUITCO ENCONTRANDOSE ESTANCADA DESDE EL CENTRO VALORAN EL TRASLADO A OTRO RECURSO ACUDE A LOS TALLRES OCUPACIONALES Y LABORALES LOS CUALES LES CUESTA SEGUIR PERCIBE ORFANDAD ABSOLUTA Y PF SALDO 4000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2021-07-22','-Amalia : llama su hno. 698922767 , dice que hoy lo han llevado a urgencias del hospital . Que lo ha visto un médico y le han dado el alta , que tiene mal los pulmones. No quiere que esté en casa , dice que está mal y que " nos lo llevemos otra vez al psiquiatrico " Le explico el proceso , el tramite con el 112 si fuese necesario. Voy a intentar solicitar cita en ESM para valoracion.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2021-07-22','Buenos días Miguel , qué tal ? esta petición de informe es para poder realizar el inventario que hay que confeccionar y enviar al juzgado explicando la situación de esta señora. Lo único que llega a la Comisión , es una sentencia , en la que se nos nombra tutores de la misma pero sin ningún dato más . Al corresponder a los Juzgados de Badajoz , se pide informe a ese SSASB . Se ha producido una remoción del cargo de tutor anterior , que recaía en la hermana . El cargo de tutor lo aceptamos el 9/07/2021. Desconocemos su situación y no tenemos ningún tf. de contacto . Te envio la sentencia por si te pudiera aportar algún dato que pueda facilitarte la intervención . Un saludo Miguel Ruiz Moreno >mruiz@aytobadajoz.es> Jue 22/07/2021 12:27 Hola Amalia, soy Miguel de los Servicios sociales de Badajoz. Me ha llegado petición de informe N/REF.:24/T/21//JLG Remedios Sánchez Moreno. Te mando imeil por si tuvieseis algún telefono de algún familiar para poder ponerme en contacto con Remedios, ya que en las visitas al domicilio realizadas no la he localizado. Mi extensión es 25082, por si me quieres comentar algo. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-23','miguel, contestacion de Patricia Bono (tía del curatelado): Buenas tardes, En relación a la explicación de la abogada no podemos admitirla como válida y suficiente para pretender llegar a un acuerdo extrajudicial. En relación al : Doc.1 Efectivamente existía una cuenta cuyo titular era Alejandro Nuñez Bono y como autorizado puesto que se trataba de un menor su padre, pero la titularidad la tenía Alejandro, su padre no era cotitular era autorizado, el dinero el del titular de la cuenta, independientemente de donde proceda, eso nos explicó un asesor en su día cuando le preguntamos por esta cuestión, por lo tanto no está tan claro que ese dinero haya que repartirlo porque no estaba la cuenta a nombre de su padre. El abogado de las hermanas lo que tiene que explicar es, en base a que norma bancaria que rige la titularidad de las cuentas u otro tipo de reglamento queda claro que ese dinero se considera herencia. Doc.2 Al cumplir la mayoría de edad Alejandro podía disponer de los 147.408,84 puesto que era el titular de la cuenta y por miedo a que hiciera mal uso teniendo en cuenta su estado psíquico y que todavía no tenía asignada la curatela por recomendación del banco se metió en un fondo 140.000 € El pico restante se utilizó para hacer frente a los gastos extraordinarios originados por Alejandro. Pedro Bono Mena (abuelo de Alejandro) tiene pendiente de cobrar de Francisco Núñez Bono una deuda de 48.000 € puesto que él afrontó todos los gastos de Francisco Núñez Bono durante años cuando desapareció, así está recogido en Sentencia y posterior Auto, documentación que Belén Bono entregó a Amalia el otro día para que la hiciera llegar al departamento jurídico de la comisión tutelar. Los herederos también heredan las deudas y está en la intención de Pedro Bono de reclamarla. Por lo tanto el acuerdo justo sería pagar la deuda y el dinero restante repartir, sino hay que ir a juicio para defender los intereses de Alejandro, la comisión tutelar no puede admitir el camino mas sencillo, debe velar por los intereses de Alejandro y con este acuerdo extrajudicial que presentan las hermanas solamente salen beneficiadas ellas. Un saludo Belén Bono Contreras Pedro Bono Mena Patricia Bono','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-07-23','TERESA Te escribo para informarte de que hemos recibido telefónicamente la citación para el forense de Natalia. La acompañaremos desde aquí, el miércoles 28 a las 10 de la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='NOGALES'and apellido2='MUÑOZ'),'2021-07-23','Por último comentarte que el padre de JESÚS NOGALES MUÑOZ, falleció ayer, estaba muy enfermo. Habrá que solicitar para él la Prestación Familiar Por Hijo a Cargo y la Pensión de Orfandad. Actualmente es perceptor de una PNC. La familia tiene un seguro de defunción en el que Jesús está incluido. Puede que esta gestión se la realicen desde el seguro pero como la madre se pierde en estos datos técnicos (la titularidad de las prestaciones tendrían que ir a nombre de la CTAEx) te voy a dar su teléfono por si necesitas hablar con ella así como el de Felipe , mi compañero , coordinador del Servicio de Residencia. Este jueves 22, es mi último día de trabajo. Después me voy de vacaciones. Regreso el 1 de Septiembre. Teléfono de Manuela (madre de Jesús): 646 78 09 84. Teléfono de Juan Antonio, hermano de Jesús ( si lo necesitaras, puedes llamarle a él también): 617 89 27 12.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-07-22','-Se le adjudica plaza en RAE " FCO ASUAR " DE Fuente de Cantos . El centro envia informe mostrando su desacuerdo por falta de personal . -Maribel Mesa informa q desde Aprosuba Olivenza le han solicitado la baja en tratamiento. Quedo pte. notificarle el nuevo destino .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-23','miguel, Buenos días, según dicha documentación independientemente de quién aparezca como titular queda acreditado que todos los abonos de la cuenta corresponden a la persona autorizada (el padre de Alejandro). Por otra parte las hermanastras tenían un derecho preferente reconocido por la administración por la cual cobraban el derecho de pensión alimenticia, quedando la de Alejandro como derecho pendiente y posterior. En otro orden, las hermanastras pagaron al igual que Alejandro unas cantidades por ingresos indebidos de la pensión, unido a que condonan la deuda del pico de 7.416€. Y por último recuerden que entablar un procedimiento judicial donde es muy complicado que Alejandro gane el caso supondrán unos costes procesales importantes por el nombramiento de abogado y procurador (ya que la junta no lo representará procesalmente). Por lo tanto teniendo en cuenta la disconformidad de acuerdo extrajudicial por parte de Alejandro con sus hermanastras, procederemos a la comunicación al juzgado para que sea éste el que resuelva y decida cómo proceder. ******************************************************** Me llama Patricia Bono 628297513, insiste igual que su padre en que le metamos en un centro para que desintoxique y pueda tratarsele, le explico que la dependencia de estupefacientes hace inviable su ingreso (aunque previamente habría que pasarlo a tutela y obtener una orden judicial de ingreso involuntario). Le explico lo mismo que en el email, y ella insiste en la deuda de 48.000€ que se le debe a su padre. Por eso la aconsejo vaya a un abogado y se asesore antes de decidir si quieren ir o no a juicio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2021-07-23','-LLama la vecina de Carmen de Valdecaballeros,924643480, dando voces y con mala educación , por los desperfectos que le ocaiona la casa conlindante y pq no se la vendemos . Ella ha dado 6000€ por el patio , la autorizacion de venta que ya se dispones establece precio de la casa en 54000€ . No se puede vender por menos de ese precio , pero la casa es para tirar y nadie la comprará por esa cantidad . Angel juridico ha hablado con el alcalde , a espera de recibir documentacion para justificar todo esto al juzgado y que permita bajar esa tasacion . Carmen no tiene dinero para repara los desperfectos. Dice la vecina q el alcalde les dice que lo va a tirar , Angel ha hablado con él .','2');
