insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2021-07-26','Belén: se envía CI para Anestesia y Cirugía Cardiovascular a la Unidad de TS de HIC fax(924219615). También se le adjunta por correo electrónico (mariajose.corvo@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2021-07-26','Ana: El día 19, Paloma Reyes, TO CRR-CC, nos remitió informe de seguimiento de Juan José: "Juan José sigue teniendo una gran dificultad en el manejo del dinero, más concretamente en la planificación y gestión del gasto a corto y medio plazo. En los últimos meses se ha trabajado y ha mejorado mucho con respecto a las compras compulsivas de comida. Al tener un menú y lista de la compra cerrados, hemos evitado los gastos superfluos de este tipo y la compra de comida basura. También se han visto limitadas las compras de productos no necesarios por internet y teletienda. En cambio, con el dinero de bolsillo que administra semanalmente, no se ha conseguido que se adapte a un presupuesto adecuado al dinero disponible. En los primeros días de la semana, hace un gasto excesivo en tabaco, comer fuera, … que consecuentemente le provoca no poder hacer frente, en ocasiones, a gastos periódicos y que son importantes (como la factura de farmacia), necesitando un anticipo por parte de la entidad...". *Guardo informe en el extpe. **Mientras no mejoren sus habilidades para la gestión econónica se mantendrá la autorización de retirada semanal de efectivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-07-23','Belén. Llamo a Manoli TS del CSS Mérida (ext. 24012), me comenta que Antonia le ha dicho que tiene una deuda con una clínica dental, como aún no tenemos los movimientos de la cuenta bancaria no le puedo dar ninguna información al respecto. Va a intenar llamar a la clínica para solicitar información. También me informa que van a iniciar el procedimiento para promover la incapacitación total.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-07-26','Ana: Reenvío el Auto a Chema Tovar (asociacionace@hotmail.com) y pido nos indique la fecha en que Soledad comenzará a asistir al Serv. de C.O.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-07-19','Ana: Correo de Toni, TS del CR Cervantes: "Buenas días Ana. En relación al estado de salud de Guillermo Galán Gigaldo, te adjunto el informe de la doctora Camino Iglesias Rodriguez. Intentaremos que se encuentre lo mejor posible y que no sienta dolor un saludo" *Le han trasladado a una habitación solo y han comenzado los cuidados paliativos. Situación crítica. *Guardo informe en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-07-13','Ana: nuevo correo de la vecina, Mariángeles Reyes Gómez (mariangeles.reyes@hotmail.es): "en relación con este asunto que tratamos, que podría hacer yo para que su tutela fuera también personal,porque este señor debería tener una persona que se ocupase ,al,menos ,de si se toma su medicación,porque la comunidad de vecinos no descansa con las andaduras de este hombre.Sobre todos los que damos al patio común y colindantes. Atentamente ,un saludo y muchas gracias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-26','Email de Ana con respecto al tema del nicho : Yo entiendo que si puede, que creo que sí, habría que abonar el alquiler del nicho. ¿No sería todo mucho más sencillo si se abonara mediante transferencia directamente sin que haya más intermediarios? Cuando estuvo en Plasencia, como no había lugar pues se pospuso la renovación debido al Covid, se aplazó, pero la idea era abonarlo si podía permitírselo. Pongo en copia a Alberto, a ver qué opina. Seguimos. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2021-07-26','Belén. Jose Mª tiene cita en el CADEX el 11 de agosto a las 11h. En esa fecha está de vacaciones con su familia en C/ Ramón Delorumbe Nº 10 portal 13 1ºB. en Badajoz. Se manda correo a Toni de FUTUEX para que mande a la delegada y lo acompañe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-07-26','Ana: Conversación con Sonia Bernabé, ASINDI (669 602 920): Aarón ha vuelto hoy de la visita con su padre. *Éste pide que no se le aisle. Pero la distancia física con los compañer@s es lo que está ayudando a que no agreda a otras personas. *Por otra parte reconoce que está más tranquilo y ha pasao bien el fin de semana.','2');
