insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-07-26','miguel, tras dos fallos en registro de entrada del informe forense me lo remiten desde el Jzdo nº1 Castuera por email y se lo doy a Tere por si consideran que aleguemos algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-07-26','-Amalia : remito por email a los juridicos los informes médicos de Ati para que puedan enviarlos al juzgado . Buenas , adjunto los ultimos informes médicos que disponemos de Ildefonso , son los ingresos hospitalarios que ha tenido , los pedí al hospital y los han remitido. Estoy llamando a CEDEX por confirmar si ha pasado por allí en alguna ocasión pero no puedo contactar con nadie , dudo muchísimo que haya acudido; porque de ser así, hubiesen contactado conmigo. El juzgado ha solicitado informes médicos actualizados tanto de salud mental como de CEDEX , referentes a su consumo de tóxicos. Se puede leer en los informes médicos del hospital que consume alcohol y cannabis habitualmente y cocaína de manera esporádica. Adjunto informes para que podáis remitirlos al juzgado correspondiente , no sé si pedían también algo con respecto a sus cuentas ; si es así , esa parte tendría que ser remitida por la seccion eco. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-26','-EMAIL DE JURÍDICO : Buenas tardes, ya contesté a Damian, a su prima, hablé con Gisela del CRR y lo apunté todo en la intranet por si queréis consultarlo. Resumiendo le expliqué que la sentencia es para su curatela no de terceras personas (familiares, etc), amenazó con pedir la remoción (mejor dicho, pidió que la solicitara yo al juez), en definitiva que tras conversación telefónica con Gisela, quedé que remitiera al email ctutelar presupuesto de gasto A/A de la parte económica para el abono del nicho (la forma del pago entiendo que tiene que decidirla la parte económica)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-07-26','-TEMA MOVIL , EMAIL DE ANA: Buenas, de nuevo, Amalia, En el caso de Damián, se hizo una excepción con el contrato de telefonía. Siempre y cuándo él no exceda la media de gasto (50 €) se le mantendría. Si el gasto comenzase a ser superior se daría de baja el contrato y se le pasaría a tarjeta de prepago. De la compra del terminal nuevo y tarjeta, que valore la sección económica, pongo en copia a Alberto. No me parece un gasto descabellado. Pero eso sí creo que debiera abonarlo con el dinero que tiene en el CRR para extras. Seguimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-07-27','TERESA HABLO CON ORFANDAD YA QUE SIGUE MAL EL MUMERO DE CUENTA, ME PIDE LE ENVIE POR EMAIL ANA-MARIA-RUIZ@SEG-SOCIAL.ES COMUNICACION CON NUEVO NUMERO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-07-27','Me han llamado del Juzgado de Zafra. Asunto: orden alejamiento Beatriz Mejías de la Morena. La jueza pide que vaya mañana miércoles a las 9:00 con algún responsable que le tutele para tomarle declaración y que le vea el forense. Te he llamado. Ya me dices. Gracias. Se gestiona , irá en taxi con monitor del piso y en los juzgados la espera la delegada tutelar','2');
