insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-07-27','TERESA ENVIO AUTORIZACION PARA SALIDA VACACIONES DEL 5 AL 4 SEPBRE ESTA SALIDA ESTA COORDINADA CON EL EQUIPO DE FAMILIA TAJO SALOR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-07-07','miguel, remito al abogado Jorge Calvo y la procuradora Cristina Soto el poder apud acta a favor de la procuradora para procedimiento de desahucio (para proced. de jzdos de 1º instancia de Badajoz), emitido hoy por los juzgados de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-07-27','miguel, recibo llamada de Jairo con dos peticiones básicamente: 1.-quiere la intervención de la Ctaex para encotrar un trabajo para su inclusión 2.-Va a denunciar al centro por un delito de odio. Quiere irse a un centro a Cáceres. Le indico que esta conversación ha de mantenerla con la parte social','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2021-07-27','- El hno. de José , Joaquín acude al SEPAD y lo llamo por tf. al 698922767 . Me dice que ve a su hno enfermo , y que lo han llevado a urgencias del hospital. Tiene insuficiencia respiratoria , el informe de alta indica que acudan a A. Primaria para seguimiento y derivacion por cita a ESM Mérida , pues verbalizan que no tiene adherencia a tratamiento. Contacto con ESperanza , TS del ESM , allí acudió en 2019 en cita administrativa y no hay nada más . Me india que este señor tiene que acudir a su médico de cabecera para que le den cita . Llamo al hermano para que soliciten al medico la cita , si se niega a ir que pidan al medico que acuda a domicilio . No se ha querido poner la vacuna del covid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-07-27','TERESA ARCHIVO RESOLUCION DE PFHC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-07-27','miguel, voy a la vista donde se llega a un acuerdo entre abogado defensor Moises Palacios Cotano y el Ministerio Fiscal consistente en absolverla del delito de atentado del articulo 550.1 CP (delito contra la autoridad) y delito de lesiones del art 147.2CP, por aplicación de la eximente completa del artículo 20 CP, no obstante se establecen las siguienes medidas de seguridad: internamiento en régimen cerrado en centro adecuado por 8 meses y control médico periódico por 2 meses. Además deberá indemnizar a Mª Belén Bertol Lorenzo con 190€+intereses','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-07-27','miguel, llega la sentencia por fax donde para su ejecuciónse remiten las actuaciones al Jzdo de lo Penal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-07-28','Ana: Correo de Inés, TS CSS-Plas. (inesm.romero@salud-juntaex.es): "Buenos días, Ana. Soy Inés, la sustituta de Estrella Durán en el Centro Sociosanitario de Plasencia. Te escribo para informarte que el viernes 23 de julio Juan Carlos Ruíz García se escapó del centro. Se avisó a la policía que lo devolvió al centro. No se si te tengo que enviar un informe o con que te avise así es suficiente, tu me lo dices por favor. Por otro lado, me comenta la psicóloga que no deja de preguntar cuándo vienen las chicas de FUTUEX a sacarle de paseo. Ellas le dijeron a Estrella que en verano la cosa estaba difícil pero de todos modos tengo que llamarlas de nuevo a principios de agosto. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-07-28','TERESA Hola, tenemos testamento de la madre, intentaré hacerme con el certificado de últimas voluntades del padre para verificar si tenía o no testamento (caso que no lo tenga necesitaré dos testigos para hacer ante notario declaración de herederos). Por lo que he podido comprobar sólo han dejado los padres esa cuenta de la que era también titular Sergio. Por tanto en principio los 72.000€ que hay en la cuenta eran un 66% de los padres y un 33% de Sergio por lo que ya podeis coger su parte. Una vez presentado el impuesto de sucesiones podremos dividir lo que quede entre los dos hermanos. He visto que en la última rendición de cuentas Raúl tenía unos 10.000€ y si Sergio coge lo que le corresponde a día de hoy al menos 24.000€ son suyos…hasta que el trámite de herencia esté hecho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-07-28','TERESA Hola, tenemos testamento de la madre, intentaré hacerme con el certificado de últimas voluntades del padre para verificar si tenía o no testamento (caso que no lo tenga necesitaré dos testigos para hacer ante notario declaración de herederos). Por lo que he podido comprobar sólo han dejado los padres esa cuenta de la que era también titular Sergio. Por tanto en principio los 72.000€ que hay en la cuenta eran un 66% de los padres y un 33% de Sergio por lo que ya podeis coger su parte. Una vez presentado el impuesto de sucesiones podremos dividir lo que quede entre los dos hermanos. He visto que en la última rendición de cuentas Raúl tenía unos 10.000€ y si Sergio coge lo que le corresponde a día de hoy al menos 24.000€ son suyos…hasta que el trámite de herencia esté hecho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-07-28','Ana: Correo de Julián - Gerente de COCEMFE (gerencia@cocemfecaceres.org): "Te escribo en relación a las vacaciones de Tomás y los gastos correspondientes Hay que realizar tres pagos: - COCEMFE importe hotel: 195x2=390€ (estancia T.E.I. y su asistente).................................... Nº cuenta: ES15 2100 1570 7402 0015 0916 - Asistente personal (Miguel Hernández): 600€ ....................................................................... Nº cuenta ES95 0049 6780 5928 9518 4571 - Tomás Esteban Iglesias: 200€ gastos personales en vacaciones para reintegro en la sucursal habitual. Necesitaríamos lo antes posible el pago del hotel y que nos enviéis justificante al siguiente correo: agustina.pc@cocemfecaceres.org Los ingresos del asistente personal y de Tomás se pueden abonar a primeros de septiembre." ············· Tal y como indicó Alberto, jefe secc. ecca, se lo reenvío a Estrella, secc. ecca. para que se encargue. ······························································································································································································ Julián envía por adelantado la declaración jurada del Asistente Personal. *Se la paso también a Estrella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-07-28','TERESA Estamos reunidos Tere y yo: varias cuestiones relacionadas con los REINTEGROS INDEBIDOS que ha realizado este tutelado: Cuestión: ha realizado un reintegro NO autorizado en LIBERBANK x 1.200 € el pasado 15/07/2021. Ya había hecho otros 2 reintegros indebidos x 3.200 € en CAIXABANK...cuenta que cancelamos para abrir en LIBERBANK. • ÁREA JURÍDICA: os adjunto reclamación enviada a CAIXABANK y su correspondiente contestación. o Con respecto al reintegro indebido de LIBERBANK, Iciar se pondrá en contacto mañana con el banco. o La idea saría comunicar al JUZGADO LA ACTUACIÓN DEL TUTELADO informando de los reintegros y adjuntando también un INFORME SOCIAL del centro sobre el comportamiento del tutelado (ha enganchado al consumo a un compañero del centro que llevaba 11 años sin consumir). • TERESA: habla con centro, si lo ves adecuado, y que nos hagan un INFORME sobre el tutelado y su comportamiento. • TERESA: quizás el centro tenga alguna idea nueva de como actuar con el tutelado...que nos lo remitan y lo vemos. • ICIAR: ponten en contacto con oficina LIBERBANK y que nos den una explicación sobre lo ocurrido: REINTEGRO SIN AUTORIZACIÓN. (con Liberbank actuemos con cuidado).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-07-27','Belén. Nieves TS de la residencia Felipe Trigo me envía correo diciendo: hola Belén.Cuando hablé con Andrea para decirle que le íbamos a bajar la cuota, ya que tenía un préstamo hipotecario, ella pensó que queríamos vender la vivienda. Para ella es muy importante su vivienda, no quiere que se venda. No sé a cuánto asciende el IBI y el seguro de decesos, pero igual puede ayudar algo alguno de sus hijos, para evitar la venta. No obstante, el seguro de decesos y el IBI prorrateado no creo que sea mucho teniendo en cuenta el tipo de vivienda. Por nosotros, no hay problema, en hacer el reingreso mensual y gestionar el dinero de bolsillo para los gastos que dices. Lo que necesitamos es la autorización para sacar dinero de la cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2021-07-28','TERESA ENVIO AUTORIZACION PARA SALIDA FAMILIAR DEL 26 DE JULIO AL 3 DE AGOSTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-07-28','Maite:Teresa y yo hemos hablado con Maribel ( directora residencia INCLUSIVES), sobre el presupuesto para JOse MAria. Le van a dar un asignación semanal de 10 €. Y desde el centro enviarán justificación trimestral de gastos; para los extraordinarios, pedirán autorización. Respecto a la adpatación de José MAría en el centro, Maribel nos ha comentado que se encuentra muy bien y tranquilo. Hace años estuvo cumpliendo una medida allí y guarda buenos recuerdos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-07-28','Ana: Tras recibir llamada de Mª Ángeles, hermana de Isabel (927 90 47 03), indicando que se deben 500€ de farmacia y que su heraman necesita ponerse dentadura y comprar una TV, llamo a Jose, Director Res. de Jaraicejo (608 962 782): dice que le pasó a Gloria-Futuex, presupuesto de dentista (*Pero filtro en los correos y no hay nada al respecto), confirma que también se debe la farmacia y que Isabel quiere un TV para el cuarto, pues tenían el de la compañera que se ha ido y ya no tiene. **Me enviará a mi correo el presupuesto de la clínica dental, el contacto de la farmacia y más adelante presupuesto para la TV. ··············· Envía presupuesto. *Se lo paso a Alberto, jefe secc. ecca., que da OK. *Escribo a Jose se lo comunico para que pidan cita y pido me remitan la factura cuando la tengan para abonarlo mediante transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-07-23','Ana: Correo de Ángela, Placeat (directora@placeat.org): "Buenos dias Ana, te remito documento de declaración jurada de la persona que ha realizado el acompañamiento a Cristofer. Informarte que está bien, ayer tuvo consulta con el especialista. Cualquier cosita , puedes dirigirte a Ana Amor, ya que yo me voy de vacaciones hasta el 25 de agosto. Saludos" ············· *Paso la declaración jurada con el nº de cuenta a la secc. ecca. para el abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-07-28','Ana: Envío correo a Toni-Futuex: "Buenos días Toni, Ya sé que estás de vacaciones, y espero que disfrutes y desconectes, pero para cuando vuelvas, informarte de varias cuestiones relativas a Aº Hidalgo Romo. Ayer me facilitó Teresa el nº de Gloria y estuve hablando con ella. Ya hemos cerrado: - El cáterin comenzará el lunes día 2. - Tendrá una asignación semanal de 20€, que también podrá comenzar a retirar el día 2. Gloria le acompañará el primer día a ambas cuestiones. Por otra parte (y esto no lo hablé con ella), tenemos pendiente averiguar lo relativo a un vehículo que debe tener, pues tiene domiciliado un seguro. Como en otros casos, necesitamos saber más acerca de ello, matrícula, paradero del mismo, si se le da uso y demás. Y si Antonio tiene permiso de conducir en vigor. Cuando pueda Gloria que se encargue de ello. Iremos paso a paso. Por último, infórmate que hemos recibido Autorización para internamiento como medida cautelar, no obstante, a priori no cumple perfil para ninguno de los recursos existentes… así que esto no será de un día para otro. Gloria ya lo sabe. Contactaré con la Médica de Atención Primara y la TS del SSASB al respecto, ya os iré informando. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2021-07-28','Ana: Correo del día 23 de Toni-Futuex: "Después de acudir a la consulta de oftalmología, en la que el oftalmólogo indicó que Salvadora puede retomar su vida, más o menos, con normalidad; se habla con la teniente alcalde de la localidad, persona que se está haciendo cargo de la dirección de los PPTT, tras la intervención del ayuntamiento en los mismos, se le comenta el cambio en la situación de Salvadora y la necesidad de retomar las salidas, principalmente, como medida terapéutica, pues lleva como año y medio sin salir del centro. Se estipula que salga una hora en horario de mañana y otra en horario de tarde, para que se vaya adaptando. Para comenzar dichas salidas es conveniente que la tutelada cuente con algo de dinero de bolsillo, ya que lleva sin retirar desde marzo de 2020 y no tiene nada de solvencia. Además, al hablarlo con Salvadora, expone que tiene primas en la localidad y algunas amigas que han venido a veranear, con quienes acostumbra a tomar un zumo o algo. Se plantea que pueda acudir a Brozas a retirar asignación, la cual, en lugar de hacerlo todas las semanas, cubra un mes, retirando unos 100-150€, por ejemplo, para que pueda ir a la peluquería y salir a tomar algo; dicha cantidad se le daría de forma quincenal y se lo podría administrar la educadora de apoyo. También, para ir a Brozas, el desplazamiento, para que sea más seguro y no pase la mañana, sola, en la localidad, estaría bien que lo hiciese en taxi, la educadora acompaña a la gestión y se vuelve de la misma forma, evitando así que deambule por Brozas. Se adjunta, en documento a parte, el presupuesto que ha facilitado la taxista para ello, en principio, se propone para el día 2/08/2021." ·············· Se lo paso a Alberto, secc. ecca. con mi ok. ································································································································································································ *También tengo correo de Cruz, TS SSASB, exponiendo la situación. ············ Envío correo-respuesta a CRuz, TS SSASB (cruzmerino@tajosalor.es): "Buenas tardes Cruz, Muchas gracias por informar. Confiamos en que Salvadora continúe evolucionando bien y pueda retomar con "normalidad" (dentro de las circunstancias actuales) su vida diaria. Ante vuestra propuesta, tras haberlo hablado con el jefe de la sección económica, se aprueba una retirada de efectivo puntual para la semana que viene (el día 2 ya podrían acudir a retirarlo) de 150€. A partir de septiembre tendrá una periódica de 100€/mes (más no es posible dada su situación económica). El trayecto en taxi una vez al mes para dicha retirada también se aprueba. *Eso sí, le pediremos a la educadora del programa de apoyo que nos envíe regularmente la nota para poder abonarlo mediante transferencia. Ante cualquier cuestión no dudes en volver a contactar. Un saludo y buena tarde." ······ Envío mail con la misma información a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2021-08-04','-Operan a Rosa el día 4 en cardiologia , ya tienen todos los consentimientos informados . He avisado a su hija Iris.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-28','-Acude sin cita al SEPAD gerencia Badajoz la abuela . Reclama que se le dé más dinero para gastos de Alejandro y que la herencia del padre sea sólo para su nieto . Le informo , que la pensión de orfandad que se entrega a su hija es para cubrir esos gastos y que tendrán que administrarselo . No se le puede dar más dinero , con la extra que se le guarda se abonan otros pagos como multas , embargos.. Quiere traer facturas de gastos para que se le abonen , ya se les explicó desde la sección económica que no se abonarán gastos extras , se les entrega la pensión . El tema de la herencia está en estudio por jurídicos , ya se lo ha explicado mi compañero Miguel a su hija Patricia y al abuelo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-07-28','Ana: Recibimos el Certificado de Empadronamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-28','Amalia : envio email a Miguel : Buenos dias , ha estado la abuela de Alejandro en el SEPAD , esta familia no se entera o no se quiere enterar de la situación A nivel eco , el pto. de Alejandro está cerrado , se le entrega la pension a la madre para cubrir gastos y Alberto no autoriza para pagar nada más . Las extras las guarda para pagar multas y embargos . Me dice que venía aquí derivada por tí para entregar facturaras para que se le abonaran , dudo que esta sea la información facilitada , pero te lo comento para que lo tengáis claro , no se abona nada extra ! si tienen alguna reclamación al respecto que acudan al juzgado , desde la CTAEX no se les va a dar más explicaciones . No están de acuerdo con lo de la herencia , le indico lo mismo . Quieren confirmar que la documentación te haya llegado , te están llamando para eso , supongo que ya la tendrás , el conductor la llevo el martes. Por otro lado , desde el ESM , están intentando el internamiento involuntario a través del 112 , a ver si pueden conseguirlo . Ya ha habido dos ingresos pero no ha llegado a ingresar en la UHB. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-28','- Amalia , envio email a la delegada tutelar . Buenos días Tere , te comento sobre Alejandro , desde el ESM estan intentando un internamiento involuntario con el 112 . Solicitan que la delegada tutelar lo acompañe , para que esté en urgencias junto con la madre, y que se garantice la entrega de un sobre que le han dado a Belén , para que lo entregue allí a los médicos . En ese sobre se indica lo que el psiquiatra ha dispuesto , al parecer ya ha ido el 112 dos veces a la casa pero ninguna de las veces se ha conseguido su ingreso en la UHB . Una de las veces se quedó allí solo en la sala de espera y cuando le pareció se marchó. Os comunicaré lo que me vaya diciendo Carmen . Un saludo , gracias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-28','-Escribo email a Carmen , TS del ESM , para preguntar cómo lleva el proceso del internamiento involuntario por 112.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-07-28','miguel, me llama Antonia del SSB de Almendralejo, para informarse cómo proceder sobre los okupas que están en su domicilio donde se sospecha que hay drogas y prostitución(denunciar y quién tiene que hacerlo en el juzgado si el tutelado, el SSB, nosotros, etc) Le comento que o bien lo denuncie el tutelado directamente o me envíen toda las declaraciones por escrito de vecinos y el propio tutelado para dar traslado al Ministerio Fiscal como hecho ilícito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-28','Amalia : aviso a la delegada tutelar por si hay que acompañra a Alejandro en el internamiento involuntario .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-28','- envio email a Carmen , TS del ESM : Acude sin cita al SEPAD gerencia Badajoz la abuela . Reclama que se le dé más dinero para gastos de Alejandro y que la herencia del padre sea sólo para su nieto . Le informo , que la pensión de orfandad que se entrega a su hija es para cubrir esos gastos y que tendrán que administrarselo . No se le puede dar más dinero , con la extra que se le guarda se abonan otros pagos como multas , embargos.. Quiere traer facturas de gastos para que se le abonen , ya se les explicó desde la sección económica que no se abonarán gastos extras , se les entrega la pensión . El tema de la herencia está en estudio por jurídicos , ya se lo ha explicado mi compañero Miguel a su hija Patricia y al abuelo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-07-28','Ana: Llamo a Fermina, Directora de la Res. de Aldea del Cano (646 437 879) en relación al acompañamiento para la cita médica: CONSULTA MEDINA INTERNA HOSPITAL SAN PEDRO DE ALCANTARA DE CACERES FECHA CITA: 3/8/2021 Hora: 11:30 *Cuentan con una persona de confianza para que la acompañe. *Nos enviarán a posteriori la declaración jurada con los datos y nº de cuenta para hacer la transferencia. *Se abonará a razón de 10€/hora. ··········· Se lo comunico a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-07-28','Ana: Envío mail a Toni-Futuex: "Buenas tardes Toni, Cuando sea posible, podéis gestionar cita y acompañar a Alfonso Marín de Cáceres a renovar el DNI, el que tienen en el banco, y nosotros, está caducado. Lo necesitamos bien escaneado a color. Hablad si queréis con la hermana, para poneros de acuerdo, pues también se lo he comentado aprovechando que me ha escrito con motivo de la compra de ropa para Alfonso. Gracias. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-07-27','Ana: Correo de Patricia, hermana de Alfonso (p_m_decaceres@outlook.es), remite nº cuenta para transfercia para el abono de la ropa que le han comprado a Alfonso. **Ya le aclaré que la próxima vez con presupuesto previo y con factura a nombre de Alfonso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-07-29','Ana: Llamo a Pilar, de la farmacia de Jaraicejo (616 599 410), confirma que se le deben casi 500€. Gloria, Ed. Futuex, recoge las facturas todos los meses, pero al correo de ctutelar@ no han llegado. **Le facilito las direcciones de correo a la farmacéutica para que nos las remita ella directamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-07-29','Ana: Recibimos por valija, remitido desde el C.R. Cervantes, las llaves y la cartera con la documentación de Guillermo. *Las llaves de la vivienda se las remitiremos al hermano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2021-07-29','Belén. Se llama al SSB de Montijo (Mª Ángeles 924459085) para volver a solicitar el Informe Social para poder hacer el inventario. Me cuenta que han intentado localizarla y no responde al teléfono, pero informa que ahora está bastante bien. En cuanto puedan hablar con ella harán el informe. Le van a mandar una citación para que acuda al SSB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORCILLO'and apellido2='HERRERO'),'2021-07-29','Belén. Se lla a la residencia (927508050) para hablar con la TS y volver a solicitar Informe Social para el inventario. La TS está de vacaciones y se incorpora el lunes 2 de agosto. Le van a dar mi teléfono para que se ponga en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-07-16','Ana: Conversación con Paula, TO CRR-Plas. (682 704 401): Ceferino continúa con la demanda de cambio de CRR. Lleva 2 años en el recurso. Desde ESM insisten en que tiene esa demanda, lo valorarán en equipo. *Le pido nos comuniquen por escrito lo que dictamente, tal y como hicieron en septiembre de 2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2021-07-29','TERESA TELEFONO DERECOTRA RM 670381292 gEMA SANCHEZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-07-23','Ana: Correo de Toni-Futuex: "22/07/2021 Vuelta a Valencia de Alcántara: Contacta José Manuel, vía e-mail, para comunicar que la próxima semana regresará, con Manuela al domicilio habitual, no especifica el día, como costumbre, mantiene sus ocultaciones e intrigas, comunica lo siguiente: “Buenas tardes Gloria, qué tal?.. comentarte que en el transcurso de la semana que viene, el día más apropiado para viajar con mi Abuela, regresaremos a Valencia de Alcántara..Saludos” Se le responde, al mismo, indicando que comunique una vez esté en el domicilio para programar una visita."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-07-29','Ana: Llamo al Ayto. de Alcuescar (927 38 40 02), me dicen que María, TS, hoy no está. ············ Llamo a la Mancomunidad Integral Sierra de Montánchez (927 389 030 / 32) me indican que María hoy se encuentra en Aldea del Cano (927 38 30 02) Llamo: María me informa que la semana pasada acudió a su domicilio a valorarlo el Médico Forense. María estuvo presente y Antonio verbalizó que estaba dispuesto a ingresar en una residencia, pues la casa estaba muy sucia, él también y además así no estaría todo el día sólo "tirado como un perro". ············ *Acordamos que María, TS, emitirá el informe social (modelo de Dependencia) y yo cumplimentaré la solicitud para reactivar el PIA. *Desde la CTAEX nos pondremos en contacto con la MAP para que haga la derivación preferente al ESM. ····························································································································································································· Maite, Jefa Secc. CTAEX, llama al C. Salud de Alcuéscar (927 38 42 10), habla con la Dra. Rocío Domínguez le dice que mañana hará la derivación y que realizará el informe médico. Maite le facilitará por mail el modelo de dependencia. ······························································································································································································ María, TS SSASB, me remite por mail, firmado electrónicamente, el Informe Social de Emergencia Social, en el modelo de Dependencia. ···························································································································································································· Cumplimento y pongo para firma la solicitud de Dependencia para reactivación del PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2021-07-29','miguel, remito la sentencia que dictó el jzdo nº2 de Cáceres en relación a Soledad Esteban Iglesias (contra Nace)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-07-29','miguel, envío de nuevo a la notaria la documentación a la notaria de herrera (notariaherreraloli@gmail.com, tlfno 9246502302, notaria de Luis Pablo Sanchez Martinez): Buenas tardes, conforme conversación telefónica adjunto documentación para preparar declaración de herederos del fallecido Agustin Rodriguez Montalban. Actualmente su madre (única heredera) Alfonsa Montalban Serrano se encuentra en la Residencia de Mayores de Siruela. Nos comentan desde dicha residencia que los dos testigo podrían ser la propia directora (Marisa tlfno 630181685) y la trabajadora social del centro. Adjunto testimonios de sentencia de incapacitación, y nombramiento a esta Comisión Tutelar de Adultos, junto con certificado de defunción de Agustin, dni y libro de familia.','2');
