insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-07-29','miguel, me llama Jorge Calvo (tlfno 644340448) donde me dice que no puede interponer vía procedimiento desahucio porque el contrato establece que se someterá a arbitraje. Dicho arbitraje tendrá que ser en derecho (porque no el objeto del proceso es indisponible para las partes). Eso supone que tiene que hacer un requerimiento previo (volverá en agosto a enviar un burofax: que diga que hay que llamar a un arbitro que intervenga. Como el contrato no establece las condiciones de arbitraje, y como no contestará la inquilina, tendrá que solicitar por demanda al juez, para que decida. ************************************************ Todo se somete a la ley de arbitraje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2021-07-29','-Amalia , se recibe Informe social y documentos personales del IMSS Badajoz para hacer el inventario . La discapacidad es física , sordera . Guardo en su expediente toda la documentación para hacer el Plan de intervención . Se lo derivo a Iciar para unir al inventario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-07-29','TERESA Soy Maite Gómez, compañera nueva en el CTAEX. Nos surgen varias dudas respecto a la estancia de Beatriz en el domicilio familiar, que nos gustaría que nos comentaseis para autorizar la salida: • ¿ Beatriz expresa el deseo de querer pasar unos días con sus padres?. En la visitas que hace a su casa cuando va a ver a su hija, la madre no muestra mucho interés en Beatriz. • ¿Reúne condiciones adecuadas el domicilio familiar para la estancia de Beatriz?? • Los padres tienen que adquirir el compromiso de tomar las medidas de prevención del coronavirus recomendadas ; uso de mascarilla, medidas higiénicas y distanciamiento social. También tendrán la obligación de informar sobre las personas con las que haya tenido contacto durante al salida, a fin de que se pueda disponer de un registro en caso de detectarse algún positivo. Asimismo, los padres han de saber que en caso de contagio se tienen que hacer cargo de Beatriz hasta que pueda volver al centro. Este compromiso debe ir por escrito y firmado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-07-29','Ana: Envío correo a Choni (Ascensión Montero Pérez) T.S. del SSASB de Miajadas y responsable temporal de los PP.TT. (Tfno: 927 347 000 Ext.: 3401 e-mail: servicios.sociales@miajadas.org): Buenas tardes Choni, Te remito adjunta la citación de Esteve Pascual Ramos para valoración por el EVO en el CADEX el próximo día 12/08/21 a las 8:30 h. No sé si podrán acompañarle desde el recurso, sino, dímelo e intento gestionarlo con la Educadora del Programa de Apoyo Comunitario. Seguimos en contacto. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2021-07-30','TOD@S: en estos últimos 12 meses NO se ha producido ningún EMBARGO. ICIAR: tenemos una DEUDA con AEXPAINBA x importe de 1.470 €, que se corresponden con los siguientes conceptos: PAGO ATRASOS SEPTIEMBRE 2019 X 294 €. PAGO ATRASOS OCTUBRE 2019 X 294 €. PAGO ATRASOS NOVIEMBRE 2019 X 294 €. PAGO ATRASOS DICIEMBRE 2019 X 294 €. PAGO ATRASOS FEBRERO 2020 X 294 €. TOTAL: 1.470 € PAGAMOS A TRAVÉS DE TRANSFERENCIA 1 ATRASO CADA MES CON SU CORRESPONDIENTE CONCEPTO. HABLA PREVIAMENTE CON CENTRO','2');
