insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-07-30','Ana: Conversación con Paqui López, pareja de Félix (617 025 534): la documentación que enviaron por emial, no sirve, pues enviaron dos veces la misma hoja en la que no aparecían las cuantías relativas a la compra-venta del trastero. **Volverán a enviarlo de nuevo. ························ En cuanto a la vivienda de Félix, dice que allí no vive nadie, pero pide que no se dén de baja los suministros pues ella se encarga de la limpieza y mantenimiento de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-07-30','miguel, tras conversación telefónica con el abuelo le comento: 1 la documentación que me ha remitido todavía no me la han subido de registro de entrada. 2 quiere justificar los gastos que tiene su nieto (remitirá facturas y en un email concretará dichos gastos pues quieres se le suba la asignación mensual) 3 Hablarán durante Agosto con un abogado de confianza para decidir si van o no a impugnar la reclamación de la cuenta de los 140.000€. Así se lo hago saber al abogado de la contra parte, Carlos Jurado. Quedamos a prinicipios de septiembre donde la familia de Alejandro nos comunicará si acepta o no el acuerdo extrajudicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-08-02','miguel, recibimos email de la abogada Rocio: Buenas tardes Miguel, He recibido una llamada de una mujer que es la que está viviendo ahora en la casa de Damián junto con su hija y su nieta de dos años. Me dice que Antonio, que es el titular del contrato de arrendamiento y con quién yo he estado hablando todo este tiempo, es la ex pareja de su hija y padre de la nieta, pero que han finalizado la relación de pareja y se ha ido de la casa. Esta señora me pide un poco de tiempo para irse porque alega que lleva buscando casa y no encuentra por no tener salario fijo. Me insiste y me suplica que Damián le deje estar allí un tiempo y que estaría dispuesta a pagar hasta 550 euros mensuales. No sé si Damián está dispuesto a seguir alquilando un tiempo más o prefiere que interpongamos ya la demanda de desahucio. La señora insiste mucho y jura pagar religiosamente. Yo no tengo mucha confianza en que lo haga pero la decisión es de Damián. Espero vuestra respuesta para interponer o no la demanda el 1 de septiembre ( ya sabes que en agosto no podemos hacer nada) Saludos','2');
