insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-08-02','Ana: llamo de José Luis García, Secretario General de la Policía Nacional del Cáceres (927 626 548), me indican que está de vacacion,pero podrá atenderme el Inspector Raúl Ávila Guillén (927 626 558) quien tiene acceso al correo de José Luis. ·········· Raúl no sabe si José Luis habrá hecho alguna gestión al respecto, sugiere que se lo vuelva a enviar, pues aunque está de vacaciones sí que mira el correo. ···························································································································································································· Envío correo a José Luis, Secretario Gral. de la Policía (jose.garmu@dgp.mir.es): "Buenas tardes José Luis, Al no haber obtenido respuesta con respecto al correo que le envié el día 8/07, se lo reenvío de nuevo para preguntarle si ha podido hacer alguna gestión al respecto, pues seguimos pendiente de poder obtener un DNI o documento de identidad similar de Dª. Mª Rosario González Jorna, tutelada por la CTAEX. Disculpe la insistencia, pero como sabe es una cuestión que nos preocupa y llevamos meses intentando solucionar. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-08-02','miguel, llega sobre con varias sentencias (divorcio y liquidacion de matrimonio, de ejecución y ampliación de cantidad, la ejecución hipotecaria de la vivienda familiar). Remito el siguiente email a Patricia Bono (y reenvío copia a Alberto y Amalia): Buenos días, te adjunto la documentación remitida por tus padres para que la adjuntes a la documentación que te remití el otro día a efectos de que podáis hacer la consulta en un abogado y decidáis antes de principios de septiembre si aceptáis o no la propuesta de la otra parte acerca de la cuenta de los 140.000€. Comentarte que el viernes nos llamó el abogado de la otra parte y a parte de aceptar hasta principios de septiembre el plazo para que decidáis si iréis o no vía judicial con este asunto. Se ofreció a hablar con el abogado que designéis a efectos de aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-08-02','Ana: Correo de María González Palomo, TS Autismo Sur (teayudamos@autismosur.es): "Buenas tardes María, ¿cómo estás? Espero que bien. No sé si estarás de vacaciones. Por favor, ¿Podrías facilitarme el nº de contacto de PNC-Málaga? No consigo hablar con nadie. Gracias y un saludo." ················· María me contesta que no tiene nº de contacto de PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-08-02','Ana: Llamada de Clara, TS del C.Salud (53107), Juan no ha pasado por el C. Salud para el volante de la ambulancia para acudir mañana a la cita en Salud Mental. Ha hablado con Teresa- Ed. Futuex, y ésta le dice que no ha habido manera de convencer a Juan para que acuda a la cita de mañana. ····· *Mañana llamaré para hablar con el Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-07-29','Ana: Conversación con Teresa-Futuex; La visita con Juan fue bien, compraron la ropa y otras cosillas que le venían bien. Cree que finalmente asisitirá a la cita de Psiquiatría el próximo martes 3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-08-02','Ana: Envío correo a Toni-Futuex: "Buenas tardes Toni, Espero que tus vacaciones bien. Teníamos algunas cuestiones pendientes que nos planteaba Alberto: “Ana: • NO tenemos conocimiento de los CONSUMO: AGUA + ELCTRICIDAD + GAS...y estas 2 últimas facturas son de 108,85 y 142,25 respectivamente (sólo de luz). • No sabemos quién paga el agua. • No sabemos quién paga el gas • Xfa...coméntaselo a TONI para ver si nos puede informar en la próxima visita que le haga.” En cuanto al presupuesto que habíamos comentado para hacer una limpieza en profundidad en el domicilio, no sé qué decirte, pues como me comentó Teresa la semana pasada, la casa no reúne condiciones, no sólo es cuestión de limpieza e higiene… En este caso, ¿qué reformas son las que habría que hacer? ¿sería posible hacer un informe por escrito sobre la situación de la vivienda? En función de esto vemos si se piden presupuestos o qué hacemos. Por otra parte, habría que valorar las conductas desadaptativas… Ya me vais diciendo. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2021-08-03','-Amalia , email de Mari Luz Madrigal , ya se está gestionando revision PIA para que pase a Ctro. residencial . Buenos días, considero que desde el centro estáis actuando de manera adecuada dentro de vuestras posibilidades en relación a los problemas de salud de esta usuaria. Teniendo en cuenta su edad y patologías orgánicas, considero que podría ser beneficioso para ella a corto- medio plazo su paso a un centro de mayores, en dónde pueda contar con el apoyo de profesionales sanitarios de los que los CRR no disponen. Está valorada con Grado I de Dependencia, por lo que sería necesario solicitar una revisión de Grado y PIA, enfocado a su posible paso a la red de mayores. Vamos hablando a ver cómo evoluciona y que opina la Comisión T. Saludos, M.Luz Madrigal González Sección Programas Asistenciales Telefono 924003893-64898','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2021-08-03','TERESA TELEFONO MADRE JOSE FLORENCIO 642550070','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2021-08-03','Belén. Desde hace una semana se está intentando localizar a la TS del centro sin éxito. Se le envía un correo (rguadiana@caseresidencial.es) solicitando nos remitan Informe Social para el segundo requerimiento de la rendición de cuentas anual de la administración de los bienes de la tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-08-03','Buenos días os adjunto email y documentos que ha remitido la familia de lo que ya sabíamos, derechos de alimentos, pensión compensatoria, ejecución por incumplimiento del padre y ejecución hipotecaria de la vivienda. Se lo he remitido como podéis ver en el email de más abajo a Patricia Bono para que lo imprima junto con lo que le remití que nos dio el abogado de la contraparte para que se asesoren con un abogado y decidan antes de principios de septiembre si van o no a juicio (tal y como hemos ya hablado con el abogado de las hermanastras Carlos Jurado).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-02','-Amalia : El día 23 , Mayte ( jefa de sección) habla con el director del CAM sobre el caso , para comunicarles que en breve se haría el traslado . Sin embargo , hoy nos acaba de informar Manuela , que desde el viernes 23 , Juan José fue derivado del centro de menores y reside con su hermano Cristian en la casa familiar de Oliva de la Frontera . Cristian llama constantemente al Dtor. pq no tiene capacidad para atenderlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-03','-Amalia y Mayte nos reunimos con Soraya Masa , se confirma que ingresará en el CAMP de D. Benito a principios de septiembre , que regresa la psicologa de vacaciones para garantizar la adaptación al centro. Mientras tanto , hay que presta apoyo a Cristian para que durante el mes de agosto pueda permanecer con él . Activaré apoyos desde SSASB , Delegada Tutelar ...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2021-08-03','email de Alberto para la venta de la vivienda en Puebla de Sancho Perez: TERE: comunica que hay una persona interesada en compra vivienda tutelada: Ctra. Zafra-Medina s/n - Puebla de Sancho Pérez. ALBERTO: comunica que tiene recursos suficientes. TODOS: ACORDAMOS PROCEDER A POSIBLE VENTA DADO QUE YA CONTAMOS CON COMPRADOR. TERE: solicitará oferta formal de compra...CTAEX no aceptará menos del valor fiscal Junta Extremadura (34.000 € aprox.) MIGUEL: AUTORIZACIÓN JUDICIAL VENTA: Miguel buscará ABOGADO para que tramite la solicitud de AUTORIZACIÓN VENTA en Juzgado. MIGUEL: buscará PERITO en caso de que compradorá no aporte la valoración de un técnico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-08-03','miguel, para la comunicación al juzgado de los reintegros realizados indebidamente por el tutelado se adjunta los pasos a seguir por email de Alberto: Estamos reunidos Tere y yo: varias cuestiones relacionadas con los REINTEGROS INDEBIDOS que ha realizado este tutelado: Cuestión: ha realizado un reintegro NO autorizado en LIBERBANK x 1.200 € el pasado 15/07/2021. Ya había hecho otros 2 reintegros indebidos x 3.200 € en CAIXABANK...cuenta que cancelamos para abrir en LIBERBANK. • ÁREA JURÍDICA: os adjunto reclamación enviada a CAIXABANK y su correspondiente contestación. o Con respecto al reintegro indebido de LIBERBANK, Iciar se pondrá en contacto mañana con el banco. o La idea saría comunicar al JUZGADO LA ACTUACIÓN DEL TUTELADO informando de los reintegros y adjuntando también un INFORME SOCIAL del centro sobre el comportamiento del tutelado (ha enganchado al consumo a un compañero del centro que llevaba 11 años sin consumir). • TERESA: habla con centro, si lo ves adecuado, y que nos hagan un INFORME sobre el tutelado y su comportamiento. • TERESA: quizás el centro tenga alguna idea nueva de como actuar con el tutelado...que nos lo remitan y lo vemos. • ICIAR: ponten en contacto con oficina LIBERBANK y que nos den una explicación sobre lo ocurrido: REINTEGRO SIN AUTORIZACIÓN. (con Liberbank actuemos con cuidado). ******************************************************** En el día de hoy Teresa me da informe social y Alberto los 3 reintegros indebidos (los dos primeros fueron reclamados a la Caixa, la cual se disculpó). Prepararé y remitiré al juzgado comunicación de esta situación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-08-03','-email de TS de ESM Valdepasillas : Buenas tardes Amalia, la verdad es que por si era poco, más complicaciones y, más también, tenemos que andar conteniendo enfados extras., sobre todo tu. La madre vino a los dos días por los informes, estuvimos, otra vez, entrenado lo que tenía que decir y hacer si llaman al 112, y que le enseñara tb el informe último de la fuga, para que se quedara un policía con él. Estuve hablando con el médico de familia para que estuviera al tanto, por si en algún momento se dirigían a él, que supiera de qué iba el caso, y que mirara la jara, porque él no lo conoce como paciente. Un saludo y buen finde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2021-08-04','TERESA TERE: comunica que hay una persona interesada en compra vivienda tutelada: Ctra. Zafra-Medina s/n - Puebla de Sancho Pérez. ALBERTO: comunica que tiene recursos suficientes. TODOS: ACORDAMOS PROCEDER A POSIBLE VENTA DADO QUE YA CONTAMOS CON COMPRADOR. TERE: solicitará oferta formal de compra...CTAEX no aceptará menos del valor fiscal Junta Extremadura (34.000 € aprox.) MIGUEL: AUTORIZACIÓN JUDICIAL VENTA: Miguel buscará ABOGADO para que tramite la solicitud de AUTORIZACIÓN VENTA en Juzgado. MIGUEL: buscará PERITO en caso de que compradorá no aporte la valoración de un técnico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2021-08-04','Belén. Se llama al CSS de Plasencia (927428800) para hablar con Prado TS y comentarle que Ángel está tutelado y estamos en proceso de inventario. Pero que pueden ir eleborando los gastos mensuales y de bolsillo que vaya a necesitar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2021-08-04','Belén. Me comenta Prado (TS) que Margarita va a pasar a larga estancia y el médico le ha propuesto comenzar un tratamiento de parches de nicotina para reducir el consumo de tabaco. Nos tienen que mandar presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-08-04','miguel, recibo email de Patricia Bono: Gracias Miguel por remitirme toda la documentación. Nuestro planteamiento es que de ese dinero se debería descontar la cantidad que en su día reclamó mi hermana a su exmarido por no cumplir con la sentencia de divorcio. Estamos intentando hablar con la abogada que en su día llevó ese tema para exponerle todo el caso y ver si habría posibilidad de cobrar esa deuda. ******************************************* mi contestacion: Buenos días imagino que hasta primeros de septiembre no lograreis hablar con la abogada. Una vez habléis con ella avisadme y si lo creéis conveniente se pueden poner en contacto ambos abogados para aclarar cualquier cosa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2021-08-04','Belén. Recibo llamada de Vanesa(trabajadaora del centro) para informarme que Gloria la TS está de vacaciones y no se incorpora hasta el 16 de agosto. Que en esa semana intentará mandarnos el informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-08-04','miguel, recibo email de la abogada Rocio: Buenos días de nuevo Miguel, No logro contactar contigo por teléfono. La señora que está en el piso de Damián no para de llamarme insistiendo en que quiere pagarle los meses que esté allí hasta que encuentre algo. La demanda de desahucio no la podemos interponer ya hasta septiembre y una vez iniciado el procedimiento pueden solicitar una suspensión del lanzamiento por vivir en ella una menor y que intervenga servicios sociales , con lo cual va a tardar mucho en recuperar la vivienda pues todo va con muchísimo retraso. Puede que le interese hacerle un contrato a ella por unos meses y que le pague mientras tanto. Decidme lo que decidáis para actuar de una forma u otra porque la señora no para de llamarme casi a diario. ********************************* antes de contestar se lo reenvío a Amalia y Alberto: Buenos días, he recibido email de la abogada que está tramitando el desahucio de la vivienda de Damian en Málaga. Entiendo que debería seguir adelante con el desahucio, claro está que es posible que desde Servicios sociales lo paralicen hasta que esta señora encuentre algo o como mínimo ganará tiempo (no sé cuánto). La opción alquiler yo no la valoraría por que la nueva ley establece una duración para los contratos de alquiler de 5 años, además de la falta de seguridad de pago de la misma. Si lo veis bien, le digo a la abogada que continúe con el desahucio tarde lo que tarde? ************************************************** llamo a Rocio, la abogada y la hago saber que no queremos alquilar y que continúe los trámites de desahucio tarde lo que tarde (serán meses debido al RD que impedian los desahucios, unido a que hay una menor en la vivienda y recurririan a servicios sociales)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-08-03','miguel, recibo email del asesor del tercer hermano no tutelado por la Comisión (Carlos Mora email:gerencia@casesores.com, tlfno 924-256306 y 661-761502) Buenos días, A continuación reenvio correo recibido de Agustin Caballero: Para poder hacer la declaración de herederos necesito: Libro de familia Certificado de defunción Datos de los 3 herederos (nombre, D.N.I., domicilio, profesión y estado civil) Certificado de últimas voluntades Dos testigos que comparezcan a la firma junto con la heredera que vendrá a firmar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-08-04','miguel, contesto al asesor del otro hermano, Carlos Mora: Buenos días, desde la Comisión ya estamos trabajando en la presentación del impuesto de sucesiones, quedando pendiente la Declaración de Herederos. Para dicha realizar dicha declaración necesitaríamos que se firmarse en una notaria de Badajoz, a ser posible la de Valdepasillas de D. Carlos Alberto Iñiguez ya que los dos hijos tutelados por esta Comisión Tutelar de Adultos se encuentran residiendo en Centro cerca de allí. Si es preciso una vez concierte cita con su cliente en la notaria indíqueme el oficial que la preparará para ponerme en contacto con él. En cuanto a lo solicitado en su email le indico que los testigos serían el hermano del fallecido y su esposa (Severo Martinez Ortega tlfno 924-496151). Una vez acuerden con la notaria fecha y hora avísennos para que podamos citar a los otros dos hijos tutelados por esta Comisión Tutelar de Adultos, Juan José Martínez Pérez con nif 08866184Y y Antonio Martínez Perez nif , solteros y con domicilio en el Centro Ntra Señora de la Luz sito en c/ Godofredo Ortega y Muñoz 3, 06011, Badajoz, sin profesión ambos. Por otra parte estamos intentando localizar el libro de familia aunque me indican que será complicado. Adjunto certificado de últimas voluntades y de defunción de D. José Martínez Ortega.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2021-08-04','TERESA ENVIO DOCUMENTACION SOLICITADA POR MARIBEL MESA PARA SOLICITUD EN CENTRO RESIDENCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2021-08-04','TERESA Ahí va el informe médico, ahora sí en el modelo que nos enviaste. Hoy he aprovechado para echar cuentas con él, porque el lunes empiezo vacaciones y quería dejarle a las compañeras la información del dinero que iba a necesitar y cuándo vendría por el centro. En principio, entre alquiler, dinero para la compra de comida y gastos semanales, nos salen unos 315€ al mes, por lo que le quedarían unos 85€ al mes para las facturas que vayan llegando. Además del dinero que vais ahorrando vosotros, él tiene aquí en el centro otros 300€ ahorrados para gastos imprevistos, por ejemplo, éste mes tuvo que mandar a arreglar uno de los audífonos y le ha costado 150€, o para comprar ropa, zapatos, etc. He quedado con él en que el lunes día 30 de agosto, volvemos a vernos y repasamos por si ha llegado algo nuevo. Te paso el contacto de otras dos compañeras por si necesitas algo durante el tiempo que estaré fuera: • Elisabeth Ballesteros (Directora): meballesteros.cdmeba@caritas.es - 607580199 • Ana Isabel Tena (Técnico Social): aitena.cdmeba@caritas.es - 673375323','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2021-08-04','TERESA TELEFONO RAMON 623273747','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2021-08-05','TERESA A PARTIR DE AHORA CUALQUIER RECIBO QUE TUTELADO PASE A SU CCC SI AUTORIZACIÓN TENDRÁ REPERCUSIÓN SOBRE SU REINTEGRO PERMANENTE (ACTUALMENTE 90 €/SEM): SE REDUCIRÁ EL REINTEGRO PERMANENTE EN EL IMPORTE CORRESPONDIENTE AL RECIBO/S QUE HAYAN SIDO CARGADOS (ESTA REDUCCIÓN SE DISTRIBUIRÁ EN VARIAS SEMANAS SI EL IMPORTE ES MUY ELEVADO)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-05','Amalia : recibo email con los datos de su hno. que he pedido al Dtor del CAM Buenas tardes Amalia. Como te he comentado por teléfono te detallo los datos del hermano de Juan José para que iniciéis el apoyo hasta tanto se produce el ingreso en el CAM de Villanueva. CRISTIAN MESA CANDIL C/ Federico García Lorca, N.º 11 Oliva de la Frontera 06120 Teléfono 642496729 Estoy a vuestra disposición para todo aquello que necesitéis. Muchas gracias. Un cordial saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-07-30','miguel, llega desde servicios contenciosos sentencia de juicio verbal de desahucio 476/2020 donde la demandada es la recién tutelada, de la cual estamos preparando el inventario. Dicha sentencia será firme a partir del 29-9-21. Hablo con el Jzdo nº3 de Plasencia y les comento que la declaran en rebeldía en el procedimiento y por tanto no tiene representación procesal. En la sentencia la condenan en costas procesales, multa de 480€ y desahucio con lanzamiento forzoso en 15 días desde que sea firme la sentencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-08-05','miguel, comento con Ana la sentencia de desahucio y me confirma que la tutelada se encuentra en Centro Residencial de Mayores. La informo de que habría que retirar sus enseres antes de que sea firme la sentencia y si es posible devolver las llaves a la arrendadora','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-08-05','miguel, hablo con CRR Plasencia (Carol)acerca del accidente del curatelado, le comento que recapitulen todas las facturas de los gastos que vaya generando hasta la curación con secuelas o sin ellas del curatelado a efectos de que en el procedimiento penal (que habrán de notificarnos desde el juzgado y en el que nos personaremos-solicitaremos nombren abogado que le represente)se contabilicen el total de gastos e indeminación. Me comenta que actualmente se está recuperando en un centro especializado. *************************************** Hablo con Belén Ts para que hable con el Centro, donde actualmente se encuentra el curatelado, para que les comente que pidan facturas de cualquier gastos relacionado con este accidente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-08-05','Ana: Se adelanta la fecha de salida de Aarón a casa de su padre a este fin de semana (del 6/8 al 9/8), para que no coincida con las fiestas del pueblo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2021-08-05','TERESA VIVE EN AZUAGA LA VIVIENDA PRESENTA ALGUNAS DEFICIENCIAS ADEMAS DE ESTAR ALEJADA TIEEN DOS HIJOS RECIBE LA VISITA DE SU HIJA EL FIN DE SEMANA Y ES LA QUE SE ENCARGA DE LA VIVIENDA RECIBE EL APOYO DE FUTUEX PERCIBE PENSION DE VIUDEDAD 522.50 SALDO 11000','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-08-05','miguel, envío a por carta solicitud de aclaración de la compraventa del vehículo rover 25 al tutelado y le adjunto fotocopia de la compraventa realizada en el 2018, caso que no conteste le aviso procederemos a su retirada y envío a desguace o venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-08-05','Ana: Recibo llamada de un taxita de Alcuestar, tiene una factura de un traslado a cita médica de junio pendiente de abono. *Se la dió a Gloria-Futuex. Aquí no ha llegado. *Corroboro el servicio con la Directora de la Residencia. ········· Pido a Toni-Futuex que envíen la factura. ··········· **Se la paso a Alberto para que lo abonen en cuanto puedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-08-05','miguel, me remite Ana Ts, email de Toni (Futuex): Tal y como se solicitó, se ha intentado investigar y recabar datos sobre los propietarios del bloque de Ramón Civantos, se creyó que lo más oportuno sería hacerlo a través del registro de la propiedad, por lo que se acudió, en compañía del tutelado, a solicitar nota simple de cada vivienda y así conocer a nombre de quién figura cada vivienda; se adjunta (en documento a parte) toda la información conseguida. También, se habló con el responsable del taller donde se tiene recogido, de manera voluntaria, el coche de Ramón, para la realización de un presupuesto por valorar un posible arreglo, desde el primer momento, Nica comenta que es una reparación muy cara y no merece la pena por los años y condiciones que tiene el coche; también se adjunta en documento a parte. Nica ruega que se tome determinación lo antes posible, pues desde medioambiente le han vuelto a llamar la atención y le van a terminar denunciando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-08-06','miguel, mi contestación a Toni (Futuex), Ana Ts, y Alberto como representante de la parte económica: Buenos días, añado a Alberto al email como representante de la parte económica. En cuantos a las dos cuestiones pendientes de este tutelado comentar lo siguiente: 1.- En cuanto al vehículo, viendo el presupuesto remitido por el taller para este vehículo, cuya matrícula indica que el vehículo tiene 48 años (matriculado en 1973), no se va a proceder al arreglo del mismo pues el valor del mismo debe ser inferior al de su arreglo, por lo tanto Tony si es posible indicadle al del taller que lo envíe al desguace (ellos deberían hacerse cargo de darlo de baja). 2.-Desperfectos en el tejado del edificio de la vivienda donde reside el tutelado. Corre prisa el arreglo de la misma. Es necesario identificar a todos los vecinos (sólo nos remites la nota simple de los del bajo derecha). No necesitamos notas simples, únicamente los nombres y apellidos de cada vecino y con qué vivienda se corresponden. He intentado hablar de nuevo sin éxito con Paco Ortes (la empresa que hará la reforma), lo seguiré intentando. Él quedó también en hablar con los vecinos y darles el mes de julio de plazo para que nos dijeran si iban o no a arreglar el tejado. Aunque decían que no podían arreglarlo hasta que no se constituyeran en comunidad, ya le dije yo que eso no es necesario porque la cuota de participación de cada vecino en cuanto a los gastos que tendrán que soportar para el arreglo del tejado viene reflejada en el nº de finca registral de la finca matriz (también pueden verlo en la escritura de división horizontal de cuando se dividió por viviendas el bloque). En definitiva que por favor Toni, indicadnos lo antes posible (ya que este tutelado vive en condiciones insalubres en esa vivienda) quiénes son el resto de vecinos. Por nuestra parte, si a Paco Ortes no le han confirmado que asumen la deuda el resto de vecinos y comienzan los arreglos, procederemos a nombrarle un abogado para que interponga la correspondiente demanda en el juzgado (para lo cual nos pedirán identificar pisos y vecinos propietarios del mismo, siendo esta la información que Toni y no sé si Paco Ortes nos deberán facilitar).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='ORTEGA'and apellido2='SEVILLA'),'2021-08-06','TERESA RESIDE EN EL CENTRO RESIDENCIAL Y FAMILIAR NUÑOMORAL PRESENTA DISCAPACIDAD FISICA Y MENTAL, 42 AÑOS ESTA BIEN ADAPTADO Y TIENE BUENA RELACION CON LOS COMPAÑEROS, PARTICIPA EN LOS TALLERES. NO TIENE RELACION CON LA FAMILIA PERCIBE PNC 402.80 SALDO 3181.93€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-08-06','-Amalia , envio email a TS del ctro. penitenciario: Buenos días , se ha autorizado la petición , se le va a hacer transferencia a cuenta peculio para ropa y TV . Tiene el DNI caducado , necesitariamos que se le renovara . Desconozco el procedimiento desde centro penitenciario. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2021-08-06','TERESA RENDICION RESINDE EN LA RM PADRE LEOCADIO ESQUIZOFRENIA, DETERIORO COGNITIVO, TRASTONO DE CONDUCTA CON ALTERACIONES ESPORADICAS ESTA BIEN ADAPTADO Y TIENE BUENA RELACION CON LOS COMPAÑEROS RECIBE ALGUNA VISITA Y LLAMADAS DE LOS HERMANOS PERCIBE IPT 859 SALDO 68000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2021-08-05','Belén. Se envía autorización para la retirada de 100€/mes para dinero de bolsillo y todos los gastos que pudieran sugir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-08-06','TERESA RESIDE EN EL CAMPF DE DON BENITO JUNTO A SU HERMANO SERGIO TIENE DEFICIENCIA MENTAL SEVERA CON UN 81% DISCAPACIDAD NO HAY RELACION FAMILIAR PERCIBE 604 SALDO 10000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-08-06','Ana: Ante el correo de Toni-Futuex, remitido ayer a última hora y que guardo en el expte. digital. Envío el siguiente correo a Alberto, Miguel y Maite - CTAEX: "Buenos días, Como sabéis este caso es complejo y aún nos quedan cuestiones pendientes. Miguel: Aquí tienes documentos (Escritura e impuesto de transmisiones) de la vivienda de la C/ General Margallo (Cáceres). Al parecer sigue pendiente de poder registrar en registro de la propiedad. Alberto: los suministros de la vivienda en C/ Caballeros de la Virgen en Guadalupe son los siguientes: • Contrato de luz con Iberdrola, que solicita sean domiciliados, cuyos requerimientos se han enviado a la comisión. • Contrato del agua, es abonado por su padre. • Y el gas que utiliza es gas butano, que compra bombona según demanda al distribuidor de la localidad. Según el propio Miguel, en la vivienda de la C/ Margallo nº 3 en Cáceres, no tiene de alta otros suministros. *En cuanto a la MULTA que pusieron a su hija (residente en Madrid) por desobediencia 242,3€, Miguel quiere pagárselo. Por un lado, yo no lo veo, pero por otra parte, se aprobó en su día darle una ayuda de 50 € todos los meses (propuesta de Miguel también), pero no se le está haciendo, si no me equivoco, porque no disponíamos de su nº de cuenta. No sé qué opináis. Desde luego él quiere ayudarle y, si no me equivoco, puede hacerlo. Maite, del resto de cuestiones ya hablamos tú y yo, te he puesto en copia para que vayas conociendo también este caso. En función de la próxima cita médica, de la medicación y evolución, habrá que decidir, si intentar convencerle para que acepte Ayuda a Domicilio, que a día de hoy no quiere, o plantear solicitar internamiento involuntario… La casa, al parecer también requiere alguna reforma, además de mayor limpieza, pero él no ha permitido nuevas fotos y valoración en la última visita de Futuex. Puedes leer el informe adjunto. Seguimos. Buena mañana." ··································································································································································································· Envío correo a Clara, TS C.S. Guadalupe (isabel.garcial@salud-juntaex.es): "Buenos días Clara, La coordinadora de Teresa (Programa de Apoyo Comunitario - Futuex), me informa de que es imposible que otra compañera acompañe el día 11 a Miguel a la Consulta en Salud Mental. No obstante, ya han hablado con el Dr. Jiménez Cano al respecto y con el hijo de Miguel, quien en teoría acudirá acompañarle. El doctor ya lo sabe según me dice Toni (Coordinadora). Esperemos que así sea. Por otra parte, dada la dificultada para el control de la toma de medicación de este paciente, y las dudas de si lo estará tomando correctamente, el Dr. Plantea reajustar la medicación y pautarle un inyectable. Pongo en copia a la compañera Pilar para que esté al corriente. Un saludo y buen día a las dos." ······························································································································································································ Correo-e de Toni - Futuex: "Hola Ana, confirmado que irá en bus, no tiene problema en la gestion autonoma de este desplazamiento, de hecho en ocasiones se desplaza a cacers por otros motivos, y confirmado tb que el hijo lo acompaña. El problema no es con Miguel el asistir a la cita, sino mas bien la adherencia al tratamiento, a ver que tal..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-08-06','miguel, contesto a loli de la notaria de Herrera del Duque(notariaherreraloli@gmail.com): Buenos días, adjunto dni de la tutelada, de su marido, junto a su certificado de defunción y escrituras de herencia, y escrituras de liquidación de su herencia (+), su hijo Juan Felipe (+) tanto su dni como su certificado de defunción y declaración de herederos, mientras que del hijo Agustin (+) remito dni+ certificado de defunción. Juan Felipe tiene hecha la declaración de herederos que adjunto y su viuda (sin hijos), tiene presentado en la oficina liquidadora de Herrera del Duque a Liquidación el Impuesto de Sucesiones. El representante de la Comisión Tutelar de Adultos por delegación del Consejero José Mª Vergeles, es el Gerente del SEPAD José Vicente Granado Granado (adjunto dni y publicación de cargo y delegación en DOE). Necesitamos nos confirme si es necesario la presencia del Gerente el día de la firma de la Declaración de Herederos, (representante de la Comisión Tutelar de Adultos), en cuyo caso tendrán que indicarnos si es posible ratificar dicha escritura de Declaración de herederos en una notaria de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-08-05','-Amalia : se recibe email de TS del hospital de Mataró donde está ingresado en la UHB , internamiento involuntario tras brote psicotico. Ya no tiene relación sentimental con Joaquina , que tb es paciente de ese hospital . Lo encontraron en Barcelona con un brote y fue derivado a ese hospital que es el que le corresponde según su lugar de residencia , el que aparece en su DNI es el de los padres de Joaquina. Lo han comunicado al juzgado que corresponde por residencia. Quieren hacer traslado a la UHB del H. Mérida. Le vuelvo a escribir tras conversacion con Soraya Maya para que nos faciliten informacion que derivar al SES De: Pou Canales, Noemi >npou@csdm.cat> Enviado el: lunes, 2 de agosto de 2021 13:18 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: PERSONA TUTELADA INGRESADA EN EL HOSPITAL DE MATARÓ Buenos días, He intentado contactar con ustedes telefònicament pero no ha sido posible. Quería hablar con los referentes tutelares del Sr. Ildefonso García Rodríguez (DNI: 80044285F). En estos momentos se encuentra ingresado en la unidad de psiquiatria del Hospital de Mataró. Mi teléfono de contacto es el 663 96 79 96. Quedo a la espera de su respuesta. Un saludo, Noemi Pou Canales Responsable de Treball Social Treballadora Social Sanitària Consorci Sanitari del Maresme Telf: 93 741 77 00 ext.1513 Mòbil: 663967996 npou@csdm.cat','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-08-05','miguel, me pide loli de la notaria de Herrera del duque: Buenos tardes, estamos revisando la documentación que nos ha enviado solicitando Acta de Declaración de Herederos de Don Agustin Serrano Montalban, ademas de la documentación enviada falta, Certificado de defunción del padre, y del hermano del acusante, además es necesario la fotocopia de d.n.i. tanto de la tutora como de los dos testigos... cualquier otra cuestión le hablamos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='ARNOSI'and apellido2='PEREZ'),'2021-08-06','TERESA RENDICION JUAN JOSE RESIDE EN EL CAMPF DE DON BENITO OCUPA PLAZA RAL TIENE UN 81% DISCAPACIADAD RETRSO MENTAL SEVERO TIENE CONTACTO PUNTUAL CON SU FAMILIA DE MADRID Y LA FAMILIA QUE TRABAJA EN EL CIRCO LO VISITA CUANDO EL CIRCO ESTA EN LA CIUDAD PERCIBE ORFANDAD 472 Y PF 399 SALDO 9000','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-08-06','Belén. Se envía correo a la inmobiliaria (info@fincasi.es) informando que el mobiliario de la vivienda va incluido en la venta y preguntando si tienen algún posible comprador o alguien interesado en la misma.............. Me contesta Emiliano (Inmobiliaria):hola Belén, pues hemos ido a enseñarla a cuatro interesados, pero después de ver el estado en el que está la han descartado. Tan solo ayer por segunda vez se la enseñamos a una pareja con sus padres y me van a pasar una oferta, es lo que me dijeron ayer, yo te la haré llegar para que toméis una decisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-08-06','Belén. Se llama a la residencia Ntra. Sra. de Guadalupe de Bohonal de Ibor (927574262) y se habla con Mario (administrativo) para decirle que nos mande factura de todos los gastos que genere Jose Manuel durante el proceso de recuperación (farmacia, acompañamiento,...)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-08-06','Ana: Envío correo a Clara, TS C.S. Guadalupe (isabel.garcial@salud-juntaex.es): "Buenos días de nuevo, Clara, Finalmente no he llamado al Dr. Jiménez Cano en relación a Juan Chamorro, pues según comunicaciones tanto de Pilar Martín, compañera de Salud Mental, como de Toni, coordinadora del Programa de Futuex, informando de que el Dr. finalmente ha propuesto solicitar nueva cita para el mes de septiembre en el horario que mejor le venga a él. Así que es cuestión de esperar al mes que viene. Por otra parte, el Psiquiatra tampoco considera necesario que lo comuniquemos aún al Juzgado. Por cierto, ¿cuándo te vas tú de vacaciones? Yo no estaré las próximas 2 semanas. Un saludo y cuídate!"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICANOR'and edp.apellido1='IÑAÑEZ'and apellido2='CORTES'),'2021-08-06','El paciente Nicanor Iñañez Cortés ha tenido que ser intervenido quirúrgicamente esta mañana de urgencia, por lo que os comunico que la Directora ha firmado el Consentimiento informado. Un saludo, Maribel','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-08-06','miguel, contestación de la inmobiliaria (Emilio info@fincasi.es) Hola Belén, pues hemos ido a enseñarla a cuatro interesados, pero después de ver el estado en el que esta la han descartado. Tan solo ayer por segunda vez se la enseñamos a una pareja con sus padres y me van a pasar una oferta, es lo que me dijeron ayer, yo te la hare llegar para que toméis una decisión. Saludos. FINCA INMOBILIARIA Emiliano Delfa Tlf.- 654552843','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-08-05','Ana: Correo de Pilar Martín, TS de ESM-CC y llamada e Clara, TS del CS Guadalupe con el mismo mensaje: Finalmente Juan no acudió a la cita en salus mental. ·············· Pido a Pilar que nos remita un informe, aunque sea SOAP, notificándolo para poder comunicarlo al Jdo. ·············· Correo de Toni-Futuex: Y tal como estaba programado, nos ponemos en contacto con el Dr. Jiménez Cano, hoy mismo, martes 03 de agosto, para comunicarle que el paciente Juan Chamorro no acude a consulta presencial. Le confirmamos al psiquiatra que su tratamiento de inyectable se mantiene en pauta correcta todos los meses (5 de julio última cita, siguiente el 13 de Agosto). Así mismo él asegura que toma su pauta oral: Rivotril y Olanzapina. Juan se encuentra con su discurso recurrente: medicina nazi, su hermana debe estar en la cárcel, dinero que le han robado y que le quiten la curatela. Es cierto que no existen incidencias en relación a los vecinos, que sigue su rutina diaria, paseos por el centro del pueblo y poco más de actividad. Realiza comprar semanal en el supermercado Dia, así como un jueves cada quince días, se le entrega desde la parroquia un vale para canjear por productos perecederos en el mismo supermercado. El Dr. Jiménez Cano, nos comunica que se solicite nueva cita presencial desde este equipo de apoyo social comunitario de Badajoz, para mediados de septiembre, en día y hora que se pueda adecuar a Juan chamorro. Y que se controle la administración de su inyectable cono se viene haciendo en contacto con su centro de salud de Guadalupe." ·········· En vista de la nueva propuesta de cita, esperaremos a septiembre a ver si acude. *Guardo nota en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-06','EMPRESA DE AYUDA A DOMICILIO QUE PRESTARÁ APOYO LOS 25 DIAS DE AGOSTO EN EL DOMICILIO , SE HA ACEPTADO PTO. DE 1500€ CON FACTURA . "LA SALVE " , DTRA. NEKANE TF 691577307 SE CONTRATAN 8 H AL DIA , SABADOS Y DOMINGOS INCLUIDOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-08-06','Ana: Envío a Alberto presupuesto de TV para la habitación de Isabel, que me remite Jose, Director de la Residencia de Jaraicejo. Por mi parte, Ok a la compra. Pido que se lo confirmen. ············· Respuesta de Alberto: "ANA: OK A PRESUPUESTO TV X 190 € ICIAR: XFVOR, HABLA CON DIRECTOR CENTRO (josevillegassanchez356@gmail.com) E INFÓRMALE DE QUE SI PUEDE COMPRAR LA TV. ICIAR: FORMA DE PAGO. COMO TU LO VEAS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-08-06','miguel, contestación a Ana Ts con copia a Maite: Buenos días, por lo que puedo ver no nos remitieron nota simple de esta vivienda con lo que es posible que no esté presentada para inscribir en el registro de la propiedad, aunque sí aparece en c/ General Margallo la titularidad del tutelado en Catastro. Para su inscripción se requiere presentar en el Registro de la propiedad nº2 de Cáceres la escritura original de compraventa de la notaria + modelo 600 (pago del impuesto de transmisión patrimonial que fue abonado 11-1-2018) Lo suyo sería que algún conocido o familiar se acerque a inscribirla al Registro nº2 de Cáceres. El motivo de su falta de inscripción debe ser porque le han debido de girar una complementaria entre el valor escriturado de 35.000€ y el fiscal(que puede haber acabado en embargo) ya que el valor fiscal de la finca es de 79.833,09€ (según indica la página de valoración de bienes inmuebles de la Junta de Extremadura). 2.-Por otra parte tengo pendiente de que Toni (Futuex) conteste a un email de 2-7-2021 para que averigue quién tiene el coche del tutelado y a qué tipo de acuerdo llegaron ya que según el tutelado el vehículo lo entregó para compensar una deuda, pero desconocemos el contenido de ese acuerdo y por tanto quién tenga el coche tiene que acreditarnos esa deuda y si finalmente es correcto el cambio tendrá que inscribir su titularidad en la DGT.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-08-06','miguel, remito al Jzdo nº2 Coria escrito de comunicación consistente en 3 reintegros que ha hecho el tutelado sin autorización','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-08-06','miguel, Ana Ts me pide que envíe directamente email a Toni (Futuex) y así lo hago: Buenas tardes Toni, me pide Ana Ts que te conteste en relación al tutelado arriba indicado. 1.-En relación a la vivienda de c/ General Margallo, aparece la titularidad del tutelado en Catastro pero no en registro de la propiedad. Para su inscripción se requiere presentar en el Registro de la propiedad nº2 de Cáceres la escritura original de compraventa de la notaria + modelo 600 (pago del impuesto de transmisión patrimonial que fue abonado 11-1-2018) Lo suyo sería que algún conocido o familiar se acerque a inscribirla al Registro nº2 de Cáceres, previo Futuex intente localizar dicha escritura de compraventa y modelo 600 del pago del impuesto originales. 2.-Con fecha de 2-7-21 te remití un email para localizar quién tiene el vehículo del tutelado, ya que tendrá que acreditarnos qué deuda tenía el tutelado con él y nos lo acredite. Caso contrario tendrá que devolvernos, las llaves, documentación y vehículo. El mismo sigue apareciendo en DGT a nombre del tutelado con lo que debéis de preguntar también a quién lo tenga porqué no ha hecho el cambio en la DGT. Según nuestros cálculos dicho vehículo a fecha actual vale al menos 7.000€. Quedo a tu disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-08-06','miguel, remito a la notaria de herrera del duque (Loli) documentación que me requiere para que prepare la Declaración de herederos de Agustin (hijo de la tutelada) ********************************************************** Llega por carta la propuesta de liquidación de la oficina liquidadora de Herrera del Duque. Lo escaneo y lo envío a Estefanía (abogada de Gijón que representa a la nuera) para vea si está o no correcto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2021-08-09','TERESA RECIBO LLAMADA 677716154 DE MANUEL INDICANDOME QUE LE AUTORICE SALIR A ZAFRA PORQUE SE HA QUEADO ALLI UNA MALETA LE INDICIO QUE SE LO PEDIDRE A FUTUEX PARA QUE SE PASE A POR ELLA Y SE LA HAGA LLEGAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTIN'and edp.apellido1='RAMOS'and apellido2='CALERO'),'2021-08-03','-Amalia : recibo llamada de Maria , TS de la Granadilla en sustitución , indicando que ha fallecido que según Nortehispana ha causado baja en este mismo mes. La hermana , Antonia Ramos , tomadora del seguro insiste en que ella no ha sido . Contacto con Nortehispana para q justifiquen esta baja , que al parecer hizo Antonia via telefónica. Se solicita factura a otra funeraria para cumplir con los servicios funerarios necesarios . Solicito a Nortehispana justificante de esa baja por escrito el dia 9/08/2021 desde mi correo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTIN'and edp.apellido1='RAMOS'and apellido2='CALERO'),'2021-08-09','miguel, recibo email de requeremiento de justificante a la aseguradora de Decesos NorteHispana (de estar de baja el seguro): soy la Trabajadora Social de la Comisión Tutelar de Adultos de la Junta de Extremadura. Les recuerdo que hablamos el martes de la semana pasada en relación a una persona tutelada que había sido benificiario del seguro de decesos con esa compañía. Como tutores del mismo , por sentencia 136/18 de fecha 20 de noviembre de 2018, en la que se nombra tutora de D. VALENTÍN RAMOS CALERO con DNI 08740944 R a la Comisión Tutelar de Adultos de Extremadura se les informa : Que en cumplimento del Codigo Civil , tenemos que justificar en su declaración final de cuentas que se ha tenido que abonar los servicios funerarios necesarios dado, que según vuestra compañía no estaba cubierto por el seguro que tenía contratado su hermana Antonia Ramos ; tomadora del seguro en el que según ustedes había causado baja en el mes de julio del presente año . Quedamos a la espera en la conversación telefónica mantenida , que quedó grabada y que duró mas de 30 minutos , de recibir esta justificación que tenemos que aportar al juzgado y que quedaron en enviarnos al día siguiente y aún no se ha recibo. Se solicita que nos lo envíen a la mayor brevedad, puesto que hay fecha límite para hacer la comunicación al juzgado . Para cualquier consulta pueden escribir directamente al email de esta institución: ctutelar@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-08-09','TERESA RECIBO RESOLUCION DE PF CON FECHA EFECTO 1/10/2021','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-08-09','TERESA RECIBO RESOLUCON PF FECHA EFECTO 1/10/21','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2021-06-30','Belén. Nos envían presupuesto para implantes dentales debido a que las prótesis removibles normales no se le pueden poner. Solicitando aceptación o denegación del presupuesto para poder inciar tratamiento. Se le pasa a la sección económica para que lo estudie. Pendiente de resolución de prestación de orfandad.','1');
