insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2021-08-09','Belén. Se llama al centro Toñi (ext. 20113) informando de la resolución favorable de orfandad. El importe de la plaza será el 75€ del total de la prestaciones actuales sin tener en cuenta las pagas extras. Se pasa a la sección económica para que estudie la posibilidad de realizar los implantes dentales. También se habla de la posibilidad de fraccionar el pago de los implantes mensualmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-08-09','miguel, ha llegado la liquidación de impuestos de la oficina liquidadora. Tras verla vemos Angel y yo que no viene recogido el usufructo de Mercedes la nuera. Sí que la cifra en principio coincide con cuál sería la cifra de la parte hereditaria de Juan Felipe (la variación debe deberse al importe comprobado de saldo en cuentas) Envío email a la abogada comentandole que por nuestra parte lo vemos bien, ya que aunque falta la carga deducible de gastos de sepelio, sí recoge el importe de la porción hereditaria de Juan Felipe','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-08-09','Belén. Correo de Emiliano Delfa (inmobiliaria):Buenas tardes Belén, te adjunto los DNI de Saul y de Ana Maria, esta pareja pasa una oferta de 50.000 Euros por la compra de la vivienda, con todo lo que hay en el interior, por lo que no tenéis que preocuparos de tirar todo lo que hay dentro (que es bastante). Los gastos serían según Ley. Recordaros que la vivienda actualmente tiene solería rota y suelta en la planta de arriba, desconchados en pare del salón y garaje, puertas hinchadas que no funcionan bien y rozan en el suelo, en fin que más contarte que tu no sepas. Quedo a la espera de que me digáis algo. Se le contesta al correo: Buenos días Emiliano, le acabo de pasar el correo con la oferta a Miguel (área jurídica) que se pondrá en contacto contigo, para ver cual es el siguiente paso que hay dar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-09','Lun 09/08/2021 12:44 Buenos días , he estado hablando con Cristian , con quien Juanjo lleva conviviendo desde el día 23 de julio , lleva en el domicilio 17 días. El viernes contraté un servicio de ayuda a domicilio que cubriría 8h/dia , y un servicio de menú diario con un bar de la localidad . Después de todos los esfuerzos por localizarle , no cogía mis llamadas , tuve que contactar con el Ayuntamiento de Oliva de la Frontera , Jefe de policia local , Director del CAM , su hermana Alba .. conseguí que un policia local se acercase a su domicilio y desde su móvil poder explicarles los apoyos que había establecido. Se negó en rotundo , no quiere depender de nadie , no quiere que nadie entre en su casa y tener que estar supeditado a visitas diarias. Rechazó igualmente los menús , a pesar de que sus ingresos económicos son mínimos , según me cuenta vive con la pensión de orfandad simple , y recibe bolsa de alimentos de Cáritas . La vivienda es una viendada de promoción pública , en la que vivieron sus padres y de la que salieron todos los hermanos para ingresar en centro de menores. Cristian , está desbordado por la situación, tiene ansiedad y no puede aguantar más al cuidado de su hermano. No tiene capacidad de control con su hermano Juanjo , del que tiene que estar pendiente las 24 h del día . Sin red social ni familiar de apoyo . Hay una hermana que vive en la misma localidad , muy cerca del domicilio .Convive con la familia de su pareja , no puede prestar ningún tipo de ayuda porque se encuentran confinados por protocolo covid. Cristian me cuenta que desde el centro le dijeron que Juanjo pasaría allí el fin de semana y que después irían a recogerlo al domicilio , y que ya han pasado más de dos semanas sin que nadie le dé una solución. Ante todo esto , y ante la negativa de Cristian de aceptar la ayuda que se le ha buscado , su estado de su salud ,su deficitaria situación socio económica, inexistencia de red social y familiar de apoyo .. , considero necesario buscar otra alternativa residencial para Juanjo por emergencia social . Seguimos en contacto . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2021-08-09','TERESA FELICIANO RESIDEN EN EL PISO SUPERVIDADO DE PROINES DON BENITO ESTA ESTABLE Y BIEN ADAPTADO, PARTICIPA EN EN LOS TALLERES OCUPACIONALES. TIEN BUENA RELACION CON SUS COMPAÑEROS, NO TIENE CONTACTO FAMILIAR PERCIBE ORFANDAD 733 Y PF 399 SALDO 97000','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-09','Lun 09/08/2021 12:44 . Amalia : envio email a Soraya Masa y Maite , Jefa de Sección CTAEX sobre la situación de Juanjo después del fin de semana : Buenos días , he estado hablando con Cristian , con quien Juanjo lleva conviviendo desde el día 23 de julio , lleva en el domicilio 17 días. El viernes contraté un servicio de ayuda a domicilio que cubriría 8h/dia , y un servicio de menú diario con un bar de la localidad . Después de todos los esfuerzos por localizarle , no cogía mis llamadas , tuve que contactar con el Ayuntamiento de Oliva de la Frontera , Jefe de policia local , Director del CAM , su hermana Alba .. conseguí que un policia local se acercase a su domicilio y desde su móvil poder explicarles los apoyos que había establecido. Se negó en rotundo , no quiere depender de nadie , no quiere que nadie entre en su casa y tener que estar supeditado a visitas diarias. Rechazó igualmente los menús , a pesar de que sus ingresos económicos son mínimos , según me cuenta vive con la pensión de orfandad simple , y recibe bolsa de alimentos de Cáritas . La vivienda es una viendada de promoción pública , en la que vivieron sus padres y de la que salieron todos los hermanos para ingresar en centro de menores. Cristian , está desbordado por la situación, tiene ansiedad y no puede aguantar más al cuidado de su hermano. No tiene capacidad de control con su hermano Juanjo , del que tiene que estar pendiente las 24 h del día . Sin red social ni familiar de apoyo . Hay una hermana que vive en la misma localidad , muy cerca del domicilio .Convive con la familia de su pareja , no puede prestar ningún tipo de ayuda porque se encuentran confinados por protocolo covid. Cristian me cuenta que desde el centro le dijeron que Juanjo pasaría allí el fin de semana y que después irían a recogerlo al domicilio , y que ya han pasado más de dos semanas sin que nadie le dé una solución. Ante todo esto , y ante la negativa de Cristian de aceptar la ayuda que se le ha buscado , su estado de su salud ,su deficitaria situación socio económica, inexistencia de red social y familiar de apoyo .. , considero necesario buscar otra alternativa residencial para Juanjo por emergencia social . Seguimos en contacto . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-08-09','miguel, envío a la abogada Estefanía: Buenos días, yo he revisado la liquidación de impuestos que remiten y de los tres bienes declarados dos difieren: 1.- la vivienda de Talarrubias (Badajoz). Valor declarado: 92.430€ Valor Comprobado: 92.428,07€ 2.-Saldo de cuenta la Caixa: Valor declarado:1.058,22€ Valor Comprobado:2.116,45€ A parte no estarían recogidas las cantidades objeto de alquiler (pendientes de que las reingrese Mercedes la nuera). Según escrituras de adjudicación del padre Mariano: Juan Felipe adquiere la cuantía hereditaria de 63.817,20€+ 220€ de la adicción de herencia del coche, lo cual viene a ser casi los 64.454,30€ de la propuesta de la liquidación de impuestos de sucesiones que remite la oficina liquidadora de Herrera del Duque (la variación entiendo que se corresponde con los saldos que pudieran haber a fecha de fallecimiento). Ten en cuenta que la propiedad al no haber descendencia ni testamento pasa por ley a los ascendientes(en este caso de Alfonsa, la madre). Es verdad que no veo la deducción de los gasto por sepelio ni el usufructo de tu clienta Mercedes. Si lo crees conveniente y viene recogido el doble usufructo en notas simples de registro de la finca nº27.457 del registo de la propiedad de Madrid nº35 y finca nº 4172 de Rgtro de la Propiedad de Herrera del Duque-Puebla de Alcocer (la adjunto). Si pides o tienes la nota simple del piso de Madrid envíamela. Por nuestra parte creo que no tenemos que alegar nada. En cuanto tenga firmada la declaración de herederos de Agustín podré proceder a que vayan preparando la herencia total(siendo la única heredera la madre Alfonsa al ser la ascendiente, conforme a ley) Cualquier duda ya me dices.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-09','-Amalia , anulo los servicios contratados , no se han llegado a facilitar . ------------------------------------------------------------- Clemen , Dtra. CAMP ha llamado a Cristian y ha confirmado todo lo que le he transmitido , se ha quedado muy sorprendida por la actitud desde menores . Quiere que ingrese el dia 12 , quedo pendiente del traslado ( taxi + delegada tutelar ) y buscar servicio SAD en D. Benito.','2');
