insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-09','-Amalia : cuadro servicio taxi para el traslado al CAMP Buenos días , soy Amalia , Trabajadora social de la COMISION TUTELAR DE ADULTOS DE LA JUNTA DE EXTREMADURA. Según conversacion tf solicito el siguiente servicio de taxi ;recogida el jueves dia12 en Oliva de la Frontera , en C/Federico Garcia Lorca , Nº 11 a las 10.00h para trasladar a nuestro tutelado Juan José Mesa Candil hasta el centro CAMP de Don Benito , en Avda. Alonso Martín , 16 , tf 924021574.Irá acompañado de una delegada tutelar . Quedamos a la espera de recibir su Nº cuenta y factura para hacer transferencia . Taxista : Anselmo Tf. 636268849','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2021-08-09','-Amalia : desde VPP nos envian documento para dejar la vivienda , ha superado el tiempo máximo en el que se puede reservar y tienen que hacer nueva adjudicacion El documento lo dejo en Mérida para firma cuando vuelva el gerente de vacaciones. Avisaré a su madre para que se ponga en contacto con VPP para recoger enseres personales.','2');
