insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-11','Buenos días. Sí, tiene la pauta completa de vacunación con Pfizer. Adicionalmente te informo que la próxima cita de Psiquiatría de Juanjo con Dr. Gutiérrez en Badajoz es el 13/12/2021 y en cuanto a su pauta de medicación, se la facilité completa para el mes, así como la medicación en inyectable que se puso la semana pasada y Cristian tiene otro inyectable más que le llevé para hacer completo agosto. Por lo que en principio hasta que se produjera el ingreso estaría cubierto de medicación y no habría que llevarlo a revisión de psiquiatría, salvo que su condición personal empeorase. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-08-10','Ángel: llamo a José Luis García, Secretario General de la Policía Nacional del Cáceres (927 626 548), me indican que está de vacaciones (vuelve el lunes 16/8),pero podrá atenderme el Inspector Raúl Ávila Guillén (927 626 558) Raúl no sabe si José Luis habrá hecho alguna gestión al respecto, sugiere que le llamemos a partir del lunes 16/8 que volverá de vacaciones.','2');
