insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2021-08-10','-Amalia , llamo al CRR a Julián para ver lo del tema de pasar a piso de alquiler . Buenas Mª del Mar , ya he hablado con él y parece que lo tiene bastante claro Si a nivel terapeútico lo véis factible y se cubren todas las necesidades se podría ir iniciando la búsqueda de alquiler . Tendréis que tener en cuenta que con sus ingresos cubra todos los gastos : alquiler , suministros , menú diario ... Y si se va probando con salidas programadas a su vivienda familiar?? no sé si se lo ha planteado , para ir valorando su grado de autonomía antes de dar el paso definitivo. Un saludo','2');
