insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2021-08-11','TERESA RENDICION ANUAL JOSE MARIA VIVE EN SU CASA EN VALENCIA DEL VENTOSO, TIENE SAD DE UNA HORA AL DIA DE LUNES A VIERNES EL CUAL RESULTA INSUFICIENTE PARA CUBRIR TODAS LAS NECESISADS QUE PRESENTA LA CASA Y EL USUARIO, A ESTO SE UNE LA NEGATIVA DE JOSE MARIA ANTE LA LIMPIEZA DE ALGUNAS ZONAS DE LA CASA ASI COMO DEL ASEO PERSONAL JOSE MARIA VIVE SOLO CON ESCASA RED DE APOYO Y SIN RELACIONARSE CON NADIE PADECE ESQUIZOFRENIA LA CUAL ESTA CONTROLADA CON MEDICACION QUE LE CONTROLA LA AUXILIAR, LA DELEGADA TUTELAR LE ACOMPAÑA A LAS CITAS MEDICAS DE SALUD MENTAL ULTIMAMENT HA TENIDO UN INGRESO HOSPITALARIO PERO SE HA RECUPERADO BIEN LA TS PLANTEA EL INGRESO EN RESIDENCIA DEBIDO A SU AVANZADA EDAD Y LAS NECESIDADES QUE VA PRESENTANDO PERO EL NO QUIERE TAMBIEN PLANTEA LA POSIBILIDAD DE AMPLIAR DE FORMAR PRIVAA LAS HORAS DE SAD PERCIBE UNA IPABSOLUTA 677 SALDO 3000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MARTINEZ'and apellido2='ORTEGA'),'2021-08-11','miguel, recibido email de Carlos Mora: Buenos días Miguel, Reenvío email recibido por parte de Agustin Caballero de la notaria de don Timoteo Díez al respecto. Actualmente me encuentro de vacaciones, para cualquier asunto te puedes comunicar con este señor, abajo encontrarás su email, teléfono de contacto 924 23 48 00 (extensión 6). Por mi parte tengo cita previa concertada para presentar el impuesto de sucesiones del heredero (padre de Evelyn) el próximo día 13 de los corrientes, dentro del plazo de los 6 meses para acogerse a las reducciones y/o bonificaciones recogidas en la Ley de aplicación. Presentaré la liquidación (no autoliquidación) y un informe de la notaria en caso de que aún no esté constituida la Declaración de Herederos de que se está tramitando, siguiendo instrucciones de Agustin Caballero. Seguimos en contacto, Un saludo, ******************************************* mi contestación: Buenos días, en un par de días remitiré a la oficina liquidadora la autoliquidación del impuesto de sucesiones, aunque no tenemos: -Certificado de fallecimiento de su esposa. -certificados de saldos bancarios. -Declaración notarial de herederos. -Libro de familia. Llamé sin éxito ayer a Evelyn y la remití el siguiente email: Necesito me indique la fecha en que falleció su tía Doña Luisa Perez Alvarez. Si tiene certificado de defunción de ella aunque sea una fotocopia envíemela a este email. También necesitaría libro de familia de su tío fallecido Don José Martinez Ortega y sus tres hijos. Por tanto remitiré cuaderno particional privado con lo que se aportó en la rendición final de cuentas al juzgado+los modelos 650 que salen negativos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2021-08-11','TERESA LLAMA LA HERMANA DE LUCIA PARA PREGUNTAR SOBRE LA PRESTACION DE SU HERMANA YA QUE COMENTA QUE NECESITA PONERSE UNA DENTADURA CONSULTO EL EXPEDIENTE EN PNC Y AUN ESTA PENDIENTE DE RESOLVERSE','2');
