insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-08-11','Maite:reitero correo electrónico, enviado con fecha 29 de julio,a la médico de familia de Antonio, solicitando envién informe médico para tramitar valoración del grado de dependencia, y nos informe si ya ha realizado la derivación al equipo de salud mental para que lo citen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-08-11','Belén. Vuelvo a llamar a Sandra TS SSB Hervás (674693539) para informarla que el telf. que me facilitó ayer no responde nadie. A través de la policía local intentará localizarla para que me den su número nuevo e intentar conseguir las llaves de la vivienda para sacar las cosas personales de la tutelada. Me llamará en cuanto averigüe algo.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-08-11','Maite: he llamado a varios teléfonos de la Junta de Andalucía, pensiones no contributivas, gerencia de málaga y ha sido imposible contactar. He enviado correo electrónico a una dirección encontrada enla pagina web, solicitando un número de teléfono: Buenas tardes! Soy Maite Gómez, jefa de sección de la Comisión Tutelar de Adultos de Extremadura. Necesitamos información a cerca del expediente de PNC relativo a uno de nuestros tutelados, COSTI ALEXANDRU RIZEA. He llamado a varios teléfonos pero me ha sido imposible contactar. Si es posible, necesitaría que me facilitasen un número al que llamar para poder informarme. Muchas gracias. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-08-11','miguel, me llama Mely y me comenta que me enviará un email de la Notaria donde le indican que el auto (todavía No firme) no establece claramente que autorice la venta a terceros (sino que como está redactado obligatoriamente habría que hacer subasta pública) Tras comprobar el auto no observamos ese impedimento. No obstante remito fax al juzgado solicitando la firmeza junto con la aclaración para que se pueda vender a un tercero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-08-12','TERESA NOTA FUTEX: se va a ir a Jerte del Valle, su pueblo, a pasar 15 días. Comenta que ha hablado con sus padres y sus hermanos y todos tenían muchas ganas de reunirse, ahora que están todos vacunados. (llevaban dos años sin querer que fuera para alla) José Mª cuenta que en el CEDEX ha pedido metadona para más de 15 días, y que tiene preparada la maleta para marcharse el sábado día 7 de Agosto en autobús hasta Plasencia. Quiere coger en Zafra el de las 09:50h y llamará a su hermana Teresa (927 47 02 79) para que le recoja en Plasencia; y su idea es volverse a Zafra el lunes 23 de Agosto. Por lo que estaría en Jerte del Valle el lunes 16 de Agosto cuando le tocaría ir al Liberbank a retirar su asignación de 175€. Se le ha preguntado si no va a tener ningún problema para sacar el dinero allí, y él mismo ha asegurado que no. (no sabemos si va a sacar el dinero alli o no va sacarlo) Se le ha explicado que debería haber avisado a la delegada tutelar con tiempo suficiente para que ésta pudiera comentarlo a la comisión tutelar y que ellos le hubieran dado permiso o no. Ya que son sus tutores legales los que tienen que decidir este tipo de cosas, José Mª ha respondido que él estaba tranquilo porque tenía el permiso de sus padres y como se ha ido otras veces a verlos y a la comisión le ha parecido bien... Se ha llamado al teléfono fijo de los padres de José Mª (927 47 00 22) y se ha hablado con Marcela y con Félix. Ellos han confirmado que el tutelado va a pasar unos días en su casa, situada en la calle Coronel Golfín, 32, de la localidad Jerte del Valle. Marcela ha comentado que será su hermana Teresa la que le recoja en Plasencia en la estación de autobuses y tanto ella como su marido tienen muchas ganas de verle. En la actualidad está pasando unos días en casa su otro hijo, Félix, que reside en el CRR de Cáceres, y se va a reunir toda la familia por unos días, algo que no han podido hacer desde antes de la pandemia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2021-08-12','Belén. Llamo a Gema, directora (670381292) para que nos mande gastos mensuales y de bolsillo de la tutelada. También se los solicito por correo electrónico (gsanchez@nexusintegral.com). Me los hará llegar por correo electrónico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-08-11','Belén. Vuelvo a llamar a Sandra TS del SSB de Hervás (674693539) para comentarle que en el telf. facilitado no me responde nadie. La policía local consigue otro telf. de la Marta propietaria de la vivienda arrendada (652511744). Llamo a Marta y le explico la situación, que en breve va dictarse la sentencia firme de desaucio y es necesario sacar las pertenencias de la tutelada pero no tenemos llaves. Me comenta que ella tiene una llave y nos puede abrir pero que ahora se encuentra fuera de la península hasta el 17 de agosto no llega. Quedo con ella en llamar a la delegada de FUTUEX para que cuando me diga día y hora llamarla para que vaya con ella a abrir y que ésta pueda sacar las pertenencias de Ángeles. También me pondré en contacto con la policía local para que esté presente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-08-12','miguel, remito a Caixabank (Isabel tlfno 949-845-102) el siguiente email (8771@caixabank.com): Buenos días, he intentado ponerme con usted a través del teléfono 949-845102, sin éxito. Soy compañero de Iciar, y el motivo de mi llamada es para aclarar con ustedes cómo proceder para la disposición de las cantidades de dinero en la cuenta 2100.8771.18.2100123169 cuya titularidad corresponden al tutelado Don Raúl Gil Sanz con dni 53265044B y sus fallecidos padres Máximo Gil Garcia con dni 03001944F y Doña Teresa Sanz Carrascosa con dni 03001800R. Por favor póngase en contacto conmigo lo antes posible ya que necesitamos realizar transferencia de la parte cuya titularidad corresponda a nuestro tutelado. Lógicamente entendemos la indisponibilidad de la parte cuya titularidad corresponda a los padres, mientras se gestiona la herencia. La liquidación del impuesto de sucesiones de su madre ya fue realizada por su padre (fallecido posteriormente) y sus dos hijos los cuales se encuentran tutelados por esta Comisión Tutelar de Adultos. Adjunto los testimonios de nombramiento de cargo de tutores de los hijos Raúl y Sergio Gil Sanz, así como los impuestos de sucesiones presentados en 2020 por el fallecimiento de su madre. Por tanto entendemos que una vez esté liquidado el impuesto de sucesiones del padre Máximo podrán desbloquear y repartir entre los dos hijos Raúl y Sergio el resto del dinero de esa cuenta de la que son titulares como arriba se indicó Raúl y sus padres fallecidos Máximo y Teresa. ****************************************** A su vez, remito email a Alberto y Teresa junto con este email: Hola, he intentado sin éxito hablar con Isabel de Caixabank por lo que la he remitido el email que debajo podéis ver. Por lo que veo para el desbloqueo de la parte de la cuenta cuya titularidad correspondía a los padres sería necesario liquidar el impuesto de sucesiones del padre Máximo, para lo cual Teresa necesito veas si alguien lo está tramitando ya y caso contrario necesitaré mínimo certificado de defunción de Máximo (el padre).Si puedes consígueme también el dni , testamento (si tuviera) certificado de últimas voluntades (no sé si lo tienen pedido). Quedo a la espera de respuesta de la oficina de Caixabank ***************************************************** Envío nuevo email a Alberto y Teresa Ts: En relación al email anterior, y a la espera de que me conteste Caixabank en relación de si podemos disponer del % del que es titular Sergio junto con sus padres. Si bien la herencia de la madre (la presentación del Impuesto de sucesiones ya fue presentada) y por lo tanto faltaría presentar la del padre Maximiliano. Problema es que son de Castilla la Mancha por lo que no puedo ver el catastro de allí y es por eso que he pedido a Teresa las siguientes gestiones: -Hablar con el Centro y averiguar si alguien está o no tramitando las herencias de los padres, y en concreto del padre. Caso contrario averiguar si tienen certificado de últimas voluntades y testamento. -Por otro lado y debido a que vamos fuera del plazo de 6 meses para liquidar el impuesto de sucesiones, ya que fallece el 15-9-2020. Además hay que añadir que tanto el padre como la madre fallecen en Guadalajara por lo que hay que presentar el impuesto de sucesiones allí. Teniendo en cuenta que no podrá aplicársele las reducciones que correspondan por el transcurso del período voluntario de los 6 meses, propongo esperar a la prescripción del impuesto de sucesiones de los 4 años para desbloquear la parte de la cuenta cuya titularidad corresponda a los padres. Lógicamente intentaré con Caixabank que desbloquen y nos permitan transferir la parte del dinero cuya titularidad es de Sergio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-08-12','TERESA TERE: TE ADJUNTO JUSTIFICANTE PAGO BANCARIO (INCLUYE 04,05 Y 06 DE 2021). ICIAR: • HECHO ESCRITO Y ARCHIVADO EN EXPEDIENTE PARA TRAMITACIÓN • HECHA TRANSFERENCIA A HERMANA. TE ADJUNTO JUSTIFICANTE EN ESTE CORREO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-08-13','TERESA el pasado 4 de Agosto se visitó a Emilia Morales Botello en Don Benito, ciudad en la que reside con su pareja. Se le acompañó al centro de salud ya que tenía cita de salud mental. Se observó que la tutelada tenía un apósito en la barbilla y se le preguntó qué había sucedido, ella respondió que la noche anterior Miguel Ángel había estado discutiendo con los vecinos del piso de arriba de su bloque y cuando ella salió a la puerta le tiraron todo tipo de objetos. Al arrojar objetos de todo tipo, le produjeron un corte en la barbilla, Emilia llamó a la ambulancia y se personó también la policía local. A Emilia le hicieron un parte de lesiones por agresión y le curaron la herida, seguidamente ella interpuso una denuncia al vecino de arriba. Se adjunta envía tanto el informe de asistencia sanitaria como la denuncia. Se entró en la consulta del Dr. Alberto con la tutelada y el psiquiatra le estuvo haciendo una serie de preguntas a Emilia sobre su estado de ánimo, ritmos de sueño y comida. Y le recordó que tenía que tomar la medicación exactamente como él se la había pautado porque sino, no funcionaría. Ella comentó que había ido a urgencias el día anterior por dolores muy fuertes de espalda y le habían mandado Valium 5mg, los tenía que tomar durante 5 días y comentaba que se sentía muy dormida. El Dr. Alberto le preguntó a Emilia si no querría ingresar unos días en la UHB de Mérida para apartarse durante un tiempo de la casa de su pareja, ya que se está quejando continuamente de lo mal que se encuentra con él. Pero ella respondió que no iba a ingresar por nada del mundo ya que en el hospital le tenían restringido el tabaco y no podía salir de la unidad. Emilia comentó que si se iba a algún lado sería a una pensión a Mérida, pero se le explicó que eso no era posible porque no disponía de dinero para mantenerse en una pensión por mucho tiempo. Por último se habló con Inma, la trabajadora social del centro de salud, que comentó que había optado por pedir una plaza en un CRR por emergencia social para Emilia, solamente necesitaba la firma de la tutelada para poder enviarla. Emilia la firmó y preguntó cuándo podría irse, Inma le contestó que no se lo podía decir con exactitud, pero no sería inmediato, podría tardar más de un mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-08-12','TERESA RECIBO INCIDENCIA DEL PRESIDENTE DE LA COMUNIDAD DE LA VIVIENDA DE ANTONIA A TRAVES DE LA TS DEL SSB ALMENDRALEJO RESPONDO ¿Esta incidencia le ha dado registro en algún sitio? Antonia Engracia está actualmente en el centro sociosanitario de Mérida, nosotros estamos en proceso de inventario. Hemos pedido movimientos de cuentas al Santander pero aún no nos han facilitado nada. Hemos abierto una nueva cuenta con su tutor legar y domiciliado allí las prestaciones para poder tener la gestión del dinero ya que con el Santander a fecha de hoy no podemos hacer nada. En cuanto tengamos el dinero suficiente vamos a contratar una empresa de limpieza para que ponga la vivienda al día, pero hasta que no tengamos solvencia económica no podemos hacer ningún gasto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2021-08-12','TERESA Teresa buenas tardes, solamente destacar que Bartolome ya reside solo, incidencia esta que ya fue puesta en vuestro conocimiento en la documentacion que previamente se remitió, saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='DIAZ'and apellido2='DOMINGUEZ'),'2021-08-12','Belén. Vuelvo a llamar a la directora de la residencia CK Senior de Villafranca de los Barros, Ruth (924910411) para volver a solicitar el informe social de Lucía Díaz necesario para el inventario. Queda en mandármelo hoy a lo largo de la mañana.','2');
