o.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-08-12','miguel, Toni me remite email de copia encargando lo que la solicité, que se lo ha remitido a Gloria','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-08-12','TERESA EMIAL DE MANUEL PICADO Buenos días: Teresa te mando las facturas que debe Beatriz a su hermana Rosa. El tema lo he tratado con las dos. Beatriz asume la deuda y la reconoce. Está a nombre de su hermana la linea de vodafone porque a ella no se la daban. Necesito resolverlo y que se le abone la deuda a Rosa, su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2021-08-13','Belén. Me envían por correo electrónico gastos mensuales de la tutelada :"Hola, os detallo los gastos de M. Ángeles Rosado Cuantía a pagar de forma mensual Residencia de Mayores 1428,14 euros Gastos de peluquería: según el servicio que necesite. Una media de 20 euros mensuales Gastos de podología: 10 euros mensuales Gastos de bolsillo: 50 euros Reciban un cordial saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-08-13','miguel, desde el centro indican a Teresa Ts que hablemos con la prima Amelia (que seguramente está tramitando la herencia): Buenos días, Creo que tenéis que contactar con Amelia, una prima que ha llevado a cabo varios trámites de la herencia de sus tíos y primos, su teléfono de contacto es 628 58 19 97. ¿Algún familiar ha tramitado la herencia de Máximo? Amelia ¿Ha dejado algún bien? una vivienda ¿Dejo hecho testamento o se ha pedido certificado de voluntades? algo me comentó sobre la liquidación de la plusvalía que se realiza en la CCAA donde se produce el fallecimiento. Esta persona conoce los trámites, la asesoría jurídica no va a tener dificultad para que le aclaren estas cuestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-08-13','TERESA Me informan desde UHB HOSPITAL SAN PEDRO que dan el alta previsible el viernes 20/08/2021. NO HAY CENTRO ALTERNATIVOA A DÍA DE HOY pero UHB dice que no debe estar en la calle y que x eso han buscado (ellos mismos) PLAZA PRIVADA EN CRR MERIDA ADEMÁS HAN REALIZADO DERIVACIÓN A CRR (COMISIÓN EN SEPTIEMBRE) hablo con GRUPO 5 y confirmo precio: 1.545 € x manutención y alojamiento. ALBERTO/ICIAR: dado su nivel de ingresos y saldo podemos asumir esto durante un tiempo. ANA: debe retomar esta cuestión cuando se incorpore y en cuanto podamos minoramos costes. TERE/ANA: hay que gestionar revisión de GRADO X DEPENDENCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-08-13','TERESA ARCHIVO INFORME RECIBIOD DEL SSASB EN EL QEU SE PROPONE PEDIR AMPLIACION DE LA INCAPACIDAD SE LO PASO A LA SECCION JURIDICA PARA RETOMAR EL SEPBRE CON LA NUEA LEGISLACION','2');
