insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FILOMENA'and edp.apellido1='SERVAN'and apellido2='SANCHEZ'),'2021-08-18','EXITUS Su entidad bancaria (ibercaja) remite certificado de posición a fecha de 03/03/21 porque, según ellos, Dña. Filomena ha fallecido.*****************************************************Preguntado por tal extremo el CSS de Mérida, en el segundo intento, contesta confirmando el fallecimiento y dejando sin responder la fecha del mismo.*******************Queda pendiente, por tanto, recibir el certificado de defunción que remitirá el CSS. Del mismo se obtendrá la f/ del óbito y se regularizará la misma en las bases de datos CTAEx y EXITUS.','2');
