insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2021-08-18','Belén. Llamo a Esther de PNC Badajoz (924010043) para preguntarle por la resolución de PNC de Lucía. Me comenta que le hace falta la sentencia de separación. Le comento que Miguel (área jurídica) comenta que llamó al juzgado y es casi imposible. Esther me dice que haga un escrito como tutores legales, y se lo envíe por correo electrónico (esthermaria.lopez@salud-juntaex.es), especificando la imposibilidad de conseguir la sentencia, que es el marido (Pedro Guerrero Porro) el que de forma temporal le está pagando la plaza en los pisos tutelados y que en la actualidad no percibe ninguna pensión compensatoria....Correo de Esther "María buenos dias nuevamente, según conversación telefónica, quedamos a la espera de recibir vuestro informe sobre la situación de la referida solicitante de PNC"....Se le envía el escrito "Te envío escrito de LUCÍA PORRO MORENO, según conversación telefónica, firmado por el representante legal(guardado en su expediente). Contestación de Esther "María, resuelto, cobrará a final de septiembre con atrasos desde julio"','2');
