insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-08-19','Ángel: Me llama José Luis, Secretario General de la Policía Nacional del Cáceres (927626548). Habló con Extranjería y según comenta, quien ha actuado mal en este tema es la Embajada Francesa, al decir que no era ciudadana francesa y sin embargo si lo es, por los documentos que les enviamos (carnet de conducir y pasaporte). Lo que procede es que la Embajada Francesa documente a esta señora. Una vez esté documentada por la Embajada Francesa, podemos solicitar la tarjeta de residente comunitario aquí en España. Con esto ya sería suficiente para regularizar su situación. Si con posterioridad queremos que tenga DNI español, habría que iniciar los trámites para el cambio de nacionalidad.','2');
