insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-08-18','TERESA RENDICION ANUAL JOSE MANUEL RESIDE EN INCLUSIVES SE ENCUENTRA BIEN ADAPTADO Y PARTICIPA EN LA ACTIVIDADES SOBRE TODO EN LA ORGANIZACION DE LAS MISMAS HA TENIDO ALTERACIONES DE CONUCTA DE FORMA PUNTUAL EL PADRE LLAMA SEMANALMENTE AL CENTRO Y HABLA CON LOS PROFESIONALES YA QUE LAS CONVERSACIONES DIRECTAS CON SU HIJO LE GENRABAN MUCHO NERVIOSISMO Y MALAS INTERPRETACIONES TIENE PROBLEMAS DE OBESISDA PERICIBE PNC 604 SALDO 19500€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIO'and edp.apellido1='GALLEGO'and apellido2='MOLINA'),'2021-08-18','TERESA RENDICION ANUAL FLORENCIO DE 71 AÑOS DE EDAD RESIDE EN NUÑORAL TIENE UN 91% DE DISCACACIDAD DEBIO A RETRASO METAL MODERAO Y UNA HERMIPLEJIA NECESITA APOYO PARA TODAS LAS ACTIVIDADES BASICA DE LA VIDA DIARIA COME SOLO CON AYUDA DE UNOS CUBIERTOS ADAPTADOS PERCIBE ORFA 733 Y PF 593 SALDO 102000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2021-08-18','TERESA RENDICION ANUAL EUGENIO RESIDE EN P.I. CABEZA DEL BUEY LA RELACION CON LA FAMILIA SE HA VISTO FAVORECIDA A RAIZ DEL PROGRAMA DE VIDEO LLAMADAS LLEVADA A CABO CON MOTIVO DEL AISLAMIENTO POR EL COVID DEMANDA CONTINUAMENTE IR A SU PUELBO, SE HACENV VISITAS MENSUALES AL MISMO TIENE PEQUEÑAS ALTERIACIONES DE CONDUCTA CUANDO LAS COSAS NO SE HACEN COMO EL QUIERE, SOBRE TODO EN PERIDOS DE VACACIONES QUE VE COMO SE MARCHAN MUCHOS DE SUS COMPAÑEROS PERCIBE ORF 384 Y UNA PF 399 SALD 9900000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2021-08-18','TERESA RENDICIO ANUAL RESIDE EN EL CAMP DE DON BENITO JOSE ANTONIO PROVIENE DE UNA FAMILIA DESESTRUCTURADA SON 7 HERMANOS, UNO DE ELLOS TAMBIEN ESTA EN ESTE CENTRO ESTA BIEN ADAPTADO Y PARTICIPA EN LAS ACTIVIDADES DEL CENTRO SALE EN PERIODOS VACACIONALES A CASA DE LA HERMANA PERCIBE ORF 208€ Y PF 399€ SALDO 20500','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-08-19','miguel, llega email de Toni de Futuex: Paso esta información relativa a la tutelada M. Morato y las gestiones legales q han parecer esta iniciando su nieto, al parecer por un posible incidencia en la vivienda, detallamos a continuación 18/08/2021 Incidencia en la vivienda: Contacta José Manuel para comunicar que ayer se derrumbó parte del techo de la vivienda, donde la habitación de Manuela, según indica, justo después de levantar a la tutelada. Se le pide que envíe foto del estado de la habitación, pero establece que ha hablado con su abogada y ésta con el fiscal a quien envía todo lo que va sucediendo, según comenta se llama Miguel y le ha señalado que no es necesario que se envíen fotos, pues se debe proceder. Dicho esto se le solicita que facilite el contacto de la abogada que menciona y del fiscal que nombre, pero no lo hace y desvía la conversación comenzando con exigencias, exige que se llame al ayuntamiento para pedir que lleven el contenedor de obras y se comience con el arreglo tirando el escombro y demás… Se le dice que el procedimiento, como siempre se le ha señalado, es comunicar de todo a la CTAEX y será este órgano quien decida cómo se debe proceder. Exige que se tenga todo para la visita del viernes 20, se le vuelve a decir que se comunicara a la ctaex. ***************************************** Contesto a Toni: Gracias Toni. De todo esto tiene conocimiento el juzgado hace meses sin que nos contestaran. Paso nota a la parte social y económica, y llamaré al juzgado pero siendo mes inhábil seguramente por ahora haya que esperar. Por la parte social estará Ana a partir del lunes y por la parte jurídica Angel ***************************************** Remito email a Angel,Ana y Alberto: Buenos días, como sabéis hace meses que se solicitó al Juzgado de Valencia de Alcantara que nos autorizaran a llevarnos a Manuela Morato Picado a un piso de alquiler y a no arreglar la vivienda. Dicho juzgado no nos ha contestado nada. Según nos remite Futuex se ha caído el tejado de la vivienda de Manuela. Os remito lo sucedido para vuestro conocimiento. Al ser mes inhábil hasta septiembre no podré saber con el juzgado en qué estado se encuentra el escrito que remitimos solicitando no arreglar la casa y trasladar a la tutelada a un piso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-08-19','miguel, remito el siguiente fax al Juzgado de Valencia de Alcantara nº1: En relación con nuestra tutelada, Dª MANUELA MORATO PICADO, se comunica a este juzgado lo siguiente: 1.-Que por Sentencia dictada por ese Juzgado en el Procedimiento de Incapacitación nº 205/2013, de fecha 4 de junio de 2014 se declara la Incapacidad Total de Dª. MAUELA MORATO PICADO y se nombra tutor de la misma a la COMISIÓN TUTELAR DE ADULTOS DE EXTREMADURA, cargo que fue aceptado con fecha 15 de abril de 2014. 2.- Que se ha recibido hoy 19-8-21 email de FUTUEX en relación con la incidencia consistente en el “derrumbe parte del techo de la vivienda, en la habitación de la tutelada” (Doc. nº1) 3.-Con fecha de registro de salida 5/2/21 se remitió a su juzgado escrito, (Doc. nº2), por esta Comisión Tutelar de Adultos, sin contestación hasta la fecha por este Juzgado, donde se les solicitaba: -A trasladar a la tutelada a un piso de alquiler donde queden cubiertas todas sus necesidades. -A no realizar la obra de la vivienda solicitada por el nieto de la tutelada José Manuel. Y caso contrario que desde el Juzgado soliciten abogado de oficio para representar a la tutelada en procedimiento para gastos extraordinarios. -A instar a José Manuel a que no impida el acceso a la vivienda siempre que se le solicite por esta Comisión. Solicitamos tengan por presentados y sirvan admitir este fax y tras los trámites correspondientes, resuelvan sobre este escrito y el referido en Doc. nº2','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-08-19','miguel, llamada de teléfono del abuelo del curatelado donde me indica que la abogada (Amanda?) que le representaba en un juicio le ha llamado para comunicarle la sentencia luego le ha llamado para decirle que se ha equivocado. ***************************************************** Me comenta que no logran hablar con la abogada Soledad Carreres para aclarar lo de la cuenta a repartir. Como yo le he mandado a su hija Patricia Bono toda la documentación que nos envió el abogado Carlos y la que me remitió su abuelo Pedro para que lo consultara con su abogada Soledad, y teniendo en cuenta que la nueva ley de dicapacidad ley 8/2021 entra en vigor el 3/9/2021 le informo que puede hablar con su abogada a efectos de que el juzgado revisen la sentencia de incapacitación y nombramiento de curatela para que incorporen sus peticiones tanto de dinero como de que quieren que les den un piso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-08-18','miguel, llama Estefanía (abogada) que tras revisar el escrito que me remitió la oficina liquidadora (donde no se dice nada del usufructo de ambas titulares (Alfonsa y su nuera Mercedes) queda en que llamará a dicha oficina liquidadora para se lo aclaren y le indique cuándo y cómo alegar. De paso preguntará si puede o no hacer una declaración complementaria para justificarlo a la funeraria a efectos que le devuelvan el importe abonado incorrectamente. Aprovecho para comentarle que la notaria de herrera del duque en pocos días me dirá cuándo van a firmar la declaración de herederos de Agustin (el hermano fallecido) Recordemos que una vez que esté firmada la declaración de herederos del hermano Agustin (quedará la liquidación del IS) y posteriormente solicitar aprobación de herencia y autorización de venta (piso de Madrid al inquilino, que sólo llevaba 2 meses viviendo antes de morir Juan Felipe)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2021-08-18','TERESA RENDICION ANUAL JUAN ANTONIO RESIDE EN LA RM DE LOS SANTOS ESTA PERFECTAMENTE ADAPTADO Y PARTICIPA EN LAS ACTIVIDADES DE LA RESIDENCIA PADECE ESQUIZOFRENIA RESIDUAL RECIBE LAS VISITAS PUNTUALES DE SU HERMANO DIEGO PERCIBE 399.20€ SALDO 30000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-08-19','miguel, me llama Estefanía para comunicarme que ya ha hablado con la oficina liquidaora de Herrera del Duque. Le dicen que haga un escrito indicando lo del usufructo (aunque ya le han confirmado de palabra que saldrá 0€) También se han ofrecido desde la oficina liquidadora a hacerle la autoliquidación del modelo 650 (declaración complementaria del dinero abonado indebidamente a la funeraria). *********************************************** Quedamos que para principios de septiembre me habrá enviado modelo 650 hechos por ella de Mercedes para que haga yo el de Alfonsa, unido al escrito que hará y la documentación complementaria a adjuntar para que mi parte la remita directamente a la oficina liquidadora de Herrera del Duque','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-08-20','Belén. Respuesta de Toni de FUTUEX "De acuerdo. Ya está avisada una compañera de la zona de Cáceres, hará la gestión el martes 24, aq le he pasado tfno de la casera a ella por si quieres avisar tu tb". La retirada de las pertencias de la tutelada serán el 24 de agosto entre las 10-10:30, ya está avisada también la propietaria de la vivienda. Estoy intentando localizar a Sandra TS del SSB de Hervás (674693539) sin éxito, para que las acompañe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='DIAZ'and apellido2='DOMINGUEZ'),'2021-08-20','Belén. Me informa la directora de residencia CK de Villafranca de los Barros que Lucía ha fallecido esta mañana en el hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2021-08-20','Belén. Llega el informe social para el inventario. Convive con su hermano, cuñada y un sobrino con fuertes lazos afectivos en la unidad de convivencia. Vivienda que precisa mejoras. Recursos económicos suficientes para cubrir las necesidades de Juan José. Existe un préstamo personal a su nombre cuya cuota mensual es de 110€. Asiste al Centro Ocupacional Nova Forma siendo un recurso esencial para su integración social y muy valorado por el tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-08-20','TERESA RESIDENTE: MARÍA ELENA DURÁN DURÁN Nº D.N.I.: 76245926Y FECHA INGRESO: 08/04/2021 ACTUALIZACIÓN: INTENTO FRUSTRADO DE AUTILISIS EL 19/08/2021. SE APODERA DE UNAS TIJERAS E INTENTA PROVOCARSE CORTES EN UNA DE LAS MUÑECAS. NO LO CONSIGUE, LAS AUXILIARES Y ENFERMERO DEL CENTRO SE DAN CUENTA DE LO QUE OCURRE. NO TIENE NINGUNA LESIÓN. NI SIQUIERA LEVE. HOY, 20/08/2021, RECONOCE LO QUE HA INTENTADO HACER Y SE MUESTRA ARREPENTIDA. INTENTO DE AUTOLISIS PROVOCADO POR SU ESTADO ANSIOSO DEPRESIVO. Para cualquier aclaración, estamos a tu disposición en el teléfono 924563200. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2021-08-20','miguel, hablo por teléfono con Tere (aunque el teédonfo corresponde a Antonia, otra de las hermanas, 675565674) Me comenta que Diego es otro de los hermanos y el motivo por el que no he logrado hablar con él estos días es porque está hospitalizado (924690174). Me comenta que Dolores estaba casada y que la herencia está hecha hace años. Compruebo que tanto la cuenta que tenía con el marido, (Lorenzo, con quien se casó en 1990) como sus bienes los tenemos recogidos en nuestras rendiones de cuentas. *************************************** Por tanto le dejo el recado a Angel (Tere y yo estaremos de vacas) y a la hermana de la Tutelada Teresa le dejo el teléfono de Angel para que en el momento que tenga las llaves le llame para que Angel ponga en contacto a compradora y algún hermano que se la enseñe','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2021-08-20','TERESA informarte que Eugenio es contacto estrecho de una trabajadora que ha dado positivo en covid; por tanto estará en aislamiento preventivo y se realizará una pcr en el hospital de Talarrubias mañana 21 de agosto. En cuanto sepamos los resultados os informamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MIRANDA'and apellido2='GODOY'),'2021-08-20','miguel, remito al jzdo nº2 de Catuera comunicación de imposibilidad de control de las cuentas y por tanto de ejercer la curatela y solicito revisen resolcuión judicial de nombramiento','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-08-23','Ati esta en la UHB de Llerena Me ha llamado Constanza que le da el alta el martes y vendrá hasta Mérida en ambulancia. Está indocumentado porque ha perdido la cartera. Le he dicho que ponga una denuncia cuando esté en Mérida y pida cita para hacerse de nuevo el DNI. No se si con la denuncia podrá sacar dinero…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='DIAZ'and apellido2='DOMINGUEZ'),'2021-08-20','EXITUS (leer asiento anterior)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2021-08-23','Amalia Diaz Gonzalez Lun 23/08/2021 9:22 Buenos días Carmen soy Amalia , te he llamado por tf pero no he podido contactar , no sé si estarás de vacacioenes. Es con respecto a Rosa , el Jefe de Sección de la parte económica solicita que se domicilie el recibo SAD a la cuenta de Rosa , te lo reenvio directamente y ya me dices. Un saludo. ALBERTO MARTIN ROSETE Jue 12/08/2021 14:04 Me gusta Hola Amalia/Tere. La tutelada traslada a la CTAEX el siguiente problema: la Trabajadora Social del Ayuntamiento de Valdelacalzada (Carmen), NO acaba de domiciliar el ingreso por la Ayuda a Domicilio de su marido BLAS, en la cuenta de la tutelada, que si tiene saldo suficiente para ser abonada, ya que dicha ayuda no cubre la totalidad del servicio. Esto está suponiendo que la cuenta de BLAS se quede en números rojos y que la tutelada esté continuamente reiterando esta cuestión. Yo no voy puedo pasar un dinero a esa CCC sobre la que no tenemos control alguno y que podrían disponer del mismo sin nuestra autorización en cualquier momento. Podríais hablar con la trabajadora del Ayuntamiento para solventar esta cuestión???. Alberto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-08-06','Ana: Correo de Toni-Futuex: Remite copia del Certificado de Empadronamiento que finalmente gestionó con la mediación de Gloria-Ed. Futuex. *Guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2021-08-23','Amalia : envio email a EVA para que nos aclare el tema catering: Buenos días , no sé si estás de vacaciones , te reenvio este email de la sección económica a ver si puedes aclararnos este asunto . Sigue con catering? entiendo que estas facturas pendientes sí hay que abonarlas. Un saludo ALBERTO MARTIN ROSETE Vie 13/08/2021 14:13 Hola Amalia. Imposible para nosotros decidir si hay que pagar o no las facturas que la empresa de cátering nos solicita. Iciar ha comprobado que estos importes no se han abonado. Pero no sabe el motivo, puede ser que YA NOS HUBIERAS DICHO que abandonasemos el servicio y le subiesemos el reintegro o que realmente no se abonaron. No nos consta haber recibido facturas y no abonarlas. Por cierto...ya no estamos usando cátering, no? Si hay que pagar esto. Me lo dices y lo ABONAMOS cueando se pueda...actualmente tiene 313,99 €. Alberto De: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Enviado: viernes, 13 de agosto de 2021 13:43 Para: ALBERTO MARTIN ROSETE >alberto.martinr@salud-juntaex.es> Asunto: RV: URGENTE FCO PINILLA BAENA Buenas He comprobado que efectivamente no hemos abonado estas facturas, son del catering, tiene en su cuenta 313,99 € a día de hoy, el total de las facturas pendientes es 228 €. hacemos la transferencia? firma iciar 2019','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-23','-Amalia: solicito que se abone la factura del taxi a la parte eco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-08-06','Ana: Correo-e de Choni, TS SSB Miajadas (servicios.sociales@miajadas.org): "Buenso días Ana, referente a la cita de Esteve para acudir el día 12 al CADEX, nos va a resultar imposible acompañarle, a día de hoy tenemos confinada a una cuidadora hasta el 14 de agosto. la idea era ir con un taxi para Esteve y una cuidadora de acompañante, pero a Esteve no lo puedo dejar viajar solo con el taxista y a la hora que es la cita no sé si la educadora podría estar tan temprano en Miajadas para acompañarlo en el taxi. Ya me dices, yo también estoy confinada hasta 16 de agosto. si tienes que llamarme hazlo al tlf 683511955." ····························································································································································································· Mi respuesta: "...Al parecer, ninguna de las dos educadoras del Programa de Apoyo Comunitario de la provincia de Cáceres están en esa fecha… y yo cojo vacaciones el lunes también. ¿Habría posibilidad de que alguien de confianza, Auxiliar, Cuidador/a, o algo así, le hiciera el acompañamiento a la consulta? Se le abonaría desde la cuenta de Esteve, tendría que firmar una declaración jurada indicando sus datos y de qué hora a qué hora hizo el “servicio” y el nº de cuenta para que se le haga la transferencia. Es lo único que se me ocurre. Y el taxi pues también se abonaría, claro (se requeriría factura a nombre de Esteve) Ya me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-08-09','Ana: Correo de Choni, TS SSB: "YA VEO QUÉ PUEDO HACER."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-08-23','Ana: Correo de Choni, TS del SSASB de Miajadas, el día 13, comunicando que el día 16 de agosto intervienen de fimosis a Esteve. ····················· Envío correo a Choni (servicios.sociales@miajadas.org): "Buenos días Choni, Me incorporo hoy tras dos semanas de vacaciones. ¿Qué tal estás? En relación a Esteve, quería preguntarte qué tal fue la intervención quirúrgica y cómo se encuentra él. Por otra parte, ¿pudo acompañarle alguien al CADEX? Cuando puedas me informas al respecto de ambas cuestiones. . Ah, y como supongo que entregarían informe médico al alta, agradecería que cuando podáis me lo hagáis llegar. Gracias. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-08-23','-Amalia , envio informe social + i. médicos a UHB : Buenos días , en referencia a Ildefonso Garcia , ingresado en la UHB de ese hospital , remito informe solicitado a fin de valorar su ingreso en UME con las últimas incidencias acaecidas. Se adjunta también los informes médicos aportados a esta Comisión desde la UHB del Hospital de Merida en su último ingreso hospitalario. Seguimos en contacto . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-08-23','Email de Teresa a Manuel Picado respecto al pago del tf : Tras hablar con Alberto, jefe de sección económica, me comenta que no se autorizo a contratar esta línea de teléfono, además las personas tuteladas por esta comisión tienen prohibido contratar líneas de teléfono, solo se les permite tarjeta prepago. En este caso Beatriz utilizo los datos de su hermana para contratar la línea con lo cual no se autoriza el pago de estas facturas. Ahora mismo esta pagando piso mas gastos personales y se le acaba de autorizar presupuesto para depilación con lo cual el ahorro está siendo mínimo. Este expediente lo lleva mi compañera Amalia (amalia.diaz@salud-juntaex.es), para cualquier gestión ponte en contacto con ella ya que yo ya no llevo este expediente. Un saludo firma teresa 2019 MARIA TERESA BLANCO PARRA Jue 12/08/2021 14:01 Hola Manuel Este es un tema puramente económico, lo paso a la sección económica saludos firma teresa 2019 De: MANUEL PICADO MENDEZ >manuel.picado@salud-juntaex.es> Enviado el: jueves, 12 de agosto de 2021 13:54 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es>; MARIA TERESA BLANCO PARRA >teresa.blancoparra@salud-juntaex.es> Asunto: deuda Beatriz Mejias de la Morena Buenos días: Teresa te mando las facturas que debe Beatriz a su hermana Rosa. El tema lo he tratado con las dos. Beatriz asume la deuda y la reconoce. Está a nombre de su hermana la linea de vodafone porque a ella no se la daban. Necesito resolverlo y que se le abone la deuda a Rosa, su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-08-23','sE recibe email de Manuel Picado : Buenos días: espero que estés llevando el veranito bien. Te comento: tenemos problemas de convivencia, respeto y normas de Francisco Cacho Garrido. Lo tuve en el bajo A y lo trasladé al bajo B. Le conseguí un trabajo en la Clínica Quirón de una sustitución. Ya lo terminó. Insiste muchísimo que se quiere ir a vivir solo. Le he comentado que está tutelado. El problema es que no cumple normas y perfil para los PS. Los monitores me llaman casi a diario y yo también le atiendo. Dime que podemos hacer. Altera el orden de la normal convivencia. Quiere imponer sus normas a los demás. discute con otros usuarios. Se queja de todo: limpieza, comida, compañeros, etc. Amalia, este msj lo envié a Mª Luz. Te informo nuevas situaciones. El viernes por la tarde fue la policía al piso porque quería su tarjeta sanitaria para sacar medicación. El jueves por la tarde hice terapia grupal y no quiso asistir ni se excusó. No participa en nada, se compra latas de comida por su cuenta y se las come en el piso, le falta el respeto a los monitores y a mi, etc. En resumen, no cumple con los objetivos de rebabilitación terapéutica de los PS. Necesito que me digas como procedemos porque cada día es peor. Boicotea todo. Hasta me plantó uno de los días con el trabajo que le había buscado y con otro trabajo empezó con pegas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-08-23','Ana: Registro de entrada en el ORVE, solicitud de PFHC, modelo para personas jurídicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-08-23','Ana: Tras hablarlo con Alberto, jefe secc. ecca., se aprueba el presupuesto remitido por Martín, para obra en el cuarto de baño, se aprovecha para cambiar bañera por plato de ducha. ·········································· Por otra parte Alberto me informa de que en el último año Martín está teniendo facturas de luz muy elevadas (media de 180€/mes). Lo comunico a Futuex para que indaguen a qué es debido, pues antes no era así en absoluto. Comunico también la autorización de la obra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-08-23','Envio respuesta a Manuel Picado : Con respecto a qué hacer sobre la decisión de Fco. de irse a vivir sólo , en principio son recursos en los que se exije la voluntariedad , si no quiere permanecer no se le puede obligar a seguir en el piso . Otra cuestión es la posibilidad de expulsión por incumplir normas que tendría que concretar la sección de salud mental . Habría que valorar qué opciones reales tiene para vivir fuera del recurso de manera autónoma . Cuenta con unos ingresos de 400€ , no le llegaría para cubrir piso de alquiler y gastos de manutención y suministros. En su inventario no aparece como propietario de ningun tipo de bien urbano , existe alguna vivienda familiar a nombre de la madre ?? sé que es mayor y que reside en los pisos tutelados. En definitiva , buscar otras opciones para preparar la salida . Un saludo MANUEL PICADO MENDEZ Mar 17/08/2021 12:11 Buenos días: espero que estés llevando el veranito bien. Te comento: tenemos problemas de convivencia, respeto y normas de Francisco Cacho Garrido. Lo tuve en el bajo A y lo trasladé al bajo B. Le conseguí un trabajo en la Clínica Quirón de una sustitución. Ya lo terminó. Insiste muchísimo que se quiere ir a vivir solo. Le he comentado que está tutelado. El problema es que no cumple normas y perfil para los PS. Los monitores me llaman casi a diario y yo también le atiendo. Dime que podemos hacer. Altera el orden de la normal convivencia. Quiere imponer sus normas a los demás. discute con otros usuarios. Se queja de todo: limpieza, comida, compañeros, etc. Amalia, este msj lo envié a Mª Luz. Te informo nuevas situaciones. El viernes por la tarde fue la policía al piso porque quería su tarjeta sanitaria para sacar medicación. El jueves por la tarde hice terapia grupal y no quiso asistir ni se excusó. No participa en nada, se compra latas de comida por su cuenta y se las come en el piso, le falta el respeto a los monitores y a mi, etc. En resumen, no cumple con los objetivos de rebabilitación terapéutica de los PS. Necesito que me digas como procedemos porque cada día es peor. Boicotea todo. Hasta me plantó uno de los días con el trabajo que le había buscado y con otro trabajo empezó con pegas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-08-23','e: María del Mar Barroso Gómez >mmbarroso.sanmiguel@hospitalarias.es> Enviado el: martes, 17 de agosto de 2021 11:34 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: José Manuel R.M Buenos días Informaros que José Manuel R.M ha tenido una salida del centro de 48h, de martes mañana a jueves mañana como consecuencia de haber presentado comportamientos disruptivos con compañeros y profesionales. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-08-23','Ana: Correo-e de Estrella Durán, TS CSS: "Buenos días, Ana. Te escribo para comunicarte que Jairo ha dado positivo en covid y está ingresado en la unidad covid de este centro socio-sanitario. Está asintomático. Hemos habilitado un móvil para que la familia pueda hablar con estos pacientes, es el 683502182 de 11,30 a 13 horas. Por si queréis hablar con él...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2021-08-23','Ana: Correo de Estrella, TS CSS Plas: "Buenos días, Ana. Ya estoy de vuelta de vacaciones, espero estés bien. Supongo que sabrás que tenemos brote de covid en el Centro, así que el viaje que tenía previsto organizar para que Yolanda fuese a su centro, por ahora no se organizará..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-08-24','Amalia : recibo email de Manuel Picado . buenos días amiga. Gracias por informar. Te cuento las últimas: la semana pasada estuve en el piso y Fco. ni me saludó. Se puso a dar voces, diciendo que todo esto es una "mierda". Intenté hablar con él, se fue a la habitación, le seguí y si no quito la mano me parte los dedos con el portazo que dió. Comprobé que pone la música a todas horas y alta. Por la tarde me llamó una usuaria (Manoli Garrido) llorando porque le insulta: guarra, loca, no vales para nada, .... Con los monitores las faltas de respeto son continuas, no obedece ninguna norma, tiene serios problemas de conducta personales y de convivencia. Ante esta situación, considero la expulsión inmediata de Fco. Carmen Franco sabe la situación, creo que hoy tiene una reunión con vosotros por otros temas e intentará hablar contigo o Soraya. Necesito saber cómo proceder. Gracias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-12','-Ingrsa en el CAMP con Pcr negativa , en taxi privado acompañado de delegada tutelar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-24','-Amalia : hago informe sobre acciones realizadas con el caso a Mayte , se lo pasará a Manuela para hablar de estos casos con menores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-08-23','Ana: Tras conocer, por correo de Pablo, nieto, que Manuela Morato está ingresada en el hospital, confirmo dicha información con Gloria, Ed. Futuex: Manuela ingresó la madrugada del domingo al lunes ("anoche") por urgencia en el HUC, en el Serv. Digestivo. José Manuel, nieto está con ella junto con la hermana de éste. ································································································································································································· Llamo a Marisol, TS del HUC (56823): comunicará al servicio médico que Manuela está incapacitada judicialmente y tutelada por la CTAEX (envío por correo a Marisol: maria.acevedo@salud-juntaex.ex la sentencia y aceptación del cargo). Perdirán que me faciliten a mí toda información, CI, en su caso, e Informe Médico. *Mañana Marisol acudirá a ver a Manuela y a hablar con algún médico del servicio, pues no tiene asignado uno en concreto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-08-24','Ana: Recibo informe de Gloria de la últimas visitas e incidencias. Incorpora fotos de la situación actual de la vivienda. *La vivienda no reúne condiciones adecuadas de habitabilidad. ··········· Hablo con Ángel, Asesor Jurídico, solicitaremos AUTORIZACIÓN de ingreso en centro residencial adecuado. *Aportaremos informe médico (lo solicito a Marisol, TS del UHC), informe de la Policía en relación a la visita realizada el viernes (Ángel llama a la Policía) y el informe facilitado por Gloria, Ed.Futuex. ····························································································································································································· Dado que Manuela está valorada por Dependencia con Grado III, solicitaremos cambio de recurso. Cumplimento la solicitud. ························ Llamo a Pilar Márquez, TS de Valencia de Alcánara (927 580 326, ext.8) varias veces, pero no obtengo respuesta. ································································································································· Conversación con Daniel Martín, Médico Aparato Digestivo HUC (56176): Manuela presenta un cuadro de hemorragia digestiva. Le han transfundido sangre y a priori está respondiendo bien. *La endoscopia han decidido no hacérsela por ser una prueba muuy invasiva dada la edad de Manuela. Mañana le harán una analítica y comenzarán a darle de comer, a ver si lo tolera. *Le explico brevemente la situación y acordamos que me enviará informe médico breve en que haga constar que está ingresada, el motivo/diagnóstico y estado en que se encuentra a mi correo electrónico para poder comunicarlo al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-08-23','Ana: correo de Toni-Fututex el domingo 19: Paso esta información relativa a la tutelada M. Morato y las gestiones legales q han parecer esta iniciando su nieto, al parecer por un posible incidencia en la vivienda, detallamos a continuación "18/08/2021 Incidencia en la vivienda: Contacta José Manuel para comunicar que ayer se derrumbó parte del techo de la vivienda, donde la habitación de Manuela, según indica, justo después de levantar a la tutelada. Se le pide que envíe foto del estado de la habitación, pero establece que ha hablado con su abogada y ésta con el fiscal a quien envía todo lo que va sucediendo, según comenta se llama Miguel y le ha señalado que no es necesario que se envíen fotos, pues se debe proceder. Dicho esto se le solicita que facilite el contacto de la abogada que menciona y del fiscal que nombre, pero no lo hace y desvía la conversación comenzando con exigencias, exige que se llame al ayuntamiento para pedir que lleven el contenedor de obras y se comience con el arreglo tirando el escombro y demás… Se le dice que el procedimiento, como siempre se le ha señalado, es comunicar de todo a la CTAEX y será este órgano quien decida cómo se debe proceder. Exige que se tenga todo para la visita del viernes 20, se le vuelve a decir que se comunicara a la ctaex. Saludos y gracias"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-08-24','Ana: conversación mantenida con Raquel, Amvo. del CRR-Grupo 5 (924 30 45 38 / 650 103 996): Javier ha ingresado hoy en plaza privada, de momento es un ingreso temporal por no haber podido ingresar en UME debido al brote de Covid acaecido en el CSS-Plas. Ha llegado con lo puesto, pues dice que durante su viajes ha ido dejando por el camino todo lo que le molestaba. Presenta mal aspeco físico, muy desaliñado. *Pero a priori parece motivado y colaborador. **Tiene 15 días de prueba para ver si se adapta al recurso. **Necesita ropa, productos de higine y abonar las tasas para renovar el DNI. **Adelantarán el dinero desde la entidad y se les devolverá mediante transferencia en cuanto sea posible. ··················· Solicito me remitan Cdo. de ingreso en el centro. ···················· Tal y como acordamos remito por mail (administracion.crrmerida@grupo5.net) fotocopia DNI (antiguo), fotocopia tarjeta sanitaria, sentencia de incapacitación y acuerdo de aceptación del cargo para su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-08-24','-Amalia : llama Juana Martín , Jefa Sección de SSASB de Mérida . Tf 619142167/ juana.martin@merida.es Ana ha acudido a SSASB para renovar Renta Extremeña Garantizada , con malos modos y alterando el servicio . No quiere que la atiendan 4 de las TS que están allí . No quieren atenderla y solicita que al estar tutelada se le tramite desde aquí. Le indico que solo se puede realizar desde SSASB ya que se gestiona desde una aplicación informática . Le remito sentencia incapacitación que quiere revisar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCO ANTONIO'and edp.apellido1='BENITEZ'and apellido2='PIN'),'2021-08-25','Ana: Maribel Rivera, Directora INCLUSIVES Vva., envía factura del acompañamiento hospitalario. Finalmente ha estado menos tiempo hospitalizado de lo que esperaban. ········· Paso a Alberto, secc. ecca, la factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-25','-Amalia : Llamo a Monts , CAMP , la adapatación por el momento bien. Se contrató una empresa para acompañamiento , enviará factura y se ha sustituido por otra nueva , ya iniciado el servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-08-25','Ana: Correo de ayer de Estela Enriquez Gía, PNC Málaga (estela.enriquez@juntadeandalucia.es): "Buenos días soy Estela de Pensiones No Contributiva Málaga. Estoy tramitando el expediente de: RIEZA , COSTI ALEXANDRU, NIE Y1090272. Necesitaría una copia de la tarjeta de ciudadano de la UE, ya que de la dispongo no se ve con claridad. Si pudiera mandármela por este medio sería suficiente. Un saludo, Estela." ················· Le envío el CERTIFICADO DE REGISTRO DE CIUDADANO DE LA UE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-08-24','Ana: Correo para secc. ecca: "Hola de nuevo. Mañana irá un ordenanza de nuestro centro a extraer 300 euros para gastos de bolsillo de los siguientes tutelados: Andrés Silva Bonifacio..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-08-24','Ana: Correo de Estrella, TS CSS-Plas.: "Hola de nuevo. Mañana irá un ordenanza de nuestro centro a extraer 300 euros para gastos de bolsillo de los siguientes tutelados: ... Juan Carlos Ruíz García..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-08-25','-Amalia , se recibe llamada de Emi , la atiende Ana , al parecer ha dejado D. Benito , se ha enfadado con su pareja y está en la estación de autobuses de Mérida . Dice encontrarse mal y se le pide que entre en urgencias del hospital . LLamo a la TS de la UHB sin exito ayer . Vuelvo a llamar hoy , desde enfermería confirmo que no está ingresada en la UHB No consigo contactar con ella , su tf. está apagado , desconocemos dónde se encuentra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIANA'and edp.apellido1='HERNANDEZ'and apellido2='GARCIA'),'2021-08-24','Ana: Toni, TS del CR Cervantes, me remite resolución estimatoria de la ayuda para material ortoprotésico solicitada, por el cojín antiescaras. Le conceden 87€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELESTINO'and edp.apellido1='NAVARRETE'and apellido2='MURGA'),'2021-08-25','Ana: Llamada de Paqui, Directora del C.R. Hernández de Soto - Jerez de los Caballeros (21781): Acaba de enterarse de que Celestino ha sido incapacitado judicialmente y tutelado por la CTAEX. Lleva muchos años residiendo en el centro. Pregunta por la autorización para retirada de efectivo. Le explico que el cargo se ha aceptado recientemente, el inventario aún no está hecho y tampoco tenemos aún acceso a sus cuentas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2021-08-25','- Amalia : llama J.F. enfrentamiento familiar con la madre y lo ha echado . Quiere que le demos ya la plaza en centro o dienro para un hostal . Hoy llama la madre , sigue en la casa con ella . Hoy está pidiendo dinero .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-08-25','-Amalia , contacto con CRR de Merida para preguntar si han visto a Emi por allí , respuesta: Hola Amalia, Ayer en cambio de turno se comentó que José María había dicho que Emi estuvo en la puerta del CRR y le trajo dinero. Nadie de nosotros la ha visto, es lo único que escuchamos. Cualquier novedad te contamos. Abrazo, Gisela','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-08-25','Ana: Envío C.I. firmado para vacuna Covid a Raquel (administracion.crrmerida@grupo5.net), pues a Javier no le han vacunado en el hospital. ······· Acudirán hoy mismo al IFEME. ················· Por otra parte, solicito nos envíen presupuesto de gastos de bolsillo para hacer la autorización. *Solicito también que, una vez asignado médico de Att. Primaria en Mérida, le soliciten Informe de Salud para valoración de Dependencia (adjunto el modelo). *Cumplimento y pongo para la firma la Solicitud de Valoración de Dependencia. ······························································································································································································· A petición de Javier, Director, y Gisela, TO, del CRR de Mérida, mantengo conversación telefónica con ellos y con Javier Agudo, pues nadie le explicó en el hptal. que la plaza a la que ha accedido es privada y tiene que pagarla. Dice que no puede permitírselo, que es muy cara. Se ha puesto muy nervioso y ha comenzado a decir que se quiere ir, que le cobren el día que ha estado pero que él se va. **Tras mantener la conversación, accede a estar al menos una semana y media en que se realizarán gestiones pendientes y necesarias (Asignación de médico, Solicitud de Valoración de Depenendencia, Renovación del DNI...) y volverán a valorar la situación pasado dicho plazo (no accede a más tiempo a priori). Se le informa de su situación económica actual (sí que puede permitírselo una temporada) y se le explica lo necesario de que permanezca en un recurso como el que está, con los profesionales de apoyo con que cuenta. Se le expone también brevemente, de la protección que supone para él la Tutela. ········· En cuanto a su petición de ir a un Centro de Acogida, se le informa de la dificultad actual por la falta de plazas disponibles. ································································································································································································ Tras hablar con Soraya, de la derivación a UME, llamo a Estrella, TS del CSS-Plas. Se informará al respecto, pues no tiene conocimiento sobre ello, y me llamará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-08-25','Ana: Tras hablar con Pilar, Resid. FEMAR Logrosán, me envía correo-e (residenciafemar2019@gmail.com): "Buenos días, según conversación mantenida telefonicamente le informo del ingreso en UCI de Valentina Fernandez Trejo. Pasamos sus datos al Hospital San Pedro de Alcántara por si fuese necesario firmar algún documento que requiera el hospital. Le rogamos nos mantengan informados. Pilar Manzano Azañon (Residencia Femar Logrosán) 639585489. Un saludo." Valentina está ingresada en el Serv. de Cardiología, tras avisar al 112 la trasladaron a urgencias con arrítmias importantes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-08-25','Ana: Llamo al Dr. Daniel Martín (56176), pero me dicen que no está. Me atiende Javier, Médico Digestivo. Me informa que a pesar de la transfusión de sangre hoy se ha anemizado un poquito y ha tenido unas décimas de fiebre. De momento no hay previsión de alta en pocos días. **Me enviará el un informe breve. ································ Finalmente, dadas las fechas, acuerdo con Ángel, Asesor Jurídico, y así procede, que lo comunicará a la Fiscalía para que con carácter de urgencia adopten las medidas cautelares para proceder al ingreso en recurso residencial adecuado, pues la vivienda no reune los requisitos apropiados para regresar a mismo. *Adjunta informe de futuex e informe médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-08-26','-Amalia : pongo para firma el cambio del N º cuenta de la pnc .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-08-25','Ana: La secc. ecca. da ok al presupuesto que presentan desde el CSS de una clínica dental (1.000€)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='MINERO'and apellido2='PEGUERO'),'2021-08-26','-Amalia , paso para registrar a PNC modelo de alta a 3º','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICOLAS'and edp.apellido1='SANCHEZ'and apellido2='AREVALO DONOSO'),'2021-08-26','-Amalia , paso para registrar a PNC modelo de alta a 3º','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-08-26','Ana: Recibo correo de Estela Enriquez Gía, PNC Málaga (estela.enriquez@juntadeandalucia.es): Buenos días, ya está resuelto el expediente de COSTI ALEXANDRU RIZEA. Le ha sido concedida la Pensión No Contributiva, se abonará la primera mensualidad a primeros de octubre. Un saludo y gracias por la ayuda. Estela"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTIBALIZ'and edp.apellido1='MENDEZ'and apellido2='CARRASCO'),'2021-08-25','-Amalia : se comunica desde PNC cambio de cuantia q pasa a 321,46€ con efectos 1/7/21 al computar los ingresos laborales que percibe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-08-26','Ana: Conversación con la Dra. García, UCI HSPA-CC (56430): Valentina llegó al hospital con insuficiencia respiratoria con retención de carbónico. Le tuvieron que entubar y conectar a máquina respiratoria. Están intentando despertarle del coma y quitarle el tubo para ver si puede respirar por sí misma. Si evolucina bien la pasarán a planta. Hay que tenen en cuenta sus otras patologías de base (insuficiencia cardíacas entre otras). Una vez pase a planta se valorará si necesita y se puede poner acompañamiento. Pues están estableciendo restricciones debido a un brote de Covid en el hptal. ········ Suelen llamar para informar casi a diario entre 13 y 13:30h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2021-08-26','Ana: Correo de Blanca, Directora del CRR-Plas.: "Buenos días ANA, Os comento sobre Félix Franco, tiene prevista una salida del 6 de septiembre al 12 de septiembre a Calpe con su primo Enrique. La noche del 11 la pasará en Madrid en casa de su prima Laura. Estas salidas ya las realizó un año y por nuestra parte no hay inconveniente." ············ Respondo que por la nuestra tampoco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-08-26','Ana: Envío correo a Alberto: "Hola de nuevo, Te reenvío otro correo con presupuesto, aunque aparece en la imagen como “PAGADO”, aún no se ha pagado es un presupuesto. Como es muy necesario, y la ropa que le han donado en el centro no le sirve, para no demorarlo más (pues el presupuesto es del 6/07) LO HE AUTORIZADO “unilateralmente”, jeje, ya sé que su situación ecca. no es boyante, pero es más que necesario. El lunes irán a recoger la ropa y nos facilitarán la factura para abonarla. Seguimos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-08-26','Ana: Correo de Estrella, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Buenas de nuevo. Con respecto a la cuestión que me plantaste ayer sobre Javier Agudo Cumplido, pregunté a los Psiquiatras y me dijeron que sí habían aceptado la derivación de la UHB, pero que desde el CRR no puede ser derivado a UME, ya que si está en CRR es porque está estable..." ····························································································································································································· Gisela, CRR, envía presupuesto de gastos de bolsillo, le indico que Alberto no está hasta el martes, así que habrá que esperar para su aprobación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2021-08-26','-Amalia : su grado de discpacidad queda prorrogado hasta 2022 , el CADEX enviará resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-08-27','- Amalia : La Jafa de Seccion de SSSS nos envia email con los correos intercambiados con Ana para gestionar Renta Extremeña Garantizada. Estimada Juana, He estado esperando la llamada de la Trabajadora Social, que me hayan asignado para poder tramitar la Renta Básica. No se si no se enteró bien de la cuestión planteada que es la siguiente, Tengo que tener la solicitud registrada antes del día 1 de septiembre de 2021 - plaza límite o máximo para renovación el 31 de agosto- Vds. me indicaron que la Trabajadora Social de Zona Dª Susana Gámez, está de vacaciones y que no se incorpora hasta el día 1 de septiembre- yo ya estaría fuera de plazo- Les llevo solicitando una sustituta para que pueda atenderme desde el día 16/ 17 de Agosto; En relación de las dilaciones a la hora de asignarme a una sustituta, que pudiera atenderme dentro de los plazos marcados, indicarle lo siguiente- - La privación del acceso a la Administración, al derecho y su efectividad, por causas ajenas a esta parte- como pueden ser las cuestiones normativas internas o de cualquier naturaleza, en este caso, cuestiones organizativas y de servicio- de la plantilla de personal, en relación a las vacaciones- no es que solamente sea causa de nulidad, por vulnerar normas de carácter imperativo y prohibitivo, y tener otras como consecuencia otras que igualmente lo son, como son el privar del medio de subsistencia y de vida de esta; Imponer castigos o sanciones totalmente prohibidos por el ordenamiento júrídico, para quien está cumpliendo con los requisitos y presupuestos que me marca la ley, inlcluido los plazos, y no obtener una contrapestación adecuada por parte de la Administración, el garantizarme el acceso a mi derecho en los plazos que marca la ley. Dicha "discriminación legal", en cuanto al tiempo en que yo realizó mi solicitud, por causas ajenas a mi, ya sean normativas, de tramitación o de cualquier naturaleza, como son las vacaciones, y con los efectos legales de pérdida de mi derecho y del medio de subsistencia y de vida, no puede repetirse, al igual que acaeció el año pasado en la solicitud inicial de la Renta Básica y otras Ayudas,- de los hechos del año pasado, que aún están pendientes de recurso- me hicieron Vds, perder 8 meses de renta básica que aún están pendientes de recurso parar recuperar- puesto que yo solicité cita en Diciembre y hasta el mes de julio no me registraron la solicitud, por causas ajenas totalmente a mi, como pueden ser no darme cita o una vez dada pedirme los mismos documentos en más de cuatro ocasiones durante las mismas y meternos en un Estado de Alarma por un coronavirus. En cumplimiento de la normativa y para evitar más daños y perjuicios a esta parte y a la propia Administración- y con ello gastos a los ciudadanos- y evitarnos cuestiones litigiosas, en todos los ordenes incluido el penal, algo totalmente increible, para poder presentar una solicitud de Renta Básica, es necesario, que Vds. también pongan de su parte a la hora de solventar estas cuestiones. Le agradecería que en cumplimiento de las obligaciones legales, puesto que yo estoy cumpliendo con las mias, solicitando cita en tiempo y forma- y yo no tengo la culpa de que no cogan Vds el teléfono en muchas ocasiones- me dieran cita el lunes o el marte, el último día que tengo para registrar las cosas, yo prefiero el lunes a partir de las 12- si la Srª Trabajadora Social, tiene hueco de agenda, si no es posible, cuando ella tenga hora. Pero tiene que ser inexcusablemente antes de la fecha límite. Yo no tengo coche, por lo que no puedo desplazarme 16 km todos los días- ida/vuelta hasta la parada de autobús- y he estado sin mi teléfono habitual por pérdida y problemas con la compañía de telefonía móvil cerca de un año. Otra razóm más, para que yo no pueda desplazarme todos los días a su oficina o al Centro a presentar quejas/ recursos en queja por las causas mencionadas o esperarme en la puerta de su oficina a que en el mejor de los casos Vds. me puedan atender. En relación a la documentación que Vd me envía de otra persona, le agradecería igualmente, que tuviera precaución en relación a los datos de carácter personal y el derecho al honor de otras personas, Vd. ni siquiera sabe o si lo desconozco- si los datos remitidos pudieran ser de algún familiar e igualmente, constituye una vulneración de sus derechos legales.- Le vuelvo a dar las gracias, pero es necesario que agilice el tema de la cita, para que pueda registrarse en plazo adecuado y no se vulneren mis derechos igualmente. Quedo a la espera, y con impaciencia claro, que la que se queda sin prestación soy yo y sin ser culpa mía.- ANA MARIA ROSCO AVALOS Teléfono: 616729463 De: Juana Martin >juana.martin@merida.es> Enviado: jueves, 26 de agosto de 2021 7:53 Para: amra ra >rosam982@hotmail.com> Asunto: Re: RB Sí, apórtalo. Gracias El 25/08/2021 a las 13:26, amra ra escribió: > Estimada Juana, > Necesito me indique si necesito el documento de de vida y estado del registro civil.Por soltera yo no libro familia. > > El año pasado me lo pedisteis. > > Ana María > > > > Get Outlook for Android > From: Juana Martin >juana.martin@merida.es> > Sent: Wednesday, August 25, 2021 1:17:07 PM > To: rosam982@hotmail.com >rosam982@hotmail.com> > Subject: Re: RB > > Ana por error te he puesto otra contraprestación de otra persona , te > ruego la elimines de tu correo.Te remito la tuya > > El 25/08/2021 a las 13:01, Juana Martin escribió: > > Ana te remito los documentos adjuntos que deberás presentar cuando tu > > trabajadora social te llame para el trámite de la Renta > > Garantizada.Además de lo adjunto tiene que presentar justificante de > > haber tramitado ingresos mínimo vital. siendo esto imprescindible para > > el trámite de la renta. > > > > También te adjunto la contraprestación que ( programa de > > acompañamiento para la inclusión), necesario su cumplimiento para la > > concesión de la Renta Garantizada. > > > > > > > > Juana Martín Romano. > > > > Jefa de Sección de Servicios Sociales. > > Juana Martin >juana.martin@merida.es> Vie 27/08/2021 8:38 -------- Mensaje reenviado -------- Asunto: RE: RB Fecha: Fri, 27 Aug 2021 00:35:02 +0000 De: amra ra >rosam982@hotmail.com> Para: Juana Martin >juana.martin@merida.es> Estimada Juana, He estado esperando la llamada de la Trabajadora Social, que me hayan asignado para poder tramitar la Renta Básica. No se si no se enteró bien de la cuestión planteada que es la siguiente, Tengo que tener la solicitud registrada antes del día 1 de septiembre de 2021 - plaza límite o máximo para renovación el 31 de agosto- Vds. me indicaron que la Trabajadora Social de Zona Dª Susana Gámez, está de vacaciones y que no se incorpora hasta el día 1 de septiembre- yo ya estaría fuera de plazo- Les llevo solicitando una sustituta para que pueda atenderme desde el día 16/ 17 de Agosto; En relación de las dilaciones a la hora de asignarme a una sustituta, que pudiera atenderme dentro de los plazos marcados, indicarle lo siguiente- - La privación del acceso a la Administración, al derecho y su efectividad, por causas ajenas a esta parte- como pueden ser las cuestiones normativas internas o de cualquier naturaleza, en este caso, cuestiones organizativas y de servicio- de la plantilla de personal, en relación a las vacaciones- no es que solamente sea causa de nulidad, por vulnerar normas de carácter imperativo y prohibitivo, y tener otras como consecuencia otras que igualmente lo son, como son el privar del medio de subsistencia y de vida de esta; Imponer castigos o sanciones totalmente prohibidos por el ordenamiento júrídico, para quien está cumpliendo con los requisitos y presupuestos que me marca la ley, inlcluido los plazos, y n