insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-08-27','-Recibo llamada de UHB LLerena , de la TS ,le han concedido pasar a UME pero hasta dentro de 2 meses no hay plaza. Ha preguntado en centros de transeuntes y no hay plaza en ninguno .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-08-27','aMALIA : remito email a Soraya Masa y Mayte ( Jefa Seccion CTAEX ) Buenos días , en llamada telefóncia , la TS de la UHB de LLerena me ha informado que Ati ha sido aceptado para UME , pero que hasta dentro de 2 meses no tiene plaza . La psiquiatra le ha pedido a Mª Eugenia que busque plaza en centro de transeuntes , hay lista de espera en todos ellos . Si la idea es dar un alta a la espera de plaza , no habrá posibilidades de garantizar la continuidad asistencial ni el plan de intervención previsto para él desde la Comisión Tutelar. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-08-27','Ana: A petición de Rosa, TS Higuera de la Real (924 727 001 / rmarquez@higueralareal.gob.es) le remito la Modificación del Contrato de SAD firmada por el Representante Legal. Al parecer se había enviado sin firmar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-08-27','Ana: Envío a Marisol, TS del HUC, la solicitud para plaza T3 que me remite debidamente firmada y sellada por el Representante Legal. ··· Le envío también la copia del DNI de D. Gerente, Nombramiento y Delegación de Competencias. ······························································································································································································ Recibimos en el ctutelar, informe de la policía local (policialocal@valenciadealcantara.es) con fotos de la habitación de Manuela firmado por Juan Antonio Morato Bonito - Oficial Jefe de Policía Local. ······ *Sólo indica que se adjuntan fotos del derrumbe y que José Manuel hace constar que durante la obra llevarán a la abuela a "su segunda residencia" en la localidad de El viso de San Juan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-08-26','Ana: Conversación con Marisol, TS del HUC (56823): Han pasado la herramienta T3 a Manuela y ha dado 27 puntos. El problema es que en estos momentos no hay plaza disponible en toda la provincia de CC, no sabe si las habrá en BA. *Necesitarán Certificado de Convivencia, Fotocopia del DNI, Tarjeta Sanitaria y Cdo. de Pensión. **Le remito toda la doucumentación por mail a excepción del Cdo. de Convivencia, que Julio CTAEX solicita al Ayto. ······· Otro inconveniente es que también hay que presentar los justificantes de Ingresos de los convivientes. El nieto no querrá facilitarlo. *Pero de momento, mientras no haya autorización judicial para el ingreso, no se le informará de las gestines que estamos realizando al repecto. **Marisol hablará con Pedro u alguna compañera de Recursos Residenciales de Mayores de Serv. Territoriales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2021-08-27','Ana: Estrella, TS CSS, me comunica que Margarita le ha pedido que le soliciten la P. de Orfandad. *Intentarán obtener los datos necesarios del padre así como la fecha y lugar de defunción. **Tampoco sabemos si alguno de los dos padres cotizaron en su día.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-08-30','Amalia : no se puede solicitar valoracion CADEX ,ni DEPENDENCIA , pq no tenemos informes médicos , ni ella aceptaría ir al CADEX , ni permitiria acceso a su domcilio de Dependencia. Está tramitando REG , para su renovación. "Actualmente no tiene reconocida una discapacidad ni está valorada por la Ley de Dependencia. Desde la Comisión Tutelar de Adultos, no se ha podido tramitar las correspondientes solicitudes de valoración debido a la no disponibilidad de informes médicos necesario para ello y a la imposibilidad de valorarla ya que se niega a ir al Equipo de Salud Mental (Doc.Nº4). Sin embargo, de la Sentencia de Incapacitación nº 29/2020 referido al procedimiento de incapacitación ICP INCAPACITACIÓN nº 136/18 ante el Juzgado de 1º instancia e instrucción nº1 de Mérida, se desprende conforme a su fundamento de derecho Primero, que conforme informe del Forense, tiene trastorno psicótico por ideas delirantes de perjuicio por parte de terceros, trastorno querulante, de curso crónico y mal pronóstico en ausencia de conciencia de enfermedad. Y la propia juzgadora comprobó la incapacidad de la tutelada para gobernar su persona y voluntad de forma que no le permite tomar decisiones en la esfera patrimonial."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-08-30','Ana: Llevo a registro (ORVE), comunicaciones de variaciones de datos bancarios del INSS (Pensiones de Orfandad) y PFHC, adjunto certificado bancario con nº de cuenta. **Me dicen que están en pleno proceso de "Migraciones", hasta el día 1 no lo tendrán implementado y hasta entonces no podrán registrar documentos destinados a otras administraciones. ································································································································································································ Hablo con Javier Pecero, Director del CRR-Mérida (606 41 33 88), expongo las respuestas que me dieron tanto en el CSS como en el HSPA. Cualquiera de los procesos se van a dilatar en el tiempo. Intentará hablar mañana desde el CRR con algún Psiquiatra de la UHB, para ver si hay alguna posibilidad de que se le derive desde ahí a UME. *Javier Agudo sigue convencido, y con toda coherencia, de que pudiendo pasar a plaza pública, a la que se le había derivado, no va a seguir pagando plaza privada. Mantiene el plazo de semana y media. ············ Por otra parte, pido a Javier Pecero que le pregunte a Javier, si recuerda en qué provincia le reconocieron su grado de discapacidad, para poder solicitar el traslado de expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-08-30','Ana: Llamada de Isabel de Cáceres, madre de Alfonso (680 784 490), dice que aún no se le ha ingresado el dinero de la ropa que le compraron a Alfonso en julio. **Me extraña porque Alberto se lo pasó a Icíar para que hiciera la transferencia. No obstante se lo paso a Alberto para que lo comprueben cuando puedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-08-30','Ana: Hablo con el médico de guardia de la UCI - HSPA (56434): Valentina está evolucionando muy bien. Han conseguido extubarla y le han controlado las arritmias mediante medicación ("control farmacológico"): Posiblemente hoy mismo le den el alta en UCI y pase a la Planta de Cardiología. ·········· Lo comunico a Pilar, directora de la Res. Femar de Logrosán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-06-26','Mar 22/06/2021 13: Amalia , escribo a Seguridad social : felipe.cabezas@seg-social.es Buenos días , Como tutores de DÑA. MARIA LUISA ESPINAR DEL ARCO , con DNI 00473356Q , solicitamos información sobre la prestación comunitaria de Alemania que ha dejado de percibir de 746,48€/mes . ( De Renten Service Deutsche ) . Actualmente , se encuentra ingresada en la Residencia de Mayores de Puente Real II en Badajoz y envié una fe de vida actualizada hace unos meses a Alemania por si pudiera ser el motivo de la suspensión de la pensión. Gracias por tu atención. Quedo a la espera de respuesta para poder activar dicha prestación. Un saludo Amalia Díaz González Trabajadora Social de Comisión Tutelar de Adultos de Extremadura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2021-08-30','-SE ENVIA POR RGTO. SALIDA TODA LA DOCUMENTACION DE INGRESO EN CENTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2021-08-30','Recibimos Sentencia condenatoria de la AP, de Badajoz, sección penal, PO 15/2020. Le condenan a: 1. Por el delito continuado de amenazas en el ámbito de la violencia de género la pena de 9 meses y 1 dia de prisión. 2. Por Por el delito de agresión sexual sobre menor de diecíseis años en grado de tentativa con la circunstancia agravante de discriminación 3 años y 10 meses de prisión. 3. Por el delito de lesiones en el ámbito de la violencia de género de art. 153.1 y 3 del C.P. la pena de 9 meses y 1 dia de prisión. 4. Por el delito de maltrato habitual del art. 173.2 del C.P. la pena de 1 año, 9 meses y 1 dia de prision. 5. responsabilidad civil se condena al citado procesado a que abone a la perjudicada Doña Noelia Mendo Sánchez en la cantidad de 40.000 euros en concepto de daños morales, y en la de 400 euros por las lesiones causadas. 6. Privación de la patria potestad por tiempo de 6 años. 7. Asi como de conformidad con el articulo 192 del C.P._por el delito de abuso sexual continuado y de aqresion sexual en grado de tentativa sobre menor de dieciseis años, Ia medida de libertad vigilada par tiempo de 5 años y la pena e inhabilitacion especial para cualquier profesion u oficio, sea o no retribuido que conlleve contacto regular y directo con menores de edad durante un tiempo de 7 años. 8. Pago de las costas procesales conforme a lo dispuesto en el artículo 123 y 124 del Código Penal. TOTAL DE PRISIÓN: 7 AÑOS, 1 MES Y 3 DÍAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-08-30','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informaros que Felisa Bruno está ingresada en la unidad de salud mental desde el sábado por la mañana. Ha tenido varios momentos de agresividad hacia profesionales y residentes coincidiendo por la noche. La última fue el sábado agredió a una cuidadora y a una residente dándoles golpes con el palo de una fregona. Tuvieron que llamar al 112. Ambas personas agredidas tienen parte de lesiones. A la cuidadora además de los golpes en la cabeza y espalda por los que va a ir a la mutua porque no mejora, le rompió la casaca y las gafas. Estamos viendo si entra en el seguro del centro, ya os informaré. Esta mañana contactaran con la psiquiatra para ver cómo se encuentra. Nos han pedido algo de ropa. Al no tener viaje a Cáceres se lo vamos a mandar por correo, son 9 € pero no tenemos otro medio ahora mismo. Yo estoy de vacaciones pero puedes llamar al centro y te informarán. Un saludo,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-08-27','Ana: Juani, TS del HSPA (56341), tras consultarlo con el Psiquiatra, me comunica que desde el hptal. ya no pueden hacer nada, pues además Javier ya no está en el mismo área de salud... Que para que Javier pudiera acceder a UME, tendría que inciar el circuito de cero: Ser derivado a ESM para que el Psiquiatra valore si requiere ingreso en UHB y de ahí a la UME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-08-30','Ana: Conversación con la Dr. Carmen, de Apto. Digestivo: La evolucón de Manuela es regular. La hemorragia está estabilizada, pero actualmente presenta picos de fiebre e infección respiratoria, para lo que le están tratando con antibióticos, así como escaras en talones y sacro. En su opinión NO ESTÁ EN CONDICIONES DE VOLVER AL DOMICILIO, es posible que diera puntuación para plaza sociosanitaria tipo T1. Le indico que le pasaron la herramienta la semana pasada y dio 27 puntos (T3). Cree que habría que revalorarla, pues posiblemente dé mayor puntuación a día de hoy. **Le pido que nos envíen informe sobre la situación actual y la necesidad de cuidados que presenta, para que podamos remitirlo a Fiscalía. ········· Si no puede hoy lo hará mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MILAGROS'and edp.apellido1='CORDERO'and apellido2='DIEGUEZ'),'2021-08-31','Ana: Correo de Estrella, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenos días. Informo que Milagros Cordero Diéguez ha dado positivo en covid, está asintomática y ha sido trasladada a la unidad covid de este centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-08-31','-Amalia : escribo a Alberto , seccion eco : Buenas , este caso pasa a mi zona , en un principio Ana se encargó del Plan Inicial y os pidió que no se le diera asignación mensual para intentar que pasase por el SEPAD y poder activar el 112. Se le dió una inicial y me dice Iciar que no se ha vuelto a pedir nada nuevo . Desde la entidad bancaria le dan toda la prestación por miedo a pesar de no tener nuestra autorización. Quiero regularizar esta situación , se le autorizará a sacar toda la mensualidad hasta que el juzgado nos autorice al ingreso involuntario que hay solicitado. Seguimos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-08-11','Ana: Correo de Toni, Futuex: "06/08/2021 Área económica (factura clínica dental): Desde la clínica dental Aqua envían la factura del arreglo dental de Isabel, se contacta con la misma para consultar a qué se debe el coste y qué se le hizo en la consulta de ayer, comenta que ha subido porque tienen que poner dentadura nueva en algunas piezas, pero ayer sólo se hizo limpieza, radiografía y curetaje, por lo que no es el total. Se le solicita que vayan enviando las facturas fraccionadas de cada consulta, aunque al área económica también se le haga llegar la total que han facilitado, comenta que sin problema, la hará y la enviará. De momento, se adjunta, en documento a parte, la que han facilitado." ······· Se lo paso a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-08-25','Ana: Correo de Alberto, Jefe Secc. Ecca. CTAEX para Estrella, secc. ecca. y para mí: "2021/08/25: ANA/ALBERTO: Futuex nos remite factura (en realidad se trata de un presupuesto) de la clínica AQUA, que va a atender a la tutelada. Se ACEPTA dicho presupuesto x un total de 1.074 €. Se irá abonando a través de facturas parciales que nos remitirá la clínica, bien directamente, bien a través de Futuex o Ana. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-08-31','Ana: llamo al INSS, a Ignacio Tejada, Jefe Secc. P. Jubilaciones (927 62 00 62), en relación al embargo que ñe están prácticando en su pensión, pero no obtengo respuesta. ····· Pruebo a llamar a Control de Pensiones, pero tampoco obentgo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-08-31','Amalia : email a Soraya y Angel , vamos a intentar agilizar los dos meses de espera para entrar en UME via judicial . Le he pedido el escrito de respuesta de aceptación UME a la TS de la UHB Llerena. Buenas , te envio la respuesta de Ángel con respecto a solicitar orden judicial para agilizar ingreso en UME. Sería posible obtener esa derivación que ya se ha aceptado a UME para enviarla a Fiscalía ? Como la TS del CSS está de vacaciones , a quien se la podría pedir ?? Seguimos.. Angel Marín Martínez Lun 30/08/2021 14:49 Buenos días, La autorización judicial de ingreso involuntario que solicitamos y el Juzgado nos concedió a finales del año pasado, era para su ingreso en la UHB (Unidad de Psiquiatría), del Hospital de Mérida, por el tiempo imprescindible según criterio de los médicos que le atiendan y en tanto persistan las circunstancias tenidas en cuenta para la concesión de la autorización. Si los médicos entienden que ya está para el alta, se supone que es porque está estabilizado, desde el punto de vista médico, con lo que no contaríamos con el aval en el que justificar su ingreso involuntario, de nuevo, en centro, en este caso en el CSS, de Mérida, a no ser que desde la UHB, hagan la derivación a CSS, de Mérida, para que aquí ingrese y el Juzgado se ratifique en 24 horas, pero como dices, no hay plaza hasta dentro de 2 meses. La solicitud de ingreso involuntario por nuestra parte, debe estar basada en una inestabilidad médica, para apoyarnos en eso, pero se supone que para eso ha estado ingresado en la UHB, aunque si la UHB ha aceptado su derivación al CSS, de Mérida, será en base a algo. En este caso lo pediríamos basándonos en este criterio y lo enviaríamos a Fiscalía antes, para intentar agilizarlo. Hablamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-08-31','Ana: Tras las llamadas de Felisi, madre de Aitor y Jesús, pareja de ésta, pidiendo dinero pues según dicen se le ha autorizado muy poco a Aitor y érte "come mucho" y ya no tienen ni para pagar el billete de vuelta el día 4 a Castuera. *Llamo a Toni, Adiser Horizontes (924 76 10 09 // 678 54 22 41): El billete de autobús no lo pueden comprar de ida y vuelta porque hace trasbordo en Don Benito. *Para la próxima vez verán la posibiliad de que se vaya en tren (que no saben si hay trayecto directo) o preguntar si hay alguna manera de que lleve todos los billetes cerrados. **En esta ocasión no le han enviado un lote de alimentos porque Jesús les dijo que eso a ellos no le solucionaba nada, que lo que necesitan es más dinero... A partir de ahora se lo enviarán cada vez que vaya, para que al menos no puedan quejarse por la comida. ············· Hablo con Alberto, jefe secc. ecca.:','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2021-08-31','Ana: Reenvío a Alberto, jefe secc. ecca., correo de Gema Sánchez, Directora Res. Malpartida de Cáceres - Grupo Nexus (gsanchez@nexusintegral.com): Se deben varias faturas de farmacia y necesitan se autorice los pagos de los medicamentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-08-23','Ana: Correo en el ctutelar@ del CRPS: "Buenas tardes Teresa Te adjunto la información de una excursión que va a realizar Mª Elena del 8 al 15 de Septiembre con el CRPS de Zafra. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-08-31','-Amalia , envio email a Angel : Buenas Angel , he conseguido el documento de aceptación a UME para derivar a Fiscalía . Hasta dentro de 2 meses no sería posible su ingreso y desde la UHB de Llerena le quieren dar el alta . Se podría justificar en base a que Ildefonso no tiene domicilio fijo , ni posibilidad de acceder a ningún recurso social ( ha sido expulsado de los hostales , no hay plazas en Ctro. transeuntes y nadie le quiere alquilar piso ) , ni dispone de red familiar ni social de apoyo y a fin de garantizar su continuidad asistencial , adherencia a tratamiento y rehabilitar habilidades sociosanitarias perdidas se solicita la oportuna autorización judicial para ingreso en CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-08-31','Ana: Envío a Alberto, jefe secc. ecca., la documentación relativa a la compra-venta de trastero de Felix, para el ejercicio IRPF 2019, que remite Paqui López. Para que puedan remitirlo a la Gestoría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2021-08-31','-Amalia : llama su hno. Fernando , le piden para la testamentaria documento de acreditacion de J.Vicente . Se lo paso a Angel .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2021-08-31','Amalia : Ángel ha revisado el documento enviado por VPP , lo pongo a firma gerente .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2021-08-31','Ana: Llamo a Felisi, madre de Aitor (722 494 033): le comunico que entre el jueves y el viernes podrá retirar 15€ para el billete de autobús para el regreso el día 4 al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-08-31','Ana: Llamada de Felisi (722 494 033), hablo con ella y con Jesús. Vuelven a pedir dinero para unas zapatillas y renovación del DNI. *Le transmito lo mismo que el mes pasado. *No obstante lo hablo con Alberto, NO se le dará más, debe administrarse con su asignación periódica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-08-31','Ana: Llamo a David LEFEVRE - Servicio de Asuntos sociales "Consulat Général de France à Madrid" (91-700-78-36), para intentar verificar su identidad francesa, me pide que le envíe todos los documentos de que dispongamos junto a una foto actualizada de su rostro. **Una vez la haya verificado, ya vemos cómo proceder después, pues a priori, para poder expedir documento de identidad francés, debería trasladarse al Consulado para tomar su huella. *Le indico que, a priori no es factible, pues se haya incapacitada para desplazarse. ····························································································································································································· Envío correo a Sandra, TS Res. Real Patronado de Coria Sandra (alexandra.alfonso@coria.org) solicitando fotografía a color de Rosario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-08-31','Ana: recibo llamada de Begoña, directora de la Res. Santiago de Alcántara (680 799 543): ya ha cesado en el puesto. El Ayto. vuelve a asumir la gestión del centro. Llama para despedirse y comunicar que de momento se queda de referencia Beatriz, TO, por si necesitamos algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2021-08-26','Ana: llamada de Laura, Gerente Asoc. Vera (687 37 44 56): dedebido a un brote de Covid en el centro, se pospone la salida por vacaciones de Mª Carmen. Ellas se encargarán de llamar al hostal y cambiar la fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2021-08-26','Ana: llamada de Laura, Gerente Asoc. Vera (687 37 44 56): dedebido a un brote de Covid en el centro, hay que posponer el regreso de Adrian (se encuentra de vacacione en el domicilio familiar). El viernes 3 harán otro cribado en el centro, si dieran todos negativo organizarían el regreso de Adrián para el día 7. *Ya lo han hablado con Teresa, Ed. Futuex para organizarlo todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2021-08-31','Ángel. Hablo con Fernando, hermano de María Fernanda (627523544) porque le han pedido desde el Banco Santander, de Los Santos de Maimona (Noelia), algún documento con la firma de José Vicente. No sabe decirme exactamente que es. Entiendo que se refiere a la acreditación como tutor de la hermana. Le doy mi teléfono para que nos llamen desde el Banco Santander y hablemos con ellos. Está tramitando la herencia de su hermana fallecida (María Rosa). Son 4 herederos. REMOCIÓN. Al mismo tiempo me dice que está en trámites de solicitar ser tutor de su hermana, lo ha puesto en manos de su Abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-08-31','Ana: Registro de ENTRADA, en la Direcc. Gral. de SS.SS., infancia y familia, las comunicaciones al INSS de variación de datos de las 3 pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2021-09-01','Ana: Correo en ctutelar@ de José Aº Pulido, TS de de Sierra de Montánchez (tsocial1@mancomunidadsierrademontanchez.es): "Buenas tardes! Adjunto se les remite presupuesto de vacaciones para la residente del piso tutelado de Almoharín, María Jesús Criado Rodríguez ,con el fin de que den su consentimiento y el visto bueno. La residente carece de familiares y desde que ingresó en el Piso nunca fue de vacaciones por ello hemos considerado que le vendría bien disfrutar de unos días en el mar como nueva experiencia. La chica sería acompañada por una cuidadora de confianza que en este caso sería la cocinera del Piso tutelado, persona con la que mantiene muy buenas relaciones. Esperando una respuesta de su parte, a la mayor brevedad posible, se despide de Vds con un cordial saludo." ··········· Se lo reenvío a Alberto, si es viable por mi parte OK.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-01','Ana: Tras hablar ayer con Soraya Masa, Jefa Ud. PP.AA., envío un correo a Estrella para que por favor, hable de nuevo con el equipo y se reconsidere el ingreso de Javier en UME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-09-01','Ana: Llamada de Alejandro, Médico del HSPA (51689): Si todo va bien, hoy mismo procederán a darle el alta. Está estable, la arritmia controlada y la insuficiencia cardiaca con la medicación también. Le han pedido PCR y si da negativo pedirán la ambulancia para que puedan trasladarla a la residencia. ············ Lo comunico a la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-01','Ana: puesto que no recibí, ni ayer ni antesdeayer, el informe que acordó la Dra. Carmen en enviarme, llamo al HUC (56176), hablo con el Dr. Javier Molina. Ayer, sorprendentemente vio a Manuela muy bien, le quitó la sonda vesical y el oxígeno. Remontó mucho de un día para otro. Hoy, si sigue así, le podrían dar el alta. Dado que dio puntuación para T3 y aún estamos pendiente de Fiscalía, le pido que aguanten un poco, pediré a mi compañero que llame a Fiscalía hoy mismo. ········ Hablo con Ángel, Asesor Jurídico CTAEX. ················· Ángel llama a Fiscalía, le confirman que recibieron el correo y los informes, pero que Camen Barquilla, Fiscal de CC, hasta mañana no se incorpora y por tanto no nos han podido dar respuesta. ······························································································································································································ Llamo a Marisol, TS HUC (56823): "ya envió solicitud de T3, hablará con Pedro, de SS.TT.-CC. ······························································································································································································· Llamo de nuevo al Dr. Javier Molina - HUC (56176), me atiende un compañero suyo que le tramsmitirá el mensaje y le dará mi extensión por si me tuviera que llamar. Pido que aguanten a Manuela 2-3 días más para que pueda dar respuesta la Fiscal y se termine de tramitar la plaza T3. ······························································································································································································· Llamo a Pedro Sánchez, Gerencia Territorial de CC (927 00 42 24): ya tienen allí el expte. de T3 de Manuela. Le explico la situación. Me pide la Sentencia de Incapacitación, pues la copia que le han enviado está incompleta. Así mismo pide la "Cartilla de Vacunación Covid". ············· **Llamo al Centro de Salud, hablo con Nuria, MAP (54208), me enviará la cartilla de vacunación al final de la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-09-01','Ana: correo de Estrella, TS CSS: "Jairo ya dejó la unidad de aislamiento y está de vuelta en URA" (T.S. de referencia es Mariví Clemente)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MILAGROS'and edp.apellido1='CORDERO'and apellido2='DIEGUEZ'),'2021-09-01','Ana: Correo de Estrella, TS CSS-Plas.: "Milagros continúa en unidad de aislamiento y si sigue todo bien, regresará al Psicogeriátrico el viernes día 3."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-09-01','Ana: Tras coordinación en los días previso con Maru, TS C.S. Manuel Encinas y con Celia y Marta Pascual de Mayores (Gerencia SEPAD), recibo llamada de Marta Pascual, Jefa de Secc. comunicando que Clementa va a ingresar en el C.R. El Cuartillo de Cáceres por Emergencia Social y voluntariamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2021-09-01','Amalia : incidencias de JF , envio email a Julio : gracias por informarme , ya he hablado yo también con él esta mañana. Ahora quiere un centro en Fuente de Cantos , elige hasta el sitio ..o un hostal . No lo he autorizado , hasta no saber para cuando le darían la plaza , no creo que tenga capacidad económica para pagar hostal + manutención + sus enredos ... durante muchos meses. Cuando vuelva Teresa que decida el plan de intervención , es de su zona . ------------------------------------------------------- Hola, Ama: Me ha llamado José Florencio. Está buscando un alquiler por su cuenta. Me ha dado el número de un tal Fidel que, siempre según José Florencio, le alquila muy barato. Te lo digo, más que nada, para que sepas que sigue enredando y que no te coja de nuevas si te llamara, por un casual, el tal Fidel. Su número de tfno., el de Fidel (de Fte. de Cantos), es: 611 617 641.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-09-01','Ana: Recibo llamada de Anabel, TS SSASB Miajadas (927 34 70 00 / servicios.sociales@miajadas.org), me informa que Choni ya no trabaja allí y es ella quién va a asumir ahora sus funciones. *Estamos pendiente de las resolución del CADEX. *Habría que solicitar también revisión del grado de discapacidad y PIA. Quieren solicitar cambio de recurso residencial a uno específico de Salud Mental. *En cuanto tengamos Cdo. del CADEX solicitaré PNC. ················ Anabel me remite el último informe que tiene del ingreso en la UHB. **Solicitaré al ESM todos los informes que tengan del seguimiento de Esteve. ···················· Envío fax a la Dra. Julia Gía. White, Coord. ESM solicitando los informes de consulta del último año y medio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-09-01','Ana: correo-e de Toni de Diego, TS CR Cervantes (antonia.dediego@salud-juntaex.es): "Buenos días Ana te adjunto el informe médico del oftalmólogo de la tutelada Mª luisa Montaño Aliseda, Le han prescrito gafas, así que ya cuando se abra la residencia, contacto yo con virginia para que comience con los tramites de la compra de gafas. un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-09-02','ICIAR: HACER REINTEGRO PERMANENTE A TUTELADA X TOTALIDAD PENSIÓN (HAGO EL ESCRITO Y TE LO DEJO EN EL EXPEDIENTE PARA SU TRAMITACIÓN: ÉCHALE UN VISTAZO) AMALIA: mira su CCC...en negativo...además de reintegro: teléfono y comisiones. IMPOSIBLE DE CONTROLAR. Al autorizarle la totalidad de la pensión nos encontramos con que puede haber desajustes si tutelada NO tiene en cuenta esos gastos añadidos. De todas formas se hace una autorización x la totalidad de la pensión...pero voy a cambiar el texto e incluir la palabra "hasta" el límite de la pensión cada mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-09-02','Buenos días. Como podemos observar, la Fiscalía le ha respondido a Ángel que NO es necesaria la previa autorización judicial para afrontar este gasto. X tanto, entiendo que se trata de un gasto santiario que vamos a afrontar. Amalia, si no estas de acuerdo manifiéstate. Si estamos todos de acuerdo: ICIAR: HABLA CON LA CLÍNICA DIANA SOBRE EL INICIO DEL TRATAMIENTO Y SU FORMA DE PAGO (presupuesto de 5.290 €: tienes copia en correos previos a nombre del tutelado). ICIAR: UNA VEZ TRATADO EL TEMA CON LA CLÍNICA AVISAS AL CENTRO PARA QUE SE LO COMUNIQUE AL TUTELADO E INICIE TRATAMIENTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-02','Ana: Plácido Alejandre (927 00 42 61) nos confirma que tienen plaza T3 para Manuela en Bohonal de Ibor. *Recuerda que necesotaría PCR negativa para su ingreso. ································································································································································································ Ángel, Asesor Jurídico, llama a Fiscalía, donde le indican que el procedimiento adecuado es a través del Jdo. *Ayer ya lo envió. ·········· Llama al Jdo., le indican que "Su Señoría" no ha tenido tiempo de verlo. Esperan poder darnos respuesta mañana. ····························································································································································································· Llamo al HUC, el Dr. Daniel Martín (56176) dice que ya está para alta. Aguantarán a mañana y si no hay respuesta del Jdo. le darán el alta. La analítica está bien, el TAC bien y no presenta dolor ni fiebre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-09-03','Ana: Conversación con Mª Carmen, Admvo. C.R. El Cuartillo (22161): Le facilito el nº de cuenta y el importe de la pensión. *Tiene que abonar el 75% de su pensión. En este caso: 762,67 €/mes. Así mismo le pasarán por su cuenta los gastos de podología y peluquería que pueda necesitar. ·········· *Comunico a Alberto y a Julio - CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-09-03','-Amalia : escribo a la TS de la UHB : Buenos días , he comentado el caso de Ildefonso con una de las compañeras del Centro Sociosanitario de Mérida . Ella piensa dado las particularidades del caso , que el psiquiatra hable directamente con la Directora del centro sociosanitario solicitando la posibilidad de que ingrese cuanto antes. El jurídico está estudiando el caso también . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-09-23','-Amalia : envio el documento de derivacion a UME a Angel para solicitar CSS via judicial . Angel no ve claro que esto se pueda solicitar dado que ya está ingresado en la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-02','Ana: Conversació con Javier, Director CRR Mérida: Javier ha abandonado el CRR. ····· Lo han encontrado más tarde en la C/ Santa Eulalia con signos de alteración. Se ha activado el 112 y lo han llevado al hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-03','Ana: Envío correo a Soraya Masa, Jefa U.PP.AA., con copia a Maite, Jefa Secc. CTAEX: "Buenas tardes Soraya, Ya sé que estás de vacaciones y espero que estés disfrutando. Te envío no obstante el correo para que puedas leerlo a tu vuelta. Esta es la respuesta que me dan desde el Equipo de UME del C. Sociosanitario de Plasencia en relación a la derivación que hizo a UME desde el hospital Universitario de Cáceres de JAVIER AGUDO CUMPLIDO. Como novedad, decirte que ayer Javier abandonó el CRR, lo encontraron después en la C/Santa Eulalia sin camiseta y alterado, la propia policía activó el 112 y lo llevaron al hospital. *Como no había camas en UHB, lo derivaron al hospital Virgen del Puerto de Plasencia. Hoy he hablo con el Dr. Blanco, quién dice que cuando vuelva a haber cama libre en el hospital de Mérida lo volverán a trasladar. Un saludo." ······· Guardo respuesta en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2021-09-06','miguel, llega email de Aexpainba, Soledad Romero Maya: Buenas: El usuario Juan José Murillo, ha sido denunciado en el mes de agosto por un acto de robo. Mando la denuncia realizada para que puedan gestionar este hecho. Se recibirá una notificación del día de la citación en los juzgados, pues se le ha sido asignado un abogado de oficio. Cuando la reciba, os la haré llegar. Si necesitáis más información, no dudéis en llamarme por favor. Me gustaría que en algún momento pudiéramos concertar una reunión, para contemplar la modificación de la capacidad de obrar de Juan José Murillo en su totalidad. **************************** Contesto a Amalia y Belén: Buenos días compañeras, lo guardo en su expediente. Al ser una curatela exclusivamente en la esfera patrimonial, no intervenimos más que en caso de que le impongan alguna multa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2021-09-06','-Amalia : Entrego a Maribel Ramos eleccion de centros tanto para VT como RAL . Tengo que solicitar por PIA CO , aunque ya haya estado hay que volver a pedirlo . Se solicitó por PIA RAL/ VT , pero no C.O sólo . Lo tramitaré para que le den CO en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-09-02','miguel, recibo email de Patricia Bono: Hasta hoy no han podido contactar con la abogada Soledad Carreres, le han expuesto el tema y esa deuda que le reclamó mi hermana por impagos al padre de Alejandro y que no cobró, se puede reclamar, Soledad va a llevar el caso Entonces, no se los pasos que seguirá la abogada, de momento le vamos a pasar toda la documentación. Hazle llegar a la otra parte que esperaba una respuesta a primeros de septiembre que tenemos el tema en mano de nuestra abogada y que estamos a la espera de que estudie el caso y los pasos que va a seguir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-09-06','miguel, remito email a Patricia Bono con copia al abuelo del curatelado Pedro Bono: Buenos días, quedo pendiente me indiquéis en unos días si finalmente vuestra abogada impugnará o no esas cantidades adeudas. Si lo creéis conveniente podemos poner más adelante a los abogados para que entre ellos hablen pues así pueden aclarar sus dudas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-08-23','miguel, email de la inmobiliaria: Buenos días Migue, ya tenemos el certificado de eficiencia energética y comunicarte que la pareja ha decidido que la vivienda irá finalmente solo a nombre de ella de Ana María Muñoz Toro. Tenemos la llave de la cochera y de la vivienda pero nos falta la llave del trastero y hay que facilitarle el acceso al Tasador de la entidad financiera. ¿Podrías decirle al Ayuntamiento que me dieran todas las llaves que tengan?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-08-27','miguel, email de la inmobiliaria donde adjuntan Autorización de la Junta (para la venta): Buenos días Miguel y Belén, ya tenemos (os lo adjunto) la autorización de venta de la junta de Extremadura, ya tenemos todo para proceder a la firma de la escritura. No sé si firmará Juan Carlos Rubio Galán la escritura o tendrá que firmarla algún tutor de la Junta, si así fuera me tenéis que remitir los poderes y cuando vosotros me digáis podemos encargar en la Notaria de Montijo la firma de la escritura de compraventa. Yo estaré de vacaciones desde el día 7 al 15 de septiembre, aprovechando que en Montijo son las ferias y fiestas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-08-29','llega email de Damian: hola miguel soy damian queria saber de que manera me puede ayudar a quitarme la curatela y como pedirle permiso al juez para gastarme los 5000 euros en el presupuesto que me dio la clinica dental diana no le diga nada a gisela que le he escrito porque no quiere que escriba a la comision yo tengo derecho de hablar con usted para eso es mi abogado y me contesta usted por aqui siempre respetandole y no mandarle muchos correos para que usted no se sienta molesto conmigo y para preguntarle tambien como va el tema de mi piso de malaga mi prima alicia esta enfadada conmigo porque ella iba ha hablar con rocio la abogada que teneis la comision que teneis contratada en malaga y mi prima por mandarle tantos correos se ha enfadado y no me contesta no le diga a la comision que yo le he escrito sino amalia se lo dice a gisela y gisela me regaña por eso le escribo a su correo privado un cordial saludo y espero su contestacion a mis dudas muy atentamente damian','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-08-30','llega email de Damian: hola don miguel perdone la molestia queria saber como iba el tema del piso es que le escribi ayer y no he tenido contestacion perdone la molestia es que ya me comento que cuando tuviera alguna duda que podia escribirle a su correo asi me informa usted gracias muy señor nuestro un cordial saludo y disculpe la molestia es que no tengo todavia telefono gracias ****************************** muchas gracias don miguel aunque no me halla contestado se que me esta ayudando me han concedido el presupuesto del dentista de los 5000 y pico de euros para arreglarme la boca gisela me lo ha comunicado esta mañana atraves de amalia de la comision ahora LE MANDO OTRO CORREO CON LO QUE ME ACABAN DE DECIR ESTA TARDE EN LA CLINICA QUE ACABO DE VENIR DE LA CLINICA DIANA DONDE ME VAN HAHACER LO DE PONERME LOS DIENTES ************************************** DIGALE POR FAVOR A LA PARTE ECONOMICA QUE SE PONGA EN CONTACTO CON LA CLINICA DIANA PARA QUE LLAMEN AQUI AL CENTRO PARA QUE ME DEN CITA PORQUE PREVIAMENTE LOURDES DE LA CLINICA DENTAL SE VA A PONER MAÑANA EN CONTACTO CON LA COMISION PARA DE QUE FORMA SE HACE EL PAGO A LA CLINICA SI ES POR TRANSFERENCIA BANCARIA O COMO VA A SER PERO NO LE DIGA A LA PARTE ECONOMICA QUE SE HA PUESTO EN CONTACTO CONMIGO PORQUE GISELA NO QUIERE QUE HABLE CON LA COMISION DIGALE A LA COMISION QUE MAÑANA LOURDES DE LA CLINICA LLAMARA O MANDARA CORREO A LA COMISION DE COMO HACER EL PAGO DEL DINERO YA QUE TENGO 19000 EUROS Y EL JUEZ LO HA AUTORIZADO SEGUN ME CONFIRMA GISELA SE LO HA DICHO AMALIA.EN DEFINITIVA LOURDES VA ALLAMAR A LA COMISION DE COMO HACER EL PAGO A LA CLINICA Y CUANDO LA COMISION PARTE ECONOMICA PARA QUE USTED HABLE CON LA PARTE ECONOMICA MAÑANA .LA PARTE ECONOMICA HABLARA CON LOURDES PORQUE ELLA VA LLAMAR MAÑANA A LA COMISION Y YA LA COMISION SE PONE EN CONTACTO CON LA CLINICA DIANA PARA QUE LA CLINICA DIANA LLAME AQUI AL CRR Y ME DE CITA PARA EMPEZAR HA ARREGLARMWE LOS DIENTES QUE ME FALTAN MUCHOS AYUDEME POR FAVOR DON MIGUEL LE APRECIO MUCHO Y USTED SIEMPRE ME HA AYUDADO ES USTED UNA GRAN PERSONA Y MUY BUENA PERSONA CON LO QUE SEA AYUDEME MAÑANA PARA QUE AMALIA O LA PARTE ECONOMICA SE PONGA EN CONTACTO CON LA CLINICA PARA ABONAR POCO APOCO LO QUE CUESTA PONERME LOS DIENTES MAS O MENOS CON ESTE CORREO ME EXPLICO MI DESEO DE QUE CUANDO MAÑANA LOURDES LLAME A LA COMISION QUE USTED INFORME A LA PARTE ECONOMICA QUE EN LA CLINICA NO LE ME HAN DADO CITA ESTA TARDE PARA OTRO DIA PORQUE LA CLINICA TIENE QUE SABER COMO VA A RECIBIR EL DINERO DE MI CUENTA Y TIENE QUE SABER LA CLINICA COMO LA COMISION LE VA A INGRESAR POCO APOCO LO QUE ME VALLAN HACIENDO EN LA BOCA VARIOS INPASTES QUITARME ALGUNA MUELA Y PONERME MUCHOS DIENTES PORQUE TENGO MUCHA DIFICULTAD PARA COMER CONFIO EN USTED MUY SEÑOR NUESTRO PARA QUE SE ARREGLE EL PAGO Y ME PUEDA DAR CITA LA CLINICA CUANDO LA COMISION PARTE ECONOMICA SE PONGA EN CONTACTO CON LA CLINICA PARA HABER COMO INGRESAN EL PAGO A TRAVES DE MI CUENTA DE LIBERBNK QUE HAY 19000 EUROS SIN NADA MAS QUE AÑADIR MAÑANA LA CLINICA SE PONE EN CONTACTO CON LA COMISION Y PREVIAMENTE POR FAVOR SE LO DIGO CON MUCHA EDUCACION Y RESPETO QUE ME AYUDEN A ARREGLARME LA BOCA .SE LO DIGO PORQUE MAÑANA ES EL ULTIMO DIA QUE TRABAJA GISELA PORQUE PASADO MAÑANA 1 DE SETIEMBRE GISELA COGE VACACIONES PARA QUE HABLEN POR FAVOR CON LA CLINICA DIANA PORQUE YA AMALIA SE LE MANDO PREVIAMENTE EL PRESUPUESTO DESDE LA CLINICA Y GISELA TAMBIEN SE LO ENVIO LE PIDO POR FAVOR QUE ESTA CONVERSACION SEA CONFIDENCIAL QUE ES USTED MI ABOGADO Y NO LE DIGA A AMALIA NI A LA COMISION QUE ESTOY HABLANDO CON USTED PORQUE SE ENFADAN Y AHORA MISMO EL UNICO APOYO QUE TENGO DE LA COMISION ES USTED LE MANDO UN FUERTE ABRAZO Y UN CORDIAL SALUDO DE DAMIAN MUY ATENTAMENTE Y MUCHISIMAS GRACIAS POR ESTAR AYUDANDOME EN CUALQUIER MOMENTO QUE AUNQUE NO ME HALLA CONTESTADO USTED A LOS OTROS CORREOS SE QUE USTED ME HA AYUDADO PARA HABLAR CON EL JUEZ Y ME CONCEDAN EL PRESUPUESTO MUCHISIMAS GRACIAS MUY AGRADECIDO SIN NADA MAS CON MUCHO RESPETO Y AMABILIDAD QUE PASE BUENA TARDE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-08-31','miguel, me llega email de Damian: señor miguel le escribo siempre desde el ordenador del centro y despues borro los mensajes tenia una duda si usted es mi abogado porque no me puede responder a los correos de mis dudas yo no soy mala persona y usted me dijo que cuando tuviera una duda que se lo podia consultar por correo electronico.cuando usted pueda contesteme por favor se lo pido es que necesito su ayuda para eso es mi abogado,me he llegado a la clinica dental de diana y gisela ya le ha enviado un correo a amalia y no contesta para que la clinica se ponga en contacto con la comision y con gisela para que amalia conteste agisela porque tiene que autorizar amalia y que la clinica llame aqui al centro para concederme cita para ir a arreglarme los dientes se lo pido por favor ayudeme y si puede por favor contesteme a los correos se lo pido por favor gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-09-02','miguel, me llega email de Damian: Don Miguel ya le estoy escribiendo desde mi móvil por favor a ver si mañana la comisión habla con la clínica Diana mañana para que me den cita porque Gisela se fue ayer de vacaciones y no viene hasta el día 10.digale a Amalia por favor se lo pido que se ponga en contacto con la clínica que necesito arreglarme los dientes no puedo comer bien y ya este mensaje es privado desde mi móvil contésteme las dudas se lo ruego por favor si usted me lo dijo que podía contar con usted por eso es mi abogado y representante e infórmeme del piso por favor.gracias y buenas noches','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2021-09-06','Buenas: El usuario Juan José Murillo, ha sido denunciado en el mes de agosto por un acto de robo. Mando la denuncia realizada para que puedan gestionar este hecho. Se recibirá una notificación del día de la citación en los juzgados, pues se le ha sido asignado un abogado de oficio. Cuando la reciba, os la haré llegar. Si necesitáis más información, no dudéis en llamarme por favor. Me gustaría que en algún momento pudiéramos concertar una reunión, para contemplar la modificación de la capacidad de obrar de Juan José Murillo en su totalidad. --------------------------------- Miguel contesta q al ser curatela eco , solo tendriamos q pagar la denuncia si fuera el caso . Le paso su tf a la Dtra. para comentar proceso de modificacion.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-09-06','miguel, recibo email de su tía Mely(AMELIA RODRIGO SANZ >melitonarodrigo@hotmail.es>): Buenos días, Miguel, disculpa la tardanza en responderte pero no he podido hacerlo hasta ahora. En cuanto al certificado de últimas voluntades de mi tia Teresa, no lo encuentro en toda la documentación que tengo de ellos, voy a ponerme en contacto con el banco porque se lo haría llegar a ellos y me puedan mandar una copia. En cuanto a escritura de compra de la vivienda o nota simple, no tengo nada de ello porque la vivienda la recibió por herencia de sus padres, mi tia Teresa, que era mis abuelos también, si que tengo relación de bienes de mis abuelos y cómo los reparte entre sus tres hijas, podría hacerte llegar ese documento. No sé cual es el número de la finca pero si puede hacerte llegar un recibo del Ibi, ya atrasado porque no recibo ningún justificante de pago del mismo en la actualidad, en el recibo del IBI viene la referencia catastral. Te mando copia del testamento de mi tia Teresa Sanz ********************************************* Buenos días de nuevo, Miguel, te reenvio un correo del departamento de siniestros de Segurcaixa Adeslas, mis tios Teresa y Máximo tenían contratado un seguro de decesos, al fallecimiento del último de los asegurados, mi tío Máximo, quedó un sobrante pendiente de cobro de 250,19 euros. Intenté que lo abonaran en su cuenta pero no se pudo realizar porque en su momento había que actualizar y escanear dnis de los titulares y la cuenta estaba bloqueada hasta que se realizara dicha actualización. Solicitan determinada documentación que ya obra en vuestro poder. Por favor, poneos en contacto con ellos para poder cobran ese sobrante. Gracias y saludos *********************************************** (siniestrosdecesos2@segurcaixaadeslas.es)Buenos días. En primer lugar, deseamos trasladarle nuestro más sincero pésame por la defunción del Sr. Máximo Gil García (q.e.p.d.) ocurrida el pasado día 15/09/2020. Atendiendo su petición, le informamos que tal y como se recoge en La Ley del Contrato del Seguro, “el exceso de la suma asegurada sobre el coste del servicio prestado por el asegurador corresponderá al tomador o, en su defecto, a los herederos”. Por lo tanto, para proceder con la devolución de este importe, la compañía precisa la siguiente documentación, que acredite a los herederos del fallecido/a: •Certificado de registro de últimas voluntades de la persona fallecida. •En el caso de que la persona fallecida hubiera otorgado testamento, necesitamos una copia de este. •En el caso de que no lo hubiera otorgado, necesitaremos una copia de la declaración de herederos abintestato. •Certificado de titularidad de las cuentas bancarias de las personas beneficiarias •Copia de los DNIs de las personas beneficiarias, para emisión de certificado con el que se deberá liquidar el Impuesto de Sucesiones y Donaciones. Además, le informamos que, en cuanto al abono del excedente, estarán obligados al pago del impuesto a título de contribuyentes las personas físicas residentes en España que reciban una indemnización de un seguro individual a título de beneficiario según se establece en la siguiente normativa legal: Art.5 de la Ley 29/1987 de 18 de diciembre del impuesto de sucesiones y donaciones. Y Art. 16 Real Decreto 1629/1991, de 8 de noviembre, por el que se aprueba el Reglamento del Impuesto sobre Donaciones y Donaciones. Dicha documentación debe remitirla a través de correo electrónico a la siguiente dirección, excedentedecesos@segurcaixaadeslas.es, indicando como referencia, en las primeras posiciones del campo del asunto, solamente el número de expediente de la forma que sigue: 720009784-02025 Nos mantenemos a la espera de recibir la documentación solicitada, para continuar con la gestión del siniestro. Para cualquier consulta o aclaración estaremos encantados de atenderle en el teléfono de atención al cliente 900 50 50 40.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-09-06','miguel, recibo email de Info finca (Emiliano): Buenas tardes yo marcho de vacaciones hoy hasta el día 15 de septiembre que me incorporo. El oficial de la notaria de Montijo se llama Jacinto Alvarez su email es jacinto.notariamontijo@notin.net y su número de teléfono es el 924453000, cuando habléis con el referirle que es una operación que llevo yo Emiliano de Finca Inmobiliaria. De la llave ya me la han dejado en el Ayuntamiento, eso ya lo tenemos solucionado. La firma de la escritura la podemos poner para el día 30 de septiembre, por lo que necesito el certificado del préstamo con esa fecha 30 de septiembre. La entidad Caja Rural de Almendralejo va a financiar la compra de la vivienda y como vuestro préstamo de Ibercaja no lo vais a cancelar en el momento, no creo que vaya el director a cancelarlo, se le retendrá a Juan Carlos una provisión de fondos para su cancelación y cuando este cancelado se le devolverá el sobrante de la provisión de fondos y los justificantes de los gastos de cancelación, así es como funcionan las cancelaciones actualmente entre entidades financieras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-09-07','miguel, remito a Jacinto de la Notaria de Montijo email (jacinto.notariamontijo@notin.net): Buenos días Jacinto, en relación a la venta de la vivienda de c/ Hinojo, que os encargará Emiliano de Info finca. La parte vendedora está Curatelada por la Comisión Tutelar de Adultos (SEPAD) de la Junta de Extremadura. Adjunto sentencia de incapacitación y testimonio de aceptación de cargo por esta Comisión Tutelar de Adultos. Necesito que me aviséis con al menos 10 o 14 días antes de la firma de la venta para avisar al Banco y al propio curatelado. Por parte de la Comisión Tutelar de Adultos iría yo con Autorización de nuestro Gerente del Sepad que es el vicepresidente de esta Comisión (cuando tenga dicha autorización te la adjuntaré). Cualquier duda o documento que necesites indícamelo. Quedo pendiente me indiques fecha de firma. *********************************************************** miguel, remito email a Emiliano de Info finca: Buenos días Emiliano, comunicaremos a la entidad que necesitaremos certificado de deuda a 30-9-2021. Te indicaré lo que nos digan en cuanto a la forma de pago, que intentaremos que sea por transferencia. En cuanto al trámite del levantamiento registral de la hipoteca indanos cuando vuelvas un presupuesto de lo que retendréis. En relación a vuestros honorarios si es posible retenedlo también del precio de venta ***************************************************** miguel, remito email a Iciar y Alberto: Buenos días Alberto e Iciar, para cuando volváis necesito que por favor habléis con la entidad donde tiene la hipoteca juan Carlos Rubio Galán para que os remita certificado de deuda pendiente a fecha de 30-9-2021 que es cuando quiere firmarse la venta del inmueble de la c/el Hinojo. Ya le he dicho a Emiliano que nos presupueste el coste el levantamiento registral de la carga de la hipoteca (que habrán de tramitar ellos). Del precio de venta nos tendrán que retener la hipoteca y sus honorarios. Lo hablamos si tenéis cualquier duda. *********************************************** Nuevo email de la inmobiliaria que reenvio a Alberto e Iciar: Me acaban de llamar otra vez del banco, a parte del certificado con fecha vencimiento 8 de octubre necesita también el número de cuenta de Ibercaja, via Banco de España, donde tienen que ingresar el importe de préstamo. Lo siento por no decírtelo todo junto, pero me están llamando sobre la marcha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-09-07','miguel, recibo de Jesús Bueno (abogado) del procedimiento judicial de autorización de gastos extraordinarios, Auto autorizando los gastos extraordinarios de la c/ General Margallo. Al no ser firme le pido nos remita la Firmeza junto con Factura de sus honorarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2021-08-27','miguel, recibo email de Carlos Mora (asesor del tercer hermano): En relación al asunto que aún tenemos pendiente y una vez presentados los impuestos de sucesiones qué faltaría aún para citar a las partes para la firma ante notaría? Y en caso de faltar alguna documentación aún (creo recordar Libro de Familia), cuales son los pasos a seguir? Ya he entregado la documentación a mi representado y me están preguntando. Quedo a la espera de vuestras noticias,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2021-09-07','miguel, remito email a Carlos Mora con copia a Agustin de la Notaria de Badajoz de D. Timoteo: Buenos días, entendemos que únicamente queda pendiente de firmarse la Declaración de Herederos. No tenemos el libro de familia en el expediente. Por lo que me dicen la trabajadora social no es posible localizarlo. Teniendo en cuenta la incapacitación de los dos hermanos Juan José y Antonio, y para agilizar, vuestro cliente (que es parte interesada) puede acercarse al registro civil y solicitar todo lo que pueda necesitar Agustín para redactar la Declaración de Herederos, creo que la documentación se la dan en el acto. Una vez que esté firmada la Declaración de Herederos únicamente habría que entregar en la entidad dicha declaración de herederos junto con vuestra presentación del impuesto de sucesiones y la nuestra para que procedan al desbloqueo. No hay que hacer escritura de adjudicación de herencia (no hay bienes inmuebles).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2021-08-27','miguel, recibo email de Carlos Mora (asesor del tercer hermano): En relación al asunto que aún tenemos pendiente y una vez presentados los impuestos de sucesiones qué faltaría aún para citar a las partes para la firma ante notaría? Y en caso de faltar alguna documentación aún (creo recordar Libro de Familia), cuales son los pasos a seguir? Ya he entregado la documentación a mi representado y me están preguntando. Quedo a la espera de vuestras noticias,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='MARTINEZ'and apellido2='PEREZ'),'2021-09-07','Buenos días, entendemos que únicamente queda pendiente de firmarse la Declaración de Herederos. No tenemos el libro de familia en el expediente. Por lo que me dicen la trabajadora social no es posible localizarlo. Teniendo en cuenta la incapacitación de los dos hermanos Juan José y Antonio, y para agilizar, vuestro cliente (que es parte interesada) puede acercarse al registro civil y solicitar todo lo que pueda necesitar Agustín para redactar la Declaración de Herederos, creo que la documentación se la dan en el acto. Una vez que esté firmada la Declaración de Herederos únicamente habría que entregar en la entidad dicha declaración de herederos junto con vuestra presentación del impuesto de sucesiones y la nuestra para que procedan al desbloqueo. No hay que hacer escritura de adjudicación de herencia (no hay bienes inmuebles).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2021-09-07','AMALIA . Desde el CRR nos piden que solicitemos revision PIA para R. Mayores . Está solicitado desde 2018 . NO se vuelve a pedir . Tiene un Grado II .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='AVILES'and apellido2='ZANCADA'),'2021-09-07','Buenas tardes. Te adjunto la última factura de la cuidadora de Rosa Avilés. El día 5 le dieron el alta a Rosa. Se encuentra muy flojita pero genial de ánimo y de aspecto. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-09-07','miguel, me confirma la inmobiliaria que la fecha se retrasa al 8-10-21: Buenos días Miguel, tenemos cambios, lo siento, debido a que la operación del préstamo de la compradora va más lento de lo que pensaba ella, le ha comunicado su entidad un nuevo día de firma, en lugar del 30 de septiembre será el 8 de octubre, te lo digo a efectos del certificado de Ibercaja. Quien retiene la cantidad de provisión de fondos no somos nosotros es la entidad que va a financiar la compra En cuanto a nuestros honorarios intentare que se descuenten también. ********************************* Reenvío email a Alberto e Iciar para que soliciten certificado de deuda a esa fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2021-09-07','miguel, llega email de Toni para Ana y para mi: Buenas de nuevo, se adjuna también documentación requerida por el area juridica de la comision, el relacion a la casa y el coche del tutelado Ramon Civantos Después de diversas gestiones en relación con el vehículo, se consigue la baja el seguro (se adjunta documento), y gestionar con el taller y el desguace la recogida y baja del mismo, intentando que se agilice y no se lleve a cabo por el procedimiento habitual pues se demoraría mucho más en el tiempo, comprenden la situación y acceden a la recogida sin coste alguno, mediante la autorización del propietario, se le facilita el documento firmado por Ramón (se adjunta). El coche ya está en el desguace y a lo largo de esta semana enviarán el documento de baja del mismo para poder zanjar el tema. En cuanto a la vivienda, a continuación, se detallan los datos de los propietarios del resto de viviendas del bloque, que si se encontraban detallados en las notas simples facilitadas por el registro de la propiedad. En la nota adjunta se detalla pormenorizdamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-09-07','miguel, me llega a mi y a Ana informe de varios asuntos Futuex (vivienda c/ general margallo, vehículo que no localizabamos, y deuda que le reclaman: Buenos dias a continuación se informa en relación a las gestiones solicitadas desde el área jurídica de la comisión tutelar, al respecto del tutelado Miguel Santos Cordero 1) 1) Intentar inscripción en registro de la propiedad de la vivienda de Miguel Santos en C/ Margallo en Cáceres. Miguel tiene las escrituras originales, así como el modelo 600 (pago del impuesto de transmisión patrimonial) ya abonado. El tutelado tiene una cita en oftalmología el viernes 3 de septiembre de 2021ª última hora de la mañana. Ha pedido pues, acompañamiento, bien ese mismo día u otro que se pudiera planificar, para realizar dicha inscripción en el registro nº 2 de Cáceres. Puestos en contacto con registro de la propiedad nº 2, nos comunican la necesidad de presentar en esta oficina, junto con escritura original y modelo 600, un justificante del impuesto de plusvalía del Ayuntamiento de Cáceres (ya abonado en su momento por parte del vendedor). En contacto telefónico con dicha área del Ayuntamiento, se nos ha informado que se debe de registrar en ventanilla única las escrituras y con el justificante, ya se puede iniciar su inscripción en el registro de la propiedad nº 2. El expone que prefiere ser acompañado para realizar ambos trámites. Se le comunica, que ya se planificará el día lo antes posible, puesto que se nos ha confirmado que no se necesita cita, ni en registro general del Ayuntamiento ni en registro de la propiedad. 2) Localizar quién tiene vehículo marca Peugeot Bipper vehículo mixto con matrícula nº 3722HVZ. Como se informó en anterior nota, el vehículo fue vendido por Miguel a D. Julián Tena Gonzalo, por importe de 2500 euros. Dinero que ingresaron en la cuenta del hijo de Miguel. Cuando hemos logrado contactar con él, reconoce que ocultó la verdad, pero también engañado y presionado por su padre y que la cantidad se la entregó a su padre a los pocos días. Se adjunta copia del PERMISO DE CIRCULACION entregado por DGT a nombre de Julián Tena Gonzalo y copia del SEGURO DE VEHÍCULO, también a su nombre de la compañía Generali. Con estos datos, se confirma que el vehículo ya está oficialmente a nombre de su comprador Y miguel recibió la cantidad acordada entre ellos. Confirmamos también, que entregó al desguace el otro vehículo que tenía en propiedad: Renault Megane con matrícula M7641Vm, se le ha solicitado documentación de dicha entrega para su verificación. 3) 3) Miguel nos hace llegar un requerimiento de deuda, crédito de fecha 04/06/2018, que según él recuerda es en torno a 15.000 euros. Este crédito fue solicitado antes de su ingreso en centro sociosanitario y afirma que algún pago se realizó, pero no sabe qué cantidad adeuda en la actualidad. Se adjunta a este email, la nota informativa, y los documentos entregados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-09-09','VALE. EL JUEVES TE DIGO QUE ME TIENEN QUE MANDAR EL CERTIFICADO DE EMPADRONAMIENTO. TS DE UHB LLERERNA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-09-09','TERESA Ahora me pongo en contacto para comentarte que la cuidadora que acompaña a Beatriz a Trujillo a visitar a la niña podría llevarla el día 20 de septiembre, por si puedes comunicárselo a la abuela o si la cuidadora se la comunica a ella directamente. Ya me dices cuando puedas, que aún quedan unos días','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2021-09-09','TERESA Informamos que el sábado 4 de Septiembre, la tutelada Guadalupe Martín Martín, tras caerse se ha fracturado la cadera. Se ingresó ese mismo día en el Hospital de Mérida. En estos momentos está siendo operada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-06','Ángel: En relación con el internamiento de Manuela Morato Picado, hablo con Fiscalía, Carmen Barquilla (927620434). Me indica que acaba de incorporarse. Que en este caso, debe tenerse en cuenta la opinión de Manuela, conforme al cambio legislativo que está en vigor desde el 3 de septiembre. Le indico que la solicitud de internamiento involuntario la realizamos antes de la entrada en vigor del cambio legislativo. Le indico que Manuela no puede volver a su casa por varios motivos. Parte de la vivienda está derrumbada y que la relación con su nieto, según Futuex, no es sana, entre otras. Me dice que se vaya de alquiler. Le digo que Manuela tiene 96 años, tiene alzheimer, es totalmente dependiente, no puede vivir de manera independiente y la relación con su nieto no es buena, amén que se la lleva a Toledo sin nuestro consentimiento en varias ocasiones y que impide ver al resto de nietos a la abuela. Me dice que para eso está la ayuda a domicilio. Le digo que esta ayuda es solo para unas horas. Que va a hablar con la Juez de Valencia de Alcántara, para tratar el tema y que lo suyo es que se realice una videoconferencia entre todas las partes. NUEVA LEGISLACIÓN. En relación con la nueva legislación me pregunta si NOS HAN PUESTO REFUERZOS. Le digo que no. Me dice que el cambio legislativo es muy significativo. Le respondo que ya lo sabemos y que así se le trasladó a la Dirección Generencia del Sepad. Propone una reunión telemática con todas las partes implicadas, Fiscalía, Jueces, Abogacía General, Comisión Tutelar, etc. Va a tratarlo con el Fiscal Jefe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-07','Ángel: Llamo a Fiscalía para preguntar por el internamiento involuntario. Me dicen que Carmen Barquilla en ese momento no está, que llame después. Llamo más tarde y tampoco consigo hablar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-09','Ángel: LLamo al Juzgado de Valencia de Alcántara, para preguntar por el internamiento involuntario. Me dicen que el Forense ya contestó y que se le ha dado traslado al Ministerio Fiscal para que informe, pero que no han recibido nada. Les digo que la Fiscal, Carmen Barquilla, me comentó que iba a ponerse en contacto con el Juzgado para tratar el tema. El oficial me dice que desconoce si entre ellos han hablado, porque la Juez de Valencia de Alcántara está de vacaciones y la que le sustituye es la de Coria. Llamo a Fiscalía de Cáceres. No me lo cogen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='CABRERA'and apellido2='MORA'),'2021-09-09','Ángel: En relación con la solicitud de gastos extraordinarios para pagar a la Inmobiliaria por la gestión en la venta del inmueble, me dice el oficial que el Fiscal se ha opuesto y que el asunto está pendiente de resolverse por su señoría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-09-09','-Amalia : le explico por tf. que para pedir traslado a otro CRR necesita estar 6 meses en el de Olivenza , y aún así , cuando lo solicite no se garantiza que se le de traslado, pasará por una comisión que valorará el caso . Es la respuesta literal que me ha dado Eva , de la sección de salud mental del SEPAD . le explico el protolo de atención , que todas sus demandas tienen que venir canalizadas por la terapeuta ocupacional del centro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-09-09','Ana: Envío correo a Julián, Cocenfe: "Buenos días Julián, En relación a la subvención del SES para la silla de ruedas de Tomás, confirmarte que a finales del julio le hicieron desde el SES los ingresos oportunos. En cuanto a las vacaciones, ya ha visto la compañera que el día 2 retirasteis el dinero tanto para gastos de bolsillo periódico como para los gastos durante las vacaciones. Y en cuanto al abono del servicio del Asistente Personal durante las vacaciones, me dice la compañera de la secc. económica que hoy mismo procederá a realizar la transferencia. Ante cualquier cuestión, no dudes en contactar. Un saludo y buen día." ·············· La cuantía de la subvención del SES para la silla de ruedas, realizada en tres ingresos, asciende a un total de 1.753,49€ ·························································································································································································· Respuesta de Julián, Gerente COCEMFE (gerencia@cocemfecaceres.org): "Comentarte que Tomás está pasándolo muy bien en las vacaciones, hablo todos los días con él y está muy contento. Le traslado a su asistente personal que se le realiza el pago."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-09','Ana: Correo de Toni del día 7: "...finalmente se fueron el viernes al domicilio de alta, pero ha regresado ayer lunes. Pero en la tarde de ayer, según la información de Jose Manuel, le dieron nuevamente el alta..." *Guardo correo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MORATO'and apellido2='SILVA'),'2021-09-09','Ana: Como respuesta a su correo, envío a Mª Salobrar Cruz, Servicio de Prestaciones Sociales, Dirección General de SS.SS. (mariasalobrar.cruz@salud-juntaex.es) el siguiente : "Buenos días Mª Salobrar, Adjunto remito los siguientes documentos relativos a D. Juan Morato Silva: - Testimonio de Firmeza de la sentencia de incapacitación y nombramiento de tutor - Testimonio de Aceptación del Cargo Pongo en copia a mi compañera Teresa, que es quién lleva este expte. por si necesitáis cualquier otra cosa. Un saludo y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-09-09','Ana: Sandra, Res. Coria, me envía fotografía a color de Mª Rosario. ······························································································································································································ Remito a David Lefevre, Serv. de Asuntos Sociales del Consulado de Francia en Madrid (david.lefevre@diplomatie.gouv.fr): fotografía de la cara a color, copia del antiguo pasaporte francés y copia del Permiso de Conducir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2021-09-09','Ana: Conversación con Fátima, Ed. Asoc. Vera (sustituye temporalmente a Cristina) educadorasocial@asociacionvera.com, me remite nueva autorización para vacaciones (ha habido que cambiar la fecha por el brote que hubo en el centro). *La subo al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-09','Ana: correo de Mamen, TS HSPA (maria.alvarezs@salud-juntaex.es), el día 7: "Buenos Días Ana, el paciente Javier Agudo está ingresado en la UHB y quiere ponerse en contacto contigo. Llámame cuando puedas. Saludos" ····· Llamo un par de veces, pero no obtengo respuesta. ···· Respondo a su correo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-09-09','Ana: Envío a Ángel y Miguel, Asesores Jurídicos CTAEX, correo de Felisa Custodio, TS CAMF, en relación al valor de la vivienda que tiene en Castilla y León y el interés de una sobrina en adquirir el ususfructo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-09-09','Ana: Desde la Res. Virgen de Guadalupe, nos remiten la Renovación de la Demanda de Empleo de José Manuel. Próxima renovación: 03/12/21. *La nueva clave de usuario es: 7v36Vu ·············· Por otra parte remiten a Belén, TS (que me reenvía) el siguiente correo: "Maria, Salvo objeción tuya, a petición de nuestra Fisio y de Jose Manuel Moreno Carlos, el próximo martes 07/09/21, se va a solicitar la prórroga de estancia en la Residencia Ntra. Sra. de Guadalupe hasta el próximo 30-11-21, con el fin de completar su rehabilitación. Cualquier duda o consulta, no dudes en llamar" ·················· Se lo remito a Alberto, Jefe Secc. Ecca. para que esté al corriente, espero que no haya inconveniente a nivel ecco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-09-09','TERESA ACTUALIZACIÓN: INTENTO FRUSTRADO DE AUTILISIS EL 19/08/2021. SE APODERA DE UNAS TIJERAS E INTENTA PROVOCARSE CORTES EN UNA DE LAS MUÑECAS. NO LO CONSIGUE, LAS AUXILIARES Y ENFERMERO DEL CENTRO SE DAN CUENTA DE LO QUE OCURRE. NO TIENE NINGUNA LESIÓN. NI SIQUIERA LEVE. HOY, 20/08/2021, RECONOCE LO QUE HA INTENTADO HACER Y SE MUESTRA ARREPENTIDA. INTENTO DE AUTOLISIS PROVOCADO POR SU ESTADO ANSIOSO DEPRESIVO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-09-06','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informarte que han dado el alta a Felisa Bruno que regresa a lo largo de la mañana. Esperemos que venga mejor con el nuevo tratamiento porque ahora mismo hay mucho nerviosismo tanto en residentes como profesionales, pensando en que pueda repetirse esta situación. Dada la gravedad de las conductas agresivas vamos a informar al SEPAD".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-09-06','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net): "...me acaban de informar que Aaron está ingresado en Salud Mental desde este fin de semana".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2021-09-03','Ana: Envío correo a José Aº Pulido, TS (tsocial1@mancomunidadsierrademontanchez.es): "Buenos días José Antonio, El presupuesto para vacaciones de María Jesús Criado Rodríguez, ha sido aprobado. Ya he hablado con Gloria." ········ Queda todo organizado con secc. ecca. y Gloria, Directora recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-09-06','Ana: Correo de Amor, TS Aspace :" comunicarte que Brahim ha dado positivo en Covid-19 algo que realmente no tenemos explicación ya que todo el personal y compañeros de la residencia es negativo. A pesar de ello, él se encuentra en perfecto estado, aislado en su habitación al igual que sus compañeros por precaución. El próximo jueves día 9 le repiten la prueba PCR y si todo es correcto el viernes saldrá del aislamiento. ... aún tenemos pendiente de realizar la cédula que os mandaría resolución positiva a la comisión para poder ir a la policía a realizarla." ·········· Acordamos que hablaremos la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-09-09','Ana: Correo del lunes 6/09 de Claudia Alonso, TS C.R. El Cuartillo (rm.elcuartillo@salud-juntaex.es): "Buenas tardes. Soy Claudia Alonso, trabajadora social del C.R El Cuartillo. El viernes 27/08/2021 ingreso en este Centro Dña. Clementa Amado Vivas vía Emergencia Social. Según nos consta, la residente se encuentra Incapacitada Parcialmente por la Comisión Tutelar ( administra sus bienes). Clementa NO QUIERE PERMANECER EN EL CENTRO, rogamos nos informéis de manera urgente sobre cómo tenemos que proceder, ya que como os informo, la residente quiere abandonar el Centro." ························ Respondo que no trabajé esos días, y que continuamos siendo Administradores de Bienes y no contamos con Autorizacón de Internamiento. ······· *Hablamos más tarde y me comunica que el Jdo. le ha remitido a la residencia un Auto de Autorización de Internamiento. **Me lo envía escaneado. ·············· Se lo remito a Ángel, Asesor Jurídico CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2021-09-10','CIERRE EXPTE. Mediante DIOR, el Jzdo. de 1.ª Inst. e Inst. n.º 2 de Arganda del Rey, declara firme el Auto de 7 de abril de 2021 por el que se declara la remoción del cargo de la CTAEx. Nombrando para el mismo a la Agencia Madrileña para la Tutela de Adultos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-09-10','Ana: Correos de Toni de Diego, TS CR Cervantes (antonia.dediego@salud-juntaex.es): "Buenos días, Ana te informo que la residencia se mantiene cerrada. por lo tanto Mª luisa y Eugenia no han ido al banco a sacar dinero, estos dos últimos viernes. un saludo" ············· "...Pues hoy les he comprado yo el tabaco. Con dinero que me ha dado el centro. porque ninguna de las dos tiene ya dinero. Se le ha comentado que cuando puedan salir a cobrar, que me tienen que pagar el tabaco a mí. Eugenia son 5 € Mª Luisa 12€. Si te parece cuando se abra el centro te aviso y como algo excepcional, ese viernes podrían sacar el dinero que le corresponde a la semana más las deudas del tabaco" ··········· Lo comunico a Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-09-10','Ana: Correos de Toni de Diego, TS CR Cervantes (antonia.dediego@salud-juntaex.es): "Buenos días, Ana te informo que la residencia se mantiene cerrada. por lo tanto Mª luisa y Eugenia no han ido al banco a sacar dinero, estos dos últimos viernes. un saludo" ············· "...Pues hoy les he comprado yo el tabaco. Con dinero que me ha dado el centro. porque ninguna de las dos tiene ya dinero. Se le ha comentado que cuando puedan salir a cobrar, que me tienen que pagar el tabaco a mí. Eugenia son 5 € Mª Luisa 12€. Si te parece cuando se abra el centro te aviso y como algo excepcional, ese viernes podrían sacar el dinero que le corresponde a la semana más las deudas del tabaco" ··········· Lo comunico a Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-10','Ana: Como en otros días en las 2 últimas semanas, se recibe llamdada de Reme (626 31 20 09), esposa de Antonio, nieto de Manuela, interesándose por ella. ·················································································· Ana: Conversación con Plácido Alejandre - Plazas T3 Gerencia Territorial de CC (927 004 261): No pueden guardar más la plaza. No obstante, mantendrán a Manuela en la lista "stand by", a la espera de que tenga lugar la vista en el Jdo. a la que nos han emplazado. ······································································································ Recibimos citación del Jdo. para comparecencia por la solicitud de internamiento no voluntario de Manuela Morato para el día 15/09 a las 10:30 h. ················ Se lo comunico a Plácido y Pedro, Gerencia Territorial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-09-10','Buenos días , Sección económica : os escribo en relación al caso de María Báez Soriano , que ingresó en Junio por emergencia social en la Residencia de Mayores de San Vicente de Alcántara. He hablado con la Dtra. del centro que me indica que sigue pendiente el tema económico . Me confirma que Caja Rural tiene entidad física en esa localidad , en Mérida os decían que no existe . Si es así , tendríais que enviar autorización de reintegro con la cantidad establecida , después de abonar la parte proporcional por el copago de la plaza. Con respecto a ésto , la Dtra. ha enviado los modelos de Alta a 3º de los meses de Julio y Agosto , al ser plaza T4 es necesario enviarlos cada mes , así lo exige la Junta. Son a mes vencido , los irá enviando a final de cada mes. Faltan esos dos meses. Hay que tener en cuenta , que no tiene seguro de decesos contratado , no creo que por la edad las compañías quieran hacerlo. Habrá que ahorrar por este concepto. Podéis poneros en contacto con Mª Ángeles , Dtra. del centro en el tf. 638490750/924410835 para aclarar todas las gestiones económicas . Hay deudas pendientes de abonar de podología y peluquería. El día que vaya a ir a retirar el reintegro podéis indicármelo a mí o directamente a Toni de Futuex para que una delegada tutelar la acompañe al banco . Toni ( FUTUEX ) Así mismo , Toni , cuando sea posible me gustaría que se empezase a visitar a María en el centro , incluso pueden salir a dar un paseo fuera del mismo siguiendo protocolo covid establecido. La incluimos en el programa de apoyos . María puede recibir visitas de su hija y de sus nietos , siempre que ella así lo desee . Sólo ha recibido una llamada de su hija y no recibe visitas de nadie más . Un saludo . Gracias .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-09-10','Ángel: MODIFICACIÓN DE MEDIDAS. Recibo hoy la sentencia firme para dejar de pagar la pensión de alimentos a la exmujer. Se lo comunico a Estrella para que anule la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-09-10','Ana: En la secc. ecca. necesitan el DNI actualizado para algunas gestiones y el que hay en el expte. está caducado. *Llamo al C. Penitenciario de CC (927 181 407), Maite TS, compañera de la otra Maite, intentará localizarlo en el expte. ··········· *Al final de la mañana me envía imagen del DNI. La guardo en PDF en su expte. y se lo remito a Estrella, secc.ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-09-09','Ana: Correo de Julián Álvarez, COCEMFE (gerencia@cocemfecaceres.org): "Comentarte que Tomás está pasándolo muy bien en las vacaciones, hablo todos los días con él y está muy contento. Le traslado a su asistente personal que se le realiza el pago."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2021-09-10','-Angel jurídico: Recibo hoy la sentencia firme para dejar de pagar la pensión de alimentos a la exmujer. Se lo comunico a Estrella para que anule la transferencia. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2021-09-09','Ana: Correo de Paula, TO - CRR-Plas.(tocupacional.crrplasencia@grupo5.net): "Buenos días, contacto con vosotras para comentaros que hemos programado con Conchi Fernández una salida para este fin de semana con su hermana. Aunque esto suele ser habitual, en este caso tiene una importancia terapéutica importante puesto que responde a parte de la intervención que se está realizando de cara al afrontamiento del duelo por la pérdida de su hijo. Por ello y, habiendo dándola a conocer como en ocasiones anteriores las medidas de prevención frente al Covid, si no hay oposición por vuestra parte se irá mañana y volverá de nuevo el domingo al centro. Muchas gracias por vuestra atención por adelantado. Un saludo. Paula."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-09-10','Ana: Correo de David Lefevre: "Gracias Ana ! Una cosa, no hay posibilidad de tener una foto con los ojos abiertos y sin el tubo ? No tiene la nacionalidad española ni DNI? Sólo tiene nacionalidad francesa ? Asimismo, seria posible que me remitieras un informe social sobre su situación familiar, financiera (ingresos etc), su salud, las circunstancias de tutela, los apoyos familiares etc ?? Indica también lo que necesitais del consulado : renovación de documentación etc… Voy a abrir una ficha sobre ella. Un saludo." ················ Mi respuesta (pongo en copia a Maite y Ángel CTAEX): "Buenos días David, La fotografía que nos remiten desde la residencia de mayores de Dª. Mª Rosario González, se la han hecho esta misma semana. La Sra. se encuentra encamada y con un delicado estado de salud, por lo que es difícil fotografiarla de otra manera. Según nos ha informado la Policía Nacional, no tienen nacionalidad española, la perdió hace muchos años y les consta que tiene la nacionalidad francesa. En cuanto al Informe Social, intentaré tenerlo listo para la semana que viene. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-09-10','Ana: Envío correo a Pilar Martín, TS ESM-CC: "Buenos días Pilar, Espero que hayas podido descansar y disfrutar de tus vacaciones. En relación a Juan Chamorro Holguín, y tal y como hablé con Clara, compañera del C. Salud de Guadalupe, te envío este correo tan sólo para recordarte que está pendiente programar una nueva cita de Psiquiatría para este mes. Ante cualquier cuestión no dudes en contactar. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2021-09-10','Ana: envío a Fátima, Ed. Soc. Vera, los documentos remitidos para autorización de vacaciones firmados digitalmente por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-09-09','Ana: correos de Estrella, TS CSS Plas: 1- "Buenos días, Ana. Como os comenté en mayo, Juan Carlos Ruíz García agredió a otro paciente y se dio parte de lesiones al Juzgado. Nos ha llegado una citación y al parecer a vosotros también (adjunta la remito). En reunión del martes de la UHDAC se puso de manifiesto que sería conveniente que Juan Carlos no tuviera que ir a ese juicio y que los abogados de la Comisión, pudieran arreglar para que así fuera...no sé si esto es posible, ya me dices....." ······ *Se lo paso a los Asesores Jurídicos CTAEX y pido que respndan al mismo. ··················· 2- "Ah Ana, a propósito de Juan Carlos, ayer se escapó del centro, estuvo por ahí un rato y volvió a las 8,30 de la tarde por su propia iniciativa, se compró una mascarilla ya que está muy sensibilizado con el tema covid. Sospechamos que no pasaría del Polígono Industrial que está cercano a nuestro centro...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MILAGROS'and edp.apellido1='CORDERO'and apellido2='DIEGUEZ'),'2021-09-06','Ana: correo de Estrella, TS CSS Plas: "...Milagros Cordero Diéguez ya ha salido del aislamiento y se encuentra en su unidad de Psicogeriatría."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='ANDREU'and apellido2='DAVILA'),'2021-09-13','TERESA ENVIO AUTORIZACION VIA EMAIL','2');
