insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2021-09-09','-Amalia : entrego a Mª Luz el modelo de alta a 3º , copia del contrato con la empresa y documento PIA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2021-09-13','TERESA Te paso información de esta tutela para que comencéis a intervenir con este caso Francisco Javier ha terminado su tratamiento en piso supervisado de Zafra y ha comenzado a vivir solo en un piso de alquiler en Zafra. Francisco J. está acostumbrado a manejarse con bastante dinero y a partir de ahora al tener que pagar el alquiler del piso no se como se va a manejar pues el poder adquisitivo le baja bastante y él suele comprarse muchos caprichos…. (bicis, ordenador, cámara de fotos…), y ha trapicheado mucho con el tema de sacar móviles y luego venderlos. Ahora mismo no tiene posibilidad de hacer estos trapicheos ya que está con tarjeta prepago pero ya nos está demando que quiere tener internet en el domicilio. La madre, Dora, está bastante pendiente de él, ha sido ella la que le ha buscado el piso de alquiler en Zafra. Ya me vais informado a ver qué tal se desenvuelve, la dirección del piso es calle mulhacen 2 A. Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='BAEZ'and apellido2='SORIANO'),'2021-09-20','-Amalia : entrego aceptacion PIA a Ana Moreno y ya estaría todo el expediente .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2021-09-13','Ángel: Envío correo electrónico a agrupaciondetalaveralareal@gmail.com ------------------------------------------------------------En relación con D. Juan José Murillo Romano, que se encuentra incapacitado y curatelado por la Comisión Tutelar de Adultos de Extremadura, en virtud de Auto nº 223/18, de fecha, 9 de julio de 2018, dictado por el Juzgado de Primera Instancia nº 4, de Badajoz, una vez aceptado el cargo, con fecha 23 de octubre de 2018, y habiendo recibido Citación Judicial, para que comparezca en la sede del Juzgado de Paz de Valdelacalzada, el día 14 de septiembre de 2021, a las 9:30, para cumplimentar diligencias de su interés, solicitamos nos las envíen, así como toda la documentación obrante en este procedimiento, a los efectos de tener conocimiento y podamos ejercitar los derechos que le correspondan en defensa de sus derechos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-09-13','TERESA RECIBO LLAMADA DE ANTO LA TS DEL SSB ALMENDRALEJO 682209060 ME PIDE ORGANICEMOS LA LIMIPIEZA DE ANTONIA QUEDO CON MIGUEL LIMPIEZA EXTREMA 664621946 PARA VISITAR EL MIERCOLES LA VIVIENDA Y PODER HACER PRESUPUESTO DE LIMPIEZA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-09-09','miguel, recibo email de abogada Rocio: Como te expuse en mi correo de fecha 9/3/21, para el procedimiento de desahucio sin reclamación de la renta debida los gastos son: Honorarios letrada: 700 euros ( + IVA) Honorarios procuradora: 165 (+IVA) Burofax: 31,75 euros, tal y como te acredito con la factura que adjunto al presente correo. Habéis entregado una provisión de fondos de 300 euros por ingreso en cuenta el 14/4/21. Se debe ampliar la provisión de fondos en 200 euros para abonar los honorarios de la procuradora con la presentación de la demanda. Quedo a la espera de respuesta. *********************************************** La pido me indique el número de cuenta y se lo reenvío a Alberto y ctutelar para que ingresen los 200€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-09-07','miguel, recibo email de Rocio la abogada: Buenas tardes Miguel, Para terminar la demanda de desahucio respecto de la vivienda de Damián, necesito completar algunos datos: 1.- Dirección del SEPAD 2.- El Decreto por el que se designa a Jose Vicente Granado Granado director gerente para aportarlo junto con el apoderamiento apud acta que me enviásteis. Muchas gracias *************************************** La remito por email lo solicitado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-09-12','miguel, recibo email de Damian: Buenos días don Miguel he hablado con Rocío la abogada que he conseguido su número de móvil y me ha dicho que está intentando contactar con usted para que usted se ponga en contacto con ella porque por lo visto va a preparar documentación para el desahucio del piso y quería hablar con usted del tema y estoy preocupado cuando pueda por favor mañana póngase en contacto con la abogada Rocío muchas gracias y que pase un buen día de domingo','2');
