insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2021-09-13','-Eva:Con respecto a Pinilla, te comento que la factura que manda SERCOM es antigua, Francisco no ha vuelto a comer del servicio cátering. No se qué dirá cuando llama a vosotros, pero cualquier cosa que diga no es cierto, porque él lo único que quiere es disponer de más dinero y se enfada mucho cuando no puede pagar facturas a menos que sean de su asignación semananal. Dice que es muy poco dinero el que le habéis asignado. Yo creo que es mucho, que eso es lo que ha hecho que no tenga nada ahorrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-13','Ana: Envío correo a Toni-Futuex: "...Te adjunto citación para Comparecencia de Manuela Morato Picado para el próximo miércoles 15 a las 10:30 h. Solicitamos que, a ser posible, le acompañe Gloria, Educadora y se lo comunique a José Manuel, nieto, para que tenga a Manuela preparada para acudir al Juzgado a la hora correspondiente. Pedirte además que gestione taxi para el traslado del domicilio de Manuela al Juzgado. La factura correspondiente nos la pasáis a posteriori como siempre." ················ Respuesta de Toni: "Pues justo se da la coyuntura, que no está Gloria esta semana, está de vacaciones. No obstante la compañera de su zona, que tambien conoce el caso puede hacerlo y dado que creemos que se puede liar.... va a acudir como apoyo tambien otra compañera del equipo de badajoz que conoce el caso (Teresa). Temenos que cuando se le comunique se niegue o el mismo dia de la comparecencia, Jose Mauel, se niegue tambien a acudir al juzgado o facilitar que su abuela lo haga... pero bueno en ese caso, imaginamos que también sera peor para el, de todos modos documentaremos e informaremos de todo lo que suceda ese dia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-09-13','Ana: Correo de Mario Estrella, CR Ntra. Sra. Guadalupe de Bohonal de Ibor: "Buenos días Ana, Te adjunto la resolución de D. Jose Manuel Moreno Carlos con la prorroga temporal hasta el 20 de Octubre del 21" ·············· Guardo la resolución en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2021-09-13','-Amalia : Hablo con Teresa ( NOVAFORMA) Juan JOsé asiste allí a C.O. acceso via PIA . Sería conveniente solicitar RAL , a pesar de tener 78 % G.Discapacidad . Tiene G. Dependencia , pte. sacar de SiDex , G1 . Percibe PFHC+ P.ORFANDAD ABS. Solicito cambio titularidad de PFHC + CPTO. ATP. LLevo la solicitud para la firma del Gerente y los documentos para enviar a registro ( creo q no es necesario compulsarlos preguntar a Julio) Necesito Nº cuenta para incluir a J.Vicente e indicarlo en las pensiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-09-13','miguel, conforme petición de Ana remito email al abogado representante de la parte compradora, acondebarbero@condefuentetajaabogados.es: Buenas tardes nos ponemos en contacto con usted en relación a la oferta de la compra del derecho de usufructo de la vivienda sita en Castilla y León y cuyo valor ofertado no nos vale pues se trata de una valoración fiscal, cuyo valor es inferior al precio de mercado. Necesitaríamos que nos remitieran una valoración de mercado mediante certificado o justificante de tasadora, tal como se establece en el artículo 10 del Real Decreto Legislativo 1/1993 de 24 de septiembre, por el que se aprueba el texto refundido de la Ley del impuesto de transmisión patrimonial y actos jurídicos documentados. Quedando pendiente de su acreditación reciban un cordial saludo. *********************************** remito email a Ana, Angel y trabajadora social de Alcuescar: Buenas tardes, adjunto email que he remitido al abogado representante de la parte compradora donde le requiero para nos acredite con certificado de tasadora a efectos de conocer el valor de mercado de la vivienda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='MACHIO'),'2021-09-13','-Amalia , envio email a aquanex: Buenos días , adjunto sentencia y aceptación del cargo de nuestro tutelado D. ROBERTO CARRERA MACHIO . Solicitamos cambio de titularidad en el suministro del agua a favor de su mujer Dña . ALFONSA PEREZ VACA , con DNI 08803475H con el objetivo de solicitar ayudas por mínimos vitales . Si tenemos que firmar algún documento , por favor , pueden reenviármelo a este email. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2021-09-13','TERESA INFORMA FUTUEX Buenas tardes Teresa, comentar que se han puesto en contacto, con el programa de Apoyo Social Comunitario, desde la Residencia La Salud (Manoli - enfermera). Nos indica que José Antonio Quirós Sauceda lleva ingresado en el hospital 12 días, que lo derivó el médico de la residencia debido a una obstrucción intestinal. Estando allí ingresado le han tenido que intervenir de urgencias por una peritonitis. Actualmente está en la UCI en donde lleva dos días. Desde el servicio médico les han indicado, a las profesionales de la residencia, que si evoluciona favorablemente será trasladado a planta en dos días y que finalmente la bolsa de la colostomía tendrá que ser permanente. El teléfono de la residencia “La Salud” es 717 786 034, desde esta línea nos han llamado para proporcionarnos la información. No sabemos si la persona con la que se ha contactado en ocasiones como cuidadora, Violeta, estara al tanto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2021-09-13','Buenos días Amalia, Si sigo queriendo operarme, he llamado a clínicas privadas y suelen valer entre 6.000 euros o más, he estado hablando con Eva y me ha comentado que es muy difícil que me vayan a aceptar tanto dinero, porque básicamente no tengo..... no se que pensaras tu, no e adjunto presupuesto por que supongo que 6.000 o mas no tengo para poder pagarme esa operación..... Un abrazo, espero tu repuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2021-09-13','Ana: Envía a Estrella, secc.ecca, factura de ropa que envía Toni-Futuex. Alberto ya me dió el visto bueno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-13','Ana: Tras comunicar Mamen, TS de la UHB HSPA (56283), que Javier quiere hablar conmigo, con el visto bueno del Psiquiatra, le llamo (Tlf. para familiares: 927 25 69 55 / Control de Enfermería 56826): Javier vuelve a preguntar por su situación económica, insiste de nuevo en que él no puede pagar ningún recurso. Y plantea la opción de ir a vivir de alquiler a un piso compartido. *Indico que desde aquí tendremos en cuenta el criterio de los especialistas (Psiquiatras) y que considero que lo más recomendable es que realice de forma adecuada un proceso terapéutico en los recursos a los que le vayan derivando, antes de dar ese paso para vivir de forma independiente de nuevo. *Parece comprenderlo y aceptarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-10','Ana: Conversación con Mamen (56283): La UME sigue cerrada. *No sabe por qué han derivado allí a Javier. El Dr. Enrique Daniel es el Psiquiatra de referencia. *Le informo de que hay planteada una subcomión sociosanitaria para la semana del 20 de septiembre, aún no hay fecha cerrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-09-13','Ana: llamada de Marta, TS del SSASB de Cilleros (927 51 20 37): Julia está allí en su despacho. Quiere comunicar que tiene una Resonancia en la Clínca San Miguel de Cáceres el próximo viernes a las 11:30 h. *No quiere que le lleve su padre. *Y Gloria, Ed. Futuex está de vacaciones. ········· Lo comunico a Toni-Futuex, por mail, para ver si puede acompañarle otra educadora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-09-13','Ana: Envío correo a Toni-Futuex: "Buenas tardes Toni, En relación a Julia Morón Hdez, he recibido una llamada de Marta, Trabajadora Social del SSASB de Cilleros. Julia tiene programada una RESONANCIA en la CLÍNICA SAN MIGUEL de Cáceres el próximo viernes a las 11.30 h. No quiere que la lleve su padre. Dado que Gloria está de vacaciones, ¿habría posibilidad de que la acompañe otra educadora del programa? Ya me dices mañana. Gracias y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2021-09-13','TF FCO. JAVIER: 617186125 Ha venido al SEPAD Bjoz , quiere revocar su sentencia incapacitacion , lo derivo a juzgados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-09-14','Ana: respuesta de Toni-Futuex, a mi correo de ayer: "Buenos dias, si ya esta organizado irá Virginia con ella, Julia es muy demandante y se puso en contacto tambien la semana pasada con Gloria"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2021-09-14','Ana: Se autorizan vacaciones organizadas por Asoc. Vera en Chipiona del 20 al 26 de septiembre. Coste 208€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2021-09-14','Ana: Llamada de Marta, hermana de Mª Teresa (615 501 169), sus circustancias han cambiado y le gustaría asumir la tutela de su hermana. Le facilito la información del Jdo. que la incapacitó. ··· Por otra parte, como su padre falleció recientemente, tienen que hacer gestiones relativas a la herencia. *Le remito y facilito los contactos de los asesores jurídicos CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='CUEVAS'and apellido2='MOYANO'),'2021-09-14','-Amalia : envio email a Alberto , seccion eco : siguiendo con este caso , y una vez que se haya procedido a incluir al Dtor. Gerente en su cuenta , he hablado con la TS del Centro y paso a detallarte tema económico: -Habría que hacer una autorización de 90€/mes a nombre del Dtor de la Residencia Felipe Trigo para comprar tabaco : ROGELIO SANCHEZ-PANIAGUA MORENO , DNI 76232341 Z Por lo demás sus cuentas están saneadas , te hago captura del inventario . Tiene seguro decesos en Mapfre. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-09-14','Ana: Recibimos del Registro Civil el ACTA de NACIMIENTO de Florencia con la incripción de la incapacidad en el margen izdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='CUEVAS'and apellido2='MOYANO'),'2021-09-14','-Amalia ; plan de intervencion : -reside en RM. Felipe Trigo , hace años , tras una caida en la que ingresó en el hospital . Vivía solo en Higuera , sin red familiar de apoyo. -Se ha solicitado traslado a la residencia de su pueblo , a espera de que le den plaza. -Tema economico visto con la seccion eco , anotado anteriormente. -Tiene seguro decesos con Maphre. -En cuanto esté resuelto la parte eco lo puedo derivar a Tere para seguimiento .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2021-09-14','Ana: correo del Hogar San Vicente de Paúl: "Buenos días, les informamos que Mª del Carmen Matillas Jiménez realizará la actividad "Vacaciones en Rota" los días del 20 al 30 de Septiembre, junto con el resto de residentes del Hogar San Vicente de Paúl, bajo la supervisión de los educadores. Debido a que la incidencia del Covid 19 ha descendido, consideramos que se puede realizar dicha actividad y que es necesaria para nuestras residentes, después del tiempo tan difícil que hemos vivido. El coste de la actividad asciende a 500,00 euros por persona, cantidad que deben abonar en la cuenta del Hogar. Muchas gracias. Un saludo" ··········· Se lo paso a Alberto, Secc. Ecca., con el OK por mi parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2021-09-14','Ana: Se autorizan vacaciones organizadas por Asoc. Vera en Chipiona del 20 al 26 de septiembre. Coste 208€','2');
