insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2021-09-14','Ana: Remito a Ana Benavente, TS de ESM Plas. la Solicitud de subvención para el fomento de la movilidad en transporte público (Anexo I) de María Antonia debidamente firmado y sellado por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-09-14','Ana: Llamo a Ayto. de Alcuescar, no obtengo respuesta. Llamo al Ayto. de Aldea del Cano, me dicen que María, TS, está de vacaciones. Se incorpora el lunes. *Envío un correo para que lo lea a su vuelta (tsocial7@mancomunidadsierrademontanchez.es): "...Mi Jefa de Sección, Maite, ha hablado de nuevo con la Dra. Rocío Domínguez, Médica de Aten. Primaria de Antonio Hidalgo Romo, pues aún estamos pendiente del informe de salud para la solicitud de activación de dependencia que le pedimos. Le ha dicho que ya ha hecho la derivación a Salud Mental y que el informe de salud también lo hizo y se lo entregó al hermano de Antonio, quién en teoría te lo entregaría a ti. No sé si sabes algo de esto. Ya nos dices a tu vuelta. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-09-14','TEREASA EMVIO CONTRATO SAD MODIFICADO A PETICION DE LA EMPRESA POR CARTA CERTIFICADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-14','Ana: Recibimos del Ayto. de Valencia de Alcántara CDO. DE EMPADRONAMIENTO COLECTIVO y CDO. DE CONVIVENCIA. (Escaneado en su expte.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-09-14','Ana: correo de Estrella, TS CSS Plas: "Hola Ana. Con respecto a lo que me comentabas en este correo, he llamado a los dos Cadex, el de Cáceres y el de Badajoz, en ninguno aparece pedido el perfil. En el de Cáceres me explicaron que las valoraciones de perfil "van para rato" porque solo ven uno a la semana y me aseguran que el de Badajoz todavía está peor....Yo estoy dispuesta a rogarles cuando aparezca allí su solicitud para que por favor lo valoren lo antes posible...está muy cansado de estar aquí, el otro día ha vuelto a agredir a otro paciente...." ············· Tras hablar con Manuela y Belen, Secc. Discapacidad, envío correo a Estrella: "Buenas tardes Estrella, Me confirman desde la Secc. de Discapacidad (Manuela y Belén) que está pedido el perfil al CADEX de Badajoz. Lo único que faltaba algún trámite que ya está hecho también desde hoy. Buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-09-14','Ana: Sandra, TS de la Res. Real Patronato de Coria, me remite por mail Informe Social de Mª Rosario. ··············· Se lo remito a David Lefevre, Dpto. de Asuntos Sociales del Consulado de Francia en Madrid (david.lefevre@diplomatie.gouv.fr).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2021-09-14','Ana: Llamada de Jairo: Tras mucho divagar en torno a las "denuncias que ha interpuesto" y su Abogado Estanislao, finaliza diciendo que por todo ello prefiere posponer el proceso de búsqueda activa de empleo y comenzarlo una vez hayan terminado los "procedimientos judiciales" y "pleitos". Habla de "falsedad documental", pues en sus "documentos no aparecen los apellidos de sus padres", "la que falleció no es mi madre biológica" dice "... y la de verdad está deseando verme". *Dice ser "Nieto de D. Adolfo Suárez, Presidente de la Transición Española", e hijo de "D. Paolo Wilson".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-09-15','miguel, llega de email de Curro con Diligencia de Ordenación de junio donde nos piden demos la dirección de esta tutelada para ser valorada por el forense a efectos del procedimiento involuntario que solicitamos. Como no sé qué Trabajadora social lo lleva, le envío email a Amalia y Tere para me indiquen la dirección de ella para poder contestar lo antes posible al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2021-09-15','miguel, tras hablar con el Jzdo nº1 de Coria, reenvío email a Meli: Buenos días Meli, me comentan en el juzgado, para que hables con la notaria, que esta autorización es correcta. Que si ven algo que les impida firmar la venta tendrán que emitir una resolución desde la notaria para que se la podamos trasladar al juzgado. Si acaso quedara firmada la venta, también tendrías que comunicármelo porque tendríamos que ratificarla en Mérida (la notaria de allí tendría que remitirla electrónicamente a la de aquí para dicha ratificación…)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-09-15','miguel, tras hablar con Estrella, remito email a Toni en relación al email de las indagaciones realizadas por ellos: Buenos días, gracias Toni por todas las gestiones. Comentarte que necesitamos saber dos cuestiones a resolver cuando podáis: 1)El vehículo que mencionas que está en el desguace Renault Megane con matrícula M7641Vm, tenemos que confirmar que está dado de baja definitivamente, a ver si Miguel tuviera algún documento que lo acredite. 2)El documento que nos remites del crédito en torno a 15.000€ que indicas que Miguel comentó que pidió, necesitaríamos la documentación que tenga de esto, ya que lo que te ha dado es un escrito que le remite la compañía sin identificar nada, ni número del préstamo, ni cantidad debida (desglosada en concepto de principal, intereses, etc). Pregúntale también porqué tiene a su nombre los recibos de luz de la vivienda de Guadalupe, si se supone que son de su padre y allí viven su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-09-15','-Se envia email a juridico : SEGUNDO.- Que conforme certificado del padrón municipal de Mérida, reside actualmente en c/ Aries 8, 1º, Pta 18, Mérida (Badajoz) (Doc. Nº 2). Buenas Miguel , en el documento que enviaste al Juzgado para el internamiento tienes recogida esta información. Es la misma que se recoge en el informe social del SSASB . Sé que vive en la zona de Proserpina , Ana llevó el caso inicialmente , si pudiera confirmar que es esta zona podrías indicarlo al juzgado . Dado la complejidad de este caso , creo que lo más conveniente es llevarlo a reunión de coordinación para abordarlo de forma conjunta entre todos . Si os parece lo vemos mañana o pasado que estaremos todos presentes . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-15','Ana: Se suspende la vista en el Jdo. dado que José Manuel, nieto, ha enviado un escrito diciendo que Manuela está convaleciente y no puede acudir a la misma. *El próx. martes 21 irán a reconocerla al domicilio y volverán a citar a la CTAEX para el miércoles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-09-15','Ana: Correo de Pilar Martín, TS ESM (pilar.martinp@salud-juntaex.es):Buenos días, Ana te informo de la cita con su psiquiatra de Juan Chamorro Holguín el día 28 del mes en curso a las 10,50. También se lo he dicho a Clara y a Teresa. Un abrazo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-09-15','Ana: Correo de Pilar Martín, TS ESM (pilar.martinp@salud-juntaex.es): Ana, te informo de la cita con su psiquiatra el próximo 1 de octubre a las 9,30 de Miguel. Ya se lo he dicho a Teresa. Un abrazo. ······························································································································································································· Envío correo a Toni - Futuex: "Buenos días Toni, En relación a este tutelado, quería confirmar contigo si en algún momento se ha llegado a solicitar (y enviarnos, pues no encuentro nada) presupuesto para las reformas (y entiendo que limpiezas) que requeriría la vivienda en que reside actualmente Miguel en Guadalupe. Si no los hay, agradecería que con el apoyo de Teresa, Miguel pudiera solicitarlos. Así mismo, creo recordar que nos informasteis de que Miguel pasaba largas estancias en Cáceres y quisiera saber si continúa siendo así, pues en ese caso, quizá lo que habría que valorar es si quiere trasladarse a vivir allí y en consecuencia, la vivienda que habría que adecentar sería esta última (para ello también necesitaríamos presupuestos, como siempre). *Por último, confirmarme por favor si Teresa acompañará a Miguel a la cita en Salud Mental el día 1 de octubre y si es así, pediros que solicite al especialista informe y me lo hagáis lo llegar. Gracias de nuevo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-09-15','Ana: correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Comenté con Maripaz Psicóloga de Remedios Chaves lo que hablamos ayer con respecto a las visitas a su madre. Le parece bien, que venga su madre la próxima vez aquí a Plasencia y puedan salir por la ciudad a dar una vuelta, acompañada por un Auxiliar de Enfermería. Así que, voy a llamar a su madre a ver si le parece bien, abonando Reme el taxi..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-09-07','Ana: correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Ana, otra cuestión que se ha tratado en reunión de UHDAC es ver la posibilidad de que cuando vaya Reme a visitar a su madre, dichas visitas se realicen en otro lugar que no sea el centro de Aprosuba 3. Primero porque en Septiembre la sala destinada a visitas, se destina a las actividades de Terapia Ocupacional y segundo porque la madre de Reme se ha quejado de "que parecen que molestan en el centro". No sé, si podéis ofrecer otro lugar en Badajoz, donde puedan verse...." ············ Hago la consulta a Amalia, CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-09-10','Ana: correo de Amalia, en relación a las visitas de Remedios a su madre: "Buenas , como bien indicas , no tenemos otra opción para realizar las visitas , el centro de referencia de Reme es Aprosuba 3 . Se les podría pedir que estudien en el centro otra opción más apropiada para las visitas. También podría ir la madre a visitarla a ella , no sé las razones por las que no se hace así . Sería más fácil que fuese la madre a Plasencia en un taxi , incluso si es por falta de medios económicos se le puede facilitar el abono de éste . Y que se reúnan en Plasencia , que no sea siempre Reme la que tenga que viajar." ············ Se lo traslado a Estrella, CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2021-09-15','Buenos días Amalia, si hemos recibido la renuncia y le hemos dado de baja en el contrato de alquiler. Nos pondremos en contacto con su madre antes de quitar el tapiado para que recojan los muebles y enseres. Un saludo y gracias. Nuria Moreno Rebollo Trabajadora Social Teléfono 924 332459 Servicio de Adjudicación y Mantenimiento Dirección General de Vivienda Consejería de Movilidad, Transporte y Vivienda Avd. de las Comunidades S/n 06800 Mérida','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2021-09-15','Buenos días Amalia, si hemos recibido la renuncia y le hemos dado de baja en el contrato de alquiler. Nos pondremos en contacto con su madre antes de quitar el tapiado para que recojan los muebles y enseres. Un saludo y gracias. Nuria Moreno Rebollo Trabajadora Social Teléfono 924 332459 Servicio de Adjudicación y Mantenimiento Dirección General de Vivienda Consejería de Movilidad, Transporte y Vivienda Avd. de las Comunidades S/n 06800 Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2021-09-15','-Amalia : email a Alberto seccion eco: Hola , ya hablamos de este caso , se ha rectificado el documento de renuncia de la VPP . Ya han procedido a dar de baja al alquiler ,y he pedido que antes de quitar el tapiado avisen a la madre para que vaya a recoger sus muebles y pertenencias . Creo que ya lo anotaste ,pero por recordarlo , habría que dar de baja a los suministros de esa vivienda . Seguimos...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2021-09-15','Se me ha olvidado comunicarte en el correo anterior que el paciente RUBÉN MONTERO SÁNCHEZ se traslada de alta al CRR de Mérida mañana jueves,16-09-2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-09-16','Ana: David Lefevre, Serv. de Asuntos Sociales del Consulado de Francia en Madrid (david.lefevre@diplomatie.gouv.fr) envía correo a la hija de Mª Rosario y me pone en copia: "Buenas tardes Elisabeth, Le escribo en relación a su madre, Maria del Rosario GONZALEZ JORNA, nacida el 28/05/1936 en Villamiel (España) Hemos sido solicitados por el servicio de tutelas de Extremadura para renovar su documentación. A dia de hoy, no hemos encontrado ningun acta de nacimiento francés o justificante de la adquisición de la nacionalidad francesa (por matrimonio etc..). Por lo que no se le puede renovar ninguna documentación sin más pruebas de nacionalidad francesa. Con el fin de verificar su nacionalidad francesa, le ruego me remita, escaneado por mail, cualquier documento que permita verificar la nacionalidad francesa de su madre (libro de familia de sus padres, acta de matrimonio, acta de nacimiento francés etc) Atentamente," ·········· Se lo reenvío a Maite y Ángel, CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-09-16','TERESA le he puesto un correo a la TS del CSS Mérida para que nos cuente cual es su estado actual . Los tf de Vivienda son : 924332459/924332456.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-09-15','EXITUS La familia (su hijo) comunica su fallecimiento. Acaecido el 15/09/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2021-09-16','miguel, llega email de Soledad de Aexpainba: Buenas: Juan José Murillo Romano, deberá comparecer ante el juzgado el día 4 de Noviembre a las 10:00 horas. En la actualidad, es declarado cómplice de un robo, por lo que la documentación que se debe presentar por el letrado es la siguiente: - Certificado del CADEX que refleje su grado de discapacidad. - Informes psicológicos y psquiátricos. - Hoja de tramiento. De momento eso es todo, cualquier actualización, os voy informando. ********************************** Reenvío el email a Amalia: Amalia, por favor, voy a pedir abogado de oficio, y nos dan cita para 4-11-21 a 10h en jzdo nº4 de Badajoz, para que asista el tutelado. Recaba la documentación que puedas de lo que dice Soledad de Aexpainba: certificado de CADEX de discapacidad, informes psicológicos y psiquiátricos, y hoja de tratamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-09-16','Ana: Llamada de Juan Carlos. El próximo miércoles tiene cita con el dentista. *Están elaborando un proyecto para presetar a la Protectora de animales. Esta semana han visto una película y han hecho dibujos y papiroflexia en los talleres. ····· Pregunta por Pedro, se emociona y llora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-09-16','Ana: Envío a Laura, Fisoterapeuta de ASINDI (fisioterapia.asindi@gmail.com), la respuesta de fiscalía: Autorizan para participar en la Convivencia de los JEDES. (*Se remitió a la fiscalía por la autorización de derechos de imagen).','2');
