insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2021-09-16','miguel, llama la prima del curatelado 657042224 para informarse de cómo van los trámites de desbloqueo de la cuenta.(veo email de Villafaina y Cid y parece ser que hará falta nombrar abogado para el desbloqueo de la cuenta) Paralelamente quiere hacer arreglo de la vivienda y que se le compren varias cosas como un colchon, así q le transfiero la llamada a Tere ******************************************* Remito email a Inmaculada de la Asesoria del Cid y Villafaina: Buenas tardes Inmaculada, necesito me indiques qué hace falta exactamente para el desbloqueo de la cuenta bancaria. Si por lo que veo en tu email es preciso entablar un procedimiento de jurisdicción voluntaria de aprobación de herencia necesitaría un presupuesto vuestro para gestionarlo con el juzgado para que lo podáis interponer lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2021-09-16','miguel, Tere me pide: Ha fallecido la madre de las tuteladas Mª Teresa y Juana Gonzalez Naranjo, son las únicas herederas. La madre se llama Teresa Naranjo León, falleció ayer en la residencia de mayores de Azuaga. Ya me dices que necesitas para hacer la herencia. ************************************************ La respondo: Hola Teresa, para hacer el pago del impuesto de sucesiones, y el trámite de adjudicación de herencia necesitaríamos que te envíen una serie de documentación: -Certificado de defunción -Certificado de últimas voluntades -Testamento -Notas simples o escrituras de compraventa de los inmuebles que tuviese la fallecida. -Certificados de cada cuenta del banco a fecha de su fallecimiento y los movimientos de dichas cuentas desde la fecha de su fallecimiento a un año atrás. En principio con eso sería suficiente, si hiciese falta algo más te lo iría diciendo. Pueden adelantarte esta documentación por email pero en un futuro necesitaremos los originales ya que habrá que pedir seguramente conforme obliga la ley (ambas hijas están tuteladas) autorización judicial para la aceptación de la herencia, y una vez que se firme la adjudicación de herencia en la notaria habría que solicitar de nuevo en el juzgado la aprobación de la herencia. Posteriormente si se quisieran ir vendiendo el/los inmuebles que puedan constituir la herencia también habría que pedir autorización judicial para vender.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-09-16','Ana: Tras conversación con Pilar Martín, TS ESM (54612 / pilar.martinp@salud-juntaex.es), le reenvío el correo con el Testimonio de la Sentencia, recordando: "...quedo a la espera de lo informes en que se indique desde cuándo Martín Domínguez Palencia no está acudiendo a su seguimiento por el Equipo de Salud Mental." ····························································································································································································· Maite, Jefa Secc. CTAEX, habla con la vecina de Martín, al parecer Martín debe tener otra avería, pues se le está filtrando agua por la terraza. *Enviarán a mi correo presupuesto. ······························································································································································································ Ana: llamo al INSS, a Ignacio Tejada, Jefe Secc. P. Jubilaciones (927 62 00 62), en relación al embargo de su pensión: No obtengo respuesta. ···· Llamo también a Control de Pensiones (927 62 00 49)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2021-09-16','miguel, Tere me pide: Ha fallecido la madre de las tuteladas Mª Teresa y Juana Gonzalez Naranjo, son las únicas herederas. La madre se llama Teresa Naranjo León, falleció ayer en la residencia de mayores de Azuaga. Ya me dices que necesitas para hacer la herencia. ************************************************ La respondo: Hola Teresa, para hacer el pago del impuesto de sucesiones, y el trámite de adjudicación de herencia necesitaríamos que te envíen una serie de documentación: -Certificado de defunción -Certificado de últimas voluntades -Testamento -Notas simples o escrituras de compraventa de los inmuebles que tuviese la fallecida. -Certificados de cada cuenta del banco a fecha de su fallecimiento y los movimientos de dichas cuentas desde la fecha de su fallecimiento a un año atrás. En principio con eso sería suficiente, si hiciese falta algo más te lo iría diciendo. Pueden adelantarte esta documentación por email pero en un futuro necesitaremos los originales ya que habrá que pedir seguramente conforme obliga la ley (ambas hijas están tuteladas) autorización judicial para la aceptación de la herencia, y una vez que se firme la adjudicación de herencia en la notaria habría que solicitar de nuevo en el juzgado la aprobación de la herencia. Posteriormente si se quisieran ir vendiendo el/los inmuebles que puedan constituir la herencia también habría que pedir autorización judicial para vender.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-09-16','Maite: ayer Teresa y yo realizamos visita a Jose MAria en el centro INLCUSIVES.Manifiesta encontrarse bien allí, pero presenta alteraciones de conducta. Se hará seguimiento de su adaptación a través de FUTUEX. Hoy se ha enviado correo de derivación al programa de apoyo comunitario para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2021-09-16','Ana: Llamada de Mariví, TS URA CSS-Plas. (24142): a Santiago tienen que practicarle una colonoscopia. El C.I. lo firmará la Directora del CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-09-16','Ana: Envío correo a Alberto, Ángel y Miguel, CTAEX: "He recibido llamada de José Teomiro (644 70 47 12), sobrino de Felisa Felipe Teomiro, Tutelada por la CTAEX. Al parecer, Felisa y su hermana, Josefa Felipe Teomiro, tiene un FONDO DE INVERSIÓN. Josefa quiere rescatar ese dinero, pero obviamente necesitan la firma de José Vicente Granado. Pide que se le llame para informar sobre cómo proceder. Por favor, quien corresponda, que se ponga en contacto con él. Ya me vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-09-16','Ana: Solicito por mail al CADEX de CC nueva RESOLUCIÓN DEL GRADO DE DISCAPACIDAD. Acudió a revisión el día 12/08. ··························································································································································································· Remito a Anabel, TS SSASB, el informe médico remitido por el ESM-CC. ··················· Respuesta de Anabel: "OK, MUCHAS GRACIAS. realmente continua igual con alucinaciones, yo creo que necesita un ajuste de medicación. pero segun el informe de salud mental la consulta seria al menos en enero. Iremos observando y si continua igual habra que llamar para comunicar la situacion."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-09-09','Ana: Recibimos del ESM-CC Informes médicos solicitados. **HAN RECHAZADO la derivación a la UHDAC porque su CI supera el exigido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2021-09-16','-Amalia , envio a CSS Mérida la citacion a CADEX el 20 septimbre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2021-09-17','TERESA RECIBO LLAMADA DE DIEGO 672216213 PARA PREGUNTAR POR LOS PRESUPUESTO DE PINTURA Y ELECTRICIDAD LE DOY OK A LA PINTURA ELECTRICIDAD PENDIETNE DE OK DE ALBERTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-09-17','miguel, remito email a Juana Heras de Liberbank (y reenvio el email a Angel, Ana y Alberto): Buenos días, necesitaríamos saber de la tutelada por la Comisión Tutelar de Adultos, Doña Felisa Felipe Teomiro, cómo proceder para el desbloqueo y reparto de este fondo de inversiones (instrucciones de cómo hacerlo), ya que la hermana y titular también de la cuenta se ha puesto en contacto con nosotros con dicha finalidad de desbloqueo y reparto. Adjunto los datos identificativos de dicho fondo junto con la aceptación del cargo de esta Comisión tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-09-17','miguel, contestación de Juana Heras de Liberbank que reenvío a Ana, Angel y Alberto: Buenos días, Miguel. Se lo he pasado a la oficina gestora del cliente, para que nos den respuesta, ya que ellos son conocedores del procedimiento y producto con más detalle que yo. En cuanto tenga respuesta, te la envío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-09-17','miguel, recibo por email contestación del abogado AQUILINO CONDE BARBERO >acondebarbero@condefuentetajaabogados.es>: Buenos días, para obtener esta información, precisamos hacer un informe pericial de valoración de la vivienda. Dado que entiendo tiene concedida la Justicia Gratuita, solicitaré que nos concedan la gratuidad del informe. Si no fuera así, y no tuviera derecho al mismo, deberá costearse por cuenta de Dª. Maria del Carmen Gómez Muñoz. En el momento que me informen sobre esta cuestión, lo pondré en su conocimiento. Un saludo. *************************************************** mi contestación al abogado: Buenas tardes, al tratarse de una curatela no es necesario pedir una peritación judicial (tampoco estamos en contra de que la pidan). Por ley no es preceptivo pedir ningún tipo de autorización judicial, simplemente pedimos un certificado de tasación. Quedamos a la espera nos remitan dicha valoración cuando la tengan, saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='NOGALES'and apellido2='MUÑOZ'),'2021-09-17','-Amalia: pongo en registro salida ( Julio ) la PFHC+P.ORFANDAD y la documentación anexa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-17','Ana: Conversación con Mª Jesús Gómez Lozano TS - SSASB (621 247 237) en relación a Javier y su situación actual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-09-17','Ana: Me envían por mail desde el CADEX la RESOLUCIÓN DE LA REVISIÓN DEL GRADO DE DISCAPACIDAD y el DICTAMEN TÉCNICO FACULTATIVO. ················ Se lo remito a Anabel, TS del SSASB Miajadas. ····································································································································· Correo de Anaisabel (servicios.sociales@miajadas.org): "Hola Ana buenos dias! paso a reenviarte, el menaje que ayer por la tarde me remitio una de las cuidadoras del Piso Tutelado "Esteve esta tarde ha estado desde que ha venido del c.o con el brote de alucinaciones ,he estado hablando con él por lo menos 1h ,esta tranquilo y parece que se le ha pasado el brote de alucinaciones". con al foto adjunta. te lo envio como ejemplo de lo que pasa con bastante frecuencia, al parecer el medico de familia le ha solicitado cita preferente en Salud Mental, pero no se ni cuando será, ni como trataran el tema. En mi opinion, y considerando que llevo apenas quince dias conociendole, deberiamos hacer lo posible para que estuviera en un recurso de salud mental, no creo que este recurso sea adecuado, sobre todo porque no todos los cuidadores tienen la misma sensibilidad hacia él, y tampoco son especialistas en tratar este tipo de circunstancias. saludos" *Adjunta remite la nota y dibujo que ha realizado. ·········· Se lo reenvío junto al Informe Médico del ESM, así como el Cdo. Discapacidad y el Dictamen Técnico del CADEX a Soraya Masa (pongo en copia a Maite, Jefa de Secc.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-09-17','TERESA RECIBO LLAMADA DE EMI 644625593, ME COMENTA QUE ESTA EN EL PISO CON MIGUEL ANGEL, QUE SE ENCUENTRA BIEN. ESTA YENDO A PROINES','2');
