insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-09-20','Ana: correo de Soraya Masa (U.PP.AA.) (19/09) a Mariluz Madrigal y Eva Paredes (Salud Mental): "Buenas... este caso que nos envían desde la CTAEX, esta actualmente en una vivienda tutelada de Miajadas para personas con Discapacidad Intelectual... viendo la evolución del caso, creo que habría que hablar con el ESM de Cáceres, me parece que puede ser un perfil de los pisos de TMG."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2021-09-20','TERESA RECIBO LLAMA DE CLAUIDA TS DEL RESIDENCIA EL CUARTILLO 22162,ME COMENTA QUE TIENE SOSPECHAS DE QUE PUEDA HABER UN INTERES ECONOMICO EN LA REMOCION DE LA TUTELA. LE PIDO INFORME SOCIAL EN EL QUE REFELEJE EL DIA A DIA DE CARMELO Y LA REALCION QUE MATIENE CON LA PERSONA QUE QUIRE COGER LA TUTELA ESTA PERSONA ES LA HIJA DEL ANTERIOR TUTOR EL CUAL FUE DENUNCIADO POR MALOS TRATOS. ME QUEDO A LA ESPERA DE RECIBIR INFORME SOCIA PARA PASARLO A LA SECCION JURIDICA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-17','Ana: Correo de Toni-Futuex: "Y a continuación paso a relatarte las gestiones que dos compañeras efectuaron el 15 de septiembre sobre este asunto, que como sabeis, no se pudo realizar y se postpuso hasta que la jueza visitara el domicilio el proximo miercoles 22. No vamos a poder acudir, a Valencia de Alcantara este dia, primero porque el nieto nos lo ha prohibido taxativamente y que en todo caso deberia recibir el un email sobre quien va a acudir, y sobretodo debido a que las amenzas que realiza Jose Manuel, sobre las compañeras, son absolutamente intolerables.. especialmente sobre Gloria, diciendo que va a recibir una demanda penal por haberlo difamado, responsabilizandola de que se vaya a producir el ingreso de su abuela.. y etc etc etc... sabemos que esto no tiene ni pies ni cabeza, pero no podemos exponer a la compañera a este tipo de situaciones. Es mas, es posible que el haya tenido acceso algun informe o documento de los seguimientos efectuados?? obviamente nosotras no le hemos facilitado nada, (ni desde el equipo de apoyo social comuniatario, ni vosotros desde la comisión) peero hablaba como si hubiera leido (y mal interpretado) informes, si hubiera tenido acceso al escrito que se eleva al juzgado o el juzgado le hubiera dado parte, me pareceria ya gravisimo.. Imagino, que el, estara elucubrando , mas que otra cosa, pero como te digo, ya las amenezas son graves y no las vamos a tolerar. ..." *Guardo el correo completo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-09-20','Maite: Manuela, jefa de sección de la Unidad de Programas Asistenciales, envía dos correos ( 17-09/21 y 20/09/21)con informes presentados por ASINDI, sobre las últimos hechos protagonizados por Felisa, en los que se recogen varias agresiones a distintas cuidadoras ( adjunta partes de lesiones).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-09-20','TERESA Teresa informarte de las siguientes circunstancias: 1. Dña. Antonia Engracia es beneficiaria del Servicio de Ayuda a Domicilio desde hace años, en su caso y dada su situación psiquica de poco ha servido el mismo. Se le ha mantenido, con dos auxiliares los lunes/miercoles y viernes para contener la presión del vecindario , ante las quedas de estos por los olores que se desprendian de la vivienda y para poder hacerle a la misma un seguimiento que permitiera conocer su situación y actuar ante cualquier emergencia. 2-En Almendralejo no existe ninguna empresa de cartering que lleve comida a domicilio. Se le propuso ir a comer a la residencia Nta. Sra. de la Pieded , utilizando el servicio de club de comidas y ella se negaba. Tal vez no habria problema en buscar algún bar que sirviera menú y ella fuera allí a comer y este seria el problema que ella no iria al preferir quedarse en casa y preparar su comida . En este sentido se le ofreció que las auxiliares cocinasen y ella se negó. 3-Ante las caracteristicas del caso y las condiciones infrahumanas en las que Dña. Antonia se encontraba y vivia, la Subcomisión de Gestión de Casos de Salud Mental del Area de Merida, se reunió el 27/05/2021 y definió un circuito terapeitica que paso a detallarte" Los miembros de esta subcomisión entienden que el circuito terapéuico que podria ser efectivo, consistiría en actvar el 112 para realizar el ingreso involuntario en la Uhb de Merida . Posteriormente a la estabilización de la paciente, se consideraria su acceso a la UME del CSS de Merida para dar paso a la Red de Recursos Residenciales de Mayores una vez se active el PIA desde el Sepad". Si ahora no estiman el ingreso en centro , no se esta cumpliendo con el protocolo definido en un principio,desconozco si el equipo medico que ahora la atiende conoce este protocolo. En este sentido, si te parece, seria bueno que hablaras con Angela Arias (miembro permanente de la Subcomisión) para que ella te informarse del protocolo que ellos mismos activaron y que ella supiera que la propuesta desde el hospital psiquiatrico para Dña. Antonia es el retorno a su domicilio. Propuesta contraria a aquella que la Subcomision definió. Para finalizar , solo recordarte que ibas a contactar con la Direccion de Vivienda para que reparensen los desperfectos en ventanas, crstales y sanitarios además de revisar el lavabo y taza del water al estar atascadas. Saludos y vamos hablando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2021-09-20','TERESA Ha fallecido la madre de las tuteladas Mª Teresa y Juana Gonzalez Naranjo, son las únicas herederas. La madre se llama Teresa Naranjo León, falleció ayer en la residencia de mayores de Azuaga. Le pedí a la directora de la residencia el certificado de defunción. Una vez que nos envíe la documentación os la mando por e.mail. Tan solo conocemos a un sobrino con domicilio en Badajoz pero del que apenas existe contacto. Los únicos familiares son las dos hijas que están aquí en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2021-09-20','TERESA TERESA Ha fallecido la madre de las tuteladas Mª Teresa y Juana Gonzalez Naranjo, son las únicas herederas. La madre se llama Teresa Naranjo León, falleció ayer en la residencia de mayores de Azuaga. Le pedí a la directora de la residencia el certificado de defunción. Una vez que nos envíe la documentación os la mando por e.mail. Tan solo conocemos a un sobrino con domicilio en Badajoz pero del que apenas existe contacto. Los únicos familiares son las dos hijas que están aquí en el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-09-20','TERESA Buenos días Lola Tras hablar con al trabajadora social del SSAB de Almendralejo me comenta que en la subcomisión de caso que se celebró se acordó que tras el ingreso en UME se haría derivación a mayores ya que no tiene habilidades para poder vivir sola en el domicilio Te paso el teléfono de Ángela miembro permanente de la comisión de casos para que hables con ella y te informe 924-300457 La trabajadora social me comenta Que Dña. Antonia Engracia es beneficiaria del Servicio de Ayuda a Domicilio desde hace años, en su caso y dada su situación psíquica de poco ha servido el mismo. Se le ha mantenido, con dos auxiliares los lunes/miércoles y viernes para contener la presión del vecindario , ante las quejas de estos por los olores que se desprendían de la vivienda y para poder hacerle a la misma un seguimiento que permitiera conocer su situación y actuar ante cualquier emergencia. En Almendralejo no existe ninguna empresa de cartering que lleve comida a domicilio. Se le propuso ir a comer a la residencia Ntra. Sra. de la Piedad , utilizando el servicio de club de comidas y ella se negaba. Ella prefiere quedarse en casa y preparar su comida . En este sentido se le ofreció que las auxiliares cocinasen y ella se negó. Ante las características del caso y las condiciones infrahumanas en las que Dña. Antonia se encontraba y vivía, la Subcomisión de Gestión de Casos de Salud Mental del Área de Merida, se reunió el 27/05/2021 y definió un circuito terapéutica que paso a detallarte" Los miembros de esta subcomisión entienden que el circuito terapéutico que podría ser efectivo, consistiría en activar el 112 para realizar el ingreso involuntario en la Uhb de Merida . Posteriormente a la estabilización de la paciente, se consideraría su acceso a la UME del CSS de Merida para dar paso a la Red de Recursos Residenciales de Mayores una vez se active el PIA desde el Sepad". Si ahora no estiman el ingreso en centro , no se está cumpliendo con el protocolo definido en un principio, desconozco si el equipo médico que ahora la atiende conoce este protocolo. La comisión esta preparando la vivienda de cara a que vuelva al domicilio pero entendemos que dadas sus circunstancias no es la mejor opción Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2021-09-20','miguel, hablo con Coro tlfno 618817695 (hermana de la tutelada)pregunta por cómo van los procedimientos judiciales porque quieren vender. Hablo con Angel y le envía un email al abogado que lleva el caso de la tutelada (Angel Garcia Calle): lo último que sabemos es que pidió en juino a Angel un certificado de empadronamiento para acreditar su domicilio a efectos de omprobar la competencia del juzgado. Me confirma que ya está la firmeza de la aprobación de la herencia y queda pendiente la resolución de la autorización de venta. ***************************** Llamo a Coro tlfno 618817695 (hermana de la tutelada) y la informo. Cuando tengamos resolución hay que avisarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-09-20','TERESA PROPUESTA TERE: TUTELADA ESTÁ INGRESADA EN CSS MÉRIDA + ESTÁ PREVISTA EL ALTA EN BREVE PLAZO + TERE NECESITA ARREGLAR DE CASA PARA QUE ESTÉ MÍNIMAMENTE DIGNA: SALDO EN CAJA RURAL EXTREMADURA HOY: 14.000 €/APROX. TERE: SI TOTALIDAD ARREGLO SUPERA LOS 7.000 € LO VEMOS DE NUEVO • PINTURA Y LIMPIEZA: 3.811,5 € (IVA INCLUIDO). • FONTANERIA: TERE NOS PASARÁ PRESUPUESTO/FACTURA. • ARREGLO VENTANAS: TERE NOS PASARÁ PRESUPUESTO/FACTURA. • MOBILIARIO: TERE NOS PASARÁ PRESUPUESTO/FACTURA TERE NOS IRÁ FACILITANDO LOS PRESUPUESTOS Y FACTURAS PARA ABONAR LOS MISMOS A TRAVÉS DE TRANSFERENCIA • ICIAR/NATALIA: PAGAR LO QUE NOS PASE TERE','2');
