insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-09-20','miguel, llega comunicación propuesta de acuerdo de complementaria de la declaración 2018, queda pendiente nos remitan la resolución firme con la carta de pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-09-20','miguel, llega por email por Gerencia (Alicia) dos notificaciones, consistentes en la comunicación tramite de audiencia del ejercicio 2016 de AEAT y del ejercicio 2018 requerimiento para que aportemos certificados de rendimientos de trabajo a AEAT. Reenvío email a Amalia y Alberto: Buenas tardes de Doña Mª Luisa Espinar del Arco han llegado dos complementarias más 2016 y 2018 (no son firmes: en la del 2016 tenemos período de alegaciones, y en 2018 nos requieren para que aportemos certificados de los rendimientos de trabajo) Como ya hablamos si no podemos hacernos con ellos, según nos comentó Amalia en su día, habría que esperar a que sean firmes y abonarlos una vez que llegue la carta de pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAMIAN SALVADOR'and edp.apellido1='GRANADOS'and apellido2='HEREDIA'),'2021-09-20','miguel, llega email y lo reenvío a Amalia y Alberto: Buenas tardes señor Miguel soy Damián tengo el problema que Gisela está de baja y no ha avisado la comisión a la clínica para ir a ponerme los dientes y hacerme empastes etc....en la clínica Diana le pediría por favor a la comisión que como Gisela no puede hablar con la comisión al estar de baja para que llamaran a la clínica Diana para que me vallan dando citas poco a poco para ir arreglandome la boca ya que tengo muchas dificultades al masticar la comida porque me faltan muchas piezas dentales para que pregunte por favor cuando la comisión la parte económica que ya está aprobado el presupuesto para ir a la clínica diana.pregunte por favor cuando la parte económica se va a poner en contacto con la clínica para ir yo a la clínica Diana e ir abonando las sesiones para realizar el arreglo de mi boca espero su contestación muy señor nuestro un cordial saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='COMENDADOR'and apellido2='GARCIA'),'2021-09-20','Ana: Conversación con Mª Encarnación Vadillo, TS Mancom. Campo Arañuelo (927 54 73 57 // ssbase1@campoaranuelo.org // MOVIL 620 456 257): preguntan por este expte. pues en el Jdo. le comunican que ya nos lo han enviado. *Es una situación urgente por abandono absoluto de su persona. ··· Le informo que según me comunica Enrique, Admvo. Secc. Jurídica, estamos pendientes de Abogacía para ver si nombran a la CTAEX Defensa Judicial o no. ··· Planteo la posibilidad de que vuelvan a comunicar al Jdo. el empeoriamiento y gravedad de la situación proponiendo se adopten medidas cautelares previas.','2');
