insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-09-21','Ana: Llamada de Ceferino (611 442 878), se quiere apuntar a la Escuela Oficial de Idiomas, quiere aprender italiano. (Matícula 76,53. Hay que abonarlo con el Modelo 50) ···· También quiere comprar una aplicación para el móvil para mejorar la técnica de escritura "Doméstika Escritura" (precio apróx. 20€) . ···· Le van a publicar un relato "Big Little" (80 páginas). Envió la sinópsis a la Editorial Círculo Rojo. . Desiré, trabajadora de la editorial le explicó cómo funcionan. *Tiene que abonar 325€ para publicarle 50 ejemplares. *Ya está escribiendo otro relato "Historia de la Sra. Luci" (de este sólo lleva 4 páginas). ···· También se quiere apuntar a un curso de Arqueología de la Universidad Popular. ········ Indico que deben enviarnos todo por escrito (incluídos documentos de pago) a la comisión tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-09-21','TERESA ENVIO PNC YA QUE AHORA ESTA COBRANDO PF Y LE ES MAS BENEFICIOSO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RODRIGUEZ'and apellido2='OLMO'),'2021-09-20','CIERRE EXPTE. Se recibe Testimonio, devenida firma, del Auto n.º 49/21, de 25 de febrero, por el que se remueve del cargo de tutor a la CTAEx y se nombra, para ejercerlo, a Dña. María Dolores Sancho Rodríguez. HIja de la tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-09-21','Ana: Conversación con Pilar Martín, TS: Le llamó ayer Mariluz Madrigal, Jefa de Secc. Salud Mental. **Se va a derivar a Esteve a CRR o Piso Supervisado. Ya ha hablado con Anabel, de SSASB de Miajadas, para que preparen la solicitud de revisión del PIA y adjunten informe social para solicitarlo por emergencia social. ································································································································································································ Llamo a Anabel, TS de SSASB (Tfno: 927 347 000 Ext.: 3401): Le han dado cita en el MAP para emitir el informe de salud para la revisión de dependencia el día 8/10. Cuando lo tengan me lo remitirá junto al Informe Social por emergencia Social para priorizar el cambio de recurso y la Solicitud de Dependencia. ······························································································································································································· *Cumplimento la Solicitud de PNC y recabo la firma del D. Gerente. ············· Se la entrego a Julio, CTAEX, junto al oficio para que le dé REGISTRO DE SALIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2021-09-21','Ana: Llamo a Pilar Sánchez - Hogar S.Vicente de Paúl, Plas. (671 01 66 15): Aunque aún no se ha abonado nada, Mª Carmen se ha ido igualmente de vacaciones con las compañeras del Hogar. ··········· *Envío correo a Alberto, secc. ecca., y pido que se abone cuando se pueda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-09-21','TERESA En relación al correo que enviaste ayer respecto al caso de Antonia Lavado, te detallo a continuación el estado actual de la situación: Conociendo el circuito establecido en la subcomisión de casos para la paciente, ésta ingresó en UME el 6/7/2021. Desde el inicio de su estancia en esta unidad, se ha venido trabajando con ella en el sentido de hacerle tomar conciencia de la necesidad de admitir un ingreso en un centro residencial de mayores. La negativa, sin embargo, ha persistido por su parte, habiéndonos sido imposible que admita voluntariamente la mencionada posibilidad. Dadas sus circunstancias legales, ya que no tiene reconocida la incapacitación legal y la única figura de protección otorgada para ella es la curatela económica, no entra dentro de nuestras posibilidades forzar un ingreso en centro alguno. Esto haría recomendable en nuestra opinión iniciar un procedimiento de incapacitación, dada su total falta de recursos personales para su propio cuidado. Por otra parte, a causa de la duración previsible de un proceso de este tipo - en el caso en que se decidiera iniciarlo - no sería posible su espera en la unidad de media estancia, siendo necesaria una solución transitoria para dicho periodo de tiempo. Tras contacto con su psiquiatra de referencia, se ha decidido a los efectos anteriormente expuestos la convocatoria de una nueva subcomisión de casos. Somos plenamente, como ves, conscientes de la situación a la cual nos enfrentamos con esta paciente, y esperamos que en el seno de la subcomisión, teniendo en cuenta todos los factores, se encuentre una solución adecuada. Recibe un cordial saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-09-21','miguel, envío email a Amalia, Alberto, Maite: Buenos días, me ha vuelto a llamar la policía (Ramón o Jesús 648072582 y 0824-905049) para pedirnos que retiremos de una vez el vehículo Rover 25 de la c/ Legión. Me confirman que el vehículo está a nombre del tutelado en tráfico y por tanto y a todos los efectos legales el responsable legal es el tutelado. He hablado con el desguace Caballero de aquí de Mérida (tlfno: 924-123100) y me piden autorización del gerente, testimonio de nombramiento de la Ctaex, dni del tutelado y del gerente. También quieren que alguno nos personemos en el lugar en el momento de retirarlo de la vía pública. Al no quedar cerrado la posible compra con el interesado y debido al tiempo que lleva el coche pendiente de retirarse, debemos mandarlo a desguace ya. He quedado con la policía que a lo largo de la mañana le diré la decisión adoptada. Si estáis de acuerdo preparo el acuerdo del Gerente y procedemos a que se lo lleve el desguace. ***************************************** Lógicamente intenté ponerme en contacto con la compradora (supuesta) y el teléfono que me dio la policía decía que no existía (924-903665), así que remití una carta certificada que me la han devuelto ausente a la dirección que me indicó la policía y que coincide con la que tenemos c/ Tomás Romero de Castilla 11, P1.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-09-21','miguel, llega email de Juana Heras de Liberbank: Buenos días. Ésta es la respuesta de los compañeros de Asesoría y oficina: Al ser el fondo un contrato mancomunado, necesitamos que estén todos los titulares presentes para efectuar el reembolso. Como una de las clientas está tutelada por la Junta, necesitaríamos orden por parte del tutor para realizarlo. Cualquier aclaración, me decís. *************************************************** envio el email a Amalia, Angel, Alberto: Buenos días, os adjunto contestación de Liberbank. Entiendo que la parte económica tendréis que acompañar al gerente a firmar el desembolso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2021-09-21','-Amalia : rgistro de entrada al INSS Caceres PFHC para cambio de titularidad y solicitar cpto. ATP.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-09-21','TERESA Teresa muchas gracias por la información , me parece muy acertado que establezcan una nueva reunión desde la Subcomisión para dar una respuesta a la situacion de la paciente. Te informo para tu conocimiento del caso, que fue desde servicios sociales, a través de un informe a la Fiscalia , donde se promovió la incapacitación, siendo la propia Fiscalia la que presentó demanda de incapacitación en el Juzgado de Almendralejo. La incapacitacion se desestimó, asignánsosele solamente la curatela, la familia recurrió y fue la Audiencia de Merida la que desestimó el recurso y vuelve a considerar solamente la incapacitanción parcial como curatela, asi llevamos desde el año 2018. Creo, el tiempo nos irá diciendo, que es un riesgo el que esta retorne al domicilio y a una comunidad de vecinos que dia a dia sufren las consecuencias de los actos de Dña. Antonia Engracia , ojala se pudiera hacer algo por el bien de todos. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-21','Ana: Recibo llamada de Rosa, Admvo. CSS-Plas: Javier ha ingresado esta mañana en UME. Desde el HSPA no nos habían notificado nada. *Necesita que le envíe sentencia de incapacitación y aceptación del cargo (se lo envío por email). Así mismo necestia dinero para gastos de bolsillo. *Necesitaremos presupuesto de gastos aproximado. *Se lo pedirá a Estrella, TS. *En cuanto al problema con el banco, las compañeras de la secc. ecca. acudirán al banco con José Vicente Granado en cuanto puedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='MACHIO'),'2021-09-21','-Amalia : se adjunta el documento para cambio titularida del agua a la empresa , tengo copia en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2021-09-21','email a TS de la Luz : Buenas , pongo en firma Anexos II y III , te los reenviaré en cuanto estén para que lo firme también Miguel . Hecho el oficio para el INSS solicitando Cdo. PFHC , lo pondré en registro , cuando llegue te lo envio . He ampliado zonas tanto para RAL como para VT , a petición de la sección de discapacidad . Lo llamé para que él mismo eligiese zonas : Badajoz , Zafra .. lo más cercano a su domicilio . Sigue en lista de espera . Un saludo.','2');
