insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2021-09-21','TERESA ME LLAMA M JOSE DEL PISO SUPERVISADO PARA COMUNICARME QUE LUCIA ESTA INGRESADA EN EL HOSPITAL DE ZAFRA DESDE EL 14 DE SEPTIEMBRE POR UNA BRONQUITIS LE COMUNICO QUE YA COBRA LA PRESTACION Y QUE LE PUEDEN CALCULAR EL PRECIO DE LA PLAZA EN FUNCIO A ELLA TAMBIEN ME PASA EL CONTACTO CON LA FARMACIA PARA HACER EL PAGO Y QUITAR LA DEUDA NATALIA ACUERDA CON LA FARMACIA EL PAGO POR TRANSFERENCIA, ENVIARAN FACTURA A CTUTELAR','2');
