insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2021-09-21','TERESA RECIBO LLLAMA DE LA DIRECTORA DE LA RESIDENCIA 659896158 ME COMUNICA EL DESEO IMPERANTE DE MARIA ELENA DE IRSE A SU CASA, NO QUIERE ESTAR EN ESE CENTRO NI EN NINGUNO CONSULTO CON LOS ASESORES JURIDICOS Y ME INDICAN QUE NO HAY IMPEDIMENTO PARA QUE MARIA ELENA PUEDA VOLVER A SU CASA SI ESE ES SU DESEO Y ASI SE LO COMUNICO A LA DIRECCION ME QUEDO A LA ESPERA DE SI FINALMENTE SE MARCHA PARA FIRMAR LA RENUNCIA DE LA PLZA T4','2');
