insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-09-22','Ana: Correo de Estrella Durán, TS CSS-Plas.: "Ana, ayer en reunión de UHDAC quedamos en que venga la madre de Reme a Plasencia a visitarla y salgan por la ciudad, acompañadas por un auxiliar, a tomar algo. Sería el próximo miércoles día 29 por la mañana. Tengo que hablar con su madre a ver si le viene bien. Y con su tía Vele, que me va a enviar dos presupuestos de taxis, para enviarlos luego a vosotros y nos deis el visto bueno."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2021-09-22','Ana: Correo de Toni, Futuex, con facturas pendientes, que envío a Alberto, jefe secc. ecca. y nota de seguimiento y acompañamiento a cita: "21/09/2021 Se realiza acompañamiento a consulta en salud mental con el Dr. Jiménez Cano, en consulta el tutelado se muestra a la defensiva y responde con cierta agresividad a las cuestiones que se le plantean, solicita reducción en la pauta de tratamiento psiquiátrico, pero el doctor no lo valora oportuno argumentando que la pauta ya es bastante baja. Jesús insiste nuevamente en el complot que inicio su familia en contra de el por el cual fue incapacitado por vía judicial, pero el psiquiatra le recuerda que está obligado a cumplir con el tratamiento por una pena que le fue impuesta por agresiones a la familia y que le obligó a permanecer ingresado durante un tiempo y a seguir el tratamiento, por lo que si no lo hace se verá obligado a informar a los juzgados, se le confirma por parte de la educadora de equipo que acude cada mes al centro de salud Plaza de Argel para la administración del tratamiento inyectable (en torno al día 3 ó 4 de cada mes). Posteriormente, al salir de la cita solicita ayuda para la solicitud de cita en el banco para la retirada de dinero, el sistema de citas por contestador es un trámite muy tedioso y no es capaz de solicitar la cita por lo que se le ayuda en este aspecto, se realiza la llamada en su nombre y se comprueba que efectivamente es demasiado complicado la petición de cita vía telefónica, porque no puede elegir el día y le dan en oficinas de otras localidades, se acude a la oficina pero no facilitan otra vía de contacto respondiendo que “toda la gente pide cita por esa vía”. Tras intentarlo durante un largo rato, se le transmite que se le intentara solicitar esta cita vía web, finalmente se consigue cita para el lunes 27 a través de la web de liberbank-unicaja y se le comunica esta cita al tutelad con posterioridad."','2');
