insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-09-22','Ana: Remito a David Lefevre, Serv. de Asuntos Sociales del Consulado de Francia en Madrid (david.lefevre@diplomatie.gouv.fr) Informe Médico pendiente que me remite Sandra, TS de la Residencia. ····················· Respusta de David: "Gracias Ana ! Estoy esperando la respuesta de su hija a mi mail del pasado 15/09/2021 con el fin de verificar la nacionalidad de Maria del Rosario. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-22','Ana: Correo de Estrella Durán, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es), en relación a la solicitud de CRR: "Ana, hablé con Mamen T.S. de Psiquiatría del HSPA de Cáceres, me dice que no había enviado el Informe Social, pensando que lo retomásemos el caso aquí en UME, le he dicho que si ella tenía datos recogidos, que hiciera el favor de enviarlo ella porque será más rápido...me dice que sí, que ella lo envía."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2021-09-22','Ana: Descargo informes de seguimiento del aplicativo de Futuex y los guardo en su expte. *A destacar que Brahim está más tranquilo en las últimas visitas, posiblemente se deba al cambio de mediación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-09-22','TERESA EMAIL FUTUEX el pasado 21 de Septiembre se estuvo conversando telefónicamente con Lola, la trabajadora social del sociosanitario de Mérida que lleva la UME, sobre el caso de Antonia Engracia Lavado de Hoyo que está ingresada en la unidad actualmente. Lola comentaba que según las decisiones que se tomaron en la subcomisión de caso, Antonia pasaría del sociosanitario a una centro residencial. La problemática reside en que Antonia no quiere irse a una residencia de ninguna manera y al ser una curatela económica de la comisión, no se la puede obligar. Se está trabajando con ella en la UME para que vea las ventajas de residir en un centro, la compañía, las actividades que podría realizar y los cuidados médicos de los que dispondría, pero ella lo ve inviable, pide continuamente volver a su domicilio. Lola cuenta que se va a convocar otra subcomisión para discutir el caso de Antonia y para ver si se podría iniciar la incapacitación para así poder hacer un internamiento involuntario. Pero ese proceso es largo y no pueden mantenerla todos esos meses en la UME, por lo que se baraja la posibilidad de que regrese a su domicilio en Almendralejo mientras tanto. El domicilio de Antonia está en unas condiciones muy malas, ya que carece de ventanas, puertas, y de mobiliario en general, de hecho no dispone ni de sanitarios en el cuarto de baño. Se ha hablado también con Antonia Morán, de los SSB de Almendralejo y que conoce el caso de Antonia E. Lavado desde hace muchos años. La trabajadora social tiene custodiada la llave del domicilio de la curatelada y se va a ir con ella la semana que viene al piso. Se va a comprobar en qué estado está y se va a hacer un inventario de lo más básico que habría que comprar para que Antonia pudiera regresar a su vivienda. Aunque seguramente sera bastante costoso pq al parecer la casa no tenia de nada, lo habia roto todo. Seguidamente se iría a las tiendas de Almendralejo para pedir presupuestos de todo lo necesario y se enviaría otra nota adjuntando esos presupuestos para que la comisión se haga una idea lo que costaría todo. Que tengas una buena mañana, un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-09-22','Ana: Vuelvo a llamar al INSS, tanto a P. Jubilaciones (927 62 00 62) como a Control de Pensiones (927 62 00 49/65) en relación al embargo de su pensión: No obtengo respuesta. ······························································································································································································· Llamada de Jesús Domínguez Palencia (927 23 75 73 // 600 70 22 55), hermano de Martín: Comunica que su hermano se encuentra en urgencias y le van a ingresar en el HSPA por encontrarse mal físicamente. ············ Mamen ha hablado con Ausi, mujer de Jesús. ·· También le ha llamado la médica de urgencias, pues ha visto en el expdte. que es un paciente de Salud Mental. ··· Martín van a ingresar en Medicina Interna. Mamen hablará con el especialista que le asignen para proponer la interconsulta a Psiquiatría. ···· En principio ella considera, que una vez se le hagan las pruebas pertinentes y se le estabilice clínicamente, quizá pueda volver al domicilio y con apoyos (SAD / TAD) pueda llevar una vida normalizada. *NO tiene tlf. móvil. ······· Seguiremos en contacto en los próximos días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-22','Ana: Comparecencia en el Jdo. de José Manuel Correa y la CTAEX. ·························································································································· Envío nuevo correo a Plácido y Pedro, Secc. Centros Gerencia Territorial de CC comunicándoselo. Cuando tengamos la resolución judicial volveré a ponerme en contacto. ···················· Respuesta de Plácido (residenciasmayorescc@salud-juntaex.es): "Hola Ana, Justamente he estado llamándote esta mañana porque tenemos plaza en la Residencia de Geryvida. Seguiré dejándola en lista pero tramitando las vacantes actuales. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-09-22','Ana: Conversación con Lucía Ávila, Residencia El Conquistador de Trujillo (660 963 767): Nos remitirá la aceptación PIA para la firma del Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='NARANJO'and apellido2='LUENGO'),'2021-09-22','miguel, remito email a raiz de la notificación que nos hace el ayuntamiento de Azuaga donde se ha presentado la vecina del c/ Dinino Morales 45, Azuag, Mª Belinda Gonzalez Gonzalez que pone de manifiesto las humedades que produce la vivienda actualmente de la tutelada (por herencia pendiente de tramitar, por fallecimiento de sus padres y su hermano). Pregunto al email de referencia: omic@azuaga.es varias cuestiones: Buenas tardes, en relación a la actual propietaria y tutelada por esta Comisión Tutelar de Adultos (Doña Josefa Naranjo Luengo) nos ponemos en contacto con ustedes por si nos pueden informar de las siguientes cuestiones a efectos de justificar al juzgado el arreglo de gastos extraordinarios y reparación que nos requieren desde su ayuntamiento: -¿Se derribó totalmente o no la vivienda en su día? -¿pueden facilitarnos la referencia catastral y el número de finca registral de esta vivienda?. -¿Es posible que nos faciliten certificado de defunción y número de los dni de los padres y hermana de la tutelada Josefa Naranjo Luengo? ****************************************** Me contesta Manuel Sequedo que el martes cuando vuelva me llamará para aclarar todo a efectos de acreditar la titularidad actual de la tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-09-22','miguel, me llama por teléfono la abogada de la familia Soledad Carreres a la que le explico la situación (que ella ya conoce pues tramitó los procedimientos de ejecución por reclamación de cantidades de derecho de alimentos, etc). Le remito tanto la documentación que me remitió la familia como la que remitió el abogado de la otra parte Carlos Jurado, para que ella se ponga en contacto con él una vez que estudie en profundidad el caso y llegue si es posible a un acuerdo. Con lo que sea ya me llamarán para decirme si van o no a juicio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-08-11','miguel, devuelta por Ausencia la Carta que remiti a la posible compradora a la dirección que me remitió la policía y que coincide con la que nosotros tenemos en c/Tomar Romero de Castilla 1,P1 y llamo al tlfno 924-903665 q me dieron y dice no existir. Hablaré con el Desguace para su retirada definitiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-09-23','miguel, la abogada Ana de Pablo me confirma que la fecha de la firma será el 1-10-21 a 10h. Reenvío el email a Ana de la notaria de romero leal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2021-09-23','Ana: Alberto, jefe secc. ecca, me confirma que Mª Carmen sí tiene Seguro de Hogar en Generali. ··········· Se lo comunico a Pilar, Directora Hogar San Vicente Paúl (671 01 66 15) y le remito copia del recibo que me facilita Alberto (direccion.hgsvplasencia@gmail.com).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-23','Ana: Correo de Estrella, TS del CSS-Plas.: "Ana, acabo de hacerle entrevista para abrirle historia social. Está bastante adecuado y colaborador, en la unidad también. Hicimos presupuesto de gasto mensual, dice que quiere el tabaco más barato que haya, son puritos que valen 1,20 diez, como fuma 20 al día, serían 2,40 por 31 días, son 74,4. Le sugiero que sean 100 para que le sobren 25,6 para algún café o refresco...dice que le parece bien. Como gasto extra, dice que quiere un MP3 con unos cascos que pueden suponer unos 50 euros más. Cuando tengáis la autorización la enviáis para poder sacarle dicho dinero.... Con respecto a sus planes, me dice que lo primero que quiere es "reformarse" "estar tranquilo" y luego irse a un piso compartido de alquiler, le pregunto si no quiere ir a un CRR, me dice que sí, que primero a un CRR. También le pregunto si no le gustaría ir a su casa del pueblo, dice que no le gusta vivir solo....que se fue por ahí a vagar porque estaba muy nervioso..." ·············· Paso propuesta de gastos de bolsillo y extra puntual a Alberto, secc. ecca. Por mi parte Ok a ambas cosas. ············ Envío correo a Estrella: "Hola de nuevo Estrella, La sección económica aún no me ha confirmado, pero creo que no habrá inconveniente con la asignación para gastos de bolsillo ni con el extra. En relación a la autorización general se enviará pronto al centro, pues este mes ya le están ingresando pensiones en la nueva cuanta de Liberbank. En cuanto el resto de cuestiones planteadas en la entrevista, es lo mismo que hablé yo con Javier unos días antes de pasar de UHB a UME. Planteaba irse a un piso de alquiler, pero razoné con él la conveniencia de realizar el proceso terapéutico primero que le fueran indicando los especialistas y aceptó de buen grado hacer ese circuito si así se lo proponían desde el Sociosanitario (UME – CRR y si luego todo va bien Piso Supervisado u otras opciones como la que él plantea, que se irá valorando según evolucione) *En cuanto a la llamada a Javier, intentaré llamar el lunes sobre las 12 h."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-09-24','-TF DE ALEJANDRO 671330861 , me ha llamado por tf. solicita tarjeta debito . Se le explica la razón por lo que no se le puede entregar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-09-24','-Amalia : se recibe email de Manuel Picado de Piso Supervisado de Mérida . Buenos días Manuel , ya me había comentado algo Mª Luz . Los recursos de rehabilitación de salud mental exigen la voluntariedad del usuario , desde esta Comisión Tutelar no se interviene en el alta o no del recurso .Si en este caso Francisco ha solicitado su alta no nos podemos oponer . Este tema y para poder disponer de la plaza lo tienes que comentar con Mª Luz , o con las compañeras del Servicio de salud mental . Sigue actualmente en el piso o se ha marchado ya ? dónde tiene pensado ir tras el alta ?? esta información la necesitamos conocer para poder seguir interviniendo en el caso . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-09-24','Hola Amalia, te informo: Fco. Cacho salió del PS el 1-9-21. He estado informándome de su recorrido fuera. Por lo que sé estuvo en Cádiz y ahora está en un albergue en Cáceres. Hablé con Ana (familiar, creo que estuvo en la Consejería de Bienestar Social) y le expliqué la situación. He esperado todo este mes por si reacciona y vuelve, pero viendo que no tiene intención -de momento- no puedo tener la plaza sin ocupar tanto tiempo. Así que, siguiendo tus instrucciones, procedo al alta por renuncia voluntaria. Se lo mando a Mª Luz Madrigal. Como siempre, gracias por tu atención y respuesta rápida. Cuídate que tienes demasiados usuarios a tu cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-09-24','Ana: Se recibe llamada de Álvaro Borrega (662 186 901), Abogado de Miguel Santos, hijo de Miguel. Expresa Miguel, hijo, nos ha solicitado por mail informes relativos a su padre. Le indico, por un lado que no los ha solictado en forma y que una vez fallecida la persona tutelada finaliza la relación y el ejercicio del cargo de tutor. Desde la CTAEX sólo queda la rendición final al Jdo. ···· Le remito al Jdo. para cualquier cuestión que quieran plantear/solicitar. ······ No obstante, ante sus preguntas, explico que desde la CTAEX, desde un primer momento, se han llevao a cabo muchas gestiones de diversa índole relativas a propiedades, deudas, vehículo, asignación de educadora para visitas perídicas ya acompañamientos a consultas médicas y gestiones, coordinación con profesinales del C. Salud y del ESM, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LORENZO'and apellido2='FERNANDEZ'),'2021-09-24','Ana: desde la CTAEX se aprueba el presupuesto que remiten desde el CSS para la compra de la SILLA DE RUEDAS con resposapiés que pueden elevarse y reposacabezas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='TESORO'and apellido2='GARCIA'),'2021-09-24','Ana: desde la CTAEX se aprueba el presupuesto que remiten desde el CSS para la compra de la SILLA DE RUEDAS con resposapiés que pueden elevarse y reposacabezas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2021-09-24','Ana: se da el visto bueno a la propuesta de actividad remitida por Felisa Custodio, TS CAMF-Alcuescar: "...Cáceres, Gran Teatro, 08 de octubre, actúa Ana Guerra. Desplazamiento: taxi adaptado de la localidad. Acompañante: el propio taxista, es también conductor de ambulancias y conoce el manejo de las sillas de ruedas, ha acompañado en otras ocasiones a otros residentes a eventos similares. Solamente le cobra el trayecto y su entrada al concierto. Gastos: 90 euros taxi y 20 euros dos entradas. Ya le he advertido a la residente que no puede ir con nadie más, incluido el "novio" que tiene y que ya hemos hablado del tema en ocasiones anteriores." ········· Se lo comunico a Felisa por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-09-23','Ana: Correo de Paula, TO del CRR-Plas: "como os he ido contando Ceferino ha ido desarrollando una de las actividades por las que siente gran interés como es la escritura. Ha escrito un par de novelas y ha mandado una de ellas a una editorial con una buena valoración de la misma, en la que le ofrecen la posibilidad de autoeditarla (es decir pagar su edición). A nosotras nos parece que es muy positivo para él hacerlo, puesto que ha requerido esfuerzo, dedicación y compromiso, logrando los objetivos marcados en relación a la tarea. La cantidad es de unos 350 Euros para una edición de 50 libros. Os va a enviar los documentos que le ha facilitado la persona de contacto de la editorial para que se pueda realizar. Además esto le ha motivado y va a apuntarse a la escuela de idiomas (77 Euros) y posiblemente a algún otro curso de la universidad popular (unos 20-25 Euros), por lo q que próximamente nos pondremos en contacto con la parte económica específicamente para que pueda afrontar todos los gastos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-09-24','Ana: Remito a Anabel, TS SSASB Miajadas, por mail el C.I. para la tercera dosis de la Vacuna Covid firmado electrónicamente por su representanta legal.','2');
