insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-09-03','Ana: correo de Ana, Enfermera de la Res. FEMAR (residenciafemar2019@gmail.com): "BUENAS TARDES: SOY ANA GARCIA , ENFERMERA DE LA RESIDENCIA FEMAR , LE ADJUNTO INFORME DEL HOSPITAL DE VALENTINA . POR LAS CIRCUNSTANCIAS EN LAS QUE NOS ENCONTRAMOS ACTUALMENTE EN LA RESIDENCIA SE ENCUENTRA EN AISLAMIENTO . NO TIENE FIEBRE Y SATURA A 91 , ESTA MAÑANA SE LE HA REALIZADO CURA DE LAS MANOS Y APLICADO VENDAJE COMPRESIVO EN MANO IZQUIERDA AL IGUAL QUE AYER . YA QUE LLEGO CON UN EDEMA IMPORTANTE DEL HOSPITAL EN DICHA MANO. PESE A ENCONTRARSE ACTUALMENTE CONEN BUEN ESTADO ,LA PASADA NOCHE TUVIERON QUE LLAMAR A CS YA QUE TENIA SATURACIONES BAJAS AL IGUAL QUE LA TENSIÓN ARTERIAL. CON HIDRATACIÓN POR VIA ORAL FUE REMONTANDO Y ACTUALMENTE SE ENCUENTRA BIEN, CON LAS CONSTANTES INDICADAS ANTERIORMENTE . ELLA SE ENCUENTRA ANIMADA AUNQUE HA PERDIDO MOVILIDAD Y DICE ESTAR MUY FLOJA . HAY QUE DARLE DE COMER , DUCHARLA , ASEARLA ... IREMOS INFORMÁNDOLA CON LA FRECUENCIA QUE ESTIME OPORTUNA . UN SALUDO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-27','Ana: Recibimos del Jdo. Autorización de Internamiento Involuntario para Manuela. ······················ Remito correo a Plácido Alejandre y Pedro Gía, Gerencia Territorial (residenciasmayorescc@salud-juntaex.es): "Buenos días Plácido y Pedro, ¿Qué tal estáis? En relación a Dª Manuela Morato Picado, y la solicitud previa de plaza Sociosanitaria (T3), acabamos de recibir la Autorización de Internamiento Involuntario del Juzgado de 1ª Instancia e Instrucción nº1 de Valencia de Alcántara, la remito adjunta para que procedáis, en cuanto sea posible, a asignarle centro y podamos desde la CTAEX activar el 112 en el día que nos indiquéis. Ante cualquier cuestión no dudéis en contactar. Gracias y buena mañana." ············· Conversación con Placido Alejandre (927 004 261): Hay una plaza en Baños de Montemayor, va a consultar si es posible en algún recurso más cercano a su pueblo y me lo comunicará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-09-27','Ana: Correo de Estrella Durán, TS del CSS: "Te escribo para comunicarte que, de nuevo Juan Carlos Ruíz se ha escapado del centro, el viernes sobre las 20:30 se echó en falta y lo trajo la Policía a las 12 de la noche."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-09-27','TFO. FCO. CACHO 641569490. TFO. ANA (FAMILIAR) 661417701','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2021-09-27','miguel, asistimos presenciales Maite y yo.Desguace Caballero procede a la retirada del vehículo, al que entregamos acuerdo del gerente de retirada, testimonio de aceptación de cargo y dni del gerente y del tutelado. Aparece como titular de un seguro con bbva 2019-2020)una persona se desconoce, también se ve el pago de tasa de Itv del 2019. Los papeles oficiales (tarjeta de inspección, permiso de circulación)siguen apareciendo a nombre del tutelado. Hacemos fotos de los papeles y los dejamos en su carpeta virtual de propiedades, retirada y desguace. ********************************************** Llamo de nuevo a la policía para confirmarles su retirada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2021-09-27','Buenos días , me parece una propuesta estupenda . Yo me encargo de comunicarlo al Servicio de Prestaciones , necesito contrato y cuantía que percibiría . Un salud Buenos días Amalia. La Junta de Tratamiento ha propuesto a Cristofer Rollán Suarez para el desempeño en este centro de un destino remunerado como peluquero, esto conlleva un alta en Seguridad Social a través del O.A. de Trabajo Penitenciario., y aunque las rentas por el destino son bajas (unos 100 €/mes como máximo), y se podría compatibilizar con la percepción de la PNC, hay que comunicarlo al Servicio de Prestaciones. Al ser tutelado vuestro, necesito saber si hay algún problema con esto, y en todo caso, coordinarnos para realizar esta gestión. Quedo a la espera de vuestra respuesta. Gracias y un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2021-09-27','miguel, me llama Coro (618817695)para ver si sabemos algo. Angel mando un email el otro día al abogado para que le confirmara en qué estado se encontraba el procedimiento de autorización de venta (ya que el que si tenemos ya firme es la aprobación judicial de venta). Me dice que son 7 hermanos y que están a la espera de poder vender el inmueble. ******************************************** llamo al abogado Angel Garcia Calle y me comenta que el abogado de la familia José Santiago está informado de todo ya que cada vez que tiene una resolución se la remite. En cualquier caso me comenta que la viasta para reafirmarse en la demanda la tienen el 26-10-21 y que epocos días después cree que tendrá la resolución contra la que cabrá recurso de reposición de 20 días, tras lo cual será firme la sentencia. Llamo a Coro para comunicarselo. Quedo con ella en llamar al abogado y si no insistirá ella (Abogado Angel Garcia Calle móvil 627044985 y 924-523300)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-09-27','miguel, me llama la procuradora del desahucio que tenemos pendiente (Cristina Pardo 660-404923, email: csotoprocura@aicosl.com; Cristina Soto Ruiz crisoto@aicosl.com)para que hagamos nuevo poder apud acta y autorización administrativa: "respecto al asunto de doña Carmen Leal. • Al tener que someternos a arbitraje por contrato, empezaremos solicitando al Tribunal Superior de Justicia el nombramiento de árbitro para lo cual necesitamos un poder para sometimiento y realizar el árbitraje ante el TSJ. • Se hace en los juzgados de Mérida igual que hiciste el anterior pero para que podamos presentar ante el TSJ y que este nombre árbitros. • Por otra parte, necesitamos un documento administrativo autorizándonos, tanto Jorge como a mi, para que podamos represeantarle en arbitraje . • Para mayor comodidad te pongo los datos de los dos: o Letrado: Jorge Calvo Onsurbe, colegiado ICABA, 3397 o Procuradora: Cristina Soto Ruiz, colegiada ICProcuradores Badajoz, 393. DNI 33987993L"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-09-27','Ana: Conversación con Pilar, Res. FEMAR - Logrosán (639 585 489): Valentina está mejor, continúan haciéndoles curas en las manos, pero van a mejor. Posiblemente vaya a necesitar fisioterapia, en tal caso nos enviarán presupuesto llegado el momento. ··· Por otra parte necesita ropa, solicitarán un presupuesto a la tienda que han abierto en Logrosán. ···· En cuanto a su vivienda, según les informa un vecino, es posible que sea necesario hacer algún arreglo/reforma. Le inidico que, una vez comprobado, también nos remitan prespuesto. **Por último, solicitaremos Revisión del Grado de Dependencia, pues ahora, sí que necesita más apoyos. Hablará con la TS y la MAP. (*Está valorada con grado I).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-09-27','Ana: Llamada de Isabel (649 642 635): Dice haber pasado un buen fin de semana con su familia. ··· pregunta que si cuando le den el alta puede volver a su casa a Trujillo. Hablamos sobre la conveniencia de un "paso intermedio", teniendo, eso sí, siempre en cuenta el criterio médico de los especilistas. Aceptaría acudir primero a un CRR, a ser posibel el de Cáceres. ············· *Por otra parte, me habla de la sentencia por los abusos sexuales que ejerció su primo sobre ella cuando tenía 13 años, motivo por el que éste está en prisión. *Dice que tenía que haberle indemnizado con 20.000€, pero que se ha declarado insulvente. El procedimiento tuvo lugar hace 3 años apróx. ·········· Envía imágenes de la sentencia al ctutelar. ······· A petición de Ángel, Asesor Jurídico, le pido que nos haga llegar, a través del CSS, el documento completo escaneado. ································································································································································································ Envío correo a Estrella, TS del CSS-Plas. con copia a Alberto, jefe secc. ecca.: "Buenas tardes Estrella, Isabel ya está percibiendo las dos pensiones en su cuenta: CCC ES20 2048 1086 1434 0008 1016 Así que cuando consideréis podéis derivar a Isabel a ULE y comenzar a cobrar la plaza. Cuando puedas dime qué coste tendrá exactamente. Por otra parte, Alberto, Jefe secc. económica nos recuerda: “En función del coste final plaza + los 150 €/mes aprox de gastos de bolsillo + el ahorro que decidamos en la CTAEX podremos calcular las veces que se puede abonar la estancia con su madre.” Ya me dices cuando puedas. Buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2021-09-27','miguel, me da Alberto embargos que han llegado del Oar de Cáceres de su supuesto hermnao Benigno nif 6745239Y. Tras consulta de Julio en Civitas aparecen 3 hermanos Collado Esteban (la actual Florencia Sofia, Benigno y Dolores (que ya fue tutelada por la Ctaex), y los dos últimos hoy día fallecidos. Quitando una vivienda de Benigno y un almacen estacionamiento de Dolores, los demás bienes, todos de Guadalupe, son mini parcelas rústicas (solares) de poco valor que en suma no llega a 1.000€. Tras comentarlo con Angel llegamos a la misma conclusión (él ya lo comentó con Pedro sobre el 2017) que debido a que no tiene más familia, que el resto de sobrinos no tienen relación con ella y que es muy mayor y económicamente no le hace falta, llegamos a la conclusión que tramitar esto es complicado pues no disponemos de la documentación de testamentaria de los dos hermanos fallecidos. Unido a que se requeriría abogado y procurador para la solicitud de aaceptación de herencia, aprobación de herencia y un posible autorización de venta (que requeriría a demás de los gastos de represntación procesal, el de una tasacion de esos biene). Por todo lo cual le digo a Alberto que domicilie los pagos de Benigno y que no haremos trámite alguno de herencia. Angel habló en su día con José Tello (jtellos1967@gmail.com> y móvil 635981922) interesado en explotar algunas tierras y que pretendía explotarlas previo contrato de alquiler (que no pudo hacerse porque oficialemente todavía no se han hecho los trámites de herencia). Por lo que si se requiere desbrozar o cualquier cosa tendríamos que contratarlo a parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-09-27','Maite: he hablado con Andrés, Gerenete de Down Cáceres. Me ha confirmado que Soledad no se ha incorporado a Centro Ocupacional, y que desde Nace no se han puesto en contacto con ellos en ningún momento. También he enviado correo a José María Tovar preguntando por este tema: ¡Buenos días José María! Queríamos saber, si Soledad ya está asistiendo al servicio de Centro Ocupacional de la entidad Down, en cumplimiento del auto del juzgado de 1ª estancia nº 002 de Cáceres, de fecha 13 de julio de 2021. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA'and edp.apellido1='MARTINEZ'and apellido2='LARRINAGA'),'2021-09-27','TERESA Adjunto, se remite, a nombre de Dña. Ana María Martínez Larrinaga, la siguiente documentación: • Consentimiento informado para la realización de cirugía oral','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-09-27','Ana: Tras llamada de Clara, TS del C.S. Guadalupe (53107), comunicando que Juan ha pasado hoy por el C. Salud, envío correo a Toni-Futuex: "Buenas tardes Toni, En relación a Juan Chamorro Holguín, como sabéis tiene la cita con su psiquiatra en el Equipo Salud Mental, el próximo día 28 a las 10,50 h. Hoy ha acudido al Centro de Salud para recoger el volante de la ambulancia. Espero que llegado el día no cambie de opinión. ¿Teresa va a acompañarle, verdad? Ya me decís. Un saludo y buena tarde." ············· Respuesta de Toni: "Pues primera noticia a lo del volante de la ambulancia, porque lo ultimo que sabiamos era que se negaba en rotundo y de forma tajante, que el inyectable si se lo pone (eso es cierto) pero que al psiquiatra no va porque "el tiene mucho con esto de las terceras dosis que esta poniendo" y otras cosas delirantes de este tipo decia... pensabamos ir, para hablar con el medico, Jimenez Cano de todos modos aunque el no fuera, y si va pues acompañarlo. Teresa está justo regresando de vacaciones, pero iria otra compañera de caceres con el. Vamos a ver si conseguimos hablar con el o con centro de salud de guadalupe para confirmar que quiera acudir"','2');
