insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-09-27','miguel, pregunta el arquitecto por email sobre vivienda c/General Margallo: Buenas tardes, ¿me podrían informar del estado de este expediente? Muchas gracias ******************************************* Le contesto: Buenos días, el tutelado ha fallecido el día 15-9-2021, lo cual supone la extinción del cargo de tutor por parte de esta Comisión Tutelar de Adultos conforme el artículo 231.3º Código Civil, sin perjuicio de la rendición final de cuentas que se remitirá al juzgado nº2 de Plasencia, conforme establece el artículo 232CC.','2');
