insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2021-09-24','Ana: Correo de Pilar Márquez, TS SSASB Valencia de Alcántara al ctutelar@ (trabajadorasocial@valenciadealcantara.es): "Buenos días, Ya mantuve una conversación telefónica con alguno de vosotros por este tema, esta señora Dña. Rosa Gómez Nevado tutelada de Valencia de Alcántara, tiene una casa en propiedad, y este verano , por orden de una concejala se pintó la fachada de su vivienda por estar en muy mal estado. La factura os la hicimos llegar a través de Gloria , técnico de Futuex que supervisa a los tutelados en nuestra localidad. No sé si me podéis dar alguna información acerca del tema , el pintor , como es lógico , quiere cobrar. Gracias por vuestro interés, Un cordial saludo. Pilar Márquez" ····················· Se lo reenvío a Alberto, jefes secc. ecca.','2');
