insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2021-09-28','Ana: Reenvío a Alberto, correo de la Residencia Sta. Catalina de Calzadilla, presupuestos para tratamiento odontológico urgente.··········· Alberto aprueba cualquiera de los dos presupuestos. Desde la secc. ecca. se pondrán en contacto con el centro: Loli- Administrativo (927 14 64 58)','2');
