insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-09-28','Ana: paso a Alberto, Jefe Secc. Ecca., correo de Mª José Polo, TS Trasierra T. Granadilla, que había en el ctutelar, con facturas pendientes relativas a Florencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-09-28','Buenas confirmado , se puede hacer el contrato de alquiler con fecha 15 de octubre. Saldrá el dia 1 del piso y pasará con la familia los primeros 15 dias . Voy a cuadrar un presupuesto para la parte eco con los nuevos gastos , incluido el alquiler. Seguimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2021-09-28','-Amalia : Francisco solicitó el alta voluntaria de los pisos supervisado en Mérida el 1 de septiembre . Se le ha dado un mes de margen por si cambiaba de opinión pero no ha sido así . Está residiendo en el albergue de Caceres y su intención es permanecer allí un tiempo . Cuadro presupuesto económico , para que pueda retirar 320€/ mes como estaba haciendo hasta ahora . Lo va a retirar en la oficina central del Liberbank de Cáceres. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-28','Ana: Correo de Plácido Alejandre: "Hola Ana, Tenemos plaza en Geryvida (Cáceres) para Manuela Morato Picado. Por favor, ponte en contacto conmigo para gestionarla Un saludo" Le llamo (927 004 261): Acordamos que cuando me confirmen en el C. Salud el día que podrán acudir al domiclio, se lo comunicaré y organizaremos el ingreso para el día siguiente. *El resultado de la PCR lo consultará él a primera hora del día siguiente. ·············· Llamo al Centro de Salud, para hablar con Nuria, MAP (54208): Acordamos que mañana acudirá la enfermera a realizar la PCR. *Me enviará la historia clínica resumida con especificación del tratamiento para facilitarlo al centro residencial. ·············· Maite y Ángel, CTAEX, llaman a José Manuel Correa, nieto, le comunican la Autorización del Juzgado y que mañana acudirán del centro de salud para hacer la PCR a Manuela. **José Manuel dice que va a recurrir la senencia y no se le va a hacer la prueba ni va a ingresar. *Ángel explica que la parte dispositiva del Auto no da lugar a recurrir. ·········· Ángel, Asesor Jurídico, llama al Jdo y tal y como le piden, hace una nueva comunicación por escrito al Jdo. pidiendo la colaboración de los cuerpos y fuerzas de seguridad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LORENZA'and edp.apellido1='CASAS'and apellido2='PIÑERO'),'2021-09-28','EXITUS El centro informa de su muerte, producida el 27/09/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-09-28','miguel, el arquitecto me remite el email: le rogaría me indicase cómo podemos ver esta cuestión con el juzgado puesto que estamos pendientes de que se resuelva el pago desde hace meses y ahora parece que volvemos a empezar... Gracias. ********************************* Remito email a el abogado Jesús Bueno solicitandole la firmeza de gastos extraordinarios para el arquitecto pueda reclamar en el momento que preesntemos la rendición final al juzgado el dinero que se le debe. ***************************************************** Me contesta: Vaya, cuanto lo siento, en el momento que transcurran los 20 días hábiles lo solicitamos (creo que el 7 de octubre se puede pedir ya)************************************** ******************************************************* remito email de nuevo a Adrián (el arquitecto):Buenas tardes, adjunto el auto de autorización judicial cuya firmeza he vuelto a solicitar al abogado que nos remita. Cuando nos llegue se la remito para que con ella pueda dirigirse al Juzgado de 1º instancia e instrucción nº2 de Plasencia, e indicarles que en relación al procedimiento de incapacitación nº 267/2017 se le debe ese importe. Por parte de la Comisión se recabará toda la documentación necesaria para en un plazo de 2 meses aproximadamente proceder a remitir a dicho juzgado la rendición de cuenta final. *****************************************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-09-28','miguel, llega por carta certificado de nacimiento de otra persona que no es el curatelado. Remito de nuevo email al registro civil de Badajoz, (registrocivil.badajoz@justicia.es): Buenos días, nos ha llegado la petición que les hicimos incorrectamente ya que nos han remitido el certificado de nacimiento de un tal Francisco Javier y necesitamos la de Juan Carlos donde en el margen izquierdo aparezca la inscripción de la sentencia de nombramiento del cargo de Curador a favor de la Comisión Tutelar de Adultos. Se adjunta dni del curatelado, testimonio de nombramiento (que debió remitirse al registro civil para su inscripción), testimonio de aceptación del cargo por la Comisión Tutelar de Adultos, partida de nacimiento. Necesitaríamos que nos remitieran dicho certificado firmado electrónicamente por esta vía. Caso de que se trate de certificado firmado físicamente ruego nos lo remitan al SEPAD (Comisión Tutelar de Adultos). Junta de Extremadura. Avda de las Américas 4, cp 06800, Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2021-09-28','Ana: Correo de Rebeca Gordillo, Concejala del Ayto. de Santiago de Alcántara, a través del inf.saludextremadura@salud-juntaex.es: "Buenos días, intentamos ponernos en contacto con Pedro para pasarle la factura de un tutelado de la Junta y así devolverle el dinero al familiar que le ha comprado la ropa, pero no somos capaces de contactar con nadie. Solicito me manden un contacto por favor al correo concejala@santiagodealcantara.com El ayuntamiento es el nuevo director de la Residencia de mayores de Santiago de Alcántara donde está el tutelado Arturo Rocha Merchán. Gracias ······ Llamo a Rebeca (673 58 45 26): le explico que Pedro ya no está. Le facilito varios datos de contacto (entre ellos los míos). Le pido que nos remitan la factura de la ropa, hablaré con Alberto, Jefe de secc.ecca., entiendo que no habrá problemas en esta ocasión, pero explico el modo de proceder para ocasiones futuras. **Sin presupuesto previo aceptado no se abonará nada más. ········ El correo de Rebeca es: concejala@santiagodealcantara.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-09-28','miguel, remito al juzgado contestación al oficio de requerimiento de información de orden de alejamiento. Aunque el juzgado (Ana)quedó en remitirme de nuevo el requerimiento, al no llegar, hemos contestado sobre el que remitieron en junio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2021-09-28','TF JORGE 655086066','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2021-09-28','Ana: Pongo para la firma del D.Gerente Autorización para participar en las Jornadas “Convivencias 2021” del Programa de Actividades de Naturaleza y Aventura, que tendrán lugar en la localidad de Barcarrota (Badajoz) desde el miércoles 29 de septiembre hasta el viernes 1 de octubre de 2021. *Es totalmente gratuita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-09-28','Ana: Correo de Carmen Gía Martín, TS EVD Plas (carmen.garciamarti@salud-juntaex.es): "hola Ana, tenemos aqui la aceptacion pia de Isabel Muñoz, no se muy bien porque ha vuelto aqui. Saldra por valija a merida Modiifcare el pia ( me he liado con tantas descargas que he hecho ) ya mañana e intentare que quede reflejado el cambio de pia te insisto,disculpa las molestias habidas Seguimos en contacto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-09-29','Ana: correo de Julián, Director COCEMFE (gerencia@cocemfecaceres.org): "Buenas tardes Ana. Te informo que T.E.I. ingreso ayer tarde en el hospital universitario de Cáceres por fiebre alta y posible infección de orina. Esta mañana fui a verle a urgencias (en zona de observación) donde aún se encontraba a la espera de que le diesen habitación en planta de urología. Tras hablar con el hospital hace 15 minutos me indican que sigue a la espera de que se le adjudique habitación. Por su perfil, va a necesitar un cuidador durante su estancia en el hospital en horario de 14.00 a 22.00 aproximadamente. Una vez nos notifiquen la adjudicación de la habitación y podamos hablar con los médicos os informamos. Un saludo" ················ Mi respuesta: "Buenos días Julián, Gracias por informar. Espero que Tomás evolucione bien y el ingreso dure el menor tiempo posible… En cuanto al cuidador, yo creo que es mejor que sea alguien de confianza, como en las vacaciones, sino tendríamos que buscar una empresa privada. Dinos si hay alguien que conozcáis que esté interesado y pueda hacer el acompañamiento y en ese caso presupuesto diario para que Alberto, jefe de secc. ecca. pueda autorizar. Un saludo y buena mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-09-29','miguel, me contesta por email el registro civil de Badajoz, que el curatelado nació en Don Benito. Reenvío el email al Registro Civil de Don Benito','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2021-09-28','TERESA ENVIO POR NOTA INTERIOR PERMUTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELESTINO'and edp.apellido1='NAVARRETE'and apellido2='MURGA'),'2021-08-18','Belén. Se llama al SSB de Jerez de los Caballeros solicitando el informe social para el inventario porque ha pasado más de un mes desde la petición inicial. Me informan que la compañera que lleva el caso está de vacaciones, pero lo enviarán la semana que viene. Intentarán adelantarlo por correo electrónico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CANSADO'and apellido2='LAGAR'),'2021-09-29','ARCHIVO EXPTE. Mediante Auto n.º 13/21, de 19 de enero, dictado por el Jzdo. de 1.ª Inst.e Inst. n.º 4 de Baadajoz. Según refiere el mismo, fue la propia fiscalia quien solicitó el desistimiento en la vista del proceso de incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2021-09-29','Ana: Remito a Fátima, Ed. Asoc. Vera (educadorasocial@asociacionvera.com), la Autorización para la conviviencia de los JEDES en Barcarrota firmada digitalmente por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-29','Ana: Llamo a Nuria, MAP Centro de Salud Valencia de Alcántara (54208 // nuria.diaz@salud-juntaex.es): La enfermera ha realizado la PCR a Manuela a primera hora. ···· Me envía la Historia Clínica Resumida. ·············· Conversación con Tamara, TS Res. Geryvida-CC (927 101 800): le informo sobre la situación de Manuela. *Le envío por correo-e (trabajosocial@geryvida.com): Historia clínica resumida, testimonio de sentencia de incapacitación y nombramiento, testimonio de aceptación del cargo y Autorización Judicial de Internamiento. ··············· Comunico a Plácido que ya se la ha realizado PCR a Manuela y que también he contactado ya con la residencia Geryvida. ························· Hablo con Toni-Futuex: Confirma que mañana acudirán Gloria y Virginia, ambas Ed., a las 10:30h a casa de Manuela, intentarán colaborar para coger la cosas de Manuela, si José Manuel no lo impide. *Especifico que lo principal es la medicación y la silla de ruedas. ·········································· **Envío mail con "Fax" al 112 (112@juntaex.es) para solicitar el traslado de Manuela al C.R. Geryvida mañana, adjuntando toda la documentación pertinente. ·············· Llamo al 112 (924 31 02 04), hablo con Fernando, Jefe de Sala. Explico la situación y él revisa todo lo enviado por mail. Confirma que todo está OK, lo comunicarán a la Guardia Civil y al Centro de Salud. *Especifico la necesidad de la Ambulancia con Soporte Vital Básico. ·················································· Recibo correo de Geryvida con la información sobre el abono de la plaza (que remito a Alberto, Jefe secc. ecca.) y autorización 3ª dosis vacuna Covid así como el Reglamento de Régimen Interno. **Pongo estos dos últimos para la firma del D.Gerente. ···················· Recibo llamada de Nuria, MAP (54208): me informa que José Manuel Correa ha acudido al C. Salud solicitando a la administrativa la ayuda del Celador para movilizar a Manuela, según le ha dicho, ha hablado con su abogado y procurador y "se va a paralizar el ingreso". Va a trasladar a Manuela a un piso que ha alquilado en la misma calle. *La administrativo le ha dicho que el celador estaba muy ocupado y no podía acudir. Por lo que ha establecido que lo hará entonces con la Auxiliar. **Nuria mira en Google-Map y por las indicaciones que ha dado ("un bloque de pisos") debe ser el nº 19 de la C/ Extremadura, pero no sabe si el A o el B. ··········· Lo comunico por teléfono a Fernando, Jefe de Sala del 112. ············· Lo comunico igualmente a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-09-29','miguel, me llega email de la inmobiliaria: Buenos días Miguel para poder firmar la escritura en la Notaria de Montijo el próximo día 8 de octubre, la entidad financiera Caja Rural de Almendralejo (financian a la compradora) nos pide la siguiente documentación: -DNI Y PODERES DE LA PERSONA QUE VA A REPRESENTAR EN LA FIRMA AL VENDEDOR. -CERTIFICADO AL DÍA 8 DE OCTUBRE DEL PRESTAMO PENDIENTE DE CANCELAR. -NUMERO DE CUENTA DONDE CAJA RURAL DE ALMENDRALEJO TIENE QUE HACER EL PAGO DE LA CANCELACIÓN DE LA HIPOTECA EXITENTE, LO HARAN VIA BANCO DE ESPAÑA. Quedo a la espera. *********************************Tras conversación telefónica con Emiliano confirmando lo mismo que el email, comentamos lo de la solicitud de certificado de nacimiento al registro civil de Don Benito y me comenta que lo va a pedir él también a través del de Montijo. *************************************** Remito email a la parte económica y social (Tere): Buenos días, en relación a la venta del inmueble de Juan Carlos Rubio, os adjunto el email que solicita la inmobiliaria. Se quiere firmar el día 8/10/21 con lo que solicita dos cosas: -Certificado de saldo bancario (de la hipoteca) a fecha de la firma, es decir 8-10-21 . También se necesita nº de cuenta al cual Caja Rural de Almendralejo hará la transferencia, para la cancelación económica total, que se hará vía banco de España (OMF) -El Certificado de nacimiento que nos pide la notaria (donde figure en la inscripción marginal el nombramiento de la Comisión Tutelar de Adultos) espero que llegue antes de esa fecha. Lo he solicitado al Registro civil de Don Benito y el de la Inmobiliaria también lo intentará conseguir por su cuenta. -Persona que asistirá a la firma seré yo, mediante autorización (como siempre hacemos). Por tanto parte económica necesito: -Certificado de saldo pendiente (que incluya todo: principal, intereses, comisión por cancelación anticipada) y número de cuenta al que hacer la transferencia para cancelar la hipoteca. Preguntad al banco cómo harán para cancelar la deuda registralmente. Parte Social: Cuando nos confirmen si finalmente se firma el día 8-10-21, Tere tendrás que avisar que Juan Carlos tendrá que ir a firmar a la notaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-09-29','miguel,recibo email de Amelia (tía de los tutelados): Buenos días, Miguel, respecto a la herencia de Raul y Sergio Gil Sanz, la notaria me pide la siguiente documentación, respecto a las gestiones realizadas, te comento: -Los testamentos son copias simples, hay que pedir copias autorizadas, me dicen que tienen que pedirlas herederos de los fallecidos, también para recoger las mismas, el tfno. De contacto de la notaria de Brihuega es 949 280270 he hablado con Mönica y el correo es documentación@notariabrihuega.es -CERTIFICADO ULTIMAS VOLUNTADES TERESA, por algún motivo no lo tengo en mi poder, vuelvo a contactar con el banco para que me mande una copia, ya que lo entregaría con el resto de documentación. -TITULOS DE PROPIEDAD Y RECIBOS DE CONTRIBUCIÓN. Se lo aportaré yo con la documentación que tengo y el IBI ultimo lo pediré al banco -CERTIFICADO CUENTAS BANCARIAS, se lo proporciono yo La notaria de Guadalajara que está gestionando la escritura de aceptación de herencia es la de JIMENA DEL CASTILLO RODRIGUEZ, paseo Fdez Iparraguirre, 3 1ºD.19002 Guadalajara Tfno 949 248079 Contacto Ana Sepulveda: aisepulveda@despacho.notariado.org ****************************************************** contestación a Amelia (tía de los tutelados): Buenos días Amelia, debido a la distancia, se nos ocurre que podríamos hacerte una Autorización para realizar esos trámites, si te parece bien (o a una asesoría de confianza) Si me indicas de los testamentos que hay que solicitar notario, nº de protocolo, fecha de firma te hacemos una autorización (previo nos enviaras tus datos o dni) para que o bien te entreguen a ti el original o bien para que puedas solicitarlo y que lo remitan la copia autorizada original vía telemática a la notaria donde se firmará la adjudicación de herencia. Si finalmente te las entregan físicamente (y no las remitieran vía electrónica a la otra notaria donde se vaya a firmar la adjudicación de herencia)tendrías que entregárselas a dicha notaria donde se vaya a firmar la herencia. En cuanto a lo que haya que ir abonando necesitaría que nos remitieran vía email a ctutelar@salud-juntaex.es dichas facturas Cualquier duda dímelo.','2');
