insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-09-29','miguel, Emiliano de la inmobiliaria me remitirá el Certificado de Nacimiento por email ya que lo ha podido conseguir directamente en el registro civil. Por tanto sólo queda por conseguir el certificado de deuda del banco','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2021-09-29','Ana: Llamada de Mari,Directora de la Res. de Malpartida de Plas. (927 830 203): han recibido la Sentencia de Incapacitación de Antonia. *Le indico que aún no es firme. Una vez recibido el Testimonio de la Firmeza en la CTAEX se procederá a la aceptación y de oficio se comenzará a solicitar/recabar los documentos pertinentes (Informe Social, Cdo. Pensiones, Cdo. Discapacidad, Datos Bancarios...)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2021-09-29','miguel, nuevo email de Amelia: Buenos días, Miguel, en cuanto a la Autorización, tal vez sea lo más rápido para realizar las gestiones para todas las partes, desconozco qué será más adecuado si asesoría de confianza o autorización, lo que vosotros consideréis oportuno. Mis datos son: Amelia Rodrigo Sanz con DNI 03091440X domiciliada en Calle Ferial, 1 1ºA.19002 Guadalajara, mi tfno. Es 628 581 997 Mis tios otorgaron testamento el 14 de abril de 1998 en la notaria de Brihuega con protocolos 229 y 230 dando fe la notaria Alicia Velarde Valiente. Seguimos en contacto y yo a la espera de documentación del banco. Saludos ********************************* Mi contestación: Perfecto, te preparo una autorización y en un par de días te la remito por esta vía y por carta certificada te remitiré el original. En cuanto al certificado de últimas voluntades la notaria que haga la adjudicación de herencia puede pedir directamente vía telemática la misma para lo cual cuando tengas la escritura de testamento original podrás llevársela a ellos para que lo pidan. Sí que tenemos el certificado de últimas voluntades del padre Máximo Gil García, y que te vale porque contiene al final del documento el Código de seguro de verificación (lo que significa la firma electrónica, que equivale a un original). Te lo adjunto junto a su seguro de vida, para se lo remitas a la notaria.','2');
