insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-09-29','miguel, me llega email de la Abogada de la exnuera Mercedes: Buenos días Miguel, he estado intentando contactar contigo estos días y no he podido (comunica a veces y otras no me cogéis) . Te envío la instancia que he realizado para Mercedes, la de Alfonsa sería similar. A ver si me puedes llamar tu al teléfono 985170250 ***************************************** mi contestación: Buenas tardes, mañana te llamo sin falta y comentamos lo que me remites que en principio entiendo que no hace falta que lo remitamos nosotros también, ya que al tratarse del mismo expediente de oficio la oficina liquidadora tendría que modificar el cálculo del impuesto de sucesiones y remitirlo a ambas (Mercedes y Alfonsa), anulando la liquidación que nos remitió. A ver si por fin mañana logramos hablar.','2');
