insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-09-29','Ana: Recibimos el documento de pago de reclamación de deuda por cobros indebidos (cambio de PNC a P. Viudedad)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-09-30','Maite: La tutela de Marta es firme por sentencia 77/2021 de 14 de septiembre. Marta se encontraba en el centro de menores  Pedro de Valdivia de Villanueva de la Serena desde el año 2020. El 22 de enero de 2021, desde la Dirección General de de Servicios Sociales, Infancia y Familias, se solicita su incapacitación. ASisitia al CEE de INCLUSIVES. Al cumplir la mayoria de edad, el 29 de julio de 2021, sale del centro de menoroes regresando a su domicilio familiar en Cabeza del Buey. Marta estaba en lista de espera por decreto para centro de atención a personas con discapacidad. Pedimos que agilizaran la revisión PIA para que adelantase puestos en lista de espera. Se va a valorar como situación de emergencia para asignarle un centro lo antes posible. Estamos en contacto con el centro de educación especial de INCLUSIVES , que tiene buena rerlación con élla y siguen manteniendo contacto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2021-09-30','Ana: Recibimos escrito de PNC solicitando aportemos en el plazo de 10 días: Nº de cuenta a nombre del titular y del representante legal y Alta de tercero. *Se lo paso a Alberto, jefe secc. ecca.','2');
