insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='NARANJO'and apellido2='LUENGO'),'2021-09-30','miguel, me llega contestación del Ayuntamiento de Valencia de Alcantara de Manuel Sequeda: En contestación a tus preguntas, te informo: . La vivienda se derribó totalmente . La referencia catastral es 5366313TH6358N0001JR . Con respecto a la finca registral, que estaba y está actualmente catastrada a nombre de Herederos de Dª Manuela Luengo Martín, el Ayuntamiento solicitó Nota Simple informativa, contestando el Registro de la Propiedad de Llerena que la finca sita en C/ Divino Morales 43, de Azuaga, no aparecía inscrita a nombre de la interesada ni al de ninguna otra persona. . Con respecto a los certificados de defunción y DNI de los padres y hermana de Dª Josefa Naranjo Luengo, no disponemos de esos datos. El único DNI que aparece en la fica catastral de la finca es el de Dª Manuela Luengo Martín (08295646Y) ********************************************************* Envío email a Tere y Alberto: Buenas tardes, os adjunto los emails que he intercambiado con el Ayuntamiento de Azuaga. Al ser la única heredera y tener que hacerse cargo de los gastos de la vivienda tendréis que pedir al menos dos presupuestos y hablar con la vecina una vez que lo tengáis y arreglarlo. Si el importe es alto habría que pedir autorización judicial por gastos extraordinarios. Si queréis cuando tengáis dichos presupuestos nos reunimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-09-30','Ana: Recibimos escrito del Serv. de Prestaciones Sociales: "La solicitud de PNC ha tenido entrada con fecha de 22/09/21"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='NARANJO'and apellido2='LUENGO'),'2021-09-30','miguel, reenvío el email del Ayto de Azuaga a Alberto y Tere: Buenos días, os reenvío email que me remiten desde el Ayuntamiento de Azuaga donde nos requieren para el arreglo de la casa, parece ser conforme la queja de la vecina que lo que quede de la casa derruida le provoca humedades por lo que habría que pedir un par de presupuestos para el arreglo del mismo. No se va a poder hacer la herencia, pues no tienen documentación de testamentaria de sus padres y hermano (certificado de defunción, últimas voluntades, etc) Por tanto si os parece bien, me limitaría a hacernos cargos de los desperfectos que nos vayan comunicando que hay que ir arreglando, ya que según la última rendición de cuentas tiene más de 40.000€ Ya me decís.','2');
