insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-09-30','Ángel: La Dirección General de Infancia y Familia, REVOCA la inadmisión de la solicitud presentada por Ana María, de Renta Extremeña Garantizada, una vez que presentamos el Recurso de Alzada y por lo tanto, continúa la tramitación de su solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2021-09-30','TERESA RECIBO LLAMADA DEL CENTRO EN EL QUE NOS COMUNICA QUE NO TIENE DNI QUE ESTAN PENDIETE DE CITA PARA HACERLO NO PODEMOS GESTIONAR LA PESNION PORQUE NO PODEMOS ABRIRLE CUENTA HAY QUE MANDAR NUMERO DE CUENTA A PNC CUANDO LO TENGAMOS EMAIL PNC: Buenas tardes, resuelto ya el problema principal de la tutoría, solo recordaros que necesitamos una cuenta bancaria y alta de terceros para poder abonarle la pensión no contributiva. Ref: EXPEDIENTE PNC 355/I/20 CARLOS MARIA GRANDE VICARIO esthermaria.lopez@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2021-09-30','TERESA RECIBO EMAIL DE MERCEDES DE CARITAS Buenas tardes Teresa: Después de estos meses de verano, creo que es bueno que te pongamos un poco al día del caso de Tomás: Sigue en el piso de alquiler, ayer lunes, estuve con él y por lo que cuenta está bastante contento y adaptado tanto a la nueva zona como a los compañeros y el piso. Cada 15 días, más o menos nos vemos para hacer actualizar la administración económica y entregarle el dinero que necesite. De momento se administra bien, nunca ha sido una persona que gastase en exceso y sigue en la misma línea. A principios de mes sigue entregándonos todo el dinero que saca del banco. Durante el verano retomó la relación con Mª Ángeles y de momento continúan juntos, ella ya ha comenzado las clases en el Colegio de la Luz y ha salido de él buscar actividades para estar entretenido y haciendo algo y no tener todo el día ocioso. De momento se ha acercado al Hernán Cortes por las sesiones de cine, a la parroquia de Suerte de Saavedra por los talleres en los que ha participado otros años, pero aún no han comenzado. Con los compañeros está muy a gusto, a Manuel lo conocía de nuestro piso y con Alfredo los dos encantados él uno con el otro. En la casa se repartieron las tareas y cada uno es responsable con lo que le corresponde. La zona le gusta porque se encuentra más cerca de la biblioteca pública, de casa de Mª Ángeles, etc. Por otro lado, me gustaría preguntarte cómo le influye a Tomás el cambio de la normativa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-09-30','miguel, me remite el certificado de deuda la oficina de Guadiana del Caudillo: Buenas tardes. En la tercera página del documento enviado anteriormente están los datos completos de la cuenta. El concepto de la transferencia CANCELACION PRESTAMO 645060030000137001044. No obstante, os rogaría que me lo solicitarías por correo; aunque ya lo estáis comentando. El certificado lo adjto. Y efectivamente, por el funcionamiento de este tipo de préstamo, sería conveniente enviar la cantidad que indicáis. Saludos. **************************************************** Envío email a la inmobiliaria y a notaria de Montijo (con copia a Alberto e Iciar) con las instrucciones de la venta: Buenos días os adjunto certificado de deuda de la hipoteca de la compraventa de la c/ El Hinojo nº4 que se quiere firmar el viernes 8-10-2021 (ya nos decís hora) El número de cuenta al que hacer el ingreso de la deuda pendiente de la Hipoteca de Ibercaja es (según el email de más debajo de la oficina la cuenta del curatelado, es decir la página 3 del documento que os adjunto): ES 84-2085-4507-98-0330362042. El concepto a poner en dicha transferencia es: El concepto de la transferencia CANCELACION PRESTAMO 645060030000137001044. La parte compradora en el momento de hacer la transferencia vía banco de España, deberán llamar a la oficina para que procedan inmediatamente a la cancelación económica total del préstamo hipotecario. Debido a los posibles intereses y demás la parte compradora debería retener unos 32.900€+la provisión para la cancelación registral+gastos según ley+honorarios de la inmobiliaria. El sobrante también habrá de hacer transferencia la parte compradora a la cuenta de Juan Carlos Rubio Galán, es decir, al nº ES84 2085 4507 9803 3036 2042, indicando en el Concepto: Sobrante de la venta c/ El Hinojo nº4.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-09-30','Ana: Correo de Julian Álvarez - COCEMFE (gerencia@cocemfecaceres.org): "Hola Ana. Estamos pendientes de evolución, en principio está con antibiótico por vena y esperan que para el sábado o principios de la semana que viene salga del hospital. Nosotros hemos diseñado un cuadrante para que de 14.00 a 21.00 horas esté acompañado por personal cuidador de residencia. También hemos estado acompañando el día del ingreso lunes de 18.00 a 24.00. Además por las mañanas irá un cuidador al hospital de 12.00 a 13.30 para recabar información de los médicos sobre la evolución (lo asume COCEMFE) Te envío el cuadrante mañana con todas las horas. Te voy informando de posibles novedades"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-09-30','Ana: Se procede al ingreso de Manuela en el CR Geryvida. Acompañan Gloria y Virgina, Ed. Futuex e interviene la Guardia Civil. ···················· *Trato con Alberto las gesiones eccas. (Correos) ···························· Llamo a Amelia, Servicios del Fresno (924 677 705) y comunico la baja en el servicio de Manuela por ingreso en C. Residencial. ··············· Envío a Julio, Aux. CTAEX, - Oficio - Solicitud de baja de la prestación vinculada al servicio de ayuda a domicilio concedida por la ley de dependencia, para que lo registre. ······················································· Envío a Tamara, TS Geryvida, C.I. para 3ª dosis de la vacuna Covid.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-01','miguel, tras preguntar a Alberto y a Iciar, y teniendo en cuenta que la cuenta de Ibercaja está el curatelado de cotitular con su madre, es mejor hacer la transferencia de la venta de la c/hinojo en la otra cuenta, en la de la Caja Rural de Extremadura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-01','miguel, me llega email de Emiliano de la notaria: Buenas tardes Miguel Angel, hemos reservado la hora de firma las 10:00 el día 8 me dice Jacinto el oficial de la Notaria que le tienes que mandar a el, la autorización tuya para firmar tu la venta. Y os tenéis que traer todos los originales de los nombramientos de tutor que tenéis. Del precio de venta también descontaremos la cantidad de 1.996,50 Euros de nuestros honorarios (1.500 honorarios + 150 certificado energético= total 1.650euros + 21% de iva 346,50euros igual a 1.996,50 euros) tal y como me dijiste que lo hiciéramos. ************************************** Remito email a Jacinto y Emiliano: Disculpad veo que la hora de la firma es a las 10h viernes 8-10-21. Necesitaré que a lo largo de la semana que viene Jacinto me remitas el borrador. Te mandaré martes o miércoles mi autorización para firmar la operación, y llevaré los originales (testimonio de nombramiento, etc)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='NARANJO'and apellido2='LUENGO'),'2021-10-01','Buenos días , Josefa Naranjo se encuentra en el CSS de Mérida . Es para una intervención puntual . Tiene una vivienda en Azuaga que está causando daños a una vecina . El tf. de Belinda aparece en su escrito de solicitud. Me puse en contacto con ella para que pidiese un presupuesto , va a reformar su vivienda y a ese mismo albañil le ha pedido presupuesto . Por favor , contactad con ella para ir a recoger el presupuesto y ver la vivienda in situ . No sabemos dónde pueden estar las llaves de esa vivienda , podéis preguntar si están en el CSS si no habrá que avisar a un cerrajero . El jurídico pide 2 presupuestos , a ver si podéis pedir otro más . Seguimos en contacto . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DARIO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2021-10-01','Maite: con fecha 29/09/2021 firmamos renuncia al servicio de centro ocupacional, porque va a realizar un módulo de formación. Le he enviado la renuncia por mail a Fátima, trabajdora social del CO INCLUSIVES. Tb se la paso a la unidad de programas asistenciales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-10-01','Amalia : Manuel , psicolo de PS envia email : os comunico el alta de Beatriz Mejias de la Morena con fecha de hoy. Esta usuaria está tutelada por CTAEX y ha residido en el PS de Mérida. Os mando todos los documentos. También os informo que se marcha de este recurso con un objetivo positivo: va con su familia y después a un piso de alquiler. Recibirá ayuda de FUTUEX y CRPS. Gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-10-01','Amalia : envio email a Manuel : recibido todo , muchas gracias . Queda pendiente el envío del presupuesto . No es necesario que en el dinero que se le da de reintegro se especifique si es para alimentación, tabaco.. se le calcula un total y ella tendrá que distribuirlo. He hablado con ella y le he dado una orientación sobre lo que puede gastar . Estos primeros días tiene con los 114 € que lleva para cubrir sus gastos . Un saludo . ----------------------------------------------------- FUTUEX : notifico continuar seguimiento .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2021-10-01','TERESA ENVIO CONSENTIMIENTO INFORMADO POR EMAIL PARA TRATAMIEENTO HIPETIROIDISMO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-10-01','miguel, firmo en notaria la ratificación de la compraventa de la vivienda de Azkoitia. Protocolo 1215 del notario Fco de Borja Igartua Fesser. Compraventa hecha en notaria de Azkoitia ante la notaria Iciar Fernández Zornoza hoy 1-10-21 con protocolo 840','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='DIAZ'and apellido2='ROMERO'),'2021-10-01','Buenas Eva , el cargo ha sido aceptado el día 28 de septiembre , por lo tanto ya somos tutores . Empezamos la fase inventario , no tenemos ninguna información de este chico . Si está en vuestro centro necesitamos que nos reenviéis toda la información de la que dispongáis : DNI Tarjeta sanitaria Prestaciones que percibe y Nº Cuenta . Seguro decesos... Informe social Informes de menores , técnico de referencia para contactar con ellos . Una vez que tengamos elaborado y aprobado el inventario nos pondremos a intervenir en este caso . Desconocemos la información sobre las visitas con la madre , ésto tendrías que preguntarlo a menores. Un saludo . Icíar te pongo en copia por si estás tú haciendo inventario , para que tengas esta información. Eva Álvarez >trabajadorasocialco@plenainclusionmontijo.org> Jue 30/09/2021 14:10 Buenas tardes Amalia. Tenemos a un chico que estaba tutelado por menores hasta hace unos meses que cumplió los 18 años, Alberto Díaz Romero. Se celebró la vista y se nombró a CTAEX como tutores, pero mientras se jura el cargo ha asumido la guada de hecho por parte de la presidenta de Plena Inclusión Montijo. Cuando estaba en menores tenía visitas esporádicas con su madre, pero ahora no sabemos cómo hay que hacerlas, si hay algún documento que diga como las tenemos que gestionar y demás. Ya me decís lo que sea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2021-10-01','TERESA ENVIO PETICION DE INFORME SOCIAL PARA VALORAR REMOCION A JUANA MARTIN ROMERO JEFA SECCION SERVICIOS SOCIALES MERIDA SERVICIOSSOCIALES@MERIDA.ES 619142167','2');
