insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-10-01','Ana: Remito a la Dra. Martín Mata, Traumatóloga HSPA (mariajose.martin@salud-juntaex.es // 56691), CI para cirugía (fractura de cadera), anestesia general y anestesia locoregional. ···················· Conversación también con el Dr. Fernández - Anestesista (56440). *Se interesa por la situación familiar y legal de Valentina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2021-10-01','-Amalia : Pongo en firma la renuncia de la VT . Pido a Alberto que suba la asignacion económica mensual . Quedo pte. revisar PIa y solicitar CO Proserpina.','2');
