insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2021-09-29','-Amalia y Mayte , hacemos visita a domicilio para apoyar a que acepte la plaza de VT de MOntijo adjudicada . Se niega , quiere CO Proserpina , quiere seguir viviendo con su madre. Pepi ( madre ) nos cuenta que la relación con la familia paterna ha desaparecido y tampoco se habla con la mujer de su hno. JOrge. Percibe 570€ viudedad . No paga agua y luz , dice que " sus vecinos " tampoco lo hacen y que todos están enganchados a la luz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-01','Ana: Conversación con Tamara, TS CR Geryvida (927 101 800): Manuela ha pasado bien la noche. Hoy le han aseado bien (no presentaba adecuda higiene), le han cortado las uñas, lavado el pelo, peinado, y le han puesto algo de ropa del centro (pantalón y blusa). *Lo malo es que apenas está comiendo. De continuar así consultarán al médico. ······· El nieto, José Manuel, acudió ayer pasadas las 15 h. Llevó poca ropa y el colchón antiescaras. Le han solicitado que lleve la silla de ruedas y otras prendas de vestir, pues lo poco que ha llevado es de verano. **Le han enviado un correo electrónico tal y como ha pedido él al llamarle por teléfono. *Nos envían copia. Guardo en el expte. ························· Tamara me remite documento de protección de datos de carácter personal que reenvío a los A. Jurídicos para que lo revisen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-10-04','miguel, remito email a la abogada y a la hermana ,Inés, del tutelado: Buenos días, la ratificación de la compraventa la hicimos el viernes día 1-10-21 y se remitió a la notaria de Azkoitia telemáticamente por la notaria de Mérida. Hemos comprobado que se entregó cheque (en vez de transferencia) para el pago de José Luis, en vez de transferencia conforme indicamos. Necesitamos nos confirméis en qué cuenta se ha hecho el ingreso del cheque a nombre del tutelado José Luis Murillo Horrillo. El dinero debe ser ingresado en la cuenta que comenté en el email anterior: Liberbank ES 72-2048-1001-93-3000163718 de titularidad del tutelado. Por otra parte, de la parte de señal 7.000€ la parte correspondiente a José Luis, nos tenéis que acreditar los gastos que se le descuenten, ya que de todo hay que dar parte al juzgado. Un saludo.','2');
