insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2021-10-04','TERESA RECIBO LLAMADA DE ROSA DEL FUENTE DE CANTOS Y ME COMUNICA QUE HOY INTERVIENEN A RAMON DE UNA HERNIA NECESITARA REPOSO DESPUES DE LA INTERVENCION,ME PIDE QUE GESTIONES UNA PLAZA SOCIOSANITARIA YA QUE EL RESPOSO EN EL CENTRO ES COMPLICADO QUE LO HAGA DEBIDO A SU PATOLOGIA MENTAL HALBO CON ISABLE TS DEL HOSPITAL DE LLERENA 47085, ESTA INFORMADA DE LA SITUACION . LO VAN A DERIVAR A RIVERA SALUD ALMENDRALEJO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-04','Ana: En relación al correo recibido en el ctutelar@ de Pablo Correa, nieto de Manuela, envío correo a Tamara, TS de la Res. (trabajosocial@geryvida.com): "Buenos días Tamara, Como ya comentamos mediante conversación telefónica, desde la CTAEX no hay inconveniente en que ninguno de los nietos y biznietos de MANUELA MORATO PICADO acuda a visitarla. Agradecería que los comuniques en el centro a quien corresponda, pues hemos recibido correo de Pablo Correa Morato, otro de los nietos, diciendo que ha llamado a la Residencia para pedir cita para visitar a su abuela y le han dicho que tenemos que ser nosotros quiénes pidamos cita u organicemos dichas vistas. Entiendo que las visitas tenéis que organizarlas desde ahí conforme los protocolos correspondientes. Espero que Manuela se esté adaptando bien y siga estable, ya me informas cuando puedas. Gracias de nuevo y buen día." ···························· Respuesta de Tamara: "Ana, ya me he enterado de todo, la familia ha debido liarse, desde el centro lo que se le ha dicho es que ahora está una semana en aislamiento y que luego ya podrán visitarla reservando la visita, de hecho ya tiene una visita reservada. También se le ha dicho que no se le van a informar de temas médicos que al estar incapacitada se le comunica al tutor en este caso a la Comisión tutelar. Por otro lado esta mañana tenía 6 email del nieto con el que convivía, me ha mandado incluso una foto de lo que trae, he pedido que lo revisen por si falta algo, el sábado trajo sus cosas. No ten reenvío los correos porque igual te saturo. En otro me ha mandado un informe de alta del hospital. Por ahora todo va bien, te iré contando. Un saludo, Tamara." ········································································· Paso a Julio, CTAEX, oficio y Reglamento de Régimen Interiror de la Residencia, debidamente firmado y sellado, para registralo y remitirlo por correo certificado a Geryvida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-10-04','miguel, me dan cita para acompañarme a hacer un poder apud acta con el Gerente el miercoles 6-10-21 a 10h. Envío email al juzgado de Mérida nº1 para solicitarlo: Buenos días, necesitamos nos concedan cita el día 6-10-21 a las 10h para otorgar poder al letrado y procuradora: Jorge Calvo Onsurbe, colegiado ICABA, 3397 y Procuradora: Cristina Soto Ruiz, colegiada ICProcuradores Badajoz, 393. DNI 33987993L para que puedan solicitar en nombre de la tutelada Doña Maria del Carmen Leal Benito con dni 15237059I al Tribunal Superior de Justicia que nombren los árbitros para un procedimiento de desahucio que será sometido ante dicha instancia de arbitraje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-10-04','Ana: Llamada de Mamen, TS HSPA (56283): Martín sigue ingresado y ha manifestado querer ingresar, de forma temporal, en una residencia al alta hospitalaria. Mamen me pregunta por las posibilidades económica (P. Incapacidad Permanente Absoluta: 911,13€/mes x 14). *No está valorado por el CADEX y por Dependencia dio un "sin grado" en 2013. Solicitarán ambas cosas. No obstante, la plaza a la que opte en un incio tendrá que ser privada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-10-04','Ana: Llamada de Omar Novilla, Traumatólogo HUC (56083): La intervención quirúrgica de Valentina ha ido bien. Le han puesto una prótesis parcial de cadera. Hoy le harán una radiografía de control y una analítica para asegurarse que no ha perdido mucha sangre. Si todo sigue igual de bien, probablemente a finales de semana le darán el alta. ···························· Informo mediante mail a la Residencia Femar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-10-04','miguel, recibo email de la abogada Ana de Pablo: Buenos días Miguel Angel, efectivamente se entregaron cuatro cheques nominativos a nombre de cada hermano. Se ingresaron los tres cheques de Mª José, Inés y Ander en la cuenta bancaria que los tres abrieron tras el fallecimiento de la madre para gestionar todas las cuestiones relativas a la herencia. El cheque a nombre de José Luis no se pudo ingresar lógicamente por ser nominativo y no figurar José Luis como titular de dicha cuenta, por lo que no se pudo ingresar en ella y después hacer la transferencia a ustedes, que era lo que en principio pensábamos hacer. Sólo el representante legal de José Luis Murillo puede ingresar el cheque nominativo en la cuenta de la que sea titular. Por lo que no tengo más remedio que enviarle el cheque por correo certificado para que usted firme en el reverso y lo ingrese en la cuenta. Verá que aparece en el reverso una firma, es la de su hermana Mª José que firmó para ingresarlo en la cuneta de los hermanos. Respecto a los 7.000€ recibidos a la firma del contrato de Arras, le enviaré los movimientos de la cuenta y una liquidación de los ingresos y gastos realizados hasta la fecha, y el resultado de dicha liquidación le será transferido a la cuenta que usted indica. Confírmeme que el envío lo hago a esta dirección: A la atención de M. A. Fernández de Llera. Comisión Tutelar de Adultos de la Junta de Extremadura (SEPAD) Avda. de las Américas Nº 4 06800. Mérida. Badajoz Quedando a la espera de su respuesta, reciba un cordial saludo ******************************************************* Tras consultar con la parte económica Alberto e Iciar vemos que ese cheque es nulo por estar ya firmado. Envío el siguiente email a Ana de Pablo (la abogada): Ana, ese cheque es nulo, no nos lo pueden enviar así. Tienen que hablar con el comprador y acercarse con él a que hagan uno que no esté firmado ya que sino la entidad no nos autorizará a ingresarlo en su cuenta. Otra opción es que el comprador lo anule y haga la transferencia a la cuenta que les indiqué (de esta forma evitaríamos que se pierda y que cobren comisión al tutelado). Caso que envíen el cheque (nuevo) remítanlo por mensajería para que no se pierda.','2');
