insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-10-01','Ana: Correo-resumen de Alberto, Jefe secc. ecca., en cuanto al FONDO DE INVERSIÓN que tienen Felisa y su hermana: "TOD@S: LA SOLUCIÓN DE ESTA CUESTIÓN VA A LLEVAR TIEMPO DADA LA SITUACIÓN DE PERSONAL EXISTENTE Y QUE HAN DE PONERSE DE ACUERDO MUCHS PARTES: BANCO-INTERESADOS-DIRECTOR GERENTE. ICIAR: Comienzo con la secuencia: • Ana/Miguel reciben lladmada de José Teomiro (644 70 47 12) - sobrino de Felisa Felipe Teomiro (Tutelada por la CTAEX): o Felisa (tutelada) y su hermana JOSEFA (madre de José) tiene el FONDO DE INVERSIÓN a medias o Josefa (hermana tutelada) quiere rescatar ese dinero y disponer de su parte. o La CTAEX no tiene inconveniente a proceder a la RECUPERACIÓN del FONDO DE INVERSIÓN y que se ingreso la parte correspondiente en la CCC tutelada. • Miguel habló con JUANA HERAS (LIBERBANK), que a su vez se puso en contacto con oficina correspondiente, que a su vez nos comunicó lo siguiente: "Al ser el fondo un contrato mancomunado, necesitamos que estén todos los titulares presentes para efectuar el reembolso. Como una de las clientas está tutelada por la Junta, necesitaríamos orden por parte del tutor para realizarlo." • OPERATIVA: o Iciar: hay que hablar con sobrino e indicarle que NO hay inconveniente x parte de la CTAEX en cuanto a la recuperación del FONDO DE INVERSIÓN. o Miguel: entiendo que a nuestra tutelada le corresponde el 50 % del total del fondo. Confírmamelo xfavor (tienes los datos del fondo, como me habías pedido, en expediente online) o Iciar: Intentamos trasladarle la LOGÍSTICA de las firmas presenciales al sobrino de la tutelada, haciéndole ver que Gerente debe firmar en Mérida (si es posible). o Iciar: habla con Juana Heras u oficina para ver si hay forma de obviar la presencialidad del tutor a través de alguna vía. Habla con ella también sobre la LOGÍSTICA (papeles necesarios, solicitudes (de ambas partes???)...)"','2');
