insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2021-10-05','email del CTro . penitenciario , finalmente no va a aceptar el contrato : Buenas tardes Amalia. Te envié un email diciéndote que finalmente Cristofer ha renunciado al contrato y le han dado de baja, para que paralizaras la comunicación a PNC. Fue justo al día siguiente de enviarte el contrato. He hablado con él y dice que se precipitó, pero que se ha dado cuenta que no quiere desempeñarlo, así que si hay próxima ocasión os enviaremos previamente el contrato. Muchas gracias y un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2021-10-05','Ana: Correo de Ángela Bueno: "Buenos dias Ana te adjunto estos documentos de la Fexddi que son necesarios para la participación de Mª Rosa Iglesias Calzas en la actividad de eliminatorias previas de los jedes de este año, que es el 15 de octubre. Un saludo" ··········· Cumplimento y subo ambos documentos (Anexo I y IV) al portafirmas digital. ·········· Envío a Ángela por mail ambos documentos ya firmados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-09-30','Ana: Correo de Paula, TO CRR-Plas: "Buenos días Ana, te reenvío el correo de Ceferino con la información acerca de la Editorial que le ha ofrecido realizar la autopublicación de su novela. Como te decía nos parecía muy importante. De primeras la opción que se había barajado era la de hacer 50 ejemplares (unos 350-375 Euros si no recuerdo mal). Si lo veis posible él os enviará los documentos para solicitarlo. La verdad es que está activo, se ha apuntado al curso de Italiano en la escuela de idiomas y tratamos de apoyar su iniciativa y su esfuerzo en mantener tanto las actividades de escritura como de música (mezcla). Espero vuestra respuesta, un saludo. Paula."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-10-04','Ana: Tras valorarlo con Alberto, jefe secc. ecca., se autoriza la Autoedición de su novela (presupuesto máx. establecido 400€). *Se lo comunico telefónicamente tanto a Paula como a Ceferino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-05','TERESABuenas tardes El próximo viernes día 8 se va a proceder a la firma para la venta de la vivienda propiedad de Don Juna Carlos Rubio Galán en la notaria de Montijo, la dirección es Notaria Sara De Soto Cardenal C/ Eduardo Núñez 4 Montijo Telf.: 924 45 30 00 Juan Carlos tiene que estar allí a las 9:45 horas, allí le espera mi compañero Miguel. Debe llevar el DNI. Para el desplazamiento contratar taxi, la forma de pago es mediante transferencia bancaria presentado factura (que indique en la factura el número de cuenta) Para el acompañamiento presentar declaración jurada en la que conste el tiempo empleado en el acompañamiento así como el desglose del precio por hora y el importe total. Incluir número de cuenta par hacer el pago por transferencia Me lo puedes hacer llegar a esta dirección de correo','2');
