insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MORENO'and apellido2='MOVILLA'),'2021-10-05','miguel, nos reenvía Amalia el email de Aprosuba 3: Buenos días: Pedro dice que quiere saber cuánto dinero tiene ahorrado. También sigue demandando hacer testamento. Eso es posible? ************************************* Tras leer Angel y yo la sentencia y ver que expresamente no se le prohibe testar, contesto al email tanto a aprosuba 3 como a Amalia: Buenas tardes, en relación a la petición a si puede o no hacer testamento depende de lo que estime un notario conforme al artículo 665 del Código Civil. Por tanto si se empeña en hacer testamento nos tiene que indicar en qué notaria querría firmarlo para que desde la Comisión Tutelar podamos acreditar a la notaria que Don Pedro se encuentra curatelado.','2');
