insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2021-10-05','Ana: *María González, TS ASPACE, me remite la Prescripción Médica para el material ortoprotésico. ··············· Cumplimento y subo al portafirmas digital la SOLICITUD DEL MATERIAL ORTOPROTÉSICO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-10-05','Ana: Llamo a Carmen, TS del SSASB-Coria (927 50 80 00 Ext: 318): no obtengo respuesta. ················ Envío un correo (carmen.martinez@coria.org): "Buenas tardes Carmen, He intentado hablar contigo, pero supongo que he llamado ya a mala hora… Dime, cuando puedas, sobre qué hora te viene bien hablar mañana o llámame tú cuando puedas. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CELESTINO'and edp.apellido1='NAVARRETE'and apellido2='MURGA'),'2021-10-05','TERESA PRESUPUESTO NATALIA: HACER UN REINTEGRO PUNTUAL DE 45 € A SACAR ENTRE EL 08/10 Y EL 14/10 DE 2021. NATALIA/TERE: HACER REINTEGRO PERMANENTE DE 45 €/QUINCENA (90 €/MES) A PARTIR DEL 15/10/2021 NATALIA: CANCELAR TARJETA NATALIA: SEGURO DECESO: TIENE CARGOS CON SANTA LUCIA: OBTENER CONTRATO Y ASEGURAR QUE SE TRATA DE SEGURO DECESO Y EL ES EL BENEFICIARIO. TE ADJUNTO 1 RECIBO NATALIA: TIENE EMBARGOS: XFAVOR HABLAR CON DIPUTACIÓN BADAJOZ Y VER QUE DEUDAS TIENE, SI LE CORRESPONDEN Y DECIDIMOS SI DOMICILIAMOS. TE ADJUNTO 1 RECIBO MIGUEL: COMPROBAR PROPIEDAD TUTELADA (SI NO ESTÁ HECHO): TE ADJUNTO RECIBO IBI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-09-29','Ana: Correo de Maite, TS C.P. CC (trabajosocialcpcaceres@dgip.mir.es): "Buenos días Ana!! Me pongo en contacto contigo para comunicarte que ayer estuve hablando con el interno Saturnino Miguel Salgado Jiménez. El interno solicita el poder hablar directamente con vosotros, es decir, que se le autoricen las comunicaciones telefónicas con vosotros directamente porque dice tener dudas con respecto a varios temas. Por otra parte plantea la posibilidad de que se le pueda incrementar a la cantidad que ya viene percibiendo semanalmente ,unos 15€ más a la semana porque no tiene suficiente con lo que se le ingresa ahora. Informarte de que para que el interno pueda llamaros necesitaríamos que nos hagas llegar un escrito donde se diga que está tutelado por vosotros, el teléfono de contacto y el día así como la hora. He llamado a Seguridad por lo de las llamadas telefónicas a su madre y he corroborado que durante el mes de septiembre ha contactado con ella de forma regular. Un saludo y buenos días!!" ································· Convesación telefónica con Maite. Las dudas de Saturnino son relativas a su pena y sentencia. *Se lo derivaré a los compañeros jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-10-05','Ana: Envío correo a Ángel y Miguel, Asesores Jurídicos: "Buenas tardes compis, En relación a SATURNINO MIGUEL SALGADO JIMÉNEZ, interno actualmente en el C. Penitenciario de Cáceres, recientemente he recibido llamada telefónica de la Maite, la TS. Al parecer Saturnino solicita poder hablar con algún jurídico sobre su situación actual, tiene dudas sobre su sentencia, duración de su pena… Maite me informa de que para que el interno pueda llamaros necesitarían que les hagáis llegar un escrito donde se diga que está tutelado por la CTAEX, el teléfono de contacto y el día así como la hora. ¿Podéis encargaros de esta cuestión? Os facilito contacto de la TS, por si tuvieseis que consultarle algo: Maite: 927 181 407 // trabajosocialcpcaceres@dgip.mir.es Saludos y buena tarde!" ··························································································································································································· Envío correo a Maite, TS CTAEX: "Buenas tardes Maite, Según reunión mantenida con el jefe de sección económica, Saturnino tienen aún pendiente de amortizar algunas deudas. Además, como sabéis, se está haciendo frente a los tratamientos dentales pertinentes. A fecha de hoy no es viable aumentar su asignación. Cuando tenga las cuentas más saneadas podrá volver a plantearse dicho aumento. En cuanto a las comunicaciones, ya he comunicado la demanda de Saturnino a los compañeros asesores jurídicos. Seguimos en contacto. Un saludo y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-10-05','Ana: Llamada de Mª Ángeles, Aux. de SAD (675 264 255): Felipe necesita ropa y hace ya varios meses que entregaros presupuesto a Gloria, Ed. Futuex. ····················· Envío correo a Toni- Futuex: "Buenas tardes Toni, Ya sé que tengo correos tuyos, pero aún no me ha dado tiempo a verlos… a ver si con suerte mañana, pues hoy ya no creo… En relación a FELIPE RODRÍGUEZ SOLÍS, me ha llamada su Aux. de Ayuda a Domicilio, la verdad es que la mujer se implica mucho. Dice que hace meses entregó a Gloria un presupuesto para ropa de “LA SASTRERÍA” (tienda de Miajadas), pero por más que he filtrado y buscado, tanto en el ctutelar@ como en mi cuenta de correos, no lo encuentro. ¿Podríais intentar localizarlo y hacérnoslo llegar, por favor? Gracias y buena tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-06','Ana: correo del Dpto. de Fisioterapia de la Res. Geryvida (fisioterapia@geryvida.com): "Buenos días: Les adjuntamos el Consentimiento de Barandillas, desde el departamento de Fisioterapia, de la Residencia de Mayores GERYVIDA ( de Cáceres) para que ustedes nos lo envíen firmado. Muchas gracias. Un saludo" ················· Envío el C.I. firmado por el D.Gerente al Departamento de Fisioterapia. ···························································································································································································· Correo de Tamara, TS Geryvida (trabajosocial@geryvida.com), reenviando correos de Jose Manuel, nieto de Manuela, pidiendo informes médicos de la situación actual y que soliciten cita con su "Neurólogo de siempre". ··········· Mi respuesta: "Ok, gracias Tamara. Lo guardo. En cuanto al Neurólogo, el que él solicita, si no me equivoco, es uno privado. Ha estado mucho tiempo sin llevarla a revisiones, porque al parecer, no eran necesarias…. Yo sí que solicitaría, una vez que tenga asignada Médico de Atención Primaria, que se le de derive al Servicio de Neurología, pero a la Seguridad Social." ························································································································································································································································································································· Correo de Mercedes Vega Sánchez, Médica de la Residencia Geryvida (direccionmedica@geryvida.com): "Hola , otra vez Informarte que el estado clínico de Dña Manuela ha mejorado levemente desde su ingreso. Los primeros días presentó negativa a la ingesta , motivo por el cual el 1-10-21 se le colocó una via sc para prevenir la deshidratación, como ya te comenté por tfno. ayer. Los 2 últimos días las ingestas han mejorado, no presenta estreñimiento, tiene buen control de constantes , se la levanta al sillón por la mañana y por la tarde con buena tolerancia. Esta mañana se ha administrado la 3º dosis de vacuna covid 19. He solicitado a su Médico de A Primaria tramitación de cita con Neurología para revisión. Saludos cordiales"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-10-06','miguel, remito nuevo email a Ana de Pablo (la abogada) con copia a la hermana del tutelado (Inés): Buenos días, podríais confirmarme si ya se ha hecho el abono en la cuenta de José Luis de la venta? O si finalmente vais a enviar un cheque nuevo porque el otro lo había firmado su hermana?. Estamos pendientes de esto para comunicar la venta al juzgado. En cuanto al importe de la retención de la parte de José Luis de los 7.000€ que se ha hecho necesitaremos conforme se vayan haciendo pagos nos remitáis las facturas para ir justificándolo al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2021-10-06','Buenos días. Ya sabemos con certeza que la madre de la tutelada ZORAIDA AYUSO PIÑERO falleció. Estuvo enferma de cáncer con un tumor cerebral. Lo hemos averiguado contactando con algunos miembros de la familia biológica. Hemos hablado con Zoraida y se lo hemos dicho. Os comunicamos esta noticia para que estéis informados. Un saludo. Soledad Olmos Olmos - Trabajadora Social','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-10-06','Hola Situación ECO el 24/08/2021: SALDO: 66.164,09 € ---- EVOLUCIÓN ÚLTIMOS 24 MESES: - 15.258,06 € AMALIA: TE ADJUNTO LA DOCUMENTACIÓN DE LA QUE HABLAMOS: JUSTIFICANTES BANCARIOS DE LAS PENSIONES ICIAR: Cuenta con unos INGRESOS X ABONO RENTAS B.SANTANDER de 91,17 €/MES: HABLAR CON SANTANDER Y AVERIGUAR HASTA CUANDO DISPONE DE ESTE INGRESO. Adjunto documento. Tras hablar con AMALIA y confirmar que tutelada no volverá a casa: se acuerda DAR DE BAJA LA LUZ. Adjunto documento. PENSIÓN: una de las 2 pensiones procedentes de ALEMANIA ha dejado de cobrarse en 08/2020 (azul) y desconocemos el motivo. X favor: hablamos con B. Santander para que nos faciliten toda la información relativa a esa PENSIÓN: Beneficiario. Motivo CANCELACIÓN o MODIFICACIÓN CCC de ABONO (si fuera el caso). Amalia ha comprobado con la Seguridad Social de Alemania que esa Pensión NO HAN DEJADO DE ABONARLA. Si conocen alguna otra CCC que no nos hayan comunicado o si conocen otras CCC en otras entidades. Esta información hay que facilitársela a AMALIA para que siga investigando sobre la situación de esa pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-10-06','miguel, mando email a la notaria de Herrera del Duque que tenían que tramitar la declaración de herederos de Agustin (hijo de la tutelada) para que me indiquen cuándo se puede firmar. ******************************************** Llamo a la notaria de Herrera del Duque y dejo el recado para Loli (oficial) para que conteste al email donde le solicité que prepararan la Declaración de Herederos de su hijo Agustin ************************************************* Llamo a Estefanía (abogada) y dejo el recado de haberla llamado: la llamo para me confirme si ha impugnado o no la liquidación del impuesto de sucesiones de Felipe (hijo casado con su representada y exnuera Mercedes). Una vez esté correcta la liquidación del impuesto de sucesiones y firmada la declaración de herederos de Agustin, habrá que hacer la escritura notarial de adjudicación de herencia de los dos hijos Felipe y Agustin, una vez lo cual habrá que nombrar abogado para solicitar aprobación de herencia y autorización de venta (siendo la finalidad la venta del piso de Madrid que parece que el inquilino estuviera interesado en comprar, y con ese dinero comprar la parte de usufructo de la exnuera Mercedes. De esa forma sólo quedaría por liquidar la casa de Talarrubias).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MENDO'and apellido2='SANCHEZ'),'2021-10-06','EXITUS El Auto n.º 8/21, de 9 de febrero, dictado por el Jzdo. n.º 1 de Valencia de Alcántara, decreta el sobreseimiento del procedimiento de icp. por fallecimiento de la persona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-10-06','Ana: Conversación con Marta, TS SAD, Cilleros: La mayoría de las ocasiones Emilia no abre la puerta a las auxiliares y las últimas veces que lo ha hecho, por mediación de la TS, han surgido incidencias. *De hecho este martes el hijo cerro la puerta con llave diciendo a las 2 Aux. que no iban a salir de allí hasta que terminasen de limpiar todo. *Además Emilia presenta una importante falta de higiene personal. ······························· Conversación con Carmen, TS del SSASB-Coria (927 50 80 00 Ext: 318): la situación de Emilia es cada vez más insostenible. A Gloria, Ed. Futuex, no le deja apenas comprar alimentos y productos de higiene, pues lo que quiere es que le quede efectivo para manejar ella. El hijo sigue generando problemas, además, en cuanto ingrese en prisión se quedará totalmente sola. *Puesto que ya que disponemos de Autorización Judicial de Internamiento No Voluntario vamos a solicitar plaza residencial por emergencia social (Decreto). *Tiene 80 años. ······························································································································································································ Envío correo a Carmen (carmen.martinez@coria.org): "Buenos días Carmen, Tal y como hemos acordado, tras hablar por teléfono he ido a consultarlo y EMILIA GUTIERREZ SERRADILLA NO está valorada por la Ley de Dependencia, ni hay ninguna solicitud de valoración en curso. Por tanto, mantenemos la idea de solicitar la plaza residencial por emergencia social vía DECRETO. Ya tiene 80 años. Además de que nos envíes, cuando te sea posible, el informe social, ¿podrías por favor solicitar al Médico de Atención Primaria de referencia el Informe Médico en el modelo correspondiente? Si no puedes, dímelo e intento pedirlo por otras vías. **Por cierto, en el informe médico, para que no nos pongan problema en el acceso, debe constar que Emilia no presenta alteraciones de conducta. Seguimos en contacto. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-10-06','Ana: conversación con Pilar Martín, TS ESM: Juan acudió a su cita de Psiquiatría el día 28/09. Según lee en el JARA en la presentaba discurso delirante expansivo. *Solicitaré informe a Dr. Juan Pedro Jiménez Cano. *El día 10/10 tiene cita con la Enfermera en el C. Salud de Guadalupe (Inyectable).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-10-06','Ana: conversación con Marta, TS Cilleros (927 51 20 37): esta semana se han reunido ella y Gloria, Ed. Futuex, con Julia en su despacho. Últimamente Julia presenta conductas y horarios inadecuados. Además en cuestión de meses se ha producido un cambio radical, de no querer salir de casa a pasar casi todo el tiempo fuera. Con llamadas de atención y llamadas al 112. *La propia Julia dice que enviará ella el último informe médico por correo certificado, a pesar de que Marta le dice que lo puede enviar ella directamente y sería mucho más rápido, ella no cede.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2021-10-06','Ana: Conversación con Ana - Servicio de Ayudas Complementarias al Alquiler de Viviendas (924 33 23 66): Dado que tenemos justificantes bancarios de abono del alquiler de todos los meses excepto agosto y el último trimestre del año (*No estamos seguros de si se abonó todo junto a primeros de 2020. *Estrella, admvo. CTAEX, lo ha solicitado al banco) me indica que presentemos los que tenemos y en función de esto le hará un ingreso de la ayuda. *A posteriori podemos subsanarlo con el resto de justificantes, si apareciesen. ·················································································································································································· *Paso a Julio, CTAEX, el Oficio y pido que lo registre adjuntando los justificantes bancarios que a día de hoy tenemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-10-06','miguel, remito email a Juana de Liberbank: Buenas tardes Juana, te remito un borrador de documento de reparto del Fondo de Inversiones de la tutelada Doña Felisa Felipe Teodomiro con la finalidad de que nos confirméis si es posible la firma por su representante D. José Vicente Granado (representante de la Comisión Tutelar) y de la hermana de la tutelada, sin necesidad de acudir a la oficina que creo está en Plasencia. Caso contrario, podría el representante de la Comisión Tutelar de Adultos firmar en vuestra oficina en Mérida ya que debido a su cargo es muy complicado desplazarse a oficinas de fuera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2021-09-03','Ana: Recibimos escrito del Servicio de de Ayudas complementarias al alquiler de vivienda: "... se le concede a la interesada una cuantía de 113,75€/mes, equivalente al 65% del importe mensual de la renta" *Requieren que presentemos los justificantes bancarios del abono del alquiler de todas la mensualidades del año 2019 (año en que aún tenía una incapacidad total y estaba tutelada por la CTAEX). ················· *Estrella, secc. ecca., solicitará al banco los justificantes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-10-06','Ana: Paso a Iciar, secc. ecca., el modelo de alta de tercero firmado por el D.Gerente, para que cuando puedan lo lleven al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2021-10-07','Ana: Correo de Tomás Álvarez, COCEMFE (gerencia@cocemfecaceres.org): "Buenos días Ana. Te informo que Tomás ya ha salido del hospital, llegó a COCEMFE sobre las 19.00h. Está bien, ha superado la ITU complicada (Infección del Tracto Urinario) según aparece en el diagnóstico de la Unidad de Urología del Hospital Universitario de Cáceres. En breve os remitiremos declaraciones juradas y presupuesto del importe de cuidados. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-10-07','miguel, hablo con Loli de la notaria de herrera del Duque.Me confirma que va a pedir las últimas voluntades para poder hacer la declaración de herederos. Que en unos 20 días la llame para ver si ha llegado, una vez lo cual se firmará.(Avisarla en 20 días para ver si le ha llegado ya)','2');
