insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERMINA'and edp.apellido1='SERRANO'and apellido2='MOCHOLI'),'2021-10-07','Ana: A petición de Rosa, Admvo. CSS-Plas., enviamos CI original por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-10-07','miguel, hablo con Ana de Pablo, quedo con ella que irá a Caixabank a intentar cambiar el cheque por una transferencia y para acreditar la titularidad de la cuenta que me pide la remito la fotocopia del contrato de titularidad de José Luis Murillo Horrillo, junto con el testimonio de la sentencia de incapacitación y testimonio de aceptación del cargo. Una vez que tenga la forma de pago la llevará a la notaria para que Nagore pueda hacer una subsanación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-05','Ana: Paso a Julio, CTAEX, oficio y documento de protección de datos de la Residencia, debidamente firmado y sellado, para registralo y remitirlo por correo certificado a Geryvida. ·········································································································································· Correo de Toni-Futuex, con nota sobre la mañana del ingreso de Manuela. Relata toda la secuencia y la actuación y alteración de José Manuel. Estuvieron presentes también la abogada de éste (quien se mostró colaboradora) y la Guardia Civil, además de los técnicos de ambulancia y 2 educadoras de Futuex. **Guardo correo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-10-07','Ana: paso a Icíar, secc. ecca., Modelo de Alta de Terceros, firmado por el D.Gerente, para que lo lleven al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-09-23','miguel, llama el hermano de la tutelada Pedro Barragan (tfno 629278526) para comunicarnos que en la notaria de Plasencia de MANUEL gOMEZ MORO Y PABLO ANTONIO MATEOS LARA tfno 927-411461 (Felipe el oficial) está tramitando escritura de compraventa. Dice que se le debe dinero y lo ha hecho constar y acreditado en la escritura que se está preparando. Comenta que él pagó por la reclamación de Generalis. Angel me comentó que Generalis demandó a la tutelada y a la Junta e intervino Abogacía General, cuya resolución todavía no la conocemos. Por otro lado, dice que hay dos bienes rústicos de la tutelada aunque piensa que sólo le quedan las tierras que tiene a un 50% con él y de la cual ya me adelanta que hay un interesado que ofrecerá por debajo del valor que en su día se valoró. Y de la tierra que sigue apareciendo al 100% de ella en realidad la vendió con otra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2021-10-07','miguel, llamo sin éxito a la notaria de Plasencia de Gomez Moro para intentar hablar con Felipe (que está tramitando la compraventa)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-10-07','miguel, llega email de bufete de abogados de Zafra Teresa Vega: Buenos dias Con relación al asunto de DOÑA BEATRIZ MEJIAS DE LA MORENA y toda vez que la Ley 8/2021 de 2 de junio establece que el presunto incapaz dispone de un breve plazo para solicitar la revisión de su expediente conforme a la reforma normativa,y en aras a garantizar los derechos de la Sra. Mejías es por lo que les solicitamos procedan a la aprobación a la mayor brevedad y suscripción por parte de Doña Beatriz de la correspondiente hoja de encargo de prestación de servicios jurídicos. Para cualquier duda o aclaración ruego contacten con nosotros al telefono 625 13 57 19 ***************************************************** Mi contestación: Buenos días, en relación a su email, indicarle que esta persona se encuentra tutelada y que por sus condiciones económicas no requiere los servicios de un abogado de pago por lo que no se acepta la petición realizada por su bufete. Caso de que la tutelada Doña Beatriz quiera ejercitar dicha petición deberá ponerse en contacto con por escrito fundamentado por los cauces administrativos legales habituales . Reciban un cordial saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-10-07','EMAIL DE ANTO TS SSAB Buenas tardes Teresa, soy Antonia Morán de servicios sociales, considerando que el retorno de Antonia Engracia es eminente, quiero informarte, por si lo desconoces, que esta tiene reconocido un grado II de dependencia y asignado el recurso de Ayuda a Domicilio con una asignación economica vinculada al mismo. A fecha, no tiene establecido contrato con ninguna empresa, por lo que creo que seria conveniente que conocieras esta circunstancia , por si valorais necesario articular al servicio con cualquier empresa antes que esta retorne. Desde el ayuntamiento y al tener reconocido recurso por dependencia no podemos continuar prestándole la ayuda a domicilio, habiendo esperado un tiempo prudencial hasta tanto en cuanto alguien asumiera su tutela , como ocurre en la actualidad . Para cualquier duda o aclaración que preciseis me escribes o llamas por teléfono, como prefieras. Saludos . el servicio Te informo que si retorna es imposible poder continuar prestándole el servicio de ayuda a domicilio del ayuntamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2021-10-07','AUTORIZAMOS SUBIR AMBAS TRANSFERENCIAS PERMANENTES X MANUTENCIÓN A MADRE TUTELADOS A 300 €/MES CADA UNO. AVISA A TUTELADOS DE QUE EL INCREMENTO SERÁ A PARTIR DEL 01/11/2021.','2');
