insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-10-07','miguel, llamo a Paula del CRR tlfno 682704401 para me informe de la herencia que hay que hacer y me facilite documentación. Sigo sin lograr hablar con ella','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-07','Ana: Correo de Alberto, jefe secc. ecca.: "Hola Ana. Comunicarte que ha vuelto a cobrar subsidio INEM a partir de la nómina de JULIO 2021 (abono en agosto). Importe: 451,92 € x 12." ······························································································································································································ Envío correo a Jorge Morán Pilo, Jefe de secc. de Prestaciones Eccas. - UGRDS (jorge.moran@salud-juntaex.es): "Buenos días Jorge, ¿Qué tal estás? Tan sólo recordarte que seguimos pendiente del documento de COBRO INDEBIDO relativo a José Manuel Moreno Carlos. Acordamos que me avisarías cuando lo tuvieras y bajaría a por él, ¿os ha saltado ya? Más que nada para no demorar mucho la devolución. Ya me dices cuando puedas. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-10-07','Ana: Recibimos, del Serv. de Gestión Económica de Pensiones notificación de RESOLUCIÓN DE CONCESIÓN DE PNC con COMPLEMENTO del 50% por necesidad de tercera persona. Cuantía mensual 604,20€/mes x 14. *Primer ingreso, con atrasos: 5135,70 € ···································· Lo comunico a María, TS de Asoc. Autismo Sur mediante mail (teayudamos@autismosur.es), solicitándole nos remitan: - Certificado de deuda actualizado contraído con vuestro centro detallado por concepto. - Modo de proceder para el abono de la plaza a partir de ahora. - Coste mensual de dicha plaza - Propuesta de presupuesto aproximado de gastos de bolsillos mensual','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-10-08','Ana: Llamo al HUC (56083 / 56691) para preguntar por Valentina, pero no obtengo respuesta. ·········· Desde Centralita (927 25 62 00) me pasan con planta, aquí me facilitan otros números de Trauma: 56690 / 56692 / 56693): No obtengo respuesta en ninguno de ellos. ············································································ Vuelvo a llamar más tarde. El Dr. Hdez. Carretero, Traumatólogo, me comunica que Valentina está bien, ha evolucionado favorablemente y hoy mismo le darán el alta. Está pendiente del resultado de la PCR. Esta tarde la trasladarán en Ambulancia a la Residencia de Logrosán. Posiblemente a última hora. ······················ Lo comunico por mail a Ana, Enfermera de la Res. Femar de Logrosán (residenciafemar2019@gmail.com) y pido que cuando puedan nos envíen el informe de alta escaneado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-08','miguel, remito email a la notaria de Don Benito (Marisa): Buenos días, en relación a mi email anterior les remito para que preparen declaración de herederos de su madre Rosa Galan Merino y la posterior Renuncia de herencia de su madre, ya que la de su padre ya se hizo y se las remití en la documentación adjuntada en mi anterior email. Por favor pónganse en contacto con nosotros ya que en reiteradas ocasiones hemos intentado hablar con ustedes por teléfono sin éxito. ********************************************* Voy a la notaria de Montijo a firmar la compraventa de la c/El Hinojo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-10-07','Amalia : Ati salió a las 15.00 h. de alta de la UHB de LLerena . Se le ha contratado hostal Carmen en Zafra , se adjunta presupuesto. Se le ha comprado tabaco en estanco se pagará por transferencia. La Delegada tutelar estará esperándolo en el hostal para entregárselo . Irá a la comisaría a preguntar cómo se le puede sacar el DNI . Ati sabe que tiene cita para ingresar en UME en CSS . Hola Buenos días, le confirmo la reserva siguiendo sus indicaciones. Hostal Carmen : El precio es de 55.00 € por dia incluyendo Pensión completa con alojamiento en habitación individual desayuno (en cafetería incluyendo café o zumo, bollería o tostada), comida y cena tipo menú del dia. Para el domingo al estar cerrada la cafetería y el restaurante se le preparara un picnic para desayuno, comida y cena. Espero su confirmación de la reserva aceptando este presupuesto. Un saludo Jose A. Rojas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-10-07','Ana: Conversación con Pilar Martín, TS ESM-CC (54612): La Psiquiatra de referencia es Mª Isabel Rubio Merino ("Mabel"). Su próxima cita en Psiquiatría es el día 22/10/21 es a las 10:10 h. Y en con Montse, Enfermera, el día 21/12/21. ············· El nº de Doroteo es: 609 928 621 y el de Carmen, su madre 600 549 302. ·························································································································································································· Llamo a Doroteo: Me presento y le explico en qué consiste el cargo y que irá a visitarle una educadora. *Doroteo hace incapié en las herencias que debe hacer y de las que se hace mención en el Informe Social que emitió Pilar Martín, TS del ESM-CC para el Inventario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-10-08','Ana: Envío correo de derivación a Futuex: "Procedo a hacerte la derivación de un cargo nuevo. Se llama DOROTEO DÍAS CERRO, tiene 52 años y reside con su madre en una vivienda de alquiler en la ciudad de Cáceres. Yo hablé ayer con él y aunque intenté explicarle en qué consiste la tutela y demás cositas, creo que hará falta que le clarifiquen ciertas cuestiones de nuevo. Lo que sí le quedó claro y le alegró, es que se pondrá en contacto con él una Educadora y que irá a visitarle. Dice que no tiene cuenta (sí que tiene, se lo he intentado explicar yo), pues además percibe una Incapacidad Permanente Absoluta. Pero dice que eso lo cobra su madre… **Hay que realizar una propuesta aproximada de gastos (tanto de bolsillo como de otros gastos mensuales de alquiler, de suministros, alimentación, telefonía…) *Desconozco la situación económica de la madre, pero entiendo que Doroteo tendrá que colaborar con los gastos. Hay que establecer también una asignación semanal. ¿Podríais elaborar con él dicho presupuesto? Con la madre no he llegado hablar, le dije si quería pasármela, pues se le escuchaba dando voces de fondo preguntando “a quién le daba cuentas”… y me dijo que no, que mejor ya hable con ella la educadora cuando acuda. *Decirte, que las compañeras de la sección económica solicitaron que añadieran a José Vicente en la cuenta en el mes de junio y aún estamos esperando…. Tienen que volver al banco, a ver si pronto se soluciona, pues mientras tanto no tienen acceso a la misma y no pueden operar. *Acude periódicamente al E.S.M. de Cáceres. Pilar Martín, TS le conoce. Presenta un grado de discapacidad del 65% . Diagnóstico según Dictamen Técnico: Trastorno de la Personalidad y Esquizofrenia Paranoide. Su Psiquiatra de referencia es: Mª Isabel Rubio. *Su próxima cita en Psiquiatría es el día 22/10/21 a las 10:10 h. Si dejara que le acompañe la educadora que asignes, estupendo (si no pudiera ser, por ser precipitado lo entiendo) Domicilio: C/ DE LAS MARGARITAS, 59. C.P. 10004 Tlf. De Doroteo: 609 928 621"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-08','miguel, dejo firmada la escritura de compraventa cuyo sobrante tras pagar la parte de inmobiliaria y de hipoteca de Ibercaja quedará en su cuenta de Caja Rural. Intento hablar sin éxito con Ibercaja para que procedan a la cancelación económica total pero no cogen el teléfono, así que les remito fax: Buenas tardes, solicitamos la cancelación económica total del préstamo hipotecario 645060030000137001044, cuyo titular es el Curatelado Don Juan Carlos Rubio Galán con Dni 8849335Q. En la mañana de hoy se ha hecho una transferencia vía banco de España a la cuenta por usted indicada 2085 4507 98 0330362042. Una vez pasados unos días, ruego nos remitan el Certificado de cancelación económica total para dejarlo en la notaria de Montijo para que puedan firmar la Cancelación de la hipoteca. ************************************************ Tras conversación con el curatelado, me pide solucione varias cuestiones: 1.-Lápida de la madre 2.-Dinero para ropa 3.-Posibles deudas del Oar de Badajoz 4.-Venta de la casa de c/Constitución (para lo cual comento a Tere que habrá de hablar con Amalia para localizar a la Trabajadora Social del pueblo que tiene la llave, para avisar a Emiliano de la inmobiliaria Info finca para que la tase) De todo tenemos que hacer reunión a 3 bandas: parte económica/social y jurídica','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-10-08','Ana: María, TS Autismo Sur (teayudamos@autismosur.es), me remite correo con información relativa a la deuda contraida con la Fundación y los gastos aprox. a partir de ahora. ································ Nuevo correo respondiendo sobre cómo está Álex: "Se me olvidó comentarte que tal, está Alex.... Ya están con más rutinas por fin vuelta a la normalidad... y están retomando las salidas de senderismo, cafetería... Esta en un ciclo muy bueno... donde está super colaborador haciendo talleres.... En su cumple lo llevaron dos compis al McDonald que le encanta y playa.... Es un disfrutón"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-10-08','Maite: el 6 de octubre llama la trabajadora social del servicio de atención social básica de Talarrubias (belén Prieto 924 631079)para preguntar cómo va el tema de la herencia de Alfonsa. También propone el cambio de residencia de Siruela a la residencia San Roque de Talarrubias, ya que en este momento hay plaza y la hermana de Alfonsa reside allí. Una vez hecho el estudio económico, hoy he hablado con Belén para decirle que sí haremos el cambio y me explicase el procedmiento a seguir. Le ha pedido que nos envíe un escrito exponiendo las razones que motivan su petición de cambio de centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-10-08','Ati ha ido esta mañana al BBVA de Zafra ( estaba expulsado del BBVA de Mérida y por eso se le abrió cuenta en otra entidad ) y sin llevar el DNI le han dado 225€ . De momento , para no hacer saltar la liebre , desde la sección eco no van a comunicar nada hasta la semana que viene .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-10-08','Maite: la trabajadora social de Cabeza del Buey, Agueda( 636786917)ha enviado hy el informe social para que se valore su ingreso en centro por emergenecial social. Ayer la visito el quipo de fammilia en la localidad de Peñalsordo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-10-08','Ana: Doroteo tiene reconocido GRADO I, Nivel 2 de Dependencia y percibe: PRESTACIÓN ECONÓMICA PARA CUIDADOS EN EL ENTRONO FAMILIAR Y APOYO A CUIDADORES NO PROFESIONALES: 173,80€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-10-08','miguel, a petición de Pilar Martin del centro, según me reenvía Ana, pregunto al Jzdo de 1º instancia nº2 de Cáceres, procedimiento nº 402/20, que me confirma que se trata de procedimiento de incapacitación, con lo cual remito email a secretaría y a contencioso de abogacía para que nos remitan la resolución del juzgado, con su firmeza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-11','miguel, recibo email de la oficina de ibercaja de Guadiana del Caudillo (Emilio Director): Buenos días. El préstamo quedó cancelado el viernes. ********************************************************* mi contestación: Buenos días, gracias. Cuando esté preparado el certificado de cancelación económica total indíquenos si les vendría bien firmar la escritura de cancelación de hipoteca en la notaria de Montijo, para lo cual si les parece bien pueden remitirnos por email el mismo (para remitirlo a la notaria) y el original llevarlo el apoderado de Ibercaja el día que vaya a firmarla. Saludos cordiales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-10-11','Ana: Tras leer el correo de Desiré, Ed. Círculo Rojo (desire@editorialcirculorojo.com) en ctutelar@, se lo reenvío a los Asesores Jurídicos y a Alberto, secc. ecca. CTAEX, para que revisen el contrato antes de ponerlo a la firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-10-11','Ana: Envío correo a Alberto, Ángel y Miguel, CTAEX: "Buenos días a tod@s, reenvío este correo de Pedro Pastor, señor que suele ayuda a JESÚS ROMERO PÉREZ. - Alberto, ¿Podéis valorar la petición de Jesús de aumentar su asignación en 20€/mes? (para clarificar puedes leer los dos correos de más abajo) - Ángel/Miguel, ¿sería posible que os pusieseis en contacto con el dueño del piso en el que vive de alquiler? Según se indica en el correo: no arregla lavadora ni se encarga de la revisión de caldera de gas..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-10-11','Maite: desde la visita al centro, han comunicado varias incidencias sobre el comportamiento de José MAría. La convicencia con el resto de residenctes se hace cada vez más difícil. Tienen miedo y aseguran no vivir tranquilos desde que llegó; los amenaza sino le dan lo que quiere, agrede y extorsiona. La unidad de programas asistenciales , desde donde se asigna el recurso está al tanto y se empieza a pensar en una alternativa. Respecto a las visitas de la delegasa tutelar. es cada quince días. José Maria ha aceptado de buen grado estas visitas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-10-07','Ana: Conversación con Julia Hdez., madre de Julia (644 876 893): manifiesta que Julia está muy nerviosa ultimamente. El otro día tuvieron que llamar a la Guardia Civil para localizar a Julia y acudir a Plasencia a buscarla, pues se fue sola en autobús de línea. Se gastaron 100€ en ir a buscarla y pide que se los devolvemos de la cuenta de Julia. *Gloria, Ed. Futuex, está al corriente y va a intentar adelantar la cita en ESM. *La madre opina que estaría mejor en un centro, pero no en el CRR, pues ya estuvo en el de Mérida y no estuvo bien. "Tenía demasiada libertad y pasaba todo el día en la calle", argumenta. ····························································································································································································· Consulta en SIDEX: El expdte. se encuentra en fase de "gestión de citas" ··························································································································································································· Correo de Toni-Futuex: "Buenas tardes Ana, adjuntamos informe actualizado con las ultimas circunstacias acontecidas en torno a Julia Morón, especialmente desde el incidente de esta pasada semana, que se detalla, que se fue de casa a Plasencia, aunque ya esta de vuelta. No consideraron en la guardia civil que fuera al hospital para evaluacion psiquiatra.. inexplicamente, tambien Gloria ha hablado con la medica, que indica que descompensada no la ve.. es una situación a nivel social y familiar muy muy compleja, y nosotras creemos que desde luego tb a nivel psiquiatrico- En el informe, tratamos de poner en contexto, la situación actualizada. Cualquier cosa, quedamos a disposición."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2021-10-11','miguel, mi contestación: Buenos días, por favor indicad donde localizar el contrato de alquiler o los datos del arrendador para ponernos en contacto con él. Hay algún informe social que indique exactamente cuáles son los desperfectos del piso a arreglar?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-10-11','miguel, tras intentar hablar con el sobrino José Cabrera Teomiro (tlfno:644 70 47 12) sin éxito, le envío email y con copia a la parte económica y a Angel: Buenas tardes, en relación a su solicitud del desbloqueo del Fondo de Inversiones de su madre y su tía ,tutelada por esta Comisión, le remito el borrador que tras consultarlo con Liberbank dan por bueno. Queda porque indiquen ustedes su número de cuenta y me lo remitan una vez firmado (en una oficina de Liberbank (actual Unicaja), preferiblemente en la oficina de c/ Santa Eulalia de Mérida (contacto Juana Heras). Deben firmarlo en presencia de una persona de la oficina, una vez esté remitanoslo antes del jueves si es posible, donde acudiremos con el representante de la Comisión a firmarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-10-08','miguel, me llega email de Juana Heras: Buenos días, Miguel. Me trasladan desde la oficina la siguiente respuesta de nuestra Asesoría Jurídica: - Debéis rectificar el DNI y Apellido de Felisa, ya que no son correctos. - Debe ir firmado de manera manuscrita, a ser posible en oficina, o con firma electrónica cualificada. - En el último párrafo hacer mención a Unicaja Banco, no a Ibercaja. - Debéis indicar un número de cuenta de la persona no tutelada, preferiblemente de la Entidad. Con estas consideraciones sería válido el documento para el rescate del fondo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2021-10-11','miguel, llega sentencia del juzgado nº2 de lo Penal (no firme) con condena de prisión, orden de alejamiento a 300 m por 5 años y de contacto físico o por cualquier medio con la tutelada e indemnización de 5.000€ y costas procesales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-10-08','Maite: la trabajdora social ha enviado el informe justificando el cambio de residencia.Lo he puesto en su expediente','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-10-11','Ana: Envío correo a Toni-Futuex: "...Precisamente el jueves hablé con la madre con respecto a las últimas incidencias y con Marta, TS de Cilleros, uno días antes. Me informó de la “reunión” que ella y Gloria mantuvieron con Julia. Nosotros no tenemos ningún informe de la Guardia Civil en su expediente, voy a llamar por teléfono, a ver qué consigo y si es necesario se los solicito por escrito. La semana pasada también hicimos consulta y se encuentra en fase de “Gestión de citas” de la Ley de Dependencia, no obstante, tal y como hice en su día, aunque sin los resultados esperados, volveré a contactar con la sección de dependencia correspondiente, a ver si se puede agilizar mínimamente. Con respecto a los últimos informes del Serv. De Urgencias, los hemos recibido también la semana pasada en papel, Julia los envió por correo postal ordinario, pero me temo no nos van a servir de mucho. Cito textualmente: - En el del 30/09: “ANSIEDAD RESULTA A LA LLEGADA AL SERVICIO DE URGENCIAS. SIN IDEAS PSICÓTICAS NI AUTOLÍTICAS. NO SINTOMAS DE ALARMA EN EL MOMENTO ACTUAL.” - En el del 4/10: “La paciente refiere encontrarse mejor, tranquila, se explica pauta puesta por psiquiatría y ajuste de medicación, tanto a ella como a su padre. Quedan conformes y solicitan ambulancia de cara al alta” Seguimos en contacto." ································································································································································································ Llamo a la Guardia Civil de Cilleros (927 51 20 21), la llamada salta en Cuartel de Moraleja, al parecer no están todo los días en Cilleros y cuando es así les desvían las llamadas. No obstatne, *le pasarán aviso a Francisco, Sargento, mediante correo electrónico con mis datos para que se ponga en contacto conmigo. ····························································································································································································· Envío correo a Mª Dolores Venegas, TS del EVD-Coria, Secc. Dependencia II, Plas. (dolores.venegas@salud-juntaex.es): "Buenos días Dolores, En relación a JULIA MORÓN HERNÁNDEZ, tutelada por la CTAEX, quería preguntar si tardarán mucho en ir a valorarla. Un compañero han consultado en SIDEX, yo no tengo acceso, y al parecer está en “Gestión de citas”, pero la situación de Julia cada vez es más delicada. Si queréis puedo facilitaros copias de las últimas derivaciones al Serv. De Urgencias del Hospital San Pedro de Alcántara y el último ajuste de medicación. En la vivienda cada vez hay más desorden y menos higiene y las relaciones familiares no son nada favorecedoras. Ya me dices cuando puedas. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-10-13','Ana: correo de Alicia Marín, Enfermera - Res. Femar: "Buenos días, Les comunico que Valentina Fernández tiene consulta en el servicio de Cardiología el día 21/10/21 a las 11:00H, en el HSPA y necesita acompañante. Un saludo," ······················ Mi respuesta: "Buenos días, Gracias por informar. ¿Hay alguna persona de confianza que pueda acompañarla? Si es así, comuníquenoslo e indíquenos el precio/hora del acompañamiento, para que el jefe de sección económica pueda dar el visto bueno. A posteriori deberán enviarnos una declaración jurada firmada por la persona acompañante indicando el número de cuenta para que se le pueda hacer transferencia. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-10-13','2021/10/04 AMALIA/ALBERTO: MODIFICACIÓN SITUACIÓN TUTELADA QUE PASA DE PISOS TUTELADOS A ALQUILER EN ZAFRA A PARTIR DE 15/10/2021: ICIAR: YA HECHO ESCRITO MODIFICACIÓN REINTEGRO PERMANENTE QUE PASA A 70€/SEMANA (303€/MES APROX.): EN EXPEDIENTE ONLINE PARA TRAMITACIÓN. HACER YA (A PARTIR 11/10/2021) SE PRESUPUESTAN CONSUMOS DE 75 €/MES: EN CASO DE QUE SUPERE ESA MEDIA SE DETRAERÁ DICHO IMPORTE DE SU REINTEGRO. ICIAR: HACER TRANSFERENCIA: YA HECHO ESCRITO TRANSFERENCIA PUNTUAL PAGO FIANZA Y PAGO ALQUILER 2ª QUINCENA OCUTUBRE 2021: (350+175: 525 €) EN EXPEDIENTE ONLINE PARA TRAMITACIÓN . CUANDO ÁNGEL NOS DE OK ICIAR: HACER TRANSFERENCIA: YA HECHO ESCRITO TRANSFERENCIA PERMANENTE PAGO ALQUILER: (350 €/MES) EN EXPEDIENTE ONLINE PARA TRAMITACIÓN. CUANDO ÁNGEL NOS DE OK. OTROS: NO FORMALIZACIÓN CONTRATO TELEFONÍA: PREPAGO DE SU ASIGNACIÓN. POSIBLES DEUDAS CON SU HERMANA DEBERÁ RESOLVERSLAS TUTELADA DIRECTAMENTE CON ELLA. CTAEX NO ABONARÁ NADA A ESTE RESPECTO. DEPILACIÓN: NO: AMALIA SABE QUE LO VA A PAGAR CON EL SUELDO DE TRABAJADORA ESPORÁDICA COMO TELEOPERADORA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-10-13','Ana: Llamada de Marta, TS Cilleros (927 51 20 37): el lunes la madre de Julia tuvo que volver a llamar a la Guardia Civil, pues Julia no regresaba a casa. ······ Marta ha llamado a Paco, Sargento de la Guardia Civil. Han quedado para reunirse el viernes para hablar sobre Julia. Intentará que Paco emita informes actuales. Él se queja de que ha ya enviado otros en 2018 y 2019. *Ninguna de nosotras 2 disponemos de dichos informes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-10-13','NATALIA: X FAVOR, LLAMA AL HOSTAL CARMEN DE ZAFRA Y ACUERDA CON EL, SI ES POSIBLE: PAGOS SEMANALES X TRANSFERENCIA: HABLAR CON JOSÉ A. ROJAS - 924 55 14 39 55 € X 7 DÍAS= 385 €/SEMANA (1669 €/MES). EVIDENTEMENTE TE REMITIRÁ FACTURAS. DEBE FACILITARTE Nº CCC PARA LA TRANSFERENCIA AMALIA: COMO YA HEMOS HABLADO, HA HABIDO SUERTE Y HA SACADO DINERO EN BBVA ZAFRA: 225 €/SEMANA (LO QUE TENÍA AUTORIZADO ANTERIORMENTE). QUEDAMOS EN QUE MANTENEMOS ESTO ESTA SEMANA Y LA QUE VIENE. ICIAR: ESTAMOS PENDIENTE DEL REINTEGRO DE LA SEMANA QUE VIENE Y DE SI LO DAMOS DE BAJO O MODIFICAMOS IMPORTE TRAS VERLO CON AMALIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-10-13','Ana: Correo de María, nueva directora de la Res. Jaraicejo (mariagarciarecio97@gmail.com): "Buenos días Ana, soy María la trabajadora social y la directora de la residencia de mayores de Jaraicejo. Me dirijo a usted para comunicarle que Isabel Muñoz Melchor,tiene cita el día 18 de octubre para el dentista, y también tiene cita en Plasencia el día 21 de octubre para el psiquiatra y la trabajadora social, así mismo, también comunicarle que dice de querer irse a alguna residencia de Plasencia. Quedo a su disposición para cualquier duda- 664598967 Un abrazo" ························ Llamo a María, Directora Residencia: Le explico cómo está la situación en cuantro a centros, pues Isabel rechazó la plaza concedida en Plasencia a primeros de año. ·· En cuanto a las próximas consultas, solicitarán ambulancia en el C. Salud, para acuidr al ESM Plas., donde le acompañará Gloria, Ed. Futuex. ·· Para la Clínica Dental solicitarán presupuesto a la Taxista del pueblo que ha realizado el traslado en otras ocasiones y propondrá a alguna persona de confianza el acompañamiento (Enviarán a posteriori Declaración Jurada)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-13','Ana: correo del día 11 de Mario Estrella, Res. Ntra. Sra. Guadalupe, Bohonal de Ibor: "Buenas tardes Ana, Como sabes, el próximo día 20 de octubre finaliza la estancia de D. Jose Manuel Moreno Carlos en nuestra Residencia. De cara a organizar su salida, te ruego me indiques los datos relativos al transporte." ···················· Mi respuesta: "Buenos días Mario, Entiendo que José Manuel podrá realizar el traslado en taxi, si es así, ¿podríais solicitar un presupuesto para dicho traslado y remitírnoslo para que el jefe de la sección económica dé el visto bueno? Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2021-10-13','TERESA RECIBO LLAMADA DE ROSA DIRE FUENTE DE CANTOS FINALMENE RAMON FUE DADO DE ALTA Y VOLVIO AL CENTRO YA QUE EL REPOSO ERA REDUCIDO Y NO IBA A NECESITAR MAYORS CUIDADOS HA VUELTO A INGRESAR PORQEU LE HAN VISOT UN COAGULO EN UN PUMON, HA SIDO DADO DE ALTA NUEVAMENTE A PESAR DE QEU RESPIRA MUY MAL Y SE NIEGA A DEJAR DE FUMAR Y A PONERSE AL MASCARILLA LAS HORAS INDICADAS POR EL MEDICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-13','Reunión parte económica, jurídica y social: TERE: LÁPIDA: OBTENER UN PAR DE PRESUPUESTOS PARA LÁPIDA MADRE. TERE: TIENE QUE OBTENER CERTIFICADO DEUDA (LO MÁS DETALLADO POSIBLE) + ACLARAR SI YA ESTÁN CARGANDO EL COSTE DE LA PLAZA + PROPUESTA PRESUPUESTO MENSUAL. ALBERTO: MIGUEL INDICA QUE NO CANCELEMOS IBERCAJA HASTA QUE HAGAMOS CANCELACIÓN REGISTRAL HIPOTECA (DE ESTO SE ENCARGA MIGUEL). TOD@S: VENTA DE LA OTRA VIVIENDA: C/ CONSTITUCIÓN (GUADIANA DEL CAUDILLO) • VIVIENDA PARECE QUE ESTÁ EN MALAS CONDICIONES + POSIBLEMENTE REQUERIRÍA REHABILITACIÓN. • MIGUEL HABLA CON TUTELADO Y ESTE HA VERBALIZADO QUE SI CONSIENTE LA VENTA DE ESTA VIVIENDA. • MIGUEL: VA A TRATAR CON LA MISMA INMOBILIARIA DE VENTA ANTERIOR (INFOFINCA-EMILIANO) QUE SE COMPORTÓ MUY EFICIENTEMENTE Y A UN COSTE BAJO. • MIGUEL: NO ES NECESARIO AUTORIZACIÓN JUDICIAL • MIGUEL: OAR PARA VER SI TIENE DEUDAS Y CONFIRMAR SI TENEMOS QUE DOMICILIAR ALGÚN CONCEPTO. AMALIA: NECESITAMOS TU OPINIÓN SOBRE LA VENTA DE ESTA SEGUNDA VIVIENDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CLEMENTA'and edp.apellido1='AMADO'and apellido2='VIVAS'),'2021-10-13','miguel, tras comunicarnos abogacía (Curro) no haber recibido la firmeza de la sentencia de incapacitación, remito email (conforme indicación del Jzdo nº2 de Cáceres) al Scop: Buenos días, en relación al nombramiento como Administradores de Bienes de Doña Clementa Amado Vivas, ha sido dictado por el Juzgado de 1º instancia e instrucción nº2 de Cáceres con respecto al procedimiento de incapacitación 402/2020, resolución firme de dicho procedimiento de incapacitación, ya que nos comentan desde abogacía general que allí no lo han remitido. Si es posible, independientemente que lo remitan vía Lexnet y debido a que nos urge la misma, remítanosla bien a este email o bien al fax 924-003194. Adjunto testimonio de nombramiento como Administrador de Bienes a la Comisión Tutelar de Adultos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-13','Ana: Tras intercambiar varios correos con Pablo Correa, nieto de Manuela, a petición suya, se programa reunión con él y con su hermano Antonio el día 18 a las 9:00 h. ··························································································································································································· Correo de Tamara, TS Geryvida: "Buenos días Ana, Comentarte que ha venido hoy a la visita su nieto Pablo y su esposa Raquel, me cuenta que el próximo lunes tiene cota con la Comisión Tutelar porque desean saber la evolución de su abuela y también la posibilidad de trasladarla a un centro más cercano a su domicilio y así que les sea más sencillo poder ir a visitarla. Le han traído por iniciativa propia la siguiente ropa y enseres: - 2 camisones. - 3 camisetas interiores. - 3 jersey negros. - 1 chaqueta de botones negra. - 1 vestido (este no es nuevo lo tenían en su domicilio cuando la atendían). - 1 pantalón elástico negro. - 9 pares de calcetines negros. - 1 manta para la silla - 1 zapatillas de parafarmacia (con velcros en los laterales)negras. - 1 champú. - 1 gel de ducha. - 1 crema hidratante. - 1 cepillo de pelo. Todo es nuevo menos el vestido que ya era de la señora. Te lo envío para que estés al corriente de todo y la petición que me han hecho, así cuando os reunáis sabes lo que te pedirán. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-13','TERESA TERE: LÁPIDA: OBTENER UN PAR DE PRESUPUESTOS PARA LÁPIDA MADRE. TERE: TIENE QUE OBTENER CERTIFICADO DEUDA (LO MÁS DETALLADO POSIBLE) + ACLARAR SI YA ESTÁN CARGANDO EL COSTE DE LA PLAZA + PROPUESTA PRESUPUESTO MENSUAL. ALBERTO: MIGUEL INDICA QUE NO CANCELEMOS IBERCAJA HASTA QUE HAGAMOS CANCELACIÓN REGISTRAL HIPOTECA (DE ESTO SE ENCARGA MIGUEL). TOD@S: VENTA DE LA OTRA VIVIENDA: C/ CONSTITUCIÓN (GUADIANA DEL CAUDILLO) • VIVIENDA PARECE QUE ESTÁ EN MALAS CONDICIONES + POSIBLEMENTE REQUERIRÍA REHABILITACIÓN. • MIGUEL HABLA CON TUTELADO Y ESTE HA VERBALIZADO QUE SI CONSIENTE LA VENTA DE ESTA VIVIENDA. • MIGUEL: VA A TRATAR CON LA MISMA INMOBILIARIA DE VENTA ANTERIOR (INFOFINCA-EMILIANO) QUE SE COMPORTÓ MUY EFICIENTEMENTE Y A UN COSTE BAJO. • MIGUEL: NO ES NECESARIO AUTORIZACIÓN JUDICIAL • MIGUEL: OAR PARA VER SI TIENE DEUDAS Y CONFIRMAR SI TENEMOS QUE DOMICILIAR ALGÚN CONCEPTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2021-10-13','El día de hoy,llega mediante correo electrónico un Auto de 4 de Octubre de 2021, por el que se adoptan Medidas cautelares N.º62/2021-0001, solicitadas por el Fiscal y se autoriza el internamiento NO voluntario en la unidad de media estancia del hospital Díaz Ambrona de Mérida.Recurso de apelación:20 días','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-10-13','TERESA el pasado 7 se visitó la casa de Antonia Engracia Lavado del Hoyo situada en la calle Federico García Lorca, 49 2ª Izquierda en Almendralejo. Se hizo acompañados de Antonia Morán de los SSB, y dentro de la vivienda se encontraba un equipo de fontaneros desatascando el baño principal. Se revisó la casa y se hizo una lista con los materiales básicos que la tutelada necesitaría para volver a instalarse: una cama de 105cm, mesilla y lamparilla de noche. Un sofá de dos plazas, mesa camilla y dos sillas, brasero eléctrico y faldas de camilla. Un mueble para el baño y otro tipo alacena para la cocina. Y ropa de cama, almohada y algo de menaje de cocina. Además de lámparas para toda la casa ya que no tiene ninguna. Se fue a una tienda de muebles en Almendralejo que se llama Rapimuebles (924 11 94 09) para pedir presupuesto y asciende a 1.105€. Se adjuntan envía dicho presupuesto. El pasado 8 de Octubre se visitó la tienda Pavo (640 22 34 45) en Almendralejo para pedir presupuesto de la ropa de cama, almohada, brasero eléctrico, toallas, falda de camilla y paños de cocina. El presupuesto asciende a 347,96€ y se adjunta envía en el email. Se observó en la vivienda de Antonia E. Lavado del Hoyo, que la electricidad estaba totalmente inoperativa, de hecho no había ningún enchufe en su sitio, estaban todos arrancados. Por lo que se propone a la comisión que se ponga con contacto con la empresa que está haciendo las reparaciones de la vivienda para que se encargue de ese tema, ya que es algo muy importante para el funcionamiento de una casa. E incluso y si fuera posible, que esta misma empresa instalara las lámparas de toda la casa ya que la vivienda no dispone de ninguna. Además se ha preguntado en las tiendas de muebles de la ciudad por las lámparas de techo y no tienen en ninguna parte. También se han encontrado dos armarios empotrados en la vivienda, y tanto el equipo social comunitario como Antonia Morán de los SSB han pensado que en vez de comprar un armario nuevo, que conllevaría elevar mucho el presupuesto, la empresa de limpieza puede poner una barra para las perchas y algunas baldas para colocar la ropa en uno de los armarios. Habría que resaltar que la vivienda estaba pintada y limpia, pero las puertas de la casa estaban sin pintar y algunas estaban en mal estado. De hecho faltaba la puerta de la habitación principal, y ninguna disponía de tiradores. Y por último, el calentador de agua. En la casa está instalado uno de gas que no está operativo, pero se tiene conocimiento de que Antonia ha tenido problemas con las bombonas de butano, ya que las movía de madrugada e incluso las tiraba por las escaleras del edificio. Por lo que se propondría cambiar ese calentador por uno eléctrico que evitara tener en casa bombonas de butano. Y sería más sencillo de usar para la tutelada. Ya me indicas si hay que hacer alguna gestión más al respecto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-10-13','TERESA opción de conseguir el libro de familia en su vivienda, el único libro de familia que se ha encontrado es el de sus abuelos maternos. De hecho, las compañeras lo trajeron a la oficina con la idea de escanearlo y mandarlo escaneado, y ya aqui, comprobamos que era de Guillermo Gilgado Dávida y Soledad Porras Cordero, (hemos inferido que corresponde a los padres de su madre)- Según nos comenta Pablo el libro de familia de sus padres lo tiene su hermano el que se encuentra en un centro en Don Benito. (Tampoco sabemos si esto es cierto) Contactamos con Luisa la trabajadora social del ayuntamiento de Zalamea y nos indica que en el expediente de Pablo y Guillermo solo tiene el certificado de nacimiento, no el libro de familia ******************************************************* miguel, contestación al email de Tere: Hola Tere, consigue por favor el certificado de nacimiento. El motivo por el que necesito el libro de familia es para hacer la declaración de herederos del hermano fallecido Guillermo. Por lo que dice Toni en su email cabe la posibilidad (aunque parece remota) de que el hermano de Pablo, Julio sepa donde está el libro de familia. Intenta contactar con la trabajadora social de Don Benito para que hable con Julio Galán a ver si él pudiera darnos alguna información…Si no fuera así intentaría hablar con el Registro Civil…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2021-10-13','TERESA NATALIA: HABLAR CON IBERCAJA SOBRE EL SALDO: • FIGURA UN SALDO EL 11/10/201 DE 4.372,27 € PERO FIGURAN COMO RETENIDOS -3.119,2 €: QUE QUIERE DECIR ESTO Y CUAL ES EL MOTIVO DE DICHA RETENCIÓN. • HAY ÚNICAMENTE 2 RECIBOS DEL OAR DE FECHA, AMBOS 13/05/2021: A QUE CORRESPONDEN?: CONCEPTO Y DOMICILIO QUE FIGURA. HAY QUE PASARLE ESTA INFORMACIÓN A MIGUEL • SEGURO DEL HOGAR NORTEHISPANIA: NO ABONAMOS HASTA QUE NO TENGAMOS LAS COSAS MÁS CLARAS. MIGUEL: PLANTEAR LA OPCIÓN DE INICIAR LOS TRÁMITES DE HERENCIA • SE TIENE QUE PONER EN CONTACTO CON OAR PARA INVESTIGAR SOBRE PROPIEDADES YA QUE CATASTRO Y REGISTRO SON NEGATIVOS. • HABLAR CON ÁREA SOCIAL PARA OBTENER INFORMACIÓN SOBRE POSIBLES FAMILIARES O PERSONAS QUE PUEDAN PARTICIPAR DE LA HERENCIA. • INFORMARSE DE IGUAL FORMA DE AQUELLO QUE AFECTA A LA TENENCIA UN UN CICLOMOTOR POR EL TUTELADO TERE: ASISTIR A MIGUEL EN CUANTO A LA INFORMACIÓN DE LA FAMILIA U OTRA QUE SE PUEDA APORTAR PARA EL TEMA DE LA HERENCIA Y DEL CICLOMOTOR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-10-13','Ana: Paso a Julio, CTAEX, para que dé registro, el oficio y solicitud de valoración de dependencia para revisión de grado y de PIA, junto con los informes remitidos por Anabel, TS SSASB Miajadas (Informe Social, Informe Social anexo IV, Informe Salud, Historia Clínica Resumida) y el resto de documentación pertinente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2021-10-13','TERESA Me informa Javi Fraile, que ha tenido un problema al intentar vender una bici que tenía. Pues lo puso en venta por internet y contactaron con el, supuestamente, con el fin de comprarle la bicicleta. Le facilitó ciertos datos como primer nombre y primer apellido, dirección y correo electrónico para que le hiciera el supuesto envió. Acordaron que el hombre se encargaría de los gastos de envío, que supuestamente eran de 100euros. A los pocos días le ha vuelto a escribir extorsionándolo, diciendo que o le mandaba los 100euros, o lo demandará. A mi me impresiona que sea una estafa, para ver si le mandaba el dinero, pero por si acaso, lo pongo en vuestro conocimiento por si ocurriera algo. Ya he hablado con él el hecho de que haga estas operaciones sin consultároslo ni a vosotros, ni a nosotros, pero dice que la idea había sido de su madre para quitarse la bici que le estorbaba en el piso y tener ese dinero por si le hacía falta para algo de la casa. Dice que no volverá a ocurrir, tanto por su parte, como por la de su familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-13','miguel, llamo sin éxito a Emiliano (inmobiliaria Info finca), por lo que le envío email para encargarle la venta del inmueble del curatelado: Buenas tardes Emiliano, conforme te comenté ha sido aceptada por la parte económica y la social de la Comisión tutelar de Adultos la venta del vivienda de la c/ Constitución de Guadiana (Badajoz). Adjunto documentación de catastro, escritura de compraventa y nota simple registral. Me comenta la parte social que la llave la tiene la Trabajadora social del pueblo Inma tlfno 605061530 para que se la pidas y pases a ver la vivienda y nos mandes un informe con la valoración para vender. Asimismo indícame de nuevo tus honorarios y si podrías solicitar el certificado energético (incluyelo en tus honorarios). Comentarte que me indica la parte social que puede haber una posible compradora interesada, cuyo tlfno de contacto es Estela Grillo Moral tlfno 689-115164. Una vez que nos des un precio hablaremos con el curatelado para saber si está o no de acuerdo con las condiciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2021-10-13','Ana: Recibimos DECLARACIÓN JURADA de la P. de Orfandad de Clases Pasivas del Eº (a favor de familiares de militares) para devolverla firmada por el Representante Legal a su Habilitado: Pablo Guillén Caro (info@guillenzancas-habilitados.es / 626 654 440). ··················· Lo pongo para la firma del D.Gerente. ············ Llamo a la oficina del habilitado, en relación al certificado de PFHC que no recibimos, lo solicitarán ellos al Ministerio de Hacienda y me lo remitirán por mail. ·············· El habilitado (zancash@gmail.com) me remite el Cdo. de PFHC (ISFAS) por mail. ······· Se lo reenvío a Longina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-10-14','Ana: Nos remiten desde la Secc. Discapacidad (U.G.P.A.) SOLICITUD DE ELECCIÓN DE CENTRO. Según CADEX su perfil es de RAL. ···· Cumplimento y lo pongo para la firma del D. Gerente (Dejamos la solicitud abierta a todos los centros) ·················· Se lo entrego a Belén, TS Secc. Discap. (UGPPAA), mediante nota interior (escaneado y guardado en su expdte. digital)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELES'and edp.apellido1='MARTINEZ'and apellido2='GAVILAN'),'2021-10-14','Ana: Envío email a Ana, TS de la Res. Virgen de la Asunción de Torres de Don Miguel (gerovida2010@hotmail.com) solicitando CDO. DE INGRESO en centro residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-13','Ana: Envío correo a Mario Estrella, Res. Ntra. Sra. de Guadalupe, en respuesta a su consulta sobre cómo regresará José Manuel a su centro de referencia el día 20 (fecha de alta): "Entiendo que José Manuel podrá realizar el traslado en taxi, si es así, ¿podríais solicitar un presupuesto para dicho traslado y remitírnoslo para que el jefe de la sección económica dé el visto bueno?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-10-14','miguel, llega por email de Tere que le remite Toni de Futuex, Auto del procedimiento DPA Diligencias previas proced. abreviadao 114/2021 del Jzdo 1º instancia e instrucción nº2 Castuera, por posible delito de atentado contra la autoridad (lesiones en junio a un policia local)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-10-14','Ana: Correo de Anabel, TS SSASB Miajadas (servicios.sociales@miajadas.org): "Hola Ana buenos dias! solo informarte de que ayer a ultima hora de la tarde y tras no cesar las alucinaciones de ESTEVE los cuidadores de la vivienda tutelada, se pusieron en contacto con el servicio de urgencias y se tramitó la derivacion a la unidad de psiquiatria del Hospital San Pedro de Alcántara, donde permanece ingresado. saludos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-14','Ana: Subo al portafirmas digital la Aceptación PIA para MANTENIMIENTO DE PLAZA T3. ··························································································································································································· Envío correo-e a Toni-Futuex: "Buenos días Toni, En relación a Manuela Morato Picado, queremos solicitaros que Gloria contacte con un cerrajero y acuda con el mismo a cambiar la cerradura de la vivienda. Te adjunto los siguientes documentos que podría necesitar: - Certificado de catastro, donde certifica que la vivienda es propiedad de Manuela, al 100% - Correo electrónico del nieto comunicando que se trasladaron a otra vivienda - Testimonio de Providencia de Aceptación del Cargo de Tutor Una vez realizado el cambio, necesitaremos que acuda de nuevo, ya con las llaves nuevas, para entrar en la vivienda con el técnico de la compañía del agua, pues vamos a proceder a dar de baja el suministro. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='CASARES'and apellido2='MARISCAL'),'2021-10-14','Amalia : llama Victoria , TS de Alburquerque 924400000 , es posible que cierren la R.M. por falta de cuidadoras que no cobran y habria que trasladar a Prudencio a otra residencia. Abona el 65 % de la plaza,a pesar de no estar concertada con el SEPAD , es de gestión municipal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-10-13','Maite: Manuela y yo hemos hablado con Oscar y Julia del CEE de INCLUSIVES, para ver con ellos la oportunidad de adjudicar plaza a marta en el centro de Plena Inclusión de Cabeza del Buey, para evitar un mayos desarraigo de Marta y facilitar su ingreso. Después hablé con Carolina, trabajadora social del programa de familia de cabeza del Buey ( 924 76 06 33)para que me informase sobre la situación de Marta en Peñalsordo, ya que la semana pasada la psicóloga y élla visitaron a Marta. Me dice que se encuentra bien, en cuanto a cobertura de necesiadades básicas y que se siente protegida. Marta está viviendo con su novio José Teodoro ( 28 años y discapacidad)y la madre de éste. La relación es buena . Pero Carolina afirma que es un entorno carente de estímulos, que no favorece su desarrollo personal, social, laboral y /o académico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-13','TERESA HABLO CON TONI TS PARA QUE ME PASE CERTIFICADO DE DEUDAS CON EL CENTRO PRESUPUESTO MENSUAL GASTOS DE BOLSILLO PRESPUESTO LAPIDA PARA NICHO DE SU MADRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2021-10-14','Ana: Envío correo a María Bueno, PNC (maria.buenomar@salud-juntaex.es): "Buenos días María, ¿qué tal estáis? No sé si tendréis algún problema con la línea de teléfono, pues no permite completar la llamada a ninguno de los números que tengo vuestros. En relación a la petición de Alta de Terceros que no hacéis de dos de los últimos cargos aceptados por la CTAEX: - Juan José González Carrero - Adela Sole Latorre Comunicaros que aún no ha sido posible añadir al representante legal en su cuenta bancaria, por lo que se va a demorar, aún más, la gestión de solicitud del Alta de Terceros. En cuanto lo tengamos os lo hacemos llegar. Solicitaríamos por favor, que no procedan a la suspensión del pago de las PNC. Ante cualquier cuestión, no dudéis en contactar. Gracias y buena mañana." ····························································································································································································· Respuesta de María Bueno: "Hola Ana! Isabel Durán, Jefa de Sección ,me ha comentado q ya ha hablado con vosotras de este tema y que no hay problema alguno, pues no sería motivo de suspensión . Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2021-10-14','Ana: Envío correo a María Bueno, PNC (maria.buenomar@salud-juntaex.es): "Buenos días María, ¿qué tal estáis? No sé si tendréis algún problema con la línea de teléfono, pues no permite completar la llamada a ninguno de los números que tengo vuestros. En relación a la petición de Alta de Terceros que no hacéis de dos de los últimos cargos aceptados por la CTAEX: - Juan José González Carrero - Adela Sole Latorre Comunicaros que aún no ha sido posible añadir al representante legal en su cuenta bancaria, por lo que se va a demorar, aún más, la gestión de solicitud del Alta de Terceros. En cuanto lo tengamos os lo hacemos llegar. Solicitaríamos por favor, que no procedan a la suspensión del pago de las PNC. Ante cualquier cuestión, no dudéis en contactar. Gracias y buena mañana." ··························································································································································································· Respuesta de María Bueno: "Hola Ana! Isabel Durán, Jefa de Sección ,me ha comentado q ya ha hablado con vosotras de este tema y que no hay problema alguno, pues no sería motivo de suspensión . Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2021-10-14','-Amalia : Se ha trasladado de CSS a P.Supervisados de Mérida . Ya se ha cuadrado pto. con Manuel Picado. Hecho el plan de intervención, percibe PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2021-10-14','TERESA OK A PRESUPUESTO MENSUAL DE 40 €/MES CON REINTEGRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-10-14','TERESA Con respecto al tema del pago farmacéutico de Pablo le han cambiado el código y le sale a pagar los gastos farmacéuticos, entiendo que debe haber un error. Hay que ir de manera presencial al INSS para ver que ha pasado pues no me cogen el teléfono. Este es el teléfono de cita previa 924805042, creo que es mas operativo que pisa Susana la cita para que la pueda adaptar a su agenda….','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-10-14','miguel, envío contestación a Dirección General de Servicios sociales, infancia y familia (Servicio de Prestaciones) en relación a la petición de documentación del hermano del curatelado que según un certificado de empadronamiento erroneo indicaba que vivian juntos en otro domicilio. El escrito que remito indica que vive sólo en c/Cristobal Colón de Alcuescar (Cáceres)y por tanto solicito levanten la suspensión con carácter retroactivo de su pensión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-10-14','miguel, me llama Ana Soria para preguntarme si quiero copia simple, la indico que sí y me envía la factura de la ratificación de la compraventa de Azkoitia para que se la abonemos. Remito email a Alberto e Iciar: Hola tenéis que comprobar que han ingresado ya en su cuenta el abono de la venta del inmueble, caso contrario decídmelo para hablar con la abogada. Os adjunto la factura de la notaria por la ratificación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-10-14','miguel, mando email a la abogada Ana de Pablo: Buenos días Ana, ya habéis hecho el ingreso del dinero de la venta? No se pueden demorar más, el ingreso debe estar hecho en pocos días. Manténgame informado ya que hay que notificar al juzgado dicha venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2021-10-14','miguel, me pregunta Tere que cómo vemos el vender el solar de Calera de León que está a nombre de los herederos de Aurora Chavez Caballero. Contesto en email a Alberto, Tere y Angel: Hola, para poder vender previamente habría que hacer el pago del impuesto de sucesiones y la adjudicación de la herencia para lo cual necesitamos de Aurora Chavez Caballero: -Libro de familia -Certificado de defunción -Últimas voluntades -Testamento si lo hubiera -Nota simple del registro de la propiedad de posibles bienes que haya dejado la fallecida -Certificado de saldo bancario a fecha del fallecimiento de las cuentas de que fuera titular. Una vez que estuviera hecho dicho pago del Impuesto de sucesiones, tendría que solicitar al juzgado autorización de aprobación de herencia y autorización de venta para lo cual habría que contratar a un abogado ya que dispone según la última rendición de cuentas de unos 21.000€. Todo ello si decidís venderlo ya que por lo que veo, en cuanto su capacidad económica no parece que le haga falta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-10-14','miguel, voy presencial con Jose Vicente a firmar, a Liberbank (Juana Heras), acuerdo privado para el desbloqueo del FONDO DE INVERSION. Ayer fue firmado por su hermana (que fue acompañada de su sobrino) ******************************************** Me indicó ayer Juana Heras por email: Miguel, como te he comentado, ya ha firmado la hermana de la tutelada y la oficina me contesta esto: Coméntale también que la hermana que no está tutelada se persone el martes para firmar el reembolso del fondo porque nos pide recoger firma digital de al menos un titular. Viven en Navas del Madroño. Por favor, comunicádselo a Josefa Felipe Teomiro. Ya no está en la oficina y no tengo forma de contacto. **************************************** Le remito email al sobrino José Cabrera: Buenas tardes, me comenta la oficina que os avise de que tenéis que acercaros a la oficina donde firmaron el Fondo de Inversiones para dejar finalizado el desbloqueo. Adjunto el email que me ha mandado Juana Heras de la oficina de Mérida. Mañana por la mañana iré con el Gerente del SEPAD a firmar el desbloqueo a la oficina de Juana Heras. Saludos. ******************************************************** Contestación del sobrino José Cabrera: Vale pero si mi madre que es la que no esta tutelada para que tiene que ir el martes a firmar otravez si ya a ido hoy? Es que ella no se lleva bien con el de esta oficina y no estoy para ir con ella no puede hacerlo en otro pueblo que estoy yo y voy con ella? Tendria que ser en navas si o si? **************************************************** remito email a José Cabrera: Buenas tardes, ya hemos firmado el documento privado en Liberbank y por tanto debería valer así para el desbloqueo. Si les parece hablen con su oficina pasados unos días si no se hubiera hecho el ingreso en la cuenta indicada nº ES86-2048-1239-49-3000023645','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2021-10-14','miguel, voy con José Vicente para hacer el poder apud acta al juzgado de Mérida, y en concreto para procedimiento de desahucio que ha de tramitarse por un tribunal de arbitraje de Badajoz (lugar donde está la vivienda alquilada) ************************************************ Remito email al abogado Jorge Calvo y la Procuradora Cristina: Buenas tardes, adjunto poder apud acta a favor de Cristina. Me comenta el Juzgado que tenía que indicar la localidad competente, que entiendo que es Badajoz (donde se encuentra ubicada la finca). Lo digo por el problema que tendréis para la designación de árbitros. Confirmadme que es correcto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='CUEVAS'and apellido2='MOYANO'),'2021-10-14','-Concluido Plan de Intervención,lo paso a seguiiento de Tere .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-14','miguel, recibo email de Amalia (dirigido a Alberto, Maite y a mi): Buenos días , solicito reunión urgente para el lunes o martes de la semana que viene con la familia de Alejandro Núñez Bono. Propongo martes día 19 a las 10.00. Espero confirmación de todos vosotros para trasladárselo a la familia ********************************************** mi contestación: Hola, por mi parte no hay problema para reunirnos pero no tengo de que tratar debido a que todavía no tenemos respuesta de su abogada Soledad Carreres para que nos diga si llegan o no a un acuerdo con las hermanastras y su abogado Carlos Jurado para el reparto de la cuenta de los 147.000€. Nos puedes aclarar si es una reunión con su familia o sólo nosotros? ******************************************************* contestación de Amalia: La familia me dice que ya tienen acuerdo con el abogado , solicitan reunión urgente para tratar varios temas y como afecta a todas las secciones considero que es más eficiente hacer una reunión en que estemos todos ************************************************* Envío email a la abogada de la familia Soledad Carreres: Buenos días Soledad, podrías informarme de en qué estado se encuentran los trámites de la cuenta?. Me comentan en la oficina que la familia ha pedido una reunión urgente con la Comisión y me gustaría estar plenamente informado antes de hablar con ellos **************************************************** Envío email al abogado de la otra parte Carlos Jurado: Buenos días Carlos, nos comenta la familia que habéis llegado a un acuerdo acerca de la cuenta, pero a fecha de hoy ni Soledad ni la familia me ha concretado nada. Es correcto? Podrías llamarme o aclarármelo? ********************************* Contestación de Alberto: Hola Personalmente estoy de vacaciones la semana que viene. Me incorporo al trabajar el lunes 25 o el martes 26 de octubre, aún no lo se. Con respecto a la reunión en si misma, mi opinión es que si no sirve para poder darles soluciones económicas distintas a las que les estamos dando actualmente, no tiene sentido. Me refiero a que si Miguel no tiene documentación con la que valorar lo que dice la familia es inútil. Que nos la remitan Miguel ha tenido y tiene contacto con la abogada de la familia Nuñez Bono y con el abogado de la otra familia. Ninguno de los 2 le ha informado de nada relativo a la existencia de un acuerdo. De todas formas Miguel ha vuelto a ponerse en contacto con ambos y está a la espera de ver que le indican. A nivel ECO: ya sabemos que le estamos dando todo y que no podemos darles más. La reunión, si nos va a ocupar a todas las áreas, debe tener un sentido. Soy de la opinión de que, en cuanto Miguel tenga algo que permita avanzar o tomar decisiones, consensuadas o no con la familia Nuñez Bono, celebremos esa reunión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-14','miguel, hablo con el abuelo y le contesto a Amalia, Maite y Alberto: Amalia, acabo de hablar con el abuelo Pedro quien me confirma que ellos no vendrán. Ya le he dicho que cuando tengamos la información de soluciones económicas les llamaremos. Le he comentado que cuando tenga por escrito el acuerdo al que han llegado daré traslado a la parte económica y social. Y en cuanto a la parte de la salud, le he recomendado que los psiquiatras le hagan una hoja de ruta y trabajen en ello. Por tanto no habrá reunión con la familia por ahora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-10-15','Ana: Envío correo-e a María, TS de Autismo Sur (teayudamos@autismosur.es): "Buenos días María, En relación a los gastos que detalláis relativos a Costi Alexandru Rizea y tras mantener una reunión con los respectivos jefes de la CTAEX, secciones económica y social, me pongo en contacto contigo para pediros que nos aclaréis los siguientes conceptos: - La cuota de socio protector, ¿qué ventajas supone exactamente para Alex? Necesitamos saber en qué consiste para valorar si se seguirá abonando o no, pues como bien habéis calculado, Costi va a andar muy justo a nivel económico y al Jefe de sección, con buen criterio, le gusta ir ahorrando algo anualmente de cara a imprevistos y gastos urgentes sobrevenidos. - En cuanto a la aportación de vehículo de paseo, también necesitamos saber con exactitud qué salidas mensuales realizáis con él. - Por último querríamos saber qué gastos de farmacia (medicamentos, cremas…) tiene Alex que no entren por la Seguridad Social, pues a partir de ahora, al percibir la PNC, está exento de abonar medicamentos. En cuanto al resto de cuestiones relativas al banco, abono de la deuda contraída en vuestra entidad, lo de la autorización que solicitabais y demás las compañeras de la sección económica están en ello. Se pondrán en contacto con vosotros próximamente, pues no está siendo fácil las gestiones con la entidad bancaria en cuestión. Ni siquiera han podido comprobar si ya le han ingresado la pensión. Sé que la situación de la entidad es delicada y que Alex lleva muchos meses sin abonaros nada, pero os pedidos algo más de paciencia. Gracias por la comprensión. Un saludo y buen día." ···························································································································································································· Respuesta de María: "Buenos tardes, En cuanto a la cuota de Socioprotector, es una cantidad que beneficia a las personas usuarias en descuentos de actividades que realizamos de forma lúdica... rebajas en entradas de parques de atracciones, cine, revisiones de podólogo, peluquería, piscina, heladerías, cafeterías, comidas MCDONALS. cosas que hasta ahora la diferencia de precio la estamos asumido y creemos que son esenciales para vida... Al igual en cuanto a la declaración de l renta es deducible, en el caso de realizarla... Vehículo de paseo lo usan para la realización de todas las salidas que realizamos diariamente... asistencia al medico...Está esta opción o que se muevan en taxis.... En cuanto a Farmacia... nos entregan las facturas... hay cosas que recetan los sanitarios que si tienen coste... Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-10-15','Ana: Correo de Anabel, TS SSASB Miajadas (servicios.sociales@miajadas.org): "Buenos días Anabel, Quería pedirte un favor, mi compañero solicitó un certificado de empadronamiento al Ayuntamiento de Miajadas relativo a Esteve Pascual Ramos la semana pasada. Nos lo solicitan desde el Servicio de Prestaciones Sociales, para que pueda comenzar a percibir la PNC. ¿Podrías preguntar por el mismo y, en su caso, agilizarlo? Más que nada porque nos han dado un plazo para contestar. Por cierto, ¿os han informado desde el hospital sobre cómo sigue Esteve? Gracias y buena mañana." ················· Respuesta de Anabel: "Buenos dias! En cuanto al certificado de empadronamiento fue remitido el 13/10/21, adjunto el oficio y el certificado. En lo relacionado con el Hospital ayer hablamos con el psiquiatra y dijo que lo quedaria ingresado unos dias, puesto que aunque es cierto que el nivel de agresividad no era excesivo, el grado de inquietud y mal estar debido a las alucinaciones persistentes, hacia necesario una revision del tratamiento. saludos" ············ Guardo expte. ··········· Preparo oficio y entrego a Julio, CTAEX, para registrar el Documento de ELECCIÓN DE PNC y enviarlo al Serv. de Prestaciones Sociales, junto al Alta de Terceros y Cdo. de Empadronamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-10-14','Maite: He enviado a Belén, trabajadora social de Talarrubias, la solicitud de revisión de prestación vinculada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-10-14','Maite:He hablado con Guadalupe, hermana de Marta, con la que tiene muy buena relación.Le comneté la posibilidad de que Marta resida en el centro de PLena Inclusión Cabeza del Buey. Y le pedí que hablase con élla para convencerla, ya que no quiere. Lo hara en los próximos dias. Me comentó que Marta se encuentra muy bien viviendo con su novio y la madre de éste.Está tranquila y entre ellos hay buena relación. También me dijo que MArta está usando métodos anticonceptivos ( parches) y que han pedido cita en planificación familiar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-15','Ana: Paso a Julio, Aux. Admvo. CTAEX: Oficio, dirigido a Plácido Alejandre, Jefe Secc. Centros II, para registrar la Aceptación del PIA para MANTENIMIENTO DE LA PLAZA T3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-15','miguel, llega email de Emiliano (Infofinca): Buenos días Miguel te adjunto una copia de la escritura de venta del dúplex sito en Guadiana en la Calle El Hinojo propiedad de vuestro tutelado Don Juan Carlos Rubio Galan. Hemos realizado en el día de ayer la visita a la vivienda también de su propiedad en la calle Constitución 13, ya te mandaré el informe, te adelanto que han debido de entrar en la vivienda, pues estaba una puerta que da con el patio abierta, todo revuelto, gatos en el interior de la vivienda, lleno de excrementos, bueno resumiendo en un estado ruinoso, ya te mandaré fotos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='GONZALEZ'and apellido2='SILVA'),'2021-10-15','KIKE: LLama Florencio del Cuartillo cuyo tfno corto es 22161 indicando que a la hermana se le está cobrando la misma deuda que al hermano(deuda expediente EXP06052100037). Deuda que se reclamo en su día por esta comisión y que hemos conseguido quitarla.Realizar los mismos trámites con ella','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-10-15','Ana: Envío a Alberto, factura que hay que abonar de unas zapatillas que necesitaba Valentina. *Recuerdo a la Res. el modo de proceder: Necesario presupuesto previo. ···················· Envío también a Alberto el siguiente correo de Ana, Enfermera de la Res. Femar (residenciafemar2019@gmail.com): "Buenas tardes Ana : soy Ana enfermera de la residencia FEMAR . El acompañamiento seria desde que sale de la residencia en la ambulancia hasta que regresa , y el precio es 50 euros tarde lo que tarde . La chica que la acompaña cuando llega aqui nos informa de los cambios o advertencias que indique el doctor y nos dara documentación remitidda por el cardiologo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2021-10-14','Ana: Correo de Teresa Nogueira, TS Novaformra (trabajadorasocial.novaforma@gmail.com): "Buenas tardes, os informo ; Que este fin de semana del día 15 al 17 se realizara la salida a la "Aldea de Yuste", de los siguientes tutelados: Álvaro González Álvarez Felipe Blanco Guisado Fermín García Pablos Eduardo Rivera Torio Manuel Blázquez"','2');
