insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2021-10-14','Ana: Correo de Teresa Nogueira, TS Novaformra (trabajadorasocial.novaforma@gmail.com): "Buenas tardes, os informo ; Que este fin de semana del día 15 al 17 se realizara la salida a la "Aldea de Yuste", de los siguientes tutelados: Álvaro González Álvarez Felipe Blanco Guisado Fermín García Pablos Eduardo Rivera Torio Manuel Blázquez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-10-15','miguel, me llama Ana de Pablo y escribe un email comentando lo mismo, que el cheque le dicen en la Caixa es válido y que me lo remitirá para su ingreso: desde la Caixa nos dicen que el cheque no es nulo pese a la firma que se hizo en el reverso, y que el representante del tutelado lo puede ingresar directamente en su cuenta presentando el poder que ostenta. De esta manera, si le parece bien, le envío el mencionado cheque por correo certificado a la dirección que usted me indique para que les llegue lo antes posible. En cuanto a los 7.000€ que se percibieron a la firma del contrato de Arras y de los cuales 1.750€ corresponden a D. José Luis Murillo, si le parece bien, se puede alegar al Juzgado que su tutelado está pendiente de percibir porque dicho importe se destinó a sufragar los gastos notariales, de Registro y de mantenimiento de las fincas heredadas, cuya liquidación se presentará al finalizar las operaciones de venta de todas las fincas. Quedando a la espera de su respuesta, reciba un cordial saludo ******************************************* Le envío nuestra dirección para intentar ingresarlo: Buenos días, conforme hemos hablado le indico nuestra dirección. Servicio Extremeño de Protección de la Autonomía y Atención a la Dependencia (SEPAD) Comisión Tutelar de Adultos A/A Miguel Fernández Avda de las Américas 4, 06800, Mérida (Badajoz) Quedo pendiente que a ser posible el cheque llegue por mensajería entre lunes y martes próximo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='BLAZQUEZ'and apellido2='SANDOVAL'),'2021-10-14','Ana: Correo de Teresa Nogueira, TS Novaformra (trabajadorasocial.novaforma@gmail.com): "Buenas tardes, os informo ; Que este fin de semana del día 15 al 17 se realizara la salida a la "Aldea de Yuste", de los siguientes tutelados: ... Manuel Blázquez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2021-10-14','Ana: Correo de Teresa Nogueira, TS Novaformra (trabajadorasocial.novaforma@gmail.com): "Buenas tardes, os informo ; Que este fin de semana del día 15 al 17 se realizara la salida a la "Aldea de Yuste", de los siguientes tutelados: Álvaro González Álvarez Felipe Blanco Guisado Fermín García Pablos Eduardo Rivera Torio Manuel Blázquez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-15','miguel, llega email de Amalia: Buenos días , ayer se presentó en el Servicio Territorial del SEPAD la abuela de Alejandro Núñez Bono . Cómo todos sabéis , no se atiende sin cita previa , los interesados tienen que llamar y si es algo relacionado con mi intervención social les doy cita en el edificio Sara , puesto que en el SEPAD no se dispone ni de sala de reuniones ni de vigilante de seguridad. La Sra. vino dando voces e insultando , las ordenanzas le dijeron que llamase para pedir cita pero ante la agresividad verbal , le dijeron que pasase y me buscara. Montó una trifulca tremenda , a mí me insultó y mi amenazó porque no se le da el dinero que piden . Exigía que se le diera cita para hablar con" los jefes ", que están hartos de llamar a la parte económica y no se les atiende . Y que llaman a Pedro y tampoco se lo coge. Yo les volví a explicar su situación económica , que siguen sin compartir , les indiqué que pueden dirigirse al juzgado donde rendimos cuentas anuales si quieren más explicación , pero nada más puedo hacer . Decía que venía derivada por Miguel el jurídico , insisten en que les ha dicho que todas las facturas y todo lo que tengan pendiente tienen que venir hablar conmigo. Ovbiamente Miguel, debe ser un mal entendido que te agradecería que les aclarases. Acepté a que entregasen documentación jurídica que le habías solicitado, pero a partir de este momento , todo lo que tengan que enviar que lo hagan por correo a nuestra dirección postal. Hubo un momento de bastante tensión , y aquí no tengo protección ninguna , ni siquiera puedo moverme de mi asiento. Hay 6 compañeras sentadas en la misma sala que lo pasaron fatal. Exigía una cita para que se les atienda personalmente para informarles de todo lo relacionado con su nieto . Me comentaba también que ya habían alcanzado un acuerdo con sus abogados , asunto que yo tampoco podía resolver . Las ordenanzas han expuesto sus quejas ante esta situación a la Gerente que ya conoce todo lo sucedido y con la que estoy pendiente de reunirme. Informo de todo lo ocurrido , y voy a presentar la denuncia pertinente siguiendo el protocolo de prevención de riesgos laborales. A petición de esta señora solicité a todas las secciones una cita en la que puedan acudir y se les aclare la situación en Mérida . Al parecer Miguel habló con el abuelo que le indicó verbalmente que no van a acudir . Creo que sería conveniente enviarles una citación por correos y si no acuden a la cita no podrán denunciar que no se les atiende . Alberto , la situación es parecida a la que se produjo con Mercedes P.P. , acudía al SEPAD exigiendo que yo le diese el dinero que reclamaba. Si ves alguna opción ,desde la sección económica , con la que se puedan evitar y prevenir estas situaciones tan conflictivas agradecería tu intervención. En favor de la señora , he de decir que su estado de desesperación es extremo. Alejandro les agrede verbal y físicamente tanto a ella como a su abuelo y a la madre. También a los vecinos . La agresividad es cada vez mayor .Esta semana ha roto el ascensor del bloque , y ha roto en varias ocasiones el cuadro del telefonillo ... La policía acude al domicilio en innumerables ocasiones y la solución que le dan a la familia es que desde la Junta se le tiene que buscar un recurso. La probabilidad de riesgo es muy alta y la gravedad extrema , con peligro para la integridad física de los familiares , vecinos , y profesionales como yo misma . Desde la parte social y puesto que es curatela económica y de la salud , he solicitado recursos tanto de discapacidad como de salud mental . Todas las resoluciones vienen denegadas por no cumplir pérfil por consumo de drogas. Así mismo , le he gestionado derivación a los Equipos de Conducta Adictiva , no puede ingresar en Comunidad terapeútica , primero por su no voluntariedad que se exige para el ingreso y segundo por su discapacidad . He mantenido numerosos contactos telefónicos y presenciales con el Equipo de Salud Mental . El psiquiatra indica a la familia y que avisen al 112 ante incidencias graves con la idea de que ingrese en la UHB . Incluso ha hecho un escrito en Jara para que los psiquiatras de guardia que pudieran atenderle lo queden ingresado .Pero cuando se activa el 112 y acuden al domicilio o él se escapa , o le ponen un inyectable y en alguna ocasión que ha llegado a ingresar en la UHB le han dado el alta a las horas . A petición de la TS de ese ESM , solicita que dado que somos curadores para la esfera sanitaria se solicite desde la Comisión internamiento involuntario en CSS de Mérida . Estoy de acuerdo con esta petición , y creo que podría ser una solución para intervenir en este caso . Así mismo propongo, si lo estimáis convenientes, reunión de equipo para abordar todo lo que os he comentado . ************************************************* mi contestación: Buenos días, vaya por dios, siento lo sucedido, no sabía nada. Entiendo por lo que dices que no deberían haberla dejado pasar al edificio. Por otra parte entiendo que deberías recapitular todas las incidencias y o bien se comunica al juzgado o bien se solicita la ampliación a tutela (si lo estimáis necesario) con la finalidad de solicitar un internamiento involuntario (el cual veo complicado por su dependencia, y ejemplos tenemos como el de Pablo Galán) Comentarte que me llamó ayer el abuelo y nada me comentó del percance, únicamente me indicó la imposibilidad para contactar con nosotros motivo por el que le di el email de ctutelar. Se queja de que tiene que estar pagando gastos de su nieto y le dije que mande los presupuestos a la parte económica (ya he hablado con Alberto y tiene una asignación mensual a la que tendrá que ajustarse). Ignorando lo sucedido le comente lo mismo que a ti, que no tenía información hasta que el abogado contestara y por tanto de nada serviría que vinieran. Yo no les he dado las instrucciones que comentas, únicamente les he dicho que las incidencias las hablen con la trabajadora social quien lo comunica a la Comisión, pero nada de llevarte documentación. Esta mañana he hablado con el abogado y me ha comentado que me mandará un borrador del acuerdo para que lo completemos, modifiquemos, etc. Parece ser que van a repartir la cantidad entre las dos hermanastras, la madre de Alejandro y Alejandro. Concretas sólo me ha sabido decir las cifras de las hermanastras, 35.000€ cada una. Cuando queráis hacemos una reunión para tomar decisiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-10-15','Ana: Llamo a Julia Hdez., madre de Julia (644 876 893): le informo que hay que tener paciencia en cuanto a la valoración de dependecia pues va con mucha paciencia. ············ En cuanto a los 100€ que solicitan, le comunico que Alberto, Jefe de secc. ecca., me ha indicado que es imposible, pues apenas tienen dinero en la cuenta. ··········· Ella me informa de que el día 4 de noviembre Julia tiene cita en Psiquiatra - ESM de Coria. ··············· Hablo también con Julia, para aclarar cómo está la situación con respecto a su solicitud de centro y el tema económico. Está nerviosa y un tanto desesperada por irse a un centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-15','Buenos días, vaya por dios, siento lo sucedido, no sabía nada. Entiendo por lo que dices que no deberían haberla dejado pasar al edificio. Por otra parte entiendo que deberías recapitular todas las incidencias y o bien se comunica al juzgado o bien se solicita la ampliación a tutela (si lo estimáis necesario) con la finalidad de solicitar un internamiento involuntario (el cual veo complicado por su dependencia, y ejemplos tenemos como el de Pablo Galán) Comentarte que me llamó ayer el abuelo y nada me comentó del percance, únicamente me indicó la imposibilidad para contactar con nosotros motivo por el que le di el email de ctutelar. Se queja de que tiene que estar pagando gastos de su nieto y le dije que mande los presupuestos a la parte económica (ya he hablado con Alberto y tiene una asignación mensual a la que tendrá que ajustarse). Ignorando lo sucedido le comente lo mismo que a ti, que no tenía información hasta que el abogado contestara y por tanto de nada serviría que vinieran. Yo no les he dado las instrucciones que comentas, únicamente les he dicho que las incidencias las hablen con la trabajadora social quien lo comunica a la Comisión, pero nada de llevarte documentación. Esta mañana he hablado con el abogado y me ha comentado que me mandará un borrador del acuerdo para que lo completemos, modifiquemos, etc. Parece ser que van a repartir la cantidad entre las dos hermanastras, la madre de Alejandro y Alejandro. Concretas sólo me ha sabido decir las cifras de las hermanastras, 35.000€ cada una. Cuando queráis hacemos una reunión para tomar decisiones. Saludos. firma miguel 2019 Amalia Diaz Gonzalez Vie 15/10/2021 10:08 Buenos días , ayer se presentó en el Servicio Territorial del SEPAD la abuela de Alejandro Núñez Bono . Cómo todos sabéis , no se atiende sin cita previa , los interesados tienen que llamar y si es algo relacionado con mi intervención social les doy cita en el edificio Sara , puesto que en el SEPAD no se dispone ni de sala de reuniones ni de vigilante de seguridad. La Sra. vino dando voces e insultando , las ordenanzas le dijeron que llamase para pedir cita pero ante la agresividad verbal , le dijeron que pasase y me buscara. Montó una trifulca tremenda , a mí me insultó y mi amenazó porque no se le da el dinero que piden . Exigía que se le diera cita para hablar con" los jefes ", que están hartos de llamar a la parte económica y no se les atiende . Y que llaman a Pedro y tampoco se lo coge. Yo les volví a explicar su situación económica , que siguen sin compartir , les indiqué que pueden dirigirse al juzgado donde rendimos cuentas anuales si quieren más explicación , pero nada más puedo hacer . Decía que venía derivada por Miguel el jurídico , insisten en que les ha dicho que todas las facturas y todo lo que tengan pendiente tienen que venir hablar conmigo. Ovbiamente Miguel, debe ser un mal entendido que te agradecería que les aclarases. Acepté a que entregasen documentación jurídica que le habías solicitado, pero a partir de este momento , todo lo que tengan que enviar que lo hagan por correo a nuestra dirección postal. Hubo un momento de bastante tensión , y aquí no tengo protección ninguna , ni siquiera puedo moverme de mi asiento. Hay 6 compañeras sentadas en la misma sala que lo pasaron fatal. Exigía una cita para que se les atienda personalmente para informarles de todo lo relacionado con su nieto . Me comentaba también que ya habían alcanzado un acuerdo con sus abogados , asunto que yo tampoco podía resolver . Las ordenanzas han expuesto sus quejas ante esta situación a la Gerente que ya conoce todo lo sucedido y con la que estoy pendiente de reunirme. Informo de todo lo ocurrido , y voy a presentar la denuncia pertinente siguiendo el protocolo de prevención de riesgos laborales. A petición de esta señora solicité a todas las secciones una cita en la que puedan acudir y se les aclare la situación en Mérida . Al parecer Miguel habló con el abuelo que le indicó verbalmente que no van a acudir . Creo que sería conveniente enviarles una citación por correos y si no acuden a la cita no podrán denunciar que no se les atiende . Alberto , la situación es parecida a la que se produjo con Mercedes P.P. , acudía al SEPAD exigiendo que yo le diese el dinero que reclamaba. Si ves alguna opción ,desde la sección económica , con la que se puedan evitar y prevenir estas situaciones tan conflictivas agradecería tu intervención. En favor de la señora , he de decir que su estado de desesperación es extremo. Alejandro les agrede verbal y físicamente tanto a ella como a su abuelo y a la madre. También a los vecinos . La agresividad es cada vez mayor .Esta semana ha roto el ascensor del bloque , y ha roto en varias ocasiones el cuadro del telefonillo ... La policía acude al domicilio en innumerables ocasiones y la solución que le dan a la familia es que desde la Junta se le tiene que buscar un recurso. La probabilidad de riesgo es muy alta y la gravedad extrema , con peligro para la integridad física de los familiares , vecinos , y profesionales como yo misma . Desde la parte social y puesto que es curatela económica y de la salud , he solicitado recursos tanto de discapacidad como de salud mental . Todas las resoluciones vienen denegadas por no cumplir pérfil por consumo de drogas. Así mismo , le he gestionado derivación a los Equipos de Conducta Adictiva , no puede ingresar en Comunidad terapeútica , primero por su no voluntariedad que se exige para el ingreso y segundo por su discapacidad . He mantenido numerosos contactos telefónicos y presenciales con el Equipo de Salud Mental . El psiquiatra indica a la familia y que avisen al 112 ante incidencias graves con la idea de que ingrese en la UHB . Incluso ha hecho un escrito en Jara para que los psiquiatras de guardia que pudieran atenderle lo queden ingresado .Pero cuando se activa el 112 y acuden al domicilio o él se escapa , o le ponen un inyectable y en alguna ocasión que ha llegado a ingresar en la UHB le han dado el alta a las horas . A petición de la TS de ese ESM , solicita que dado que somos curadores para la esfera sanitaria se solicite desde la Comisión internamiento involuntario en CSS de Mérida . Estoy de acuerdo con esta petición , y creo que podría ser una solución para intervenir en este caso . Así mismo propongo, si lo estimáis convenientes, reunión de equipo para abordar todo lo que os he comentado . Un saludo.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2021-10-15','Buenos días , solicito Nº cuenta donde esté incluido el Dtor .-Gerente para REMEDIOS SANCHEZ MORENO para solicitar cambio de titularidad de la PHHC . Solicito cambio de titularidad de la PFHC. Por el momento y hasta hacer seguimiento de la tutelada no se bloquean las cuentas. Seguirá retirando como lo viene haciendo . Seguimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2021-10-15','TERESA NUEVO NUMERO DE EMI 633810132','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-10-11','Ana: Correo de Toni-Futuex con el seguimiento de los meses de Sep-oct. ·········· Según las notas, la Dra. Güendolina, Psiquiatra, "comenta que no lo conoce porque no ha acudido a ninguna de sus citaciones" ······· Adjunta informe de Alta del ingreso hospitalario en Medicina Intena, en el que se especifica que NO ESTÁ TOMANDO EL TRATAMIENTO PAUTADO POR PSIQUIATRÍA. *El ingreso se debió a insuficiencia cardiaca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-15','miguel, envío nuevo email a Maite, Alberto y Amalia: Hola comentaros que acabo de hablar con Soledad Carreres la abogada y me confirma el acuerdo al que han llegado y la preocupación de que Alejandro no intente coger el dinero ni de la madre ni el que se le asigne. Veo que tiene cuenta en el Santander, propongo a la parte económica que abra una cuenta en Liberbank para tenerla controlarla y ahí se le ingrese el dinero. Creo que a fecha actual tiene unos 138.000€, me confirma la abogada que han llegado a un acuerdo por el dinero que se le debía a la madre, ya que esta ejecución de sentencia (por incumplimiento del convenio regulador) ascendía a 48.000€ que sería mucho más si sumamos intereses y costas de un posible procedimiento. Por tanto cada hermanastra se quedará con 35.000€ y la madre de Alejandro con 45.000€ y la diferencia de lo que quede Alejandro, que creo salen unos 23.000€. La semana que viene espero me envíen el borrador para que lo estudiemos y firmemos. Por mi parte estoy de acuerdo en principio con dicho acuerdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-10-15','Ana: Guardo en el expdte. el informe de Interconsulta de Psiquiatría, que me remitió Mamen, TS HSPA. Y le envío correo (maria.alvarezs@salud-juntaex.es): "Buenas tardes Mamen, ¿Qué tal? A ver si el lunes podemos hablar de este paciente, que al final solicitó el alta voluntaria. ¿Tú solicitaste la valoración de dependencia o alguna otra cosa? Ya me dices. Un saludo y buen fin de semana." ································································································································································································ Llamada del hermano de Martín, nos pide que solicitemos la ampliación de la curatela a la esfera de la salud. Mamen, TS - HSPA, le propuso ingreso en C. Residencial de mayores, en plaza privada, pero lo rechazó. *Mamen ha iniciado también los trámites para solicitar las valoraciones de dependencia y discapacidad. *Martín ha solicitado el alta voluntaria a fecha de 6/10. ········ Tiene cita en ESM el 25/10/21 a las 12 h con la Dra. Wendolina. *No acepta el acompañamiento propuesto por Futuex, pues dice que la CTAEX sólo tiene competencias en los asuntos eccos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='FERNANDEZ'and apellido2='GARCIA'),'2021-10-18','EXITUS Ha fallecido Mª Luisa Fernández Garcia el 17/10/2021 en el hospital Don Benito-Villanueva, residente del Camp Las Cruces , Don Benito Informa directora del Centro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2021-10-18','TERESA ENVIO CAMBIO DOMICILIACION PF Y ORFANDAD A PETICION DE ALBERTO A NUEVA CUENTA DE IBERCAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2021-10-18','Ana: En relación a la llamada de Carmen (633 616 167) el viernes solicitando poder ayudar a su madre con los gastos de su hijo Alejandro: NO tiene beca de estudios este año y no pueden pagar los libros. *Llamo a Benita, madre de Carmen (628887928): Alejandro va a estudiar "Chapa y Pintura" en un Instituto. **Acordamos que nos envíen desdela papelería (ella no sabe) presupuseto de los libros. *Si se acepta desde la secc. ecca. se abonarán mediante transferencia al a propia papelería. ···························· **La PENSIÓN ALIMENTICIA de 150E/mes que abona Carmen es para sus dos hijos. *El padre de Alejandro sólo le ha pasado 50€ para ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-18','Ana: Conversación con Plácido Alejandre: no hay plazas tipo T3, cerca de la localidad de Valencia de Alcántara. *Según evolución se podría solicitar cambio de PIA para plaza en R.Mayores en la Residencia Buenos Aires, de la localidad (tiene grado III de Dependencia). ············ Convesación con Mercedes, Médica de la Res. Geryvida: Aún no tienen los resultados de la analítica, por tanto no saben si aún tiene anemia. Está comiendo ya bastante mejor. *Ya le quitaron la vía subcutánea. Por otra parte, Manuela presenta mucha fragilidad capilar y la piel muy delicada. Actualmente tiene dos leves levantamientos de la piel en la pierna y otro en el antebrazo. *En cuanto a los cuernos cutáneos (lesión tumoral, por lo general de aspecto cónico en la cual prevalece la longitud sobre su diámetro) que tiene en la mano, se lo recortaron y está mejor, no obstante, no cree que se le pueda hacer nada más, pues los riesgos a esta edad son mayores a los beneficios. ·· La demencia está muy avanzada, considera que ya puede tener un GDS 7-8. Presenta mutismo, y aunque a veces si que hace intención de hablar, no llega a emitir palabra. Sí que expresa con la mirada y gestos/señales. ·· Está tranquila. ·································································································································································································································································· Reunión en la CTAEX con Pablo y Antonio (nietos de Manuela) y las esposas de éstos. Asistimos Maite, Ángel y yo. *La principal petición de los familiares es el cambio de recurso de Manuela a la residencia de su pueblo para que puedan ir a visitarla con más frecuencia. *Se les explica cómo está situación y que, siempre, bajo creterio médico, cuando sea posible se solicitará el cambio . Reiteramos que desde la CTAEX lo que queremos es el bienesar de Manuela. ······· Se interesan por el estado de salud de la misma. ·········· En cuanto a la vivienda de Manuela, dicen no querer nada, que si es necesario que se venda para las atenciones o cuidados que Manuela pueda necesitar. Que revierta todo el diner en ella. ············ Se muestran agradecidos con la atención. ···················································································································································································································································································································· Envío correo-e a Tamara, TS Geryvida (trabajosocial@geryvida.com): "...En relación a MANUELA MORATO PICADO, te remito adjunta la ACEPTACIÓN DEL PIA de Mantenimiento del Servicio, firmada por su Representante Legal y ya remitida a Plácido por Registro. En cuanto a la reunión con sus nietos, Pablo y Antonio, así como sus esposas, comentarte que les ha venido bien desahogarse un poco. Demuestran interés y preocupación por Manuela. Como bien me comentaste, solicitan el acercamiento de Manuela al pueblo. Ya les hemos explicado, tal y como nos han informado en la Gerencia Territorial, que no existen, a día de hoy, plazas sociosanitarias T3 cerca de su pueblo. Por tanto, según evolucione Manuela, teniendo en cuenta siempre el criterio del personal médico y de enfermería del centro, se podrá solicitar cambio de recurso para que acceda a plaza de “Asistidos” en la Residencia de Valencia de Alcántara. Esta mañana, antes de la reunión, estuve hablando con Mercedes, la Médica de vuestro centro, para conocer la evolución de Manuela. Y ya le expuse esta idea, en función de cómo evoluciones y de la intensidad de cuidados de enfermería que requiera, solicitaremos el traslado. Por último, comentarte, y esto supongo que ya te lo habrán dicho a ti esta mañana, pues de aquí iban a visitar a Manuela, que solicitan “apoyo” y comprensión en la gestión de las citas, para que todos puedan ir a visitarla. Y que ni a ellos, ni al otro nieto, se les pueda dar dos citas consecutivas imposibilitando la entrada al resto de familiares. *Yo ya les he dicho que la gestión de las visitas en la residencia, se gestionan desde la propia residencia y tendrían que hablarlo allí, pero que igualmente te lo comentaría, por si hay algo que se pueda hacer. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-10-18','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Buenas Ana, no he podido contactar contigo antes, quería informarte de que Cefe podría disponer de 50 Euros de los extras anuales, puesto que como te conté ha utilizado el dinero de los extras de este trimestre para apuntarse a la escuela de idiomas y los libros (unos 100 Euros). Por otro lado como es su cumpleaños va a ir a comer con su hermano a Cáceres, ida y vuelta en el mismo día. Ya os contaremos como ha ido. Un saludo. Paula."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-18','miguel, recibo por email de Emiliano (Inmobiliaria Infofinca) presupuesto y fotos de la vivienda que se quiere vender c/Constitución: Buenas tardes Miguel, te adjunto el informe de la visita a la vivienda de Juan Carlos Rubio en Guadiana en la calle Constitución 13 y nuestro presupuesto de intermediación de venta. Tal y como te indico en el informe el estado de la vivienda es ruinoso, hay zonas que están tan llenas de enseres (basura) que no hemos podido acceder, sobre todo dos dormitorios y una nave existente en el patio. Ya me comentas algo. ********************************************* Reenvío email a Alberto y Teresa y le añado: Buenos días, ya podemos reunirnos las 3 partes y decidir si vendemos o no la vivienda de la c/ Constitución que nos la valora la inmobiliaria en principio en 40.000€, y que nos cobraría sus 1.500€honorarios +iva, por el certificado energético 150€+iva, la cédula de habitabilidad 150€+iva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-18','-Amalia : recibo llamada de MANUEL FERNADEZ , TF . 659966949 , presidente de la comunidad de vecinos . Quiere informar de las continuas incidencias con Alejandro , ha roto el ascensor , las puertas , las llaveras de la luz , el telefonillo , ha tirado el extintor , agresiones a la madre , a un chico que pasaba por la calle con su novia con un báte de beisbol , ... Le he pedido que nos envíe todo por correos con la intención de comunicarlo al juzgado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2021-10-18','miguel, llegan dos certificados de nacimiento literales, sin que conste inscrita la tutela que ejercemos, por lo que hay que esperar al testimonio que remitan desde el juzgado a la solicitud que hizo Enrique.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2021-10-19','kike:llega un Auto del 13 de octubre por el que se acuerda el mantenimiento en el centro sociosanitario Adolfo Díaz Ambrona de Mérida, para su tratamiento médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-09-02','Ana: Correo de Javier, Director CRR-Mérida (direccion.crrmerida@grupo5.net): "Como sabes desde el primer momento que Javier vino al centro ha tenido mucha suspicacia con respecto al tema económico y la posibilidad de pago de la plaza. Sin embargo por el esfuerzo y el trabajo vuestro y nuestro hemos logrado que decida quedarse en el recurso. Hoy como sabes estaba todo preparado para que pudiese ir a cobrar a la Caixa para tener dinero de bolsillo, sin embargo en la oficina nos han puesto muchas reticencias, informando que no podíamos sacar el dinero hasta que lo consultasen con sus servicios jurídicos. Esto ha supuesto para Javier un mayor nivel de ansiedad y suspicacia, a pesar de los intentos por parte del equipo del CRR, Javier ha decidido dejar el centro. Sobre las 11.30, ha abandonado el recurso sin llevarse consigo ninguna de sus pertenencias, según nos cuenta, su intención era estar en la calle o ir a un albergue. Me gustaría que pudiésemos hablar sobre los paso a tomar para que podamos hacerlo en coordinación, si bien esperamos unas hora, damos aviso a policía… Cuando te sea posible hablamos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2021-10-19','TERESA Te adjunto una autorización para la salida que Josefa viene haciendo cada mes y medio, dos meses…a casa de su hermano Rafael en Valdeobispo. Esta dinámica es la que la tiene mas o menos estable después de su regreso de la UDHAC. Como sabes, por otras ocasiones…se va en tren (el billete lo puede pagar del dinero de sus gastos de aquí) y la trae su hermano quien recibe (y con mucho gusto ;P) el importe de 83.98 € del kilometraje realizado. Y esa cantidad si necesito que se lo envíes aquí, al numero de cuenta de siempre, indicando kilometraje Josefa. El dinero que se lleve para gastar también se lo doy de sus gastos de aquí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-10-19','Ana: Confirman documentalmente desde el banco a Icíar que Doroteo no tiene cuenta propia. La pensión se la ingresan en la cuenta de la madre. ···· *Le abrirán cuenta nueva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-10-19','Ana: Llamada de Inma, Técnica del CADEX - CC (22005): Ya está la resolución de la valoración, pero la han enviado y se la han devuelto de correos. *Confirmo la dirección, que estaba bien. **Volverán a enviarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-10-19','Ana: Llamo a Ceferino (641 881 543): quiere alquilar un estudio para hacer su música... enviará presupuestos. ······ En cuanto a su publicación, enviará por mail el borrador que envió a Círculo Rojo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-10-19','Ana: Recibo correo de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es) en relación a la salida de Isabel al domicilio y al cambio de recurso: "...Con respecto a la fecha, acaba de decirme su Psiquiatra que una semana, o sea desde mañana día 20 hasta el 27 de octubre. También quería comentarte que su Psiquiatra está planteándose que le solicitemos el CRR de Cáceres, estamos confeccionando solicitud e informes para ello, cuando lo tengamos, si lo veis conveniente, te lo paso la firma de su Tutor" ························· Mi respuesta: "Buenas tardes Estrella, De acuerdo. Con respecto a la salida al domicilio, se le ha hecho hoy una transferencia a Francisca, madre de Isabel, de 80€, para los 2 traslados, para comprar un detalle para el cumpleaños de su sobrino y algún otro gasto que pueda tener. Agradecería que se lo comunicaseis a Isabel para que se quede más tranquila. Es la cuantía que ha solicitado su madre. En cuanto a tabaco, entiendo que podrá llevar desde ahí, ya que es donde se le compra habitualmente y tenéis autorización para ello, si no recuerdo mal. Por último, dado que el acceso a CRR es de carácter voluntario, la solicitud debe ir firmada por Isabel (es como en las comunidades terapéuticas, a no ser que haya habido algún cambio al respecto). Si lo consideráis conveniente en el equipo terapéutico, por nosotros no hay inconveniente. Es más, en mi opinión, es mucho mejor esa opción a que regrese a su domicilio. Seguimos en contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-19','Ana: Dado que Alberto no me dió respuesta al presupuesto del taxi, y esta semana no está, doy yo el ok. *Cuando envíen la factura se la pasaré a las compañeras de la secc. ecca. para que hagan la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-10-18','Ana: Correo de Estrella, TS CSS-Plas. para Alberto, secc. ecca. y para mí. Javier necesita ropa de invierno, pues no tiene nada. Él quiere comprarse lo mínimo... ········· Alberto no está esta semana, pero entiendo que hay que comparsela. Le pido, a ser posible, que envíen presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-10-19','Ana: correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Te escribo para informarte que al final se ha consensuado con Soraya Masa que Reme vaya a Plena Inclusión Cabeza del Buey, cuando se le dé el alta. Desde aquí se irán haciendo videollamadas de contacto con dicho centro, para hacer un tránsito progresivo de Reme al mismo...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-10-18','Ana: Aunque la CTAEX tiene aceptado el cargo de Curatela Ecca., dado que nos remitió el Jdo. la Autorización de Internamiento Involuntario de Antonio, se pone para la firma del D.Gerente la Aceptación PIA para plaza residencial por emergencia social, que nos remite Natividad Bonilla, TO del EVD de Miajadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-10-18','Ana: Recibimos las siguientes NOTAS DE CITA del ESM: Consulta de PSIQUIATRÍA: Viernes 22/10/21, Dra. Mª Isabel Rubio Merino. ····· Consulta Enfermería: Martes 21/12/21.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-19','Ana: correo de Mario EStrella, Res. Ntra. Sra. de Guadalupe (administracion@residenciaguadalupe.es): "Ya está avisado el taxista. Mañana le recoge el taxi sobre las 09:00 y tiene previsto llegar sobre las 11:00"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-19','-Amalia: escrio a la TS del ESM . Buenos días Carmen , retomando la conversación de ayer , has podido hablar con el psiquiatra sobre la posibilidad de que sea él quien active el 112 ? habría que trasladarle que la opción que planteó de que fueran los familiares quien llamasen en el momento de mayor alteración y agresividad , y a pesar de haber dejado las oportunas medidas establecidas en Jara, no está funcionando . No hay forma de que ingrese en la UHB. Desde esta Comisión informo tras las últimas incidencias ocurridas y verbalizadas por la abuela y el presidente de la comunidad de vecinos de que la probabilidad de riesgo de que ocurra algún incidente es muy alta y la gravedad extrema . Peligran la integridad física y la vida tanto del propio Alejandro , como de su madre a la que agrede y la de los abuelos directamente. De manera indirecta se ven afectados los vecinos de la comunidad, profesionales que intervenimos y cualquier otra persona , ha llegado a agredir a un chico que pasaba por la calle con un bate de beisbol. La policia acude al domicilio en numerosas ocasiones , ayer tuvieron que personarse a la 1.00 y a las 5.00 de la mañana . La alarma social es tremenda , los vecinos tienen miedo de salir de sus casas. Esta semana ha roto la puerta del ascensor , que se añade a los múltiples desperfectos en el bloque : ha arrancado el extintor y lo ha lanzado contra paredes y puertas , ha roto el el telefonillo , golpea las paredes ... La madre se encierra en una habitación por la noche , y él se pasa horas golpeándo la puerta para abrirla ,los vecinos están desesperados. Pongo en copia de este email a Mayte ( Jefa de Sección de la CTAEX ) y a Soraya Maya como coordinadora de casos con la que queremos reunirmos esta mañana . Seguimos en contacto y en coordinación para poder dar una solución a este caso . Muchas gracias por tu intervención . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2021-10-20','Te escribo para informarte que al final se ha consensuado con Soraya Masa que Reme vaya a Plena Inclusión Cabeza del Buey, cuando se le dé el alta. Desde aquí se irán haciendo videollamadas de contacto con dicho centro, para hacer un tránsito progresivo de Reme al mismo....','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-20','miguel, nos remite Ana el siguiente email del CRR de Plasencia: Hola Ana, podría regresar a media mañana. Intentamos contactar con la Residencia para comunicárselo esta tarde y lo dejen anotado para mañana. Nosotras hemos hablado esta mañana con la Fisioterapeuta y la Terapeuta Ocupacional para preveer un poco los apoyos que necesitará José Manuel. Como continúa con una importante limitación en el hombro derecho necesitará un apoyo presencial para la ducha (pedimos presupuesto a la empresa que atiende a otras personas para entre tres o cuatro días en semana y os lo enviamos). Así mismo creemos que no ha finalizado su rehabilitación física, pues nos confirman que su limitación sigue siendo muy importante por lo que queríamos preguntar al departamento jurídico si deberíamos solicitar atención a nivel privado y pedir factura o como proceder para ello. ********************************************************* Mi contestación: Buenos días Ana, necesitamos que se recapitulen todas las facturas de todos los gastos para reclamarlos a la compañía aseguradora del vehículo que le atropelló. En relación al accidente no veo ni en intranet ni en el expediente virtual el seguro del coche, ni denuncia, ni procedimiento y juzgado donde se está tramitando. Tendremos que contratar un abogado una vez que conozcamos juzgado y procedimiento que está conociendo el caso. Caso que lo desconozcan, a ver si la otra parte (el vehículo que le atropello) os puede facilitar alguna información (o a ver si hay una persona de contacto con la que podamos hablar) Cualquier duda que me llamen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-09-30','Ana: Toni-Futuex me envia correo con incidencia: "Buenas tardes Ana, te paso una incidencia registrada en otro dia por el tutelado Antonio Hidalgo. A primera hora de la mañana contacta la trabajadora social de la localidad para comunicar que el lunes 27, por la tarde-noche, tuvo que intervenir la policía con Antonio. Al parecer, debía haber bebido bastante y, seguramente, consumido también, por lo que estaba bastante alterado y fuera de sí, llegando a meterse e increpar a una vecina y al hijo menor de ésta; la vecina, viendo que la situación salía de la normalidad y por miedo a las reacciones del tutelado, llamó a la policía, quienes intervinieron para llevarse al tutelado. Se le pide, a María, si hay informe de la policía, denuncia de la vecina…, documento que describa lo ocurrido y las medidas que se tomaron, comenta que no se ha abierto diligencia por el momento; se le dice que igualmente se comunicará , si reúne algún documento se le solicita que lo envíe para poderlo adjuntar e intentar hacer fuerza para que se haga efectivo el ingreso en centro, pues, al final, puede llegar a provocar peores situaciones y atentar contra la integridad de personas de la localidad. Este señor, la verdad que casi esta peor desde que tiene dinero asignado, pero claro, sin dinero no puede estar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-10-19','Maite: ha llamado la madre de Marta para saber cómo está , puesto que no puede hablar con élla pq ha bloqueado sus llamadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-20','Ana: Bajo al despacho de Jorge Morán, a recoger la carta del pago indebido (SAD - Ley Dependecia) y los modelos 50 para el abono de los mismos . *Se los pasaré a Alberto, jefe secc. ecca., a su regreso la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-10-20','miguel, Ana me remite email del hijo de Miguel Santos: Soy Miguel Santos Antequera. He tenido problemas en el banco para pedir el extracto bancario de mi padre (ya fallecido) y tutelado por vosotros. Quiero que me remitas un documento sobre el expediente cerrado de mi padre. Para que pueda hacerme cargo de todas las gestiones como heredero suyo que soy. Espero confirmación de la recepción del correo y el documento que te pido lo antes posible. Un saludo ********************************************* mi contestación: Buenas tardes, en relación al escrito recibido comentar que conforme se publicó y entró en vigor la actual ley 8/21 de 2 de Junio que entró en vigor a partir del 3-9-21, y conforme la Disposición Transitoria 2º todas las tutelas y curatelas se regulan por esta nueva norma. Este tutelado falleció el 15-9-21 y conforme al artículo 291 de la ley 8/21 de 2 de Junio, establece la extinción del cargo de tutores por el fallecimiento del tutelado. Conforme establece el artículo 292 de la ley 8/21 de 2 de Junio, la Comisión Tutelar deberemos rendir cuenta final al Juzgado, en plazo de 3 meses desde el fallecimiento, prorrogables por el tiempo necesario si existe causa justa. Actualmente dicha rendición final está pendiente de remitirse al juzgado. Por tanto, al haber extinguido nuestro cargo con el fallecimiento, no podemos facilitar nada, debiendo cualquier interesado ponerse en contacto con el juzgado de Logrosan nº1 con el procedimiento nº39/21 (ya que el Juzgado de 1º instancia nº2 de Plasencia, se inhibió en las cuentas anuales una vez que salió del Centro Socio Sanitario de Plasencia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-10-20','Ana: Subo al portafirmas la COMUNICACIÓN DE CAMBIO DE DOMICILIO de DEPENDENCIA. ····························································································································································································· Envío correo a Estrella Durán, TS CSS-Pla (estrella.duranc@salud-juntaex.es): "Buenos días Estrella, En relación a Javier Agudo, informarte cuando ingresó en el CRR de Mérida, aprovechamos para pedir el informe de salud y solicitarle la Valoración de Dependencia, pues no estaba valorado, he puesto para la firma del representante legal el documento de comunicación de cambio de domicilio, pues entre cosas y cosa me he dado cuenta que aún no lo había comunicado. Espero que pueda registrarse de entrada hoy mismo o mañana mucho tardar. ¿Habría alguna posibilidad de que se agilizase la valoración estando ahí en vuestro centro? Pues me dicen que para el acceso a CRR sería muy recomendable, ya que sus ingresos son elevados y a día de hoy, estando en un recurso, ya no se considera emergencia social y por tanto lo tendría difícil para acceder. Ya me dices cuando puedas. Por otra parte, quería pedirte, que cuando podáis, nos enviéis copia del DNI actualizado, escaneado a color. Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-10-15','Maite: he enviado el contrato de la nueva residencia firmado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-10-19','Maite. he recibido correo de la residencia de Talarrubias: Alfonsa Montalbán al final no ingreso en la Residencia porque la PCR que se realizó el día antes para el ingreso ha sido positiva. Actualmente está en aislamiento por Covid- positivo, por lo que cuando le den el alta epidemiológica ingresará en el centro. Os lo comunicaré y os enviare el nuevo contrato. Muchas gracias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2021-10-20','miguel, rebibo email del Oar Badajoz como que no hay deudas a nombre de este tutelado. Remito email a Tere: Buenos días Tere, Anastasio Vazquez Pizarro según me dijistes (mira la intranet) tenía un dinero retenido. Pues bien, he hablado con el OAR Badajoz y no tiene ninguna deuda pendiente por lo que la parte económica (habla con Alberto) tendrá que averiguar el origen de esa retención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-20','miguel, recibo email del OAR Badajoz a solicitud de recibos domiciliados y deudas pendientes. Me remiten documentacion donde hay 5 recibos en ejecutiva con origen Junta de Extremadura. Les envío email para que aclaren el origen de esa deuda y nos remitan carta de pago. A fecha actual debe 3.345€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-10-20','Ana: Llama Ana, enfermera de la Res. Femar (927 360 430), como Alberto no está, autorizo el acompañamiento a la consulta médica mañana. *Enviarán Declaración Jurada con número de cuenta bancaria para hacer la transferencia. ································································································································································································ Envío a Alberto, jefe secc. ecca., presupuesto de rehabilitación, 600€ (lo verá la semana que viene, pues ésta no está)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-20','miguel, me remiten desde el OAR las cartas de pago y se las doy a Iciar para que haga los oficios. La deuda no me la han sabido identificar por lo que los abonaremos y ya está.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-10-20','Ana: Correo de Estrella, TS CSS-Plas: "Buenos días, Ana. Vale, ya se lo digo a Isabel. Quería llevarse 20 euros que tiene aquí de gastos de bolsillo para comprar regalo a su sobrino, le digo que los deje porque ya le habéis hecho transferencia a su madre. Sí, el tabaco se lo puede llevar de aquí. Tienes razón, la solicitud de CRR la tiene que firmar ella.... Otro tema, Ana, me dicen de Gestión Económica del centro, si ya se le puede cobrar la cuota por estar aquí ingresada, que al parecer, faltaba que tuviera domiciliadas las pensiones en cuenta....." ················· Respondo que sí pueden cobrarle ya la cuota. ······························································································································································································ Ana: Llamada de Isabel (649 642 635): Ya está en casa. Me dice que ya ha firmado la solicitud de plaza en CRR-CC. *En relación a la intervención quirúgica que quiere que le hagan (quitar placa del codo) esperar a que esté residiendo en Cáceres para que la vuelvan a valorar en el mismo hptal. en que se operó.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-20','miguel, email de Ana: Buenas Miguel, Si no recuerdo mal, alguno de vosotros ya habló con Blanca, directora del CRR al respecto. Al parecer la hermana del tutelado había estado haciendo gestiones al respecto, no sé si con este última llegasteis a hablar. Los números deben estar en la Intranet, al menos el de Blanca, para que puedas hablar directamente con ella. En cuanto a los gastos, podrás pedírselos a Alberto la semana que viene cuando venga, pues la sección ecca. se habrá estado encargando. *Yo acabo de pasarle a Natalia, para que abone, unas facturas que me han remitido desde la Residencia en que ha estado temporalmente debido al accidente, pero no sé si anteriormente se habrán abonado otras. Pongo en copia a Alberto, para que pueda leerlo a su vuelta. *********************************************** mi contestación: Hola Ana, lo único que tenemos en la intranet es una conversación por encima que tuve con una tal Carol del CRR pero no tenía documentación ninguna que remitirnos, y lo único que hice fue decirla que esperábamos que desde algún juzgado nos remitieran la apertura de un procedimiento por lesiones (pues se supone que habrá atestado de la policía que debería haber asistido al lugar del siniestro… En cuanto a hermanos veo en la intranet que tiene un hermano con el que no tiene trato y con una hermana que vive en Cataluña que se llama Juliana y que a parte de vivir lejos no tienen teléfonos de contacto. Si no sabemos a quien dirigirnos no podré saber en qué juzgado se encuentra el accidente, y si no podemos identificar al conductor de la otra parte o su abogado o su aseguradora no podremos reclamar nada, y hay un plazo por ley para ejercer acciones… Por lo que veo las únicas conversaciones que has tenido es con Blanca la directora del CRR pero no veo que te haya remitido ni información, ni documentación del accidente… Repito, no tenemos nada (ni información, ni documentación, ni a quién dirigirnos) por lo que desde la parte jurídica no podemos hacer nada. Quedamos pendiente de si os transmiten algo a la parte social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2021-10-20','Buen días Amalia. Ayer en cambio de turno, informan que Mari Loli había sido ingresada en hospital de Mérida, trasladada por servicio de urgencias después de las 22 horas del 18/10. Motivo: ingesta medicamentosa de tramadol/paracetamol. Estuve en acompañamiento durante la mañana de ayer por lo que no tenía esta información (tampoco funciona el parte diario de incidencias para haberlo leído); fue comentado por educadores en cambio de turno. Ayer recibió el alta (hora del informe de alta 14:53). Evolución/informe de Psiquiatra: la han mantenido en observación con monitorización continua, lavado gástrico y analíticas. Alta por psiquiatría, mantener tratamiento sin cambios; control por MAP y seguimiento de ESM. Desde ya muchas gracias. Un saludo. Gisela','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2021-10-20','TERESA ARCHIVO INFORME SOCIAL RECIBIDO DEL SSB MERDIA SOLITADO PARA APORTAR A LA REMOCION DE TUTELA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2021-10-21','TERESA Buenos días, soy Inmaculada, hija de María Concepción Delgado Motiño. Me pongo en contacto con vosotros para comunicarles una serie de cuestiones. En primer lugar, quería advertirles de que ya se ha procedido al arreglo de los desperfectos eléctricos que había en el domicilio familiar y, estoy pendiente de que el técnico me haga y entregue factura para efectuar el pago. También, quería comentarles, que mi madre necesita con urgencia un colchón, puesto que el suyo, a parte de tener más de 30 años, está en unas condiciones deplorables y, debido a ello, dice que tiene problemas de espalda. Por otro lado, la puerta del domicilio necesita una cerradura nueva, ya que la que tiene no funciona y no gira la llave, de hecho, esto lleva así más de 1 año. Por otra parte, también se ha estropeado, hace un tiempo, el horno y quería preguntar si puede comprar otro, puesto que este no tiene arreglo. Sé que son varias cosas, pero quería comunicarlo todo junto para no dejar pasar más tiempo y ver si cabe la posibilidad de proceder cuanto antes a la subsanación de todo ello y, que me digáis qué hacer al respecto. De hecho, aún hay más que decir en cuanto a desperfectos, pero no sé si seguir o comunicarlo más adelante... Les adjunto y mando también la última factura de luz para proceder al pago. Muchas gracias y perdone las molestias. Inmaculada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-10-21','Ana: Paso a Julio, CTAEX, para REGISTRO oficio y Comunicación Cambio de Domicilio de Dependencia. **Solicitando le valoren por la Instrucción 47 (para que puedan valorarle las TS del CSS).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-10-20','Ana: Correo de Sonia Bernabé, ASINDI: "Hola Ana, quería informarte de lo que el ginecólogo le ha dicho a Felisa Bruno. Por lo visto tiene ovarios poliquisticos y en estos casos es frecuente que esté varios días manchando u muy poca cantidad. De momento, todo bien. Mañana le hacen analítica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-21','Alejandro Núñez , en respuesta a mi escrito de ayer y a la presión de la TS del ESM , el psiquiatra ha activado el 112 y está ahora mismo en el hospital pendiente de que el psiquiatra de guarda decida si lo ingresa o no . Seguimos...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-21','-Amalia : llama TS del ESM , lo quedan ingresado en la UHB . Va a proponer Subcomisión de casos para valorar de nuevo UDAC / UME .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-10-21','Ana: Llamada de Paqui, amiga de Félix (617 025 534): se interesa por cómo van las gestiones relativas a Félix y si será posible, que le trasladen, como era su deseo, a la Residencia de Arroyo de la Luz, pues a Trujillo no puede desplazarse a verle con la frecuencia que le gustaría, depende de que sus hijos puedan llevarla y lleva ya un mes sin poder verlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-10-20','Maite: he hablado con la trabajadora social de Peñalsordo ( MAría) para que me hablase de la familia con la uqe vive Marta. Me ha dichho que está bien, se preocupan por élla. Depués llamé a su hermana Guadalupe para saber si ya le habia planteado a MArta la posibilidad de ir a residencia o a CO , en PLena Inclusión Cabeza del Buey. Me dijo que MArta no quiere residencia pero que había dicho que sí al CO. Hable con Marta y me dijo que no quiere ninguna de las dos cosas. El CO no le importaria pero no quiere ir a Cabeza del Buey pq no quiere ver a su madre. Plantea la posibilidad de hacer cursos del Ayuntamiento y del SEPE. Hemos serivación a Futuex e iremos a verla cuando vaya la delegada tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='AMADO'and apellido2='NARCISO'),'2021-10-19','Ana: Se registra ACEPTACIÓN PIA Prestación vinculada al SAR, junto con la documentación pertinente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-21','TERESA CONTACTO CON INMA TS 924 47 10 14 DE GUADIANA PARA LA GESTION DE LA LAPIDA DE SU MADRE ME FACILITA TELFNO DE EMPRESA DE MARMOLES 924 44 62 07, ME PONGO EN CONTACO CON ELLA PARA QUE ME FACILITE PRESUPUESTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-10-21','Respuesta de Angel : En relación con esta tutelada, ya intervenimos en su nombre, interponiendo un Recurso de Alzada, contra la Resolución de Infancia Y Familia que inadmitía su solicitud de Renta Extremeña Garantizada. Conseguimos que revocaran esa Resolución y que la solicitud de la tutelada continuara su curso. Con la Ley 8/2021, de 2 de junio, por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica, en vigor desde el mes de septiembre de 2021, las personas con discapacidad tienen capacidad jurídica en igualdad de condiciones con las demás en todos los aspectos de la vida. Dicha capacidad jurídica abarca tanto la titularidad de los derechos como la legitimación para ejercitarlos. En cualquier caso, si se enrocan en la incapacitación, siempre podemos intervenir ratificando la solicitud que presente la tutelada, subsanando de este modo la misma. ---------------------------------------- En respuesta , confirmo a Angel que gracias a ese recurso está de nuevo percibiendo REGA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-10-21','Ana: Paso a Julio, Aux. Amdvo. CTAEX, para dar REGISTRO, la Aceptación PIA. *CÓDIGO DE REGISTRO: A11030403','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-10-21','Ana: Llamo a María, F. Autismo Sur (693 759 016): en el centro realizan a diario 2 salidas por la mañana y otras 2 por la tarde. Además de acudir a Equinoterapia y Piscina, realizan actividades de ocio en la comunidad, procurando la "normalización" del autismo y su integración social. ··· En verano le han donado ropa, pues Alex no tenía ropa de verano y no cuentan con ropero. Es más, las personas con las que trabajan suelen romper mucha ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-10-21','Ana: Mª Ángeles, Aux. de SAD comunica que ya han recogido casi toda la ropa para Felipe en la tienda, sólo falta un polar que no han recibido. Cuando lo recojan le entregarán la factura y nos la harán llegar. ··· *Por otra parte, a Felipe se le ha caído el móvil y se le ha roto. Le han llevado el presupuesto a la TS para que nos lo envíe. ··········· ····· *Isabel Pino, TS SSASB-Miajadas, me envía escaneado el presupuesto del terminal móvil. ············ Se lo paso a Alberto, Jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2021-10-22','Buenas , Teresa , te confirmo que en SIDEX para el Grado II está en trámite. Tiene reconocido como sabíamos , Grado I . Terminado el plan de intervención inicial , seguirá con el seguimiento de Juan José , Ana , la Trabajadora Social de referencia de esa zona . Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-10-21','-Email de FUTUEX : envío nota sobre el cambio de residencia de la tutelada Macarena Otaño Grao, que intentando planificar una visita para ver que tal está, nos enteramos que está en Cataluña! y creo que la madre ni nadie, lo ha puesto en vuestro conocimiento. Te desarrollo la informacion: Desde el programa de apoyo social comunitario nos ponemos en contacto con Macarena para realizar seguimiento presencial, pero nos indica que se ha ido a vivir hace un par de meses a una localidad de Cataluña (Cerdanyola del Vallés). En verano conoció a un chico por redes sociales de esa localidad y aprovechando que él vino a Extremadura al entierro de un familiar se fue allí a vivir. Residen con su abuela ya que la vivienda es propiedad de ella. Hablamos también con Esperanza (madre de Macarena) para que nos proporcione más información y nos indica que no han dicho nada a Comisión tutelar ni a las profesionales del programa de apoyo social comunitario ya que pensaban que a los pocos días se volvería. Los padres han ido en otoño a llevarle ropa de abrigo que había dejado en Badajoz y han pasado con ellos unos días. La madre indica que han conocido a la pareja en ese momento y creen que es buena persona, el chico está pendiente continuamente de Macarena incluso con conductas de sobreprotección. En relación a los seguimientos médicos, nos dice que tiene de forma temporal tarjeta sanitaria del Servicio Catalán de Salud. Que en esta semana Esperanza va a ir a la internista para mandarle informe médico con él fin de llevarle desde allí el tratamiento del Lupus. Económicamente Macarena aporta su pensión y su pareja está trabajando. No sabemos si sera un destino definitivo, pero los padres, en principio tan "contentos".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2021-10-21','Se me ha olvidado comentar que según la madre, se ha empadronado alli, que no sabemos si eso a efectos de la pnc afecta o algo... Notificaré a PNC el traslado de Macarena .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='SANCHEZ'and apellido2='MORENO'),'2021-10-22','La visita de remedios muy bien. Tiene una Red de apoyo buena con su hermano y cuñada y los sobrinos. De hecho vive con el Hermano, aunque algunos días al mes se viene a su casa, pero de normal vive con ellos. Sé hizo la remoción de tutela, según me comentan, cuando entregaron rendición al juzgado y vieron que se habían comprado un coche, que dice Remedios que ella aprobó y dio su consentimiento porque ellos son los que la cuidan cada día. Pues el juzgado dijo que noo, y le ha pasó la tutela a la comisión. Pero hasta el momento, no parece que vayan a existir grandes problemas con esta señora."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-10-22','De: anaelena.luengo >anaelena.luengo@merida.es> Enviado el: jueves, 21 de octubre de 2021 14:28 Para: Maria Teresa Gomez Martin >maria.gomezma@salud-juntaex.es> Asunto: incapacidad Ana María Rosco Ávalos Buenos días! Siguiendo indicaciones de Dña Juana Martín, Jefa de Sección de los Servicios Sociales de Mérida, y después de haber consultado con el departamento jurídico ,le informamos que como medida cautelar y para no perjudicar a Dña Ana María Rosco Ávalos se va a proceder a convalidar la solicitud de Ayuda de Suministros mínimos vitales presentada por Ana María en el registro del Ayuntamiento de Mérida, tomando como refencia la ley 8/2021 de 2 de junio, aunque no modifica la ley 30/2015 que es por la que sigue rigiendo la incapacidad de la solicitante, no habiéndose presentado una modificación de sus capacidades o aptitudes hasta la fecha. Atentamente Ana Elena Luengo Martín Trabajadora Social . Servicios Sociales. Ayuntamiento Mérida Telf. 924387407. anaelena.luengo@merida.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2021-10-22','miguel, recibimos en ctutelar email de Liberbank: Buenos días me pueden indicar , cómo procedemos para facilitar documentación a los herederos del tutelado Miguel Santos Cordero, que ha fallecido ( motivo suicidio) . A quién corresponde entregar documentos para liquidación impuesto de Sucesiones********************************************** mi contestación: Buenos días, en contestación a su escrito comentarles que conforme al artículo 291 de la ley 8/21 de 2 de Junio, se ha extinguido el cargo de tutores por el fallecimiento del tutelado, por lo cual y conforme al artículo 292 de la ley 8/21 de 2 de Junio, la Comisión Tutelar deberemos rendir cuenta final al Juzgado, en plazo de 3 meses desde el fallecimiento, prorrogables por el tiempo necesario si existe causa justa. Por tanto actualmente la Comisión está pendiente de remitir la rendición final de cuentas al juzgado de nº2 de Plasencia. Por tanto desde el momento del fallecimiento momento en que se extingue el cargo de tutor de la Comisión Tutelar, la misma no tiene competencias para facilitar información y/o documentación. Cualquier consulta deberán hacerla a dicho Juzgado de Plasencia. En cuanto al impuesto de sucesiones por tanto, le corresponde a sus herederos realizarlo, sin que la Comisión tenga nada que ver al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-12-01','EXITUS Acacecido el 01/12/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-10-22','TELÉFONOS MARTA: 643 629 639 MARÍA DEL CARMEN (MADRE): 643 430 944 GUADALUPE: 652 830 994','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='DIAZ'and apellido2='DOMINGUEZ'),'2021-10-22','miguel, Buenos días, ha llamado el abogado Saturnino Delgado 646967009 quejándose del seguro de fallecidos (pedía que se lo remitiera) ya que el nicho está sin lápida y nadie había avisado a la supuesta heredera (su clienta). Me dice el abogado que urge que se remita al juzgado de Villafranca nº1 la rendición final de cuentas. Creo que tienen intención de reclamar al centro y a la aseguradora. Según me indica Teresa, la cuidadora (es la supuesta heredera). Es el caso que se intentó anular la tarjeta porque sacaba de la cuenta de la tutelada toda la pensión… Cualquier duda hablar con Teresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='ROSCO'and apellido2='AVALOS'),'2021-10-22','Buenas, compis, No sé a que ley 30/15 se refieren, pero la regulación normativa por la que se rigen las personas con discapacidad, en el ejercicio de su capacidad jurídica, es la ley 8/2021, de 2 de junio, y como os comenté ayer, las personas con discapacidad tienen capacidad jurídica en igualdad de condiciones con las demás en todos los aspectos de la vida. Dicha capacidad jurídica abarca tanto la titularidad de los derechos como la legitimación para ejercitarlos y además, establece, que las meras privaciones de derechos de las personas con discapacidad o de su ejercicio, quedarán sin efecto. En cuanto a la modificación de sus capacidades o aptitudes, los Juzgados disponen de un plazo máximo de 3 años para revisar las medidas que se hubieren establecido con anterioridad a la entrada en vigor de la nueva ley, para adaptarlas a esta. Que va a quedar en un cambio de denominación, lo que era tutela, ahora es curatela representativa y la curatela, curatela asistencial. En cuanto a la convalidación, el Ayuntamiento no puede convalidar nada, sin nuestra intervención, como representantes de la tutelada, ratificando la solicitud que presente. En cualquier caso, mientras tramiten la solicitud, nosotros nos quedamos conformes. Seguimos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-22','Ana: Recibimos copia del contrato de la Residencia Geryvida firmado ya por ambas partes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-22','Ana: Conversación con Paula, TO CRR-Pla. (682 704 401): en relación a los apoyos que necesita, han de valorar la necesidad real, cuántos días y por cuento tiempo será. No obstante, de momento, para servicios puntuales, pueden contratarlo sin problema, la curatela económica es para cuantías superiores a 150€. ··· Si finalmente lo necesitara de forma más prolongada, enviarían presupuesto y lo valoraría junto con Alberto. ·············· *Por otra parte, le indico usuario, clave y fecha para la renovación de la demanda de empleo el día 3/12/21. ··································································································································································································· Recibimos Cita Médica de Psiquiatría de ESM para el día 7/12/21 a las 12:30 h. *Se lo comunico a Paula -TO-CRR Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-10-22','Ana: Conversación con Paula, TO CRR-Pla. (682 704 401): ayudarán a Ceferino a buscar algún espacio, a ser posible público y gratuito, para que pueda dedicarse a la música. Si no es gratuito, solicitarán presupuestos y nos lo remitirán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='DIAZ'and apellido2='DOMINGUEZ'),'2021-10-22','miguel, me remite email Tere que le ha enviado la empresa de lápidas: Buenos días/tardes Su lápida ha pasado a fabricación y en el plazo de 30 días aproximadamente se le confirmará que ha sido entregada/colocada. Para lápidas de porcelana, incrustaciones, tallas y trabajos especiales en el plazo de 45 días aproximadamente se le confirmará que ha sido entregada/colocada. Le recordamos que para cualquier información o duda nos puede llamar al teléfono gratuito 900114114 o acceder a su seguimiento en nuestra página web (https://eur04.safelinks.protection.outlook.com/?url=http%3A%2F%2Fwww.nat.es%2F&data=04%7C01%7Cmiguel.fernandezd%40salud-juntaex.es%7Ced538358740c4136f53108d995496088%7Cc5ce285034b54dcb8e416db28fe40097%7C0%7C0%7C637704964644613042%7CUnknown%7CTWFpbGZsb3d8eyJWIjoiMC4wLjAwMDAiLCJQIjoiV2luMzIiLCJBTiI6Ik1haWwiLCJXVCI6Mn0%3D%7C1000&sdata=q4YsK498SOSMFs%2BYHasKcbcTWVHbU5dZUfvzeA3Yj7k%3D&reserved=0), Área personal de acceso clientes. Su nº de proyecto es 21-PL-018856 Saludos. Mármoles y granitos NAT. Ruth Gómez de Cadiñanos Gómez Direccion Villafranca Ck Senior C/ Lope de Vega 21, CP 06220, Villafranca de los Barros Tlf. 924 91 04 11','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2021-10-22','Ana: Conversación con Paula, TO CRR-Pla. (682 704 401): Mariángeles está muy contenta y adaptada al centro, a pesar de las limitaciones que presentaba se esfuerza mucho y tiene mucha fuerza de voluntad. Por otra parte está muy contenta porque este año ha visitado por primera vez en su vida la playa. ······ Por otro lado, presenta problemas bucodentales, enviarán presupuesto de clínica dental cuando puedan, para ver si es viable el tratamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-10-22','Ana: Llamo a Mamen, TS del HSPA (56283): Visitó a Martín en varias ocasiones durante su ingreso hospitalario. La primeras veces Martín decía lo que ella quería escuchar. Después ya, cambiaba de decisión continuamente. *Pidió el alta voluntaria, estando pendiente de hacerse varias pruebas. ······ El hermano y la cuñada están muy desesperados, Martín es difícil de llevar y agota emocionalmente. *Además, según informan ha destrozado la vivienda. ········· Mamen me enviará informe al respecto para que podamos hace comunicación al Jdo. de la situación y solicitar que adopten medidas cautelares. ····· *Adjuntaremos también informe de alta (solicitó alta voluntaria) y nota de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-10-25','Maite: he enviado por mail el contrato firmado a la directora de la residencia de talayuela. Ingresó el viernes 22/10/2021','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-10-25','Ana: Llamo al INSS, a Control de Pensiones (927 62 00 49/65) en relación al embargo de su pensión: me informan que no aparece ningún embargo. No se le está aplicando ningún tipo de deducción a su prestación. *Se le está ingresando 781,65€/mes. ············ Se lo comunico a Alberto, Jefe de Secc. Ecca. ······················································ Estrella, secc. ecca., averigua que el embargo es del OAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2021-10-25','Ángel: En relación con la solicitud de autorización de gastos extraordinarios, para hacer frente a los daños ocasionados en la anterior vivienda en la que se encontraba viviendo, se realiza hoy el Juicio, al que acudimos a través de videoconferencia. El Ministerio Fiscal se opone y propone que el arrendador reclame estos daños en vía judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2021-10-25','Ana: Guardo el correo de Toni, con la nota de la primera visita de la Ed. el pasado día 18/10/21. *Envío a Alberto la información sobre gastos y la propuesta de aportación para manutención y gastos de bolsillo, elaborada por Doroteo en colaboración con la Ed. Futuex. *No tenemos información de Seguro de Deceso. **Recuerdo a Alberto, jefe secc.ecc. que hay que abrirle cuenta propia a Doroteo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-10-25','Ana: Llamo al INSS, a Control de Pensiones (927 62 00 49/65) en relación al embargo de su pensión: me informan que no aparece ningún embargo. No se le está aplicando ningún tipo de deducción a su prestación. *Se le está ingresando 781,65€/mes. ············ Se lo comunico a Alberto, Jefe de Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2021-10-25','TERESA A lo largo de la semana hemos abierto con ella varias líneas de intervención y de momento están resultando fructíferas. Parece ser que el método replanteado le ha hecho recapacitar y ha adquirido unos compromisos y responsabilidades que parecen cambiar la perspectiva. Libertad en estos momentos se encuentra confusa en cuanto a deseos e intereses y está respondiendo favorablemente a las intervenciones planteadas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-10-25','miguel, dejo a Juana Heras el cheque nominativo a nombre del tutelado para su ingreso','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-10-25','miguel, llevo la orden de traspaso a Juana Heras para el ingreso del importe del Fondo de Inversión en la cuenta personal de la tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-10-25','miguel, hablo con Tere y Alberto y con el curatelado y no tienen inconveniente en vender. Envio email a la inmobiliaria Info finca: Buenos días Emiliano, me confirman los compañeros de la parte social y económica que puedes poner ya a la venta el inmueble de la c/Constitución. Si necesitas algo dimelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-10-25','Ana: Llamada de Isabel (649 642 635), dice estar pasando unos días muy buenos en casa de su madre. Mañana es el cumpleaños de su sobrino, dice haberle comprado 2 detallitos. *Pregunta por la plaza en el CRR, vuelvo a explicarle que ahora hay que tener paciencia. Desde el CSS ya han iniciado los trámites para solicitar la plaza, ahora hay que esperar. Le dijo que ahora tiene que estar bien y centrarse en las cosas positivas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-10-22','Ana: Recibimos nuevo informe del Serv. de Urgencias del HSPA, Julia fue derivada al mismo al activar la Guardia Civil el 112. *A las pocas horas le dieron el alta: "Crisis de ansiedad, resuelta a su llegada a Urgencias".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-10-21','Ana: Correo de Toni-Futuex con el relato de las últimas incidencias protagonizadas por Julia. Nueva intervención de la Guardia Civil. ········ *Marta, la TS del SSASB, le ha pedido al Sargento de la Guardia Civil un informe con los últimos incidentes, pero éste se niega, dice haber entregado ya varios hace un tiempo y no sirvió de nada. ······ *Guardo correo en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-10-25','Ana: Envío correo a Maite, jefa de secc. con el correo de Futuex, exponiendo la situación actual de Julia y las gestiones llevadas a cabo hasta la fecha. *Estamos en espera de que la TS intente, con informe, priorizar el expdte. de dependencia para valoración. *Cada vez que es derivada al hptal. le dan el alta a las pocas horas, en ninguna de las ocasiones le han ingresado en la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-25','miguel, remito a Blanca del CRR Plasencia el email siguiente: Buenas tardes, en relación al accidente circulatorio del curatelado José Manuel Moreno Carlos, hemos remitido vía fax e email requerimiento para que nos informen y nos remitan documentación relativa al mismo, ya que desconocemos juzgado, procedimiento donde se esté tramitando el mismo, o si hay denuncias, atestados policiales, e informes médicos de las secuelas del mismo. Asimismo les hemos remitido las facturas que nos hicisteis llegar. En caso de que dispongáis de alguno de esos documentos porfavor remitídnoslo. Por otra parte, si conocéis alguna persona de contacto (como su hermana) por favor dadnos sus datos de contacto por si tuviera alguna información más que aportar a este caso.**************************************************** Mando nuevo email a servicio.cliente@allianz.es: Adjunto documentación consistente en facturas a añadir al siniestro arriba referenciado del curatelado por esta Comisión Tutelar, D. José Manuel Moreno Carlos. Asimismo les requerimos para nos aporten toda documentación e informes que obren en el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-10-25','Ana: Correo de Sonia Bernabé-Directora ASINDI: "Hola Ana, quería informarte que Roberto Hernández Castaño ha sido ingresado en Salud Mental de Cáceres. Desde el viernes presentaba conductas agresivas hacia sus compañeros y profesionales. Se intervino según tenemos establecido en su programa y se llamó al Centro de Salud, después de varios avisos durante el fin de semana, ayer fue derivado por el médico. El psiquiatra llamó de madrugada para informarse mejor de todas las conductas que había tenido Roberto el fin de semana y finalmente quedó ingresado unos días. Informaré a sus padres ahora porque querían que fuera a pasar unos días a casa. Ya te iré informando. Un saludo,"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-10-25','Ana: Correo de Estrella Durán, TS CSS-Plas: "Buenos días, Ana Te comunico que el jueves pasado volvió a escaparse del centro, Juan Carlos Ruíz. No pude comunicártelo el viernes porque estuvimos sin luz y sin teléfono. Lo trajo la Policía a las pocas horas. Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-25','Ana: Envío correo a Paula, TO - CRR Plas.(tocupacional.crrplasencia@grupo5.net): "Buenas tardes Paula, En relación a la duda que nos generaba la sentencia de incapacitación relativa a JOSÉ MANUEL MORENO CARLOS, Miguel, Asesor Jurídico de la CTAEX, nos aclara que: - En la espera personal, sólo tendremos que intervenir/tomar decisiones, en fases agudas de la enfermedad - En la espera económica, siempre que el gasto/retirada de efectivo sea superior a los 150 € que establece la sentencia No obstante, sería conveniente, que aún en las operaciones de estas cuantías inferiores, se nos hiciera conocedores, sobre todo si se produjesen de forma continuada, pues podría suponer a la larga un gasto mayor al autorizado. Espero haberme explicado bien. Ante cualquier cuestión, hablamos. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2021-10-25','Ana: ante el correo de María, Directora Res. Jaraicejo (mariagarciarecio97@gmail.com): "Buenos días Ana. Quería preguntarte, Isabel Muñoz Melchor me dice que si en el mes de noviembre y diciembre podéis ingresarla 100 euros en vez de 50. Quedo a la espera de tu respuesta. Gracias, un abrazo. ·························· Envío la siguiente respuesta: "Pues le haré la consulta al jefe de sección económica, pero necesitaría que me indicaseis para qué solicita esa cuantía. Los extras se conceden siempre que económicamente sea viable y siendo justificado el motivo. Si no recuerdo mal, recientemente se le autorizó para comprar un televisor y ha tenido gastos de tratamiento dental, no sé cuál será a día de hoy su situación económica. Que te indique para qué lo solicita y yo le hago la consulta al jefe."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-10-26','miguel: da error los fax enviados, y contestan a uno de los emails: servicio.cliente@allianz.es: Te informamos que hemos recibido tu correo electrónico y lo estamos gestionando. Importante: Incluir en el Asunto de tu correo la referencia de la póliza con formato: P-123456789 (donde 123456789 es el número de tu póliza), nos ayuda a agilizar tu petición. Por favor no respondas a este mensaje, se trata de un envío automático. Num de ticket: 183955708','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-10-26','miguel, hago por videoconferencia la vista con el jzdo nº1 de Castuera por el procedimiento de internamiento involuntario quedando pendiente de sentencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2021-10-27','-se ha ampliado hace unas semanas centros RAL / VT para traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2021-10-27','Te pongo en conocimiento que el curatelado CRISTÓBAL CASQUERO GARCÍA, ha solicitado ante el Colegio de Abogados , asistencia jurídica gratuita con objeto de iniciar un procedimiento de REMOCIÓN DE TUTOR. La solicitud ha sido denegada por superar el nivel de rentas legalmente establecido. No sabía nada al respecto, él no me ha informado de ello. Me he enterado al leer la notificación del Colegio de Abogados. Ya sabes que estos usuarios con altos niveles de autonomía tienen la capacidad de hacer estas cosas sin que nos enteremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2021-10-27','Por otra parte, comentarte que la semana pasada MIGUEL ORTÍZ GORDILLO agredió a una usuaria nuestra que carece de lenguaje oral y tiene una discapacidad intelectual severa. La agredió porque ella estaba "chillando" y para que se callara. En su habitación pone la televisión muy alta y no deja dormir a sus compañeros. Ha enviado whatsapps a profesionales del servicio de residencia en el que les ha insultado, busca su provocación con el propósito de interponerles después una denuncia. Ya sabes que él el tema de las denuncias le gusta mucho. A la Directora del Servicio de Centro Ocupacional le ha escrito whatsapps en los que le insulta , le amenaza... Él tiene la inteligencia suficiente para saber qué tiene que decir según quién y hacer daño, por lo demás sigue en su tónica habitual.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2021-10-26','Ana: Se envía a Nuria Paniagua, desde el correo de Maite, jefe secc., el C.I. para la participación en el estudio de MEDEA, debidamente firmado y sellado por el Representante Legal.','2');
