insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-10-27','Ana: Llamada de Maite, TS C. Penitenciario CC (927 181 407): Saturnino está muy nervioso y enfadado y es una persona muy insistente. Continuamente solicita dinero, pues dice que en su cuenta hay dinero y que no está conforme con la asignación que le ha puesto la CTAEX. ** Tiene deudas contraídas con otros internos y ha cambiado la TV nueva por tabaco. Ya le ha explicado que tiene deudas y no se le puede dar más, pero según dice Maite, no lo entiende. También tiene dudas con respecto a su situación judicial y por qué está allí. Pide que le visitemos o al menos le llamemos y se lo expliquemos nosotros para que se quede más tranquilo. ··· Por otra parte, en su cuenta peculio tiene otros 25€ que le ingresaron del penitenciario por una actuación tocando la guitarra que hizo en navidad allí. *Le indico que de ese dinero sí puede disponer. Maite solicitará en el centro que le den esa cuantía. **Yo hablaré con Maite, jefa de secc. CTAEX y con los asesores jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='CASARES'and apellido2='MARISCAL'),'2021-10-27','te pregunto por Prudencia que está tutelado por vosotros y que vive en la residencia de Alburquerque. No sé si llevarás tu este caso. Este señor tiene primos/as en Puebla de la Calzada y han venido a interesarse porque va a pasar con él, dado que van a cerrar la residencia de mayores. a ellos les gustaría que se viniera a la residencia de mayores de Puebla de la Calzada, así podrían visitarlo. Ya me dirás tu algo, por favor. saludos Reme , TS del SSASB de Puebla de la Calzada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-10-27','-Amalia : me informa la TS del ESM que le dan el alta de la UDAC. De todas formas va a solicitar subcomisión de casos para valorar otra opcion .','2');
