insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-10-28','Buenos días , os comento las últimas novedades : Ildefonso ingresará en UME el 4 de Noviembre a las 11.00 de la mañana desde el Centro de Salud de Zafra, en ambulancia. El miércoles tiene que hacerse la PCR. A la parte eco , una vez confirmado el ingreso , dejará de sacar el reintegro y se finaliza el pago del hotel . -------------------------------------------------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-10-28','miguel, recibo email de Iciar: Buenos días, compañeros Nos han mandado movimientos de la cuenta de la tutelada Florencia Dávila García donde está de titular con su hermano Cesáreo, os la adjunto, aparece una transferencia por importe de 48.675 € del día 7/10/21, he hablado con el banco y me informa de que el concepto de la transferencia al ayuntamiento de Peraleda de la Mata es por pagos de rentas por sentencia 41/2021 del juzgado de 1ª Instancia de Navalmoral de la Mata.*********************************************Envío email a Iciar, Alberto y Angel: Buenos días Iciar, conforme tu email he indagado para averiguar el origen de la transferencia de 48.675€ de 7-10-21, que indicas en tu email. En concreto he hablado con el Juzgado de 1º instancia nº1 de Navalmoral de la Mata y no tienen, ni han tenido ninguna ejecución de sentencia. Dice que sólo le aparece la referencia al Juzgado de 1º instancia nº2 de Navalmoral de la Mata que está referido al procedimiento de incapacitación por el que nombraron a la Comisión como tutora. Por tanto el banco te tiene que indicar exactamente número de procedimiento y exactamente el juzgado ya que te han puesto el 1º instancia, y todos son 1º instancia. Reenvíales si quieres este email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2021-10-28','Ana: Envío a Alberto presupuesto para comprar el calentador a Catalina, ya lo enviaron hace tiempo al ctutelar@ es prioritario, llega el frío y no tiene agua caliente.','2');
