insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='CIEZAR'and apellido2='PLAZA'),'2021-10-27','Ana: Correo de Estrella, TS CSS (estrella.duranc@salud-juntaex.es): "Os escribo porque Manuel Ciezar Plaza carece de dinero para poder pagar el Podólogo, con lo que nos gustaría extraerle 60 euros para pueda disponer de gastos de bolsillo y para sucesivas visitas del Podólogo. Ruego enviéis la autorización para que podamos sacar el dinero en su entidad bancaria." ··········· Se lo paso a Alberto.','2');
