insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2021-10-29','Ana: Llamo a Mª Ángeles, Aux. de SAD (675 264 255): comunico que se autoriza la compra del móvil. Solicito me remitan factura y nº cuenta. ········· Estrella, secc. ecca., hará la transferencia por adelantado. ····························································································································································································· Llamo a Isabel Pino (927 34 70 00, Ext.3216), pues Felipe acudió a inscribirse a la Escuela de Adultos el primer día del plazo de inscripción y le dijeron que no quedaban plazas...: le suena muy raro, parece que no quieren admitirlo. Consultará y mediará al respecto y nos informará. ···························· Llamada de Isabel Pino, ha hablado con Belén, Directora de la Escuela de Adultos, dadas las características de Felipe, no puede asistir a una clase normalizada. Pero ha hecho la matrícula y están buscando los medios/soluciones para poder dar la atención de "Alfabetización" que precisa Felipe.','2');
