insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BUENO'and apellido2='FERNANDEZ'),'2021-10-29','uenos días, Enviamos autorización para que D. Antonio Jesús García Guerrero, Notario, pueda acudir al centro, para tramitar el testamento a otorgar por D. José Antonio Bueno Fernández, conforme a la Ley 8/2021, de 2 de junio, por la que se reforma la legislación civil y procesal para el apoyo a las personas con discapacidad en el ejercicio de su capacidad jurídica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-10-29','Ana: Correo de Estrella, TS del CSS (ana.matamorosg@salud-juntaex.es):Hola. Comunicaros que está Desideria ingresada en UME, está demandando dinero de bolsillo. Como sabréis, suelen venir una vez al mes los profesionales de Futuex para acompañarla al banco y sacar dinero. Al estar aquí ingresada, eso no va a poder ser, así que si podéis enviarnos la autorización para poder sacarlo nosotros, pues mejor." ··············· Se lo paso a Alberto, jefe secc. ecca.','2');
