insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-10-29','Maite: he hablado con Alexandra, trabajadora social de Plena Inclusión Cabeza del Buey, para comentarle que se va a hacer la derivación de MArta al servici de CO; y pedirle colaboración para que se adpate bien y que no tenga contacto con la madre, al menos en un principio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2021-11-02','TERESA EMAIL JOSE TS buenos dias !!! espero que hayas pasado un fin de semana terrorifico !!! le enseñe la casa a las personas que estan interesadas y siguen interesadas en comprarla como dice el compañero de la asesoria jurididica a paco no le corre prisa venderla porque el vive de su pension, pero el caso es que las vivendas de al lado tienen un monton de humedades al ser su casa un solar y hemos visto que se puede desprender la mediania.... ya ha gastado mucho en reparaciones y mas que tendra que hacer si no se vende, los vecinos que me han llamado estan interesados porque tienen el cercado de atras y asi tienen una salida a esa calle, si no es asi esto no se vende porque es muy estrecha en el lado mas ancho tiene 4 metros.... voy a ver si te puedo hacer de alguno de los documentos que me digiste y seguimos viendolo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2021-11-02','-Amalia : Nos llamana desde SSASB Mérida ( TS Guadalupe 824905049) , se ha presentado allí Rafael solicitando una "prestación y un piso ". Dice que ya no consume drogas. Me pongo en contacto con él , tf 622403744 , en Civitas aparece otro ( 622349259). Está percibiendo RAI y vivie en algúN lugar que dice que le han dejando ,en malas condiciones , a veces acude al comedor social . Averiguamos que su centro de salud es Merida Norte , tf 924487228 ,su Dtra . es Isabel Benito ARrroyo y su enferemera Mª Isabel Garcia de Vinuesa . Tiene 47 años . Quiere ingresar en centro voluntariamente . Solicitaré informes médicos para poder pedir ingreso en CSS de Mérida .','2');
