insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-11-02','miguel, a petición de Alberto, remito email a Juana Heras en relación al cargo de los 48.675€ cargados en la cuenta de Liberbank: Buenos días Juana, hemos comprobado un cargo en la cuenta de la tutelada arriba indicada. Te adjunto movimiento de la cuenta donde consta un cargo de 48.675 €. Mi compañera Iciar preguntó a la entidad (no sabemos con quién hablo), y la comentaron que se correspondía con la sentencia 41/2021 del juzgado de 1ª Instancia de Navalmoral de la Mata. Con esa información hablé con el Jzdo de 1º instancia nº1 de Navalmoral de la Mata y me dijeron que necesitarían el nº de procedimiento y el juzgado de 1º instancia, nº1 o nº2? Según miraron sólo les aparecía el procedimiento de incapacitación. Por tanto necesitamos localizar el motivo de dicho cargo para comunicarlo al Juzgado al ser un cargo importante, porque caso contrario tendríamos que intentar devolver el mismo. Por favor, podrías localizar dicho nº de procedimiento y el juzgado exacto donde se haya tramitado el procedimiento?.','2');
