insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-11-03','Ana: Llamada de Cristofer, dice que tiene novia, se llama Cristina, van a talleres diferentes, dice que se dan la mano. *Él dice que en taller de costura va "ahí ahí" y pregunta si hay plazas en piso. Después pregunta si hay plazas en el Centro de La Luz. A continuación pregunta por la posibilidad de ir algún centro de Cáceres. Le pregunto después por su día a día y me cuenta las cosas que hacen en su centro y en el C.O., parece más adaptado.','2');
