insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-11-02','miguel, hablo con Emiliano y me comenta de dos posibles ofertas en 33.000 y 36.000€. Comprobamos el valor fiscal que está en unos 43.000€ por lo que no debemos de bajar de unos 40.000€+gastos. Así se lo hago saber ya que es el precio en que él lo tasó y en el que está puesto en venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-11-03','Ana: Correo de ayer de Toni- TS C.R. Cervantes: "Buenos días Ana María Luisa Montaña Aliseda ha vuelto a sustraer objetos de las habitaciones de los residentes. Los problemas con ella y sus compañeros surgen a diario debido a que se provecha, en muchas ocasiones, de la vulnerabilidad que presentan los demás. Por ello creemos que es necesario que se retome el traslado de nuestro centro a unos de los solicitados en junio del 2021 un saludo y buen día" ···················· Conversación con Toni (22270): Entiendo que si Mª Luisa está incumpliendo el Reglamento del Régimen Interior habrá que notificarlo a Mayores e iniciar el procedimiento sancionador o de apercibimiento correspondiente. *Hablaré con Maite, Jefa Secc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-11-03','Ana: Llamada de Sonia Bernabé, directora Asindi; A Roberto le dieron el alta en la UHB el lunes 25, pero cuatro días después tuvo que volver a ingresar. Cuando regresó al centro lo notaron muy eufórico y después *volvió a agredir a residentes y rompió mobiliario. *Tienen que volver a ajustarle la medicación.','2');
