insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-10-30','Ana: Correo de la Médica de la Res. Geryvida: "... MANUELA SIGUE CON ADECUADAS INGESTAS , SIN ESTREÑIMIENTO , LAS HERIDAS DEL BRAZO DCHO Y LA DEL GEMELO IZDO ESTAN YA PRACTICAMENTE CURADAS , LA DE LA PIERNA DCHA ESTA LIGERAMENTE ULCERADA , SIN SIGNOS DE INFECCION . SIGUE CON HEMATOMAS EN DIFERENTES ESTADIOS , SOBRE TODO EN EEII, ALGUNOS ME IMPRESIONA QUE SON ESPONTANEOS O POR MINIMO TRAUMATISMO O ROCE . TIENE MALA POSICION EN EL SILLON CON MAL CONTROL DEL TRONCO EN SEDESTACION , TENDENCIA A LA LATERALIZACION , NO APOYA DURANTE LAS TRANSFERENCIAS Y NO COLABORA . ESTA TRANQUILA DURANTE EL DIA Y DUERME BIEN . HE RETIRADO EL TRATAMIENTO CON ADIRO POR BALANCE BENEFICIO / RIESGO DESFAVORABLE ( POR ANTECEDENTE DE HEMORRAGIA DIGESTIVA , ANEMIA RECIENTE CON NECESIDAD DE TRANSFUSION Y HEMATOMAS FACILES )" ············ Guardo en el expdte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-09','Ana: Envío correo-e a Tamara, TS y Mercedes, Médica, de Geryvida: "Buenos días Tamara y Mercedes, En relación a Manuela Morato Picado, dada su buena evolución en cuanto a su estado de salud, estamos valorando el traslado a Residencia de Mayores de su localidad a “plaza de asistidos”, donde estaría más cerca de sus familiares y podrían visitarla con mayor facilidad. Pero antes de nada, queríamos conocer vuestra opinión al respecto de este cambio de recurso y si no consideráis contraproducente la propuesta, os pedimos que solicitéis a su médico de atención primaria Informe de Salud, Anexo II de la Solicitud de Dependencia, pues dado que Manuela tiene reconocido Grado III, pediremos cambio de PIA. Quedo a la esperar de vuestra respuesta. Gracias y buena mañana." ················································································································································································································································································································ Cumplimento Solicitud de Dependencia para solicitar Cambio de PIA para plaza de asistidos en Res. Buenos Aires de Valencia de Alcántara y la pongo para la firma del Representante Legal. ················································································································································································································································································································································································· Recibo llamada de Celestino - Farmacia Celestino Anega de Valencia de Alcántara (607 304 724). Hay pendientes unos créditos relativos a gastos de Manuela. *Le indico que los remita a ctutelar@. ··················································································································································································································································································································· Respuesta de Mercedes Vega, Médica de Geryvida (direccionmedica@geryvida.com): "Buenos días Ana, hablaremos del tema en la reunión de equipo multidisciplinar de la próxima semana. Hablaré con su MAP para solicitar el Informe de Salud. Saludos cordiales" ················· Correo de Tamara, TS (trabajosocial@geryvida.com): "Ok Ana, Yo pido cita en le centro de salud y le hago llegar el informe de dependencia, no sé lo que tardarán en dármelo, intentaré pedir la cita para este jueves. Voy hablar con el equipo para ver la opinión del traslado."','2');
