insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-11-04','Ana: Correo de Sandra, TS de la Res. Real Patronato de Coria (alexandra.alfonso@coria.org): "Buenos días Ana, me ha llamado la hija de Rosario para ver si yo la podía informar de cuál es el trámite para sacar a su madre de la Residencia y poderla cuidar..........cuando puedas me dices." ······················· Mi respuesta: "Buenos días Sandra, Mientras Rosario siga tutelada por la CTAEX no puede llevarse a su madre del centro. Lo único que puede hacer es solicitar al mismo Juzgado que la incapacitó, la REMOCIÓN DEL CARGO y solicitar ser ella quien asuma el cargo. El Juzgado es el de 1ª Instancia nº 1 de Coria. Por cierto, cuando hablas con ella, por favor, pregúntale si ha remitido al Consulado de Francia en Madrid, la documentación que le han solicitado, pues seguimos sin poder solucionar el problema." ······································································· Respuesta de Sandra: "Buenos días Ana, ya le he pasado toda la información. Me comenta que no encuentra la documentación que se la pedido. Su teléfono es 621 01 26 09 por si necesitáis hablar con ella. Un saludo"','2');
