insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-11-04','paso actualizarte la información que tenemos a este respecto. Ayer, 2 de Noviembre se llamó al hostal Carmen de Zafra sobre las 14:10h y se preguntó si Ildenfonso García, que está residiendo allí, se encontraba en ese momento comiendo. Contestaron que Ildefonso se encontraba en el comedor y le pasaron el teléfono. Se conversó con el curatelado durante un buen rato y se le preguntó si se había hecho la PCR que era necesaria para ingresar en la UME el 4 de Noviembre, él contestó que no le había llegado una carta para informarle de esa PCR aunque no tenía intenciones de hacérsela ni de ingresar en la UME. Ildefonso comentó que se encontraba estable, se estaba tomando su medicación y se sentía mejor que nunca, además había recibido el alta de la UHB de Llerena y no comprendía por qué tenía que ingresar en la UME justo unas cuantas semanas después de recibir ese alta. Comentó que había estado en el centro de salud de Zafra la semana anterior para ponerse el inyectable y la Dra. Leticia le había comentado que tenía que ingresar en la UME, a lo que él había contestado que ella no era nadie para decirle eso y que se negaba totalmente. Por lo que su postura con respecto al ingreso inminente en la UME es una negativa rotunda, de hecho él estuvo demandando que se le consiguiera una vivienda en Zafra. Comentó que él quería tener un piso allí para poder hacer sus comidas y tener una vida lo más normalizada posible. Aunque no le importaría entrar en un recurso como piso supervisado o algo así, aunque sabe que para acceder a esos recursos hay listas de espera muy largas. Incluso comentó que una vez que tuviera una vivienda en Zafra, no tendría problemas en acudir semanalmente al CRPS para asistir los talleres que allí se cursan, algo a lo que se ha negado en el pasado. ..... Pinta mal la cosa, y bastante dificil el ingreso de forma voluntaria almenos... --','2');
