insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-11-04','miguel, contestación de fiscalía a la pregunta de Angel de si es o no necesario pedir autorización judicial para gastos extraordinarios: Buenos días. En relación a la consulta planteada a esta Fiscalía, sobre la necesidad de solicitar autorización judicial para realizar gastos extraordinarios, pongo en su conocimiento lo siguiente: Sin perjuicio de la necesidad de proceder a la revisión del procedimiento de curatela, conforme a las previsiones de la Disposición Adicional quinta de la Ley 8/2021, revisión que puede solicitar en cualquier momento la propia persona con capacidad modificada o su actual tutor o curador, o realizarse de oficio o a petición del Ministerio Fiscal en defecto de los anteriores, se considera que la disposición de una importante cantidad de dinero para la realización de obras en la vivienda de Dª Antonia engracia Lavado, sí precisa de la solicitud de autorización judicial. Especialmente, si la cantidad se considera elevada en relación a su volumen de ingresos. Esta necesidad, viene de la aplicación del artículo 287.6 en su nueva redacción, del Código Civil, que se aplica, tanto al curador como tal (en su nueva regulación), como al guardador de hecho (artículo 264 párrafo segundo del Código Civil). Se considera que la realización de estos gastos, (para el caso en que la cantidad exceda de la media anual de gastos, o gastos habituales que precise la persona), requiere de previa autorización judicial que se tramitará mediante expediente de jurisdicción voluntaria (artículos 61 y siguientes de la Ley de Jurisdicción voluntaria). Atentamente: Mª José Hormigo Pérez. Fiscal Jefe de la Fiscalía de Área. (Sección medidas apoyo a personas con discapacidad). ********************************************* reenvío email a Alberto, Maite, Tere y Angel: Compañeros, fiscalía nos confirma que habría que pedir autorización judicial para los gastos extraordinarios de Antonia Lavado. Por tanto seguimos con el borrador que veré con Angel para intentar hacer petición de ingreso involuntario y solicitud para nos autoricen al arreglo de la vivienda','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2021-11-04','Ana: Reenvío a Alberto correo del ctutelar@ con factura e informe de las gafas que rompió Felisa a una profesional del centro. Ya se habló en su día, pero aún no se ha abonado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-11-04','Ana: Llamada de Mª Ángeles, propietaria de la vivienda de abajo de Martin (927 582 079 / 679 074 618): De nuevo le cae agua "literalmente a chorros" en su vivienda de la vivienda de Martín, tiene toda la pintura abombada. El otro día tuvieron que llamar a la policía. Su casa está inhabitable actualmente. A parte de esto existen más problemas de convivencia, entre otras cuestiones, pone la música a elevado volumen a altas horas de la madrugada. **Le indico, que a ser posible, nos lo comuniquen por escrito, e incluso si puede ser desde la Comunidad de Propietarios. *Enviarán también fotos. ············· Se adjuntará todo al escrito que envíen los Asesores Jurídicos al Jdo. exponiendo la situación. ································································································································································································ Correo a Toni - Futuex: "Buenas tardes Toni, ¿Qué tal? En relación a Martín Domínguez Palencia, quería preguntaros si finalmente acudió a la cita en Salud Mental el día 25 de octubre y solicitaros, nos remitáis, cuando sea posible, informe actual de la situación, pues se va a enviar desde la CTAEX comunicación al Juzgado aportando todos los informes de que disponemos, para solicitar la revisión de su capacidad y que adopten las medidas cautelares oportunas, incluido internamiento involuntario. Por otra parte, he recibido nueva llamada de la propietaria de la vivienda de debajo de la suya, pues de nuevo está entrando agua en su vivienda, según dice “a chorros”, motivo por el cual, actualmente está inhabitable. Podríais concertar con ella visita a su domicilio e incluso solicitar informe y presupuestos a los profesionales oportunos (fontaneros/albañiles). Te facilito su contacto: Mª Ángeles: 927 582 079 / 679 074 618 Ya me vais diciendo. Gracias y un saludo." ····························································································································································································· **Hablo con Miguel, Asesor Jurídico CTAEX: Cuando tengamos todos los informes correspondientes, elaborarán una comunicación al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2021-11-04','Ana: Llamada de la Librería de Cáceres en la que Benita ha encargado los libros de su nieto (927 224 364), nos enviarán la factura y el nº de cuenta al ctutelar@.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2021-11-04','Ana: Tras hablar con Maite, Jefa de Secc, envío correo a Toni de Diego, TS C.R. Cervantes: "Buenos días Toni, Esta mañana he estado hablando con Maite, Jefa de Secc. Plantea lo mismo que hablamos el otro día por teléfono: 1- Derivación por parte del médico de atención primaria (centro) a Salud Mental de nuevo para valoración. 2- Activar el protocolo de la residencia para estos casos, tal cual se actuaría con cualquier otra personas residente. Si Mª Luisa, estuviera tutelada por un familiar, ¿cómo lo haríais? Pues así, entiende, deberíais de actuar. Ante cualquier cuestión, seguimos en Contacto. Un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-11-04','TERESA Me pongo en contacto para comunicarte que la visita del mes de octubre la hemos alargado y no se ha hecho para que pudiera ir a principios de este mes y asi pudiera ver a su hija lo mas cercano posible a su cumpleaños. La cuidadora ha cerrado la visita con la abuela para mañana viernes día 5. No te he avisado antes porque hasta ayer no fue definitivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2021-11-04','Ana: María, TS de ASPACE, informa que la semana que viene acudirá al centro personal de la ortopedia con que suelen trabajar, para hacer el molde del asiento de la silla de Santi. Para otro año ya se comprará la silla. *No mantendrán informados y nos enviarán presupuesto.','2');
