insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-11-05','Ana: Llamo a David Lefevre, Serv. de Asuntos Sociales del Consulado de Francia en Madrid (917 00 78 36): no encuentran nada oficial, ni acta de nacimiento, ni de matrimonio ni certificado de adquisición de nacionalidad francesa, ni ningún otro justificante ni prueba de nacionalidad francesa. No pueden dar validez a la imagen del pasaporte, caducado en el año 1993, que les envié. *Le pido que nos envíen un certificado en que se indique lo que me ha explicado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-11-05','Buenos días, te informo que Idelfonso no ha querido ingresar, se contactó con él desde el Centro de salud de Zafra y rechazó ingreso. Con respecto a la información de la vacunación del paciente, te lo agradezco, ya que desde la Unidad de Agudos no tenían ese dato y es importante por si quiere ingresar en un futuro. Gracias. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2021-11-04','Ana: Correo Res. (balconextremadura@grupociudadjardin.com): "-- Buenos días, Ana te comento Isabel Pulido Caravaca esta muy bien, en ocasiones venia su hermano ha visitarla pero últimamente no recibe visitas de Familiares, lo que si Ana necesitaría comprar Ropa y Calzado lo que tiene esta muy deteriorado o pequeño, como lo podríamos hacer?? en Montanchez no tenemos tiendas de Ropa. Un Saludo"','2');
