insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-11-05','miguel, recibo email de Allianz, Oliver Rodriguez, Faustino >faustino.oliver@allianz.es>: Buenos días. Rogamos nos indiquen el/los destinatarios del pago de las facturas reclamadas, dado que la reclamación total la hace ese Organismo. ********************************************************** mi contestación: Buenas tardes, en contestación a su escrito comentarles que este organismo, Comisión Tutelar de Adultos de la Junta de Extremadura, que actúa en nombre y representación del incapacitado y curatelado D. José Moreno Carlos, quien fue atropellado por el vehículo asegurado por su compañía como quedó acreditado en el documento que ustedes remitieron. Les adjunto testimonio de aceptación de dicho cargo. El abono de todas las cuantías correspondientes a las facturas y gastos que legalmente correspondan, han de hacerlo a la cuenta de Liberbank nº ES21 2048 1112 4330 0003 3593, cuya titularidad ostenta el afectado D. José Moreno Carlos. Cualquier duda o documentación que necesiten, ruego se pongan en contacto por esta misma vía, o en el email ctutelar@salud-juntaex.es.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PULIDO'and apellido2='CARAVACA'),'2021-11-05','Ana: Llamo a Rosana, Dir.ª de la Residencia Balcón de Extremadura - Montánchez (927 380 516 // 603 19 44 81): Acordamos que para la compra de ropa para Isabel, derivaré al programa de FUTUEX a Isabel. Pediré, que si es posible, sea Gloria quien acuda, pues ya la tienen de referencia en los otros centros gestionados por le mismo grupo. ··············· Envío correo de derivación a Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-11-05','miguel, recibo contestación de Juana Heras: Buenos días. Remito a Alberto (parte económica)la respuesta de la oficina: La cuenta de la titular tutelada, tiene dos titulares indistintos. Ha sido el titular no tutelado quien se ha personado en la oficina para ordenar transferencia a favor del Ayuntamiento de Peraleda de la Mata con quien mantenía deuda según sentencia que se detalla en el concepto de la transferencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-05','Maite: Teresa se puso en contacto con dos centros , fuera dela CA , para ver la posibilidad de que José MAria ingrese an uno de ellos. He hablado hoy con ambos: - Hermanas hospitalarias ( Málaga), Ana/ Viriginia: 952256150.Virginia me dice que estaban pendiente de una alta para poder dar cabida a JOse Maria, y finalmente no se ha producido. Si mas adelante hay cambios nos avisarán. - Grupo 5 ( MAdrid): Susana 628313945. Es un centro de nueva creación,le habían comentado a Teresa que abrirían el 1 de diciembre. Se retrasa hasta el 1 de Enero. POdrán valorar su caso la primera semana de diciembre. HAsta entonces no pueden hacer nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-05','Ana: Recibimos nuevo informe médico del Serv. Urgencias del Hptal. Ciudad de Coria remitido por la propia Julia por correo ordinario: Fecha: 04/11/21. "Motivo del alta: Indeterminado", "...Cuenta que ha discutido con sus padres, llegando a dañar físicamente (mantiene que ha sido accidental) a su madre clavándole un colgante. Aquí muestra arrepentimiento" "...insisto en la posibilidad de permanecer en el servicio hasta hablar con Psiquiatría por la mañana para evaluación... pero mantiene la insistencia de marcarse a casa... finalmente cursa alta." Escaneo y guardo en el expdte. digital. ································································································································································································· Llamo a Marta, TS Cilleros. Justo esta mañana ha realizado visita domiciliaria conjunta con Gloria, Ed. Futuex. La casa está mucho peor que las primeras veces que fue Gloria. No reúne condiciones adecuadas de higiene y habitabilidad. ··········· También han acudido a hablar con Paco, Sargento de la Guardia Civil, quien a pesar de sus reticencias iniciales, va a actualizar el informe que dice haber enviado a la Junta, no sabemos bien a dónde, en 2019 y lo va a enviar al Juzgado. También se lo enviará a Marta, quien me lo hará llegar. ··········· **Marta realizará el informe social en el modelo de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-11-04','Ana: Correo de Ana, Enfermera de la Residencia: "BUENOS DIAS ANA : SOY ANA LA ENFERMERA DE LA RESIDENCIA , TE COMENTO : VALENTINA TIENE UNA CONSULTA EL DIA 11 DE NOVIEMBRE EN EL HUC CON EL TRAUMATOLOGO . NECESITA UNA ACOMPAÑANTE PARA ASISTIR A DICHA CONSULTA , EL ACOMPAÑAMIENTO , COMO EN CITAS ANTERIORES SERIAN 50 EUROS . ERA PARA VER SI ME LO PUEDES AUTORIZAR ,UN SALUDO . ESPERO TU RESPUESTA" ············· Se autoriza el acompañamiento. *Le pasaré a Alberto la declaración jurada al igual que la vez anteior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2021-11-05','Ana: Se autoriza presupuesto para la compra del frigorífico. Se lo comunico a Toni de Futuex, con los datos de contacto de Estrella, secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2021-11-05','Ana: Correo de Paula, TO CRR-Plas. (tocupacional.crrplasencia@grupo5.net): "Buenos días Ana, como te adelanté hace unos días hemos realizado la visita a domicilio de Conchi en Madroñera (cerca de Trujillo). El objetivo de la visita era tanto ver las condiciones de habitabilidad y acondicionamiento de la vivienda como una intervención psicológica de afrontamiento; por este motivo fuimos tanto la psicóloga como yo. Además nos acompañaron una hermana de Conchi y el marido de la hermana. La casa necesita varias mejoras (en cuanto pueda os envío las fotos) en relación a humedades en los dormitorios, una barandilla de ladrillos con riesgo de derrumbe en la terraza, necesidad de pintura en toda la casa, ausencia de colchones y algún que otro mueble y electrodomésticos; esto en la zona superior o de vivienda (tiene una planta baja que necesitaría al menos limpieza y reparar una puerta para limitar el acceso). La vivienda está dentro del pueblo, menos alejada del centro del pueblo que la Residencia del centro de Plasencia. Te explico esto porque la familia insistía en este hecho como dificultad, pero es cierto que ella va cada día una o dos veces al centro de Plasencia desde el CRR sin problema. Queríamos consultaros las posibilidades reales de acondicionar la vivienda para tratar de hacer una intervención en el domicilio, con apoyos y de forma progresiva, evaluando así la viabilidad tras la intervención del regreso a casa (con todos los apoyos). Pero para esta intervención sería indispensable el arreglo de la vivienda. Paralelamente continuamos interviniendo con Conchi para la adquisición de estrategias de afrontamiento y herramientas para poder realizar la intervención en el momento en que todo esté dispuesto." ·················· Mi respuesta: "...Para que Alberto, Jefe secc. ecca., pueda hacer una valoración real de la viabilidad de la limpieza y las obras de acondicionamiento que requiere la vivienda de Conchi, necesitaríamos presupuestos específicos de los profesionales correspondientes. Dime si desde el centro, o través de los familiares de Conchi, se pueden conseguir los mismos, pues creo que sería lo más rápido. Si no fuera así, puedo proceder a la derivación de Conchi al programa de Apoyo Comunitario de Futuex (que en el futuro tendrán de intervenir también) para que vayan conociendo a Conchi y se encarguen de estas gestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2021-11-05','Ana: Remito por mail a Fermina, Res. de Mayores Francisco Sánchez Salazar: la autorización para el uso de contención física firmada digitalmente por el Representante Legal.','2');
