insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2021-11-08','Ana: Tras llamada de Felisa (722 494 033), comunicando que ya han ingresado el dinero rescatado del fondo de inversiones en su cuenta, solicita se compren los sofás, que necesita, así como la campana extractora y se pinte la casa. *Hace varias semanas que, según dicen, le entregaron los presupuestos a Virginia, Ed. Futuex. ················································ Envío correo a Toni-Futuex solicitando nos remitan los presupuestos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-11-08','miguel, recibo email de Emiliano de inmobiliaria Infofinca donde me pide le confirme si tramitan el certificado energético y la cédula de habitabilidad. Le confirmo que lo pida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-11-05','miguel, recibo email de inmobiliaria. Ya hay comprador para vivienda de c/Constitución: Buenos días Miguel, te adjunto el DNI del señor que se quiere comprar la vivienda de Guadiana por los 40.000 Euros del precio de venta, hemos estado negociando con él y hemos conseguido sacarle los 40.000 Euros. Pásame el número de cuenta donde tiene que hacer el ingreso de la reserva de 3.000 Euros y a nombre de quien está la cuenta. ********************************************** Mi contestación a Emiliano: Perfecto Emiliano, la cuenta a la que hacer la transferencia es de Caja Rural ES93 3009 0035 2822 0339 4818 cuyo titular es Juan Carlos Rubio Galan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2021-11-08','Ana: Conversación con Juan José (667 958 878): Mañana se van a mudar del piso al CRR de forma temporal, hasta que encuentren un nuevo piso, pues según le han dicho, pues según le han dicho, en el que están no reúne condiciones y además no pueden pagar. *Hablaré con Pedro o Paloma, T.O. - CRR. *Le tienen que hacer una resonancia, pues tiene daño en el menisco y la rótula desgastada. ······· Su cumpleaños fue el día 18 de octubre y quiere un extra para comprarse una esclava de plata. *Enviará presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-11-08','miguel, envío email a Alberto: Alberto, me confirma la inmobiliaria que la señal debe aparecer en Caja Rural ES93 3009 0035 2822 0339 4818 de 3.000€ por si lo queréis comprobarlo. Por otra parte me ha preguntado si hacen o no el certificado energético y si piden la cédula de habitabilidad. Le he confirmado que pidan ambas cosas, que son necesarias para la venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-11-05','miguel, recibo email de Alberto: CUESTIÓN: ESTA MUJER (VIUDA PK SU MARIDO TB TUTELADO FALLECIO HACE TIEMPO) YA ESTA EN CENTRO Y ANA INDICA QUE NO VA A VOLVER A VIVIENDA PARATICULAR + EN VIVIENDA PARTICULAR SE SOSPECHA O SABE QUE HAY OCUPAS (MIGUEL YA SE HA HABLADO DE ESTO EN CORREOS ANTIGUOS). HAY QUE INICIAR VARIAS ACTUACIONES SITUACIÓN ECO: 2 CCC: IBERCAJA (TITULARIDAD COMPARTIDA ENTRE MARIDO TUTELADO FALLECIDO Y TUTELADA) Y LIBERBANK (SOLO TUTELADA Y DONDE HAY INGRESOS X PN VIUDADAD TUTELADA, TB PAGAMOS CENTRO) . INGRESOS: DESDE HACE UNOS MESES COBRA UNA PN VIUDEDAD X 689,70 €/MES X 14. . IBERCAJA (COMPARTIDA): SALDO 2021/11/05: 9.264,36 € (- 3.000 € ESTE ÚLTIMO AÑO) . LIBERBANK (SOLO TUTELADA): SALDO 20WQ/11/05: 6.040,17 € (ESTE SALDO NO ES REPRESENTATIVO DEL TODO PK AUN NO ESTAN TASADOS LOS GASTOS AÑADIDOS AL PAGO DE LA PLAZA) MIGUEL: TEMA OCUPAS: TU DECIDES LO QUE HAY QUE HACER + DESE PARTE ECO, SALVO QUE TENGAS ALQUE QUE DECIR, VAMOS A DAR BAJA A LUZ, AGUA Y TELÉFONO. MIGUEL: HERENCIA. QUIZÁS DEBAMOS COMENZAR CON LA HERENCIA DEL MARIDO. ANA INDICA QUE NO TIENEN HIJOS. ICIAR: URGENTE: DAR BAJA RECIBOS DE AGUA, LUZ Y TELÉFONO EN COMPAÑÍAS (TE ADJUNTO RECIBOS) + ADEMÁS SOLICITAMOS A IBERCAJA QUE DEVUELVA TODOS LOS RECIBOS POSIBLES (TE ADJUNTO ESCRITO "2021-11-05 DEVOLUCION RECIBOS Y BAJA DOMICILIACIONES BANCO" PARA QUE TRAMITES) ICIAR: HAY QUE REDOMICILIAR EN LA CCC DE LIBERBANK SEGURO DECESO, SEGURO HOGAR E IMPUESTOS: TE ADJUNTO RECIBOS. ICIAR: TRANSFERIR DE IBERCAJA A LIBERBANK 5.000 € Y CUANDO SEA POSIBLE TRANSFERIR EL RESTO Y CANCELAR IBERCAJA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2021-11-08','miguel, reunión con Alberto, conclusiones en su email:PROPIEDADES: JURIDICOS: SOLICITAN NOTA SIMPLE Y CATASTRO PARA VER LAS PROPIEDADES - OJO: QUIZÁS PENDIENTE HERENCIA MARIDO. ADEMÁS DE LA VIVIENDA EN COMÚN EN CATASTRO DEL MARIDO (ANTONIO PAREDES DICHA) FIGURA OTRA PROPIEDAD. ICIAR: DAMOS DE BAJA AGUA LUZ Y TELÉFONO Y REDOMICILIAMOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2021-11-08','miguel, tras reunión con Alberto, quedamos (Angel y yo) que hablaré con el Ayuntamiento de Peraleda de la Mata para ver lo del cargo de los 48.000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-11-08','Ana: Correo de Estrella Durán, TS del CSS (estrella.duranc@salud-juntaex.es): "Os escribo para si es posible, nos enviéis autorización para sacar dinero de la entidad bancaria de Alfonso Marín de Cáceres, ya que está aquí ingresado en UME, su madre está en Madrid y le es muy difícil mandarle dinero. Ahora mismo no tiene tabaco ni dinero y tenemos que comprarle cartón de tabaco y dejarlo a deber en el estanco, porque no fumar lo irrita mucho." ···························· Hablo con Alberto, jefe secc. ecca. *Estrella, secc. ecca., enviará la autorización general al CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2021-11-08','Ana: Toni, Futuex, me remite informe de Virginia, Ed. junto con otros informes médicos recientes. ························ Envío correo con toda la documentación pertinente a Miguel, Asesor Jurídico CTAEX, para que pueda solicitar internamiento involuntario al Jdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2021-11-08','Ana: Correo de Ana Amor, Psicopedagoga de PLACEAT (ana@placeat.org): "El pasado viernes 5 de noviembre, Cristofer huyó del Centro Ocupacional de Plasencia, donde acude desde el 20 de octubre. Su intención era la de ir al hospital para que le ingresaran en la UHB de psiquiatría. Antes de llegar al hospital, una monitora consigue encontrarle. Se niega a volver al centro ocupacional, la agrede agarrándola del cuello. Llega al hospital y le atiende de urgencias la psiquiatra de guardia. Yo me persono en el hospital para hacer la consulta de urgencias. Le explico la conducta habitual de Cristofer. Ella hace su exploración psiquiátrica y decide No realizar ingreso en la unidad de psiquiatría. Cristofer insiste en su necesidad de ingresar, querer cambiar de centro e irse a Badajoz "La Luz". Le ponen relajante inyectado y regresamos a residencia San Gil. Donde se tranquiliza y pide perdón por el comportamiento, manifestando que quería hablar con un psiquiatra y que por eso huyó. Actualmente, estamos ante un problema conductual grave, ya que la ida al centro ocupacional de Plasencia supone un atractivo para que Cristofer mantenga la conducta de huida. Es posible que empiece a mantener este comportamiento y pueda ocasionar algún incidente en el exterior, ya que deambula por la calle sin cuidado y corre el peligro de atropello. Nuestro centro es un centro sin personal de seguridad y de puertas abiertas, por lo que la persona tiene fácil la huida. Existe vigilancia de los monitores, pero no es una atención de uno-uno, por lo que pueden darse estas huidas con facilidad. Es necesario que estéis informados de esta casuística y de la responsabilidad que conlleva que Cristofer asista a este servicio. Si esta conducta no cesa, habría que pensar en recursos de apoyo extenso para problemas de alteración grave de la conducta. Continuaremos trabajando para que pueda controlar este comportamiento, que en el entorno de Residencia de San Gil está bastante controlado, aunque surge esporádicamente. Les adjunto informe de urgencias." ········· Guardo informe en el expdte. ················· Le contesto e indico que lo comuniquen también a la Secc. de Discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2021-11-09','REACTIVACION EXPTE. Se reactiva el presente expte. por haber sido nombrado, definitivamente, Curadores Representativos.','2');
