insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2021-11-05','-Amalia : Elaboro Plan de Intervención Inicial . Hablo con la Dtra. del Centro Nexus donde se encuentra ingresada en Centro residencial . Tf 927276471 email: gsanchez@nexusintegral.com Hemos sido nombrados Adm. de Bienes mientras se termina proceso de incapacitación . Hay que asegurar todo lo relacionado con la plaza residencial y su abono . Ingresa 1154E x 14 pagas + PVS dependencia de 409€ Por la plaza residencial abona 1428€ Ahorros 1700€ Hay que reducir gastos , no cubre la totalidad de la plaza . Se establece presupuesto con la sección eco .','2');
