insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DE LOS ANGELES'and edp.apellido1='ROSADO'and apellido2='ALBARRAN'),'2021-11-09','PTO. ESTABLECIDO DESDE PARTE ECO : ESTRELLA: BAJA INMEDIATA EN EL SEGURO SALUD DE CASER. TE ADJUNTO RECIBO. AMALIA: GASTOS MENSUALES: XFA, QUE CENTRO TE ENVIE LA DEUDA TOTAL HASTA AHORA Y QUE, A PARTIR DEL MES SIGUIENTE, DETALLE EN CONCEPTO CORREO: ÁREA ECONOMICA Y GASTOS MENSUALES A ABONAR!!! AMALIA: A PESAR DE QUE DEMOS DE BAJA EL SEGURO DE SALUD, SI ESOS GASTOS MENSUALES SON ELEVADOS, DUDO QUE PODAMOS PAGAR ESE CENTRO. CREO QUE NUNCA DEBERIAN SUPERAR LOS 100 €/MES Y NO SE SI ASÍ Y TODO SE PODRÍA SOPORTAR EL GASTO...NOS HEMOS QUEDADO SIN DINERO.','2');
