insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-11-08','Ana: Correo-e de Sonia Bernabé (trabajosocial@asindi.e.telefonica.net): "... Han dado el alta a Roberto Hernández Castaño y regresa esta tarde. Esperemos que con ajuste de tratamiento esté mejor. Su familia está desando verle."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-11-09','Ana: Correo-e de Sonia Bernabé (trabajosocial@asindi.e.telefonica.net): "- Ignacio Rodriguez Alcántara esta mañana se ha empezado a encontrar mal y por los síntomas que presentaba le han hecho un test de antígenos en la residencia. El resultado ha sido positivo, pero al trasladarlo al Centro de Salud nos han dicho que lo mejor es confirmarlo con PCR. En otras ocasiones de cribado, a los profesionales les ha costado obtener bien la muestra de Ignacio. Por lo tanto, estamos pendiente de que nos digan si se confirma el resultado positivo. Ahora mismo él y su compañero están aislados a la espera de resultados. Coincide que en el pueblo hay varios positivos y hoy están haciendo PCR a los contactos estrechos. Esperemos que todo vaya bien."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-11-09','Ana: Correo-respuesta de Estrella, TS - CSS: "Lleva ingresado desde el 21 de septiembre, pensaba que lo sabías...venía de estar en la Unidad de Agudos...., di por hecho que o bien la madre, o el Juzgado, o desde Agudos os lo habrían comunicado" , "...también lo sabe Gloria de Futuex, de Cáceres, llamó ayer y algún día más para preguntar por él" ·························· Le envío correo: "Al propósito de este tutelado, ¿sería posible, cuando se encuentre mejor, trabajar con él el acceso a recurso (CRR) y solicitarlo desde ahí?? Dado el estilo de vida tan poco saludable que lleva en el domicilio familiar, considero que sería contraproducente que regresara al mismo. Ya me decís." ································································································································································································· Respuesta de Estrella: "Buff, Ana. Ni nos lo hemos planteado porque tiene cero conciencia de enfermedad, no me ha dejado ni hacerle entrevista para abrirle historia social, con la Psiquiatra tampoco colabora nada, es un paciente muy difícil....mañana comento esto que me dices en la reunión de unidad, pero ya te digo cómo se muestra Alfonso.... " ································ Mi respuesta: "Buenas tardes, de nuevo, Estrella, En ese caso, igual le toca pasar una larga temporada con vosotros… desde luego lo que no vemos es que retorne al domicilio y menos si la conciencia de enfermedad es nula… Ya me vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2021-11-02','Ana: Llamada de Juan Carlos, cuenta cómo ha ido los últimos días y las actividades que ha realizado. Pregunta cuándo podrá irse a un centro y además, dice que "las niñas" (refiriéndose a las Ed. de Futuex) no van, que cuándo va a ir a verle. ······· Fijamos día para próxima llamada el lunes 15 a las 12 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-11-09','Amalia : Hablo con Ati , llamando al tf del Hostal para ver qué propuestas tiene tras rechazar su ingreso en UME . No quiere seguir en el hostal , se le da plazo máximo el mes de noviembre , no es viable economicamente los 55€/ dia +225€ semanales que percibe. Quiere alquilar un piso en Zafra pero quiere que se le de el dinero en efectivo para abonarlo . Le insisto en que el pago se hará vía transferencia bancaria o domiciliando el pago . La última semana de noviembre se avisará al hostal para cancelar la estancia . Tiene pendiente hacerse el DNI .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-11-09','Ana: Envío correo a Estrella, TS del CSS: "Buenas tardes Estrella, En relación a Andrés Silva Bonifacio, queríamos saber cómo sigue. ¿Podrías enviarnos Informe de Seguimiento de la UHDAC para conocer la evolución y situación actual, así como incidencias acaecidas, si las ha habido, en los últimos meses? Gracias y un saludo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2021-11-09','Ana: Se acepta presupuesto para botas, que remiten desde Futuex. ··········· Estrella secc. ecca. se encarga del abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-08','Ana: Llamada de Marta, TS SSASB de Cilleros, comunicando nueva incidencia relativa a Julia: Según dice ésta ha sufrido abusos por un chico de Navalmoral de la Mata con el que contactó por internet y que fue a visitarla al pueblo. Paco, el sargento de la Guardia Civil, la ha citado a ella y a su madre. ·································································································································································································· Llamada de Paco, Sargento de la Guardia Civil (680 420 218), me facilita el correo para que le remita el Auto de Nombramiento de Tutor y Aceptación de Cargo (cc-pto-cilleros@guardiacivil.org). Así hago. ········· En cuanto a la supuesta agresión, han tomado declaración a Julia y la ha reconocido el médico forense. ········ Hoy la han acompañado al cuartel Gloria, Ed. Futuex y Marta, TS SSASB. *Paco dice que no debería seguir residiendo en la casa familiar, pues existe riesgos para ella misma y para los padres por violencia intrafamiliar. Indico que nosotros no disponemos de recursos propios y no hay recursos residenciales a los que pueda acceder hoy mismo. Sólo podría abonarse un hostal/pensión... pero Paco dice que no está capacitada para vivir sola. Estamos de acuerdo en ello. ······························································································································································································ Tras valorarlo en equipo en la CTAEX: Llamo a Marisa, TS ESM (70858), proponiendo que activen desde el ESM el 112, para ingreso de Julia en UHB dado el incremento del riesgo a la vista de lo últimos incidentes. *Marisa dice que eso ya se ha intentado y no ha servido, pues en el hospital consideran que no existen criterios de ingreso en UHB. ····· Por otra parte, dice que en 2015 en el CADEX, Julia dio perfil para ingresar en Caminomorisco, llegó a ingresar en C.D. de Nuñomoral, pero la madre, como tutora, solicitó la baja del recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2021-11-10','Ana: Envío autorización para la vacuna de la gripe firmada electrónicamente por el representante legal.','2');
