insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-11-10','TERESA Teresa buenas tardes, no puedo facilitarte el contrato no obra en su expediente, si aparece la primera pagina del mismo donde aparece su direccion C/ Federico Garcia Lorca, 6,2-B de Almendralejo. Perteneciente al grupo 7097 y cueta 27, te lo facilito porque te sera util a la hora de solicitar un duplicado. Añadir que hoy he recibido a la vecina de Antonia que reside en el 1-B, la misma tiene una gotera continua en su cuarto de baño ocasionado por desperfecto en la vivienda de Antonia, te lo comento por si pudierais cortar el agua y asi no perjudicarla , maxime cuando la gotera esta en contacto con el suministro electrico con riesgos a que se produzca un cortocircuito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2021-11-10','Ana: Correo-e de María Glez. Palomo, TS Autismo Sur (teayudamos@autismosur.es): "me acaban de llamar para avisar que el próximo viernes vienen desde la junta de Andalucía a revisar el grado de dependencia de Alex. Solo es por informarte..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2021-11-10','TERESA Te adjunto el recibo del viaje a Trujillo realizado como siempre por Patricia por una cuidadora del centro. Me ha comentado que los dos ultimos viajes no los ha cobrado, ni agosto ni septiembre. Me comenta que hicieron una pequeña celebración de cumpleaños de la niña y que fue todo muy bien, estaban los primos pequeños, una tía y los abuelos. La expareja de Beatriz (el padre de la niña) también estaba en la casa pero se quedó en la cocina y casi no lo vieron. Beatriz le llevó la tarta, la piñata y varios regalos y está muy contenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-11-10','miguel, llega la liquidación sellada y presentada del impuesto de sucesiones complementaria de la oficina liquidadora de Herrera del Duque','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-11-10','Ana: Remito a Rosa, Admvo. CSS, CI para Colonoscopia-Ileoscopia, debidamente firmado y sellado por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2021-11-10','miguel, llega la liquidación sellada y presentada del impuesto de sucesiones complementaria de la oficina liquidadora de Herrera del Duque. ***************************************************** Envío email a Estefanía la abogada adjuntando dicha liquidación ya presentada: Buenos días, te adjunto liquidación complementaria ya sellada por la oficina liquidadora de Herrera del Duque. Si es necesario algo más para el desembolso del importe de la funeraria dímelo. Sigo pendiente que me confirme la notaria de Herrera del Duque (Loli) si tienen o no ya firmado la declaración de herederos del hijo de Alfonsa, Agustin.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-10','Ana: Correo de Marta, TS SSASB Cilleros (tsocial@ayuntamientodecilleros.es): "Hola buenos días Ana Te adjunto el informe social para dependencia de Julia, el informe de la Guardia Civil detallando cada actuación que se ha realizado con ella desde el año 2014 hasta la actualidad, la diligencia de manifestación/denuncia de Julia con respecto al asunto del abuso sexual y las fotografías del domicilio. Todo ello lo acabo de enviar a dependencia esta mañana, pero Julia justo me ha llamado hace un rato contándome que le habían llamado los de dependencia para venir a valorarla, estoy intentando ponerme en contacto para verificar si es cierto. Cualquier cosa te voy informando."´······················································································································································································· Envío correo a Dolores Venegas, EVD: "Buenas tardes Lola, ¿qué tal estás? Te reenvío correo de la Trabajadora Social del SSASB de Cilleros, relativo a Julia Morón Hernández, tutelada por la CTAEX, de este caso ya hemos hablado e intercambiado correos en otras ocasiones, pues es un caso complicado y que nos preocupa mucho. La situación ha ido a peor. La compañera ya ha registrado todo esta mañana, pero he pensado en enviártelo todo a ti para agilizarlo más. Por otra parte, agradeceríamos que nos confirmes, si es verdad que la habéis llamado para ir a valorarla, pues se lo ha dicho esta mañana ella a Marta, Trabajadora Social. Si no es así, por favor, priorizar el expte. ahora que tenéis el informe social firmado por la compañera del SSASB, pues con el mío (en ausencia de compañeras en el Ayto.) no se priorizó. Como ves, se adjunta también informe y diligencias de la Guardia Civil de la Localidad. Es una situación de emergencia y habría que darle recurso residencial a la mayor brevedad. Ante cualquier cuestión, no dudes en contactar. Un saludo y buena tarde. P.D.: Pongo en copia a Maite, Jefa de Sección de la CTAEX."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2021-11-10','Ana: Llamada de Maribel, TS Resid. Parque del Príncipe (927 244 421), María reside en su centro. Han recibido la sentencia en que nombran curadora a la CTAEX. María reside en su centro. *Le indico que estamos pendiente de recibir la firmeza de la sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2021-11-10','Ana: corre de Alberto, jefe secc. ecca. para Icíar (me pone en copia): "ICIAR: X FAVOR, HABLA CON EL CENTRO PARA QUE HAGAN USO DE LA AUTORIZACIÓN GENERAL Y NO NOS TENGAN MACHACADOS CON CONTINUAS TRANSFERENCIAS X VISITAS. X EJEMPLO: QUE SAQUEN EL DINERO CON SU AUTORIZACIÓN Y SE LO ENTREGEN A LA TUTELADA PARA QUE ESTA SE LO DE A SU MADRE. INCLUSO PODEMOS AUTORIZARLES ESTA OPERACIÓN X CORREO ELECTRÓNICO CON UN MÁXIMO DE 1 VISITA X MES. SI NO HAY ACUERDO: TENDRÍAS QUE TRANSFERIR LOS 20 € A MADRE TUTELADA TAL Y COMO SOLICITA ANA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2021-11-10','miguel, llega email de aprosuba Badajoz a traves de Amalia: Buenos días Amalia: Te mando este correo con un asunto deveras asustador, pero se trata de una situación muy complicada. Por una llamada a Sara (profesional del centro ocupacional) del padrastro de Pilar, Lolo, que es la actual pareja de su madre, nos enteramos que al parecer, la madre de Pilar está exponiendo las partes sexuales a su hija, por fotos compartidas, desconocemos se a contactos o a redes sociales. Pilar la usuaria, es muy hermética y no cuenta nada. Os hemos comentado que con esta familia nos deberíamos de sentar y recordar sus obligaciones. Si te parece bien, quedo a la espera de una llamada para ver como vamos a tratar el tema. *********************************** Email de Amalia: os reenvío email sobre Pilar Rodriguez Escalera , usuaria de CO en Aprosuba 3 . En base a su sentencia y a las informaciones que nos da el centro , cómo se puede actuar ? al parecer , el novio de la madre ha llamado a una de las monitoras contando ésto . No sabemos si será cierto o no , ellos siguen viviendo juntos . No sé si a nivel jurídico procede hacer alguna gestión . Voy a reunirme con Aprosuba 3 , con la usuaria y su madre a petición del centro . Espero vuestra respuesta por si procede hacer algo más . ********************************************** mi contestación al email de Amalia y la conversación que tengo con Catarina de Aprosuba Badajoz: Buenas tardes, acabo de hablar con Catarina de Aprosuba de Badajoz. Debemos hablar con urgencia de este asunto. Me da a entender (no se puede demostrar) que han ocurrido cosas desagradables ya anteriormente en esa casa. Parece ser que el padrastro ha llamado muy dolido porque le pide dinero la madre de nuestra tutelada Pilar y les ha enviado un audio donde la madre pide a la hija que se haga fotos de su partes intimas para enviarlas (internet, wasap?). La he pedido discreción y que recabe todo lo que se pueda, informes psicológicos, sociales, médicos del centro, cualquier cosa para que notifiquemos a fiscalía y haya base para empezar una investigación. Sería necesario que urgentemente se busque un nuevo hogar a esta chica de 24 años (es muy sensible y llora en cuanto le preguntan algo)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2021-11-10','Ana: Correo de Estrella, TS CSS, reenviando correo con "informe" de la Mª Paz, Psicóloga de la UHDAC: "A petición de la CTA, se informa de evolución del paciente ingresado en la UHDAC desde junio de 2020 procedente de la UHB de Mérida. Durante su estancia en nuestra Unidad la evolución es tórpida y fluctuante. Oscilando periodos de mayor estabilidad conductual con otros de frecuentes y graves alteraciones de conducta (autoagresividad en forma principal de ingestas, heteroagresividad, conductas anormativas) que requieren de vigilancia y supervisión continua, con fines instrumentales y movilizadores, generando múltiples y graves injerencias en el funcionamiento de la Unidad. Con demanda recurrentes e inestables desde recibir el alta hospitalaria a permanecer en la Unidad de manera residencial, conllevando importante dificultad para el establecimiento de vínculo e intervención terapéutica, y reaccionando de manera abrupta cuando no se cede a sus demandas. Se objetiva una fragmentación afectiva marcada, con graves dificultades para la vinculación, expresión e identificación emocional. Muestra estados anímicos ambivalentes, pasando de la euforia al decaimiento anímico sin razón aparente, y que según el paciente atribuye la causa de su tristeza a la desvinculación afectiva con su madre. El discurso es pobre y superficial, algunos días casi imposible, porque únicamente se limita a demandar el alta y es impermeable a cualquier tipo de diálogo o intervención. En lo referente a la esfera del desarrollo psicosexual, en diagnósticos previos se recoge disforia de género, no parece tampoco haber una clara integración de los conceptos de identificación y orientación, manteniéndose en un espacio de indefinición y ambivalencia, algo que no es infrecuente en otros pacientes con este nivel de discapacidad intelectual. La psicopatología del paciente pone de manifiesto una estructura muy frágil, tremendamente vulnerable e influenciable. Considerando los antecedentes, la clínica actual y las expectativas de sostén futuro, el pronóstico del paciente no parece muy favorable."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2021-11-10','Ana: Envío a Fermina, Res. Aldea Del Cano (ferminasanchezgarcia@gmail.com), Autorización para la vacuna de la gripe firmada digitalmente por el representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2021-11-10','Ana: Envío a Fermina, Res. Aldea Del Cano (ferminasanchezgarcia@gmail.com), Autorización para la vacuna de la gripe firmada digitalmente por el representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2021-11-11','Amalia : escribo al ESM Mérida para pedirle cita allí . Jue 11/11/2021 9:40 Buenos días , te escribo en relación a un usuario , tutelado por la Comisión Tutelar de Adultos , Rafael Cacho García. Queríamos saber si ha acudido alguna vez a ese ESM , y si es así si tiene algún tratamiento pautado . Así mismo , solicitamos como tutores ,información para solicitar cita con el equipo para retomar seguimiento de su patología mental . Te llamaré también por teléfono para comentártelo por si no ves este email . Un saludo . -------------------------------------------------------- Llamo por tf a la TS del CEDEX Mérida ( Marisa ) para preguntar por este usuario . Hace años que no tiene tratamiento y desconocen su estado . Estuvo en julio para pedir informes médicos de los centros penitenciarios por dónde ha pasado . Solicito cita para él , dia 29 Nov a las 12.00 con la TS y 12.30 con la Doctora Angeles Piriz. Me dice que es muy agresivo y que tendría primero que ir estabilizado de su patología mental . Le indico que igualmente se está solicitando cita para el ESM . --------------------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2021-11-11','-Amalia: hablo con la TS ESM , no hay nada en sus bases de datos . Para derivación al equipo tiene que ser a través de su médico de At. Primaria . LLamo al tf de EAP del Centro de salud de Mérida Norte 924487228 , para que le den cita y derivación al ESM , nadie lo coge .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-11-11','Ana: David Lefevre, Consulado de Francia en Francia (david.lefevre@diplomatie.gouv.fr), nos remite correo con Certificado del Consulado indicando que no disponen de ninguna prueba de nacionalidad francesa y por tanto no pueden renovar ninguna documentación francesa a su nombre. ···················· Guardo en el expdte. el certificado y reenvío a Ángel, Asesor Jurídico el correo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-10','Ana: Recibimos comunicado del Juzgado informando de la denuncia que ha interpuesto Jose Manuel Correa Morato, nieto, a la Residencia Geryvida. ························· Tanto Ángel, Asesor Jurídico, como yo, hablamos con Mercedes Vega, Médica del Centro. ····························································································································································································· Correo de las médicas de Geryvida (direccionmedica@geryvida.com): "Buenas tardes , según conversación mantenida con vosotros esta mañana , os comunicamos que hemos derivado al servicio de urgencias hospitalario esta tarde, a Dña Manuela Morato Picado por presentar en la exploración realizada esta mañana , dolor a la movilización del tobillo derecho y hematoma en el mismo , para descartar lesiones óseas . En el día de hoy hemos hablado del tema del traslado , y nos parece que no hay ningún inconveniente en dicho traslado . Hemos tramitado la cita con su MAP , para que realice el informe se salud anexo II de la Solicitud de Dependencia Saludos cordiales Dra Mercedes Vega y Dra M Luisa Pinilla."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2021-11-11','miguel, llega por carta testamentaria de la madre fallecida de la tutelada consistente en dni, certificado de defunción, últimas voluntades y cartillas de la cuenta del Sch con saldo de unos 3.000€ (único bien a declarar y repartir). Compruebo que en catastro no existen más bienes. Hay que hacer la declaración de herederos ya que fallece sin hacer testamento, el cual hay que hacerlo en la notaria de Azuaga, lugar de fallecimiento ya que falleció en la Residencia Socio Sanitaria Hogar San José. Hablo con Teresa para que localice dos testigos para dicha declaración de herederos.','2');
