insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-11','Ana: Correo de Dolores, EVD Plas.: "Hola Ana , te comento , LA VIA NO ES DEPENDENCIA YA TE LO DIGO YO, por esto : 1. con respecto a esta señora, nosotras NO PODEMOS priorizar ningún expediente , POR PROTOCOLO. No está en nuestra mano. 2. En el Baremo valoramos actividades muy , muy básicas , que esta señora las realiza, yo la valoré en 2015, obtuvo 1 punto. Veo que la casa tiene mucho desorden, y tienden a acumular objetos , pero eso no es dependencia eso tiene otro nombre que en todo caso es Síndrome de Diógenes . 3 . No se si se ha llamado o no para valorarla porque nosotras no llamamos, es el Call Center el que "nos prepara" la agenda semanal. Yo estuve el lunes en Cilleros 4.Entiendo que es un tema de Emergencia Social , pero que se solicite un centro de discapacidad que valore el CADEX, ya que presenta un 65 por ciento de discapacidad. y hasta llegó yo Un saludo" ················ Lo reenvío a Maite, Jefa de Secc. ······························································································································································································ Conversación con Pilar Martín, TS del ESM-CC: en abril de 2021 no se acepta el ingreso en UHDAC en base a su diagnóstico de INTELIGENCIA LÍMITE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-11-11','Ana: Correo-e de Sonia Bernabé (trabajosocial@asindi.e.telefonica.net): Hola Ana, al final Ignacio Rodriguez Alcántara es positivo. él se encuentra bien. Se hizo cribado y, de momento, es el único residente contagiado. Les repiten la prueba el lunes o martes. Esperemos que ya haya pasado y no salgan más positivos. Os iremos informando. Un saludo,"','2');
