insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-11-11','TERESA NOS COMUNICA LOLA DEL CSS MERIDA QUE FINALMENTE ANOTONIA ACCEDE A INGREAR EN R MAYORES. LE VAN A SOLICITAR PLAZA POR EMERGENCIAS SOCIAL LA VIVIENDA NO LA VAMOS A ARREGLAR PUESTO QUE YA NO LA NECESITA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDA'and edp.apellido1='GARCIA'and apellido2='CARRILLO'),'2021-11-11','TERESA RECIBO LLAMADA DE TONI PAJARES SOBRINA DE SEGUNDA PARA COMUNICARME QUE EN SU VIVIENDA DE VILLAFRANCA ESTA SUFRIENDO INUNDACIONES A CAUSA DE UN PATIO QUE SE INUNDA ME FACILITA PRESUPUESTO DEL ARREGLO Y NOS QUEDA LA DUDA SI EL PATIO ES COMUNITARIO Y POR LO TANTO SERIA LA COMUNIDAD QUIEN TENDRIA QEU CORRER CON LOS GASTOS DE DICHA OBRA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDA'and edp.apellido1='GARCIA'and apellido2='CARRILLO'),'2021-11-11','TERESA EMAIL DE TONI SU SOBRINA Teresa te estoy llamando porque de escrituras ningún familiar tenemos nada. Suponíamos que eso lo teníais la Comisión Tutelar. Estoy intentando hablar con él Albañil para que me dé presupuesto del umbral, bisagras para la compuerta y arreglo de la puerta. Y cuando averigüemos de quién es competencia lo del sifón, a quien le competa que vuelva a pedir prepuesto. Esperemos que no ocurra nada antes y no tengamos problemas por el bien de todos. Espero que entiendas mi posición pero estoy agobiada por este asunto ya que nadie se quiso hacer cargo de nada en su día y para algunas cosas una tiene que estar ahí ( siempre para casos malos como son avería de esta envergadura o averiguar casos hospitalarios) Es una pena pero así es Y gracias a vosotros ( a tí en particular ) por hacer las cosas más Justa posibles en su beneficio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2021-11-11','miguel, llega email de Amalia: Buenos días , a esta chica se le ha intentado pedir plaza residencial de discapacidad en varias ocasiones pero se niega a ingresar en centro . Es por ello que ocupa una plaza en centro ocupacional , acude al centro a las 9.00, la recogen en transporte de la entidad y regresa a las 18.00h de L a V . Se puede solicitar internamiento involuntario en centro de discapacidad ?? se necesitaría autorización judicial . Y aunque ingresara , son centros abiertos , si no quiere permanecer allí se irá del recurso . Esperamos vuestra respuesta . ******************Mi contestación a Maite, Angel y Amalia: Buenos días, como sabéis un internamiento involuntario (que debe ir acompañado como habitualmente de un informe social y médico). Entiendo que debido a la situación de urgencia y excepcional, como ya indiqué en mi email y así se lo dije a Catarina de Aprosuba 3 Plena Inclusión de Badajoz, lo suyo es que recaben pruebas (con sigilo absoluto), ya sean informes médicos, psicólogicos, sociales, denuncias, etc, y una vez que tengamos algo lo remitiremos a Fiscalía como posibles hechos constitutivos de delito de explotación sexual con la agravante de ser una persona con discapacidad. Por tanto y salvo que desde la parte social podáis ingresarla voluntariamente por emergencia, habría que esperar a tener pruebas, y en el escrito que enviaríamos al Ministerio Fiscal solicitaríamos como medida cautelar urgente su internamiento en centro adecuado por emergencia social. *********************************','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2021-11-11','TERESA Se acompañó a Paloma Rodríguez Jiménez, que reside en la calle Cristo de la Piedad, 9 de Jerez de los Caballeros, a una tienda de su localidad que se llama Galerías Tentudía. En la tienda se aparta la ropa que ella necesitaría para la época de otoño-invierno: tres pantalones tipo mallas, tres camisetas, una cazadora, media docena de bragas y otra media docena de calcetines. En la tienda hacen presupuesto con todas esas prendas y comentan que dejarán la ropa apartada durante unos días para que nadie puede llevárselas pero al cabo de unas dos semanas, tendrán que devolverlas a las perchas si no tienen seguridad de que Paloma las vaya a comprar. El presupuesto asciende a 96,20€ y se adjunta envía en el email. Paloma comenta que también necesitaría comprarse un par de zapatos para cuando llegue el frío y la lluvia, así es que si la comisión da luz verde se puede ir con ella en la siguiente visita a una zapatería para pedir presupuesto de un par de zapatos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-11-11','Ana: Maite, Jefa Secc. y yo, mantenemos conversación con May: han recibido el expdte. de dependencia para ingreso involuntario de Antonio en Centro, pero dicen que este hombre no da perfil para ingresar en Centro de Mayores y que además en el Auto de Autorización de Internamiento indica ingreso en "Centro Sociosanitario". ····················· Hablaremos con Soraya Masa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-11-11','Ana: Correo de Anabel, TS SSASB de Miajadas: "HOLA ANA buenos dias! he hablado con Mamen Trabajadora Social del Hospital, dice que ha hablado con el psiquiatra y que esta deacuerdo con nosotras en que el Piso Tutelado no es el recurso idoneo para Esteve pero que la Unidad de Media estancia de Plasencia, tampoco es un lugar residencial, sino un recurso sanitario, que lo adecuado sería poder encontrar lo antes posible un recurso de Salud Mental idóneo, no se si tu ayer pudiste tratar el tema con las compañeras de Salud Mental en Mérida, para ver como va el recurso. Mamen hablará con Pilar de Salud Mental de Cáceres, yo por mi parte he intentado hablar con Soraya Masa pero es imposible, estoy esperando que pueda contestar mi email. saludos"','2');
