insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-12','Ana: Remito a los compañeros Jurídicos, informes para comunicar al Jdo. la situación actual de Julia y solicitar autorización de internamiento no voluntario. ················ Llamada de Marciano, Jefe secc. EVD Plas.: No entiende que Julia resida aún en el domicilio familiar y menos en las condiciones actuales, considera que debería de estar en un recurso residencial. Por otra parte, aunque irán a valorarla, no cree que vaya a dar grado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-11-10','Ana: Llamada de Anabel, TS SSASB Miajadas: Esteve estuvo 5 días bien con la nueva medicación, pero al sexto ya comenzó otra vez a tener alucinaciones (tanto auditivas como visuales). Ayer por la noche bajó de la habitación en ropa interior diciendo a otro residente que se fuera y le dejara a solas con la Aux. porque "todos tenemos apetito sexual". *Anabel entiende que se está poniendo en peligro al resto de los residentes y a los profesionales. *Por otra parte, la coordinación con el C.O. dice que le resulta imposible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='ESPINAR'and apellido2='DEL ARCO'),'2021-11-05','Amalia : Registro salida INSS Badajoz , solicitando a Alemania el N º cuenta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-12','Ana: Correo de Mercedes Vega, Médica de Geryvida: "Buenos días Ana. Les comunico el estado actual de Dª Manuela Morato Picado, tras la exploración efectuada en la tarde de ayer por la Dra M Luisa Pinilla Crespo ( médico de Geryvida ) y por mi misma . La encontramos con estabilidad en su estado general . Buen aspecto. Consciente, muy buen nivel de alerta , hidratada, tranquila, contesta con monosílabos a alguna pregunta. Realiza buenas ingestas, comprende órdenes sencillas. Misma postura que en otra ocasión con los brazos cruzados sobre el pecho. Se pone algo incómoda cuando la exploramos, da manotazos con fuerza cuando le realizamos la exploración. Distintos estadíos en cuanto a las lesiones dérmicas de hematomas, no tiene úlceras por presión. Actualmente presenta heridas en región pretibial y en gemelo de la pierna derecha con buena evolución y en fase de resolución. No dolor a la palpación de tobillo y pie derecho, movilidad completa en todo el arco de movilidad con molestias en la flexión dorsal de tobillo derecho, flexión plantar, inversión y eversión sin dolor. No edemas en pies. Por otra parte comunicarles que en la mañana de hoy he hablado con su M de Atención Primaria , Dra Obdulia Moreno , para reclamar el resultado de la analítica realizada el día 13-10-21, que aún no nos lo habían enviado. Me comenta que presenta niveles elevados de sodio y de potasio , con empeoramiento de la función renal, por lo que aconseja poner sueroterapia intravenosa durante 24h , y repetir la analítica la próxima semana ; así mismo aconseja seguir sin el tratamiento con Adiro 100, dado los antecedentes de hemorragia digestiva reciente , con anemia que ha necesitado transfusión y hematomas frecuentes. Me confirma que la cita con el especialista de Digestivo si está aceptada, aún no sabemos la fecha. Finalmente me confirma que la cita con neurología está rechazada y de común acuerdo no volveremos a solicitarla por no considerarla necesaria en estos momentos En cuanto a la denuncia presentada por su nieto José Manuel Correa Morato contra la residencia Geryvida, nos gustaría que ustedes vinieran a visitarla para comprobar cómo se encuentra. Saludos cordiales" ······························································································································································································ Nuevo correo de Mercedes a última hora: "Hola otra vez , me dicen al final de la mañana que no ha tomado nada en la comida , y que da manotazos cuando se la intenta dar de comer ; yo le he visto a primera hora en su estado habitual , he indicado a los enfermeros sueroterapia intravenosa, como ya te comente antes. La he vuelto a explorar y me impresiona de molestias abdominales y dadas las alteraciones de la analítica del dia 13-10-21 , la voy a enviar a urgencias."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-11-12','Alberto acerca del alquiler CONTRATO: si tutelado quiere formalizar, que formalice. Yo no incluiría a Director Gerente. Es una forma de mostrar disconformidad con tutelado. PAGO ALQUILER: no daría orden de TRANSFERENCIA. Alternativa: que tutelado facilite su número de cuenta para domiciliación. NO estamos dando ningún OK. PAGO SUMINISTROS: aquí es donde tengo más dudas...si se actúa igual que con el pago de alquiler o lo paga el en mano. Esto mismo lo he hablado con Miguel y está de acuerdo.','2');
