insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO'and edp.apellido1='CUEVAS'and apellido2='MOYANO'),'2021-11-15','TERESA Te informo que el tutelado Saturnino Cuevas Moyano, con residencia en "Felipe Trigo", se Traslada de Centro (Residencia de Mayores de Higuera de la Serena) el Jueves 19 de noviembre de 2021. Te paso los teléfonos de contacto: Centro Residencial: 924.77.17.35 Trabajadora Social: 924.77.14.51 Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-15','Ana: Correo de Mercedes Vega, Médica de Geryvida (direccionmedica@geryvida.com): "Buenos días Ana. El viernes a última hora, dado que no había comido y presentaba molestias abdominales , la derive a urgencias al Hospital San Pedro de Alcántara para valoración. A día de hoy permanece ingresada a cargo de Geriatría, en la 3 planta, desconocemos la evolución y el diagnóstico. Esta misma mañana llamaremos al hospital para saber de su estado." ············ Conversación con Mercedes: Cuando la derivó a urgencias el viernes no pensaba que fueran a dejarla ingresada. *Puesto que Antonio, nieto tenía concertada la visita el sábado, cuando se confirmó el ingreso le llamaron para comunicárselo. ······························································································································································································· Llamada de Remedios, mujer de Antonio, nieto (626 312 009) Desde el hospital debieron avisar a José Manuel, de modo que éste fue para allá y ya no permite que nadie más acuda a ver a la abuela. *Los médicos le dijeron a Antonio, cuando acudió, que ya había facilitado información a un familiar y no podían darla a nadie más. ····························································································· Llamo a la planta de Geriatría del HSPA, Belén, la Dra. (56842) informa de que Manuela está muy delicada. En la exploración exterior parece estar mejor de lo que está realmente. Ingresó con una deshidratación importante, presenta fallo renal (que puede causar la deshidratación), infección urinaria, arritmia, anemización potente y heces negras (indicio de posible sangrado interno). **Mañana volverán a llamarnos para informar sobre su evolución. ·············································································· Llamo a Antonio, nieto (626 917 286) para informarle del estado de su abuela. ················ Informo también a la Res. Geryvida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='SOLE'and apellido2='LATORRE'),'2021-11-15','Ana: Envío a Alberto, jefe secc. ecca., presupuestos de colchón antiescaras (47,19 € / 66,00 €). *Tb nos informan de una deuda de 91,07€ a la farmacia. ··························· Alberto, aprueba cualquiera de los dos presupuestos. *Se lo comunico a Fermina, Directora Res. e indico que nos hagan llegar también las facturas de la farmacia con nº de cuenta.','2');
