insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-11-15','Buenos días Mar , qué tal ? te he llamado por tf pero no he podido localizarte. He hablado por tf con Mercedes Perez Pinna , su discurso es incoherente , "que un exnovio la persigue , que le ha jaqueado el móvil ..." .Le he preguntado si se ha puesto el inyectable y me ha dicho que sí . Creo que sería necesario una valoración por parte del psiquiatra , le he pedido que contacte con el ESM para pedir cita. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2021-11-15','TERESA Teresa buenos días, te comento. El próximo viernes día 19, tenemos una actividad programada en la localidad de Monterrubio. No sé si necesitamos vuestra autorización para Nerea Dacosta y Aitor Moreno, o si por el contrario no hay problema en que participen. Es un desfile de moda en el que ellos (incluidos el resto de usuarios) serán los modelos. PIDO NOS ENVIEN AUTORIZACION PARA QUE LA FIRME EL TUTOR','2');
