insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2021-11-15','Ana: Guillermo ha sido ingresado el fin de semana con carácter de urgencia en el Hospital de Navalmoral, e intervenido de hernia inguinal. ········· Permanece ingresado, de momento no necesita acompañamiento hospitalario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2021-11-16','miguel, me llama Emiliano de la inmobiliaria de Info finca en relación a la venta de la vivienda de la c/ Constitución para preguntarme conforme el antiguo email si ya hemos procedido a pagar la deuda con Endesa y de si pueden empezar a tirar los enseres de la vivienda. Envío email a Teresa y Alberto: Buenos días, necesito que a lo largo de esta mañana me contestéis a petición de la inmobiliaria de varias cuestiones: Teresa: confírmame si pueden empezar a tirar todo lo que hay en la casa o hay que retirar algo. Dice la inmobiliaria que hay para varios camiones de porquería que iría el camión del punto limpio a retirarlo. Alberto: confírmame que los recibos de deudas pendientes del OAR de Badajoz que distes a Iciar están ya abonados porque van a ir al OAR a pedir justificante de que no se debe nada de IBI. Por otro lado tenéis que abonar unos 221,90€ a Endesa por varios recibos (que no tenemos) según me dice la inmobiliaria. También me ha dicho que el agua está al día. La inmobiliaria ya tiene el certificado energético y está a la espera de que la semana que viene el ayuntamiento de Montijo le de la Cédula de Habitabilidad.','2');
