insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-16','Ana: Llamada de la Dra. Lisbeth Herrera, Residente de 4º año de Geriatría (56718). Informa que Manuela se mantiene estable con respecto a la infección, el tratamiento antibiótico está haciendo efecto. *Con respecto a la Deshidratación, se ha corregido muy bien. La analítica muestra que tiene las proteínas bajitas, valorarán la nutrición en los próximos días. **Tiene una endoscopia alta programada para el próximo día 25/11. **Con respecto a la insistencia del nieto con la valoración neurológica, indica que no se puede valorar dado el estado de la paciente, y así se lo explicará al nieto. ························ Informo al centro (TS y Médica) ··············· Hablo con Raquel, mujer de Pablo, nieto (637 193 540) e informo de la evolución.','2');
