insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-11-17','miguel, llega a ctutelar email de la Comunidad de vecinos: Pongo en su conocimiento, en nombre de la comunidad de propietarios del edificio La Muralla, que en el día de ayer, por la tarde, volvimos a sufrir otro episodio provocado por el inquilino del portal 2-4°C, Alejandro Núñez Bono. En esta ocasión ha arrojado una cama por el balcón de su casa, que cayó justo delante de la puerta del garage y provocando que la vecina del bajo de su portal, una señora de edad avanzada, saliera asustada a ver que había ocurrido, ya que todo pasó debajo de la ventana de su casa. Debido al nerviosismo que le produjo todo esto, la señora tropezó y cayó al suelo, rompiéndose el húmero de un brazo, por lo que tiene que ser operada. La cama la retiró su propia madre después de enfrentarse a los vecinos que le reprochar on la actitud de su hijo. Así mismo, cuando se le preguntó a Alejandro por qué había hecho eso, respondió que porque no la podía bajar por la escalera. Les ruego que tengan en cuenta todo esto para poder poner solución a esta situación. ************************************************ envío email a Amalia: Buenos días, te adjunto email de la Comunidad de vecinos de Alejandro. Por favor ves recabando todo tipo los mensajes y denuncias de Alejandro para cuando haya que solicitar su internamiento (entiendo que previamente tendrán que revisar su sentencia para pasarlo a curatela representativa) Tengo juicio a las 10,30h. Si quieres lo hablamos después del desayuno porque ahora comunicas. ******************************************** email de Amalia al vecino Manuel f.m. (xiliana06@yahoo.es): xiliana06@yahoo.es*************************************** Envío email al vecino: Buenos días Manuel, gracias por la información que nos remite. Para poder actuar ante el juzgado, no será suficiente las quejas de los vecinos, necesitamos nos remitan por esta vía todas las denuncias que hayan presentado y las que interpongan en el futuro, los procedimientos judiciales que hayan mantenido contra Alejandro (número de procedimiento y juzgado competente), y los nombres, apellidos, domicilio y dni de aquellos vecinos que estuvieran dispuestos a testificar si lo precisara el juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2021-11-17','miguel, tenemos juicio por videoconferencia. Hablo previamente con Mª José email: mmartinmoreno@icac.es (la abogada móvil 666753922). La envío mi email para me remita la documentación del procedimiento que no la veo en el expte (o no ha llegado). Asisto a la videoconferencia donde se nombrara un contador partidor que tendrá que abonar el hermano demandante, el cual tiene 1/6 parte de la nuda propiedad, mientras nuestro curatelado tiene el derecho de la habitación. La abogada cree que lo que quiere el demandante es dinero por lo que o bien propone una compra de su parte en un futuro previo procedimiento de división de cosa común. Paralelamente la abogada tiene reclamada a la masa hereditaria dinero que se le debe al curatelado de cuando estuvo ingresado su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-11-17','Ana: envío a los Asesores Jurídicos, CTAEX, la citación y comparecencia (para el día 26/11) así como denuncia, relativa a Alfonso, por agresión al Vigilante de Seguridad del Hptal. de Plasencia, remitida previamente por Rosa Bravo, CSS (rosamaria.bravop@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2021-11-16','Ana: coreo de Ana, Enfermera Res. Femar: "te envio las citas por si necesitas tener justificante de ellas. No tenemos informe de la consulta , supongo que en los proximos dias lo recibiremos via correo postal. Nos ha comentado la chica que la acompaño que la encuentra muyu recuperada y jque siga con rehabilitación e intente caminar sin andador."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-11-16','miguel, hablo con el abogado Carlos Jurado quien me remitirá el borrador del acuerdo. Confirmo con él que hable con Soledad y que indiquen en el acuerdo el importe a asignar a todas las partes, siendo el sobrante a nombre de Alejandro porque el importe del que parte el acuerdo es sobre 140.000€ y el fondo de inversiones ha disminuido a unos 138.000€ por ahora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL MARIA'and edp.apellido1='SANTOS'and apellido2='GOMEZ'),'2021-11-17','Email de Angel a la parte social, jurídica y económica: Buenos días, Rafael Santos Gómez, ha pedido la remoción del cargo de curador que ostentamos y que se nombre nuevo curador. Os pego y reproduzco la fundamentación de su solicitud: “El único motivo para solicitar la remoción es la escasa -por no decir nula- accesibilidad que mantiene en sus relaciones económcias con la Comisión Tutelar, la absoluta falta de fluidez en su relación, falta absoluta de atención, y sensación de impotencia que le transmite el no ser escuchado para atender sus necesisdades, algo que le produce angustia, recibiendo como excusa de la Comisión Tutelar el exceso de trabajo y la insuficiencia de personal para atenderle personalmente”. Los hermanos están de acuerdo. Os adjunto la demanda, por si queríes echarle un vistazo. Nos han citado a comparecencia para el próximo día 23/11, a las 12 horas. Pediré que asistamos a través de videoconferencia. Necesito que ese día estéis presente, sobre todo desde el área económica y también social, a los efectos de responder a la demanda. Entiendo que una comparativa de su situación económica, a fecha de inicio de asunción del cargo, hasta hoy, así como una manifestación de las comunicaciones que se mantienen con Rafael, a través de correo electrónico, teléfono, fax y personalmente, así como que no nos oponemos a su solicitud, a los efectos de respetar su voluntad, de conformidad con la nueva ley, sería más que suficiente para defender nuestra postura. Deciros también que esta solicitud de remoción nos la ha remitido Curro, de Abogacía General, que indica en su correo que él no va a asistir a la comparecencia. Hasta la fecha, la Abogacía General de la Junta de Extremadura, interviene en todos los procedimientos de incapacitación en los que se propone el nombramiento o la remoción en el cargo a esta Comisión Tutelar. Deberíamos reenviar el correo de Curro a Antonio Alonso, que es el Jefe de Área de los Servicios Contenciosos, a los efectos tenga conocimiento y confirme la asistencia o no de la Abogacía General en este procedimiento. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2021-11-17','miguel, llega email de la trabajadora social de alcuescar Felisa: Estimada Ana, el pasado 3 de noviembre remití el correo inferior a Ángel, el asesor jurídico, a ver si me puedes hacer el favor de preguntarle porque no me ha respondido con nada...************************************** La respondo con copia a Angel y Ana: Buenos días Felisa, el abogado de la parte compradora Aquilino Conde Barbero me indicó en su email del día 17-9-21 que pediría la tasación gratuita judicial, pero que sino la concedían correría con el gasto nuestra curatelada al ser la Comisión quién la solicitaba. Le contesté que nos valía con un certificado de tasación (las inmobiliarias suelen valorar como pretasación, lo cual no supone coste). Esto les fue solicitado porque tal como le dije por email “se trata de una valoración fiscal, cuyo valor es inferior al precio de mercado. Necesitaríamos que nos remitieran una valoración de mercado mediante certificado o justificante de tasadora, tal como se establece en el artículo 10 del Real Decreto Legislativo 1/1993 “. Ya le contesté que no es necesario ni si quiera pedir autorización judicial por ser una curatela, simplemente ponernos de acuerdo para lo cual como digo nos vale que una inmobiliaria y/o un tasador nos diga cuánto cuesta la vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2021-11-17','Ana: A petición de Miguel, Asesor Jurídico, remito a Rosa Bravo, CSS Plas.: Citación Judicial, en calidad de ACUSADO, para el próximo 24/02/22 a las 11:00 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-11-17','Ana: Soraya Masa, me informa, que al no poder contactar con el Psiquiatra que lleva a Esteve en la UHB, ha hablado con Mamen, TS Hptal. *Ha solicitado que intenten pasarle a UME como algo temporal, mientras se convoca la Comisión y se resuelve plaza en el CRR. **En el momento que vuelve al piso se descompensa, donde se muestra estable en en Ud. Hospitalaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='LOPEZ'and apellido2='THOMAS'),'2021-11-17','Ana: Llamada de César, TS de la Res. Ntra. Sra. de la Luz, de Malpartida de Plasencia (927 14 36 20): han recibido el oficio solicitando documentación, nos facilitarán lo que tienen. ······ Facilito el nº de buzón de la CTAEX. ······························································································································································································· Icíar, secc. ecca., detecta un error en el informe social (datos de otra persona). Como César ya no está, se lo comunico a Mari, Directora, quién se lo dirá a él. Hasta el próximo martes no estará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-11-17','Ana: Llamada del Subinspector Manuel Vasallo - Policía Nacional de CC (927 629 092): han remitido el Certificado del Consulado Francés a Madrid y finalmente van a documentar a Mª Rosario como española, se le expedirá el DNI. Necesitarán la siguiente docuemntación: - Cdo. Empadronamiento actual - Certificado de empadronamiento histórico. - Partida de Nacimiento "expedida para la obtención del DNI" - Una fotografía para DNI actual. Una vez recabado todo remitir a José Luis, Secretario General. ······························································································································································································· Julio, CTAEX, solicitará los Cdos. de Empadronamiento y el Literal de Nacimiento para la obtención del DNI (Éste a Villamiel) ······························································································································································································ Solicito a Sandra, TS de la Res. Real Patronato de Coria (alexandra.alfonso@coria.org), la fotografía. Le informo que próximamente se desplazará la Ud. Móvil para la expedición del DNI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-17','Ana: Llamada de la Dra. Herrera (56718): Manuela está mejor, está más despierta y ha estado diciendo algunas palabras. Tras haber comprobado la tolerancia oral, van a comenzar con dieta triturada. *La infección está controlada. Y aunque las plaquetas están bajitas, la hemoglobina está más estable. *En cuanto a la enfermedad renal, que ya padecía, sí que han apreciado mayor deterioro en el riñón. ····················· Lo comunico por mail a la Residencia (Tamara y Mercedes) y por teléfono a Reme, mujer de Antonio, nieto (626 312 009)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-11-17','Ana: Envío correo a Pilar Martín - ESM: "Buenos días Pilar, Maite, jefa de sección, ha hablado con su MAP y dice que ella no tiene nada. Por favor, ¿Podríais poneros en contacto desde ahí (la enfermera o quién corresponda, que no lo sé) para solicitarle la información que necesitan? No podemos seguir demorando más tiempo esto. Gracias y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-11-17','miguel, llamo al Jzdo nº6 de Cáceres para informarme del procedimiento (a petición días anteriores de Ana Ts) y el cual no me facilita de nuevo nada, me remiten a la abogada y sino que lo pida por escrito. Tras conversación telefónica con Maite Ts de la Prisión de Cáceres y a petición de la misma pongo el siguiente email para se lo den a Saturnino: A/A Maite/Módulo enfermería: Buenas tardes esta información es para el interno Saturnino Miguel Salgado Jimenez, el cual se encuentra tutelado por esta Comisión Tutelar de Adultos. Según nos indican desde el Juzgado de 1º instancia nº6 de Cáceres, el interno debe ponerse en contacto con su abogada Mª Carmen Lucas Duran con teléfono 927-226664 e email mlucasduran@icac.es quién habrá de facilitarle la información que ha solicitado en relación con el procedimiento penal identificado con el procedimiento DILIGENCIAS PREVIAS 751/20 del Juzgado de 1º instancia e instrucción nº6 de Cáceres. Asimismo, desde la Comisión Tutelar rogaríamos que cualquier documento que reciban por parte del juzgado y/o abogada nos lo remitan para el control de dicho procedimiento. ************************************************ Remito email a Ana Ts: Buenas tardes, he intentado en anteriores llamadas que el juzgado, donde se está conociendo el procedimiento sobre supuesta violación (procedimiento Diligencias Previas 751/20 del Juzgado de 1º instancia e instrucción nº6 de Cáceres), nos informara, el cual nos remitió a la abogada (nombrada de oficio Mª Carmen Lucas Durán, de Cáceres) la cual no quiso facilitarnos información y nos remitió al juzgado. Hoy he vuelto a hablar con el Juzgado y me ha dicho que si queremos algo lo solicitemos por escrito y ya resolverán. Posteriormente he preguntado por Maite Ts de la Prisión de Cáceres quien me ha pedido que por escrito deje el recado para Saturnino, el cual te lo adjunto más abajo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-11-17','Maite: Marta tiene que hacerse PCR para ir a CO de PLENA INCLUSIÓN Cabeza del Buey.He hablado con la trabajadora social de Peñalsordo y tb con Felisa ( suegra de MArta) para que lo gestionen. Marta tiene el dia 22 cita en Salud Mental , en Don Benito. Teresa de Futuex la acompáñara a la cita. Hasta Don Benito irá en taxi. He hablado con el taxista, ( para pagar el taxi, la trabajadora social va a tramitar la ayuda el mínimo vital).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2021-11-17','TERESA ENVIO PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-17','Ana: Llamo a Marisa, TS ESM (70858): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-11-17','Ana: Llamo a Julia García Félix, Coordinadora de la Casa de la Misericordia de Alcuéscar (927 12 00 24): tras exponerle la situación de Antonio, me pide que le envíe los informes sociales y médicos de que dispongamos para poder valorar la posibilidad de ingreso en su centro. *El inconveniente que ve a priori es que su centro es un centro abierto. ······· Envío los informes (casadelamisericordia.alcuescar@gmail.com)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-11-17','Ana: Llamada de Manuel Vasallo, Subinspector de la Policía Nacional de CC: Han enviado a Madrid el Certificado del Consulado Francés y finalmente van a documentar a Mª Rosario. Necesitan que les enviemos, al correo de José Luis, Secretario Gral.: - Certificado de Empadronamiento actual - Cdo. de Empadronamiento Histórico - Certificado Literal de Nacimiento específico para la obtención del DNI. - Una fotografía de carné ································································································································································································ Julio, CTAEX, solicitará los Cdos. de Empadronamiento y el Literal de Nacimiento para la obtención del DNI (Éste a Villamiel)','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-11-18','Hola Amalia! Cómo estás? Estuvimos con Mercedes P.P Lunes 15 Noviembre. La vio el Psiquiatra, modificada pauta de tratamiento farmacológico. l Vemos interesante el poder reunirnos y hablar de ella. La fecha fijada, si es posible que podáis venir el 22 de Noviembre a las 10:00 h. en consulta con el DR. Galán ---------------------------------------- Hablo por tf con ella , está allí Teresa Futuex . Me comenta Mar que desde el ESM consideran oportuno un ingreso , que el psiquiatra lo ha indicado en un informe y que proceda la Comisión a activar el 112. Le indico que no compete a la CTAEX , y q es el ESM el que tendrá que realizar las gestiones que estime para el ingreso .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2021-11-18','TERESA Se pide autorización, si procede, para ROBERTO CARRERA PEREZ para irse al domicilio familiar de Zafra del 23 de diciembre al 5 de enero, en transporte público (autobús) Dicha petición ha sido realizada por la madre, mediante los SSBB de Zafra, quienes servirán de apoyo para la realización de PCR de Roberto a su regreso. Destacar que Roberto, desde la pandemia no ha vuelto a visitar a su familia, lo que venía haciendo anteriormente de forma mensual, dichas visitas se suspendieron por el riesgo de contagio en el entorno familiar y transporte público.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2021-11-18','Buenas tardes Iciar. Soy Carmen, la Trabajadora Social de Servicios Sociales. A la tutelada Dª Maria Rosa Serrano García, le ha llegado la resolución de dependencia con Grado I. Pero desde este servicio pensamos y ella también está de acuerdo, que se renuncie al menos por ahora a la Dependencia ya que tendría que abonar un copago para la ayuda a domicilio de 40 euros mensuales. Ella es atendida por el servicio de ayuda a domicilio del Ayuntamiento, servicio gratuito, y funciona muy bien con las auxiliares que tiene. Desconozco si la renuncia puede ser firmada por Rosa o la tiene que firmar la Comisión Tutelar. Espero su respuesta, un saludo Carmen Márquez Viera','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-18','Ana: Conversación con Tamara, TS CR Geryvida (927 101 800): Me informa que ha llamado José Manuel, nieto de Manuela, exigiendo que le lleven al hospital unas serie de objetos/artículos personales (colchón antiescaras, la bata, barandilla protectora...) si no se lo llevan exige que lo preparen que él pasará a recogerlo. *Acordamos que no le entregarán nada a no ser que se autorice desde la CTAEX por escrito. ····································· A petición de Tamara, le envío este correo: "Buenos días Tamara, En relación a Dª Manuela Morato Picado, Tutelada por la Comisión Tutelar de Adultos de Extremadura, no autorizamos a que ninguna persona retire del Centro Residencial de Mayores Geryvida de Cáceres, ninguna de sus pertenencia sin que desde esta Comisión se dé orden para ello. Un saludo." ················································································································································································································································································································ Conversación con Yohana, Geriatra HSPA (56718): Manuela tuvo una incidencia ayer por la tarde, le hicieron una radiografía y tiene dilatado el intestino, le han puesto una medicación. Durante la noche no ha descansado mucho, pero tampoco ha presentado alteraciones. Hoy presenta hipotensión y continúa con la infección de orina. Está comiendo poco y continúa con suero. La analítica indica que no hay gran mejoría. *Mañana le harán una gasometría. ············································ Lo comunico a Tamara y Mercedes, Res. y a Raquel, mujer de Pablo, nieto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2021-11-18','Ana: Correo de Julia, Casa de la Misericordia Alcuéscar (casadelamisericordia.alcuescar@gmail.com): "Buenos días: Tal y como hemos hablado por teléfono y una vez estudiados los informes, consideramos que nuestro recursos no es el adecuado principalmente por un motivo: es conveniente poner distancia con el ambiente social que rodea al tutelado y alejarlo para que su mejora y calidad de vida pueda ser factible. Esto sólo podrá ser posible si el recursos residencial del tutelado no se encuentra en el mismo lugar donde vive actualmente. Por ello, remitimos los informes al director de la Casa de la Misericordia de Pinofranqueado. Estamos a su disposición." ·············· Llamo a Fernando Pecero (651 97 56 17): leerán los informes con calma y valorarán en equipo la posibilidad de ingreso en su recurso, en base a la Subvención que perciben para el Apoyo a Personas con Trastorno Mental Grave. ·· *Hablaremos la semana que viene (martes-miércoles)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2021-11-18','kike,llega nuevo DIOR del juzgado para proceder al internamiento, porque el anterior no se pudo cumplir con la comunicación.Se da nueva cita para el 13/12/21 a las 10:00','2');
