insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-18','TERESA HABLO CON LA DOCTORA TACIANA PARA QUE ME INFORME COMO SE ENCUENTRA JOSE MARIA ME COMENTA QUE ESTA BIEN, QUE NO HAY CRITERIO PARA MANTENERLO INGRESADO YA QUE CONISERA QUE EL PROBLEMA NO DERIVA DE SU ENFERMEDAD MENTAL SINO QUE ES UN PROBLEMA DE CODUCTA TIPO CARCELARIO LA DESCOMPENSACION QUE HA SUFRIDO VIENE ORIGINADA POR HABERLE OCULTADO INFORMACION YA QUE IBA A VERLE EL FORENSE Y POR MIEDO A SU REACCION NO SE LE HABIA COMUNICADO TRAS EXPLICARLE LA SITUACIÓN ACTUAL EN EL CENTRO NOS CONCEDE MANTENERLO EN LA UHB COMO MÁXIMO DIEZ DIAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA ENGRACIA'and edp.apellido1='LAVADO'and apellido2='DEL HOYO'),'2021-11-18','TERESA Hoy se ha procedido a hacer la transferencia de 300€ a la cuenta de su hija tal y como habíamos acordado.','2');
