insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2021-11-18','Ana: Remito a Rosa, Admvo. CSS, CI para Sedación en Endoscopia Digestiva, debidamente firmado y sellado por el Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIA'and edp.apellido1='PORRO'and apellido2='MORENO'),'2021-11-19','TERESA Lucía ocupa plaza en los Pisos Tutelados de Bodonal de la Sierra, centro que no se encuentra en nuestra cartera de servicios por lo que no puedo negociar dicho recurso. FIRMAMOS NO ACEPTACION PIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-11-18','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería comunicarte que ayer por la tarde regresó Aaron al centro. Los compañeros estarán muy pendientes para que permanezca en la habitación el mayor tiempo posible, aunque es complicado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AARON'and edp.apellido1='ROSADO'and apellido2='ALARCON'),'2021-11-17','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informarte que al realizar el segundo cribado han dado positivos Justo Hernández Castaño y Aaron Rosado Alarcón. Ninguno presenta síntomas. Vamos a avisar también a sus familiares porque en ambos casos mantienen contacto con ellos. Respecto a Aaron al informarle que tenía que tener aislamiento y pasar a otra habitación se ha alterado mucho y tras intervenir los psicólogos del centro y comprobar que la situación no se podía controlar han avisado al centro de Salud y lo derivan a Cáceres con todos los protocolos, es decir, sabiendo que es positivo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2021-11-17','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "...En cuanto a Ignacio Rodriguez Alcántara, se encuentra bien y le darán el alta el viernes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-11-17','Ana: Correo de Sonia Bernabé - Asindi (trabajosocial@asindi.e.telefonica.net): "Hola Ana, quería informarte que al realizar el segundo cribado han dado positivos Justo Hernández Castaño y Aaron Rosado Alarcón. Ninguno presenta síntomas. Vamos a avisar también a sus familiares porque en ambos casos mantienen contacto con ellos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-11-19','recibimos en ctutelar email de la hija de la vecina del tutelado que se rompió el brazo (MONTSERRAT CORTÉS MARTÍN, email: montsecortesmartin@gmail.com): Estimados Señores: Me pongo en contacto con ustedes para denunciar la grave situación vivida el pasado martes día 16/11/2021 en mi edificio. Para ello, les expongo lo siguiente: Yo, Montserrat Cortés Martín, con domicilio en Badajoz, calle Paseo Fluvial, n°1-1°B, quiero DENUNCIAR ante ustedes que el inquilino del piso 4°C, 2° Portal de mi comunidad, Alejandro Núñez Bono, que convive con su madre, arrojó desde el mencionado piso una cama entera, cayendo justo en la entrada al garaje de la comunidad. Afortunadamente, en ese preciso instante no accedía ningún vecino al garaje, de lo contrario, lo hubiese matado. Fue tal el estruendo que se produjo, que mi madre, de 78 años, que vive sola en la planta baja de ese mismo portal, salió muy asustada y alarmada para saber qué había ocurrido y, por supuesto, llamarle la atención a este conflictivo vecino, sobre el cual pesan ya numerosas denuncias por parte de la comunidad, con tan mala suerte que mi madre tropezó con el bordillo de la acera y sufrió una grave caída que le ha provocado una fractura de húmero, habiendo tenido que ser intervenida quirúrgicamente de dicha fractura dos días después en la Clínica Clideba. Tras preguntarle directamente al mencionado vecino el por qué había tirado la cama por el balcón, nos contesta que "porque no quiero bajarla por las escaleras..." Existen vídeos y fotografías, tanto de la cama caída en la puerta de acceso al garaje, como de la madre de este vecino transportando a pie dicha cama para depositarla en unos contenedores situados en el carril auxiliar de la Avda. Antonio Masa Campos. En espera de una pronta respuesta y con el deseo de que nos puedan ayudar para solucionar este grave problema de convivencia que venimos sufriendo con este vecino, reciban un cordial saludo.*************************************************** contestación miguel: Buenos días, hemos recibido su email. Agradecemos que lo haya puesto en conocimiento de la Comisión Tutelar de Adultos. La informamos que esta Comisión ejerce el cargo de curadores en el ámbito patrimonial de Alejandro Nuñez Bono conforme a la sentencia dictada por el Juzgado de 1º instancia e instrucción nº4 de Badajoz, en procedimiento ICP Incapacitación 924/2018, lo cual implica que lo único que podemos hacer es poner en conocimiento de dicho juzgado todo lo sucedido para que desde el mismo dicten las medidas a adoptar, ya que no tenemos competencias más allá que en el ámbito económico de la persona. Al igual que se le contestó a un vecino de ustedes Manuel f.m.: Para poder actuar ante el juzgado, no será suficiente las quejas de los vecinos, necesitamos nos remitan por esta vía todas las denuncias (ante la policía y /o ante el juzgado) que hayan presentado y las que interpongan en el futuro, los procedimientos judiciales que hayan mantenido contra Alejandro (número de procedimiento y juzgado competente), y los nombres, apellidos, domicilio y dni de aquellos vecinos que estuvieran dispuestos a testificar si lo precisara el juzgado. Sin más, y lamentando enormemente lo sucedido reciba un cordial saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2021-11-19','Ana: Llamo a Javier Agudo Cumplido (UME 24176): dice estar muy bien. Vuelve a preguntar por la baja de la luz y el agua de su domicilio. Pregunta también cuándo se irá al CRR. ···························································································································································································· Correo de Estrella, TS CSS: "me dice su Psiquiatra que está para el alta o para pasar a la Unidad de Rehabilitación, ya sabéis que en esta unidad tiene que pagar...." ················ Mi respuesta: "...En cuanto al Alta, como sabéis, aún no tenemos recurso donde llevarle. Entiendo que tendrá que pasar a URH. Si no os importa, trabajar con él que se trata de una cuestión temporal, mientras resuelven plaza en CRR."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2021-11-19','Ana: Correo de Sonia Bernabé, Asindi (trabajosocial@asindi.e.telefonica.net): "...al hacer el seguimiento de los contactos de los primeros positivos están dando positivos otros compañeros que eran contactos estrechos. Uno de ellos es Roberto Hernández Castaño. Se encuentra bien, pero ayer mostraba síntomas de empezar con resfriado y ha dado positivo. Su familia está informada y mantienen contacto con el centro para saber cómo se encuentran sus dos hijos. Cruzaremos los dedos para que hayamos conseguido controlar la situación intentando que estén en sus habitaciones, aunque para algunos es muy complicado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2021-11-19','Hola Amalia! te cuento un poquito, que ayer quedó la compañera con Ati por los temas pendientes: el pasado 16 de Noviembre se quedó con Ildefonso García en el hostal Carmen de Zafra para acompañarle y asesorarle en la búsqueda de una vivienda de alquiler en Zafra. Antes de salir del hostal, se preguntó a Ildefonso si tenía teléfono y contestó que si, que se había comprado uno de prepago de Vodafone y pagaba 10€ al mes. El número es el: 667 444 596. Se recorrieron varias inmobiliarias de la localidad y en todas ellas comentaron que los alquileres estaban muy mal debido a que estaban todos pillados por los trabajadores de las placas solares que se estaban construyendo por la zona. Comentaron que quizá para finales de año saliera algo pero no estaban muy seguros, actualmente lo que tenían eran pisos de más de 450€. Ildefonso comentó a uno de los gestores inmobiliarios, que le gustaría vivir en un pueblo pequeño como Valencia del Ventoso, Medina de las Torres,...etc. Por lo que el gestor se puso a mirar en el portal de Mil Anuncios pisos de alquiler en Valencia del Ventoso y encontró uno. Se apuntó el número de teléfono del particular para llamar a lo largo de la mañana. También se habló de buscar pisos de alquiler en Almendralejo ya que en la página de Mil anuncios salían varias opciones. Se llamó desde el teléfono de Ildefonso a la propietaria del piso de alquiler de Valencia del Ventoso: Rosario Suárez; 665668320/655576513. El piso dispone de dos habitaciones, salón, cocina y un baño. Es un primero sin ascensor y cuesta 250€ al mes. Rosario comentó que el piso está ocupado todavía por una chica joven que se está mudando actualmente y ella cree que dejará el piso para la semana que viene. Ildefonso ha comentado que llamará a Rosario el lunes 22 para preguntar si el piso se ha quedado vacío y para saber si puede ir a visitarlo o cuándo se puede instalar directamente porque él no tiene mucho interés ni en verlo, se lo quiere quedar directamente. El curatelado también ha comentado que si se va a vivir a Valencia del Ventoso se tendría que comprar una bicicleta de paseo, no una montain bike de ruedas grandes para ir a Zafra y venir; ya que no tiene muchas intenciones de usar el transporte público. Con respecto a la cita para renovarse el DNI, se ha pedido una en Almendralejo para el viernes 19 de Noviembre a las 11:30h. Pero cuando se ha informado a Ildefonso de la cita, él ha respondido que no es necesario renovarse el DNI aún porque ha ido a la guardia civil de Zafra y ha explicado que se le ha extraviado el DNI y que está en trámite de alquilar una casa. Ellos le han recomendado que primero alquile una vivienda y cuando ya tenga la dirección actual, se renueve el DNI con la nueva dirección. Además le han hecho un documento que explica que tiene el DNI extraviado y donde vienen sus datos, Ildefonso comenta que con ese documento se ha comprado el móvil sin ningún tipo de problema. Ha pedido que se aplace la cita para renovarse el DNI para Diciembre o Enero. Asique como ves con este hombre, se proponen cosas, pero luego se busca las vueltas, para hacerlo como le da la gana. Estaremos un poco supervisando lo del posible piso este de Valencia el Ventoso, si nos lo permite.. y ya en el caso de hacerse te voy comentado, también por el tema del pago de los suministros y etc...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2021-11-11','Ana: correo de Estrella Durán, TS del CSS Plas. (estrella.duranc@salud-juntaex.es): "Hola de nuevo, Ana. En la última reunión de UHDAC, se puso de manifiesto que Carlos Alberto Vicente puntualmente expresa su deseo de volver a residir en Placeat además de que ha alcanzado una estabilidad importante a nivel conductual con lo que nos planteamos ese paso a un recurso residencial comunitario. Hablé con la T.S. de la entidad, Ángela y me comentó que Carlos Alberto ya no tiene plaza residencial solo de centro de día, que habría que solicitarla de nuevo. Todo esto también lo he comentado con Soraya Masa, la cual apuntó que no hay plazas libres y que tendría que esperar muchísimo. Con esta información, el equipo opina que debemos solicitarlo y tendrá que esperar el tiempo que sea en UHDAC como hasta ahora, pero si no se solicita, no tendrá esa remota posibilidad de volver al Centro Residencial de Placeat. Queremos saber vuestra opinión al respecto, ya que vosotros como tutores tenéis la última palabra...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2021-11-18','Ana: Soraya nos confirma que el Psiquiatra ha hecho derivación a UME. Quedamos a la espera de que sea aceptada en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2021-11-19','Ana: Envío correo a Maite, TS C. Penitenciario (trabajosocialcpcaceres@dgip.mir.es): "Buenas tardes Maite, Tras mantener reunión con ambos jefes (área social y área económica) se aprueba un extra de 150€ para SATURNINO MIGUEL SALGADO JIMÉNEZ. *Nos recuerda Alberto que la situación económica no es buena y que se está haciendo frente también al gasto de odontología, además de otros embargos y deudas pasadas… por lo que no se podrán aprobar estos extras con muchas frecuencia. Agradeceríamos que así se lo hieras saber a Saturnino. Las compañeras de la sección económica lo harán en cuanto puedan, pero no puedo confirmarte qué día de la semana que viene, pues están sólo dos y están desbordadas… Ante cualquier cuestión hablamos el lunes. Un saludo y buen fin de semana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-19','Ana: Llamada de la Dra. Herrera (56718): Ya están resueltas tanto la infección de orina como la deshidratación. La fibrilación también está controlada. En cuanto a la nutrición, le ha puesto un suplemente proteínico, pues no está comiendo apenas. Finalmente no hay sangrado interno. Ayer por la tarde hizo 3 deposiciones líquidas pero esta mañana ya sólo una escasa. *Se le han abierto unas pequeñas heridas en la zona perianal (lesiones por erosión) debido a estas deposiciones. Se las están tratando las enfermeras. En cuanto al riñón ha mejorado un pelín. Pero hasta ayer orinaba normal, pero hoy apenas ha orinado. Temen que el riñón "quiera dejar de funcionar". Por otra parte, la Gasometría muestra una acidosis metabólica, que le están tratando con suero y bicarbonato. Mañana le harán otra analítica de control.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL ROSARIO'and edp.apellido1='GONZALEZ'and apellido2='JORNA'),'2021-11-19','Ana: Correo de Sandra, TS Res. Coria, en relación a la fotografía para DNI solicitada: "Se la mandé a la Policia, ( Avd. Pierre de Cobertin, 13 ) he encontrado el justificante de correos, con la fecha de envío del 4 de Mayo de 2021."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-11-15','Ana: Tras hablar recibir llamada de Juan, envío correo a Alberto, Jefe secc. ecca: "Buenas, de nuevo, Alberto, ¿a Juan Chamorro Holguín se le puede dar un extra de 150€ para calzado, ropa y algunas “deudas” a personas que le han prestado/fiado? El miércoles es el mercadillo y sería bueno que pudiera retirar ese día para comprarse las botas y algo más para el frío. Ya me dices pues las compañeras tendrían que hacerlo mañana…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-11-16','Ana: Se aprueba el extra para Juan. Icíar, secc. ecca., enviará autorización al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2021-11-22','Ana: Correo de Paula, TO del CRR-Plas (tocupacional.crrplasencia@grupo5.net), del día 16: "Buenos días Ana, te escribo por Flora Gutiérrez. En los últimos meses hemos ido recogiendo y valorando con ella la idea de poder solicitar una revisión del PIA para solicitar un recurso de personas mayores (una residencia) dónde pueda recibir tanto el apoyo para su cuidado personal (higiene) como fisioterapia y actividades de terapia ocupacional más acordes con su situación actual (dificultades de movilidad física). No sabemos si tenéis que firmar/tramitar vosotros los papeles o bien tiene que firmarlos Flori. Te ruego que nos lo puedas aclarar y en su caso iniciar los trámites pertinentes. Ya nos dices." ··················· *Solicito a Paula que nos envíen el Mod. de Solicitud de Dependencia, cumplimentado para ponerlo para firma del Representante Legal y darle registro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-22','Ana: Llamada de la Dra. Herrera (56718): Manuela ayer tuvo una crisis convulsiva. Creen que puede haber tenido un ictus, puede que al no haber habido sangrado interno se haya formado un coágulo. Han solicitado un tac craneal preferente, pero aún no le han dado fecha. La función renal no se ha recuperado y comienza a haber líquido en los pulmones. Los médicos de fin de semana anotaron que presentaba mal estado en general y a día de hoy se encuentra en una "especie de estado de coma". *Comenzarán a aplicarle medidas de confort en el momento que aprecien sufrimiento (medicación paliativa). *Van a tener que retirar suero, pues no puede tolerar tal cantidad). *No aplicarán otras medidas, ni le van a entubar ni a transfundir, pues no se encuentra en condiciones para ello dada su demencia y situación actual. Sólo van a tratar los síntomas. ················ Lo comunico por mail a la residencia y por teléfono Raquel, mujer de Pablo, nieto (637 193 540) ···························································· Pregunto a la Dra. Herrera y comunico a Rema, mujer de Antonio que la habitación es la 109 de la Planta de Geriatría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2021-11-22','TERESA Me pongo en contacto para comentarte que Libertad se ha ido a pasar unos días a casa, porque hacía tiempo que no visitaba a su familia, concretamente estará en casa desde hoy lunes hasta el viernes. Este mes ha tenido más gastos porque ha sido el cumpleaños de su amigo y ha gastado un poco más. Para irse hoy le hemos prestado dinero porque no tenía suficiente para el autobús, por ello sería conveniente que le autorizaráis la retirada del banco de al menos 50€ que es el importe que le hemos prestado. Se lo podéis autorizar a partir del lunes de la próxima semana que ya haya regresado de su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2021-11-22','-Amalia : se presenta en las oficinas del SEPAD sin cita . Bajo atenderle en el espacio de información, en presencia del vigilante de seguridad . Exige un piso y una pensión para este mismo día. Le explico que no se conceden pisos desde el SEPAD y que para acceder a algún tipo de recurso ha de acudir previamente a citas del CEDEX y del ESM . Le indico que el día 29 de Noviembre a las 12.00 tiene la cita en el ESM , pero me contesta que no va acudir . Que si no se le da inmediatamente el piso se va a ir a Francia . Expresa que no quiere estar tutelado y se le da la información judicial al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2021-11-22','TERESA Buenos días. Soy Helena Macías, trabajadora social del Ayuntamiento de Zafra. He intentado contactar con vosotros para la firma de la solicitud de cambio de PIA de Beatriz Mejías de la Morena pero no hemos coincidido. Finalmente contacté con una compañera vuestra y quedamos en que os mandaría la solicitud de acceso a prestación económica vinculada a ayuda a domicilio firmada por Bea para que quedase más completa. Falta incluir los datos de la tutora y su firma y enviar la solicitud al SEPAD para que puedan reactivar el expediente lo antes posible. Si tenéis cualquier duda mi teléfono directo es el 924 54 00 73. CONTACTO CON HELENA Y LE COMUNICO QUE DESDE LA COMISION TUTLEAR NO SE ACEPTA ESTE PIA YA QUE CONLLEVA COPAGO Y PUEDE ACCEDER A SERVICIO PUBLICO EL CUAL NO CONLLEVA NINGUN COSTE PARA ELLA COMO LO HA TENIDO ANTERIORMENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NICOLAS'and edp.apellido1='FLORES'and apellido2='DOMINGUEZ'),'2021-11-22','TERESA ARCHIVO EMPADRONAMIENTO COLECTIVO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2021-11-22','TERESA RECIBO LLAMADA DE TACIANA PSQUIATRA DE LA UHB PARA COMENTAR EL ESTADO DE JOSE MARI SE ENCUENTRA TRANQUILO Y ESTABLE, ME RECUERDDA QUE EN DIEZ DIA LE DARA EL ALTA QUE NO PUEDE MANTENERLO INGRESADO PUES HAY CRITERIO YA LE HAN INFORMADO DE QUE NO VA A VOLVER A INCLUSIVES Y EL MANIFIESTA EL DESEO DE DE QUERER DESPEDIRSE DE LA GENTE DEL CENTRO Y RECOGER SUS COSAS. TACIANA OPINA QUE SERIA BUENO QUE PUEDIERA DESPEDIRSE DEL CENTRO PARA CERRAR ESE CAPITULO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2021-11-22','Ana: Envío correo a Toni, Futuex: "En relación a Juan, sólo para vuestro conocimiento, que creo no os lo dije al final, la semana pasada se le autorizó un extra de 150€ para calzado, ropa para el frío y alguna “deuda” que tenía en el pueblo." ··································· Respuesta de Toni: "Gracias por la información de Juan, te cuento que teniamos previsto dada su inistencia con el dinero intentar (como la otra vez) hacerlo cuadrar con una visita en un miercoles que es cuando hay mercadillo en el pueblo y donde se suele comprar las cosas, pero al plantearselo a el la semana pasada, insiste en que tenia que ser urgente "mañana mismo" y que "él es autónomo para comprarlo solo y no necesita acompañamiento" .. Por lo tanto invalidó la opción de acompañarlo. Está pendiente, de recibir citación para su revisión en psiquiatría (última cita el 28 de septiembre, donde todo quedó iugal, sin cambio de pauta de medicación) sigue cumpliendo eso si, su inyectable cada 28 dias en el centro de salud de Guadalupe."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2021-11-23','miguel, me comunica Tere que Futuex la comunica que han notificado en el domicilio del tutelado apertura del juicio oral y plazo de 3 días de impugnación del procedimiento DPA 114-2021, asi que mando fax indicando que es persona tutelada, que no nos han comunicado nada, que nos citen en adelante por video conferencia, y nombren abogado de oficio','2');
