insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2021-11-22','Ana: Correo de Estrella Durán, CSS Plas: "Buenos días. Desi va mañana a acompañar a Ángel a Badajoz a una consulta médica y quiere llevarse 160 euros que tiene en Admisión. Necesito vuestro permiso para dárselos o no.... Decidme cuanto antes, por favor..." ················ Tras hablar con Alberto, Jefe secc. ecca., Alberto responde al correo: "Hola Estrella. Me comenta Ana que la tutelada únicamente va a acompañar a su marido. Desconozco por tanto el concepto que justifica el gasto de 160 €. Si únicamente se trata de pasar el día en Badajoz me resulta excesivo, pero vosotros podéis entregarle el dinero que consideréis razonable."','2');
