insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-24','Ana: Tere, TS CTAEX, habla con una de las Geriatras, le indican que Manuela está peor, es posible que Manuela fallezca esta tarde o mañana. *Anotan en el hospital la compañía de seguros (Santa Lucía) y el número de contacto, para que puedan si ocurriera en horario de tarde. Tienen anotado también el número de los otros nietos, pero no saben si el médico de guardia llamará para comunicarlo, pues no tienen por qué. Se suele comunicar a uno (al que está con ella). ······················· Lo comunico a la Residencia Geryvida y a Reme, mujer de Antonio.','2');
