insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2021-11-24','miguel, en relación al embargo de los aproximadamente 3.000€ me confirma el jzdo 1º instancia nº1 de Jerez de Caballeros que es de Cofidis, envío a Alberto la contestación: Alberto, he hecho la consulta al Juzgado de 1º instancia nº1 de Jerez para que me averigue el procedimiento y el motivo del embargo (para cuando hagamos la rendición de cuentas anuales poder justificarlo al juzgado correspondiente). Me comentan que procede de un procedimiento monitorio de Cofidis del año 2012 siendo la ejecutoria 371/2013. Ya se encuentra pagado el principal con lo que las costas e intereses era lo que faltaba y es lo que se ha retenido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-11-24','Buenas tardes, se envía adjunto la nota informativa sobre lo acontecido el dia jueves 18 de Noviembre sobre la curatelada Mercedes Perez Pinna, para la cual se activó el 112 , quedando ingresada en la unidad de psiquiatría del hospital universitario de Badajoz, hasta lo presente, no tenemos conocimiento de nada mas.. suponemos que aún continue ingresada. Hemos hablado largo y tendido sobre el episodio del 112, pero tal y como te comenté te envio, la nota de lo acontecido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-11-22','-Desde el ESM , Mar anula la reunión a espera del ingreso en UHB .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-11-18','-Desde el ESM , Mar activa el protocolo de salud mental para el ingreso de Mercedes en UHB . Intentó que se hiciese desde la CTAEX pero le expliqué que no es nuestra competencia. Aprovechando que Teresa , delegada tutelar , estaba en la consulta para hablar de este caso , avisó a la Dtra. de AP . que fue con Teresa hasta el domicilio . Quedaron dentro de la casa a los animales , intenté que Mercedes nos firmara una autorización para entrar en la casa y llevarlos a la perrera pero no consintió. Finalmente avisamos a su primo Jesús y acepta hacerse cargo de ellos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-11-18','-Desde el ESM , Mar activa el protocolo de salud mental para el ingreso de Mercedes en UHB . Intentó que se hiciese desde la CTAEX pero le expliqué que no es nuestra competencia. Aprovechando que Teresa , delegada tutelar , estaba en la consulta para hablar de este caso , avisó a la Dtra. de AP . que fue con Teresa hasta el domicilio . Quedaron dentro de la casa a los animales , intenté que Mercedes nos firmara una autorización para entrar en la casa y llevarlos a la perrera pero no consintió. Finalmente avisamos a su primo Jesús y acepta hacerse cargo de ellos .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2021-11-23','NOTA INFORMATIVA DESDE FUTUEX con respecto al ingreso en UHB . Datos del tutelado: Nombre: Mercedes Pérez Pinna Dirección: C/ Fernando Caston nº 3 – 4º izqda. Puerta A 06005 Badajoz Contacto: 690969755 (número personal) Edad: 55 años Diagnóstico: esquizofrenia paranoide de curso crónico. Personalidad con rasgos narcisista. Gestiones Realizadas: En visita al área de salud mental, en centro de salud de Ciudad Jardín de Badajoz, por acompañamiento de tratamiento con tutelado, pasamos al despacho de la trabajadora social Mar Sánchez, a recabar información de la situación de la curatelada Mercedes Pérez Pinna, según se solicita desde la propia comisión tutelar. La trabajadora social nos comunica, que ha estado en consulta, tanto con ella como en la de su psiquiatra de referencia, Fernando Galán, el pasado lunes 15 de noviembre. Que la han encontrado, a pesar de sus delirios persistentes de su esquizofrenia paranoide, en una fase de reagudización, indicando y aconsejando ingreso hospitalario, pudiendo recurrir al 112. Se le comenta que se pudo haber realizado el lunes, a lo que se nos responde que, desde salud mental no se les permite activar 112 para ningún ingreso, como tampoco realizar visitas a los domicilios de los pacientes en estas situaciones o bien, hacerles seguimiento, ya que está prohibido por la gerencia del SES en Badajoz. Le expresamos la duda o sorpresa que desde la comisión no sepan estas últimas noticias relacionadas con la curatelada, nos dicen que se le ha enviado ese mismo día de consulta (lunes 15 noviembre) un email con la información, donde se relata la situación de necesidad de ingreso. Se comprueba por parte de la trabajadora social el envío del referido email, y se da cuenta que se quedó en borrador, por tanto no llegó a destinataria. En este momento, estando en su despacho, envía por tanto el email a Amalia Díaz y contacta telefónicamente con ella para tratar el asunto en cuestión, activar posible 112, ingreso de Mercedes Pérez Pinna. Ante la duda que se crea de, a quién corresponde activar el ingreso, nos comunica Mar que envía otro email convocando a una reunión el lunes 22 de noviembre con ella, con el psiquiatra Fernando Galán y con Amalia Díaz, por parte de la comisión, para seguir tratando el tema y ver la manera de solucionar y valora la situación de Mercedes Pérez Pinna. En el trayecto de regreso con el tutelado al que se ha realizado acompañamiento, se recibe llamada de Mar Sánchez, para comentar que ha logrado contactar con la médica de atención primaria del centro de salud de referencia de Mercedes (zona centro en Ronda del Pilar), y pregunta si la podemos recoger para acudir al domicilio de Mercedes, que ellos están dispuestos a activar el 112. La respuesta que le damos es que: no hemos contactado con nuestra coordinadora de equipo Antonia Mª Ramírez Cruceras, pues nuestra dinámica de trabajo es esta. Desde la comisión plantean a la Coordinadora, y desde aquí, se organiza la gestión correspondiente, y no hemos tenido conversación con Ella al respecto de este tema y creemos que tampoco desde la comisión. Se corta la comunicación, para recibir más tarde otra llamada de Mar Sánchez, para decirnos que ya ha estado hablando con nuestra Coordinadora y que estaba intentando también localizar a Amalia Díaz. Que ya estaba la médica en la puerta de Ronda del Pilar, y que se la recogiera para llevarla al domicilio de Mercedes en C/ Fernando Caston n 3, 4º izq. puerta A. Con la premura del momento y cierto desconcierto por la situación, sin haber tenido ocasión de contrastar la información directamente con nuestra Coordinadora, aunque después nos comunicamos en el trayecto, se procede a recoger a la médica de atención primaria, que para nuestra sorpresa, comenta que es el primer caso que se le da y que no sabe bien qué hacer ahora, poniendo en duda de a quién realmente le corresponde activar el 112. Es de camino al domicilio de la curatelada, Mercedes Pérez, cuando la médica (Rocío) realiza la llamada a la coordinación del 112, que le confirma la activación con la llegada de un equipo al domicilio y policía, aunque no fuera preciso, pero es de protocolo. Coincidimos en el portal con la ambulancia del 112, que acude sin enfermero ni medicación, algo que tampoco ha llevado la médica, dudando si debería avisar a su enfermero. Ya en el domicilio, Mercedes abre la puerta y permite pasar, aunque muy sorprendida al ver al personal sanitario, la policía sube más tarde aunque no entra en domicilio, no hay necesidad. Mercedes se niega acompañar al personal del 112 en un primer momento para acudir al hospital, dice que ella es solo una curatelada administrativa y nada más y puede decidir si va o no. Realiza una llamada a su primo Antonio, para pedirle consejo y repetirle varias veces que si algo le ocurriese, tiene testamento hecho a favor de médicos sin Fronteras, que por favor cumpliera esta petición. Recoge finalmente sus documentos, teléfono móvil y cargador y se decide libremente a salir junto con la médica Rocío, que la conoce y la técnico del 112 y salen del domicilio, cerrando la puerta y llevándose Ella sus llaves. Se realiza pues el traslado al hospital universitario de Badajoz, haciendo nosotros entrega a la médica, de la nota que nos fue entregada en un primer momento, en el despacho de la trabajadora social, por parte del psiquiatra, como información de la situación de Mercedes, quedándonos con una copia que adjuntamos. Mercedes es valorada en urgencias por el servicio de psiquiatría de dicho hospital, quedando ingresada a lo largo de la tarde en la unidad. Desde esa misma unidad de psiquiatría, su enfermera jefa de tarde, nos comunica, en llamada telefónica realizada en el transcurso de la tarde, en relación a la problemática surgida sobre los animales que Mercedes ha dejado en domicilio (perra, gato y tortuga) que al final ha decido autorizar, porque así ha aceptado, a su primo Jesús, que ha pasado para recoger las llaves y hacerse cargo de todo, quedando Mercedes tranquila por ello, según comenta la enfermera. Jueves, 18 de noviembre de 2021 Equipo de apoyo social comunitario de Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2021-11-24','Ana: Llamo a Carmen, TS del SSASB-Coria (927 50 80 00 Ext: 318): Acordamos que me facilitará, en cuanto le sea posible, informe social tanto para la Solicitud Ingreso en C. Residencial de Mayores por Emergencia Social como para la Valoración de Dependencia. *Yo llamaré al centro de salud para solicitar Informes de Salud al MAP.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2021-11-24','miguel, a petición del juzgado de lo penal nº1 y aunque no nos han citado en Procedimiento Abreviado 249/21, por delito de hurto a su abuelo. Se llega a un acuerdo de 6 meses de pena (el abogado pedirá la suspensión) y multa de unos 6.000€ (a ambos, aunque Jonatan ha insistido en la vista que es insolvente)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='RODRIGUEZ'and apellido2='ESCALERA'),'2021-11-25','Buenos días , te he llamando por tf. pero no he podido contactar . Te informo , me he reunido con Soraya Maya , Mayte y Manuela , Jefa de Sección de discapacidad para comentarle la situación de Pilar . Vamos a solicitar plaza por dependencia - emergencia social , que será lo más ágil . El inconveniente es que no podemos elegir plaza , será dónde haya vacante , habrá que esperar para ver llegado el momento dónde están ubicadas. Estoy tramitando la revisión por PIA para pedir la plaza .Ya tengo cumplimentado la solicitud , para ponerlo a firma . Se necesitaría informe social del SSASB , pero le he indicado a Manuela que no son usuarios de SSASB y no conocen a Pilar ( hija ) . En este caso me indica que aceptará informe social del Centro y otras pruebas que la Comisión pueda aportar . Yo haré un informe y aportaré todo lo que pueda para justificar la situación . Cuando puedas ,me reenviáis Informe social solicitado por la sección de discapacidad. Voy a aportar si os parece bien el acta de la reunión que mantuvimos . Tenemos que firmarla todos los presentes para que tenga validez . Si te parece me la enviáis firmada por escáner y yo añado mi firma y os lo pongo en copia . Qué se sabe de la situación ?? Qué ha decido la pareja ?? sabéis algo ?? queréis que les llame y pregunte ??? tenéis un tf de contacto ? Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2021-11-25','Buenos días Carmen , me he reunido con Mayte , mi jefa de sección , y Soraya Maya para tratar varios temas incluido éste . La UHDAC no ve el ingreso en esa unidad , proponen UME . Sería conveniente que se convocara a alguien de UME para la subcomisión , para valorar esta posibilidad . Te parece bien ? Un saludo','2');
