insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2021-11-25','Angel : Necesito un Informe Social para enviarlo al Juzgado, del Centro donde reside por ejemplo, en el que se exponga la situación actual en la que se encuentra Joaquín (Cristina), que avale su solicitud de revisión de la capacidad, indicando la evolución que ha experimentado desde que fue incapacitado/a y la mejoría hasta la fecha actual. -Amalia : pedido a la entidad','2');
