insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2021-11-25','Ana: Recibo llamada de Reme, mujer de Antonio, nieto de Manuela. Manuela FALLECIÓ ayer (24/11/21) sobre las 20:00 h. ·················· Lo comunico por mail a Tamara, TS y a Mercedes, Médica de Geryvida. ································· *Llamo a la Dra. Herrera (56718) y solicito informe de Alta y defunción de Manuela. Intentará enviármelo mañana por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='CRESPO'and apellido2='PEREZ'),'2021-11-25','Ana: Tras hablar con Ángel, Asesor Jurídico CTAEX, en relación a la vivienda propiedad de Ángel, llamo a Emilia Almodóvar, TS CSS (24164): No hay previsión de que Ángel vaya a regresar a su domicilio, de hecho además de no contar con red social de apoyo, no reúne capacidades para vivir solo y comienza a presentar deterioro cognitivo. *No obstante, solicitará tanto a su Médico (Cándido), como a su Psiquiatra de referencia (Agapito) informe al respecto. ··········· *Se lo pasará a Ángel, asesor jurídico, cuando lo reciba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2021-11-24','Ana: Recibimos resolución de la D.G. de SS.SS., Infancia y Familias relativa a la PNC: resuelve "modificar la cuota de Pensión No Contributiva... con efectos del 01/01/2020 a las cuantía de 325,16€ (20) y 332, 98€ (21) mensuales en función de los recursos propios del beneficiario. NO reclaman cuantía percibida indebidamente..."','2');
